// Main JavaScript for Air Traffic Control Simulator

// Data storage keys (fallback / legacy)
const STORAGE_SECTORS_KEY = 'atc_sectors';
const STORAGE_EXERCISES_KEY = 'atc_exercises';

// Server-backed cache: sectors and exercises are shared across all clients
let serverSectorsCache = [];
let serverExercisesCache = [];
const serverSectorDetailsCache = new Map();
/** Named flow packages from flows.json (per airspace: sectorId + sectorName). */
let serverFlowsLibraryCache = [];

// Initialize data storage (legacy fallback)
function initStorage() {
    if (!localStorage.getItem(STORAGE_SECTORS_KEY)) {
        localStorage.setItem(STORAGE_SECTORS_KEY, JSON.stringify([]));
    }
    if (!localStorage.getItem(STORAGE_EXERCISES_KEY)) {
        localStorage.setItem(STORAGE_EXERCISES_KEY, JSON.stringify([]));
    }
}

// Load sectors from server (shared across all computers)
function loadSectorsFromServer() {
    return fetch('/api/sectors?summary=1')
        .then(r => r.json())
        .then(data => {
            if (Array.isArray(data.sectors)) serverSectorsCache = data.sectors;
        })
        .catch(() => {});
}

function cacheFullSector(sector) {
    if (!sector || sector.id == null) return null;
    const clean = { ...sector };
    delete clean._summaryOnly;
    const sid = String(clean.id);
    serverSectorDetailsCache.set(sid, clean);
    const idx = serverSectorsCache.findIndex(s => s && String(s.id) === sid);
    if (idx >= 0) {
        serverSectorsCache[idx] = clean;
    } else {
        serverSectorsCache.push(clean);
    }
    return clean;
}

function getCachedSector(sectorId) {
    const sid = sectorId != null ? String(sectorId) : '';
    if (!sid) return null;
    return serverSectorDetailsCache.get(sid) || serverSectorsCache.find(s => s && String(s.id) === sid) || null;
}

function sectorNeedsFullLoad(sector) {
    return !!(sector && sector._summaryOnly);
}

function loadSectorFromServer(sectorId) {
    const cached = getCachedSector(sectorId);
    if (cached && !sectorNeedsFullLoad(cached)) return Promise.resolve(cached);
    return fetch(`/api/sectors/${encodeURIComponent(String(sectorId))}`)
        .then(r => {
            if (!r.ok) throw new Error('Airspace not found');
            return r.json();
        })
        .then(data => cacheFullSector(data.sector));
}

// Load exercises from server (shared across all computers)
function loadExercisesFromServer() {
    return fetch('/api/exercises')
        .then(r => r.json())
        .then(data => {
            if (Array.isArray(data.exercises)) serverExercisesCache = data.exercises;
        })
        .catch(() => {});
}

function loadFlowsLibraryFromServer() {
    return fetch('/api/flows')
        .then(r => r.json())
        .then(data => {
            if (Array.isArray(data.flows)) serverFlowsLibraryCache = data.flows;
        })
        .catch(() => {});
}

function getFlowsLibrary() {
    return serverFlowsLibraryCache;
}

/** For future Load Flows: packages tied to this airspace (id and/or saved name). */
function getFlowPackagesForAirspace(sectorId, sectorName) {
    const sid = sectorId != null ? String(sectorId) : '';
    const sname = sectorName != null ? String(sectorName).trim() : '';
    return getFlowsLibrary().filter(p => {
        if (!p || typeof p !== 'object') return false;
        if (sid && String(p.sectorId || '') === sid) return true;
        if (sname && String(p.sectorName || '').trim() === sname) return true;
        return false;
    });
}

function cloneFlowsForLibrary(flows) {
    try {
        return JSON.parse(JSON.stringify(flows && Array.isArray(flows) ? flows : []));
    } catch (e) {
        return [];
    }
}

// Get sectors (from server-backed cache)
function getSectors() {
    return serverSectorsCache;
}

// Save sectors to server and update local cache
function saveSectors(sectors) {
    serverSectorsCache = sectors && Array.isArray(sectors) ? sectors : [];
    serverSectorsCache.forEach(sector => {
        if (sector && !sectorNeedsFullLoad(sector)) cacheFullSector(sector);
    });
    fetch('/api/sectors', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sectors: serverSectorsCache, mergeSummaries: true })
    }).catch(() => {});
}

// Get exercises (from server-backed cache)
function getExercises() {
    return serverExercisesCache;
}

// Save exercises to server and update local cache
function saveExercises(exercises) {
    serverExercisesCache = exercises && Array.isArray(exercises) ? exercises : [];
    fetch('/api/exercises', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ exercises: serverExercisesCache })
    }).catch(() => {});
}

/** Export bundle identifier for JSON files produced by Export Data (for future import). */
const AITC_DATA_EXPORT_FORMAT = 'AiTC-data-export';
const AITC_DATA_EXPORT_VERSION = 1;

function downloadJsonFile(filename, obj) {
    const text = typeof obj === 'string' ? obj : JSON.stringify(obj, null, 2);
    const blob = new Blob([text], { type: 'application/json;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}

function renderExportDataModalContent() {
    const sectorsEl = document.getElementById('exportDataSectorsList');
    const exercisesEl = document.getElementById('exportDataExercisesList');
    const sectors = getSectors().filter(s => s && s.id != null && s.id !== '');
    const exercises = getExercises().filter(ex => ex && ex.id != null && ex.id !== '');
    const sectorById = new Map(sectors.map(s => [String(s.id), s]));

    if (sectorsEl) {
        if (!sectors.length) {
            sectorsEl.innerHTML = '<div class="hint-text">No airspaces available.</div>';
        } else {
            sectorsEl.innerHTML = sectors
                .map(s => {
                    const id = String(s.id);
                    const title = escapeHtml(((s.name || '').toString().trim() || 'Untitled airspace'));
                    const idEsc = escapeHtml(id);
                    return `<label class="export-data-row"><input type="checkbox" class="export-data-sector-cb" value="${idEsc}" checked /><span class="export-data-row-main"><span class="export-data-row-title">${title}</span><span class="export-data-id">${idEsc}</span></span></label>`;
                })
                .join('');
        }
    }

    if (exercisesEl) {
        if (!exercises.length) {
            exercisesEl.innerHTML = '<div class="hint-text">No exercises available.</div>';
        } else {
            exercisesEl.innerHTML = exercises
                .map(ex => {
                    const id = String(ex.id);
                    const sec = sectorById.get(String(ex.sectorId));
                    const secName = sec ? (sec.name || '').toString().trim() : '';
                    const title = escapeHtml(((ex.name || '').toString().trim() || 'Untitled exercise'));
                    const sub = secName ? escapeHtml(secName) : 'Unknown airspace';
                    const idEsc = escapeHtml(id);
                    return `<label class="export-data-row"><input type="checkbox" class="export-data-exercise-cb" value="${idEsc}" checked /><span class="export-data-row-main"><span class="export-data-row-title">${title}</span><span class="export-data-row-sub">${sub}</span><span class="export-data-id">${idEsc}</span></span></label>`;
                })
                .join('');
        }
    }
}

function openExportDataModal() {
    renderExportDataModalContent();
    openModal('exportDataModal');
}

function setExportDataCheckboxes(className, checked) {
    document.querySelectorAll('#exportDataModal .' + className).forEach(el => {
        el.checked = checked;
    });
}

async function runExportDataDownload() {
    const sectorCbs = Array.from(document.querySelectorAll('#exportDataModal .export-data-sector-cb:checked'));
    const exerciseCbs = Array.from(document.querySelectorAll('#exportDataModal .export-data-exercise-cb:checked'));
    const sectorsAll = getSectors().filter(s => s && s.id != null && s.id !== '');
    const exercisesAll = getExercises().filter(ex => ex && ex.id != null && ex.id !== '');
    const sidSel = new Set(sectorCbs.map(cb => cb.value));
    const exSel = new Set(exerciseCbs.map(cb => cb.value));

    const selectedSectorIds = sectorsAll
        .filter(s => sidSel.has(String(s.id)))
        .map(s => String(s.id));
    const loadedSectors = [];
    for (const sid of selectedSectorIds) {
        try {
            const sector = await loadSectorFromServer(sid);
            if (sector) loadedSectors.push(sector);
        } catch (e) {}
    }
    const sectorsOut = loadedSectors
        .map(s => {
            try {
                return JSON.parse(JSON.stringify(s));
            } catch (e) {
                return null;
            }
        })
        .filter(Boolean);
    const exercisesOut = exercisesAll
        .filter(ex => exSel.has(String(ex.id)))
        .map(ex => {
            try {
                return JSON.parse(JSON.stringify(ex));
            } catch (e) {
                return null;
            }
        })
        .filter(Boolean);

    if (!sectorsOut.length && !exercisesOut.length) {
        alert('Select at least one airspace or one exercise to export.');
        return;
    }

    const payload = {
        format: AITC_DATA_EXPORT_FORMAT,
        version: AITC_DATA_EXPORT_VERSION,
        exportedAt: new Date().toISOString(),
        sectors: sectorsOut,
        exercises: exercisesOut
    };

    const stamp = new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-');
    downloadJsonFile(`aitc-data-export-${stamp}.json`, payload);
    closeModal('exportDataModal');
}

/** Parsed JSON from user-selected file in Import Data modal ({ sectors, exercises } subset). */
let importDataParsedPayload = null;

function normalizeImportDataPayload(parsed) {
    if (!parsed || typeof parsed !== 'object') return null;
    const sectors = Array.isArray(parsed.sectors) ? parsed.sectors : [];
    const exercises = Array.isArray(parsed.exercises) ? parsed.exercises : [];
    if (!sectors.length && !exercises.length) return null;
    return { sectors, exercises };
}

function syncImportDataModalNameModeClass() {
    const modal = document.getElementById('importDataModal');
    const custom = document.getElementById('importDataNameModeCustom')?.checked;
    if (modal) modal.classList.toggle('import-data-modal--custom-names', !!custom);
}

function resetImportDataModal() {
    importDataParsedPayload = null;
    const fi = document.getElementById('importDataFileInput');
    if (fi) fi.value = '';
    const lbl = document.getElementById('importDataFileLabel');
    if (lbl) lbl.textContent = '';
    const empty = document.getElementById('importDataEmptyHint');
    const panel = document.getElementById('importDataOptionsPanel');
    const secList = document.getElementById('importDataSectorsList');
    const exList = document.getElementById('importDataExercisesList');
    if (empty) empty.style.display = '';
    if (panel) panel.style.display = 'none';
    if (secList) secList.innerHTML = '';
    if (exList) exList.innerHTML = '';
    const keep = document.getElementById('importDataNameModeKeep');
    const custom = document.getElementById('importDataNameModeCustom');
    if (keep) keep.checked = true;
    if (custom) custom.checked = false;
    syncImportDataModalNameModeClass();
    const confirmBtn = document.getElementById('importDataConfirmBtn');
    if (confirmBtn) confirmBtn.disabled = true;
}

function cloneExerciseForImport(ex, newSectorId, displayName) {
    const x = JSON.parse(JSON.stringify(ex));
    x.id = newSectorEntityId('ex');
    x.sectorId = newSectorId;
    x.name = (displayName || '').toString().trim() || 'Imported exercise';
    x.createdAt = new Date().toISOString();
    if (Array.isArray(x.flights)) {
        x.flights = x.flights.filter(Boolean).map(f => ({
            ...f,
            id: newSectorEntityId('flt')
        }));
    }
    return x;
}

function renderImportDataModalLists() {
    const panel = document.getElementById('importDataOptionsPanel');
    const empty = document.getElementById('importDataEmptyHint');
    const secList = document.getElementById('importDataSectorsList');
    const exList = document.getElementById('importDataExercisesList');
    const confirmBtn = document.getElementById('importDataConfirmBtn');
    if (!importDataParsedPayload) {
        if (panel) panel.style.display = 'none';
        if (empty) empty.style.display = '';
        if (confirmBtn) confirmBtn.disabled = true;
        return;
    }
    if (empty) empty.style.display = 'none';
    if (panel) panel.style.display = '';
    if (confirmBtn) confirmBtn.disabled = false;

    const sectors = importDataParsedPayload.sectors.filter(s => s && s.id != null && s.id !== '');
    const exercises = importDataParsedPayload.exercises.filter(ex => ex && ex.id != null && ex.id !== '');
    const sectorById = new Map(sectors.map(s => [String(s.id), s]));

    syncImportDataModalNameModeClass();

    if (secList) {
        if (!sectors.length) {
            secList.innerHTML = '<div class="hint-text">No airspaces in this file.</div>';
        } else {
            secList.innerHTML = sectors
                .map(s => {
                    const id = String(s.id);
                    const title = escapeHtml(((s.name || '').toString().trim() || 'Untitled airspace'));
                    const idEsc = escapeHtml(id);
                    const nameVal = escapeHtml(((s.name || '').toString().trim() || 'Imported airspace'));
                    return `<label class="import-data-row export-data-row"><input type="checkbox" class="import-data-sector-cb" value="${idEsc}" checked /><span class="export-data-row-main import-data-row-main"><span class="export-data-row-title">${title}</span><span class="export-data-id">${idEsc}</span></span><input type="text" class="form-input import-data-name-field import-data-sector-name" value="${nameVal}" /></label>`;
                })
                .join('');
        }
    }

    if (exList) {
        if (!exercises.length) {
            exList.innerHTML = '<div class="hint-text">No exercises in this file.</div>';
        } else {
            exList.innerHTML = exercises
                .map(ex => {
                    const id = String(ex.id);
                    const sec = sectorById.get(String(ex.sectorId));
                    const secName = sec ? (sec.name || '').toString().trim() : '';
                    const title = escapeHtml(((ex.name || '').toString().trim() || 'Untitled exercise'));
                    const sub = secName ? escapeHtml(secName) : 'Unknown airspace (in file)';
                    const idEsc = escapeHtml(id);
                    const nameVal = escapeHtml(((ex.name || '').toString().trim() || 'Imported exercise'));
                    return `<label class="import-data-row export-data-row"><input type="checkbox" class="import-data-exercise-cb" value="${idEsc}" checked /><span class="export-data-row-main import-data-row-main"><span class="export-data-row-title">${title}</span><span class="export-data-row-sub">${sub}</span><span class="export-data-id">${idEsc}</span></span><input type="text" class="form-input import-data-name-field import-data-exercise-name" value="${nameVal}" /></label>`;
                })
                .join('');
        }
    }
}

function openImportDataModal() {
    resetImportDataModal();
    openModal('importDataModal');
}

let playbackRecordingsCache = [];
let playbackCurrentRecording = null;
let playbackSnapshotEvents = [];
let playbackBounds = null;
let playbackCurrentSec = 0;
let playbackTimerId = null;
let playbackStartedRealMs = 0;
let playbackStartedSimSec = 0;
let playbackSubtitlesEnabled = false;

function playbackFormatTime(seconds) {
    const total = Math.max(0, Math.floor(Number(seconds) || 0));
    const mm = Math.floor(total / 60);
    const ss = total % 60;
    return `${String(mm).padStart(2, '0')}:${String(ss).padStart(2, '0')}`;
}

function playbackGetDuration(recording) {
    const metaDur = Number(recording?.metadata?.durationSimSec);
    if (Number.isFinite(metaDur) && metaDur > 0) return metaDur;
    const events = Array.isArray(recording?.events) ? recording.events : [];
    return events.reduce((max, ev) => Math.max(max, Number(ev?.simSec) || 0), 0);
}

function playbackSetStatus(text) {
    const meta = document.getElementById('playbackRecordingMeta');
    if (meta) meta.textContent = text || '';
}

function openPlaybackModal() {
    openModal('playbackModal');
    resizePlaybackCanvas();
    refreshPlaybackRecordingsList();
    drawPlaybackFrame();
}

function stopPlaybackTimer() {
    if (playbackTimerId) {
        clearInterval(playbackTimerId);
        playbackTimerId = null;
    }
}

function updatePlaybackSubtitlesButton() {
    const btn = document.getElementById('playbackSubtitlesBtn');
    if (!btn) return;
    btn.textContent = playbackSubtitlesEnabled ? 'Subtitles On' : 'Subtitles Off';
    btn.setAttribute('aria-pressed', playbackSubtitlesEnabled ? 'true' : 'false');
    btn.classList.toggle('active', playbackSubtitlesEnabled);
}

function resetPlaybackViewer() {
    stopPlaybackTimer();
    playbackCurrentRecording = null;
    playbackSnapshotEvents = [];
    playbackBounds = null;
    playbackCurrentSec = 0;
    const title = document.getElementById('playbackRecordingTitle');
    if (title) title.textContent = 'Select a recording';
    playbackSetStatus('Choose Play recording from the list.');
    const scrub = document.getElementById('playbackScrubBar');
    if (scrub) {
        scrub.min = '0';
        scrub.max = '0';
        scrub.value = '0';
        scrub.disabled = true;
    }
    document.getElementById('playRecordingBtn')?.setAttribute('disabled', 'disabled');
    document.getElementById('pauseRecordingBtn')?.setAttribute('disabled', 'disabled');
    updatePlaybackTimeLabel();
    updatePlaybackSubtitles();
    drawPlaybackFrame();
}

function resizePlaybackCanvas() {
    const canvas = document.getElementById('playbackCanvas');
    if (!canvas) return;
    const wrap = document.querySelector('#playbackModal .playback-canvas-wrap');
    const fsEl = document.fullscreenElement || document.webkitFullscreenElement;
    const isPlaybackFullscreen = fsEl && fsEl.classList && fsEl.classList.contains('playback-viewer-panel');
    if (isPlaybackFullscreen) {
        const rect = (wrap || canvas).getBoundingClientRect();
        canvas.style.aspectRatio = '';
        canvas.style.height = '';
        canvas.width = Math.max(400, Math.floor(rect.width || window.innerWidth || 900));
        canvas.height = Math.max(260, Math.floor(rect.height || (window.innerHeight - 90) || 520));
        return;
    }
    const recordedViewport = playbackCurrentRecording?.metadata?.viewport || playbackCurrentRecording?.metadata?.initialView?.viewport || null;
    const recW = parseInt(recordedViewport?.width, 10);
    const recH = parseInt(recordedViewport?.height, 10);
    if (Number.isFinite(recW) && recW > 0 && Number.isFinite(recH) && recH > 0) {
        canvas.width = recW;
        canvas.height = recH;
        canvas.style.aspectRatio = `${recW} / ${recH}`;
        canvas.style.height = 'auto';
        if (wrap) wrap.style.aspectRatio = `${recW} / ${recH}`;
        return;
    }
    canvas.style.aspectRatio = '';
    canvas.style.height = '';
    if (wrap) wrap.style.aspectRatio = '';
    const rect = canvas.getBoundingClientRect();
    const w = Math.max(400, Math.floor(rect.width || 900));
    const h = Math.max(260, Math.floor(rect.height || 520));
    if (canvas.width !== w) canvas.width = w;
    if (canvas.height !== h) canvas.height = h;
}

async function refreshPlaybackRecordingsList() {
    const list = document.getElementById('playbackRecordingsList');
    if (list) list.innerHTML = '<div class="hint-text">Loading recordings...</div>';
    try {
        const resp = await fetch('/api/recordings');
        const data = await resp.json();
        playbackRecordingsCache = Array.isArray(data.recordings) ? data.recordings : [];
    } catch (e) {
        playbackRecordingsCache = [];
        if (list) list.innerHTML = '<div class="hint-text">Could not load recordings.</div>';
        return;
    }
    renderPlaybackRecordingsList();
}

function renderPlaybackRecordingsList() {
    const list = document.getElementById('playbackRecordingsList');
    if (!list) return;
    if (!playbackRecordingsCache.length) {
        list.innerHTML = '<div class="hint-text">No recordings found. Run and stop a simulation to create one.</div>';
        return;
    }
    list.innerHTML = playbackRecordingsCache.map((rec) => {
        const filename = escapeHtml(rec.filename || '');
        const title = escapeHtml(rec.exerciseName || rec.filename || 'Recording');
        const started = escapeHtml(rec.startedAt || rec.modifiedAt || '');
        const duration = rec.durationSimSec != null ? playbackFormatTime(rec.durationSimSec) : '--:--';
        const events = rec.eventCount != null ? `${rec.eventCount} events` : 'events unknown';
        return `
            <div class="playback-recording-item" data-recording-file="${filename}">
                <div class="playback-recording-title">${title}</div>
                <div class="playback-recording-meta">${started}<br>${escapeHtml(duration)} · ${escapeHtml(events)}<br>${filename}</div>
                <div class="playback-recording-actions">
                    <button type="button" class="btn btn-success playback-play-recording-btn" data-recording-file="${filename}">Play recording</button>
                    <button type="button" class="btn btn-danger playback-delete-recording-btn" data-recording-file="${filename}">Delete recording</button>
                </div>
            </div>`;
    }).join('');
    list.querySelectorAll('.playback-play-recording-btn').forEach(btn => {
        btn.addEventListener('click', () => loadPlaybackRecording(btn.dataset.recordingFile));
    });
    list.querySelectorAll('.playback-delete-recording-btn').forEach(btn => {
        btn.addEventListener('click', () => deletePlaybackRecording(btn.dataset.recordingFile));
    });
}

async function loadPlaybackRecording(filename) {
    if (!filename) return;
    stopPlaybackTimer();
    playbackSetStatus('Loading recording...');
    try {
        const resp = await fetch(`/api/recordings/${encodeURIComponent(filename)}`);
        const data = await resp.json();
        if (!resp.ok || !data.recording) throw new Error(data.error || 'Could not load recording');
        playbackCurrentRecording = data.recording;
        if (!playbackCurrentRecording.metadata || typeof playbackCurrentRecording.metadata !== 'object') playbackCurrentRecording.metadata = {};
        playbackCurrentRecording.metadata.filename = filename;
        preparePlaybackRecording();
    } catch (e) {
        playbackSetStatus('Could not load that recording.');
    }
}

async function deletePlaybackRecording(filename) {
    if (!filename) return;
    if (!confirm(`Delete recording "${filename}"?`)) return;
    stopPlaybackTimer();
    try {
        await fetch(`/api/recordings/${encodeURIComponent(filename)}`, { method: 'DELETE' });
    } catch (e) {}
    if (playbackCurrentRecording?.metadata?.filename === filename) resetPlaybackViewer();
    await refreshPlaybackRecordingsList();
}

function preparePlaybackRecording() {
    const rec = playbackCurrentRecording;
    const events = Array.isArray(rec?.events) ? rec.events : [];
    playbackSnapshotEvents = events
        .filter(ev => ev && ev.type === 'aircraft_snapshot' && Array.isArray(ev.data?.aircraft))
        .sort((a, b) => (Number(a.simSec) || 0) - (Number(b.simSec) || 0));
    playbackBounds = computePlaybackBounds(playbackSnapshotEvents);
    playbackCurrentSec = 0;

    const duration = playbackGetDuration(rec);
    const title = document.getElementById('playbackRecordingTitle');
    if (title) title.textContent = rec?.metadata?.exerciseName || 'Recording';
    playbackSetStatus(`${rec?.metadata?.startedAt || ''} · ${playbackSnapshotEvents.length} snapshots`);
    const scrub = document.getElementById('playbackScrubBar');
    if (scrub) {
        scrub.min = '0';
        scrub.max = String(Math.max(0, duration));
        scrub.value = '0';
        scrub.disabled = duration <= 0 || !playbackSnapshotEvents.length;
    }
    if (playbackSnapshotEvents.length) {
        document.getElementById('playRecordingBtn')?.removeAttribute('disabled');
        document.getElementById('pauseRecordingBtn')?.removeAttribute('disabled');
    } else {
        document.getElementById('playRecordingBtn')?.setAttribute('disabled', 'disabled');
        document.getElementById('pauseRecordingBtn')?.setAttribute('disabled', 'disabled');
    }
    updatePlaybackTimeLabel();
    drawPlaybackFrame();
}

function computePlaybackBounds(snapshotEvents) {
    let minLat = Infinity, maxLat = -Infinity, minLon = Infinity, maxLon = -Infinity;
    snapshotEvents.forEach(ev => {
        (ev.data?.aircraft || []).forEach(ac => {
            const lat = Number(ac.lat);
            const lon = Number(ac.lon);
            if (!Number.isFinite(lat) || !Number.isFinite(lon)) return;
            minLat = Math.min(minLat, lat);
            maxLat = Math.max(maxLat, lat);
            minLon = Math.min(minLon, lon);
            maxLon = Math.max(maxLon, lon);
        });
    });
    if (![minLat, maxLat, minLon, maxLon].every(Number.isFinite)) {
        return { minLat: -1, maxLat: 1, minLon: -1, maxLon: 1 };
    }
    if (Math.abs(maxLat - minLat) < 0.01) { minLat -= 0.005; maxLat += 0.005; }
    if (Math.abs(maxLon - minLon) < 0.01) { minLon -= 0.005; maxLon += 0.005; }
    return { minLat, maxLat, minLon, maxLon };
}

function getPlaybackSnapshotAt(sec) {
    if (!playbackSnapshotEvents.length) return null;
    let best = playbackSnapshotEvents[0];
    for (const ev of playbackSnapshotEvents) {
        if ((Number(ev.simSec) || 0) > sec) break;
        best = ev;
    }
    return best;
}

function getPlaybackMapViewAt(sec) {
    const initial = playbackCurrentRecording?.metadata?.initialView || {};
    const view = {
        zoom: Number.isFinite(Number(initial.zoom)) ? Number(initial.zoom) : null,
        panX: Number.isFinite(Number(initial.panX)) ? Number(initial.panX) : 0,
        panY: Number.isFinite(Number(initial.panY)) ? Number(initial.panY) : 0
    };
    const events = Array.isArray(playbackCurrentRecording?.events) ? playbackCurrentRecording.events : [];
    events.forEach(ev => {
        if (!ev || (Number(ev.simSec) || 0) > sec) return;
        const d = ev.data || {};
        if (ev.type === 'map_initial_view') {
            if (Number.isFinite(Number(d.zoom))) view.zoom = Number(d.zoom);
            if (Number.isFinite(Number(d.panX))) view.panX = Number(d.panX);
            if (Number.isFinite(Number(d.panY))) view.panY = Number(d.panY);
        } else if (ev.type === 'map_zoom_in' || ev.type === 'map_zoom_out') {
            if (Number.isFinite(Number(d.newZoom))) view.zoom = Number(d.newZoom);
            if (Number.isFinite(Number(d.newPanX))) view.panX = Number(d.newPanX);
            if (Number.isFinite(Number(d.newPanY))) view.panY = Number(d.newPanY);
        } else if (ev.type === 'map_pan_end' || ev.type === 'map_center') {
            if (Number.isFinite(Number(d.newPanX))) view.panX = Number(d.newPanX);
            if (Number.isFinite(Number(d.newPanY))) view.panY = Number(d.newPanY);
        }
    });
    return view;
}

function getPlaybackMeasurementsAt(sec) {
    const events = Array.isArray(playbackCurrentRecording?.events) ? playbackCurrentRecording.events : [];
    const byKey = new Map();
    events.forEach((ev) => {
        if (!ev) return;
        const t = Number(ev.simSec) || 0;
        if (t > sec) return;
        const d = ev.data || {};
        if (ev.type === 'measurement_add' && d.measurement) {
            const key = d.measurement.id || d.measurement.recordingId || `idx:${d.index ?? byKey.size}`;
            const visibleFrom = Number(d.visibleFromSimSec);
            byKey.set(String(key), {
                ...simulationRecordingClone(d.measurement, {}),
                _recordingKey: String(key),
                _visibleFromSimSec: Number.isFinite(visibleFrom) ? visibleFrom : t
            });
        } else if (ev.type === 'measurement_delete') {
            const key = d.measurement?.id || d.measurement?.recordingId || `idx:${d.index ?? ''}`;
            if (key !== 'idx:') byKey.delete(String(key));
        }
    });
    return Array.from(byKey.values()).filter(m => {
        const from = Number(m._visibleFromSimSec);
        return !Number.isFinite(from) || from <= sec;
    }).map(m => {
        const clean = { ...m };
        delete clean._recordingKey;
        delete clean._visibleFromSimSec;
        return clean;
    });
}

function buildPlaybackSimulationDataAt(sec) {
    const base = playbackCurrentRecording?.playbackData?.simulationData;
    const snapshot = getPlaybackSnapshotAt(sec);
    if (!base || !snapshot) return null;
    const data = simulationRecordingClone(base, null);
    if (!data || !Array.isArray(data.aircraft)) return null;
    const byId = new Map((snapshot.data?.aircraft || []).map(ac => [String(ac.aircraftId), ac]));
    data.aircraft = data.aircraft.map(ac => {
        if (!ac || ac.id == null) return ac;
        const snap = byId.get(String(ac.id));
        if (!snap) return ac;
        const labelState = (snap.labelState && typeof snap.labelState === 'object') ? snap.labelState : {};
        const restored = {
            ...ac,
            ...labelState,
            callsign: snap.callsign || ac.callsign,
            labelOffsetX: Number.isFinite(Number(snap.labelOffsetX)) ? Number(snap.labelOffsetX) : ac.labelOffsetX,
            labelOffsetY: Number.isFinite(Number(snap.labelOffsetY)) ? Number(snap.labelOffsetY) : ac.labelOffsetY,
            labelLeaderOffsetToCenter: !!snap.labelLeaderOffsetToCenter,
            hideLabel: !!snap.hideLabel,
            publishedModeCFeet: Number.isFinite(Number(snap.modeCFeet)) ? Number(snap.modeCFeet) : ac.publishedModeCFeet,
            modeCFeet: Number.isFinite(Number(snap.modeCFeet)) ? Number(snap.modeCFeet) : ac.modeCFeet,
            publishedHeadingDeg: Number.isFinite(Number(snap.heading)) ? Number(snap.heading) : ac.publishedHeadingDeg,
            currentHeadingDeg: Number.isFinite(Number(snap.heading)) ? Number(snap.heading) : ac.currentHeadingDeg,
            publishedLabelGsKt: Number.isFinite(Number(snap.gs)) ? Number(snap.gs) : ac.publishedLabelGsKt,
            _playbackState: {
                lat: Number(snap.lat),
                lon: Number(snap.lon),
                gs: Number(snap.gs),
                simSec: Number(snapshot.simSec) || sec
            }
        };
        if (Array.isArray(snap.labelLines)) restored._playbackLabelLines = snap.labelLines.map(line => sanitizePlaybackLabelLineText(line));
        return restored;
    });
    return data;
}

function drawPlaybackFrameWithSimulationRenderer(canvas) {
    const playbackData = playbackCurrentRecording?.playbackData;
    if (!playbackData?.simulationData || !playbackSnapshotEvents.length) return false;
    const data = buildPlaybackSimulationDataAt(playbackCurrentSec);
    if (!data) return false;
    const ctx = canvas.getContext('2d');
    if (!ctx) return false;

    const prev = {
        simulationCanvas,
        simulationCtx,
        simulationData: window.simulationData,
        simulationSimTimeMs,
        simulationSettings: simulationRecordingClone(simulationSettings, null),
        simulationMap: simulationRecordingClone(simulationMap, null),
        simulationStyle: simulationRecordingClone(simulationStyle, null),
        simulationLabelZOrder: simulationRecordingClone(simulationLabelZOrder, []),
        simulationAircraftFreeTextById: simulationRecordingClone(simulationAircraftFreeTextById, {}),
        measurements: simulationRecordingClone(measurements, []),
        simulationJoinedSessionId,
        simulationJoinBoundaryIdFilter,
        simulationIsMonitorOnly,
        simulationZoomLevel,
        simulationPanX,
        simulationPanY
    };

    try {
        simulationCanvas = canvas;
        simulationCtx = ctx;
        window.simulationData = data;
        simulationSimTimeMs = playbackCurrentSec * 1000;
        simulationJoinedSessionId = null;
        simulationJoinBoundaryIdFilter = null;
        simulationIsMonitorOnly = true;
        if (playbackData.simulationSettings) simulationSettings = simulationRecordingClone(playbackData.simulationSettings, simulationSettings);
        if (playbackData.simulationMap) simulationMap = simulationRecordingClone(playbackData.simulationMap, simulationMap);
        if (playbackData.simulationStyle) simulationStyle = simulationRecordingClone(playbackData.simulationStyle, simulationStyle);
        simulationLabelZOrder = Array.isArray(playbackData.labelZOrder)
            ? playbackData.labelZOrder.slice()
            : data.aircraft.map(ac => ac && ac.id).filter(Boolean);
        const snap = getPlaybackSnapshotAt(playbackCurrentSec);
        simulationAircraftFreeTextById = {};
        (snap?.data?.aircraft || []).forEach(ac => {
            if (ac && ac.aircraftId != null && ac.freeText) simulationAircraftFreeTextById[String(ac.aircraftId)] = String(ac.freeText);
        });
        measurements = getPlaybackMeasurementsAt(playbackCurrentSec);
        const view = getPlaybackMapViewAt(playbackCurrentSec);
        if (Number.isFinite(Number(view.zoom)) && Number(view.zoom) > 0) simulationZoomLevel = Number(view.zoom);
        else {
            calculateSimulationAspectRatio();
            autoFitSimulationZoom();
        }
        simulationPanX = Number.isFinite(Number(view.panX)) ? Number(view.panX) : 0;
        simulationPanY = Number.isFinite(Number(view.panY)) ? Number(view.panY) : 0;
        drawSimulationCanvas();
        return true;
    } catch (e) {
        return false;
    } finally {
        simulationCanvas = prev.simulationCanvas;
        simulationCtx = prev.simulationCtx;
        window.simulationData = prev.simulationData;
        simulationSimTimeMs = prev.simulationSimTimeMs;
        if (prev.simulationSettings) simulationSettings = prev.simulationSettings;
        if (prev.simulationMap) simulationMap = prev.simulationMap;
        if (prev.simulationStyle) simulationStyle = prev.simulationStyle;
        simulationLabelZOrder = prev.simulationLabelZOrder;
        simulationAircraftFreeTextById = prev.simulationAircraftFreeTextById;
        measurements = prev.measurements;
        simulationJoinedSessionId = prev.simulationJoinedSessionId;
        simulationJoinBoundaryIdFilter = prev.simulationJoinBoundaryIdFilter;
        simulationIsMonitorOnly = prev.simulationIsMonitorOnly;
        simulationZoomLevel = prev.simulationZoomLevel;
        simulationPanX = prev.simulationPanX;
        simulationPanY = prev.simulationPanY;
    }
}

function drawPlaybackFrame() {
    const canvas = document.getElementById('playbackCanvas');
    if (!canvas) return;
    resizePlaybackCanvas();
    if (drawPlaybackFrameWithSimulationRenderer(canvas)) {
        updatePlaybackSubtitles();
        return;
    }
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = '#07111f';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.strokeStyle = 'rgba(74, 144, 226, 0.18)';
    ctx.lineWidth = 1;
    for (let x = 0; x <= canvas.width; x += 80) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, canvas.height);
        ctx.stroke();
    }
    for (let y = 0; y <= canvas.height; y += 80) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(canvas.width, y);
        ctx.stroke();
    }

    if (!playbackCurrentRecording || !playbackSnapshotEvents.length) {
        ctx.fillStyle = 'rgba(245, 247, 250, 0.65)';
        ctx.font = '16px Arial';
        ctx.textAlign = 'center';
        ctx.fillText('Select a recording to preview playback', canvas.width / 2, canvas.height / 2);
        return;
    }

    const snapshot = getPlaybackSnapshotAt(playbackCurrentSec);
    const bounds = playbackBounds || computePlaybackBounds(playbackSnapshotEvents);
    const pad = 50;
    const latRange = bounds.maxLat - bounds.minLat;
    const lonRange = bounds.maxLon - bounds.minLon;
    const project = (lat, lon) => {
        const x = pad + ((lon - bounds.minLon) / lonRange) * Math.max(1, canvas.width - pad * 2);
        const y = canvas.height - pad - ((lat - bounds.minLat) / latRange) * Math.max(1, canvas.height - pad * 2);
        return { x, y };
    };

    (snapshot?.data?.aircraft || []).forEach((ac) => {
        const lat = Number(ac.lat);
        const lon = Number(ac.lon);
        if (!Number.isFinite(lat) || !Number.isFinite(lon)) return;
        const p = project(lat, lon);
        ctx.fillStyle = '#4a90e2';
        ctx.beginPath();
        ctx.arc(p.x, p.y, 5, 0, Math.PI * 2);
        ctx.fill();
        ctx.strokeStyle = 'rgba(245, 247, 250, 0.85)';
        ctx.stroke();
        ctx.fillStyle = '#f5f7fa';
        ctx.font = '12px Arial';
        ctx.textAlign = 'left';
        const label = `${ac.callsign || ac.aircraftId || 'AC'}${ac.modeCFeet != null ? ` ${Math.round(ac.modeCFeet / 100)}` : ''}`;
        ctx.fillText(label, p.x + 8, p.y - 8);
    });

    ctx.fillStyle = 'rgba(245, 247, 250, 0.85)';
    ctx.font = '13px Arial';
    ctx.textAlign = 'left';
    ctx.fillText(`T+${playbackFormatTime(playbackCurrentSec)}`, 14, 24);
    updatePlaybackSubtitles();
}

function updatePlaybackTimeLabel() {
    const label = document.getElementById('playbackTimeLabel');
    const duration = playbackGetDuration(playbackCurrentRecording);
    if (label) label.textContent = `${playbackFormatTime(playbackCurrentSec)} / ${playbackFormatTime(duration)}`;
}

function getPlaybackSubtitleEventsAt(sec) {
    if (!playbackSubtitlesEnabled) return [];
    const events = Array.isArray(playbackCurrentRecording?.events) ? playbackCurrentRecording.events : [];
    const candidates = events
        .filter(ev => {
            const t = Number(ev?.simSec);
            if (!Number.isFinite(t)) return false;
            if (t > sec || sec - t > 4) return false;
            if (ev.type === 'subtitle') return !!getPlaybackSubtitleLine(ev);
            if (ev.type !== 'debug_log') return false;
            const kind = (ev.data?.kind || '').toString().toUpperCase();
            return kind === 'CMD' && !!getPlaybackSubtitleLine(ev);
        });
    const explicitSubtitles = candidates.filter(ev => ev.type === 'subtitle');
    return candidates
        .filter(ev => {
            if (ev.type === 'subtitle') return true;
            const t = Number(ev?.simSec) || 0;
            const aid = (ev.aircraftId || ev.data?.aircraftId || '').toString();
            const line = getPlaybackSubtitleLine(ev);
            return !explicitSubtitles.some(sub => {
                const st = Number(sub?.simSec) || 0;
                const said = (sub.aircraftId || sub.data?.aircraftId || '').toString();
                return Math.abs(st - t) <= 0.25 && said === aid && getPlaybackSubtitleLine(sub) === line;
            });
        })
        .sort((a, b) => (Number(a.simSec) || 0) - (Number(b.simSec) || 0));
}

function getPlaybackWaypointNameById(wpId) {
    const id = wpId != null ? String(wpId).trim() : '';
    if (!id) return '';
    const data = playbackCurrentRecording?.playbackData?.simulationData || {};
    const wps = Array.isArray(data.waypoints) ? data.waypoints : [];
    const wp = wps.find(w => w && String(w.id).trim() === id);
    return (wp?.name || id).toString().trim().toUpperCase();
}

function sanitizePlaybackLabelLineText(line) {
    return String(line || '').replace(/\bG(\d+\.\d+)\b/g, (_match, value) => {
        const n = Number(value);
        return Number.isFinite(n) ? `G${Math.round(n)}` : `G${value}`;
    });
}

function getPlaybackSubtitleLine(ev) {
    if (!ev) return '';
    if (ev.type === 'subtitle') {
        return (ev.data?.text || '').toString().trim();
    }
    const msg = (ev.data?.msg || '').toString().trim();
    let m = msg.match(/^ALV\b.*?FL?(\d{1,3})\b/i);
    if (m) return `ALV input > ${String(m[1]).padStart(3, '0')}`;
    m = msg.match(/^HDG\s+(\d{1,3})\b/i);
    if (m) return `HDG input > ${String(m[1]).padStart(3, '0')}`;
    m = msg.match(/^DCT\s+([A-Z0-9_-]+)\b/i);
    if (m && !/^DCT\s+path\b/i.test(msg)) return `DCT to > ${m[1].toUpperCase()}`;
    m = msg.match(/^HOLD ARM at wpId=(.+)$/i);
    if (m) return `Holding input > Enter holding at ${getPlaybackWaypointNameById(m[1]) || m[1]}`;
    if (/^HOLD (EXIT|CANCEL)\b/i.test(msg)) return 'Holding input > EXIT holding';
    if (/^HOLD label clear\b/i.test(msg)) return 'Holding input > EXIT holding';
    return '';
}

function updatePlaybackSubtitles() {
    const overlay = document.getElementById('playbackSubtitlesOverlay');
    if (!overlay) return;
    overlay.innerHTML = '';
    if (!playbackSubtitlesEnabled || !playbackCurrentRecording) {
        overlay.style.display = 'none';
        return;
    }
    const items = getPlaybackSubtitleEventsAt(playbackCurrentSec);
    overlay.style.display = items.length ? 'flex' : 'none';
    items.forEach(ev => {
        const div = document.createElement('div');
        div.className = 'playback-subtitle-item';
        const ts = playbackFormatTime(Number(ev.simSec) || 0);
        const who = (ev.callsign || ev.data?.callsign || ev.aircraftId || ev.data?.aircraftId || '').toString().trim();
        const msg = getPlaybackSubtitleLine(ev);
        div.textContent = `[${ts}] ${who ? `${who} > ` : ''}${msg}`;
        overlay.appendChild(div);
    });
}

function setPlaybackCurrentSec(sec) {
    const duration = playbackGetDuration(playbackCurrentRecording);
    playbackCurrentSec = Math.max(0, Math.min(duration, Number(sec) || 0));
    const scrub = document.getElementById('playbackScrubBar');
    if (scrub && String(scrub.value) !== String(playbackCurrentSec)) scrub.value = String(playbackCurrentSec);
    updatePlaybackTimeLabel();
    updatePlaybackSubtitles();
    drawPlaybackFrame();
}

function playCurrentRecording() {
    if (!playbackCurrentRecording || !playbackSnapshotEvents.length) return;
    stopPlaybackTimer();
    const duration = playbackGetDuration(playbackCurrentRecording);
    if (playbackCurrentSec >= duration) setPlaybackCurrentSec(0);
    playbackStartedRealMs = Date.now();
    playbackStartedSimSec = playbackCurrentSec;
    playbackTimerId = setInterval(() => {
        const next = playbackStartedSimSec + (Date.now() - playbackStartedRealMs) / 1000;
        setPlaybackCurrentSec(next);
        if (next >= duration) stopPlaybackTimer();
    }, 100);
}

function updatePlaybackFullscreenButton() {
    const btn = document.getElementById('playbackFullscreenBtn');
    if (!btn) return;
    const fsEl = document.fullscreenElement || document.webkitFullscreenElement;
    const isFull = !!(fsEl && fsEl.classList && fsEl.classList.contains('playback-viewer-panel'));
    btn.textContent = isFull ? 'Exit Full Screen' : 'Full Screen';
}

function togglePlaybackFullscreen() {
    const panel = document.querySelector('#playbackModal .playback-viewer-panel');
    if (!panel) return;
    const fsEl = document.fullscreenElement || document.webkitFullscreenElement;
    const isFull = !!(fsEl && fsEl.classList && fsEl.classList.contains('playback-viewer-panel'));
    if (isFull) {
        const exit = document.exitFullscreen || document.webkitExitFullscreen;
        if (exit) exit.call(document);
    } else {
        const req = panel.requestFullscreen || panel.webkitRequestFullscreen;
        if (req) req.call(panel);
    }
}

function togglePlaybackSubtitles() {
    playbackSubtitlesEnabled = !playbackSubtitlesEnabled;
    updatePlaybackSubtitlesButton();
    updatePlaybackSubtitles();
}

function setImportDataCheckboxes(className, checked) {
    document.querySelectorAll('#importDataModal .' + className).forEach(el => {
        el.checked = checked;
    });
}

const DEFAULT_AI_PILOT_GENERAL_INSTRUCTIONS = `AI Pilot — you are a pseudo-pilot answering an air traffic controller.

OUTPUT
Reply with JSON only, exactly two string fields:
{"tts":"<spoken readback with placeholders>","command":"<simulator command>"}
No markdown, no code fences, no labels, no extra keys, no text outside the JSON.

PROCESS (reason internally, never reveal it)
1. Identify the aircraft from the exercise aircraft callsign list (see IDENTIFICATION).
2. Build command: the matched ICAO callsign + supported tokens only.
3. Validate command, then write tts as a readback that uses PLACEHOLDERS for the cleared values and ends with {CALLSIGN}.
tts and command always refer to the same aircraft.

CALLSIGNS
The only valid callsigns are in the exercise aircraft callsign list appended for the running exercise; this prompt contains none.
- command begins with the exact ICAO callsign from that list, copied character-for-character.
- tts ends with {CALLSIGN}; never spell or speak the callsign yourself.
- Never invent, infer, or echo a garbled callsign, and never use one not on the list.

IDENTIFICATION (apply in order, against the exercise list)
1. Flight-number digits (primary): match the spoken/numeric digit group to the digit portion of a list callsign. Prefer digits over airline names.
2. Phonetic suffix + digits: if digits are ambiguous, map phonetic words to suffix letters and match.
3. Airline/operator name + digits (fallback only): when steps 1–2 fail.
Speech-to-text often garbles airline names but keeps digits — try digits first.
If no list entry matches: tts "Say again", command "".

FIELD: command (machine tokens only)
- Format: ICAO_CALLSIGN TOKEN [VALUES] ... — space-separated tokens, never a sentence or English phraseology.
- No words, punctuation, QNH, or spoken callsigns.

FIELD: tts (spoken readback — placeholders + spoken phraseology)
tts contains two kinds of content; combine them into ONE natural pilot reply that ends with {CALLSIGN}.

A) PLACEHOLDERS — for these cleared values use the placeholder ONLY; the simulator expands each into correct phraseology from the aircraft's live state (climb/descend, turn direction, increase/reduce). Do NOT speak these values or their verbs yourself:
- {ALVnnn} — assigned level, the same 3 digits as the ALV command (e.g. {ALV340}, {ALV030}).
- {TLHnnn} / {TRHnnn} — turn left / turn right to heading (e.g. {TLH200}).
- {HDGnnn} — fly heading, shortest turn (e.g. {HDG270}).
- {IASnnn} — indicated airspeed (e.g. {IAS280}).
- {Mnnn} — Mach, hundredths (e.g. {M078} = Mach 0.78).
- {CALLSIGN} — the aircraft's spoken callsign; MANDATORY as the LAST item of every non-empty tts.

B) SPOKEN PHRASEOLOGY — for EVERYTHING that has no placeholder, write the readback yourself, fully, in standard ICAO pilot phraseology. This covers DCT, RTE, HOLD/EXITHOLD, ROCD (rate), ILS/approach, QNH, frequency/contact changes, acknowledgements, and free questions/answers. NEVER read a raw command token aloud — translate it into how a pilot actually speaks:
- DCT BEMBO → "proceeding direct BEMBO" (NOT "DCT BEMBO")
- RTE LIMKO DENKO → "routing LIMKO DENKO"
- HOLD BEMBO → "holding at BEMBO"; EXITHOLD → "leaving the hold"
- ILS08R → "cleared ILS runway zero eight right"
- ROCD rate → full English number with thousands + "feet per minute" (1200 → "one thousand two hundred feet per minute"; never digit-by-digit, never drop "thousand")
- Frequency/contact → read the frequency back naturally; repeat QNH when given.
Never put ICAO codes or raw command tokens (TLH, ALV, DCT, HOLD, ILS, ...) in the spoken text — placeholders for group A, proper phraseology for group B.
Example shape: command "ETD855 DCT BEMBO ALV340" → tts "Proceeding direct BEMBO, {ALV340}, {CALLSIGN}".

EXERCISE CONTEXT INFORMATION
The exercise may include Context Information (set in the AI Pilot tab when editing the exercise). When present it is appended below as "Exercise-specific context" and is also resent with the General Instructions. Treat it as an extension of these general instructions and follow it — it may add scenario facts, role-play details, or special replies the pilot should give. It never overrides the JSON output format or the callsign rules.

COMMAND TOKENS
- Heading: TLHnnn (left), TRHnnn (right), HDGnnn (fly heading) — 3 digits.
- Direct/route/hold: DCT FIX | RTE FIX1 FIX2 ... | HOLD FIX | EXITHOLD (fixes from the exercise lists).
- Altitude: ALVnnn — 3 digits, no units. FL → those 3 digits (FL240 → ALV240); feet → feet/100 (3000 ft → ALV030).
- Speed: IASnnn, or Mach as Mnnn (Mach 0.78 → M078).
- Rate of climb/descent: ROCDfpm, signed, digits only (climb 1500 → ROCD1500; descent 2500 → ROCD-2500). Exact controller value 100–5000, do not round. Use ALV alone for a level with no rate; use ROCD only when a rate is instructed.
- ILS/approach: ILSnnX (e.g. ILS08R).
- Label transfer-in: LBL_TIN-nnn (exercise initial-call scripts only; never spoken in tts).

COMPOUND (several instructions, same aircraft)
- command: chain tokens after one callsign, or repeat the callsign per clause separated by semicolons.
- tts: one readback with the matching placeholders, ending with {CALLSIGN}.

ON FREQUENCY (Single User live session)
Each controller transmission includes LIVE SESSION STATE listing every aircraft as onFrequency=yes/no.
- yes: respond normally when addressed.
- no: the aircraft is not on your frequency — respond {"tts":"","command":""} even if the controller uses its callsign.

FREQUENCIES & HANDOFF
Sector names and frequencies are in the exercise data and LIVE SESSION STATE. When told to contact another sector, read back the frequency in plain tts (command "" unless a separate token clearance also applies); "point" or "decimal" marks the decimal separator. After a contact-handoff readback the simulator sets that aircraft off your frequency.

SCRIPTS (exercise timeline, not live RTF)
[SCRIPT EVENT] messages carry fields: Silent, Use AI response for TTS, optional preset TTS, optional pre-approved command, instruction line.
- Silent=yes: respond {"tts":"","command":""}.
- Silent=no: respond with JSON per the rules above.
Newer events supersede older context for the same aircraft.

SUMMARY
- JSON only: tts + command, same aircraft.
- Build and validate command first, then derive tts from it.
- Placeholders ({ALV/TLH/TRH/HDG/IAS/M}) for cleared values; write every other readback yourself in standard phraseology (never speak raw tokens like DCT/HOLD/ILS — e.g. DCT → "proceeding direct ...").
- tts ends with {CALLSIGN}; never spell or infer the callsign, level verb, turn direction, or speed change yourself.
- Follow any Exercise Context Information as an extension of these instructions.
- Unknown aircraft → tts "Say again", command "".
- Off-frequency aircraft → {"tts":"","command":""}.
- No supported instruction → spoken tts readback ending with {CALLSIGN}, command "".
- tts is never empty except [SCRIPT EVENT] Silent=yes.`;

let adminUnlockedPassword = '';
let serverDefaultAiPilotGeneralInstructions = '';
let adminAiPilotGeneralInstructions = DEFAULT_AI_PILOT_GENERAL_INSTRUCTIONS;

// Prefer the canonical default supplied by the server (always current); fall back to the bundled copy.
function getDefaultAiPilotGeneralInstructions() {
    return (typeof serverDefaultAiPilotGeneralInstructions === 'string' && serverDefaultAiPilotGeneralInstructions.trim())
        ? serverDefaultAiPilotGeneralInstructions
        : DEFAULT_AI_PILOT_GENERAL_INSTRUCTIONS;
}
const DEFAULT_ADMIN_OPENAI_MODEL = 'gpt-5.4-mini';
let adminOpenAiModel = DEFAULT_ADMIN_OPENAI_MODEL;
let adminRecordSimulations = true;
let activeLabelEditorContext = 'simulation'; // 'simulation' | 'adminGlobal'

function isAdminRecordSimulationsEnabled() {
    return !!adminRecordSimulations;
}

