async function unlockAdminSettings() {
    const password = document.getElementById('adminUnlockPassword')?.value || '';
    if (!password) {
        setAdminUnlockError('Enter the Admin password.');
        return;
    }
    setAdminUnlockError('');
    try {
        const resp = await fetch('/api/admin/unlock', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ password })
        });
        const data = await resp.json().catch(() => ({}));
        if (!resp.ok || data.ok === false) throw new Error(data.error || 'Admin unlock failed.');
        adminUnlockedPassword = password;
        if (typeof data.defaultAiPilotGeneralInstructions === 'string' && data.defaultAiPilotGeneralInstructions.trim()) {
            serverDefaultAiPilotGeneralInstructions = data.defaultAiPilotGeneralInstructions;
        }
        adminAiPilotGeneralInstructions = typeof data.aiPilotGeneralInstructions === 'string' && data.aiPilotGeneralInstructions.trim()
            ? data.aiPilotGeneralInstructions
            : getDefaultAiPilotGeneralInstructions();
        adminOpenAiModel = normalizeAdminOpenAiModel(data.openaiModel);
        adminRecordSimulations = data.recordSimulations !== false;
        applyAdminGlobalLabelFromServer(data);
        closeModal('adminUnlockModal');
        openAdminSettingsModal(data.openaiApiKey || '', adminAiPilotGeneralInstructions, adminOpenAiModel, adminRecordSimulations);
    } catch (err) {
        setAdminUnlockError(err?.message || 'Admin unlock failed.');
    }
}

