function normalizeLabelLayoutFromServer(layout) {
    const def = JSON.parse(JSON.stringify(SIM_SETTINGS_DEFAULTS.labelLayout));
    if (!Array.isArray(layout) || layout.length !== 5) return def;
    return layout.map(row => {
        const r = Array.isArray(row) ? row : [];
        return Array.from({ length: 5 }, (_, c) => ({
            field: (r[c]?.field || '').toString(),
            freeText: (r[c]?.freeText || '').toString()
        }));
    });
}

function normalizeLabelSetupsFromServer(setups) {
    if (!Array.isArray(setups)) return [];
    return setups.filter(s =>
        s &&
        typeof s === 'object' &&
        s.id &&
        s.name &&
        Array.isArray(s.layout) &&
        s.layout.length === 5 &&
        s.layout.every(r => Array.isArray(r) && r.length === 5)
    );
}

function applyAdminGlobalLabelFromServer(data) {
    adminGlobalLabelSettings.labelLayout = normalizeLabelLayoutFromServer(data?.globalLabelLayout);
    adminGlobalLabelSettings.labelSetupId = (data?.globalLabelSetupId || '').toString();
    adminGlobalLabelSetups = normalizeLabelSetupsFromServer(data?.globalLabelSetups);
    adminGlobalLoadedLabelSetupId = adminGlobalLabelSettings.labelSetupId;
    const setup = adminGlobalLabelSetups.find(s => s && s.id === adminGlobalLabelSettings.labelSetupId);
    adminGlobalLoadedLabelSetupName = setup ? (setup.name || '').toString() : '';
    applyAdminSingleUserLabelFromServer(data);
    applyAdminHostedSessionsLabelFromServer(data);
    applyLabelSimulationDefaultsFromServer(data);
}

function normalizeSingleUserLabelProfilesFromServer(profiles) {
    if (!Array.isArray(profiles)) return [];
    return profiles.filter(p =>
        p &&
        typeof p === 'object' &&
        p.id &&
        p.name &&
        p.fstLabelSetupIds &&
        typeof p.fstLabelSetupIds === 'object'
    ).map(p => ({
        id: (p.id || '').toString(),
        name: (p.name || '').toString(),
        fstLabelSetupIds: normalizeAdminFstLabelSetupIds(p.fstLabelSetupIds),
        createdAt: p.createdAt,
        updatedAt: p.updatedAt
    }));
}

function applyAdminSingleUserLabelFromServer(data) {
    adminSingleUserLabelProfiles = normalizeSingleUserLabelProfilesFromServer(data?.singleUserLabelProfiles);
    adminSingleUserAssignedProfileId = (data?.singleUserLabelAssignedProfileId || '').toString();
}

function applyAdminHostedSessionsLabelFromServer(data) {
    adminHostedSessionsLabelProfiles = normalizeHostedSessionsLabelProfilesFromServer(data?.hostedSessionsLabelProfiles);
    adminHostedSessionsAssignedProfileId = (data?.hostedSessionsLabelAssignedProfileId || '').toString();
}

function applyLabelSimulationDefaultsFromServer(data) {
    labelSimulationDefaults.defaultGenericLabelSetupId = (data?.defaultGenericLabelSetupId || '').toString();
    labelSimulationDefaults.defaultSingleUserLabelProfileId = (data?.defaultSingleUserLabelProfileId || '').toString();
    labelSimulationDefaults.defaultHostedSessionsLabelProfileId = (data?.defaultHostedSessionsLabelProfileId || '').toString();
    adminGenericLabelSetupSelection = labelSimulationDefaults.defaultGenericLabelSetupId;
    adminSingleUserProfileMainSelection = labelSimulationDefaults.defaultSingleUserLabelProfileId;
    adminHostedSessionsProfileMainSelection = labelSimulationDefaults.defaultHostedSessionsLabelProfileId;
}

