function findLabelSetupByName(setups, name) {
    const target = (name || '').trim();
    if (!target) return null;
    return (setups || []).find(s => s && (s.name || '').trim() === target) || null;
}

function generateLabelSetupCopyName(baseName, setups) {
    const base = (baseName || '').trim();
    let copyNum = 1;
    let candidate = `${base} <copy ${copyNum}>`;
    const names = new Set((setups || []).map(s => (s?.name || '').trim()));
    while (names.has(candidate)) {
        copyNum += 1;
        candidate = `${base} <copy ${copyNum}>`;
    }
    return candidate;
}

