async function commitAdminGlobalLabelSetupSave({ name, layout, mode, existingSetupId }) {
    const setups = loadLabelSetupsForActiveContext().slice();
    const layoutCopy = JSON.parse(JSON.stringify(layout || createEmptyLabelLayout()));
    const trimmedName = (name || '').trim();
    if (!trimmedName) throw new Error('Please enter a name for this label setup.');

    if (mode === 'overwrite') {
        const setup = setups.find(s => s && s.id === existingSetupId);
        if (!setup) throw new Error('Could not find the setup to overwrite.');
        setup.name = trimmedName;
        setup.layout = layoutCopy;
        setup.updatedAt = new Date().toISOString();
    } else {
        const newName = mode === 'copy'
            ? generateLabelSetupCopyName(trimmedName, setups)
            : trimmedName;
        if (findLabelSetupByName(setups, newName)) {
            throw new Error(`A setup named "${newName}" already exists.`);
        }
        setups.push({
            id: `lbl_${Date.now()}_${Math.random().toString(16).slice(2)}`,
            name: newName,
            layout: layoutCopy,
            createdAt: new Date().toISOString()
        });
    }

    await persistAdminGlobalLabelSetupChanges(setups);
    resetLabelEditorToEmptyState();
}

function beginAdminGlobalInlineLabelSetupSave() {
    const nameEl = document.getElementById('labelSetupName');
    const name = (nameEl?.value || '').trim();
    if (!name) {
        alert('Please enter a name for this label setup.');
        return;
    }
    applySimulationLabelEditorControlsToState();
    const labelSettings = getLabelEditorSettings();
    const layout = JSON.parse(JSON.stringify(labelSettings.labelLayout || createEmptyLabelLayout()));
    const setups = loadLabelSetupsForActiveContext();
    const existing = findLabelSetupByName(setups, name);
    if (existing) {
        openLabelSetupSaveConfirmModal({
            context: 'globalLabelSetup',
            name,
            layout,
            existingId: existing.id
        });
        return;
    }
    commitAdminGlobalLabelSetupSave({ name, layout, mode: 'new' }).catch(err => {
        alert(err?.message || 'Could not save label setup.');
    });
}

