// Render sectors for selection (Step 1)
function renderSectorsForSelection() {
    const sectorsList = document.getElementById('sectorsList');
    const sectors = getSectors();
    const exercises = getExercises();

    if (sectors.length === 0) {
        sectorsList.innerHTML = `
            <div class="empty-state">
                <div class="empty-state-icon">📭</div>
                <div class="empty-state-text">No sectors created yet. Create a sector in Settings to get started.</div>
            </div>
        `;
        return;
    }

    sectorsList.innerHTML = sectors.map(sector => {
        const sectorExercises = exercises.filter(ex => ex.sectorId === sector.id);
        const exerciseCount = sectorExercises.length;
        
        return `
            <div class="sector-card" data-sector-id="${sector.id}">
                <div class="sector-card-name">${sector.name}</div>
                ${sector.description ? `<div class="sector-card-description">${sector.description}</div>` : ''}
                <div class="sector-card-description" style="margin-top: 0.5rem; opacity: 0.6;">
                    ${exerciseCount} ${exerciseCount === 1 ? 'exercise' : 'exercises'} available
                </div>
            </div>
        `;
    }).join('');

    // Add click handlers to sector cards
    document.querySelectorAll('.sector-card').forEach(card => {
        card.addEventListener('click', function() {
            const sectorId = this.dataset.sectorId;
            selectSector(sectorId);
        });
    });
}

function formatSimulationExerciseAirspaceTitle(exerciseName, airspaceName) {
    const ex = (exerciseName || '').toString().trim() || '—';
    const ap = (airspaceName || '').toString().trim() || '—';
    return `Exercise: ${ex} / Airspace: ${ap}`;
}

function getJoinerSelectedAtcSectorDisplayName() {
    if (!simulationJoinAtcSectorId || !window.simulationData?.sector) return '—';
    const list = Array.isArray(window.simulationData.sector.atcSectors) ? window.simulationData.sector.atcSectors : [];
    const atc = list.find(s => s && String(s.id) === String(simulationJoinAtcSectorId));
    if (!atc) return '—';
    const nm = (atc.name || atc.id || '').toString().trim();
    return nm || '—';
}

function formatJoinerSimulationTitle(exerciseName, airspaceName, atcSectorDisplayName, role) {
    const base = formatSimulationExerciseAirspaceTitle(exerciseName, airspaceName);
    const sec = (atcSectorDisplayName || '').toString().trim() || '—';
    const r = (role || '').toString().trim().toUpperCase() || '—';
    return `${base} / Sector: ${sec} Role: ${r}`;
}

/** Hosting must not keep joiner identity — stale simulationJoinedSessionId disables host FMS physics (clock tick early-return). */
function clearSimulationJoinerIdentityForHostSession() {
    if (simulationJoinPollIntervalId) {
        clearInterval(simulationJoinPollIntervalId);
        simulationJoinPollIntervalId = null;
    }
    stopJoinPpAndExeSidecars();
    if (simulationJoinSlotHeartbeatIntervalId) {
        clearInterval(simulationJoinSlotHeartbeatIntervalId);
        simulationJoinSlotHeartbeatIntervalId = null;
    }
    clearJoinerExeAircraftPatches();
    ppJoinerPendingRocHundredsById = {};
    ppJoinerPendingAlvFlById = {};
    ppJoinerPendingDestRunwayById = {};
    ppJoinerLateralCmdSeqById = {};
    joinerHostDisplaySimTimeMs = null;
    joinerLastAppliedHostSimTimeMs = null;
    joinerLastAppliedHostStateSeq = null;
    simulationJoinedSessionId = null;
    simulationJoinClientId = null;
    simulationJoinAtcSectorId = null;
    simulationJoinRole = null;
    simulationJoinBoundaryIdFilter = null;
    simulationJoinPpAwaitingFullState = false;
}

/** Reset runtime sim state and rebuild aircraft for the same exercise (sector already in simulationData). */
function resetSimulationRunToExerciseStart(exercise, opts = {}) {
    const preserveView = !!(opts && opts.preserveView);
    if (!window.simulationData || !exercise) return;
    try {
        clearAllExeAlvModeSVerifyTimersFromList(window.simulationData?.aircraft);
        exeAlvModeSMismatchFlashById.clear();
        exeAlvDiscrepancyFirstSeenMsById.clear();
        exeAlvMismatchRadarLogKeys.clear();
    } catch (e) {}
    try { cancelDctPathMode(); } catch (e) {}
    window.simulationData.exercise = exercise;
    window.simulationData.flights = Array.isArray(exercise.flights) ? exercise.flights.map(f => ({ ...f })) : [];
    try { window.simulationData.aircraft = buildSimulationAircraftTracks(window.simulationData); } catch (e) { window.simulationData.aircraft = []; }
    try { simulationLabelZOrder = (window.simulationData.aircraft || []).map(a => a && a.id).filter(Boolean); } catch (e) { simulationLabelZOrder = []; }
    simulationAircraftFreeTextById = {};
    pendingSimulationFreeTextAircraftId = null;
    hideSimulationAlvPicker();
    hideSimulationXlvPicker();
    hideSimulationSpeedPicker();
    hideSimulationRocPicker();
    hideSimulationDctPicker();
    try { hideSimulationFlightStatusPopup(); } catch (e) {}
    simulationIsSelectingHeading = false;
    simulationSelectingHeadingAircraftId = null;
    simulationHeadingSelectMouse = null;
    simulationIsDraggingAircraftLabel = false;
    simulationDraggingAircraftId = null;
    simulationHoveredAircraftLabelId = null;
    simulationTrajectoryAircraftIds = new Set();
    simulationSpvAircraftIds = new Set();
    simulationSelectedAircraftId = null;
    try { syncAdvancedLabelPanel(); } catch (e) {}
    if (!preserveView) {
        simulationZoomLevel = 1.0;
        simulationPanX = 0;
        simulationPanY = 0;
        simulationAspectRatio = null;
    }
    isMeasuring = false;
    measureStartEndpoint = null;
    measureEndEndpoint = null;
    measureCurrentMousePos = null;
    measureCurrentEndAircraftId = null;
    measurements = [];
    measurementTextBounds = [];
    measurementColorCounter = 0;
    activeMeasurementColor = null;
    simulationDebugLogEntries = [];
    try { pushSimulationDebugLog('LOG', null, `Simulation restarted: ${exercise?.name || ''}`.trim()); } catch (e) {}
    simulationIsPaused = false;
    simulationRate = 1;
    const overlay = document.getElementById('simulationPausedOverlay');
    if (overlay) overlay.style.display = 'none';
    const pauseBtn = document.getElementById('pauseSimulationBtn');
    if (pauseBtn) pauseBtn.textContent = 'Pause';
    const speedEl = document.getElementById('simulationSpeedStatus');
    if (speedEl) speedEl.textContent = '';
    startSimulationClock(true);
    updateSimulationSpeedStatusUI();
    updatePauseButtonUI();
    updateSimulationClockFlashUI();
    resetSimulationAiPilotScriptState(exercise);
}

/** Joiner: clear local caches when host restarts the exercise (fresh state arrives on next merge). */
function resetJoinerLocalStateForHostSessionRestart() {
    joinerSkipLabelOffsetPreserveOnce = true;
    joinerSkipHeldDisplayPreserveOnce = true;
    joinerAwaitingDeferredAtmSync = isJoinerAtmDisplayClient();
    if (joinerDeferAtmSyncTimerId) {
        clearTimeout(joinerDeferAtmSyncTimerId);
        joinerDeferAtmSyncTimerId = null;
    }
    try { cancelDctPathMode(); } catch (e) {}
    hideSimulationAlvPicker();
    hideSimulationXlvPicker();
    hideSimulationSpeedPicker();
    hideSimulationRocPicker();
    hideSimulationDctPicker();
    try { hideSimulationFlightStatusPopup(); } catch (e) {}
    simulationIsSelectingHeading = false;
    simulationSelectingHeadingAircraftId = null;
    simulationHeadingSelectMouse = null;
    simulationIsDraggingAircraftLabel = false;
    simulationDraggingAircraftId = null;
    simulationHoveredAircraftLabelId = null;
    simulationTrajectoryAircraftIds = new Set();
    simulationSpvAircraftIds = new Set();
    simulationSelectedAircraftId = null;
    simulationAircraftFreeTextById = {};
    pendingSimulationFreeTextAircraftId = null;
    measurements = [];
    measurementTextBounds = [];
    isMeasuring = false;
    measureStartEndpoint = null;
    measureEndEndpoint = null;
    measureCurrentMousePos = null;
    measureCurrentEndAircraftId = null;
    ppJoinerPendingRocHundredsById = {};
    ppJoinerPendingAlvFlById = {};
    ppJoinerPendingDestRunwayById = {};
    clearJoinerExeAircraftPatches();
    simulationSessionAtmMasterClientId = null;
    try { syncAdvancedLabelPanel(); } catch (e) {}
    try {
        pushSimulationDebugLog('LOG', null, 'Session restarted by host — local state reset');
    } catch (e) {}
}

/** After host restart: use fresh host _display* only (no stale held positions from pre-restart). */
function seedJoinerDisplayFromHostAfterRestart() {
    if (!simulationJoinedSessionId || !window.simulationData?.aircraft) return;
    window.simulationData.aircraft.forEach((ac) => {
        if (!ac) return;
        delete ac._joinerHeldDisplayLat;
        delete ac._joinerHeldDisplayLon;
        delete ac._joinerHeldDisplayGs;
        delete ac._joinerHeldDisplayNext;
        delete ac._joinerHeldDisplayLastUpdateSimSec;
        delete ac._joinerHeldDisplayTraveledNm;
        delete ac._joinerTrailSamples;
        ac._trackCache = null;
        ac.routeNavTravelCacheN = null;
        if (ac.routeNavTraveledNmByUpdateSec instanceof Map) ac.routeNavTraveledNmByUpdateSec.clear();
        delete ac._atmTrajDrawCache;
        if (isJoinerAtmDisplayClient()) {
            resetJoinerAtmRouteProgressForAircraft(ac, 0);
            ac.routeNavTraveledNm = 0;
        }
        syncJoinerHeldDisplayFromAircraft(ac);
    });
}

function runJoinerAtmSyncAfterHostRestart() {
    joinerDeferAtmSyncTimerId = null;
    joinerAwaitingDeferredAtmSync = false;
    if (!simulationJoinedSessionId || !window.simulationData?.aircraft) return;
    seedJoinerDisplayFromHostAfterRestart();
    if (isJoinerAtmTrajectoryEditor()) {
        ensureJoinerExeBaselinePatchForEachAircraft();
        applyJoinerExePatchesAfterStateSync();
    }
    if (isJoinerAtmDisplayClient()) {
        window.simulationData.aircraft.forEach((ac) => {
            if (ac) syncJoinerAtmRouteProgressFromHostDisplay(ac, { forceAdvance: true });
        });
    }
    if (document.getElementById('simulationModal')?.classList.contains('active')) {
        try { drawSimulationCanvas(); } catch (e) {}
    }
}

function scheduleJoinerAtmSyncAfterHostRestart() {
    if (joinerDeferAtmSyncTimerId) clearTimeout(joinerDeferAtmSyncTimerId);
    joinerDeferAtmSyncTimerId = setTimeout(runJoinerAtmSyncAfterHostRestart, JOINER_ATM_RESYNC_AFTER_RESTART_MS);
}

function handleHostSessionRestartIfNeeded(state) {
    if (!simulationJoinedSessionId || !state) return;
    const restartSeq = state.hostSessionRestartSeq;
    if (restartSeq == null || !isFinite(Number(restartSeq))) return;
    const seq = Number(restartSeq);
    if (joinerLastAppliedHostSessionRestartSeq == null) {
        joinerLastAppliedHostSessionRestartSeq = seq;
        return;
    }
    if (seq <= joinerLastAppliedHostSessionRestartSeq) return;
    joinerLastAppliedHostSessionRestartSeq = seq;
    resetJoinerLocalStateForHostSessionRestart();
}

async function performHostedSimulationRestartCycle(opts = {}) {
    const isFollowUp = !!opts.isFollowUp;
    if (!simulationSessionId || simulationJoinedSessionId || !window.simulationData) return false;
    const exercise = window.simulationData.exercise;
    const sector = window.simulationData.sector;
    if (!exercise || !sector) return false;
    const sid = simulationSessionId;
    let restartSeq = hostSessionRestartSeq;
    const r = await fetch('/api/sessions/' + encodeURIComponent(sid) + '/restart', { method: 'POST' });
    const data = await r.json().catch(() => ({}));
    if (!r.ok || !data.ok) {
        if (!isFollowUp) {
            alert((data && data.error) ? data.error : 'Could not restart session.');
        }
        return false;
    }
    restartSeq = Number(data.hostSessionRestartSeq);
    if (!isFinite(restartSeq)) restartSeq = hostSessionRestartSeq + 1;
    hostSessionRestartSeq = restartSeq;
    hostLastAppliedPpLateralSeqById = {};
    if (!isFollowUp) {
        try { finishSimulationRecording('restart'); } catch (e) {}
    }
    resetSimulationRunToExerciseStart(exercise, { preserveView: true });
    if (!isFollowUp) {
        try { startSimulationRecording(exercise, sector); } catch (e) {}
    }
    pushHostSessionStateNowIfHosting();
    setTimeout(() => pushHostSessionStateNowIfHosting(), JOINER_ATM_RESYNC_AFTER_RESTART_MS);
    if (document.getElementById('simulationModal')?.classList.contains('active')) {
        try { drawSimulationCanvas(); } catch (e) {}
    }
    return true;
}

async function restartHostedSimulation() {
    if (!simulationSessionId || simulationJoinedSessionId || !window.simulationData) return;
    if (hostRestartInProgress) return;
    const exercise = window.simulationData.exercise;
    const sector = window.simulationData.sector;
    if (!exercise || !sector) {
        alert('Cannot restart: exercise data is missing.');
        return;
    }
    if (hostAutoSecondRestartTimerId) {
        clearTimeout(hostAutoSecondRestartTimerId);
        hostAutoSecondRestartTimerId = null;
    }
    hostRestartInProgress = true;
    try {
        const ok = await performHostedSimulationRestartCycle({ isFollowUp: false });
        if (!ok) {
            hostRestartInProgress = false;
            return;
        }
        hostAutoSecondRestartTimerId = setTimeout(async () => {
            hostAutoSecondRestartTimerId = null;
            try {
                if (simulationSessionId && !simulationJoinedSessionId) {
                    await performHostedSimulationRestartCycle({ isFollowUp: true });
                }
            } catch (e) {}
            hostRestartInProgress = false;
        }, HOST_DOUBLE_RESTART_DELAY_MS);
    } catch (e) {
        hostRestartInProgress = false;
        alert('Network error restarting session.');
    }
}

function restartSingleUserSimulation() {
    if (simulationSessionId || simulationJoinedSessionId || !window.simulationData) return;
    const exercise = window.simulationData.exercise;
    const sector = window.simulationData.sector;
    if (!exercise || !sector) {
        alert('Cannot restart: exercise data is missing.');
        return;
    }
    try { finishSimulationRecording('restart'); } catch (e) {}
    resetSimulationRunToExerciseStart(exercise, { preserveView: true });
    try { startSimulationRecording(exercise, sector); } catch (e) {}
    if (document.getElementById('simulationModal')?.classList.contains('active')) {
        try { drawSimulationCanvas(); } catch (e) {}
    }
}

async function restartSimulation() {
    if (simulationJoinedSessionId || !window.simulationData) return;
    if (simulationSessionId) {
        await restartHostedSimulation();
        return;
    }
    restartSingleUserSimulation();
}

// Start simulation - load the sector's map
async function startSimulation(exercise) {
    if (simulationSessionId) clearSimulationJoinerIdentityForHostSession();
    loadLabelSimulationConfigFromServer();
    try {
        clearAllExeAlvModeSVerifyTimersFromList(window.simulationData?.aircraft);
        exeAlvModeSMismatchFlashById.clear();
        exeAlvDiscrepancyFirstSeenMsById.clear();
        exeAlvMismatchRadarLogKeys.clear();
    } catch (e) {}
    // Get sector data
    let sector = getCachedSector(exercise.sectorId);
    if (sectorNeedsFullLoad(sector)) {
        try {
            sector = await loadSectorFromServer(exercise.sectorId);
        } catch (e) {
            alert('Could not load the airspace for this exercise.');
            return;
        }
    }
    
    if (!sector) {
        alert('Sector not found for this exercise');
        return;
    }
    
    // Close exercise selection modal
    closeModal('selectExerciseModal');
    
    // Load sector data for simulation
    const simulationWaypoints = [...(sector.waypoints || []), ...(sector.navaids || [])].filter(wp => 
        wp && 
        typeof wp.latitude === 'number' && 
        typeof wp.longitude === 'number' &&
        !isNaN(wp.latitude) && 
        !isNaN(wp.longitude) &&
        isFinite(wp.latitude) && 
        isFinite(wp.longitude)
    );
    const simulationRoutes = sector.routes || [];
    const simulationBoundaries = getBoundariesFromSectorForSimulation(sector);
    
    // Drop cached satellite-background rasters/warps from any previous exercise.
    try {
        Object.values(simulationBackgroundImageCache).forEach(e => { if (e && e.url) { try { URL.revokeObjectURL(e.url); } catch (er) {} } });
    } catch (e) {}
    simulationBackgroundImageCache = {};

    // Store simulation data
    window.simulationData = {
        waypoints: simulationWaypoints,
        routes: simulationRoutes,
        boundaries: simulationBoundaries,
        sector: sector,
        exercise: exercise,
        flights: Array.isArray(exercise.flights) ? exercise.flights.map(f => ({ ...f })) : [],
        flows: Array.isArray(sector.flows) ? sector.flows.map(fl => ({ ...fl })) : []
    };

    // Include airports/runways (for ARP/runway drawing in the running map)
    try {
        const airportsRaw = Array.isArray(sector.airports) ? JSON.parse(JSON.stringify(sector.airports)) : [];
        airportsRaw.forEach(ap => {
            if (!ap) return;
            if ((!isFinite(ap.arpLat) || !isFinite(ap.arpLon)) && ap.arpCoord) {
                const p = parseCoordinateSegment(normalizeCoordSeg(ap.arpCoord));
                if (p) { ap.arpLat = p.latitude; ap.arpLon = p.longitude; ap.arpCoord = normalizeCoordSeg(ap.arpCoord); }
            }
            (Array.isArray(ap.runways) ? ap.runways : []).forEach(rw => {
                const a = rw?.endA;
                const b = rw?.endB;
                if (a && (!isFinite(a.lat) || !isFinite(a.lon)) && a.coord) {
                    const pa = parseCoordinateSegment(normalizeCoordSeg(a.coord));
                    if (pa) { a.lat = pa.latitude; a.lon = pa.longitude; a.coord = normalizeCoordSeg(a.coord); }
                }
                if (b && (!isFinite(b.lat) || !isFinite(b.lon)) && b.coord) {
                    const pb = parseCoordinateSegment(normalizeCoordSeg(b.coord));
                    if (pb) { b.lat = pb.latitude; b.lon = pb.longitude; b.coord = normalizeCoordSeg(b.coord); }
                }
            });
        });
        window.simulationData.airports = airportsRaw;
    } catch (e) {
        window.simulationData.airports = [];
    }

    // Build aircraft tracks for this exercise
    try { window.simulationData.aircraft = buildSimulationAircraftTracks(window.simulationData); } catch (e) { window.simulationData.aircraft = []; }
    resetSimulationAiPilotScriptState(exercise);
    // Initialize label stacking order
    try { simulationLabelZOrder = (window.simulationData.aircraft || []).map(a => a && a.id).filter(Boolean); } catch (e) { simulationLabelZOrder = []; }
    // Reset runtime per-aircraft free text
    simulationAircraftFreeTextById = {};
    pendingSimulationFreeTextAircraftId = null;
    hideSimulationAlvPicker();
    hideSimulationXlvPicker();
    hideSimulationSpeedPicker();
    hideSimulationRocPicker();
    hideSimulationDctPicker();
    try { hideSimulationFlightStatusPopup(); } catch (e) {}
    simulationIsSelectingHeading = false;
    simulationSelectingHeadingAircraftId = null;
    simulationHeadingSelectMouse = null;
    simulationTrajectoryAircraftIds = new Set();
    simulationSelectedAircraftId = null;
    try { syncAdvancedLabelPanel(); } catch (e) {}
    try { syncSimulationHostAtcScopeSelect(); } catch (e) {}

    // Update simulation title (host + single-user)
    document.getElementById('simulationTitle').textContent = formatSimulationExerciseAirspaceTitle(exercise.name, sector.name);
    
    // Reset simulation zoom and pan
    simulationZoomLevel = 1.0;
    simulationPanX = 0;
    simulationPanY = 0;
    simulationAspectRatio = null;
    
    // Reset measuring tool
    isMeasuring = false;
    measureStartEndpoint = null;
    measureEndEndpoint = null;
    measureCurrentMousePos = null;
    measureCurrentEndAircraftId = null;
    measurements = []; // Clear measurements for new simulation
    measurementTextBounds = [];
    measurementColorCounter = 0;
    activeMeasurementColor = null;

    // Reset debug log for this simulation run
    simulationDebugLogEntries = [];
    try { pushSimulationDebugLog('LOG', null, `Simulation started: ${exercise?.name || ''}`.trim()); } catch (e) {}

    // Reset clock + pause state
    simulationIsPaused = false;
    const overlay = document.getElementById('simulationPausedOverlay');
    if (overlay) overlay.style.display = 'none';
    const pauseBtn = document.getElementById('pauseSimulationBtn');
    if (pauseBtn) pauseBtn.textContent = 'Pause';
    const speedEl = document.getElementById('simulationSpeedStatus');
    if (speedEl) speedEl.textContent = '';
    startSimulationClock(true);

    // Reset mode of operation for each simulation run (unless caller sets it after for Host/Single)
    if (typeof window._runTypePresetMode === 'string') {
        simulationOperationModeId = window._runTypePresetMode;
        delete window._runTypePresetMode;
    } else {
        simulationOperationModeId = 'DL';
    }
    simulationIsMonitorOnly = false;
    updateSimulationOperationModeUi();
    startSimulationRecording(exercise, sector);
    try {
        if (isAdminRecordSimulationsEnabled()) {
            pushSimulationDebugLog('LOG', null, `Recording started for ${exercise?.name || 'simulation'}`);
        } else {
            pushSimulationDebugLog('LOG', null, 'Simulation recording disabled (Admin → Record Simulations: No)');
        }
    } catch (e) {}
    
    // Open simulation modal
    openModal('simulationModal');
    syncSimulationPlaybackButtonsVisibility();

    // Initialize simulation canvas after modal opens
    setTimeout(() => {
        initSimulationCanvas();
    }, 100);
}

// Select a sector and show its exercises (Step 2)
function selectSector(sectorId) {
    const sectors = getSectors();
    const sector = sectors.find(s => s.id === sectorId);
    
    if (!sector) return;

    // Hide sector selection, show exercise selection
    document.getElementById('sectorSelectionStep').style.display = 'none';
    document.getElementById('exerciseSelectionStep').style.display = 'flex';
    
    // Update title
    document.getElementById('selectedSectorTitle').textContent = `Exercises for: ${sector.name}`;
    
    // Render exercises for this sector
    renderExercisesForSector(sectorId);
}

// Render exercises list for selected sector
function renderExercisesForSector(sectorId) {
    const exercisesList = document.getElementById('exercisesList');
    const exercises = getExercises();
    const sectorExercises = exercises.filter(ex => ex.sectorId === sectorId);

    if (sectorExercises.length === 0) {
        exercisesList.innerHTML = `
            <div class="empty-state">
                <div class="empty-state-icon">📋</div>
                <div class="empty-state-text">No exercises available for this sector yet.<br>Click "Create Exercise" to add one.</div>
            </div>
        `;
        return;
    }

    exercisesList.innerHTML = sectorExercises.map(exercise => {
        const createdDate = new Date(exercise.createdAt).toLocaleDateString('en-US', {
            year: 'numeric',
            month: 'long',
            day: 'numeric'
        });
        
        return `
            <div class="exercise-card" data-exercise-id="${exercise.id}">
                <div class="exercise-card-header">
                    <div class="exercise-card-name">${exercise.name}</div>
                    <div class="exercise-card-date">Created: ${createdDate}</div>
                </div>
                <div class="exercise-card-details">
                    <div class="exercise-detail-item">
                        <span class="exercise-detail-label">Exercise ID:</span>
                        <span class="exercise-detail-value">${exercise.id}</span>
                    </div>
                    ${exercise.description ? `
                        <div class="exercise-detail-item">
                            <span class="exercise-detail-label">Description:</span>
                            <span class="exercise-detail-value">${exercise.description}</span>
                        </div>
                    ` : ''}
                    ${exercise.difficulty ? `
                        <div class="exercise-detail-item">
                            <span class="exercise-detail-label">Difficulty:</span>
                            <span class="exercise-detail-value">${exercise.difficulty}</span>
                        </div>
                    ` : ''}
                    ${exercise.duration ? `
                        <div class="exercise-detail-item">
                            <span class="exercise-detail-label">Duration:</span>
                            <span class="exercise-detail-value">${exercise.duration} minutes</span>
                        </div>
                    ` : ''}
                    <div class="exercise-detail-item">
                        <span class="exercise-detail-label">Aircraft:</span>
                        <span class="exercise-detail-value">${Array.isArray(exercise.flights) ? exercise.flights.length : 0}</span>
                    </div>
                </div>
                <div class="exercise-card-action" style="display: none;">
                    <button class="btn btn-success btn-run-simulation" data-exercise-id="${exercise.id}">
                        <span class="btn-icon">▶️</span>
                        <span class="btn-text">RUN Simulation</span>
                    </button>
                </div>
            </div>
        `;
    }).join('');

    // Add click handlers to exercise cards
    document.querySelectorAll('.exercise-card').forEach(card => {
        card.addEventListener('click', function(e) {
            // Don't trigger selection if clicking the RUN button
            if (e.target.closest('.btn-run-simulation')) {
                return;
            }
            
            // Remove previous selection and hide all RUN buttons
            document.querySelectorAll('.exercise-card').forEach(c => {
                c.classList.remove('selected');
                const actionDiv = c.querySelector('.exercise-card-action');
                if (actionDiv) {
                    actionDiv.style.display = 'none';
                }
            });
            
            // Add selection to clicked card
            this.classList.add('selected');
            
            // Show RUN Simulation button for selected card
            const actionDiv = this.querySelector('.exercise-card-action');
            if (actionDiv) {
                actionDiv.style.display = 'flex';
            }
            
            const exerciseId = this.dataset.exerciseId;
            const exercise = sectorExercises.find(ex => ex.id === exerciseId);
            
            console.log('Selected exercise:', exercise);
        });
    });

    // Add click handlers to RUN Simulation buttons
    document.querySelectorAll('.btn-run-simulation').forEach(btn => {
        btn.addEventListener('click', function(e) {
            e.stopPropagation(); // Prevent card selection toggle
            const exerciseId = this.dataset.exerciseId;
            const exercise = sectorExercises.find(ex => ex.id === exerciseId);
            if (!exercise) return;
            pendingRunExercise = exercise;
            closeModal('selectExerciseModal');
            openRunTypeModal();
        });
    });
}

// Go back to sector selection
function backToSectorSelection() {
    document.getElementById('sectorSelectionStep').style.display = 'flex';
    document.getElementById('exerciseSelectionStep').style.display = 'none';
    // Clear any selected exercises and hide RUN buttons
    document.querySelectorAll('.exercise-card').forEach(c => {
        c.classList.remove('selected');
        const actionDiv = c.querySelector('.exercise-card-action');
        if (actionDiv) {
            actionDiv.style.display = 'none';
        }
    });
    renderSectorsForSelection();
}

// Render delete exercises list
function renderDeleteExercisesList() {
    const deleteList = document.getElementById('deleteExercisesList');
    const exercises = getExercises();
    const sectors = getSectors();

    if (exercises.length === 0) {
        deleteList.innerHTML = `
            <div class="empty-state">
                <div class="empty-state-icon">📭</div>
                <div class="empty-state-text">No exercises available to delete.</div>
            </div>
        `;
        return;
    }

    deleteList.innerHTML = exercises.map(exercise => {
        const sector = sectors.find(s => s.id === exercise.sectorId);
        const sectorName = sector ? sector.name : 'Unknown Sector';
        const createdDate = new Date(exercise.createdAt).toLocaleDateString('en-US', {
            year: 'numeric',
            month: 'short',
            day: 'numeric'
        });

        return `
            <div class="delete-exercise-item" data-exercise-id="${exercise.id}">
                <div class="delete-exercise-info">
                    <div class="delete-exercise-name">${exercise.name}</div>
                    <div class="delete-exercise-details">
                        <span class="delete-exercise-sector">Sector: ${sectorName}</span>
                        ${exercise.difficulty ? `<span>Difficulty: ${exercise.difficulty}</span>` : ''}
                        ${exercise.duration ? `<span>Duration: ${exercise.duration} minutes</span>` : ''}
                        <span>Created: ${createdDate}</span>
                    </div>
                </div>
                <button class="delete-exercise-btn" data-exercise-id="${exercise.id}">
                    Delete
                </button>
            </div>
        `;
    }).join('');

    // Add click handlers to delete buttons
    document.querySelectorAll('.delete-exercise-btn').forEach(btn => {
        btn.addEventListener('click', function(e) {
            e.stopPropagation();
            const exerciseId = this.dataset.exerciseId;
            const exercise = exercises.find(ex => ex.id === exerciseId);
            
            if (exercise && confirm(`Are you sure you want to delete the exercise "${exercise.name}"?\n\nThis action cannot be undone.`)) {
                deleteExercise(exerciseId);
            }
        });
    });
}

// Delete an exercise
function deleteExercise(exerciseId) {
    const exercises = getExercises();
    const filteredExercises = exercises.filter(ex => ex.id !== exerciseId);
    saveExercises(filteredExercises);
    
    // Refresh the delete list
    renderDeleteExercisesList();
    
    // Show success message
    const exercise = exercises.find(ex => ex.id === exerciseId);
    if (exercise) {
        alert(`Exercise "${exercise.name}" has been deleted successfully.`);
    }
}

// Render delete sectors list
function renderDeleteSectorsList() {
    const deleteList = document.getElementById('deleteSectorsList');
    if (!deleteList) return;
    const sectors = getSectors();
    const exercises = getExercises();

    if (sectors.length === 0) {
        deleteList.innerHTML = `
            <div class="empty-state">
                <div class="empty-state-icon">📭</div>
                <div class="empty-state-text">No airspaces available to delete.</div>
            </div>
        `;
        return;
    }

    deleteList.innerHTML = sectors.map(sector => {
        const linkedCount = exercises.filter(ex => ex && ex.sectorId === sector.id).length;
        return `
            <div class="delete-exercise-item" data-sector-id="${sector.id}">
                <div class="delete-exercise-info">
                    <div class="delete-exercise-name">${sector.name}</div>
                    <div class="delete-exercise-details">
                        <span>Exercises linked: ${linkedCount}</span>
                    </div>
                </div>
                <button class="delete-exercise-btn" data-sector-id="${sector.id}">
                    Delete
                </button>
            </div>
        `;
    }).join('');

    document.querySelectorAll('.delete-exercise-btn[data-sector-id]').forEach(btn => {
        btn.addEventListener('click', function(e) {
            e.stopPropagation();
            const sectorId = this.dataset.sectorId;
            const sector = sectors.find(s => s.id === sectorId);
            if (!sector) return;
            const linkedCount = exercises.filter(ex => ex && ex.sectorId === sectorId).length;
            const msg = `Are you sure you want to delete the airspace "${sector.name}"?\n\nThis will also delete ${linkedCount} linked exercise(s).\n\nThis action cannot be undone.`;
            if (confirm(msg)) {
                deleteSector(sectorId);
            }
        });
    });
}

function deleteSector(sectorId) {
    const sectors = getSectors();
    const exercises = getExercises();

    const sector = sectors.find(s => s.id === sectorId);
    const filteredSectors = sectors.filter(s => s.id !== sectorId);
    const filteredExercises = exercises.filter(ex => ex && ex.sectorId !== sectorId);

    saveSectors(filteredSectors);
    saveExercises(filteredExercises);

    // Refresh UI pieces that depend on sectors/exercises
    try { populateSectorSelect(); } catch (e) {}
    try { populateSectorSelectForEdit(); } catch (e) {}
    try { renderSectorsForSelection(); } catch (e) {}
    try { renderDeleteExercisesList(); } catch (e) {}
    try { renderDeleteSectorsList(); } catch (e) {}

    if (sector) {
        alert(`Airspace "${sector.name}" has been deleted successfully.`);
    }
}

