function parseAircraftDatabase(raw) {
    const db = {};
    const lines = (raw || '').split('\n').map(l => l.trim()).filter(Boolean);
    lines.forEach((line, idx) => {
        const parts = line.split(/\s+/);
        if (parts.length !== 18) {
            console.warn(`Aircraft DB line ${idx + 1}: expected 18 fields, got ${parts.length}`);
            return;
        }
        const [
            TYPE,
            CEILING_FL,
            KIAS_LOW_MAX, KIAS_LOW_NORM, KIAS_LOW_MIN,
            KIAS_MID_MAX, KIAS_MID_NORM, KIAS_MID_MIN,
            KIAS_HIGH_MAX, KIAS_HIGH_NORM, KIAS_HIGH_MIN,
            CLIMB_MAX_FPM, CLIMB_NORMAL_FPM,
            DESC_MAX_FPM, DESC_NORMAL_FPM,
            MIN_MACH, NORMAL_MACH, MAX_MACH
        ] = parts;

        const type = (TYPE || '').trim().toUpperCase();
        if (!type) return;

        const asInt = (v) => {
            const n = parseInt(v, 10);
            return Number.isFinite(n) ? n : null;
        };
        const asFloat = (v) => {
            const n = parseFloat(v);
            return Number.isFinite(n) ? n : null;
        };

        const rec = {
            type,
            ceilingFl: asInt(CEILING_FL),
            kias: {
                low: { max: asInt(KIAS_LOW_MAX), norm: asInt(KIAS_LOW_NORM), min: asInt(KIAS_LOW_MIN) },
                mid: { max: asInt(KIAS_MID_MAX), norm: asInt(KIAS_MID_NORM), min: asInt(KIAS_MID_MIN) },
                high: { max: asInt(KIAS_HIGH_MAX), norm: asInt(KIAS_HIGH_NORM), min: asInt(KIAS_HIGH_MIN) }
            },
            climb: { maxFpm: asInt(CLIMB_MAX_FPM), normalFpm: asInt(CLIMB_NORMAL_FPM) },
            desc: { maxFpm: asInt(DESC_MAX_FPM), normalFpm: asInt(DESC_NORMAL_FPM) },
            mach: { min: asFloat(MIN_MACH), normal: asFloat(NORMAL_MACH), max: asFloat(MAX_MACH) }
        };

        db[type] = rec;
    });
    return db;
}

function parseAircraftDatabaseStrict(raw) {
    const db = {};
    const errors = [];
    const lines = (raw || '').split('\n').map(l => l.trim()).filter(Boolean);

    const requiredInt = (v) => {
        const n = parseInt(v, 10);
        return Number.isFinite(n) ? n : null;
    };
    const requiredFloat = (v) => {
        const n = parseFloat(v);
        return Number.isFinite(n) ? n : null;
    };

    lines.forEach((line, idx) => {
        const parts = line.split(/\s+/);
        if (parts.length !== 18) {
            errors.push(`Line ${idx + 1}: expected 18 fields, got ${parts.length}`);
            return;
        }

        const [
            TYPE,
            CEILING_FL,
            KIAS_LOW_MAX, KIAS_LOW_NORM, KIAS_LOW_MIN,
            KIAS_MID_MAX, KIAS_MID_NORM, KIAS_MID_MIN,
            KIAS_HIGH_MAX, KIAS_HIGH_NORM, KIAS_HIGH_MIN,
            CLIMB_MAX_FPM, CLIMB_NORMAL_FPM,
            DESC_MAX_FPM, DESC_NORMAL_FPM,
            MIN_MACH, NORMAL_MACH, MAX_MACH
        ] = parts;

        const type = (TYPE || '').trim().toUpperCase();
        if (!type) {
            errors.push(`Line ${idx + 1}: TYPE is required`);
            return;
        }

        const rec = {
            type,
            ceilingFl: requiredInt(CEILING_FL),
            kias: {
                low: { max: requiredInt(KIAS_LOW_MAX), norm: requiredInt(KIAS_LOW_NORM), min: requiredInt(KIAS_LOW_MIN) },
                mid: { max: requiredInt(KIAS_MID_MAX), norm: requiredInt(KIAS_MID_NORM), min: requiredInt(KIAS_MID_MIN) },
                high: { max: requiredInt(KIAS_HIGH_MAX), norm: requiredInt(KIAS_HIGH_NORM), min: requiredInt(KIAS_HIGH_MIN) }
            },
            climb: { maxFpm: requiredInt(CLIMB_MAX_FPM), normalFpm: requiredInt(CLIMB_NORMAL_FPM) },
            desc: { maxFpm: requiredInt(DESC_MAX_FPM), normalFpm: requiredInt(DESC_NORMAL_FPM) },
            mach: { min: requiredFloat(MIN_MACH), normal: requiredFloat(NORMAL_MACH), max: requiredFloat(MAX_MACH) }
        };

        const hasNull = [
            rec.ceilingFl,
            rec.kias.low.max, rec.kias.low.norm, rec.kias.low.min,
            rec.kias.mid.max, rec.kias.mid.norm, rec.kias.mid.min,
            rec.kias.high.max, rec.kias.high.norm, rec.kias.high.min,
            rec.climb.maxFpm, rec.climb.normalFpm,
            rec.desc.maxFpm, rec.desc.normalFpm,
            rec.mach.min, rec.mach.normal, rec.mach.max
        ].some(v => v === null);
        if (hasNull) {
            errors.push(`Line ${idx + 1}: invalid number(s)`);
            return;
        }

        db[type] = rec;
    });

    return { db, errors };
}

const AIRCRAFT_DB_OVERRIDES_STORAGE_KEY = 'agi_webatc_aircraftDbOverridesRaw_v1';
// Server-backed: null = not loaded yet (use localStorage); string = from server
let serverAircraftOverridesCache = null;
function loadAircraftDbOverridesFromServer() {
    return fetch('/api/aircraft-db-overrides')
        .then(r => r.json())
        .then(data => {
            serverAircraftOverridesCache = (data && typeof data.raw === 'string') ? data.raw : '';
        })
        .catch(() => {});
}
function loadAircraftDbOverridesRaw() {
    try {
        if (serverAircraftOverridesCache !== null) return (serverAircraftOverridesCache || '').trim();
        return (localStorage.getItem(AIRCRAFT_DB_OVERRIDES_STORAGE_KEY) || '').trim();
    } catch (e) {
        return '';
    }
}
function saveAircraftDbOverridesRaw(raw) {
    try {
        const t = (raw || '').trim();
        serverAircraftOverridesCache = t;
        fetch('/api/aircraft-db-overrides', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ raw: t })
        }).catch(() => {});
        if (!t) localStorage.removeItem(AIRCRAFT_DB_OVERRIDES_STORAGE_KEY);
        else localStorage.setItem(AIRCRAFT_DB_OVERRIDES_STORAGE_KEY, t);
    } catch (e) {}
}

const AIRLINE_CALLSIGNS_DEFAULT = (() => {
    const src = window.AIRLINE_CALLSIGNS;
    if (!src || typeof src !== 'object') return {};
    const out = {};
    Object.keys(src).forEach((key) => {
        const code = String(key || '').trim().toUpperCase();
        const callsign = String(src[key] || '').trim();
        if (code && callsign) out[code] = callsign;
    });
    return out;
})();

const AIRLINE_CALLSIGNS_OVERRIDES_STORAGE_KEY = 'agi_webatc_airlineCallsignsOverrides_v1';
let serverAirlineCallsignsOverridesCache = null;
let airlineCallsignsOverridesPayload = { overrides: {}, deletions: [] };
let airlinesDbDraft = {};
let airlinesDbSavedPayload = { overrides: {}, deletions: [] };
let airlinesDbRowOrigins = {};
let airlinesDbEditingCode = null;

function normalizeAirlineCode(raw) {
    return String(raw || '').trim().toUpperCase();
}

function normalizeAirlineCallsign(raw) {
    return String(raw || '').trim();
}

function normalizeAirlineCallsignsOverridesPayload(raw) {
    const overrides = {};
    const deletions = [];
    if (raw && typeof raw === 'object') {
        Object.entries(raw.overrides || {}).forEach(([key, val]) => {
            const code = normalizeAirlineCode(key);
            const callsign = normalizeAirlineCallsign(val);
            if (code && callsign) overrides[code] = callsign;
        });
        const seen = new Set();
        (Array.isArray(raw.deletions) ? raw.deletions : []).forEach((item) => {
            const code = normalizeAirlineCode(item);
            if (code && !seen.has(code)) {
                seen.add(code);
                deletions.push(code);
            }
        });
    }
    return { overrides, deletions };
}

function loadAirlineCallsignsOverridesFromServer() {
    return fetch('/api/airline-callsigns-overrides')
        .then(r => r.json())
        .then(data => {
            serverAirlineCallsignsOverridesCache = normalizeAirlineCallsignsOverridesPayload(data);
        })
        .catch(() => {});
}

function loadAirlineCallsignsOverridesPayload() {
    try {
        if (serverAirlineCallsignsOverridesCache) {
            return normalizeAirlineCallsignsOverridesPayload(serverAirlineCallsignsOverridesCache);
        }
        const raw = localStorage.getItem(AIRLINE_CALLSIGNS_OVERRIDES_STORAGE_KEY);
        if (!raw) return { overrides: {}, deletions: [] };
        return normalizeAirlineCallsignsOverridesPayload(JSON.parse(raw));
    } catch (e) {
        return { overrides: {}, deletions: [] };
    }
}

function saveAirlineCallsignsOverridesPayload(payload) {
    const normalized = normalizeAirlineCallsignsOverridesPayload(payload);
    try {
        serverAirlineCallsignsOverridesCache = normalized;
        fetch('/api/airline-callsigns-overrides', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(normalized)
        }).catch(() => {});
        if (!Object.keys(normalized.overrides).length && !normalized.deletions.length) {
            localStorage.removeItem(AIRLINE_CALLSIGNS_OVERRIDES_STORAGE_KEY);
        } else {
            localStorage.setItem(AIRLINE_CALLSIGNS_OVERRIDES_STORAGE_KEY, JSON.stringify(normalized));
        }
    } catch (e) {}
}

function rebuildAirlineCallsignsEffective() {
    airlineCallsignsOverridesPayload = loadAirlineCallsignsOverridesPayload();
    const out = { ...AIRLINE_CALLSIGNS_DEFAULT };
    (airlineCallsignsOverridesPayload.deletions || []).forEach((code) => {
        delete out[normalizeAirlineCode(code)];
    });
    Object.entries(airlineCallsignsOverridesPayload.overrides || {}).forEach(([code, callsign]) => {
        const c = normalizeAirlineCode(code);
        const cs = normalizeAirlineCallsign(callsign);
        if (c && cs) out[c] = cs;
    });
    window.AIRLINE_CALLSIGNS = out;
}

function findDefaultAirlineKey(code) {
    const wanted = normalizeAirlineCode(code);
    if (!wanted) return null;
    if (Object.prototype.hasOwnProperty.call(AIRLINE_CALLSIGNS_DEFAULT, wanted)) return wanted;
    const match = Object.keys(AIRLINE_CALLSIGNS_DEFAULT).find(k => normalizeAirlineCode(k) === wanted);
    return match || null;
}

function buildEffectiveAirlineCallsignsMap() {
    const src = window.AIRLINE_CALLSIGNS;
    if (!src || typeof src !== 'object') return {};
    const out = {};
    Object.keys(src).forEach((key) => {
        const code = normalizeAirlineCode(key);
        const callsign = normalizeAirlineCallsign(src[key]);
        if (code && callsign) out[code] = callsign;
    });
    return out;
}

function computeAirlineCallsignsPayloadFromDraft(draft) {
    const overrides = {};
    const deletions = [];
    const draftMap = draft && typeof draft === 'object' ? draft : {};
    Object.keys(AIRLINE_CALLSIGNS_DEFAULT).forEach((key) => {
        const code = normalizeAirlineCode(key);
        const defaultCallsign = normalizeAirlineCallsign(AIRLINE_CALLSIGNS_DEFAULT[key]);
        const current = draftMap[code];
        if (current == null || normalizeAirlineCallsign(current) === '') {
            deletions.push(code);
            return;
        }
        if (normalizeAirlineCallsign(current) !== defaultCallsign) {
            overrides[code] = normalizeAirlineCallsign(current);
        }
    });
    Object.keys(draftMap).forEach((key) => {
        const code = normalizeAirlineCode(key);
        const callsign = normalizeAirlineCallsign(draftMap[key]);
        if (!code || !callsign) return;
        if (findDefaultAirlineKey(code)) return;
        overrides[code] = callsign;
    });
    return normalizeAirlineCallsignsOverridesPayload({ overrides, deletions });
}

function cloneAirlineCallsignsPayload(payload) {
    const normalized = normalizeAirlineCallsignsOverridesPayload(payload);
    return {
        overrides: { ...normalized.overrides },
        deletions: [...normalized.deletions]
    };
}

function payloadsEqual(a, b) {
    const left = normalizeAirlineCallsignsOverridesPayload(a);
    const right = normalizeAirlineCallsignsOverridesPayload(b);
    const leftDel = [...left.deletions].sort().join('|');
    const rightDel = [...right.deletions].sort().join('|');
    if (leftDel !== rightDel) return false;
    const keys = new Set([...Object.keys(left.overrides), ...Object.keys(right.overrides)]);
    for (const key of keys) {
        if ((left.overrides[key] || '') !== (right.overrides[key] || '')) return false;
    }
    return true;
}

function rebuildAirlineDraftOriginsFromDraft() {
    airlinesDbRowOrigins = {};
    Object.keys(airlinesDbDraft).forEach((code) => {
        const defKey = findDefaultAirlineKey(code);
        airlinesDbRowOrigins[code] = defKey || code;
    });
}

function cloneAirlinesDbDraftFromEffective() {
    airlinesDbDraft = buildEffectiveAirlineCallsignsMap();
    rebuildAirlineDraftOriginsFromDraft();
}

function isAirlinesDbDirty() {
    return !payloadsEqual(
        computeAirlineCallsignsPayloadFromDraft(airlinesDbDraft),
        airlinesDbSavedPayload
    );
}

function isAirlineDraftRowModified(code) {
    const rowCode = normalizeAirlineCode(code);
    if (!rowCode || !Object.prototype.hasOwnProperty.call(airlinesDbDraft, rowCode)) return false;
    const origin = normalizeAirlineCode(airlinesDbRowOrigins[rowCode] || rowCode);
    const defKey = findDefaultAirlineKey(origin);
    const current = normalizeAirlineCallsign(airlinesDbDraft[rowCode]);
    if (!defKey) return true;
    if (rowCode !== normalizeAirlineCode(defKey)) return true;
    return current !== normalizeAirlineCallsign(AIRLINE_CALLSIGNS_DEFAULT[defKey]);
}

const AIRCRAFT_DB_DEFAULT = parseAircraftDatabase(AIRCRAFT_DB_RAW_DEFAULT);
let AIRCRAFT_DB_OVERRIDES = {};
let AIRCRAFT_DB = { ...AIRCRAFT_DB_DEFAULT };
let AIRCRAFT_TYPES = Object.keys(AIRCRAFT_DB).sort();

// Turn performance bands (used for heading/DCT turn rate selection by FL).
// Stored separately from the aircraft DB overrides (global sim behavior).
const TURN_RATE_BANDS_STORAGE_KEY = 'agi_webatc_turnRateBands_v1';
const TURN_RATE_BANDS_DEFAULT = [
    { minFl: 0, maxFl: 99, minDps: 3.5, maxDps: 4.5 },
    { minFl: 100, maxFl: 199, minDps: 2.5, maxDps: 3.2 },
    { minFl: 200, maxFl: 299, minDps: 1.8, maxDps: 2.5 },
    { minFl: 300, maxFl: 350, minDps: 1.5, maxDps: 2.0 },
    { minFl: 351, maxFl: null, minDps: 1.2, maxDps: 1.6 }
];
let TURN_RATE_BANDS = JSON.parse(JSON.stringify(TURN_RATE_BANDS_DEFAULT));
// Server-backed: null = not loaded yet (use localStorage); array = from server
let serverTurnRateBandsCache = null;

function loadTurnRateBandsFromServer() {
    return fetch('/api/turn-rate-bands')
        .then(r => r.json())
        .then(data => {
            if (Array.isArray(data.bands) && data.bands.length) serverTurnRateBandsCache = data.bands;
            else serverTurnRateBandsCache = [];
        })
        .catch(() => {});
}

function loadTurnRateBands() {
    try {
        if (serverTurnRateBandsCache !== null) {
            TURN_RATE_BANDS = sanitizeTurnRateBands(serverTurnRateBandsCache);
            return;
        }
        const raw = localStorage.getItem(TURN_RATE_BANDS_STORAGE_KEY);
        if (!raw) {
            TURN_RATE_BANDS = JSON.parse(JSON.stringify(TURN_RATE_BANDS_DEFAULT));
            return;
        }
        const obj = JSON.parse(raw);
        if (!Array.isArray(obj)) {
            TURN_RATE_BANDS = JSON.parse(JSON.stringify(TURN_RATE_BANDS_DEFAULT));
            return;
        }
        TURN_RATE_BANDS = sanitizeTurnRateBands(obj);
    } catch (e) {
        TURN_RATE_BANDS = JSON.parse(JSON.stringify(TURN_RATE_BANDS_DEFAULT));
    }
}

function saveTurnRateBands() {
    try {
        serverTurnRateBandsCache = JSON.parse(JSON.stringify(TURN_RATE_BANDS));
        fetch('/api/turn-rate-bands', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ bands: TURN_RATE_BANDS })
        }).catch(() => {});
        localStorage.setItem(TURN_RATE_BANDS_STORAGE_KEY, JSON.stringify(TURN_RATE_BANDS));
    } catch (e) {}
}

function sanitizeTurnRateBands(bands) {
    const out = (bands || []).map(b => {
        const minFl = parseInt(b?.minFl, 10);
        const maxFlRaw = b?.maxFl;
        const maxFl = (maxFlRaw === null || maxFlRaw === '' || maxFlRaw === undefined) ? null : parseInt(maxFlRaw, 10);
        const minDps = Number(b?.minDps);
        const maxDps = Number(b?.maxDps);
        return {
            minFl: Number.isFinite(minFl) ? Math.max(0, Math.min(500, minFl)) : 0,
            maxFl: (maxFl === null) ? null : (Number.isFinite(maxFl) ? Math.max(0, Math.min(500, maxFl)) : null),
            minDps: (isFinite(minDps) && minDps > 0) ? minDps : 1.0,
            maxDps: (isFinite(maxDps) && maxDps > 0) ? maxDps : 1.0
        };
    });
    out.sort((a, b) => (a.minFl - b.minFl));
    // ensure min<=max for each band
    out.forEach(b => {
        if (b.maxFl != null && b.maxFl < b.minFl) {
            const t = b.maxFl;
            b.maxFl = b.minFl;
            b.minFl = t;
        }
        if (b.maxDps < b.minDps) {
            const t = b.maxDps;
            b.maxDps = b.minDps;
            b.minDps = t;
        }
    });
    return out.length ? out : JSON.parse(JSON.stringify(TURN_RATE_BANDS_DEFAULT));
}

function getTurnRateBandForFl(fl) {
    const f = parseInt(fl, 10);
    if (!Number.isFinite(f)) return TURN_RATE_BANDS[TURN_RATE_BANDS.length - 1] || TURN_RATE_BANDS_DEFAULT[TURN_RATE_BANDS_DEFAULT.length - 1];
    for (const b of (TURN_RATE_BANDS || [])) {
        if (!b) continue;
        const min = parseInt(b.minFl, 10);
        const max = (b.maxFl === null || b.maxFl === undefined) ? null : parseInt(b.maxFl, 10);
        if (!Number.isFinite(min)) continue;
        if (f < min) continue;
        if (max === null || !Number.isFinite(max) || f <= max) return b;
    }
    return TURN_RATE_BANDS[TURN_RATE_BANDS.length - 1] || TURN_RATE_BANDS_DEFAULT[TURN_RATE_BANDS_DEFAULT.length - 1];
}

function pickTurnRateDpsForAircraft(ac) {
    const mcFeet = Number(ac?.publishedModeCFeet ?? ac?.modeCFeet);
    const fl = isFinite(mcFeet) ? Math.max(0, Math.round(mcFeet / 100)) : 0;
    const b = getTurnRateBandForFl(fl);
    const min = Number(b?.minDps);
    const max = Number(b?.maxDps);
    const lo = (isFinite(min) && min > 0) ? min : 1.0;
    const hi = (isFinite(max) && max > 0) ? max : lo;
    return lo + Math.random() * Math.max(0, (hi - lo));
}

function getMinTurnRateDpsForAircraft(ac) {
    const mcFeet = Number(ac?.publishedModeCFeet ?? ac?.modeCFeet);
    const fl = isFinite(mcFeet) ? Math.max(0, Math.round(mcFeet / 100)) : 0;
    const b = getTurnRateBandForFl(fl);
    const min = Number(b?.minDps);
    const lo = (isFinite(min) && min > 0) ? min : 1.0;
    return lo;
}

function getNominalTurnRateDpsForAircraft(ac) {
    const mcFeet = Number(ac?.publishedModeCFeet ?? ac?.modeCFeet);
    const fl = isFinite(mcFeet) ? Math.max(0, Math.round(mcFeet / 100)) : 0;
    const b = getTurnRateBandForFl(fl);
    const min = Number(b?.minDps);
    const max = Number(b?.maxDps);
    const lo = (isFinite(min) && min > 0) ? min : 1.0;
    const hi = (isFinite(max) && max > 0) ? max : lo;
    return (lo + hi) * 0.5;
}

function getTurnRadiusNmFromGsAndTurnRate(gsKt, turnRateDps) {
    const gs = Number(gsKt);
    const dps = Number(turnRateDps);
    if (!isFinite(gs) || gs <= 0) return null;
    if (!isFinite(dps) || dps <= 0) return null;
    const omegaRadPerSec = (dps * Math.PI) / 180;
    const vNmPerSec = gs / 3600;
    const rNm = vNmPerSec / omegaRadPerSec;
    return (isFinite(rNm) && rNm > 0) ? rNm : null;
}

function computeTurnArcPointsLocalXY(ac, gsKt, refLatDeg, prevLatLon, cornerLatLon, nextLatLon) {
    // Work in the sim's local XY degrees space where:
    // x = lon * cos(refLat), y = lat. In that space, 1 degree ≈ 60 NM in both axes.
    if (!prevLatLon || !cornerLatLon || !nextLatLon) return null;
    if (![prevLatLon.lat, prevLatLon.lon, cornerLatLon.lat, cornerLatLon.lon, nextLatLon.lat, nextLatLon.lon].every(isFinite)) return null;
    const minDps = getMinTurnRateDpsForAircraft(ac);
    const rNm = getTurnRadiusNmFromGsAndTurnRate(gsKt, minDps);
    if (rNm == null) return null;
    const rDeg = rNm / 60;
    if (!isFinite(rDeg) || rDeg <= 0) return null;

    const A = latLonToLocalXY(prevLatLon.lat, prevLatLon.lon, refLatDeg);
    const B = latLonToLocalXY(cornerLatLon.lat, cornerLatLon.lon, refLatDeg);
    const C = latLonToLocalXY(nextLatLon.lat, nextLatLon.lon, refLatDeg);
    if (![A.x, A.y, B.x, B.y, C.x, C.y].every(isFinite)) return null;

    const sub = (p, q) => ({ x: p.x - q.x, y: p.y - q.y });
    const add = (p, q) => ({ x: p.x + q.x, y: p.y + q.y });
    const mul = (p, k) => ({ x: p.x * k, y: p.y * k });
    const len = (v) => Math.hypot(v.x, v.y);
    const norm = (v) => {
        const L = len(v);
        if (!isFinite(L) || L <= 1e-12) return null;
        return { x: v.x / L, y: v.y / L };
    };
    const dot = (u, v) => u.x * v.x + u.y * v.y;
    const crossZ = (u, v) => u.x * v.y - u.y * v.x;

    const v1 = sub(B, A); // inbound segment direction
    const v2 = sub(C, B); // outbound segment direction
    const L1 = len(v1);
    const L2 = len(v2);
    if (!isFinite(L1) || !isFinite(L2) || L1 <= 1e-8 || L2 <= 1e-8) return null;
    const d1 = norm(v1);
    const d2 = norm(v2);
    if (!d1 || !d2) return null;

    const cosTh = Math.max(-1, Math.min(1, dot(d1, d2)));
    const theta = Math.acos(cosTh); // 0..pi
    if (!isFinite(theta) || theta < (2 * Math.PI / 180) || theta > (175 * Math.PI / 180)) return null;

    const tanHalf = Math.tan(theta * 0.5);
    if (!isFinite(tanHalf) || tanHalf <= 1e-8) return null;
    const tDeg = rDeg * tanHalf; // tangent distance from corner along each leg (in local degrees)
    if (!isFinite(tDeg) || tDeg <= 0) return null;
    if (tDeg >= L1 || tDeg >= L2) return null; // arc doesn't fit

    const T1 = add(B, mul(d1, -tDeg)); // before corner on inbound leg
    const T2 = add(B, mul(d2, +tDeg)); // after corner on outbound leg

    const turnZ = crossZ(d1, d2);
    if (!isFinite(turnZ) || Math.abs(turnZ) < 1e-12) return null;
    const left = turnZ > 0;
    const n1 = left ? { x: -d1.y, y: d1.x } : { x: d1.y, y: -d1.x };
    const n2 = left ? { x: -d2.y, y: d2.x } : { x: d2.y, y: -d2.x };

    const C1 = add(T1, mul(n1, rDeg));
    const C2 = add(T2, mul(n2, rDeg));
    const center = { x: (C1.x + C2.x) * 0.5, y: (C1.y + C2.y) * 0.5 };

    const ang1 = Math.atan2(T1.y - center.y, T1.x - center.x);
    const ang2 = Math.atan2(T2.y - center.y, T2.x - center.x);
    if (![ang1, ang2].every(isFinite)) return null;

    const wrapPi = (a) => {
        let x = a;
        while (x <= -Math.PI) x += 2 * Math.PI;
        while (x > Math.PI) x -= 2 * Math.PI;
        return x;
    };
    const delta = left ? (wrapPi(ang2 - ang1) <= 0 ? wrapPi(ang2 - ang1) + 2 * Math.PI : wrapPi(ang2 - ang1))
                       : (wrapPi(ang1 - ang2) <= 0 ? wrapPi(ang1 - ang2) + 2 * Math.PI : wrapPi(ang1 - ang2));
    if (!isFinite(delta) || delta <= 0) return null;

    // Sample arc with ~0.25 NM spacing, capped.
    const arcLenNm = rNm * delta;
    const stepNm = 0.25;
    const n = Math.max(4, Math.min(120, Math.ceil(arcLenNm / stepNm)));
    const pts = [];
    for (let i = 0; i <= n; i++) {
        const f = i / n;
        const a = left ? (ang1 + delta * f) : (ang1 - delta * f);
        pts.push({ x: center.x + Math.cos(a) * rDeg, y: center.y + Math.sin(a) * rDeg });
    }

    return { t1: T1, t2: T2, arcPts: pts };
}

function computeFlyByLeadDistanceNm(ac, gsKt, inboundCourseDeg, outboundCourseDeg) {
    const deltaDeg = smallestHeadingDeltaAbs(inboundCourseDeg, outboundCourseDeg);
    if (deltaDeg == null || !isFinite(deltaDeg) || deltaDeg < 2) return 0; // ignore tiny bends
    // Avoid extreme tan() blow-ups near 180°.
    const clampedDeg = Math.max(0, Math.min(175, deltaDeg));
    // Use the *lowest* turn rate in the FL band (largest radius), per sim behavior request.
    const minDps = getMinTurnRateDpsForAircraft(ac);
    const rNm = getTurnRadiusNmFromGsAndTurnRate(gsKt, minDps);
    if (rNm == null) return 0;
    const leadNm = rNm * Math.tan((clampedDeg * Math.PI / 180) * 0.5);
    if (!isFinite(leadNm) || leadNm <= 0) return 0;
    // Keep the sim stable: never lead more than 25nm.
    return Math.max(0, Math.min(25, leadNm));
}

function rebuildAircraftDatabase() {
    const rawOverrides = loadAircraftDbOverridesRaw();
    const parsed = parseAircraftDatabase(rawOverrides); // permissive at runtime; modal save is strict
    AIRCRAFT_DB_OVERRIDES = parsed;
    AIRCRAFT_DB = { ...AIRCRAFT_DB_DEFAULT, ...AIRCRAFT_DB_OVERRIDES };
    AIRCRAFT_TYPES = Object.keys(AIRCRAFT_DB).sort();
}

