function normalizeSubFlowRecord(sf) {
    if (!sf || typeof sf !== 'object') return null;
    const id = String(sf.id || '').trim() || (Date.now().toString() + Math.random().toString(16).slice(2));
    return {
        id,
        name: String(sf.name || '').trim() || 'Sub-flow',
        route: String(sf.route || '').trim(),
        callsignLetters: String(sf.callsignLetters || '').trim(),
        adepAdesPairs: String(sf.adepAdesPairs || '').trim(),
        pelAlvRlvPairs: String(sf.pelAlvRlvPairs || '').trim(),
        departureProfile: !!sf.departureProfile
    };
}

function normalizeFlowRecord(fl) {
    if (!fl || typeof fl !== 'object') return null;
    const id = String(fl.id || '').trim() || (Date.now().toString() + Math.random().toString(16).slice(2));
    const lat = Number(fl.lat);
    const lon = Number(fl.lon);
    if (!isFinite(lat) || !isFinite(lon)) return null;
    const name = String(fl.name || 'Flow').trim() || 'Flow';
    const color = typeof fl.color === 'string' && /^#[0-9A-Fa-f]{6}$/.test(fl.color.trim()) ? fl.color.trim() : '#3388ff';
    const r = Number(fl.radiusNm);
    const radiusNm = Number.isFinite(r) && r > 0 ? r : 5;
    const subFlowsRaw = Array.isArray(fl.subFlows) ? fl.subFlows : [];
    const subFlows = subFlowsRaw.map(normalizeSubFlowRecord).filter(Boolean);
    return { id, name, color, radiusNm, lat, lon, subFlows };
}

function normalizeFlowsFromSector(sector) {
    const raw = Array.isArray(sector?.flows) ? sector.flows : [];
    return raw.map(normalizeFlowRecord).filter(Boolean);
}

function persistSectorFlowsToCache(sectorId, flows) {
    const sectors = getSectors();
    const i = sectors.findIndex(s => s && s.id === sectorId);
    if (i === -1) return;
    const copy = (flows || []).map(f => ({
        id: String(f.id),
        name: String(f.name || 'Flow'),
        color: String(f.color || '#3388ff'),
        radiusNm: Number.isFinite(Number(f.radiusNm)) && Number(f.radiusNm) > 0 ? Number(f.radiusNm) : 5,
        lat: Number(f.lat),
        lon: Number(f.lon),
        subFlows: Array.isArray(f.subFlows) ? f.subFlows.map(sf => ({
            id: String(sf.id),
            name: String(sf.name || 'Sub-flow'),
            route: String(sf.route || ''),
            callsignLetters: String(sf.callsignLetters || ''),
            adepAdesPairs: String(sf.adepAdesPairs || ''),
            pelAlvRlvPairs: String(sf.pelAlvRlvPairs || ''),
            departureProfile: !!sf.departureProfile
        })) : []
    })).filter(f => f.id && isFinite(f.lat) && isFinite(f.lon));
    sectors[i] = { ...sectors[i], flows: copy };
    if (currentEditingSector && currentEditingSector.id === sectorId) {
        currentEditingSector = sectors[i];
    }
}

function exerciseEditorNmToPixelRadiiAtLatLon(lat, lon, radiusNm) {
    const p0 = exerciseEditorLatLonToCanvasXY(lat, lon);
    if (!p0 || !isFinite(radiusNm) || radiusNm <= 0) return { rx: 6, ry: 6 };
    const dLat = radiusNm / 60;
    const lat1 = lat + dLat;
    const p1 = exerciseEditorLatLonToCanvasXY(lat1, lon);
    const ry = Math.max(2, Math.abs(p1.y - p0.y));
    const c = Math.cos((lat * Math.PI) / 180);
    const dLon = (c && Math.abs(c) > 1e-10) ? radiusNm / (60 * c) : radiusNm / 60;
    const lon1 = lon + dLon;
    const p2 = exerciseEditorLatLonToCanvasXY(lat, lon1);
    const rx = Math.max(2, Math.abs(p2.x - p0.x));
    return { rx, ry };
}

function drawExerciseEditorFlowsLayer(ctx) {
    const flows = currentEditingFlows || [];
    if (!flows.length) return;
    flows.forEach(f => {
        if (!f || !isFinite(f.lat) || !isFinite(f.lon)) return;
        const xy = exerciseEditorLatLonToCanvasXY(f.lat, f.lon);
        if (!xy) return;
        const color = f.color || '#3388ff';
        const rNm = Number.isFinite(f.radiusNm) && f.radiusNm > 0 ? f.radiusNm : 5;
        const { rx, ry } = exerciseEditorNmToPixelRadiiAtLatLon(f.lat, f.lon, rNm);
        ctx.save();
        ctx.globalAlpha = 0.28;
        ctx.fillStyle = color;
        ctx.beginPath();
        ctx.ellipse(xy.x, xy.y, rx, ry, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 0.85;
        ctx.strokeStyle = color;
        ctx.lineWidth = 2;
        ctx.stroke();
        ctx.restore();
        ctx.save();
        ctx.fillStyle = 'rgba(40, 40, 40, 0.92)';
        ctx.font = '12px Arial';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'top';
        ctx.fillText(f.name || 'Flow', xy.x, xy.y + ry + 4);
        ctx.restore();
    });
}

function drawExerciseEditorFlowPickWaypointHighlight(ctx, waypoints) {
    if ((!addFlowPickActive && !flowRepositionPickActive) || !flowMapPickHoverWpId) return;
    const w = waypoints.find(wp => wp && wp.id === flowMapPickHoverWpId);
    if (!w || !isFinite(w.latitude) || !isFinite(w.longitude)) return;
    const xy = exerciseEditorLatLonToCanvasXY(w.latitude, w.longitude);
    if (!xy) return;
    ctx.save();
    ctx.strokeStyle = 'rgba(255, 193, 7, 0.95)';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.arc(xy.x, xy.y, 12, 0, Math.PI * 2);
    ctx.stroke();
    ctx.restore();
}

function cancelFlowRepositionPick() {
    flowRepositionPickActive = false;
    flowRepositionTargetFlowId = null;
    flowMapPickHoverWpId = null;
    addFlowPickHoverRaf = null;
    const hint = document.getElementById('editExerciseAddFlowHint');
    if (hint) {
        hint.textContent = hint.dataset.defaultHint || 'Select a position on the map with middle-click where the flow will be located.';
        hint.style.display = 'none';
    }
    try { drawExerciseEditorCanvas(); } catch (e) {}
}

