function toggleAddFlowPickMode() {
    if (!currentEditingExerciseId || !currentEditingSectorId) return;
    if (flowRepositionPickActive) {
        cancelFlowRepositionPick();
    }
    if (addFlowPickActive) {
        cancelAddFlowPickMode();
        return;
    }
    if (!currentEditingSector) {
        alert('No airspace loaded for this exercise.');
        return;
    }
    if (!document.getElementById('editExerciseModal')?.classList.contains('active')) return;
    addFlowPickActive = true;
    const btn = document.getElementById('editExerciseAddFlowBtn');
    if (btn) btn.classList.add('add-flow-pick-active');
    const hint = document.getElementById('editExerciseAddFlowHint');
    if (hint) {
        hint.textContent = hint.dataset.defaultHint || 'Select a position on the map with middle-click where the flow will be located.';
        hint.style.display = 'block';
    }
    try { drawExerciseEditorCanvas(); } catch (e) {}
}

