const SUBFLOW_VALIDATED_INPUT_IDS = [
    'subFlowNameInput',
    'subFlowRouteInput',
    'subFlowCallsignLettersInput',
    'subFlowAdepAdesPairsInput',
    'subFlowPelAlvRlvPairsInput'
];

function clearSubFlowFormValidation() {
    SUBFLOW_VALIDATED_INPUT_IDS.forEach(id => {
        document.getElementById(id)?.classList.remove('form-input--invalid');
    });
}

function markSubFlowFieldsInvalid(ids) {
    [...new Set(ids)].forEach(id => document.getElementById(id)?.classList.add('form-input--invalid'));
}

/**
 * Validates all sub-flow fields (mandatory + format). Marks invalid inputs red and alerts.
 * @returns {{ name: string, route: string, callsignLetters: string, adepAdesPairs: string, pelAlvRlvPairs: string, departureProfile: boolean }|null}
 */
function validateSubFlowFormAndGetData() {
    clearSubFlowFormValidation();
    const issues = [];

    const name = (document.getElementById('subFlowNameInput')?.value || '').trim();
    if (!name) {
        issues.push({ id: 'subFlowNameInput', msg: 'Name of sub-flow is required.' });
    } else if (name.length > 120) {
        issues.push({ id: 'subFlowNameInput', msg: 'Name must be 120 characters or fewer.' });
    }

    const route = (document.getElementById('subFlowRouteInput')?.value || '').trim();
    if (!route) {
        issues.push({ id: 'subFlowRouteInput', msg: 'Route is required. Enter a route or use Pick on Map.' });
    } else {
        const sector = currentEditingSector;
        if (sector && Array.isArray(sector.routes)) {
            const { error, points } = computeExerciseRoutePoints(route, getRouteFixesForSector(sector), sector.routes);
            if (error) {
                issues.push({ id: 'subFlowRouteInput', msg: `Route is invalid for this airspace: ${error}` });
            } else if (!points || !points.length) {
                issues.push({ id: 'subFlowRouteInput', msg: 'Route must resolve to at least one track point in this airspace.' });
            }
        } else {
            issues.push({ id: 'subFlowRouteInput', msg: 'Cannot validate route — no airspace data loaded. Open Edit Exercise for this sector first.' });
        }
    }

    let callsignNormalized = '';
    const csRaw = (document.getElementById('subFlowCallsignLettersInput')?.value || '').trim();
    if (!csRaw) {
        issues.push({
            id: 'subFlowCallsignLettersInput',
            msg: 'Callsigns are required. Use letter-only groups (no digits), separated by commas. Example: ETD, UAE, FAD.'
        });
    } else {
        const csTokens = csRaw.split(',').map(s => s.trim()).filter(Boolean);
        if (!csTokens.length) {
            issues.push({
                id: 'subFlowCallsignLettersInput',
                msg: 'Enter at least one callsign letter group, separated by commas.'
            });
        } else {
            let csBad = false;
            for (const t of csTokens) {
                if (!/^[A-Za-z]+$/.test(t)) {
                    csBad = true;
                    break;
                }
            }
            if (csBad) {
                issues.push({
                    id: 'subFlowCallsignLettersInput',
                    msg: 'Each callsign must use letters only (no digits or spaces). Separate groups with commas. Example: ETD, UAE.'
                });
            } else {
                callsignNormalized = csTokens.map(t => t.toUpperCase()).join(', ');
            }
        }
    }

    let pairsNormalized = '';
    const pairsRaw = (document.getElementById('subFlowAdepAdesPairsInput')?.value || '').trim();
    if (!pairsRaw) {
        issues.push({
            id: 'subFlowAdepAdesPairsInput',
            msg: 'ADEP and ADES pairs are required. Example: OBBI OMDB, OTHH OBBI (comma between pairs; space between ADEP and ADES).'
        });
    } else {
        const pairSegs = pairsRaw.split(',').map(s => s.trim()).filter(Boolean);
        if (!pairSegs.length) {
            issues.push({
                id: 'subFlowAdepAdesPairsInput',
                msg: 'Enter at least one ADEP ADES pair.'
            });
        } else {
            const normPairs = [];
            let pairsBad = false;
            for (const seg of pairSegs) {
                const parts = seg.split(/\s+/).filter(Boolean);
                if (parts.length !== 2) {
                    issues.push({
                        id: 'subFlowAdepAdesPairsInput',
                        msg: 'Each pair must be exactly two ICAO codes (ADEP then ADES), separated by a space. Example: OBBI OMDB.'
                    });
                    pairsBad = true;
                    break;
                }
                for (const p of parts) {
                    const u = p.toUpperCase();
                    if (!/^[A-Z]{4}$/.test(u)) {
                        issues.push({
                            id: 'subFlowAdepAdesPairsInput',
                            msg: 'Each airport code must be exactly 4 letters (ICAO). Example: OBBI OMDB.'
                        });
                        pairsBad = true;
                        break;
                    }
                }
                if (pairsBad) break;
                normPairs.push(`${parts[0].toUpperCase()} ${parts[1].toUpperCase()}`);
            }
            if (!pairsBad) pairsNormalized = normPairs.join(', ');
        }
    }

    let pelNormalized = '';
    const pelRaw = (document.getElementById('subFlowPelAlvRlvPairsInput')?.value || '').trim();
    if (!pelRaw) {
        issues.push({
            id: 'subFlowPelAlvRlvPairsInput',
            msg: 'PEL ALV RLV triplets are required. Example: 350 330 370, 310 310 310 (comma separates each triplet).'
        });
    } else {
        const tripSegs = pelRaw.split(',').map(s => s.trim()).filter(Boolean);
        if (!tripSegs.length) {
            issues.push({
                id: 'subFlowPelAlvRlvPairsInput',
                msg: 'Enter at least one PEL ALV RLV triplet.'
            });
        } else {
            const normTrips = [];
            let pelBad = false;
            for (const seg of tripSegs) {
                const parts = seg.split(/\s+/).filter(Boolean);
                if (parts.length !== 3) {
                    issues.push({
                        id: 'subFlowPelAlvRlvPairsInput',
                        msg: 'Each entry must be exactly three flight levels: PEL, ALV, then RLV, separated by spaces. Example: 350 330 370.'
                    });
                    pelBad = true;
                    break;
                }
                for (const p of parts) {
                    if (!/^\d{1,3}$/.test(p)) {
                        issues.push({
                            id: 'subFlowPelAlvRlvPairsInput',
                            msg: 'Each flight level must be a whole number (1–3 digits). Example: 350 330 370.'
                        });
                        pelBad = true;
                        break;
                    }
                    const n = parseInt(p, 10);
                    if (n < 0 || n > 500) {
                        issues.push({
                            id: 'subFlowPelAlvRlvPairsInput',
                            msg: 'Each flight level must be between 0 and 500.'
                        });
                        pelBad = true;
                        break;
                    }
                }
                if (pelBad) break;
                normTrips.push(parts.join(' '));
            }
            if (!pelBad) pelNormalized = normTrips.join(', ');
        }
    }

    const departureProfile = !!document.getElementById('subFlowDepartureProfile')?.checked;

    if (issues.length) {
        markSubFlowFieldsInvalid(issues.map(i => i.id));
        alert('Please correct the highlighted fields:\n\n' + issues.map(i => '• ' + i.msg).join('\n'));
        document.getElementById(issues[0].id)?.focus();
        return null;
    }

    return {
        name,
        route,
        callsignLetters: callsignNormalized,
        adepAdesPairs: pairsNormalized,
        pelAlvRlvPairs: pelNormalized,
        departureProfile
    };
}

function openCreateSubFlowModal() {
    if (!flowDetailsReadModalFlowId) {
        alert('Open Flow details first.');
        return;
    }
    resetCreateSubFlowModalMode();
    const form = document.getElementById('createSubFlowForm');
    if (form) form.reset();
    document.getElementById('subFlowRouteInput').value = '';
    clearSubFlowFormValidation();
    applyCreateSubFlowModalTitleForMode();
    openModal('createSubFlowModal');
    setTimeout(() => document.getElementById('subFlowNameInput')?.focus(), 50);
}

function openEditSubFlowModal(subFlowId) {
    const parentId = flowDetailsReadModalFlowId;
    if (!parentId || !subFlowId) return;
    const flow = currentEditingFlows.find(f => f && f.id === parentId);
    const sf = flow && Array.isArray(flow.subFlows) ? flow.subFlows.find(s => s && s.id === subFlowId) : null;
    if (!sf) return;
    createSubFlowModalMode = 'edit';
    createSubFlowEditingId = subFlowId;
    clearSubFlowFormValidation();
    document.getElementById('subFlowNameInput').value = sf.name || '';
    document.getElementById('subFlowRouteInput').value = sf.route || '';
    document.getElementById('subFlowCallsignLettersInput').value = sf.callsignLetters || '';
    document.getElementById('subFlowAdepAdesPairsInput').value = sf.adepAdesPairs || '';
    document.getElementById('subFlowPelAlvRlvPairsInput').value = sf.pelAlvRlvPairs || '';
    const dep = document.getElementById('subFlowDepartureProfile');
    if (dep) dep.checked = !!sf.departureProfile;
    applyCreateSubFlowModalTitleForMode();
    openModal('createSubFlowModal');
    setTimeout(() => document.getElementById('subFlowNameInput')?.focus(), 50);
}

function confirmCreateSubFlow() {
    const parentId = flowDetailsReadModalFlowId;
    if (!parentId || !currentEditingSectorId) return;
    const data = validateSubFlowFormAndGetData();
    if (!data) return;
    const { name, route, callsignLetters, adepAdesPairs, pelAlvRlvPairs, departureProfile } = data;
    const idx = currentEditingFlows.findIndex(f => f && f.id === parentId);
    if (idx === -1) return;
    const flow = currentEditingFlows[idx];
    const nextSubs = Array.isArray(flow.subFlows) ? flow.subFlows.slice() : [];

    if (createSubFlowModalMode === 'edit' && createSubFlowEditingId) {
        const si = nextSubs.findIndex(s => s && s.id === createSubFlowEditingId);
        if (si === -1) return;
        nextSubs[si] = {
            ...nextSubs[si],
            name,
            route,
            callsignLetters,
            adepAdesPairs,
            pelAlvRlvPairs,
            departureProfile
        };
    } else {
        const sub = {
            id: Date.now().toString() + Math.random().toString(16).slice(2),
            name,
            route,
            callsignLetters,
            adepAdesPairs,
            pelAlvRlvPairs,
            departureProfile
        };
        nextSubs.push(sub);
    }

    currentEditingFlows[idx] = { ...flow, subFlows: nextSubs };
    persistSectorFlowsToCache(currentEditingSectorId, currentEditingFlows);
    closeModal('createSubFlowModal');
    clearSubFlowFormValidation();
    resetCreateSubFlowModalMode();
    renderFlowDetailsSubFlowsList(parentId);
}

function openDeleteSubFlowConfirm(subFlowId) {
    const parentId = flowDetailsReadModalFlowId;
    if (!parentId) return;
    const flow = currentEditingFlows.find(f => f && f.id === parentId);
    const sf = flow && Array.isArray(flow.subFlows) ? flow.subFlows.find(s => s && s.id === subFlowId) : null;
    if (!sf) return;
    deleteSubFlowPendingId = subFlowId;
    const msg = document.getElementById('deleteSubFlowConfirmMessage');
    if (msg) msg.textContent = `Do you want to delete Sub-flow "${sf.name || 'Sub-flow'}"?`;
    openModal('deleteSubFlowConfirmModal');
}

function confirmDeleteSubFlow() {
    const parentId = flowDetailsReadModalFlowId;
    if (!parentId || !deleteSubFlowPendingId || !currentEditingSectorId) {
        closeModal('deleteSubFlowConfirmModal');
        deleteSubFlowPendingId = null;
        return;
    }
    const idx = currentEditingFlows.findIndex(f => f && f.id === parentId);
    if (idx === -1) {
        closeModal('deleteSubFlowConfirmModal');
        deleteSubFlowPendingId = null;
        return;
    }
    const flow = currentEditingFlows[idx];
    const nextSubs = (Array.isArray(flow.subFlows) ? flow.subFlows : []).filter(s => s && s.id !== deleteSubFlowPendingId);
    currentEditingFlows[idx] = { ...flow, subFlows: nextSubs };
    persistSectorFlowsToCache(currentEditingSectorId, currentEditingFlows);
    deleteSubFlowPendingId = null;
    closeModal('deleteSubFlowConfirmModal');
    renderFlowDetailsSubFlowsList(parentId);
}

