function closeAddFlowDetailsModalOnly() {
    closeModal('addFlowDetailsModal');
}

function confirmAddFlowFromDetailsModal() {
    const nameRaw = document.getElementById('addFlowNameInput')?.value;
    const name = (nameRaw || '').trim() || 'Flow';
    let color = (document.getElementById('addFlowColorInput')?.value || '#3388ff').trim();
    if (!/^#[0-9A-Fa-f]{6}$/.test(color)) color = '#3388ff';
    const radiusRaw = parseFloat(document.getElementById('addFlowRadiusNmInput')?.value);
    const radiusNm = Number.isFinite(radiusRaw) && radiusRaw > 0 ? radiusRaw : 5;

    if (flowDetailsModalMode === 'edit' && flowDetailsEditingId) {
        if (!currentEditingSectorId) {
            closeAddFlowDetailsModalOnly();
            resetAfterFlowDetailsSave();
            return;
        }
        const idx = currentEditingFlows.findIndex(f => f && f.id === flowDetailsEditingId);
        if (idx === -1) {
            closeAddFlowDetailsModalOnly();
            resetAfterFlowDetailsSave();
            return;
        }
        const prev = currentEditingFlows[idx];
        const lat = pendingFlowPickLat;
        const lon = pendingFlowPickLon;
        const latF = isFinite(lat) && isFinite(lon) ? lat : prev.lat;
        const lonF = isFinite(lat) && isFinite(lon) ? lon : prev.lon;
        currentEditingFlows[idx] = {
            ...prev,
            name,
            color,
            radiusNm,
            lat: latF,
            lon: lonF
        };
        persistSectorFlowsToCache(currentEditingSectorId, currentEditingFlows);
        closeAddFlowDetailsModalOnly();
        resetAfterFlowDetailsSave();
        renderEditExerciseExistingFlowsList();
        try { drawExerciseEditorCanvas(); } catch (e) {}
        return;
    }

    const lat = pendingFlowPickLat;
    const lon = pendingFlowPickLon;
    if (lat == null || lon == null || !currentEditingSectorId) {
        closeAddFlowDetailsModalOnly();
        resetAfterFlowDetailsSave();
        return;
    }
    const id = Date.now().toString() + Math.random().toString(16).slice(2);
    const flow = { id, name, color, radiusNm, lat, lon, subFlows: [] };
    currentEditingFlows.push(flow);
    persistSectorFlowsToCache(currentEditingSectorId, currentEditingFlows);
    closeAddFlowDetailsModalOnly();
    resetAfterFlowDetailsSave();
    renderEditExerciseExistingFlowsList();
    try { drawExerciseEditorCanvas(); } catch (e) {}
}

