async function confirmSaveFlowsPackage() {
    const name = (document.getElementById('saveFlowsPackageNameInput')?.value || '').trim();
    if (!name) {
        alert('Enter a name for this flows package.');
        return;
    }
    if (!currentEditingSectorId || !currentEditingExerciseId) {
        alert('Select an airspace and exercise first.');
        return;
    }
    if (!currentEditingFlows.length) {
        alert('Create at least one flow before saving.');
        return;
    }
    const sector = getSectors().find(s => s && s.id === currentEditingSectorId);
    const sectorName = (sector && sector.name) ? String(sector.name) : '';
    const snapshot = cloneFlowsForLibrary(currentEditingFlows);
    try {
        const res = await fetch('/api/flows', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                append: {
                    packageName: name,
                    sectorId: currentEditingSectorId,
                    sectorName,
                    flows: snapshot
                }
            })
        });
        const data = await res.json().catch(() => ({}));
        if (!data.ok) {
            alert((data && data.error) ? String(data.error) : 'Could not save flows package.');
            return;
        }
        if (Array.isArray(data.flows)) serverFlowsLibraryCache = data.flows;
        else await loadFlowsLibraryFromServer();
        closeModal('saveFlowsPackageModal');
        const inp = document.getElementById('saveFlowsPackageNameInput');
        if (inp) inp.value = '';
        clearEditingFlowsAfterLibrarySave();
        alert(`Flows saved as “${name}”. The Create Flows editor has been cleared.`);
    } catch (e) {
        alert('Could not save flows package.');
    }
}

function normalizeCallsign(cs) {
    return (cs || '').trim().toUpperCase();
}

function callsignHasSpaces(cs) {
    return /\s/.test(cs || '');
}

function isCallsignUniqueInExercise(callsign, ignoreFlightId = null) {
    const target = normalizeCallsign(callsign);
    if (!target) return false;
    return !currentEditingFlights.some(f =>
        f &&
        normalizeCallsign(f.callsign) === target &&
        (!ignoreFlightId || f.id !== ignoreFlightId)
    );
}

function initNewCallsignCounter() {
    let max = 0;
    currentEditingFlights.forEach(f => {
        const m = (f?.callsign || '').toUpperCase().match(/^NEW(\d{3})$/);
        if (m) {
            const n = parseInt(m[1], 10);
            if (Number.isFinite(n)) max = Math.max(max, n);
        }
    });
    newCallsignCounter = max + 1;
    if (newCallsignCounter < 1) newCallsignCounter = 1;
}

function generateUniqueNewCallsign() {
    const used = new Set(currentEditingFlights.map(f => normalizeCallsign(f?.callsign)));
    for (let i = 0; i < 100000; i++) {
        const candidate = `NEW${String(newCallsignCounter).padStart(3, '0')}`;
        newCallsignCounter += 1;
        if (!used.has(candidate)) return candidate;
    }
    return `NEW${Date.now().toString().slice(-3)}`;
}

function populateEditExerciseSectorSelect() {
    const select = document.getElementById('editExerciseSectorSelect');
    const exerciseSelect = document.getElementById('editExerciseSelect');
    if (!select || !exerciseSelect) return;
    const sectors = getSectors();
    select.innerHTML = '<option value="">Select an Airspace</option>';
    sectors.forEach(s => {
        const opt = document.createElement('option');
        opt.value = s.id;
        opt.textContent = s.name;
        select.appendChild(opt);
    });
    exerciseSelect.innerHTML = '<option value="">-- Select Exercise --</option>';
    exerciseSelect.disabled = true;
}

function populateEditExerciseSelect(sectorId) {
    const exerciseSelect = document.getElementById('editExerciseSelect');
    if (!exerciseSelect) return;
    const exercises = getExercises().filter(ex => ex && ex.sectorId === sectorId);
    exerciseSelect.innerHTML = '<option value="">-- Select Exercise --</option>';
    exercises.forEach(ex => {
        const opt = document.createElement('option');
        opt.value = ex.id;
        opt.textContent = ex.name;
        exerciseSelect.appendChild(opt);
    });
    exerciseSelect.disabled = false;
}

