const FLIGHT_PLAN_CSV_HEADERS = [
    'Callsign (no spaces)',
    'Aircraft Type',
    'ADEP',
    'ADES',
    'Departure',
    'Route (space-separated)',
    'Spawn time (s)',
    'PEL',
    'ALV',
    'RLV'
];

function csvEscapeCell(value) {
    const s = value == null ? '' : String(value);
    if (/[\r\n",]/.test(s)) return `"${s.replace(/"/g, '""')}"`;
    return s;
}

function flightPlanCsvRowValues(f) {
    return [
        f.callsign ?? '',
        f.aircraftType ?? '',
        f.departure ?? '',
        f.destination ?? '',
        f.departureProfile ? 'Yes' : 'No',
        f.route ?? '',
        f.spawnTime ?? '',
        f.pel ?? '',
        f.alv ?? '',
        f.rlv ?? ''
    ];
}

function exportExerciseFlightsToCsv() {
    if (!currentEditingExerciseId || !currentEditingFlights.length) return;
    const exercises = getExercises();
    const exercise = exercises.find(ex => ex && ex.id === currentEditingExerciseId);
    const rawName = (exercise && exercise.name) ? String(exercise.name) : 'exercise';
    const safeBase = rawName.replace(/[^\w\-]+/g, '_').replace(/^_+|_+$/g, '').slice(0, 48) || 'exercise';
    const headerLine = FLIGHT_PLAN_CSV_HEADERS.map(csvEscapeCell).join(',');
    const dataLines = currentEditingFlights.map(f => flightPlanCsvRowValues(f).map(csvEscapeCell).join(','));
    const csv = `\uFEFF${[headerLine, ...dataLines].join('\r\n')}`;
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${safeBase}-flights.csv`;
    a.rel = 'noopener';
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);
}

function openExerciseFlightsListTextModal() {
    if (!currentEditingExerciseId || !currentEditingFlights.length) return;
    const ta = document.getElementById('exerciseFlightsListTextArea');
    if (!ta) return;
    const lines = currentEditingFlights.map(f => formatFlightLine(f)).filter(Boolean);
    ta.value = lines.join('\n');
    openModal('exerciseFlightsListTextModal');
    requestAnimationFrame(() => {
        ta.focus();
        ta.select();
    });
}

function copyExerciseFlightsListTextToClipboard() {
    const ta = document.getElementById('exerciseFlightsListTextArea');
    if (!ta) return;
    const text = (ta.value || '').toString();
    if (!text) return;
    const fallback = () => {
        ta.focus();
        ta.select();
        try {
            document.execCommand('copy');
        } catch (e) {}
    };
    if (navigator.clipboard && typeof navigator.clipboard.writeText === 'function') {
        navigator.clipboard.writeText(text).catch(() => fallback());
    } else {
        fallback();
    }
}

const EXERCISE_PREVIEW_PAD_SEC = 15 * 60;

function formatPreviewClockMMSS(totalSeconds) {
    const s = Math.max(0, Math.floor(Number(totalSeconds) || 0));
    const mm = Math.floor(s / 60);
    const ss = s % 60;
    return `${String(mm).padStart(2, '0')}:${String(ss).padStart(2, '0')}`;
}

function invalidateExercisePreviewDerivedCaches() {
    exercisePreviewMaxSecCache = { sig: '', maxSec: null };
    exercisePreviewRouteEndTimesCache = { sig: '', endTimesById: null };
    exercisePreviewIntegrationCache = { sig: '', previewSec: -1, radarSec: -1, acClones: null };
    exerciseSectorLoadCache = { sig: '', data: null };
}

function invalidateExercisePreviewTracksAndDerivedCaches() {
    exercisePreviewTracksCache = { sig: '', tracks: null };
    invalidateExercisePreviewDerivedCaches();
}

function exercisePreviewShouldIntegrateAcAtSimSec(ac, simSec, routeEndTimesById) {
    if (!ac) return false;
    const spawn = parseInt(ac.spawnTimeSec, 10) || 0;
    if (!Number.isFinite(simSec) || simSec < spawn) return false;
    const endT = (routeEndTimesById && ac.id != null && routeEndTimesById[ac.id] != null)
        ? routeEndTimesById[ac.id]
        : ac._previewRouteEndSimSec;
    if (endT != null && simSec > endT) return false;
    return true;
}

function exercisePreviewAircraftActiveAtSimSec(ac, simSec, routeEndTimesById) {
    if (!ac) return false;
    const pts = ac.points || [];
    if (pts.length < 2) {
        const spawn = parseInt(ac.spawnTimeSec, 10) || 0;
        return Number.isFinite(simSec) && simSec >= spawn;
    }
    return exercisePreviewShouldIntegrateAcAtSimSec(ac, simSec, routeEndTimesById);
}

function computeExercisePreviewRouteEndTimesFromTracks(tracks, radarSec) {
    const routeEndTimesById = {};
    if (!tracks || !tracks.length) return routeEndTimesById;

    let maxSpawn = 0;
    let hasRoutable = false;
    for (const ac of tracks) {
        const sp = parseInt(ac?.spawnTimeSec, 10) || 0;
        if (sp > maxSpawn) maxSpawn = sp;
        if ((ac?.points || []).length >= 2) hasRoutable = true;
    }
    if (!hasRoutable) return routeEndTimesById;

    let probeSec = Math.max(maxSpawn + EXERCISE_PREVIEW_PAD_SEC, 60);
    for (let iter = 0; iter < 12; iter++) {
        for (const k of Object.keys(routeEndTimesById)) delete routeEndTimesById[k];
        const acClones = cloneExercisePreviewAircraftTracks(tracks);
        integrateExercisePreviewAircraftBatch(acClones, probeSec, radarSec, null, routeEndTimesById);

        const allDone = tracks.every(ac => {
            const pts = ac?.points || [];
            if (pts.length < 2) return true;
            return routeEndTimesById[ac.id] != null;
        });
        if (allDone) break;
        probeSec = Math.min(86400, probeSec * 2);
    }
    return routeEndTimesById;
}

function getExercisePreviewRouteEndTimesById() {
    const sig = computeExercisePreviewTracksSignature();
    if (exercisePreviewRouteEndTimesCache.sig === sig && exercisePreviewRouteEndTimesCache.endTimesById) {
        return exercisePreviewRouteEndTimesCache.endTimesById;
    }
    const tracks = getExercisePreviewTracksCached();
    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
    const endTimesById = computeExercisePreviewRouteEndTimesFromTracks(tracks, radarSec);
    exercisePreviewRouteEndTimesCache = { sig, endTimesById };
    return endTimesById;
}

function getExercisePreviewIntegratedClonesAtSec(previewSec, radarSec) {
    const sig = computeExercisePreviewTracksSignature();
    const cache = exercisePreviewIntegrationCache;
    if (
        cache.sig === sig
        && cache.previewSec === previewSec
        && cache.radarSec === radarSec
        && Array.isArray(cache.acClones)
    ) {
        cache.acClones.forEach(applyExercisePreviewSavedLabelOffset);
        return cache.acClones;
    }

    const tracks = getExercisePreviewTracksCached();
    const routeEndTimesById = getExercisePreviewRouteEndTimesById();
    const activeTracks = tracks.filter(ac => exercisePreviewAircraftActiveAtSimSec(ac, previewSec, routeEndTimesById));
    const acClones = cloneExercisePreviewAircraftTracks(activeTracks);
    if (acClones.length && previewSec > 0) {
        integrateExercisePreviewAircraftBatch(acClones, previewSec, radarSec, null, routeEndTimesById);
    }
    exercisePreviewIntegrationCache = { sig, previewSec, radarSec, acClones };
    return acClones;
}

function exercisePreviewAircraftHasCompletedRoute(ac) {
    if (!ac) return false;
    const pts = ac.points || [];
    if (pts.length < 2) return false;
    if (ac.routeCompleted) return true;
    const idx = parseInt(ac.routeProgressIdx, 10) || 0;
    return idx >= pts.length - 1;
}

function cloneExercisePreviewAircraftTracks(tracks) {
    const acClones = [];
    (tracks || []).forEach(ac => {
        if (!ac) return;
        let clone;
        try {
            clone = JSON.parse(JSON.stringify(ac));
        } catch (e) {
            clone = { ...ac };
        }
        const savedOff = exercisePreviewLabelOffsetsByAircraftId[clone.id];
        if (savedOff && Number.isFinite(savedOff.labelOffsetX) && Number.isFinite(savedOff.labelOffsetY)) {
            clone.labelOffsetX = savedOff.labelOffsetX;
            clone.labelOffsetY = savedOff.labelOffsetY;
            clone.labelLeaderOffsetToCenter = !!savedOff.labelLeaderOffsetToCenter;
        }
        acClones.push(clone);
    });
    return acClones;
}

function applyExercisePreviewSavedLabelOffset(ac) {
    if (!ac || ac.id == null) return;
    const savedOff = exercisePreviewLabelOffsetsByAircraftId[ac.id];
    if (!savedOff) return;
    if (Number.isFinite(savedOff.labelOffsetX) && Number.isFinite(savedOff.labelOffsetY)) {
        ac.labelOffsetX = savedOff.labelOffsetX;
        ac.labelOffsetY = savedOff.labelOffsetY;
        ac.labelLeaderOffsetToCenter = !!savedOff.labelLeaderOffsetToCenter;
    }
}

function computeExercisePreviewMaxSecondsFromTracks(tracks, radarSec) {
    if (!tracks || !tracks.length) return 0;
    let maxSpawn = 0;
    let hasRoutable = false;
    for (const ac of tracks) {
        const sp = parseInt(ac?.spawnTimeSec, 10) || 0;
        if (sp > maxSpawn) maxSpawn = sp;
        const pts = ac?.points || [];
        if (pts.length >= 2) hasRoutable = true;
    }
    if (!hasRoutable) return maxSpawn + EXERCISE_PREVIEW_PAD_SEC;

    const routeEndTimesById = computeExercisePreviewRouteEndTimesFromTracks(tracks, radarSec);

    let maxEnd = maxSpawn;
    for (const ac of tracks) {
        const sp = parseInt(ac?.spawnTimeSec, 10) || 0;
        const pts = ac?.points || [];
        let end = sp;
        if (pts.length >= 2) {
            const t = routeEndTimesById[ac.id];
            end = t != null ? t : maxSpawn + EXERCISE_PREVIEW_PAD_SEC;
        }
        if (end > maxEnd) maxEnd = end;
    }
    return Math.max(Math.ceil(maxEnd), maxSpawn);
}

function getExercisePreviewMaxSecondsFromFlights() {
    const tracks = getExercisePreviewTracksCached();
    if (!tracks.length) {
        let maxSpawn = 0;
        for (const f of currentEditingFlights) {
            const t = parseInt(f?.spawnTime, 10);
            if (Number.isFinite(t) && t > maxSpawn) maxSpawn = t;
        }
        return maxSpawn + EXERCISE_PREVIEW_PAD_SEC;
    }
    const sig = computeExercisePreviewTracksSignature();
    if (exercisePreviewMaxSecCache.sig === sig && Number.isFinite(exercisePreviewMaxSecCache.maxSec)) {
        return exercisePreviewMaxSecCache.maxSec;
    }
    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
    const maxSec = computeExercisePreviewMaxSecondsFromTracks(tracks, radarSec);
    exercisePreviewMaxSecCache = { sig, maxSec };
    return maxSec;
}

function refreshExercisePreviewTimeSlider() {
    const slider = document.getElementById('exercisePreviewTimeSlider');
    const clock = document.getElementById('exercisePreviewTimeClock');
    if (!slider || !clock) return;

    const hasExercise = !!currentEditingExerciseId;
    const hasFlights = currentEditingFlights.length > 0;
    const maxSec = hasExercise && hasFlights ? getExercisePreviewMaxSecondsFromFlights() : 0;

    if (maxSec <= 0) {
        slider.disabled = true;
        slider.min = '0';
        slider.max = '1';
        slider.value = '0';
        slider.setAttribute('aria-valuetext', '00:00');
        clock.textContent = '00:00';
        try { renderExerciseSectorLoadGraph(); } catch (e) {}
        return;
    }

    slider.disabled = false;
    slider.min = '0';
    slider.max = String(maxSec);
    let v = parseInt(slider.value, 10);
    if (!Number.isFinite(v) || v < 0) v = 0;
    if (v > maxSec) v = maxSec;
    slider.value = String(v);
    const label = formatPreviewClockMMSS(v);
    clock.textContent = label;
    slider.setAttribute('aria-valuetext', label);
    try { renderExerciseSectorLoadGraph(); } catch (e) {}
}

function getExercisePreviewAtcSectorsList() {
    const sector = currentEditingSector;
    if (!sector) return [];
    if (Array.isArray(sector.atcSectors) && sector.atcSectors.length) {
        return sector.atcSectors.filter(s => s && s.boundary && Array.isArray(s.boundary.points) && s.boundary.points.length >= 3);
    }
    return migrateLegacySectorToAtcSectors(sector).filter(s => s && s.boundary && Array.isArray(s.boundary.points) && s.boundary.points.length >= 3);
}

function getAtcSectorSeriesDisplayName(sector, index) {
    const nm = (sector?.name || sector?.id || '').toString().trim();
    return nm || `SECTOR_${index}`;
}

function getExerciseAtcSectorDisplayNameById(atcSectorId) {
    if (atcSectorId == null || atcSectorId === '') return '—';
    const list = getExercisePreviewAtcSectorsList();
    const wanted = String(atcSectorId);
    const idx = list.findIndex(s => s && String(s.id) === wanted);
    if (idx >= 0) return getAtcSectorSeriesDisplayName(list[idx], idx);
    const parsed = parseInt(wanted, 10);
    if (Number.isFinite(parsed) && parsed >= 0 && parsed < list.length) {
        return getAtcSectorSeriesDisplayName(list[parsed], parsed);
    }
    return wanted;
}

function computeExerciseSectorLoadSignature() {
    const base = computeExercisePreviewTracksSignature();
    const sectors = getExercisePreviewAtcSectorsList();
    const secSig = sectors.map((s, i) => [
        s.id, getAtcSectorSeriesDisplayName(s, i),
        s.boundary?.points?.length,
        s.verticalLimits?.topFl, s.verticalLimits?.bottomFl, s.verticalLimits?.transitionFl
    ].join(':')).join('|');
    return `${base}::sl::v3timeline::${secSig}`;
}

/**
 * Mode-C FL for exercise preview sector load — same value as label MODE_C_ALT (line 2, field 1)
 * at simSec: published Mode C at the radar step for that moment (supports climb/descent).
 */
function getExercisePreviewModeCFlAtSimSec(ac, simSec, radarSec) {
    if (!ac) return null;
    const spawn = parseInt(ac.spawnTimeSec, 10) || 0;
    if (!Number.isFinite(simSec) || simSec < spawn) return null;

    const st = getAircraftPositionAtRadarUpdate(ac, simSec, radarSec);
    if (!st) return null;

    const pubSec = (st.lastUpdateSimSec != null && isFinite(Number(st.lastUpdateSimSec)))
        ? Number(st.lastUpdateSimSec)
        : simSec;

    const readModeCFeetAtPublishSec = (sec) => {
        const publishedMap = ac._previewPublishedModeCByUpdateSec;
        if (publishedMap instanceof Map && publishedMap.has(sec)) {
            const v = Number(publishedMap.get(sec));
            if (isFinite(v)) return v;
        }
        const kinematicsMap = ac._previewKinematicsBySimSec;
        if (kinematicsMap instanceof Map) {
            for (let s = sec; s >= spawn; s--) {
                const e = kinematicsMap.get(s);
                if (e && isFinite(Number(e.modeCFeet))) return Number(e.modeCFeet);
            }
        }
        return null;
    };

    const mcFeet = readModeCFeetAtPublishSec(pubSec);
    if (!isFinite(mcFeet)) return null;

    return Math.max(0, Math.min(500, Math.trunc(Math.round(mcFeet / 100))));
}

function clearExercisePreviewAircraftTimelineMaps(ac) {
    if (!ac) return;
    ac._previewKinematicsBySimSec = null;
    ac._previewPublishedModeCByUpdateSec = null;
}

function chooseExerciseSectorLoadSampleStepSec(maxSec, radarSec) {
    const base = Math.max(1, parseInt(radarSec, 10) || 1);
    if (maxSec > 7200) return Math.max(base, 60);
    if (maxSec > 3600) return Math.max(base, 30);
    if (maxSec > 1800) return Math.max(base, 15);
    return base;
}

function computeExercisePreviewSectorLoadData() {
    const atcSectors = getExercisePreviewAtcSectorsList();
    const maxSec = getExercisePreviewMaxSecondsFromFlights();
    const tracks = getExercisePreviewTracksCached();
    if (!atcSectors.length || !tracks.length || maxSec <= 0) return null;

    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
    const acClones = cloneExercisePreviewAircraftTracks(tracks);
    const routeEndTimesById = { ...getExercisePreviewRouteEndTimesById() };
    try {
        integrateExercisePreviewAircraftBatch(acClones, maxSec, radarSec, null, routeEndTimesById, { retainPreviewTimeline: true });

        const verticalMeta = buildAtcSectorVerticalMeta(atcSectors);
        const series = atcSectors.map((s, idx) => ({
            sectorId: s.id || String(idx),
            name: getAtcSectorSeriesDisplayName(s, idx),
            color: EXERCISE_SECTOR_LOAD_COLORS[idx % EXERCISE_SECTOR_LOAD_COLORS.length],
            counts: []
        }));

        const stepSec = chooseExerciseSectorLoadSampleStepSec(maxSec, radarSec);
        const times = [];
        for (let t = 0; t <= maxSec; t += stepSec) times.push(t);
        if (!times.length || times[times.length - 1] !== maxSec) times.push(maxSec);

        for (const t of times) {
            const countsByIdx = new Array(series.length).fill(0);
            for (const ac of acClones) {
                if (!ac) continue;
                const spawn = parseInt(ac.spawnTimeSec, 10) || 0;
                if (t < spawn) continue;
                const endT = routeEndTimesById[ac.id];
                if (endT != null && t >= endT) continue;
                const st = getAircraftPositionAtRadarUpdate(ac, t, radarSec);
                if (!st || !isFinite(st.lat) || !isFinite(st.lon)) continue;
                const modeCFl = getExercisePreviewModeCFlAtSimSec(ac, t, radarSec);
                if (modeCFl == null) continue;
                const sectorIdx = findAtcSectorIndexForSample(st.lat, st.lon, modeCFl, atcSectors, verticalMeta);
                if (sectorIdx < 0) continue;
                countsByIdx[sectorIdx] += 1;
            }
            for (let i = 0; i < series.length; i++) series[i].counts.push(countsByIdx[i]);
        }

        let maxCount = 0;
        for (const row of series) {
            for (const c of row.counts) {
                if (c > maxCount) maxCount = c;
            }
        }

        return { maxSec, stepSec, times, series, maxCount: Math.max(1, maxCount) };
    } finally {
        acClones.forEach(ac => clearExercisePreviewAircraftTimelineMaps(ac));
    }
}

function getExerciseSectorLoadDataCached() {
    const sig = computeExerciseSectorLoadSignature();
    if (exerciseSectorLoadCache.sig === sig && exerciseSectorLoadCache.data) {
        return exerciseSectorLoadCache.data;
    }
    const data = computeExercisePreviewSectorLoadData();
    exerciseSectorLoadCache = { sig, data };
    return data;
}

function interpolateExerciseSectorLoadCountAtTime(seriesRow, times, tSec) {
    if (!seriesRow || !Array.isArray(times) || !times.length) return 0;
    const counts = seriesRow.counts || [];
    if (!counts.length) return 0;
    const t = Number(tSec);
    if (!isFinite(t)) return counts[0] || 0;
    if (t <= times[0]) return counts[0] || 0;
    const lastIdx = times.length - 1;
    if (t >= times[lastIdx]) return counts[lastIdx] || 0;
    for (let i = 0; i < lastIdx; i++) {
        const t0 = times[i];
        const t1 = times[i + 1];
        if (t >= t0 && t <= t1) {
            const c0 = counts[i] || 0;
            const c1 = counts[i + 1] || 0;
            if (t1 <= t0) return c0;
            const frac = (t - t0) / (t1 - t0);
            return c0 + (c1 - c0) * frac;
        }
    }
    return counts[lastIdx] || 0;
}

function layoutExerciseSectorLoadCanvas() {
    const canvas = document.getElementById('exerciseSectorLoadCanvas');
    const panel = document.getElementById('exerciseSectorLoadPanel');
    if (!canvas || !panel || panel.hidden) return;
    const wrap = canvas.closest('.exercise-sector-load-chart-wrap');
    const rect = wrap?.getBoundingClientRect();
    const cssW = Math.max(180, Math.floor((rect && rect.width) ? rect.width - 8 : 280));
    const cssH = 220;
    const dpr = window.devicePixelRatio || 1;
    canvas.width = Math.floor(cssW * dpr);
    canvas.height = Math.floor(cssH * dpr);
    canvas.style.width = `${cssW}px`;
    canvas.style.height = `${cssH}px`;
}

function renderExerciseSectorLoadLegend(data) {
    const legend = document.getElementById('exerciseSectorLoadLegend');
    if (!legend) return;
    if (!data || !data.series || !data.series.length) {
        legend.innerHTML = '<span class="exercise-sector-load-legend-label">No ATC sectors in this airspace.</span>';
        return;
    }
    legend.innerHTML = data.series.map(row => `
        <span class="exercise-sector-load-legend-item" title="${escapeHtml(row.name)}">
            <span class="exercise-sector-load-legend-swatch" style="background:${escapeHtml(row.color)}"></span>
            <span class="exercise-sector-load-legend-label">${escapeHtml(row.name)}</span>
        </span>
    `).join('');
}

function renderExerciseSectorLoadGraph() {
    const panel = document.getElementById('exerciseSectorLoadPanel');
    if (!panel || panel.hidden || !exerciseSectorLoadActive) return;

    layoutExerciseSectorLoadCanvas();
    const canvas = document.getElementById('exerciseSectorLoadCanvas');
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    const cssW = canvas.width / dpr;
    const cssH = canvas.height / dpr;
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.clearRect(0, 0, cssW, cssH);

    const data = getExerciseSectorLoadDataCached();
    renderExerciseSectorLoadLegend(data);

    const margin = { top: 14, right: 10, bottom: 30, left: 34 };
    const plotW = Math.max(10, cssW - margin.left - margin.right);
    const plotH = Math.max(10, cssH - margin.top - margin.bottom);

    if (!data || !data.times || !data.times.length) {
        ctx.fillStyle = 'rgba(245, 247, 250, 0.75)';
        ctx.font = '12px Arial';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('Add flights and ATC sectors to view sector load.', cssW / 2, cssH / 2);
        return;
    }

    const slider = document.getElementById('exercisePreviewTimeSlider');
    const previewSecRaw = slider ? parseInt(slider.value, 10) : 0;
    const previewSec = Number.isFinite(previewSecRaw) ? Math.max(0, Math.min(data.maxSec, previewSecRaw)) : 0;
    const maxY = data.maxCount || 1;
    const maxT = data.maxSec || 1;

    const mapX = (t) => margin.left + (t / maxT) * plotW;
    const mapY = (count) => margin.top + plotH - (count / maxY) * plotH;

    ctx.strokeStyle = 'rgba(245, 247, 250, 0.18)';
    ctx.lineWidth = 1;
    ctx.fillStyle = 'rgba(245, 247, 250, 0.65)';
    ctx.font = '10px Arial';
    ctx.textAlign = 'right';
    ctx.textBaseline = 'middle';
    for (let yTick = 0; yTick <= maxY; yTick++) {
        const y = mapY(yTick);
        ctx.beginPath();
        ctx.moveTo(margin.left, y);
        ctx.lineTo(margin.left + plotW, y);
        ctx.stroke();
        ctx.fillText(String(yTick), margin.left - 6, y);
    }

    const xLabelCount = Math.min(6, Math.max(2, Math.ceil(maxT / 900)));
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    for (let i = 0; i <= xLabelCount; i++) {
        const t = (maxT * i) / xLabelCount;
        const x = mapX(t);
        ctx.beginPath();
        ctx.moveTo(x, margin.top);
        ctx.lineTo(x, margin.top + plotH);
        ctx.stroke();
        ctx.fillText(formatPreviewClockMMSS(Math.round(t)), x, margin.top + plotH + 6);
    }

    ctx.strokeStyle = 'rgba(245, 247, 250, 0.55)';
    ctx.lineWidth = 1.25;
    ctx.beginPath();
    ctx.moveTo(margin.left, margin.top);
    ctx.lineTo(margin.left, margin.top + plotH);
    ctx.lineTo(margin.left + plotW, margin.top + plotH);
    ctx.stroke();

    ctx.fillStyle = 'rgba(245, 247, 250, 0.8)';
    ctx.font = '10px Arial';
    ctx.save();
    ctx.translate(10, margin.top + plotH / 2);
    ctx.rotate(-Math.PI / 2);
    ctx.textAlign = 'center';
    ctx.fillText('Aircraft', 0, 0);
    ctx.restore();
    ctx.textAlign = 'center';
    ctx.fillText('Time', margin.left + plotW / 2, cssH - 4);

    for (const row of data.series) {
        if (!row.counts || !row.counts.length) continue;
        ctx.strokeStyle = row.color;
        ctx.lineWidth = 2;
        ctx.beginPath();
        for (let i = 0; i < data.times.length; i++) {
            const x = mapX(data.times[i]);
            const y = mapY(row.counts[i] || 0);
            if (i === 0) ctx.moveTo(x, y);
            else ctx.lineTo(x, y);
        }
        ctx.stroke();
    }

    const cursorX = mapX(previewSec);
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.85)';
    ctx.lineWidth = 1.5;
    ctx.setLineDash([4, 3]);
    ctx.beginPath();
    ctx.moveTo(cursorX, margin.top);
    ctx.lineTo(cursorX, margin.top + plotH);
    ctx.stroke();
    ctx.setLineDash([]);

    for (const row of data.series) {
        const yVal = interpolateExerciseSectorLoadCountAtTime(row, data.times, previewSec);
        const y = mapY(yVal);
        const countLabel = String(Math.round(yVal));
        ctx.fillStyle = row.color;
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 1.5;
        ctx.beginPath();
        ctx.arc(cursorX, y, 5, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        ctx.fillStyle = '#ffffff';
        ctx.font = 'bold 10px Arial';
        ctx.textAlign = 'left';
        ctx.textBaseline = 'middle';
        const labelX = cursorX + 7;
        const labelY = y;
        ctx.fillText(countLabel, labelX, labelY);
    }
}

function syncExerciseViewOptionsControls() {
    const labelSlider = document.getElementById('exerciseAircraftLabelSizeSlider');
    const labelValueEl = document.getElementById('exerciseAircraftLabelSizeValue');
    const labelSize = Math.min(24, Math.max(8, parseInt(simulationMap?.labelSize ?? SIM_MAP_DEFAULTS.labelSize, 10) || SIM_MAP_DEFAULTS.labelSize));
    if (labelSlider) labelSlider.value = String(labelSize);
    if (labelValueEl) labelValueEl.textContent = String(labelSize);

    const wpSlider = document.getElementById('exerciseWaypointSizeSlider');
    const wpValueEl = document.getElementById('exerciseWaypointSizeValue');
    const wpSize = Math.min(48, Math.max(6, parseInt(simulationMap?.waypointNames?.size ?? SIM_MAP_DEFAULTS.waypointNames.size, 10) || SIM_MAP_DEFAULTS.waypointNames.size));
    if (wpSlider) wpSlider.value = String(wpSize);
    if (wpValueEl) wpValueEl.textContent = String(wpSize);

    const speedVectorCb = document.getElementById('exerciseSpeedVectorCheckbox');
    if (speedVectorCb) speedVectorCb.checked = !!exerciseSpeedVectorEnabled;
}

function setExerciseLeftPanelMode(mode) {
    const nextMode = (mode === 'traffic' || mode === 'view' || mode === 'aiPilot') ? mode : null;
    exerciseSectorLoadActive = nextMode === 'traffic';
    exerciseViewOptionsActive = nextMode === 'view';
    exerciseAiPilotActive = nextMode === 'aiPilot';

    const panel = document.getElementById('exerciseSectorLoadPanel');
    const btn = document.getElementById('exerciseSectorLoadBtn');
    const section = document.getElementById('exerciseSectorLoadSection');
    const viewPanel = document.getElementById('exerciseViewOptionsPanel');
    const viewBtn = document.getElementById('exerciseViewOptionsBtn');
    const aiPilotPanel = document.getElementById('exerciseAiPilotPanel');
    const aiPilotBtn = document.getElementById('exerciseAiPilotBtn');
    const aiPilotSection = document.getElementById('exerciseAiPilotSection');
    const sidebar = document.querySelector('#editExerciseModal .exercise-sidebar');
    if (btn) {
        btn.setAttribute('aria-pressed', exerciseSectorLoadActive ? 'true' : 'false');
    }
    if (viewBtn) {
        viewBtn.setAttribute('aria-pressed', exerciseViewOptionsActive ? 'true' : 'false');
    }
    if (aiPilotBtn) {
        aiPilotBtn.setAttribute('aria-pressed', exerciseAiPilotActive ? 'true' : 'false');
    }
    if (sidebar) {
        sidebar.classList.toggle('exercise-sidebar--traffic-hidden', nextMode == null);
    }
    if (section) {
        section.classList.toggle('exercise-sector-load-section--active', exerciseSectorLoadActive);
    }
    if (aiPilotSection) {
        aiPilotSection.classList.toggle('exercise-ai-pilot-section--active', exerciseAiPilotActive);
    }
    if (panel) panel.hidden = !exerciseSectorLoadActive;
    if (viewPanel) viewPanel.hidden = !exerciseViewOptionsActive;
    if (aiPilotPanel) aiPilotPanel.hidden = !exerciseAiPilotActive;
    if (exerciseSectorLoadActive) {
        exerciseSectorLoadCache = { sig: '', data: null };
        layoutExerciseSectorLoadCanvas();
        renderExerciseSectorLoadGraph();
    } else if (exerciseViewOptionsActive) {
        syncExerciseViewOptionsControls();
    } else if (exerciseAiPilotActive) {
        syncExerciseAiPilotPanelFromExercise();
        renderExerciseScriptsList();
    } else {
        hideExerciseScriptMarkerTooltip();
        exercisePreviewScriptMarkerHoverId = null;
        exercisePreviewInitialCallMarkerHoverId = null;
    }
    try { initExerciseEditorCanvas(); } catch (e) {}
    try { drawExerciseEditorCanvas(); } catch (e2) {}
}

function setExerciseSectorLoadPanelVisible(active) {
    setExerciseLeftPanelMode(active ? 'traffic' : null);
}

function toggleExerciseSectorLoadPanel() {
    setExerciseLeftPanelMode(exerciseSectorLoadActive ? null : 'traffic');
}

function toggleExerciseViewOptionsPanel() {
    setExerciseLeftPanelMode(exerciseViewOptionsActive ? null : 'view');
}

function toggleExerciseAiPilotPanel() {
    setExerciseLeftPanelMode(exerciseAiPilotActive ? null : 'aiPilot');
}

function resetExerciseSectorLoadUi() {
    exerciseSectorLoadActive = false;
    exerciseViewOptionsActive = false;
    exerciseAiPilotActive = false;
    exerciseSectorLoadCache = { sig: '', data: null };
    const panel = document.getElementById('exerciseSectorLoadPanel');
    const btn = document.getElementById('exerciseSectorLoadBtn');
    const viewPanel = document.getElementById('exerciseViewOptionsPanel');
    const viewBtn = document.getElementById('exerciseViewOptionsBtn');
    const aiPilotPanel = document.getElementById('exerciseAiPilotPanel');
    const aiPilotBtn = document.getElementById('exerciseAiPilotBtn');
    const section = document.getElementById('exerciseSectorLoadSection');
    const aiPilotSection = document.getElementById('exerciseAiPilotSection');
    const sidebar = document.querySelector('#editExerciseModal .exercise-sidebar');
    const legend = document.getElementById('exerciseSectorLoadLegend');
    const aiPilotHint = document.getElementById('exerciseAiPilotSavedHint');
    if (panel) panel.hidden = true;
    if (btn) btn.setAttribute('aria-pressed', 'false');
    if (viewPanel) viewPanel.hidden = true;
    if (viewBtn) viewBtn.setAttribute('aria-pressed', 'false');
    if (aiPilotPanel) aiPilotPanel.hidden = true;
    if (aiPilotBtn) aiPilotBtn.setAttribute('aria-pressed', 'false');
    if (sidebar) sidebar.classList.add('exercise-sidebar--traffic-hidden');
    if (section) section.classList.remove('exercise-sector-load-section--active');
    if (aiPilotSection) aiPilotSection.classList.remove('exercise-ai-pilot-section--active');
    if (legend) legend.innerHTML = '';
    if (aiPilotHint) aiPilotHint.textContent = '';
}

function ensureExerciseSectorLoadResizeObserver() {
    const wrap = document.querySelector('.exercise-sector-load-chart-wrap');
    if (!wrap || exerciseSectorLoadResizeObserver) return;
    if (typeof ResizeObserver === 'undefined') return;
    exerciseSectorLoadResizeObserver = new ResizeObserver(() => {
        if (!exerciseSectorLoadActive) return;
        try {
            layoutExerciseSectorLoadCanvas();
            renderExerciseSectorLoadGraph();
        } catch (e) {}
    });
    exerciseSectorLoadResizeObserver.observe(wrap);
}

function computeExercisePreviewTracksSignature() {
    const flightSig = (currentEditingFlights || []).map(f => f && [
        f.id, f.callsign, f.spawnTime, f.route, f.alv, f.pel, f.rlv, f.aircraftType, f.departureProfile ? '1' : '0'
    ].join(':')).filter(Boolean).sort().join('|');
    return `${currentEditingExerciseId || ''}::${currentEditingSectorId || ''}::${flightSig}`;
}

function getExercisePreviewTracksCached() {
    const sig = computeExercisePreviewTracksSignature();
    if (exercisePreviewTracksCache.sig === sig && Array.isArray(exercisePreviewTracksCache.tracks)) {
        return exercisePreviewTracksCache.tracks;
    }
    if (!currentEditingSector || !currentEditingExerciseId) {
        exercisePreviewTracksCache = { sig, tracks: [] };
        return [];
    }
    const tracks = buildSimulationAircraftTracks({
        flights: currentEditingFlights,
        waypoints: getRouteFixesForSector(currentEditingSector),
        routes: currentEditingSector.routes || []
    });
    exercisePreviewTracksCache = { sig, tracks };
    return tracks;
}

/** Radar-step publish for exercise preview clones (matches drawSimulationCanvas MODE-C / GS / route index). */
function publishExercisePreviewRadarFields(ac, state) {
    if (!ac || !state || state.lastUpdateSimSec == null) return;
    ac.lastPublishedRadarUpdateSimSec = state.lastUpdateSimSec;
    ac.publishedModeCFeet = Number.isFinite(Number(ac.modeCFeet)) ? Number(ac.modeCFeet) : ac.publishedModeCFeet;
    ac.publishedRocFpm = Number.isFinite(Number(ac.rocFpm)) ? Number(ac.rocFpm) : ac.publishedRocFpm;
    if (ac.currentHeadingDeg != null && isFinite(ac.currentHeadingDeg)) {
        ac.publishedHeadingDeg = heading0to359(ac.currentHeadingDeg);
    }
    try {
        const pts = ac.points || [];
        const cache = ac._trackCache;
        const cumNm = cache?.cumNm;
        const legsNm = cache?.legsNm;
        if (Array.isArray(pts) && pts.length >= 2 && Array.isArray(cumNm) && Array.isArray(legsNm)) {
            if (ac.navMode === 'heading') {
                let idx = Math.max(0, Math.min(pts.length - 2, parseInt(ac.routeProgressIdx, 10) || 0));
                const PASS_RADIUS_NM = 1.5;
                const ABEAM_MAX_NM = 15;
                let guard = 0;
                while (idx < pts.length - 1 && guard < 5) {
                    const prev = pts[idx];
                    const next = pts[idx + 1];
                    if (!prev || !next || !isFinite(next.lat) || !isFinite(next.lon)) break;
                    const dNext = calculateNauticalMiles(state.lat, state.lon, next.lat, next.lon);
                    const directPass = isFinite(dNext) && dNext <= PASS_RADIUS_NM;
                    let abeamPass = false;
                    if (!directPass && isFinite(dNext) && dNext <= ABEAM_MAX_NM && prev && isFinite(prev.lat) && isFinite(prev.lon)) {
                        const dx = next.lon - prev.lon;
                        const dy = next.lat - prev.lat;
                        const ax = state.lon - next.lon;
                        const ay = state.lat - next.lat;
                        const dot = ax * dx + ay * dy;
                        const legOk = (dx * dx + dy * dy) > 0;
                        abeamPass = legOk && isFinite(dot) && dot > 0;
                    }
                    if (directPass || abeamPass) {
                        idx += 1;
                        guard += 1;
                        continue;
                    }
                    break;
                }
                ac.routeProgressIdx = idx;
                try {
                    if (idx >= pts.length - 1) {
                        ac.routeCompleted = true;
                        ac.silentDirectToWpIdx = null;
                        ac.silentDirectToTurnWpIdx = null;
                        ac.directToWpIdx = null;
                        ac.directToWpName = null;
                        if (ac.selectedHeadingDeg == null || !isFinite(ac.selectedHeadingDeg)) {
                            ac.headingTurnTargetDeg = null;
                            ac.headingTurnStartSimSec = null;
                            ac.headingTurnRateDps = null;
                        }
                    }
                } catch (eDone) {}
                try {
                    const turnIdx = parseInt(ac.silentDirectToTurnWpIdx, 10);
                    if (Number.isFinite(turnIdx) && idx >= turnIdx) {
                        ac.silentDirectToWpIdx = null;
                        ac.silentDirectToTurnWpIdx = null;
                    }
                } catch (eS) {}
                const dctIdx = parseInt(ac.directToWpIdx, 10);
                if (Number.isFinite(dctIdx) && idx >= dctIdx) {
                    ac.directToWpIdx = null;
                    ac.directToWpName = null;
                }
            } else {
                const tNm = Math.max(0, Number(state.traveledNm) || 0);
                let segIdx = 0;
                for (let i = 0; i < legsNm.length; i++) {
                    const s0 = cumNm[i];
                    const s1 = cumNm[i + 1];
                    if (tNm >= s0 && tNm <= s1) { segIdx = i; break; }
                }
                ac.routeProgressIdx = segIdx;
            }
        }
    } catch (e) {}
    if (ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) {
        ac.publishedModeSTasKt = Number(ac.modeSTasKt);
    }
    try {
        const mcFeetNow = Number(ac.publishedModeCFeet ?? ac.modeCFeet);
        const flNow = isFinite(mcFeetNow) ? Math.max(0, Math.min(500, Math.round(mcFeetNow / 100))) : null;
        const hasSpeedCommand = !!(ac.speedSelectedType || ac.speedChangeStartSimSec != null);
        const departureActive = !!ac.departureProfileActive;
        if (hasSpeedCommand && ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) {
            ac.publishedLabelGsKt = Math.round(ac.modeSTasKt);
        } else if (departureActive && ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) {
            ac.publishedLabelGsKt = Math.round(ac.modeSTasKt);
        } else if (flNow != null) {
            const gsLabel = computeGroundSpeedKt(ac.aircraftType, flNow);
            if (gsLabel != null && isFinite(gsLabel)) ac.publishedLabelGsKt = Math.round(gsLabel);
        }
    } catch (e) {}
}

/**
 * Same label speed bookkeeping as drawSimulationCanvas (host, non-joiner): sync modeSTasKt to perf GS at
 * published/Mode-C FL and set state.labelGs; publishedLabelGsKt wins for the G readout when present.
 */
function applyExercisePreviewLabelSpeedState(ac, state) {
    if (!ac || !state || simulationJoinedSessionId) return;
    try { applyAutoSpeedReadoutMode(ac); } catch (e) {}
    try {
        const mcFeet = Number(ac.publishedModeCFeet ?? ac.modeCFeet);
        const flNow = isFinite(mcFeet) ? Math.max(0, Math.min(500, Math.round(mcFeet / 100))) : null;
        const hasSpeedCommand = !!(ac.speedSelectedType || ac.speedChangeStartSimSec != null);
        const departureActive = !!ac.departureProfileActive;
        if (hasSpeedCommand && ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) {
            state.labelGs = Math.round(ac.modeSTasKt);
        } else if (departureActive && ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) {
            state.labelGs = Math.round(ac.modeSTasKt);
        } else if (flNow != null) {
            const gsLabel = computeGroundSpeedKt(ac.aircraftType, flNow);
            if (gsLabel != null && isFinite(gsLabel)) {
                state.labelGs = gsLabel;
                ac.modeSTasKt = gsLabel;
            }
        }
    } catch (e) {}
    if (ac.publishedLabelGsKt != null && isFinite(ac.publishedLabelGsKt)) {
        state.labelGs = Number(ac.publishedLabelGsKt);
    }
}

/**
 * Cruise / level-flight preview: keep Mode-S KTAS aligned with AIRCRAFT_DB via computeGroundSpeedKt for current Mode-C FL.
 * (updateSimulationAircraftSpeeds only integrates departure + speed commands + speed-change ramps; it does not refresh cruise KTAS.)
 */
function applyExercisePreviewModeSTasKtFromAircraftDbIfCruise(ac) {
    if (!ac) return;
    const simTimeSec = getEffectiveSimulationSimTimeMs() / 1000;
    const spawn = parseInt(ac.spawnTimeSec, 10) || 0;
    if (!Number.isFinite(simTimeSec) || simTimeSec < spawn) return;
    if (ac.departureProfileActive) return;
    const hasSpeedCommand = !!(ac.speedSelectedType || ac.speedChangeStartSimSec != null);
    if (hasSpeedCommand) return;
    const mcFeet = Number(ac.modeCFeet);
    if (!isFinite(mcFeet)) return;
    const fl = Math.max(0, Math.min(500, Math.round(mcFeet / 100)));
    const type = (ac.aircraftType || '').trim().toUpperCase();
    const gs = computeGroundSpeedKt(type, fl);
    if (gs != null && isFinite(gs)) ac.modeSTasKt = gs;
}

/**
 * Advance preview aircraft through the same altitude/speed/heading integration as the running sim.
 * Extends route-nav distance stepwise at radar cadence (same as live sim) and records per-second kinematics
 * so getAircraftPositionAtRadarUpdate uses altitude/TAS along the timeline, not only end-state.
 */
function integrateExercisePreviewAircraftBatch(acClones, previewSec, radarSec, tempFlightsOverride = null, routeEndTimesById = null, integrateOpts = null) {
    if (!acClones.length || previewSec <= 0) return;
    const retainPreviewTimeline = !!(integrateOpts && integrateOpts.retainPreviewTimeline);
    const savedData = window.simulationData;
    const savedMs = simulationSimTimeMs;
    const savedJoiner = simulationJoinedSessionId;
    const STEP = 0.25;
    const radarInterval = Math.max(1, parseInt(radarSec, 10) || 1);
    const flightsForTemp = (tempFlightsOverride != null) ? tempFlightsOverride : currentEditingFlights;

    const tempData = {
        aircraft: acClones,
        waypoints: currentEditingSector?.waypoints || [],
        routes: currentEditingSector?.routes || [],
        airports: currentEditingSector?.airports || [],
        sector: currentEditingSector,
        boundaries: savedData?.boundaries,
        flights: flightsForTemp
    };

    try {
        window.simulationData = tempData;
        simulationJoinedSessionId = false;

        acClones.forEach(acClone => {
            if (!acClone) return;
            acClone.routeNavTravelCacheN = null;
            if (acClone.routeNavTraveledNmByUpdateSec instanceof Map) acClone.routeNavTraveledNmByUpdateSec.clear();
            else acClone.routeNavTraveledNmByUpdateSec = null;
            acClone.routeNavLastUpdateSimSec = null;
            acClone.routeNavTraveledNm = 0;
            acClone._trackCache = null;
            acClone._previewKinematicsBySimSec = new Map();
            acClone._previewPublishedModeCByUpdateSec = retainPreviewTimeline ? new Map() : null;
            acClone._previewRouteEndSimSec = null;
            acClone.lastPublishedRadarUpdateSimSec = null;
        });

        for (let s = 1; s <= previewSec; s++) {
            const activeAtS = acClones.filter(ac => exercisePreviewShouldIntegrateAcAtSimSec(ac, s, routeEndTimesById));
            tempData.aircraft = activeAtS;

            for (let sub = 0; sub < 4; sub++) {
                simulationSimTimeMs = (s - 1 + (sub + 1) * STEP) * 1000;
                updateSimulationAircraftAltitudes(STEP);
                updateSimulationAircraftSpeeds(STEP);
                updateSimulationAircraftHeadings(STEP);
                activeAtS.forEach(acClone => {
                    if (acClone) applyExercisePreviewModeSTasKtFromAircraftDbIfCruise(acClone);
                });
            }

            activeAtS.forEach(acClone => {
                if (!acClone) return;
                const mc = Number(acClone.modeCFeet);
                const tas = Number(acClone.modeSTasKt);
                acClone._previewKinematicsBySimSec.set(s, {
                    modeCFeet: isFinite(mc) ? mc : NaN,
                    modeSTasKt: isFinite(tas) ? tas : NaN
                });
            });

            activeAtS.forEach(acClone => {
                if (!acClone) return;
                const spawn = parseInt(acClone.spawnTimeSec, 10) || 0;
                const elapsed = s - spawn;
                const onRadarBoundary = elapsed % radarInterval === 0;
                if (!onRadarBoundary && s !== previewSec) return;
                const st = getAircraftPositionAtRadarUpdate(acClone, s, radarInterval);
                if (!st || st.lastUpdateSimSec == null) return;
                if (acClone.lastPublishedRadarUpdateSimSec == null || acClone.lastPublishedRadarUpdateSimSec !== st.lastUpdateSimSec) {
                    publishExercisePreviewRadarFields(acClone, st);
                }
                if (retainPreviewTimeline && acClone._previewPublishedModeCByUpdateSec instanceof Map) {
                    const mcPub = Number(acClone.publishedModeCFeet ?? acClone.modeCFeet);
                    if (isFinite(mcPub)) {
                        acClone._previewPublishedModeCByUpdateSec.set(st.lastUpdateSimSec, mcPub);
                    }
                }
                if (exercisePreviewAircraftHasCompletedRoute(acClone)) {
                    const endSec = st.lastUpdateSimSec != null ? st.lastUpdateSimSec : s;
                    acClone._previewRouteEndSimSec = endSec;
                    if (routeEndTimesById && acClone.id != null && routeEndTimesById[acClone.id] == null) {
                        routeEndTimesById[acClone.id] = endSec;
                    }
                }
            });
            if (integrateOpts?.onSimSec) {
                try { integrateOpts.onSimSec(acClones, s); } catch (eOnSec) {}
            }
        }
        tempData.aircraft = acClones;
        simulationSimTimeMs = previewSec * 1000;
    } finally {
        window.simulationData = savedData;
        simulationSimTimeMs = savedMs;
        simulationJoinedSessionId = savedJoiner;
        if (!retainPreviewTimeline) {
            acClones.forEach(acClone => clearExercisePreviewAircraftTimelineMaps(acClone));
        }
    }
}

function exercisePreviewTrajectoryOverlayHasAircraftId(aircraftId) {
    const k = normalizeTrajectoryAircraftId(aircraftId);
    return exercisePreviewTrajectoryAircraftIds.has(k);
}

function toggleExercisePreviewTrajectoryForAircraftId(aircraftId, opts = {}) {
    const forceOff = !!opts.forceOff;
    const k = normalizeTrajectoryAircraftId(aircraftId);
    if (!k) return;
    const wasOn = exercisePreviewTrajectoryAircraftIds.has(k);
    if (forceOff) exercisePreviewTrajectoryAircraftIds.delete(k);
    else if (wasOn) exercisePreviewTrajectoryAircraftIds.delete(k);
    else exercisePreviewTrajectoryAircraftIds.add(k);
    if (!forceOff && !wasOn && exercisePreviewTrajectoryAircraftIds.has(k)) {
        try { syncExerciseInitialCallScriptsForAircraft(aircraftId); } catch (eSync) {}
    }
}

function pickExercisePreviewCallsignAircraftIdAtCanvasXY(clickX, clickY) {
    if (!exercisePreviewAircraftCallsignTextBounds.length) return null;
    const csById = new Map(exercisePreviewAircraftCallsignTextBounds.map(b => [b.aircraftId, b]));
    const isInside = (b) => b && clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h;
    const preferredId = (exercisePreviewIsDraggingLabel && exercisePreviewDraggingAircraftId)
        ? exercisePreviewDraggingAircraftId
        : null;
    if (preferredId) {
        const b = csById.get(preferredId);
        if (isInside(b)) return preferredId;
    }
    for (let zi = exercisePreviewLabelZOrder.length - 1; zi >= 0; zi--) {
        const id = exercisePreviewLabelZOrder[zi];
        const b = csById.get(id);
        if (isInside(b)) return id;
    }
    return null;
}

function pickExercisePreviewTrajectoryEstimateAircraftIdAtCanvasXY(clickX, clickY) {
    for (let i = exercisePreviewTrajectoryEstimateBounds.length - 1; i >= 0; i--) {
        const b = exercisePreviewTrajectoryEstimateBounds[i];
        if (!b) continue;
        if (clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) return b.aircraftId;
    }
    return null;
}

function drawExercisePreviewTrajectoryForAircraft(ctx, acWork, state, x, y, centre, lonScale, originX, originY, previewSec) {
    if (!exercisePreviewTrajectoryOverlayHasAircraftId(acWork.id)) return;
    const pts = acWork.points || [];
    if (!Array.isArray(pts) || pts.length < 2) return;

    buildTrackCacheForAircraftPointsIfNeeded(acWork);
    const cache = acWork._trackCache;
    const cumNm = cache?.cumNm;
    const legsNm = cache?.legsNm;
    if (!Array.isArray(cumNm) || !Array.isArray(legsNm)) return;

    let segIdx = 0;
    let tNm = Math.max(0, Number(state.traveledNm) || 0);
    if (acWork.navMode === 'heading') {
        segIdx = Math.max(0, Math.min(pts.length - 2, parseInt(acWork.routeProgressIdx, 10) || 0));
    } else {
        for (let i = 0; i < legsNm.length; i++) {
            const s0 = cumNm[i];
            const s1 = cumNm[i + 1];
            if (tNm >= s0 && tNm <= s1) { segIdx = i; break; }
        }
    }

    const trajCol = simulationStyle?.trajectory?.color || SIM_STYLE_DEFAULTS.trajectory.color;
    ctx.strokeStyle = hexToRgba(trajCol, 0.75);
    ctx.lineWidth = 2;
    const displayMode = (simulationSettings?.trajectoryDisplayMode || SIM_SETTINGS_DEFAULTS.trajectoryDisplayMode || 'point_to_point').toString().toLowerCase();

    const toCanvasXY = (lat, lon) => {
        let relLon = lon;
        let relLat = lat;
        if (centre && isFinite(centre.longitude) && isFinite(centre.latitude)) {
            relLon = lon - centre.longitude;
            relLat = lat - centre.latitude;
        }
        const px = originX + relLon * exerciseEditorZoom * lonScale;
        const py = originY - relLat * exerciseEditorZoom;
        return { x: px, y: py };
    };

    const drawPts = [{ lat: state.lat, lon: state.lon, x, y }];
    for (let i = segIdx + 1; i < pts.length; i++) {
        const p = pts[i];
        if (!p || !isFinite(p.lat) || !isFinite(p.lon)) continue;
        const cxy = toCanvasXY(p.lat, p.lon);
        if (!isFinite(cxy.x) || !isFinite(cxy.y)) continue;
        drawPts.push({ lat: p.lat, lon: p.lon, x: cxy.x, y: cxy.y });
    }

    ctx.beginPath();
    ctx.moveTo(x, y);
    if (drawPts.length >= 2 && displayMode === 'turn_radius') {
        const gsKt = Number(state.gs);
        const refLatDeg = (centre && isFinite(centre.latitude)) ? centre.latitude : Number(state.lat);
        const latLonList = [{ lat: Number(state.lat), lon: Number(state.lon) }];
        for (let i = segIdx + 1; i < pts.length; i++) {
            const p = pts[i];
            if (!p || !isFinite(p.lat) || !isFinite(p.lon)) continue;
            latLonList.push({ lat: Number(p.lat), lon: Number(p.lon) });
        }
        let cur = latLonList[0];
        const startXY = toCanvasXY(cur.lat, cur.lon);
        ctx.lineTo(startXY.x, startXY.y);
        for (let i = 1; i < latLonList.length - 1; i++) {
            const A = latLonList[i - 1];
            const B = latLonList[i];
            const C = latLonList[i + 1];
            const arc = computeTurnArcPointsLocalXY(acWork, gsKt, refLatDeg, A, B, C);
            if (!arc) {
                const bxy = toCanvasXY(B.lat, B.lon);
                ctx.lineTo(bxy.x, bxy.y);
                cur = B;
                continue;
            }
            const t1ll = localXYToLatLon(arc.t1.x, arc.t1.y, refLatDeg);
            const t1xy = toCanvasXY(t1ll.lat, t1ll.lon);
            ctx.lineTo(t1xy.x, t1xy.y);
            for (let k = 1; k < arc.arcPts.length; k++) {
                const pll = localXYToLatLon(arc.arcPts[k].x, arc.arcPts[k].y, refLatDeg);
                const pxy = toCanvasXY(pll.lat, pll.lon);
                ctx.lineTo(pxy.x, pxy.y);
            }
            const t2ll = localXYToLatLon(arc.t2.x, arc.t2.y, refLatDeg);
            cur = { lat: t2ll.lat, lon: t2ll.lon };
        }
        const lastLL = latLonList[latLonList.length - 1];
        const lastXY = toCanvasXY(lastLL.lat, lastLL.lon);
        ctx.lineTo(lastXY.x, lastXY.y);
    } else {
        for (let i = 1; i < drawPts.length; i++) {
            ctx.lineTo(drawPts[i].x, drawPts[i].y);
        }
    }
    ctx.stroke();
    ctx.lineWidth = 1;

    const gs = Number(state.gs);
    if (!isFinite(gs) || gs <= 0) return;
    const formatHHMM = (totalSeconds) => {
        const s = Math.max(0, Math.floor(totalSeconds || 0)) % 86400;
        const hh = String(Math.floor(s / 3600)).padStart(2, '0');
        const mm = String(Math.floor((s % 3600) / 60)).padStart(2, '0');
        return `${hh}:${mm}`;
    };
    const base = Math.max(0, Number(previewSec) || 0);
    ctx.font = 'bold 12px Arial';
    ctx.fillStyle = trajCol;
    ctx.textAlign = 'left';
    ctx.textBaseline = 'top';
    const trajShowFl = ((simulationSettings?.trajectoryShowLabels || SIM_SETTINGS_DEFAULTS.trajectoryShowLabels) === 'estimates_and_fl');
    const trajHeadingNav = acWork.navMode === 'heading';
    const dToNextNm = (trajHeadingNav && pts[segIdx + 1])
        ? calculateNauticalMiles(state.lat, state.lon, pts[segIdx + 1].lat, pts[segIdx + 1].lon)
        : null;
    const baseAlongNm = trajHeadingNav ? (cumNm[segIdx + 1] ?? null) : null;

    for (let i = segIdx + 1; i < pts.length; i++) {
        const p = pts[i];
        const name = (p?.name || '').toString().trim();
        if (!name) continue;
        const alongNm = cumNm[i];
        if (!isFinite(alongNm)) continue;
        let remainNm = alongNm - tNm;
        if (trajHeadingNav) {
            if (!isFinite(dToNextNm) || dToNextNm < 0) continue;
            const baseAl = Number(baseAlongNm);
            if (!isFinite(baseAl)) continue;
            remainNm = dToNextNm + Math.max(0, alongNm - baseAl);
        }
        if (!isFinite(remainNm) || remainNm < 0) continue;
        const etaSec = base + (remainNm / gs) * 3600;
        const txt = formatHHMM(etaSec);
        const dtSec = (remainNm / gs) * 3600;
        const flFromWp = (p.fl != null && Number.isFinite(p.fl)) ? Math.round(p.fl) : null;
        const flEst = flFromWp != null ? flFromWp : estimateFlAtTrajectoryEta(acWork, dtSec);
        const cxy = toCanvasXY(p.lat, p.lon);
        if (!isFinite(cxy.x) || !isFinite(cxy.y)) continue;
        const tx = cxy.x + 6;
        const tyEta = cxy.y - 10;
        if (trajShowFl) {
            const flTxt = `FL${flEst}`;
            const tyFl = cxy.y - 26;
            ctx.fillText(flTxt, tx, tyFl);
            ctx.fillText(txt, tx, tyEta);
            const wFl = ctx.measureText(flTxt).width;
            const wEta = ctx.measureText(txt).width;
            exercisePreviewTrajectoryEstimateBounds.push({
                aircraftId: acWork.id,
                x: tx,
                y: tyFl,
                w: Math.max(wFl, wEta),
                h: 30
            });
        } else {
            ctx.fillText(txt, tx, tyEta);
            const wEta = ctx.measureText(txt).width;
            exercisePreviewTrajectoryEstimateBounds.push({
                aircraftId: acWork.id,
                x: tx,
                y: tyEta,
                w: wEta,
                h: 14
            });
        }
    }
}

function isExerciseInitialCallScript(script) {
    return script && String(script.scriptKind || '') === 'initialCall';
}

function getExerciseFlightSpawnSecForScript(script) {
    if (!script?.aircraftId) return 0;
    const flight = (currentEditingFlights || []).find(f => f && String(f.id) === String(script.aircraftId));
    if (flight) return Math.max(0, parseInt(flight.spawnTime, 10) || 0);
    const ac = (window.simulationData?.aircraft || []).find(a => a && String(a.id) === String(script.aircraftId));
    return Math.max(0, parseInt(ac?.spawnTimeSec, 10) || 0);
}

function normalizeInitialCallLblTinOffsetSec(raw, previewTimeSec, spawnSec) {
    const preview = Math.max(0, parseInt(previewTimeSec, 10) || 0);
    const spawn = Math.max(0, parseInt(spawnSec, 10) || 0);
    let n = parseInt(raw, 10);
    if (!Number.isFinite(n) || n < 1) n = EXERCISE_INITIAL_CALL_LBL_TIN_DEFAULT_OFFSET_SEC;
    const maxOffset = Math.max(1, preview - spawn);
    return Math.min(n, maxOffset);
}

function getInitialCallLblTinPreviewTimeSec(script, spawnSec) {
    if (!script || !isExerciseInitialCallScript(script)) return null;
    const preview = Math.max(0, parseInt(script.previewTimeSec, 10) || 0);
    const spawn = spawnSec != null
        ? Math.max(0, parseInt(spawnSec, 10) || 0)
        : getExerciseFlightSpawnSecForScript(script);
    const offset = normalizeInitialCallLblTinOffsetSec(script.lblTinOffsetSec, preview, spawn);
    if (!offset) return null;
    return Math.max(spawn, preview - offset);
}

function buildInitialCallLblTinTransformedCommand(callsign, offsetSec) {
    const cs = (callsign || '').toString().trim();
    const off = Math.max(1, parseInt(offsetSec, 10) || EXERCISE_INITIAL_CALL_LBL_TIN_DEFAULT_OFFSET_SEC);
    if (!cs) return '';
    return `${cs} LBL_TIN-${off}`;
}

function syncInitialCallLblTinFields(script, spawnSec) {
    if (!script || !isExerciseInitialCallScript(script)) return script;
    if (!script.atcSectorId) {
        return { ...script, lblTinOffsetSec: 0, aiTransformedCommand: '' };
    }
    const spawn = spawnSec != null ? Math.max(0, parseInt(spawnSec, 10) || 0) : getExerciseFlightSpawnSecForScript(script);
    const preview = Math.max(0, parseInt(script.previewTimeSec, 10) || 0);
    const offset = normalizeInitialCallLblTinOffsetSec(script.lblTinOffsetSec, preview, spawn);
    return {
        ...script,
        lblTinOffsetSec: offset,
        aiTransformedCommand: buildInitialCallLblTinTransformedCommand(script.callsign, offset)
    };
}

function ensureExerciseInitialCallLblTinFieldsSynced(opts = {}) {
    if (!currentEditingExerciseId || !currentEditingAiPilotScripts.length) return false;
    let changed = false;
    currentEditingAiPilotScripts = currentEditingAiPilotScripts.map((script) => {
        if (!isExerciseInitialCallScript(script) || !script.atcSectorId) return script;
        const needsSync = !(Number(script.lblTinOffsetSec) > 0)
            || !/\bLBL_TIN-\d+\b/.test(String(script.aiTransformedCommand || ''));
        if (!needsSync) return script;
        const next = syncInitialCallLblTinFields(script, getExerciseFlightSpawnSecForScript(script));
        if (next.lblTinOffsetSec !== script.lblTinOffsetSec
            || next.aiTransformedCommand !== script.aiTransformedCommand) {
            changed = true;
        }
        return next;
    });
    if (changed && !opts.skipPersist) {
        persistCurrentEditingAiPilotScripts();
        try { renderExerciseScriptsList(); } catch (e) {}
    }
    return changed;
}

function normalizeSuppressedInitialPilotCallEntry(raw) {
    if (!raw || typeof raw !== 'object') return null;
    const aircraftId = raw.aircraftId != null ? String(raw.aircraftId) : '';
    const atcSectorId = raw.atcSectorId != null ? String(raw.atcSectorId) : '';
    if (!aircraftId || !atcSectorId) return null;
    return { aircraftId, atcSectorId };
}

function normalizeSuppressedInitialPilotCallsFromExercise(exercise) {
    const raw = exercise?.suppressedInitialPilotCalls;
    if (!Array.isArray(raw)) return [];
    return raw.map(normalizeSuppressedInitialPilotCallEntry).filter(Boolean);
}

function initialPilotCallSuppressionKey(aircraftId, atcSectorId) {
    return `${String(aircraftId)}|${String(atcSectorId)}`;
}

function isInitialPilotCallSuppressed(aircraftId, atcSectorId) {
    const k = initialPilotCallSuppressionKey(aircraftId, atcSectorId);
    return currentEditingSuppressedInitialPilotCalls.some(
        e => initialPilotCallSuppressionKey(e.aircraftId, e.atcSectorId) === k
    );
}

function addInitialPilotCallSuppression(aircraftId, atcSectorId) {
    if (!aircraftId || !atcSectorId) return;
    if (isInitialPilotCallSuppressed(aircraftId, atcSectorId)) return;
    currentEditingSuppressedInitialPilotCalls.push({
        aircraftId: String(aircraftId),
        atcSectorId: String(atcSectorId)
    });
}

function removeInitialPilotCallSuppression(aircraftId, atcSectorId) {
    if (!aircraftId || !atcSectorId) return;
    const k = initialPilotCallSuppressionKey(aircraftId, atcSectorId);
    currentEditingSuppressedInitialPilotCalls = currentEditingSuppressedInitialPilotCalls.filter(
        e => initialPilotCallSuppressionKey(e.aircraftId, e.atcSectorId) !== k
    );
}

function generateExerciseInitialPilotCalls() {
    if (!currentEditingExerciseId) return;
    let added = 0;
    (currentEditingFlights || []).forEach(flight => {
        if (!flight?.id) return;
        const defaults = computeExercisePreviewInitialPilotCallDefaultsForFlight(flight);
        defaults.forEach(def => {
            const existing = currentEditingAiPilotScripts.find(s =>
                isExerciseInitialCallScript(s)
                && String(s.aircraftId) === String(flight.id)
                && String(s.atcSectorId) === String(def.atcSectorId)
            );
            if (existing) return;
            removeInitialPilotCallSuppression(flight.id, def.atcSectorId);
            let entry = normalizeExerciseAiPilotScriptEntry({
                id: Date.now().toString() + Math.random().toString(16).slice(2),
                scriptKind: 'initialCall',
                previewTimeSec: def.previewTimeSec,
                aircraftId: flight.id,
                callsign: def.callsign || flight.callsign || '',
                atcSectorId: def.atcSectorId,
                lblTinOffsetSec: EXERCISE_INITIAL_CALL_LBL_TIN_DEFAULT_OFFSET_SEC,
                aiInformation: '',
                aiInformationSilent: false,
                ttsMessage: def.ttsMessage,
                ttsUseAiResponse: false,
                commandForAi: '',
                aiTransformedCommand: ''
            });
            entry = syncInitialCallLblTinFields(entry, flight.spawnTime);
            if (!entry) return;
            currentEditingAiPilotScripts.push(entry);
            added += 1;
        });
    });
    if (added > 0) {
        persistCurrentEditingAiPilotScripts();
        renderExerciseScriptsList();
        try { drawExerciseEditorCanvas(); } catch (e) {}
    }
}

function computeExercisePreviewInitialPilotCallDefaultsForFlight(flight) {
    if (!flight || !currentEditingSector) return [];
    const atcSectors = getExercisePreviewAtcSectorsList();
    if (!atcSectors.length) return [];

    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
    const maxSec = getExercisePreviewMaxSecondsFromFlights();
    if (maxSec <= 0) return [];

    const spawn = Math.max(0, parseInt(flight.spawnTime, 10) || 0);
    const w = getRouteFixesForSector(currentEditingSector);
    const r = currentEditingSector.routes || [];
    const tracks = buildSimulationAircraftTracks({ flights: [flight], waypoints: w, routes: r });
    if (!tracks[0]) return [];

    const skipSectorIdsAtSpawn = new Set();
    if (spawn <= maxSec) {
        const spawnClone = getExercisePreviewIntegratedAircraftCloneAtSimSec(flight, spawn, radarSec);
        if (spawnClone) {
            const acSeq = getAircraftForAtmTrajectorySequence(spawnClone);
            const baseState = getAircraftStateForAdvancedLabel(spawnClone);
            if (baseState && acSeq) {
                const state = getSectorSequenceStateForDisplayRoute(spawnClone, acSeq, baseState);
                const poly = buildRemainingTrajectoryPolylineForSectorSequence(acSeq, state);
                if (poly?.points?.length && isFinite(poly.totalNm) && poly.totalNm > 0) {
                    const verticalMeta = buildAtcSectorVerticalMeta(atcSectors);
                    const fl0 = getTrajectoryFlForSectorSequenceAtRemainingNm(acSeq, 0, poly.totalNm, state);
                    if (isFinite(fl0)) {
                        const sector0 = findAtcSectorIndexForSample(state.lat, state.lon, fl0, atcSectors, verticalMeta);
                        if (sector0 >= 0 && atcSectors[sector0]) {
                            skipSectorIdsAtSpawn.add(String(atcSectors[sector0].id || sector0));
                        }
                    }
                }
            }
        }
    }

    let clone;
    try {
        clone = JSON.parse(JSON.stringify(tracks[0]));
    } catch (e) {
        return [];
    }

    const callTimeBySectorId = new Map();

    integrateExercisePreviewAircraftBatch([clone], maxSec, radarSec, [flight], null, {
        onSimSec: (acArr, s) => {
            const ac = acArr[0];
            if (!ac || s < spawn) return;
            const entry = computePilotCallSectorEntryInfo(ac, atcSectors);
            if (!entry || !entry.sector) return;
            const sectorId = String(entry.sector.id || entry.sectorIdx);
            if (skipSectorIdsAtSpawn.has(sectorId)) return;
            if (callTimeBySectorId.has(sectorId)) return;
            const minutesToEntry = entry.minutes;
            if (!isFinite(minutesToEntry) || minutesToEntry > AI_PP_PILOT_CALL_MAX_MINUTES) return;
            callTimeBySectorId.set(sectorId, {
                callTimeSec: Math.max(spawn, s),
                sector: entry.sector
            });
        }
    });

    const results = [];
    callTimeBySectorId.forEach((info, sectorId) => {
        const acClone = getExercisePreviewIntegratedAircraftCloneAtSimSec(flight, info.callTimeSec, radarSec);
        if (!acClone) return;
        const ttsMessage = buildExerciseInitialPilotCallTtsTemplate(acClone, info.sector);
        if (!ttsMessage) return;
        results.push({
            previewTimeSec: info.callTimeSec,
            atcSectorId: sectorId,
            callsign: (flight.callsign || acClone.callsign || '').toString().trim(),
            ttsMessage
        });
    });
    return results;
}

function syncExerciseInitialCallScriptsForAircraft(aircraftId, opts = {}) {
    if (!currentEditingExerciseId || aircraftId == null) return;
    const flight = currentEditingFlights.find(f => f && String(f.id) === String(aircraftId));
    if (!flight) return;

    const defaults = computeExercisePreviewInitialPilotCallDefaultsForFlight(flight);
    const defaultSectorIds = new Set(defaults.map(d => String(d.atcSectorId)));

    defaults.forEach(def => {
        if (isInitialPilotCallSuppressed(aircraftId, def.atcSectorId)) return;
        const existing = currentEditingAiPilotScripts.find(s =>
            isExerciseInitialCallScript(s)
            && String(s.aircraftId) === String(aircraftId)
            && String(s.atcSectorId) === String(def.atcSectorId)
        );
        if (existing) {
            const idx = currentEditingAiPilotScripts.findIndex(s => s && String(s.id) === String(existing.id));
            if (idx !== -1) {
                currentEditingAiPilotScripts[idx] = syncInitialCallLblTinFields({
                    ...existing,
                    previewTimeSec: def.previewTimeSec,
                    ttsMessage: def.ttsMessage,
                    callsign: def.callsign || existing.callsign
                }, flight.spawnTime);
            }
        } else {
            let entry = normalizeExerciseAiPilotScriptEntry({
                id: Date.now().toString() + Math.random().toString(16).slice(2),
                scriptKind: 'initialCall',
                previewTimeSec: def.previewTimeSec,
                aircraftId,
                callsign: def.callsign || flight.callsign || '',
                atcSectorId: def.atcSectorId,
                lblTinOffsetSec: EXERCISE_INITIAL_CALL_LBL_TIN_DEFAULT_OFFSET_SEC,
                aiInformation: '',
                aiInformationSilent: false,
                ttsMessage: def.ttsMessage,
                ttsUseAiResponse: false,
                commandForAi: '',
                aiTransformedCommand: ''
            });
            entry = syncInitialCallLblTinFields(entry, flight.spawnTime);
            if (entry) currentEditingAiPilotScripts.push(entry);
        }
    });

    currentEditingAiPilotScripts = currentEditingAiPilotScripts.filter(s => {
        if (!isExerciseInitialCallScript(s)) return true;
        if (String(s.aircraftId) !== String(aircraftId)) return true;
        return defaultSectorIds.has(String(s.atcSectorId));
    });

    if (!opts.skipPersist) {
        persistCurrentEditingAiPilotScripts();
        renderExerciseScriptsList();
    }
}

function syncExerciseInitialCallScriptsForAllFlights() {
    if (!currentEditingExerciseId) return;
    (currentEditingFlights || []).forEach(f => {
        if (f && f.id != null) {
            syncExerciseInitialCallScriptsForAircraft(f.id, { skipPersist: true });
        }
    });
    persistCurrentEditingAiPilotScripts();
    renderExerciseScriptsList();
}

function deleteExerciseInitialPilotCallScript(scriptId) {
    const script = currentEditingAiPilotScripts.find(s => s && String(s.id) === String(scriptId));
    if (!script || !isExerciseInitialCallScript(script)) return;
    addInitialPilotCallSuppression(script.aircraftId, script.atcSectorId);
    const before = currentEditingAiPilotScripts.length;
    currentEditingAiPilotScripts = currentEditingAiPilotScripts.filter(s => String(s.id) !== String(scriptId));
    if (currentEditingAiPilotScripts.length === before) return;
    if (exerciseScriptsListSelectedId != null && String(exerciseScriptsListSelectedId) === String(scriptId)) {
        exerciseScriptsListSelectedId = null;
    }
    persistCurrentEditingAiPilotScripts();
    renderExerciseScriptsList();
}

function formatExerciseScriptMarkerSnippet(script) {
    if (!script) return '';
    if (isExerciseInitialCallScript(script)) {
        const text = formatInitialPilotCallTtsForExercisePreviewDisplay(script.ttsMessage) || 'Initial call';
        const max = 140;
        if (text.length > max) return text.slice(0, max - 1) + '…';
        return text;
    }
    const parts = [];
    if (script.aiInformation && String(script.aiInformation).trim()) parts.push(String(script.aiInformation).trim());
    if (script.ttsMessage && String(script.ttsMessage).trim()) parts.push(String(script.ttsMessage).trim());
    if (script.commandForAi && String(script.commandForAi).trim()) parts.push(String(script.commandForAi).trim());
    let text = parts.join(' · ');
    if (!text) text = '(empty script)';
    const max = 140;
    if (text.length > max) text = text.slice(0, max - 1) + '…';
    return text;
}

function getExercisePreviewIntegratedAircraftCloneAtSimSec(flightRow, simSec, radarSec) {
    if (!currentEditingSector || !flightRow) return null;
    const sec = Math.max(0, Math.floor(Number(simSec) || 0));
    const w = getRouteFixesForSector(currentEditingSector);
    const r = currentEditingSector.routes || [];
    const f = { ...flightRow };
    const tracks = buildSimulationAircraftTracks({ flights: [f], waypoints: w, routes: r });
    if (!tracks[0]) return null;
    let clone;
    try {
        clone = JSON.parse(JSON.stringify(tracks[0]));
    } catch (e) {
        return null;
    }
    const savedOff = exercisePreviewLabelOffsetsByAircraftId[clone.id];
    if (savedOff && Number.isFinite(savedOff.labelOffsetX) && Number.isFinite(savedOff.labelOffsetY)) {
        clone.labelOffsetX = savedOff.labelOffsetX;
        clone.labelOffsetY = savedOff.labelOffsetY;
        clone.labelLeaderOffsetToCenter = !!savedOff.labelLeaderOffsetToCenter;
    }
    integrateExercisePreviewAircraftBatch([clone], sec, radarSec, [f]);
    return clone;
}

function getExercisePreviewAircraftStateAtSimSecForFlight(flightRow, simSec, radarSec) {
    const clone = getExercisePreviewIntegratedAircraftCloneAtSimSec(flightRow, simSec, radarSec);
    if (!clone) return null;
    const sec = Math.max(0, Math.floor(Number(simSec) || 0));
    const st = getAircraftPositionAtRadarUpdate(clone, sec, radarSec);
    if (!st || !isFinite(st.lat) || !isFinite(st.lon)) return null;
    return st;
}

function solveExercisePreviewSimSecForTraveledNm(flightRow, targetNm, radarSec, maxSecHint) {
    if (!flightRow) return null;
    const hi = Math.max(0, Math.floor(Number(maxSecHint) || getExercisePreviewMaxSecondsFromFlights() || 0));
    const tgt = Math.max(0, Number(targetNm) || 0);
    const measure = (sec) => {
        const st = getExercisePreviewAircraftStateAtSimSecForFlight(flightRow, sec, radarSec);
        return st && isFinite(st.traveledNm) ? Number(st.traveledNm) : null;
    };
    const tAtHi = measure(hi);
    if (tAtHi == null || !isFinite(tAtHi)) return null;
    const capped = Math.min(tgt, tAtHi);
    if (capped <= 1e-4) return 0;
    let lo = 0;
    let r = hi + 1;
    while (lo < r) {
        const mid = Math.floor((lo + r) / 2);
        const tm = measure(mid);
        if (tm == null || !isFinite(tm)) {
            r = mid;
            continue;
        }
        if (tm < capped) lo = mid + 1;
        else r = mid;
    }
    const sec0 = Math.min(hi, Math.max(0, lo));
    let best = sec0;
    let bestD = Infinity;
    for (const c of [sec0 - 1, sec0, sec0 + 1]) {
        if (c < 0 || c > hi) continue;
        const tv = measure(c);
        if (tv == null || !isFinite(tv)) continue;
        const d = Math.abs(tv - capped);
        if (d < bestD) {
            bestD = d;
            best = c;
        }
    }
    return best;
}

function pickExercisePreviewLblTinMarkerAtCanvasXY(canvasX, canvasY) {
    if (!exercisePreviewLblTinMarkerBounds.length) return null;
    const hitR = EXERCISE_LBL_TIN_MARKER_RADIUS_PX + EXERCISE_SCRIPT_MARKER_HIT_PAD_PX;
    let best = null;
    let bestD = Infinity;
    for (let i = exercisePreviewLblTinMarkerBounds.length - 1; i >= 0; i--) {
        const b = exercisePreviewLblTinMarkerBounds[i];
        if (!b || !b.scriptId) continue;
        const inText = b.labelX != null && canvasX >= b.labelX && canvasX <= b.labelX + b.labelW
            && canvasY >= b.labelY && canvasY <= b.labelY + b.labelH;
        const d = Math.hypot(canvasX - b.x, canvasY - b.y);
        if ((inText || d <= hitR) && (inText || d < bestD)) {
            bestD = inText ? 0 : d;
            best = b.scriptId;
        }
    }
    return best;
}

function pickExercisePreviewScriptMarkerDragAtCanvasXY(canvasX, canvasY) {
    const lblTin = pickExercisePreviewLblTinMarkerAtCanvasXY(canvasX, canvasY);
    if (lblTin) return { scriptId: lblTin, dragTarget: 'lblTin' };
    const initial = pickExercisePreviewInitialCallMarkerAtCanvasXY(canvasX, canvasY);
    if (initial) return { scriptId: initial, dragTarget: 'initialCall' };
    const custom = pickExercisePreviewScriptMarkerAtCanvasXY(canvasX, canvasY);
    if (custom) return { scriptId: custom, dragTarget: 'custom' };
    return null;
}

function pickExercisePreviewInitialCallMarkerAtCanvasXY(canvasX, canvasY) {
    if (!exercisePreviewInitialCallMarkerBounds.length) return null;
    const hitR = EXERCISE_INITIAL_CALL_MARKER_RADIUS_PX + EXERCISE_SCRIPT_MARKER_HIT_PAD_PX;
    let best = null;
    let bestD = Infinity;
    for (let i = exercisePreviewInitialCallMarkerBounds.length - 1; i >= 0; i--) {
        const b = exercisePreviewInitialCallMarkerBounds[i];
        if (!b || !b.scriptId) continue;
        const inText = canvasX >= b.labelX && canvasX <= b.labelX + b.labelW
            && canvasY >= b.labelY && canvasY <= b.labelY + b.labelH;
        const d = Math.hypot(canvasX - b.x, canvasY - b.y);
        if ((inText || d <= hitR) && (inText || d < bestD)) {
            bestD = inText ? 0 : d;
            best = b.scriptId;
        }
    }
    return best;
}

function pickExercisePreviewTrajectoryMarkerAtCanvasXY(canvasX, canvasY) {
    const drag = pickExercisePreviewScriptMarkerDragAtCanvasXY(canvasX, canvasY);
    return drag ? drag.scriptId : null;
}

function pickExercisePreviewScriptMarkerAtCanvasXY(canvasX, canvasY) {
    if (!exercisePreviewScriptMarkerBounds.length) return null;
    const hitR = EXERCISE_SCRIPT_MARKER_RADIUS_PX + EXERCISE_SCRIPT_MARKER_HIT_PAD_PX;
    let best = null;
    let bestD = Infinity;
    for (let i = exercisePreviewScriptMarkerBounds.length - 1; i >= 0; i--) {
        const b = exercisePreviewScriptMarkerBounds[i];
        if (!b || !b.scriptId) continue;
        const d = Math.hypot(canvasX - b.x, canvasY - b.y);
        if (d <= hitR && d < bestD) {
            bestD = d;
            best = b.scriptId;
        }
    }
    return best;
}

function hideExerciseScriptMarkerTooltip() {
    const tip = document.getElementById('exerciseScriptMarkerTooltip');
    if (tip) tip.hidden = true;
}

function updateExerciseScriptMarkerTooltip(clientX, clientY, scriptId) {
    const tip = document.getElementById('exerciseScriptMarkerTooltip');
    if (!tip) return;
    if (!scriptId) {
        tip.hidden = true;
        return;
    }
    const script = currentEditingAiPilotScripts.find(s => s && String(s.id) === String(scriptId));
    if (!script) {
        tip.hidden = true;
        return;
    }
    tip.textContent = formatExerciseScriptMarkerSnippet(script);
    tip.hidden = false;
    const container = document.getElementById('exerciseEditorCanvas');
    if (!container) return;
    const rect = container.getBoundingClientRect();
    const pad = 12;
    let left = clientX - rect.left + pad;
    let top = clientY - rect.top + pad;
    const maxLeft = rect.width - 24;
    const maxTop = rect.height - 24;
    if (left > maxLeft) left = Math.max(4, clientX - rect.left - pad - 200);
    if (top > maxTop) top = Math.max(4, clientY - rect.top - pad - 40);
    tip.style.left = `${left}px`;
    tip.style.top = `${top}px`;
}

function updateExerciseScriptPreviewTimeFromCanvasXY(scriptId, canvasX, canvasY) {
    if (!scriptId) return false;
    const idx = currentEditingAiPilotScripts.findIndex(s => s && String(s.id) === String(scriptId));
    if (idx === -1) return false;
    const script = currentEditingAiPilotScripts[idx];
    const flight = currentEditingFlights.find(f => f && String(f.id) === String(script.aircraftId));
    if (!flight) return false;
    const cursorNm = exercisePreviewGetTargetTraveledNmForFlightAtCanvasXY(flight, canvasX, canvasY);
    if (cursorNm == null) return false;
    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
    const maxSec = getExercisePreviewMaxSecondsFromFlights();
    const totalNm = exercisePreviewGetRouteTotalNmForFlight(flight);
    const tgtNm = totalNm != null ? Math.max(0, Math.min(totalNm, cursorNm)) : Math.max(0, cursorNm);
    const newSec = solveExercisePreviewSimSecForTraveledNm(flight, tgtNm, radarSec, maxSec);
    if (newSec == null || !Number.isFinite(newSec)) return false;
    const spawn = parseInt(flight.spawnTime, 10) || 0;
    const previewTimeSec = Math.max(spawn, Math.floor(newSec));
    if (previewTimeSec === script.previewTimeSec) return false;
    let next = { ...script, previewTimeSec };
    if (isExerciseInitialCallScript(next)) {
        next = syncInitialCallLblTinFields(next, spawn);
    }
    currentEditingAiPilotScripts[idx] = next;
    return true;
}

function updateExerciseInitialCallLblTinOffsetFromCanvasXY(scriptId, canvasX, canvasY) {
    if (!scriptId) return false;
    const idx = currentEditingAiPilotScripts.findIndex(s => s && String(s.id) === String(scriptId));
    if (idx === -1) return false;
    const script = currentEditingAiPilotScripts[idx];
    if (!isExerciseInitialCallScript(script)) return false;
    const flight = currentEditingFlights.find(f => f && String(f.id) === String(script.aircraftId));
    if (!flight) return false;
    const cursorNm = exercisePreviewGetTargetTraveledNmForFlightAtCanvasXY(flight, canvasX, canvasY);
    if (cursorNm == null) return false;
    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
    const maxSec = getExercisePreviewMaxSecondsFromFlights();
    const totalNm = exercisePreviewGetRouteTotalNmForFlight(flight);
    const tgtNm = totalNm != null ? Math.max(0, Math.min(totalNm, cursorNm)) : Math.max(0, cursorNm);
    const newSec = solveExercisePreviewSimSecForTraveledNm(flight, tgtNm, radarSec, maxSec);
    if (newSec == null || !Number.isFinite(newSec)) return false;
    const spawn = parseInt(flight.spawnTime, 10) || 0;
    const previewTimeSec = Math.max(spawn, parseInt(script.previewTimeSec, 10) || 0);
    const lblTinPreviewTimeSec = Math.max(spawn, Math.floor(newSec));
    const offset = previewTimeSec - lblTinPreviewTimeSec;
    if (offset < 1) return false;
    const next = syncInitialCallLblTinFields({ ...script, lblTinOffsetSec: offset, previewTimeSec }, spawn);
    if (next.lblTinOffsetSec === script.lblTinOffsetSec) return false;
    currentEditingAiPilotScripts[idx] = next;
    return true;
}

function updateExerciseScriptMarkerDragFromCanvasXY(scriptId, dragTarget, canvasX, canvasY) {
    if (!scriptId) return false;
    if (dragTarget === 'lblTin') {
        return updateExerciseInitialCallLblTinOffsetFromCanvasXY(scriptId, canvasX, canvasY);
    }
    return updateExerciseScriptPreviewTimeFromCanvasXY(scriptId, canvasX, canvasY);
}

function tryStartExercisePreviewScriptDragAt(scriptId, dragTarget, canvasX, canvasY) {
    if (!scriptId || !currentEditingExerciseId) return false;
    const script = currentEditingAiPilotScripts.find(s => s && String(s.id) === String(scriptId));
    if (!script) return false;
    exercisePreviewScriptDragActive = true;
    exercisePreviewScriptDragId = scriptId;
    exercisePreviewScriptDragTarget = dragTarget || 'custom';
    exercisePreviewScriptDragLastCanvasX = canvasX;
    exercisePreviewScriptDragLastCanvasY = canvasY;
    exercisePreviewScriptMarkerHoverId = dragTarget === 'custom' ? scriptId : null;
    exercisePreviewInitialCallMarkerHoverId = dragTarget === 'initialCall' ? scriptId : null;
    exercisePreviewLblTinMarkerHoverId = dragTarget === 'lblTin' ? scriptId : null;
    hideExerciseScriptMarkerTooltip();
    return true;
}

function drawExercisePreviewScriptMarkersLayer(ctx, centre, lonScale, originX, originY, radarSec) {
    if (!exerciseAiPilotActive) return;
    if (!currentEditingAiPilotScripts.length) return;
    const toCanvasXY = (lat, lon) => {
        let relLon = lon;
        let relLat = lat;
        if (centre && isFinite(centre.longitude) && isFinite(centre.latitude)) {
            relLon = lon - centre.longitude;
            relLat = lat - centre.latitude;
        }
        const px = originX + relLon * exerciseEditorZoom * lonScale;
        const py = originY - relLat * exerciseEditorZoom;
        return { x: px, y: py };
    };
    const green = '#22c55e';
    const greenStroke = '#15803d';
    const blue = '#3b82f6';
    const blueStroke = '#1d4ed8';

    currentEditingAiPilotScripts.forEach(script => {
        if (!script || !script.id) return;
        if (isExerciseInitialCallScript(script)) return;
        if (!exercisePreviewTrajectoryOverlayHasAircraftId(script.aircraftId)) return;
        const flight = currentEditingFlights.find(f => f && String(f.id) === String(script.aircraftId));
        if (!flight) return;
        const simSec = Math.max(0, parseInt(script.previewTimeSec, 10) || 0);
        const spawn = parseInt(flight.spawnTime, 10) || 0;
        if (simSec < spawn) return;
        const st = getExercisePreviewAircraftStateAtSimSecForFlight(flight, simSec, radarSec);
        if (!st || !isFinite(st.lat) || !isFinite(st.lon)) return;
        const cxy = toCanvasXY(st.lat, st.lon);
        if (!isFinite(cxy.x) || !isFinite(cxy.y)) return;

        const isHover = exercisePreviewScriptMarkerHoverId != null && String(exercisePreviewScriptMarkerHoverId) === String(script.id);
        const isDrag = exercisePreviewScriptDragActive && exercisePreviewScriptDragId != null
            && String(exercisePreviewScriptDragId) === String(script.id)
            && exercisePreviewScriptDragTarget === 'custom';
        const highlighted = isHover || isDrag;
        const r = EXERCISE_SCRIPT_MARKER_RADIUS_PX;

        ctx.beginPath();
        ctx.arc(cxy.x, cxy.y, r, 0, Math.PI * 2);
        ctx.fillStyle = highlighted ? blue : green;
        ctx.fill();
        ctx.strokeStyle = highlighted ? blueStroke : greenStroke;
        ctx.lineWidth = highlighted ? 2 : 1.5;
        ctx.stroke();

        exercisePreviewScriptMarkerBounds.push({
            scriptId: script.id,
            aircraftId: script.aircraftId,
            x: cxy.x,
            y: cxy.y,
            r
        });
    });
}

function drawExercisePreviewInitialCallMarkersLayer(ctx, centre, lonScale, originX, originY, radarSec) {
    if (!exerciseAiPilotActive) return;
    if (!currentEditingAiPilotScripts.length) return;
    ensureExerciseInitialCallLblTinFieldsSynced({ skipPersist: true });
    const toCanvasXY = (lat, lon) => {
        let relLon = lon;
        let relLat = lat;
        if (centre && isFinite(centre.longitude) && isFinite(centre.latitude)) {
            relLon = lon - centre.longitude;
            relLat = lat - centre.latitude;
        }
        const px = originX + relLon * exerciseEditorZoom * lonScale;
        const py = originY - relLat * exerciseEditorZoom;
        return { x: px, y: py };
    };
    const amber = '#f97316';
    const amberStroke = '#c2410c';
    const blue = '#3b82f6';
    const blueStroke = '#1d4ed8';

    currentEditingAiPilotScripts.forEach(script => {
        if (!script || !script.id || !isExerciseInitialCallScript(script)) return;
        if (!exercisePreviewTrajectoryOverlayHasAircraftId(script.aircraftId)) return;
        const flight = currentEditingFlights.find(f => f && String(f.id) === String(script.aircraftId));
        if (!flight) return;
        const simSec = Math.max(0, parseInt(script.previewTimeSec, 10) || 0);
        const spawn = parseInt(flight.spawnTime, 10) || 0;
        if (simSec < spawn) return;
        const st = getExercisePreviewAircraftStateAtSimSecForFlight(flight, simSec, radarSec);
        if (!st || !isFinite(st.lat) || !isFinite(st.lon)) return;
        const cxy = toCanvasXY(st.lat, st.lon);
        if (!isFinite(cxy.x) || !isFinite(cxy.y)) return;

        const isHover = exercisePreviewInitialCallMarkerHoverId != null
            && String(exercisePreviewInitialCallMarkerHoverId) === String(script.id);
        const isDrag = exercisePreviewScriptDragActive && exercisePreviewScriptDragId != null
            && String(exercisePreviewScriptDragId) === String(script.id)
            && exercisePreviewScriptDragTarget === 'initialCall';
        const highlighted = isHover || isDrag;
        const r = EXERCISE_INITIAL_CALL_MARKER_RADIUS_PX;

        ctx.beginPath();
        ctx.arc(cxy.x, cxy.y, r, 0, Math.PI * 2);
        ctx.fillStyle = highlighted ? blue : amber;
        ctx.fill();
        ctx.strokeStyle = highlighted ? blueStroke : amberStroke;
        ctx.lineWidth = highlighted ? 2 : 1.5;
        ctx.stroke();

        const rawLabel = formatInitialPilotCallTtsForExercisePreviewDisplay(script.ttsMessage) || 'Initial call';
        let label = rawLabel;
        if (label.length > EXERCISE_INITIAL_CALL_LABEL_MAX_CHARS) {
            label = label.slice(0, EXERCISE_INITIAL_CALL_LABEL_MAX_CHARS - 1) + '…';
        }
        const fontSize = 10;
        ctx.font = `${fontSize}px system-ui, sans-serif`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'top';
        const tw = ctx.measureText(label).width;
        const padX = 4;
        const padY = 2;
        const labelW = tw + padX * 2;
        const labelH = fontSize + padY * 2;
        const labelX = cxy.x - labelW / 2;
        const labelY = cxy.y + r + 3;
        ctx.fillStyle = highlighted ? 'rgba(59, 130, 246, 0.92)' : 'rgba(249, 115, 22, 0.92)';
        ctx.fillRect(labelX, labelY, labelW, labelH);
        ctx.strokeStyle = highlighted ? blueStroke : amberStroke;
        ctx.lineWidth = 1;
        ctx.strokeRect(labelX, labelY, labelW, labelH);
        ctx.fillStyle = '#111827';
        ctx.fillText(label, cxy.x, labelY + padY);

        exercisePreviewInitialCallMarkerBounds.push({
            scriptId: script.id,
            aircraftId: script.aircraftId,
            x: cxy.x,
            y: cxy.y,
            r,
            labelX,
            labelY,
            labelW,
            labelH
        });
    });

    const yellow = '#eab308';
    const yellowStroke = '#a16207';
    currentEditingAiPilotScripts.forEach(script => {
        if (!script || !script.id || !isExerciseInitialCallScript(script)) return;
        if (!script.atcSectorId) return;
        if (!exercisePreviewTrajectoryOverlayHasAircraftId(script.aircraftId)) return;
        const flight = currentEditingFlights.find(f => f && String(f.id) === String(script.aircraftId));
        if (!flight) return;
        const spawn = parseInt(flight.spawnTime, 10) || 0;
        const simSec = getInitialCallLblTinPreviewTimeSec(script, spawn);
        if (simSec == null || simSec < spawn) return;
        const st = getExercisePreviewAircraftStateAtSimSecForFlight(flight, simSec, radarSec);
        if (!st || !isFinite(st.lat) || !isFinite(st.lon)) return;
        const cxy = toCanvasXY(st.lat, st.lon);
        if (!isFinite(cxy.x) || !isFinite(cxy.y)) return;

        const isHover = exercisePreviewLblTinMarkerHoverId != null
            && String(exercisePreviewLblTinMarkerHoverId) === String(script.id);
        const isDrag = exercisePreviewScriptDragActive && exercisePreviewScriptDragId != null
            && String(exercisePreviewScriptDragId) === String(script.id)
            && exercisePreviewScriptDragTarget === 'lblTin';
        const highlighted = isHover || isDrag;
        const r = EXERCISE_LBL_TIN_MARKER_RADIUS_PX;
        const offset = normalizeInitialCallLblTinOffsetSec(script.lblTinOffsetSec, script.previewTimeSec, spawn);
        const lblText = `LBL_TIN-${offset}`;

        ctx.beginPath();
        ctx.arc(cxy.x, cxy.y, r, 0, Math.PI * 2);
        ctx.fillStyle = highlighted ? blue : yellow;
        ctx.fill();
        ctx.strokeStyle = highlighted ? blueStroke : yellowStroke;
        ctx.lineWidth = highlighted ? 2 : 1.5;
        ctx.stroke();

        const fontSize = 9;
        ctx.font = `${fontSize}px system-ui, sans-serif`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'top';
        const tw = ctx.measureText(lblText).width;
        const padX = 3;
        const padY = 2;
        const labelW = tw + padX * 2;
        const labelH = fontSize + padY * 2;
        const labelX = cxy.x - labelW / 2;
        const labelY = cxy.y + r + 2;
        ctx.fillStyle = highlighted ? 'rgba(59, 130, 246, 0.92)' : 'rgba(234, 179, 8, 0.92)';
        ctx.fillRect(labelX, labelY, labelW, labelH);
        ctx.strokeStyle = highlighted ? blueStroke : yellowStroke;
        ctx.lineWidth = 1;
        ctx.strokeRect(labelX, labelY, labelW, labelH);
        ctx.fillStyle = '#111827';
        ctx.fillText(lblText, cxy.x, labelY + padY);

        exercisePreviewLblTinMarkerBounds.push({
            scriptId: script.id,
            aircraftId: script.aircraftId,
            x: cxy.x,
            y: cxy.y,
            r,
            labelX,
            labelY,
            labelW,
            labelH
        });
    });
}

function exercisePreviewMiddleClickHitsLabelBounds(canvasX, canvasY) {
    const v = (simulationSettings?.labelMoveButton || SIM_SETTINGS_DEFAULTS.labelMoveButton || 'left').toString().toLowerCase();
    if (v !== 'middle') return false;
    const byId = new Map(exercisePreviewAircraftLabelBounds.map(b => [b.aircraftId, b]));
    for (let zi = exercisePreviewLabelZOrder.length - 1; zi >= 0; zi--) {
        const b = byId.get(exercisePreviewLabelZOrder[zi]);
        if (b && canvasX >= b.x && canvasX <= b.x + b.w && canvasY >= b.y && canvasY <= b.y + b.h) return true;
    }
    return false;
}

function exercisePreviewGetTargetTraveledNmForFlightAtCanvasXY(flight, canvasX, canvasY) {
    if (!flight || !currentEditingSector) return null;
    const { points } = computeExerciseRoutePoints(flight.route || '', getRouteFixesForSector(currentEditingSector), currentEditingSector.routes || []);
    if (!Array.isArray(points) || points.length < 2) return null;
    const ll = exerciseEditorCanvasXYToLatLon(canvasX, canvasY);
    if (!ll) return null;
    let targetNm = computeTraveledNmAlongRouteToClosestPoint(points, ll.lat, ll.lon);
    const tmp = { points };
    buildTrackCacheForAircraftPointsIfNeeded(tmp);
    const totalNm = tmp._trackCache?.totalNm;
    if (isFinite(totalNm) && totalNm > 0) targetNm = Math.max(0, Math.min(totalNm, targetNm));
    return targetNm;
}

function exercisePreviewGetRouteTotalNmForFlight(flight) {
    if (!flight || !currentEditingSector) return null;
    const { points } = computeExerciseRoutePoints(flight.route || '', getRouteFixesForSector(currentEditingSector), currentEditingSector.routes || []);
    if (!Array.isArray(points) || points.length < 2) return null;
    const tmp = { points };
    buildTrackCacheForAircraftPointsIfNeeded(tmp);
    const t = tmp._trackCache?.totalNm;
    return isFinite(t) ? t : null;
}

/**
 * Adjust spawn (integer seconds) so integrated traveledNm at previewSec approaches targetNm.
 * Uses a few measure+correct steps (same physics as preview), not a crude constant-GS formula.
 */
function exercisePreviewRefineSpawnTowardTargetNm(flightId, previewSec, targetNm, radarSec, maxIter = 10) {
    const idx = currentEditingFlights.findIndex(f => f && String(f.id) === String(flightId));
    if (idx === -1 || !Number.isFinite(previewSec) || previewSec <= 0) return;
    const hi = Math.max(0, Math.floor(previewSec));
    let row = { ...currentEditingFlights[idx] };
    let sp = Math.max(0, Math.min(hi, parseInt(row.spawnTime, 10) || 0));
    const tgt = Math.max(0, Number(targetNm) || 0);
    for (let iter = 0; iter < maxIter; iter++) {
        row = { ...row, spawnTime: sp };
        const t = measureExercisePreviewTraveledNmAtSpawn(row, sp, previewSec, radarSec);
        if (t == null || !isFinite(t)) break;
        const err = tgt - t;
        if (Math.abs(err) < 0.1) break;
        const elapsed = Math.max(0.05, previewSec - sp);
        const gsInst = Math.max(120, Math.min(750, (Math.abs(t) < 1e-6 ? 400 : (t / elapsed) * 3600)));
        let dSp = Math.round((err / gsInst) * 3600);
        if (dSp === 0) dSp = err > 0 ? -1 : 1;
        const nextSp = Math.max(0, Math.min(hi, sp - dSp));
        if (nextSp === sp && sp === 0 && err > 0.5) break;
        if (nextSp === sp && sp === hi && err < -0.5) break;
        sp = nextSp;
    }
    currentEditingFlights[idx] = { ...currentEditingFlights[idx], spawnTime: sp };
    invalidateExercisePreviewTracksAndDerivedCaches();
}

function measureExercisePreviewTraveledNmAtSpawn(flightRow, spawnInt, previewSec, radarSec) {
    if (!currentEditingSector || previewSec <= 0 || !flightRow) return null;
    const w = getRouteFixesForSector(currentEditingSector);
    const r = currentEditingSector.routes || [];
    const f = { ...flightRow, spawnTime: Math.max(0, Math.floor(spawnInt)) };
    const tracks = buildSimulationAircraftTracks({ flights: [f], waypoints: w, routes: r });
    if (!tracks[0]) return null;
    let clone;
    try {
        clone = JSON.parse(JSON.stringify(tracks[0]));
    } catch (e) {
        return null;
    }
    const savedOff = exercisePreviewLabelOffsetsByAircraftId[clone.id];
    if (savedOff && Number.isFinite(savedOff.labelOffsetX) && Number.isFinite(savedOff.labelOffsetY)) {
        clone.labelOffsetX = savedOff.labelOffsetX;
        clone.labelOffsetY = savedOff.labelOffsetY;
        clone.labelLeaderOffsetToCenter = !!savedOff.labelLeaderOffsetToCenter;
    }
    integrateExercisePreviewAircraftBatch([clone], previewSec, radarSec, [f]);
    const st = getAircraftPositionAtRadarUpdate(clone, previewSec, radarSec);
    return st && isFinite(st.traveledNm) ? Number(st.traveledNm) : null;
}

function solveExercisePreviewSpawnForTraveledNm(flightRow, previewSec, targetNm, radarSec) {
    const hi = Math.max(0, Math.floor(previewSec));
    const measure = (sp) => measureExercisePreviewTraveledNmAtSpawn(flightRow, Math.min(Math.max(0, sp), hi), previewSec, radarSec);
    const tAt0 = measure(0);
    if (tAt0 == null || !isFinite(tAt0)) return parseInt(flightRow.spawnTime, 10) || 0;
    const tgt = Math.max(0, Math.min(targetNm, tAt0));
    if (tgt <= 1e-4) return hi;
    let lo = 0;
    let r = hi + 1;
    while (lo < r) {
        const mid = Math.floor((lo + r) / 2);
        const tm = measure(mid);
        if (tm == null || !isFinite(tm)) {
            r = mid;
            continue;
        }
        if (tm > tgt) lo = mid + 1;
        else r = mid;
    }
    const sp0 = Math.min(Math.max(0, lo), hi);
    let best = sp0;
    let bestD = Infinity;
    for (const c of [sp0 - 1, sp0, sp0 + 1]) {
        if (c < 0 || c > hi) continue;
        const tv = measure(c);
        if (tv == null || !isFinite(tv)) continue;
        const d = Math.abs(tv - tgt);
        if (d < bestD) {
            bestD = d;
            best = c;
        }
    }
    return best;
}

function tryStartExercisePreviewSpawnDragAt(flightId, canvasX, canvasY) {
    const slider = document.getElementById('exercisePreviewTimeSlider');
    if (!slider || slider.disabled) return false;
    if (!currentEditingExerciseId || !currentEditingSector) return false;
    if (exercisePreviewMiddleClickHitsLabelBounds(canvasX, canvasY)) return false;
    const previewSec = parseInt(slider.value, 10);
    if (!Number.isFinite(previewSec) || previewSec <= 0) return false;
    const flight = currentEditingFlights.find(f => f && String(f.id) === String(flightId));
    if (!flight) return false;
    const cursorNm = exercisePreviewGetTargetTraveledNmForFlightAtCanvasXY(flight, canvasX, canvasY);
    if (cursorNm == null) return false;
    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
    const curSp = parseInt(flight.spawnTime, 10) || 0;
    const actualNm = measureExercisePreviewTraveledNmAtSpawn(flight, curSp, previewSec, radarSec);
    if (actualNm == null || !isFinite(actualNm)) return false;
    exercisePreviewSpawnDragNmDelta = actualNm - cursorNm;
    exercisePreviewSpawnDragActive = true;
    exercisePreviewSpawnDragFlightId = flightId;
    exercisePreviewSpawnDragLastCanvasX = canvasX;
    exercisePreviewSpawnDragLastCanvasY = canvasY;
    return true;
}

function tryStartExercisePreviewLabelDragAt(clickX, clickY) {
    const slider = document.getElementById('exercisePreviewTimeSlider');
    if (!slider || slider.disabled) return false;
    if (!currentEditingExerciseId) return false;
    const byId = new Map(exercisePreviewAircraftLabelBounds.map(b => [b.aircraftId, b]));
    for (let zi = exercisePreviewLabelZOrder.length - 1; zi >= 0; zi--) {
        const id = exercisePreviewLabelZOrder[zi];
        const b = byId.get(id);
        if (!b) continue;
        if (clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
            exercisePreviewIsDraggingLabel = true;
            exercisePreviewDraggingAircraftId = id;
            exercisePreviewLabelDragAnchorX = clickX - b.x;
            exercisePreviewLabelDragAnchorY = clickY - b.y;
            exercisePreviewLabelZOrder = exercisePreviewLabelZOrder.filter(i => i !== id);
            exercisePreviewLabelZOrder.push(id);
            return true;
        }
    }
    return false;
}

/** Top-most preview aircraft id whose symbol contains (clickX, clickY), or null. */
function pickExercisePreviewAircraftIdAtCanvasXY(clickX, clickY) {
    const slider = document.getElementById('exercisePreviewTimeSlider');
    if (!slider || slider.disabled) return null;
    if (!currentEditingExerciseId || !currentEditingSector) return null;
    if (!exercisePreviewAircraftSymbolBounds.length) return null;
    const byId = new Map(exercisePreviewAircraftSymbolBounds.map(b => [b.aircraftId, b]));
    const padPx = 3;
    const hit = (b) => {
        if (!b || b.r == null || !isFinite(b.x) || !isFinite(b.y)) return false;
        const dx = clickX - b.x;
        const dy = clickY - b.y;
        const r = Number(b.r) + padPx;
        return dx * dx + dy * dy <= r * r;
    };
    for (let zi = exercisePreviewLabelZOrder.length - 1; zi >= 0; zi--) {
        const id = exercisePreviewLabelZOrder[zi];
        const b = byId.get(id);
        if (b && hit(b)) return id;
    }
    for (let i = exercisePreviewAircraftSymbolBounds.length - 1; i >= 0; i--) {
        const b = exercisePreviewAircraftSymbolBounds[i];
        if (b && hit(b)) return b.aircraftId;
    }
    return null;
}

function renderExerciseFlightsList() {
    const container = document.getElementById('exerciseFlightsContainer');
    if (!container) return;
    try {
        updateExerciseFlightsSectionCount();
        refreshExercisePreviewTimeSlider();

        if (!currentEditingExerciseId) {
        container.innerHTML = `
            <div class="empty-state">
                <div class="empty-state-icon">📭</div>
                <div class="empty-state-text">Select an exercise to start adding flights.</div>
            </div>
        `;
            return;
        }

        if (!currentEditingFlights.length) {
        container.innerHTML = `
            <div class="empty-state">
                <div class="empty-state-icon">🛫</div>
                <div class="empty-state-text">No flights yet. Click “Add Flight”.</div>
            </div>
        `;
            return;
        }

        container.innerHTML = currentEditingFlights.map(f => {
        const line = formatFlightLine(f);
        return `
            <div class="exercise-flight-item" data-flight-id="${f.id}">
                <div class="exercise-flight-line">${line}</div>
                <div class="exercise-flight-actions">
                    <button class="btn btn-tertiary exercise-flight-edit" data-flight-id="${f.id}">Edit</button>
                    <button class="btn btn-danger exercise-flight-delete" data-flight-id="${f.id}">Delete</button>
                </div>
            </div>
        `;
    }).join('');

        container.querySelectorAll('.exercise-flight-item').forEach(item => {
        item.addEventListener('click', () => {
            container.querySelectorAll('.exercise-flight-item').forEach(i => i.classList.remove('selected'));
            item.classList.add('selected');
        });
        });

        container.querySelectorAll('.exercise-flight-edit').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            openAddFlightModal(btn.dataset.flightId);
        });
        });
        container.querySelectorAll('.exercise-flight-delete').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            const flightId = btn.dataset.flightId;
            deleteCurrentEditingFlightById(flightId);
        });
    });
    } finally {
        exerciseSectorLoadCache = { sig: '', data: null };
        try { renderExerciseSectorLoadGraph(); } catch (e) {}
        try { drawExerciseEditorCanvas(); } catch (e) {}
    }
}

function saveCurrentExercise() {
    if (!currentEditingExerciseId) return;
    flushExerciseAiPilotContextFromPanel();
    const exercises = getExercises();
    const idx = exercises.findIndex(ex => ex && ex.id === currentEditingExerciseId);
    if (idx === -1) return;
    exercises[idx] = {
        ...exercises[idx],
        flights: currentEditingFlights.map(f => ({ ...f })),
        aiPilotContext: currentEditingAiPilotContext,
        aiPilotScripts: currentEditingAiPilotScripts.map(s => ({ ...s })),
        suppressedInitialPilotCalls: currentEditingSuppressedInitialPilotCalls.map(e => ({ ...e })),
        updatedAt: new Date().toISOString()
    };
    saveExercises(exercises);
    alert('Exercise saved.');
}

function getCurrentExerciseAiPilotContext() {
    return currentEditingAiPilotContext || '';
}

function getExerciseAiPilotContextById(exerciseId) {
    const exercise = getExercises().find(ex => ex && String(ex.id) === String(exerciseId));
    return typeof exercise?.aiPilotContext === 'string' ? exercise.aiPilotContext : '';
}

function getAiPilotInitialContextForExercise(exerciseId) {
    return {
        generalInstructions: getAdminAiPilotGeneralInstructions(),
        exerciseContext: getExerciseAiPilotContextById(exerciseId)
    };
}

function isLikelyIcaoCallsign(token) {
    const t = (token || '').toString().trim().toUpperCase();
    if (!t || isAiPilotCommandStartToken(t)) return false;
    if (isLikelyApproachCommandToken(t)) return false;
    return /^[A-Z]{2,3}\d+[A-Z0-9]*$/i.test(t);
}

function isLikelyApproachCommandToken(token) {
    const t = normalizeApproachName(token);
    if (!t) return false;
    return /^(ILS|LLZ|GPS|LOC|VOR|NDB|RNP|RNAV)\d{1,2}[LRC]?$/i.test(t);
}

function extractRunwayDesignatorFromApproachName(approachName) {
    const nm = normalizeApproachName(approachName);
    const m = nm.match(/^[A-Z]{2,4}(\d{1,2}[LRC]?)$/i);
    return m ? normalizeRunwayDesignator(m[1]) : null;
}

function findSimulationApproachMatchForAircraft(ac, approachNameRaw) {
    const wanted = normalizeApproachName(approachNameRaw);
    if (!wanted || !ac) return null;
    const destIcao = normalizeAirportIcao(ac.destination);
    if (!destIcao) return null;
    const ap = getSimulationSectorAirports().find(a => normalizeAirportIcao(a?.icao) === destIcao);
    if (!ap || !Array.isArray(ap.runways)) return null;
    for (const rw of ap.runways) {
        if (!rw || !Array.isArray(rw.approaches)) continue;
        for (const app of rw.approaches) {
            if (!app) continue;
            if (normalizeApproachName(app.name) === wanted) {
                return {
                    airport: ap,
                    runway: rw,
                    approach: app,
                    approachName: wanted
                };
            }
        }
    }
    return null;
}

function ensureAircraftDestinationRunwayEnd(ac, runway, runwayDesignator) {
    const wanted = normalizeRunwayDesignator(runwayDesignator);
    if (!runway || !wanted) return false;
    const aName = normalizeRunwayDesignator(runway.endA?.name);
    const bName = normalizeRunwayDesignator(runway.endB?.name);
    if (aName === wanted) {
        ac.destRunwayId = runway.id;
        ac.destRunwayEnd = 'A';
        ac.destRunwayEndName = (runway.endA?.name || wanted).toString().trim().toUpperCase();
        return true;
    }
    if (bName === wanted) {
        ac.destRunwayId = runway.id;
        ac.destRunwayEnd = 'B';
        ac.destRunwayEndName = (runway.endB?.name || wanted).toString().trim().toUpperCase();
        return true;
    }
    return false;
}

/** ROCD token → exact feet per minute (±5000, non-zero). */
function normalizeAiPilotRocFpmFromToken(rawValue) {
    const s = String(rawValue ?? '').trim().replace(/^\+/, '');
    if (!s) return null;
    const fpm = parseInt(s, 10);
    if (!Number.isFinite(fpm) || fpm === 0) return null;
    return Math.max(-5000, Math.min(5000, fpm));
}

/** Token / command ROC/D: any fpm in range with sign matching ALV vs Mode-C. */
function isAircraftRocFpmAllowed(ac, fpm) {
    if (!ac || !Number.isFinite(fpm) || fpm === 0) return false;
    if (isAircraftWithinRocAlvCaptureZone(ac)) return false;
    const alv = getAircraftAlvFlForDisplay(ac);
    const mc = getAircraftModeCFlForDisplay(ac);
    if (alv == null || mc == null || alv === mc) return false;
    const absFpm = Math.abs(Math.trunc(fpm));
    if (absFpm < 100 || absFpm > 5000) return false;
    if (alv > mc) return fpm > 0;
    return fpm < 0;
}

function formatRocCommandSubtitleLabel(fpm) {
    const n = Math.trunc(Number(fpm));
    if (!Number.isFinite(n) || n === 0) return '0 fpm';
    return `${n > 0 ? '+' : ''}${n} fpm`;
}

function applyAiPilotRocCommandToAircraft(ac, fpm) {
    if (!ac || fpm == null) return false;
    const f = Math.trunc(Number(fpm));
    if (!Number.isFinite(f) || f === 0) return false;
    if (!isAircraftRocFpmAllowed(ac, f)) return false;
    if (!isJoinerExeOrPlnClient() && simulationOperationModeId !== 'DL') return false;
    applySimulationRocFpmSelectionToAircraft(ac, f);
    return true;
}

function isAiPilotCommandStartToken(token) {
    const t = (token || '').toString().trim().toUpperCase();
    if (!t) return false;
    if (/^(HDG|TLH|TRH|ALV|IAS|MACH|M|DCT|RTE|HOLD|EXITHOLD|ROCD)$/.test(t)) return true;
    if (/^(HDG|TLH|TRH)(\d{3})$/.test(t)) return true;
    if (/^ALV(\d{2,5})$/.test(t)) return true;
    if (/^IAS(\d{2,3})$/.test(t)) return true;
    if (/^M(\d{2,3})$/.test(t)) return true;
    if (/^ROCD[+-]?\d{2,5}$/.test(t)) return true;
    if (/^LBL_TIN-\d+$/.test(t)) return true;
    return false;
}

/** AI_PP ALV token → simulator FL (030 = 3000 ft; 240 = FL240; 3000 feet legacy → 30). */
function normalizeAiPilotAlvToFl(rawValue) {
    let n = parseInt(String(rawValue ?? '').trim(), 10);
    if (!Number.isFinite(n)) return null;
    if (n >= 1000) n = Math.round(n / 100);
    return n;
}

/** M078 / 078 → Mach 0.78 (hundredths in command token). */
function normalizeAiPilotMachFromTokenDigits(digits) {
    const n = parseInt(String(digits ?? '').trim(), 10);
    if (!Number.isFinite(n) || n < 0) return null;
    return Number((n / 100).toFixed(2));
}

function normalizeAiPilotMachSpeedValue(rawValue) {
    if (rawValue == null || rawValue === '') return null;
    if (typeof rawValue === 'number' && isFinite(rawValue)) {
        const v = Number(rawValue);
        if (v >= 1 && v <= 999) return normalizeAiPilotMachFromTokenDigits(String(Math.round(v)));
        if (v > 0 && v < 0.1) return normalizeAiPilotMachFromTokenDigits(String(Math.round(v * 1000)));
        return Number(v.toFixed(2));
    }
    const s = String(rawValue).trim().toUpperCase();
    if (/^\.\d{2,3}$/.test(s)) return normalizeAiPilotMachFromTokenDigits(s.slice(1));
    const mToken = s.match(/^M?(\d{2,3})$/);
    if (mToken) return normalizeAiPilotMachFromTokenDigits(mToken[1]);
    const n = Number(s);
    if (!Number.isFinite(n)) return null;
    if (n >= 1 && n <= 999) return normalizeAiPilotMachFromTokenDigits(String(Math.round(n)));
    if (n > 0 && n < 0.1) return normalizeAiPilotMachFromTokenDigits(String(Math.round(n * 1000)));
    return Number(n.toFixed(2));
}

function parseOneAiPilotActionFromParts(callsign, parts, startIdx) {
    if (startIdx >= parts.length) return null;
    const token = parts[startIdx].toUpperCase();
    const rest = parts.slice(startIdx + 1);
    const headingMatch = token.match(/^(HDG|TLH|TRH)(\d{3})$/);
    const altitudeMatch = token.match(/^ALV(\d{2,5})$/);
    const iasMatch = token.match(/^IAS(\d{2,3})$/);
    const machMatch = token.match(/^M(\d{2,3})$/);
    const rocdMatch = token.match(/^ROCD([+-]?\d{2,5})$/);
    const lblTinMatch = token.match(/^LBL_TIN-(\d+)$/);

    if (headingMatch) {
        return {
            action: {
                callsign,
                action: 'heading',
                input: 'HDG',
                mode: headingMatch[1],
                heading: headingMatch[2]
            },
            nextIdx: startIdx + 1
        };
    }
    if (token === 'HDG' || token === 'TLH' || token === 'TRH') {
        const heading = (rest[0] || '').padStart(3, '0').slice(-3);
        if (/^\d{3}$/.test(heading)) {
            return {
                action: { callsign, action: 'heading', input: 'HDG', mode: token, heading },
                nextIdx: startIdx + 2
            };
        }
    }
    if (token === 'DCT' && rest.length) {
        return {
            action: { callsign, action: 'direct', input: 'DCT', waypoint: rest[0].toUpperCase() },
            nextIdx: startIdx + 2
        };
    }
    if (token === 'RTE' && rest.length) {
        const route = [];
        let j = startIdx + 1;
        while (j < parts.length) {
            const part = parts[j];
            if (isLikelyIcaoCallsign(part) || isAiPilotCommandStartToken(part)) break;
            route.push(part.toUpperCase());
            j += 1;
        }
        if (!route.length) {
            return { action: { callsign, action: 'unknown', raw: parts.join(' ') }, nextIdx: startIdx + 1 };
        }
        return {
            action: { callsign, action: 'reroute', input: 'DCT', route },
            nextIdx: j
        };
    }
    if (token === 'HOLD' && rest.length) {
        return {
            action: { callsign, action: 'hold', input: 'HOLD', waypoint: rest[0].toUpperCase() },
            nextIdx: startIdx + 2
        };
    }
    if (token === 'EXITHOLD') {
        return {
            action: { callsign, action: 'exitHold', input: 'HOLD' },
            nextIdx: startIdx + 1
        };
    }
    if (altitudeMatch) {
        return {
            action: { callsign, action: 'altitude', input: 'ALV', value: altitudeMatch[1] },
            nextIdx: startIdx + 1
        };
    }
    if (token === 'ALV' && rest[0] && /^\d{2,5}$/.test(rest[0])) {
        return {
            action: { callsign, action: 'altitude', input: 'ALV', value: rest[0] },
            nextIdx: startIdx + 2
        };
    }
    if (iasMatch) {
        return {
            action: { callsign, action: 'speed', input: 'IAS', value: iasMatch[1] },
            nextIdx: startIdx + 1
        };
    }
    if (token === 'IAS' && rest[0] && /^\d{2,3}$/.test(rest[0])) {
        return {
            action: { callsign, action: 'speed', input: 'IAS', value: rest[0] },
            nextIdx: startIdx + 2
        };
    }
    if (machMatch) {
        const machVal = normalizeAiPilotMachFromTokenDigits(machMatch[1]);
        if (machVal == null) {
            return {
                action: { callsign, action: 'unknown', raw: parts.slice(startIdx).join(' ') },
                nextIdx: startIdx + 1
            };
        }
        return {
            action: { callsign, action: 'speed', input: 'MACH', value: machVal },
            nextIdx: startIdx + 1
        };
    }
    if ((token === 'MACH' || token === 'M') && rest[0]) {
        const rawMach = rest[0].replace(/^M/i, '').replace(/^0?\./, '');
        if (/^\d{2,3}$/.test(rawMach)) {
            const machVal = normalizeAiPilotMachFromTokenDigits(rawMach);
            if (machVal != null) {
                return {
                    action: { callsign, action: 'speed', input: 'MACH', value: machVal },
                    nextIdx: startIdx + 2
                };
            }
        }
    }
    if (rocdMatch) {
        const fpm = normalizeAiPilotRocFpmFromToken(rocdMatch[1]);
        if (fpm == null) {
            return {
                action: { callsign, action: 'unknown', raw: parts.slice(startIdx).join(' ') },
                nextIdx: startIdx + 1
            };
        }
        return {
            action: { callsign, action: 'roc', input: 'ROC', value: fpm, fpm },
            nextIdx: startIdx + 1
        };
    }
    if (lblTinMatch) {
        const offsetSec = Math.max(1, parseInt(lblTinMatch[1], 10) || 0);
        return {
            action: { callsign, action: 'lblTin', input: 'LBL_TIN', offsetSec },
            nextIdx: startIdx + 1
        };
    }
    if (token === 'ROCD' && rest[0] && /^[+-]?\d{2,5}$/.test(rest[0])) {
        const fpm = normalizeAiPilotRocFpmFromToken(rest[0]);
        if (fpm == null) {
            return {
                action: { callsign, action: 'unknown', raw: parts.slice(startIdx).join(' ') },
                nextIdx: startIdx + 1
            };
        }
        return {
            action: { callsign, action: 'roc', input: 'ROC', value: fpm, fpm },
            nextIdx: startIdx + 2
        };
    }
    if (isLikelyApproachCommandToken(token)) {
        return {
            action: { callsign, action: 'approach', input: 'ILS', approachName: normalizeApproachName(token) },
            nextIdx: startIdx + 1
        };
    }
    if ((token === 'ILS' || token === 'LLZ' || token === 'GPS') && rest[0]) {
        const combined = normalizeApproachName(`${token}${rest[0]}`);
        if (isLikelyApproachCommandToken(combined)) {
            return {
                action: { callsign, action: 'approach', input: 'ILS', approachName: combined },
                nextIdx: startIdx + 2
            };
        }
    }
    return {
        action: { callsign, action: 'unknown', raw: parts.slice(startIdx).join(' ') },
        nextIdx: startIdx + 1
    };
}

function parseAiPilotCommandLineToActions(line) {
    const raw = (line || '').toString().trim();
    if (!raw) return [];
    const clean = raw.replace(/^\(?Command\)?\s*:?\s*/i, '').trim();
    const parts = clean.split(/\s+/).filter(Boolean);
    if (parts.length < 2) return [];

    const actions = [];
    let i = 0;
    while (i < parts.length) {
        if (!isLikelyIcaoCallsign(parts[i])) {
            i += 1;
            continue;
        }
        const callsign = parts[i].toUpperCase();
        i += 1;
        while (i < parts.length && !isLikelyIcaoCallsign(parts[i])) {
            const parsed = parseOneAiPilotActionFromParts(callsign, parts, i);
            if (!parsed) break;
            actions.push(parsed.action);
            if (parsed.action.action === 'unknown') break;
            i = parsed.nextIdx;
        }
    }

    // Fallback: single callsign + tokens (handles edge cases if loop found nothing).
    if (!actions.length && isLikelyIcaoCallsign(parts[0])) {
        const callsign = parts[0].toUpperCase();
        let idx = 1;
        while (idx < parts.length) {
            const parsed = parseOneAiPilotActionFromParts(callsign, parts, idx);
            if (!parsed) break;
            actions.push(parsed.action);
            if (parsed.action.action === 'unknown') break;
            idx = parsed.nextIdx;
        }
    }
    return actions;
}

function parseAiPilotCommandLineToAction(line) {
    return parseAiPilotCommandLineToActions(line)[0] || null;
}

function parseAiPilotCommandTextToActions(text) {
    return (text || '')
        .toString()
        .split(/\r?\n|;/)
        .flatMap(segment => parseAiPilotCommandLineToActions(segment.trim()))
        .filter(Boolean);
}

function assessExerciseAiPilotScriptCommand(commandText, expectedCallsign) {
    const command = (commandText || '').toString().trim();
    if (!command) {
        return { valid: false, message: 'No command — input could not be mapped to simulator tokens.', actions: [] };
    }
    const actions = parseAiPilotCommandTextToActions(command);
    if (!actions.length) {
        return {
            valid: false,
            message: 'Command could not be parsed. Expected CALLSIGN TOKEN (e.g. ETD855 TLH200).',
            actions: []
        };
    }
    const unknown = actions.filter(a => a && a.action === 'unknown');
    if (unknown.length) {
        const raw = unknown.map(a => (a.raw || '?').toString().trim()).filter(Boolean).join('; ');
        return {
            valid: false,
            message: `Unrecognized command token(s): ${raw || 'unknown'}`,
            actions
        };
    }
    const expected = (expectedCallsign || '').toString().trim().toUpperCase().replace(/\s+/g, '');
    if (expected) {
        const mismatch = actions.find(a => {
            const cs = (a.callsign || '').toString().trim().toUpperCase().replace(/\s+/g, '');
            return cs && cs !== expected;
        });
        if (mismatch) {
            return {
                valid: false,
                message: `Callsign in command (${mismatch.callsign}) does not match ${expectedCallsign}.`,
                actions
            };
        }
    }
    const labels = actions.map(a => {
        const kind = (a.action || 'unknown').toString();
        const input = (a.input || '').toString();
        return input ? `${kind} (${input})` : kind;
    });
    return {
        valid: true,
        message: `Valid command format: ${labels.join(', ')}`,
        actions
    };
}

function clearExerciseAiPilotScriptTransformUi() {
    const wrap = document.getElementById('exerciseAiPilotScriptTransformedWrap');
    const out = document.getElementById('exerciseAiPilotScriptTransformed');
    const assessment = document.getElementById('exerciseAiPilotScriptCommandAssessment');
    const btn = document.getElementById('exerciseAiPilotScriptTransformBtn');
    if (out) out.value = '';
    if (wrap) wrap.hidden = true;
    if (assessment) {
        assessment.textContent = '';
        assessment.className = 'exercise-ai-pilot-script-command-assessment';
    }
    if (btn) {
        btn.disabled = false;
        btn.textContent = 'Transform to Command with AI';
    }
}

function showExerciseAiPilotScriptTransformedCommand(commandStr, callsign) {
    const wrap = document.getElementById('exerciseAiPilotScriptTransformedWrap');
    const out = document.getElementById('exerciseAiPilotScriptTransformed');
    const assessment = document.getElementById('exerciseAiPilotScriptCommandAssessment');
    const cmd = (commandStr || '').toString().trim();
    if (out) out.value = cmd;
    if (wrap) wrap.hidden = false;
    const result = assessExerciseAiPilotScriptCommand(cmd, callsign);
    if (assessment) {
        assessment.textContent = result.message;
        assessment.className = 'exercise-ai-pilot-script-command-assessment' + (result.valid ? ' is-valid' : ' is-invalid');
    }
}

async function transformExerciseAiPilotScriptCommandWithAi() {
    const csEl = document.getElementById('exerciseAiPilotScriptCallsign');
    const commandEl = document.getElementById('exerciseAiPilotScriptCommand');
    const btn = document.getElementById('exerciseAiPilotScriptTransformBtn');
    const callsign = (csEl?.textContent || '').trim();
    const inputText = (commandEl?.value || '').trim();
    if (!callsign) {
        alert('Callsign is missing.');
        return;
    }
    if (!inputText) {
        alert('Enter text in the Command box first.');
        return;
    }
    const prevLabel = btn ? btn.textContent : '';
    if (btn) {
        btn.disabled = true;
        btn.textContent = 'Transforming…';
    }
    try {
        const resp = await fetchWithTimeout('/api/ai-pilot/transform-command', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ callsign, inputText })
        }, 90000);
        const data = await resp.json().catch(() => ({}));
        if (!resp.ok || data.ok === false) throw new Error(data.error || 'Transform failed.');
        showExerciseAiPilotScriptTransformedCommand(data.command || '', callsign);
    } catch (err) {
        alert(err?.message || 'Transform to command failed.');
    } finally {
        if (btn) {
            btn.disabled = false;
            btn.textContent = prevLabel || 'Transform to Command with AI';
        }
    }
}

function syncExerciseAiPilotPanelFromExercise() {
    const textarea = document.getElementById('exerciseAiPilotContext');
    const hint = document.getElementById('exerciseAiPilotSavedHint');
    if (textarea) textarea.value = getCurrentExerciseAiPilotContext();
    if (hint) hint.textContent = '';
    renderExerciseScriptsList();
}

function flushExerciseAiPilotContextFromPanel() {
    const textarea = document.getElementById('exerciseAiPilotContext');
    if (textarea) currentEditingAiPilotContext = textarea.value;
}

function saveExerciseAiPilotContext() {
    if (!currentEditingExerciseId) return;
    const textarea = document.getElementById('exerciseAiPilotContext');
    const hint = document.getElementById('exerciseAiPilotSavedHint');
    currentEditingAiPilotContext = textarea ? textarea.value : '';

    const exercises = getExercises();
    const idx = exercises.findIndex(ex => ex && ex.id === currentEditingExerciseId);
    if (idx !== -1) {
        exercises[idx] = {
            ...exercises[idx],
            aiPilotContext: currentEditingAiPilotContext,
            aiPilotScripts: currentEditingAiPilotScripts.map(s => ({ ...s })),
            suppressedInitialPilotCalls: currentEditingSuppressedInitialPilotCalls.map(e => ({ ...e })),
            updatedAt: new Date().toISOString()
        };
        saveExercises(exercises);
    }

    if (hint) hint.textContent = 'AI Pilot context saved with this exercise.';
}

function normalizeExerciseAiPilotScriptEntry(raw) {
    if (!raw || typeof raw !== 'object') return null;
    const previewTimeSec = Math.max(0, parseInt(raw.previewTimeSec, 10) || 0);
    const aircraftId = raw.aircraftId != null ? String(raw.aircraftId) : '';
    const callsign = (raw.callsign || '').toString().trim();
    if (!aircraftId && !callsign) return null;
    const scriptKind = String(raw.scriptKind || 'custom') === 'initialCall' ? 'initialCall' : 'custom';
    const entry = {
        id: String(raw.id || '').trim() || (Date.now().toString() + Math.random().toString(16).slice(2)),
        scriptKind,
        previewTimeSec,
        aircraftId,
        callsign,
        atcSectorId: raw.atcSectorId != null ? String(raw.atcSectorId) : '',
        lblTinOffsetSec: scriptKind === 'initialCall'
            ? normalizeInitialCallLblTinOffsetSec(raw.lblTinOffsetSec, previewTimeSec, raw.spawnTimeSec)
            : 0,
        aiInformation: typeof raw.aiInformation === 'string' ? raw.aiInformation : '',
        aiInformationSilent: !!raw.aiInformationSilent,
        ttsMessage: typeof raw.ttsMessage === 'string' ? raw.ttsMessage : '',
        ttsUseAiResponse: !!raw.ttsUseAiResponse,
        commandForAi: typeof raw.commandForAi === 'string' ? raw.commandForAi : '',
        aiTransformedCommand: typeof raw.aiTransformedCommand === 'string' ? raw.aiTransformedCommand : ''
    };
    return scriptKind === 'initialCall' ? syncInitialCallLblTinFields(entry) : entry;
}

function normalizeExerciseAiPilotScriptsFromExercise(exercise) {
    const raw = exercise?.aiPilotScripts;
    if (!Array.isArray(raw)) return [];
    return raw.map(normalizeExerciseAiPilotScriptEntry).filter(Boolean);
}

function getExercisePreviewFlightCallsign(aircraftId) {
    const f = currentEditingFlights.find(row => row && String(row.id) === String(aircraftId));
    return (f?.callsign || '').toString().trim();
}

function getExercisePreviewTimeSec() {
    const slider = document.getElementById('exercisePreviewTimeSlider');
    if (!slider || slider.disabled) return 0;
    const v = parseInt(slider.value, 10);
    return Number.isFinite(v) ? Math.max(0, v) : 0;
}

function persistCurrentEditingAiPilotScripts() {
    if (!currentEditingExerciseId) return;
    const exercises = getExercises();
    const idx = exercises.findIndex(ex => ex && ex.id === currentEditingExerciseId);
    if (idx === -1) return;
    exercises[idx] = {
        ...exercises[idx],
        aiPilotScripts: currentEditingAiPilotScripts.map(s => ({ ...s })),
        suppressedInitialPilotCalls: currentEditingSuppressedInitialPilotCalls.map(e => ({ ...e })),
        updatedAt: new Date().toISOString()
    };
    saveExercises(exercises);
}

function renderExerciseScriptsList() {
    const body = document.getElementById('exerciseScriptsBody');
    const deleteAllBtn = document.getElementById('exerciseScriptsDeleteAllBtn');
    const generateInitCallsBtn = document.getElementById('exerciseScriptsGenerateInitCallsBtn');
    if (!body) return;
    const sorted = [...currentEditingAiPilotScripts].sort((a, b) => {
        const ta = Number(a.previewTimeSec) || 0;
        const tb = Number(b.previewTimeSec) || 0;
        if (ta !== tb) return ta - tb;
        return (a.callsign || '').localeCompare(b.callsign || '');
    });
    if (deleteAllBtn) deleteAllBtn.disabled = sorted.length === 0;
    if (generateInitCallsBtn) generateInitCallsBtn.disabled = !currentEditingExerciseId || !currentEditingFlights.length;
    if (!sorted.length) {
        exerciseScriptsListSelectedId = null;
        body.innerHTML = '<p class="hint-text exercise-scripts-empty">No scripts yet. Right-click a callsign on the map to add one.</p>';
        return;
    }
    if (exerciseScriptsListSelectedId && !sorted.some(s => String(s.id) === String(exerciseScriptsListSelectedId))) {
        exerciseScriptsListSelectedId = null;
    }
    body.innerHTML = sorted.map(entry => {
        const time = formatPreviewClockMMSS(entry.previewTimeSec);
        const cs = entry.callsign || '—';
        const isCall = isExerciseInitialCallScript(entry);
        const sectorLabel = isCall ? getExerciseAtcSectorDisplayNameById(entry.atcSectorId) : '';
        const tinLabel = isCall && getInitialCallLblTinPreviewTimeSec(entry, getExerciseFlightSpawnSecForScript(entry)) != null
            ? ` TIN-${normalizeInitialCallLblTinOffsetSec(entry.lblTinOffsetSec, entry.previewTimeSec, getExerciseFlightSpawnSecForScript(entry))}`
            : '';
        const rowLabel = isCall
            ? `CALL ${time} ${cs}${sectorLabel && sectorLabel !== '—' ? ` · ${sectorLabel}` : ''}${tinLabel}`
            : `${time} ${cs}`;
        const selected = exerciseScriptsListSelectedId != null && String(entry.id) === String(exerciseScriptsListSelectedId);
        return `
            <div class="exercise-script-list-item${selected ? ' selected' : ''}${isCall ? ' exercise-script-list-item-initial-call' : ''}" data-script-id="${escapeHtml(entry.id)}">
                <span class="exercise-script-list-label">${escapeHtml(rowLabel)}</span>
                <div class="exercise-script-list-actions">
                    <button type="button" class="btn btn-tertiary exercise-script-edit-btn" data-script-id="${escapeHtml(entry.id)}" title="Edit" aria-label="Edit script"><span class="btn-icon" aria-hidden="true">✏️</span></button>
                    <button type="button" class="btn btn-danger exercise-script-delete-btn" data-script-id="${escapeHtml(entry.id)}" title="Delete" aria-label="Delete script"><span class="btn-icon" aria-hidden="true">🗑️</span></button>
                </div>
            </div>`;
    }).join('');

    body.querySelectorAll('.exercise-script-list-item').forEach(item => {
        item.addEventListener('click', (e) => {
            if (e.target.closest('.exercise-script-edit-btn') || e.target.closest('.exercise-script-delete-btn')) return;
            const id = item.getAttribute('data-script-id');
            exerciseScriptsListSelectedId = (exerciseScriptsListSelectedId != null && String(exerciseScriptsListSelectedId) === String(id)) ? null : id;
            renderExerciseScriptsList();
        });
    });
    body.querySelectorAll('.exercise-script-edit-btn').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            openExerciseAiPilotScriptModalForEdit(btn.getAttribute('data-script-id'));
        });
    });
    body.querySelectorAll('.exercise-script-delete-btn').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            deleteExerciseAiPilotScript(btn.getAttribute('data-script-id'));
        });
    });
}

function deleteExerciseAiPilotScript(scriptId) {
    if (!scriptId) return;
    const script = currentEditingAiPilotScripts.find(s => s && String(s.id) === String(scriptId));
    if (script && isExerciseInitialCallScript(script)) {
        deleteExerciseInitialPilotCallScript(scriptId);
        return;
    }
    const before = currentEditingAiPilotScripts.length;
    currentEditingAiPilotScripts = currentEditingAiPilotScripts.filter(s => String(s.id) !== String(scriptId));
    if (currentEditingAiPilotScripts.length === before) return;
    if (exerciseScriptsListSelectedId != null && String(exerciseScriptsListSelectedId) === String(scriptId)) {
        exerciseScriptsListSelectedId = null;
    }
    persistCurrentEditingAiPilotScripts();
    renderExerciseScriptsList();
}

function openDeleteExerciseScriptsConfirmModal() {
    if (!currentEditingAiPilotScripts.length) return;
    openModal('deleteExerciseScriptsConfirmModal');
}

function confirmDeleteAllExerciseAiPilotScripts() {
    if (!currentEditingAiPilotScripts.length) {
        closeModal('deleteExerciseScriptsConfirmModal');
        return;
    }
    currentEditingAiPilotScripts = [];
    currentEditingSuppressedInitialPilotCalls = [];
    exerciseScriptsListSelectedId = null;
    persistCurrentEditingAiPilotScripts();
    renderExerciseScriptsList();
    closeModal('deleteExerciseScriptsConfirmModal');
}

function closeExerciseAiPilotScriptModal() {
    exerciseAiPilotScriptModalAircraftId = null;
    exerciseAiPilotScriptModalEditingId = null;
    clearExerciseAiPilotScriptTransformUi();
    closeModal('exerciseAiPilotScriptModal');
}

function syncExerciseAiPilotScriptModalInitialCallFields(entry, opts = {}) {
    const wrap = document.getElementById('exerciseAiPilotScriptEntrySectorWrap');
    const sectorEl = document.getElementById('exerciseAiPilotScriptEntrySector');
    const lblWrap = document.getElementById('exerciseAiPilotScriptLblTinWrap');
    const lblTimeEl = document.getElementById('exerciseAiPilotScriptLblTinTime');
    const lblCmdEl = document.getElementById('exerciseAiPilotScriptLblTinCommand');
    const isInitial = entry && isExerciseInitialCallScript(entry);
    if (wrap) wrap.hidden = !isInitial;
    if (sectorEl) {
        sectorEl.textContent = isInitial ? getExerciseAtcSectorDisplayNameById(entry.atcSectorId) : '—';
    }
    if (!isInitial) {
        if (lblWrap) lblWrap.hidden = true;
        if (lblCmdEl) lblCmdEl.value = '';
        return;
    }
    const synced = syncInitialCallLblTinFields(entry);
    const spawn = getExerciseFlightSpawnSecForScript(synced);
    const lblSec = getInitialCallLblTinPreviewTimeSec(synced, spawn);
    const hasLblTin = synced.atcSectorId && lblSec != null;
    const cmd = hasLblTin
        ? (synced.aiTransformedCommand || buildInitialCallLblTinTransformedCommand(synced.callsign, synced.lblTinOffsetSec))
        : '';
    if (lblWrap) lblWrap.hidden = !hasLblTin;
    if (lblTimeEl) lblTimeEl.textContent = hasLblTin ? formatPreviewClockMMSS(lblSec) : '—';
    if (lblCmdEl) lblCmdEl.value = cmd;
    if (opts.focusLblTin && hasLblTin && lblWrap) {
        lblWrap.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
        try { lblCmdEl?.focus({ preventScroll: true }); } catch (e) {}
    }
}

function openExerciseAiPilotScriptModalForEdit(scriptId, opts = {}) {
    if (!currentEditingExerciseId || !scriptId) return;
    const entry = currentEditingAiPilotScripts.find(s => s && String(s.id) === String(scriptId));
    if (!entry) return;

    exerciseAiPilotScriptModalEditingId = entry.id;
    exerciseAiPilotScriptModalAircraftId = entry.aircraftId;

    const timeEl = document.getElementById('exerciseAiPilotScriptPreviewTime');
    const csEl = document.getElementById('exerciseAiPilotScriptCallsign');
    const aiInfo = document.getElementById('exerciseAiPilotScriptAiInfo');
    const aiSilent = document.getElementById('exerciseAiPilotScriptAiSilent');
    const tts = document.getElementById('exerciseAiPilotScriptTts');
    const ttsUseAi = document.getElementById('exerciseAiPilotScriptTtsUseAi');
    const command = document.getElementById('exerciseAiPilotScriptCommand');
    const titleEl = document.querySelector('#exerciseAiPilotScriptModal .modal-header h2');

    if (timeEl) timeEl.textContent = formatPreviewClockMMSS(entry.previewTimeSec);
    if (csEl) csEl.textContent = entry.callsign || '—';
    if (aiInfo) aiInfo.value = entry.aiInformation || '';
    if (aiSilent) aiSilent.checked = !!entry.aiInformationSilent;
    if (tts) tts.value = entry.ttsMessage || '';
    if (ttsUseAi) ttsUseAi.checked = !!entry.ttsUseAiResponse;
    if (command) command.value = entry.commandForAi || '';
    if (titleEl) titleEl.textContent = isExerciseInitialCallScript(entry) ? 'Edit Initial Call' : 'Edit AI Pilot Script';
    syncExerciseAiPilotScriptModalInitialCallFields(entry, opts);
    if (isExerciseInitialCallScript(entry)) {
        clearExerciseAiPilotScriptTransformUi();
    } else if (entry.aiTransformedCommand) {
        showExerciseAiPilotScriptTransformedCommand(entry.aiTransformedCommand, entry.callsign || '');
    } else {
        clearExerciseAiPilotScriptTransformUi();
    }

    openModal('exerciseAiPilotScriptModal');
}

function openExerciseAiPilotScriptModal(aircraftId) {
    if (!currentEditingExerciseId || aircraftId == null) return;
    const slider = document.getElementById('exercisePreviewTimeSlider');
    if (!slider || slider.disabled) return;

    exerciseAiPilotScriptModalEditingId = null;
    exerciseAiPilotScriptModalAircraftId = aircraftId;
    const previewSec = getExercisePreviewTimeSec();
    const callsign = getExercisePreviewFlightCallsign(aircraftId);

    const timeEl = document.getElementById('exerciseAiPilotScriptPreviewTime');
    const csEl = document.getElementById('exerciseAiPilotScriptCallsign');
    const aiInfo = document.getElementById('exerciseAiPilotScriptAiInfo');
    const aiSilent = document.getElementById('exerciseAiPilotScriptAiSilent');
    const tts = document.getElementById('exerciseAiPilotScriptTts');
    const ttsUseAi = document.getElementById('exerciseAiPilotScriptTtsUseAi');
    const command = document.getElementById('exerciseAiPilotScriptCommand');
    const titleEl = document.querySelector('#exerciseAiPilotScriptModal .modal-header h2');

    if (timeEl) timeEl.textContent = formatPreviewClockMMSS(previewSec);
    if (csEl) csEl.textContent = callsign || '—';
    if (aiInfo) aiInfo.value = '';
    if (aiSilent) aiSilent.checked = false;
    if (tts) tts.value = '';
    if (ttsUseAi) ttsUseAi.checked = false;
    if (command) command.value = '';
    if (titleEl) titleEl.textContent = 'AI Pilot Script';
    syncExerciseAiPilotScriptModalInitialCallFields(null);
    clearExerciseAiPilotScriptTransformUi();

    openModal('exerciseAiPilotScriptModal');
}

function saveExerciseAiPilotScriptFromModal() {
    if (!currentEditingExerciseId || exerciseAiPilotScriptModalAircraftId == null) return;
    const aircraftId = exerciseAiPilotScriptModalAircraftId;
    const aiInfo = document.getElementById('exerciseAiPilotScriptAiInfo');
    const aiSilent = document.getElementById('exerciseAiPilotScriptAiSilent');
    const tts = document.getElementById('exerciseAiPilotScriptTts');
    const ttsUseAi = document.getElementById('exerciseAiPilotScriptTtsUseAi');
    const command = document.getElementById('exerciseAiPilotScriptCommand');
    const transformed = document.getElementById('exerciseAiPilotScriptTransformed');

    const editingId = exerciseAiPilotScriptModalEditingId;
    const existing = editingId
        ? currentEditingAiPilotScripts.find(s => s && String(s.id) === String(editingId))
        : null;
    const callsign = existing?.callsign || getExercisePreviewFlightCallsign(aircraftId);
    const previewTimeSec = existing != null
        ? (Number(existing.previewTimeSec) || 0)
        : getExercisePreviewTimeSec();

    const entry = normalizeExerciseAiPilotScriptEntry({
        id: editingId || (Date.now().toString() + Math.random().toString(16).slice(2)),
        scriptKind: existing?.scriptKind || 'custom',
        previewTimeSec,
        aircraftId,
        callsign,
        atcSectorId: existing?.atcSectorId || '',
        lblTinOffsetSec: existing?.lblTinOffsetSec,
        aiInformation: aiInfo ? aiInfo.value : '',
        aiInformationSilent: aiSilent ? aiSilent.checked : false,
        ttsMessage: tts ? tts.value : '',
        ttsUseAiResponse: ttsUseAi ? ttsUseAi.checked : false,
        commandForAi: command ? command.value : '',
        aiTransformedCommand: transformed ? transformed.value : ''
    });
    if (!entry) return;
    let saved = entry;
    if (isExerciseInitialCallScript(saved)) {
        saved = syncInitialCallLblTinFields(saved);
    }

    if (editingId) {
        const idx = currentEditingAiPilotScripts.findIndex(s => s && String(s.id) === String(editingId));
        if (idx === -1) return;
        currentEditingAiPilotScripts[idx] = saved;
    } else {
        currentEditingAiPilotScripts.push(saved);
    }
    persistCurrentEditingAiPilotScripts();
    renderExerciseScriptsList();
    closeExerciseAiPilotScriptModal();
}

function deleteCurrentEditingFlightById(flightId) {
    const flight = currentEditingFlights.find(x => x && x.id === flightId);
    if (!flight) return false;
    if (!confirm(`Delete flight ${flight.callsign}? This cannot be undone.`)) return false;
    currentEditingFlights = currentEditingFlights.filter(x => x && x.id !== flightId);
    renderExerciseFlightsList();
    try { syncExerciseInitialCallScriptsForAllFlights(); } catch (eSync) {}
    return true;
}

function openAddFlightModal(editingFlightId = null) {
    const form = document.getElementById('addFlightForm');
    if (!form) return;
    form.reset();
    document.getElementById('aircraftTypeError')?.style?.setProperty('display', 'none');
    document.getElementById('aircraftTypeSuggestions')?.style?.setProperty('display', 'none');
    document.getElementById('flightRouteSuggestions')?.style?.setProperty('display', 'none');

    const createBtn = document.getElementById('createFlightBtn');
    const deleteBtn = document.getElementById('deleteFlightBtn');
    const title = document.getElementById('addFlightTitle');
    if (editingFlightId) {
        const flight = currentEditingFlights.find(f => f && f.id === editingFlightId);
        if (!flight) return;
        title.textContent = 'Edit Flight';
        if (createBtn) createBtn.textContent = 'Save';
        if (deleteBtn) {
            deleteBtn.hidden = false;
            deleteBtn.dataset.flightId = editingFlightId;
        }
        form.dataset.editingFlightId = editingFlightId;

        document.getElementById('flightCallsign').value = flight.callsign || '';
        document.getElementById('flightAircraftType').value = flight.aircraftType || '';
        document.getElementById('flightDeparture').value = flight.departure || '';
        document.getElementById('flightDestination').value = flight.destination || '';
        document.getElementById('flightRoute').value = flight.route || '';
        document.getElementById('flightSpawnTime').value = flight.spawnTime ?? '';
        document.getElementById('flightPEL').value = flight.pel ?? '';
        document.getElementById('flightALV').value = flight.alv ?? '';
        document.getElementById('flightRLV').value = flight.rlv ?? '';
        const depP = document.getElementById('flightDepartureProfile');
        if (depP) depP.checked = !!flight.departureProfile;
    } else {
        title.textContent = 'Add Flight';
        if (createBtn) createBtn.textContent = 'Create';
        if (deleteBtn) {
            deleteBtn.hidden = true;
            delete deleteBtn.dataset.flightId;
        }
        delete form.dataset.editingFlightId;
        const depP = document.getElementById('flightDepartureProfile');
        if (depP) depP.checked = false;
    }

    // mark aircraft type selection as not-yet-validated until a selection click happens
    const typeInput = document.getElementById('flightAircraftType');
    if (typeInput) typeInput.dataset.selectedType = (typeInput.value || '').trim().toUpperCase();

    openModal('addFlightModal');
    setTimeout(() => document.getElementById('flightCallsign')?.focus(), 50);
}

function parseRouteSegments(routeStr) {
    return (routeStr || '')
        .split(/[\s,]+/)
        .map(s => s.trim())
        .filter(Boolean);
}

/**
 * Ordered waypoint ids from sector route `startName` → `endName` (inclusive), along stored route order (forward or backward).
 * Names are matched case-insensitively to waypoint names on the route.
 */
function subpathWaypointIdsOnRoute(route, startName, endName, wpById) {
    const ids = route?.waypointIds;
    if (!Array.isArray(ids) || !ids.length) return null;
    const nameAt = (id) => ((wpById.get(id)?.name || '').trim().toUpperCase());
    const si = ids.findIndex(id => nameAt(id) === startName);
    const ei = ids.findIndex(id => nameAt(id) === endName);
    if (si < 0 || ei < 0) return null;
    const out = [];
    if (si <= ei) {
        for (let k = si; k <= ei; k++) out.push(ids[k]);
    } else {
        for (let k = si; k >= ei; k--) out.push(ids[k]);
    }
    return out;
}

/**
 * Resolve exercise route string to lat/lon points. Tokens are space- or comma-separated.
 * A sector route name must appear between two waypoints that exist on that route; the segment is expanded to all intermediate route waypoints. Waypoints, coordinates (DDMMSSN/DDDMMSSE), and hyphen-chained waypoint names are supported.
 * @returns {{ points: Array<{lat:number,lon:number,name:string}>, error: string|null }}
 */
function computeExerciseRoutePoints(routeStr, waypoints, routes) {
    const wpById = new Map();
    const wpByName = new Map();
    (waypoints || []).forEach(wp => {
        if (!wp) return;
        if (wp.id) wpById.set(wp.id, wp);
        const name = (wp.name || '').trim().toUpperCase();
        if (name) wpByName.set(name, wp);
    });

    const routeByName = new Map();
    (routes || []).forEach(r => {
        const name = (r?.name || '').trim().toUpperCase();
        if (name) routeByName.set(name, r);
    });

    const toPoint = (wpOrPoint) => {
        if (!wpOrPoint) return null;
        const lat = wpOrPoint.latitude;
        const lon = wpOrPoint.longitude;
        if (!isFinite(lat) || !isFinite(lon)) return null;
        const nm = (wpOrPoint.name || '').toString().trim();
        const flRaw = wpOrPoint.fl ?? wpOrPoint.flightLevel ?? wpOrPoint.level;
        const flN = parseInt(flRaw, 10);
        const fl = Number.isFinite(flN) ? Math.max(0, Math.min(500, flN)) : null;
        const idPart = (wpOrPoint?.id != null && String(wpOrPoint.id).trim() !== '')
            ? { wpId: String(wpOrPoint.id) }
            : {};
        return { lat, lon, name: nm ? nm.toUpperCase() : '', ...idPart, ...(fl != null ? { fl } : {}) };
    };

    const tokens = parseRouteSegments(routeStr);
    const pts = [];
    const pushPoint = (p) => {
        if (!p) return;
        const last = pts[pts.length - 1];
        if (!last || last.lat !== p.lat || last.lon !== p.lon) pts.push(p);
    };

    for (let i = 0; i < tokens.length; i++) {
        const token = tokens[i].trim();
        if (!token) continue;
        const up = token.toUpperCase();

        if (isValidCoordinateSegment(up)) {
            const c = parseCoordinateSegment(up);
            if (c) pushPoint({ lat: c.latitude, lon: c.longitude, name: '' });
            continue;
        }

        const r = routeByName.get(up);
        if (r && Array.isArray(r.waypointIds)) {
            if (i === 0 || i + 1 >= tokens.length) {
                return { points: [], error: `Route "${up}" must be placed between a start and end waypoint on that route.` };
            }
            const prevTok = tokens[i - 1].trim().toUpperCase();
            const nextTok = tokens[i + 1].trim().toUpperCase();
            if (isValidCoordinateSegment(prevTok) || isValidCoordinateSegment(nextTok)) {
                return { points: [], error: `Route "${up}" must use sector waypoints (not coordinates) as its endpoints.` };
            }
            if (!wpByName.has(prevTok) || !wpByName.has(nextTok)) {
                return { points: [], error: `Route "${up}": endpoints "${prevTok}" and "${nextTok}" must be known waypoints.` };
            }
            const chainIds = subpathWaypointIdsOnRoute(r, prevTok, nextTok, wpById);
            if (!chainIds) {
                return { points: [], error: `Route "${up}": waypoints "${prevTok}" and "${nextTok}" are not both on that route.` };
            }
            for (const id of chainIds) {
                pushPoint(toPoint(wpById.get(id)));
            }
            i += 1;
            continue;
        }

        const wp = wpByName.get(up);
        if (wp) {
            pushPoint(toPoint(wp));
            continue;
        }

        if (up.includes('-')) {
            const parts = up.split('-').map(s => s.trim()).filter(Boolean);
            for (const name of parts) {
                const wp2 = wpByName.get(name);
                const p2 = toPoint(wp2);
                if (p2) pushPoint(p2);
            }
            continue;
        }

        return { points: [], error: `Unknown route token: "${token}". Use a waypoint, coordinate, sector route (between two of its waypoints), or hyphen-linked waypoints.` };
    }

    return { points: pts, error: null };
}

function isValidCoordinateSegment(seg) {
    return /^\d{6}[NS]\/\d{7}[EW]$/i.test((seg || '').trim());
}

function parseCoordinateSegment(seg) {
    const s = (seg || '').trim().toUpperCase();
    if (!isValidCoordinateSegment(s)) return null;
    const [latStr, lonStr] = s.split('/');
    if (!latStr || !lonStr) return null;

    const latDegrees = parseInt(latStr.substring(0, 2), 10);
    const latMinutes = parseInt(latStr.substring(2, 4), 10);
    const latSeconds = parseInt(latStr.substring(4, 6), 10);
    const latDirection = latStr.substring(6, 7);
    const lonDegrees = parseInt(lonStr.substring(0, 3), 10);
    const lonMinutes = parseInt(lonStr.substring(3, 5), 10);
    const lonSeconds = parseInt(lonStr.substring(5, 7), 10);
    const lonDirection = lonStr.substring(7, 8);

    if (![latDegrees, latMinutes, latSeconds, lonDegrees, lonMinutes, lonSeconds].every(n => Number.isFinite(n))) return null;
    if (latDegrees < 0 || latDegrees > 89) return null;
    if (latMinutes < 0 || latMinutes > 59) return null;
    if (latSeconds < 0 || latSeconds > 59) return null;
    if (latDirection !== 'N' && latDirection !== 'S') return null;
    if (lonDegrees < 0 || lonDegrees > 179) return null;
    if (lonMinutes < 0 || lonMinutes > 59) return null;
    if (lonSeconds < 0 || lonSeconds > 59) return null;
    if (lonDirection !== 'E' && lonDirection !== 'W') return null;

    const latitude = DMSToDecimal(latDegrees, latMinutes, latSeconds, latDirection);
    const longitude = DMSToDecimal(lonDegrees, lonMinutes, lonSeconds, lonDirection);
    if (!isFinite(latitude) || !isFinite(longitude)) return null;
    return { latitude, longitude };
}

/** Single latitude token: DDMMSSN or DDMMSSS (2°2′ 2″ + N/S). */
function parseLatitudeDMSegment(seg) {
    const s = (seg || '').trim().toUpperCase().replace(/\s/g, '');
    if (!/^\d{6}[NS]$/.test(s)) return null;
    const latDegrees = parseInt(s.substring(0, 2), 10);
    const latMinutes = parseInt(s.substring(2, 4), 10);
    const latSeconds = parseInt(s.substring(4, 6), 10);
    const latDirection = s.substring(6, 7);
    if (latDegrees < 0 || latDegrees > 89) return null;
    if (latMinutes < 0 || latMinutes > 59) return null;
    if (latSeconds < 0 || latSeconds > 59) return null;
    if (latDirection !== 'N' && latDirection !== 'S') return null;
    const latitude = DMSToDecimal(latDegrees, latMinutes, latSeconds, latDirection);
    return isFinite(latitude) ? latitude : null;
}

/** Single longitude token: DDDMMSS + E or W (3° 2′ 2″ + hemisphere). */
function parseLongitudeDMSegment(seg) {
    const s = (seg || '').trim().toUpperCase().replace(/\s/g, '');
    if (!/^\d{7}[EW]$/.test(s)) return null;
    const lonDegrees = parseInt(s.substring(0, 3), 10);
    const lonMinutes = parseInt(s.substring(3, 5), 10);
    const lonSeconds = parseInt(s.substring(5, 7), 10);
    const lonDirection = s.substring(7, 8);
    if (lonDegrees < 0 || lonDegrees > 179) return null;
    if (lonMinutes < 0 || lonMinutes > 59) return null;
    if (lonSeconds < 0 || lonSeconds > 59) return null;
    if (lonDirection !== 'E' && lonDirection !== 'W') return null;
    const longitude = DMSToDecimal(lonDegrees, lonMinutes, lonSeconds, lonDirection);
    return isFinite(longitude) ? longitude : null;
}

function isaAtAltitude(altFeet) {
    const h = Math.max(0, altFeet || 0) * 0.3048; // meters
    const T0 = 288.15;
    const P0 = 101325.0;
    const rho0 = 1.225;
    const g = 9.80665;
    const R = 287.05;
    const L = -0.0065;

    let T;
    let P;
    if (h <= 11000) {
        T = T0 + L * h;
        P = P0 * Math.pow(T / T0, -g / (L * R));
    } else {
        T = 216.65;
        const P11 = P0 * Math.pow(T / T0, -g / (L * R));
        P = P11 * Math.exp(-g * (h - 11000) / (R * T));
    }
    const rho = P / (R * T);
    const sigma = rho / rho0;
    return { T, sigma };
}

function knotsFromMach(mach, altFeet) {
    const { T } = isaAtAltitude(altFeet);
    const gamma = 1.4;
    const R = 287.05;
    const a = Math.sqrt(gamma * R * T); // m/s
    return mach * a * 1.943844492; // knots
}

function ktasFromKias(kias, altFeet) {
    const { sigma } = isaAtAltitude(altFeet);
    if (!isFinite(kias) || kias <= 0) return null;
    if (!isFinite(sigma) || sigma <= 0) return kias;
    return kias / Math.sqrt(sigma);
}

function kiasFromKtas(ktas, altFeet) {
    const { sigma } = isaAtAltitude(altFeet);
    if (!isFinite(ktas) || ktas <= 0) return null;
    if (!isFinite(sigma) || sigma <= 0) return ktas;
    return ktas * Math.sqrt(sigma);
}

function speedOfSoundKt(altFeet) {
    const { T } = isaAtAltitude(altFeet);
    const gamma = 1.4;
    const R = 287.05;
    const a = Math.sqrt(gamma * R * T); // m/s
    return a * 1.943844492; // knots
}

function machFromKtas(ktas, altFeet) {
    const aKt = speedOfSoundKt(altFeet);
    if (!isFinite(ktas) || !isFinite(aKt) || aKt <= 0) return null;
    return ktas / aKt;
}

function computeGroundSpeedKt(aircraftType, flightLevel) {
    const type = (aircraftType || '').trim().toUpperCase();
    const rec = AIRCRAFT_DB?.[type];
    if (!rec) return null;
    const fl = parseInt(flightLevel, 10);
    const altFeet = (Number.isFinite(fl) ? fl : 0) * 100;

    let kiasNorm = rec.kias?.mid?.norm;
    if (Number.isFinite(fl)) {
        if (fl < 100) kiasNorm = rec.kias?.low?.norm;
        else if (fl < 280) kiasNorm = rec.kias?.mid?.norm;
        else kiasNorm = rec.kias?.high?.norm;
    }

    if (Number.isFinite(fl) && fl >= 280 && rec.mach?.normal != null) {
        const gs = knotsFromMach(rec.mach.normal, altFeet);
        return isFinite(gs) ? Math.round(gs) : null;
    }

    const tas = ktasFromKias(kiasNorm, altFeet);
    return isFinite(tas) ? Math.round(tas) : null;
}

function moveTowardKtas(cur, target, maxDelta) {
    if (!isFinite(cur) || !isFinite(target)) return cur;
    if (Math.abs(target - cur) <= maxDelta) return target;
    return cur + Math.sign(target - cur) * maxDelta;
}

/** Manual speed control overrides exercise “Departure” acceleration profile. */
function departureProfileSpeedSuperseded(ac) {
    if (!ac) return true;
    if (ac.speedSelectedType && ac.speedSelectedValue != null) return true;
    if (ac.speedChangeStartSimSec != null && ac.speedTargetKtas != null) return true;
    return false;
}

/**
 * Departure profile: below FL100, target IAS ramps 160→240 with altitude; at/above FL100, target KTAS from aircraft DB for current FL.
 * Acceleration: 7 kt/s below 180 KIAS; 15 kt/s from 180–240 KIAS (Mode-C below FL100); 7 kt/s at/above FL100 to type speed.
 */
function applyDepartureProfileSpeedStep(ac, dtSimSec) {
    const type = (ac.aircraftType || '').trim().toUpperCase();
    const altFeet = Number(ac.modeCFeet);
    if (!isFinite(altFeet)) return;
    const h = Math.max(0, altFeet);
    const dt = Math.max(0, dtSimSec || 0);
    let cur = Number(ac.modeSTasKt);
    if (!isFinite(cur)) {
        const k = ktasFromKias(160, h);
        cur = isFinite(k) ? k : 160;
    }

    const curKias = kiasFromKtas(cur, h);
    let rateKtPerSec = 7;
    if (h < 10000 && isFinite(curKias) && curKias >= 180 && curKias < 240) {
        rateKtPerSec = 15;
    }
    const maxStep = Math.max(0.25, rateKtPerSec * dt);

    if (h < 10000) {
        const t = Math.min(1, h / 10000);
        const targetIas = 160 + (240 - 160) * t;
        const targetKtas = ktasFromKias(targetIas, h);
        if (!isFinite(targetKtas)) return;
        ac.modeSTasKt = moveTowardKtas(cur, targetKtas, maxStep);
    } else {
        const fl = Math.round(h / 100);
        const targetGs = computeGroundSpeedKt(type, fl);
        if (targetGs == null || !isFinite(targetGs)) return;
        ac.modeSTasKt = moveTowardKtas(cur, Number(targetGs), maxStep);
    }
}

function interpolateGreatCircle(lat1, lon1, lat2, lon2, f) {
    // f in [0,1]
    const clampF = Math.max(0, Math.min(1, f));
    const toRad = (d) => d * Math.PI / 180;
    const toDeg = (r) => r * 180 / Math.PI;
    const φ1 = toRad(lat1), λ1 = toRad(lon1);
    const φ2 = toRad(lat2), λ2 = toRad(lon2);

    const sinDφ = Math.sin((φ2 - φ1) / 2);
    const sinDλ = Math.sin((λ2 - λ1) / 2);
    const a = sinDφ * sinDφ + Math.cos(φ1) * Math.cos(φ2) * sinDλ * sinDλ;
    const δ = 2 * Math.asin(Math.min(1, Math.sqrt(Math.max(0, a))));
    if (!isFinite(δ) || δ === 0) return { lat: lat1, lon: lon1 };

    const A = Math.sin((1 - clampF) * δ) / Math.sin(δ);
    const B = Math.sin(clampF * δ) / Math.sin(δ);

    const x = A * Math.cos(φ1) * Math.cos(λ1) + B * Math.cos(φ2) * Math.cos(λ2);
    const y = A * Math.cos(φ1) * Math.sin(λ1) + B * Math.cos(φ2) * Math.sin(λ2);
    const z = A * Math.sin(φ1) + B * Math.sin(φ2);

    const φi = Math.atan2(z, Math.sqrt(x * x + y * y));
    const λi = Math.atan2(y, x);
    return { lat: toDeg(φi), lon: toDeg(λi) };
}

/** Joiner (incl. PP): append host radar frame to ring buffer for history dots / past positions. */
function appendJoinerTrailSampleFromHostDisplay(ac) {
    if (!simulationJoinedSessionId || !ac) return;
    if (ac._displayLat == null || !isFinite(ac._displayLat) || ac._displayLon == null || !isFinite(ac._displayLon)) return;
    const lu = ac._displayLastUpdateSimSec;
    if (lu == null || !isFinite(lu)) return;
    if (!Array.isArray(ac._joinerTrailSamples)) ac._joinerTrailSamples = [];
    const last = ac._joinerTrailSamples[ac._joinerTrailSamples.length - 1];
    if (last && Number(last.simSec) === Number(lu)) return;
    ac._joinerTrailSamples.push({ simSec: Number(lu), lat: ac._displayLat, lon: ac._displayLon });
    while (ac._joinerTrailSamples.length > 20) ac._joinerTrailSamples.shift();
}

/** Joiners: master clock from host only. Local simulationSimTimeMs is not used while joined. */
function syncJoinerClockFromHostState(state) {
    if (!simulationJoinedSessionId || !state) return;
    if (state.simulationRate != null && isFinite(Number(state.simulationRate))) {
        simulationRate = Number(state.simulationRate);
    }
    if (state.simulationSimTimeMs == null || !isFinite(Number(state.simulationSimTimeMs))) return;
    const hostMs = Math.max(0, Number(state.simulationSimTimeMs));
    joinerHostDisplaySimTimeMs = hostMs;
    joinerLastAppliedHostSimTimeMs = hostMs;
    if (state.hostStateSeq != null && isFinite(Number(state.hostStateSeq))) {
        joinerLastAppliedHostStateSeq = Number(state.hostStateSeq);
    }
}

/** Drop incoming session state if it has no host time, or is an older hostStateSeq (stale GET). Without hostStateSeq, fall back to rejecting lower sim time (out-of-order HTTP only; breaks rewind until server sends seq). */
function shouldIgnoreJoinerIncomingState(state) {
    if (!simulationJoinedSessionId || !state) return false;
    if (state.simulationSimTimeMs == null || !isFinite(Number(state.simulationSimTimeMs))) return true;
    const seqRaw = state.hostStateSeq;
    if (seqRaw != null && isFinite(Number(seqRaw))) {
        const seq = Number(seqRaw);
        if (joinerLastAppliedHostStateSeq != null && seq < joinerLastAppliedHostStateSeq) return true;
        return false;
    }
    const t = Number(state.simulationSimTimeMs);
    if (joinerLastAppliedHostSimTimeMs != null && t < joinerLastAppliedHostSimTimeMs) return true;
    return false;
}

/** After ATM lateral is bootstrapped, DL uses only ATM + host lat/lon — not host FMS next/traveledNm. */
function joinerAtmLateralLocked(ac) {
    return !!(ac && ac._atmLateralLocked);
}

/** Last known host radar frame per aircraft — used when a poll omits _display* so we never fall back to local route math. */
function syncJoinerHeldDisplayFromAircraft(ac) {
    if (!simulationJoinedSessionId || !ac) return;
    if (ac._displayLat != null && isFinite(ac._displayLat) && ac._displayLon != null && isFinite(ac._displayLon)) {
        ac._joinerHeldDisplayLat = ac._displayLat;
        ac._joinerHeldDisplayLon = ac._displayLon;
        ac._joinerHeldDisplayGs = ac._displayGs;
        if (!isJoinerAtmDisplayClient()) {
            ac._joinerHeldDisplayNext = ac._displayNext;
        } else {
            delete ac._joinerHeldDisplayNext;
        }
        ac._joinerHeldDisplayLastUpdateSimSec = ac._displayLastUpdateSimSec;
    }
    if (!isJoinerAtmDisplayClient() && ac._displayTraveledNm != null && isFinite(Number(ac._displayTraveledNm))) {
        ac._joinerHeldDisplayTraveledNm = Number(ac._displayTraveledNm);
    } else if (isJoinerAtmDisplayClient()) {
        delete ac._joinerHeldDisplayTraveledNm;
    }
}

/** When server JSON replaces aircraft objects, copy held host frame onto new rows missing _display* (avoids one-frame fallback to local route). */
function preserveJoinerHeldDisplayAcrossAircraftReplace(prevList, nextList) {
    if (!simulationJoinedSessionId || !Array.isArray(prevList) || !Array.isArray(nextList)) return;
    const heldById = new Map();
    prevList.forEach((ac) => {
        if (!ac || ac.id == null) return;
        if (ac._joinerHeldDisplayLat != null && isFinite(ac._joinerHeldDisplayLat) && ac._joinerHeldDisplayLon != null && isFinite(ac._joinerHeldDisplayLon)) {
            heldById.set(ac.id, {
                lat: ac._joinerHeldDisplayLat,
                lon: ac._joinerHeldDisplayLon,
                gs: ac._joinerHeldDisplayGs,
                next: ac._joinerHeldDisplayNext,
                last: ac._joinerHeldDisplayLastUpdateSimSec,
                traveledNm: ac._joinerHeldDisplayTraveledNm
            });
        }
    });
    nextList.forEach((ac) => {
        if (!ac || ac.id == null) return;
        if (ac._displayLat != null && isFinite(ac._displayLat) && ac._displayLon != null && isFinite(ac._displayLon)) return;
        const h = heldById.get(ac.id);
        if (!h) return;
        ac._joinerHeldDisplayLat = h.lat;
        ac._joinerHeldDisplayLon = h.lon;
        ac._joinerHeldDisplayGs = h.gs;
        if (!isJoinerAtmDisplayClient()) {
            ac._joinerHeldDisplayNext = h.next;
        } else {
            delete ac._joinerHeldDisplayNext;
        }
        ac._joinerHeldDisplayLastUpdateSimSec = h.last;
        if (!isJoinerAtmDisplayClient() && (ac._displayTraveledNm == null || !isFinite(Number(ac._displayTraveledNm))) && h.traveledNm != null && isFinite(Number(h.traveledNm))) {
            ac._joinerHeldDisplayTraveledNm = Number(h.traveledNm);
        } else if (isJoinerAtmDisplayClient()) {
            delete ac._joinerHeldDisplayTraveledNm;
        }
    });
}

/** After session JSON replace, keep _atmLateralLocked on the new aircraft row objects. */
function preserveJoinerAtmLateralLockAcrossAircraftReplace(prevList, nextList) {
    if (!simulationJoinedSessionId || !Array.isArray(prevList) || !Array.isArray(nextList)) return;
    const lockById = new Map();
    prevList.forEach((ac) => {
        if (ac && ac.id != null && ac._atmLateralLocked) lockById.set(ac.id, true);
    });
    nextList.forEach((ac) => {
        if (ac && ac.id != null && lockById.get(ac.id)) ac._atmLateralLocked = true;
    });
}

/** EXE/PLN/INSTR/EVAL/OBS: never use host FMS _displayNext / _displayTraveledNm — reporting is display-trajectory + host lat/lon only. */
function stripJoinerAtmDisplayHostFmsReportingFields() {
    if (!isJoinerAtmDisplayClient() || !window.simulationData?.aircraft) return;
    window.simulationData.aircraft.forEach((ac) => {
        if (!ac) return;
        delete ac._displayNext;
        delete ac._displayTraveledNm;
    });
}

/** Snapshot host FMS HDG/DCT from state PUT (before strip) — used to reject host echo in ATM bucket. */
let joinerHostFmsDctSnapshotByAid = null;

function snapshotHostFmsDctFieldsFromAircraft(ac) {
    const snap = {};
    if (!ac) return snap;
    for (const k of ATM_JOINER_DCT_LABEL_KEYS) {
        if (Object.prototype.hasOwnProperty.call(ac, k)) snap[k] = ac[k];
    }
    for (const k of ATM_JOINER_PEER_NAV_STATE_KEYS) {
        if (k === '_headingNavStatesEntries') {
            if (ac.headingNavStatesByUpdateSec instanceof Map && ac.headingNavStatesByUpdateSec.size) {
                try {
                    snap[k] = Array.from(ac.headingNavStatesByUpdateSec.entries()).map(([kk, vv]) => [
                        kk,
                        vv && typeof vv === 'object' ? { lat: vv.lat, lon: vv.lon, hdg: vv.hdg } : vv
                    ]);
                } catch (e) {}
            }
            continue;
        }
        if (Object.prototype.hasOwnProperty.call(ac, k)) snap[k] = ac[k];
    }
    return snap;
}

function usesHostPpRunwayDomain() {
    return !isJoinerAtmDisplayClient();
}

function usesSimulationRwyPickerDomain() {
    return usesHostPpRunwayDomain() || isJoinerAtmTrajectoryEditor();
}

function stripHostPpRunwayKeysFromPatchObject(patch) {
    if (!patch || typeof patch !== 'object') return patch;
    for (const k of RUNWAY_LABEL_KEYS) {
        if (Object.prototype.hasOwnProperty.call(patch, k)) delete patch[k];
    }
    return patch;
}

function applyRunwayLabelFieldsFromPatchObjectToAircraft(ac, patch) {
    if (!ac || !patch || typeof patch !== 'object') return;
    for (const k of RUNWAY_LABEL_KEYS) {
        if (Object.prototype.hasOwnProperty.call(patch, k)) ac[k] = patch[k];
    }
}

/** After host GET replaces aircraft: drop host/PP runway echo (EXE/PLN restore from ATM bucket). */
function stripJoinerHostFmsRunwayDisplayFields() {
    if (!isJoinerAtmDisplayClient() || !window.simulationData?.aircraft) return;
    window.simulationData.aircraft.forEach((ac) => {
        if (!ac) return;
        for (const k of RUNWAY_LABEL_KEYS) ac[k] = null;
    });
}

/** After host GET replaces aircraft: drop host/PP HDG/DCT label fields (EXE/PLN use joinerExeAircraftPatches only). */
function stripJoinerHostFmsDctDisplayFields() {
    if (!isJoinerAtmDisplayClient() || !window.simulationData?.aircraft) return;
    window.simulationData.aircraft.forEach((ac) => {
        if (!ac) return;
        for (const k of ATM_JOINER_DCT_LABEL_KEYS) ac[k] = null;
        for (const k of ATM_JOINER_PEER_NAV_STATE_KEYS) {
            if (k === '_headingNavStatesEntries') {
                if (ac.headingNavStatesByUpdateSec instanceof Map) ac.headingNavStatesByUpdateSec.clear();
            } else {
                ac[k] = null;
            }
        }
    });
}

/** Label HDG/DCT: joinerExe (local/peer mirror) with ATM bucket fallback for EXE↔PLN sync. */
function getJoinerAtmDctLabelAircraftView(ac) {
    if (!isJoinerAtmDisplayClient() || !ac) return ac;
    const merged = { ...ac };
    const aid = String(ac.id);
    const jp = joinerExeAircraftPatches ? joinerExeAircraftPatches[aid] : null;
    const sp = (ac._atmTrajectoryPatch && typeof ac._atmTrajectoryPatch === 'object')
        ? ac._atmTrajectoryPatch
        : null;
    const pendingLocal = _joinerAtmTrajectoryPostPendingIds && _joinerAtmTrajectoryPostPendingIds.has(aid);
    for (const k of ATM_JOINER_DCT_LABEL_KEYS) {
        let v = null;
        if (pendingLocal && jp && Object.prototype.hasOwnProperty.call(jp, k)) {
            v = jp[k];
        } else if (jp && Object.prototype.hasOwnProperty.call(jp, k) && jp[k] != null && jp[k] !== '') {
            v = jp[k];
        } else if (sp && Object.prototype.hasOwnProperty.call(sp, k) && sp[k] != null && sp[k] !== '') {
            v = sp[k];
        } else if (jp && Object.prototype.hasOwnProperty.call(jp, k)) {
            v = jp[k];
        }
        merged[k] = (v != null && v !== '') ? v : null;
    }
    return merged;
}

function formatAircraftHdgDctLabelText(ac) {
    const appName = (ac?.selectedApproachName || '').toString().trim().toUpperCase();
    if (appName) return appName;
    const hold = getSimulationHoldLabelParts(ac);
    if (hold?.prefix && hold?.name) return `${hold.prefix} ${hold.name}`.trim();
    const dctName = (ac?.directToWpName || '').toString().trim();
    if (dctName) return dctName;
    const hdg = parseInt(ac?.selectedHeadingDeg, 10);
    if (Number.isFinite(hdg)) return `H${String(heading0to359(hdg)).padStart(3, '0')}`;
    return 'DCT';
}

/** Joiner trail: past dots only from host-pushed samples (_joinerTrailSamples), never local route math. */
function getJoinerTrailDotAtOrBefore(ac, targetSimSec) {
    const samples = ac?._joinerTrailSamples;
    if (!Array.isArray(samples) || !samples.length) return null;
    const t = Number(targetSimSec);
    if (!isFinite(t)) return null;
    let best = null;
    for (let j = samples.length - 1; j >= 0; j--) {
        const s = samples[j];
        if (!s || !isFinite(s.lat) || !isFinite(s.lon)) continue;
        const ss = Number(s.simSec);
        if (!isFinite(ss) || ss > t) continue;
        if (!best || ss > best.ss) best = { lat: s.lat, lon: s.lon, ss };
    }
    return best ? { lat: best.lat, lon: best.lon } : null;
}

/** Hash of waypoint lat/lon so _trackCache invalidates when coordinates change without points.length changing. */
function getAircraftPointsGeometrySignature(ac) {
    const pts = ac?.points;
    if (!Array.isArray(pts)) return '';
    let h = 2166136261 >>> 0;
    for (let i = 0; i < pts.length; i++) {
        const p = pts[i];
        const lat = Math.round(Number(p?.lat) * 1e6);
        const lon = Math.round(Number(p?.lon) * 1e6);
        h ^= lat;
        h = Math.imul(h, 16777619) >>> 0;
        h ^= lon;
        h = Math.imul(h, 16777619) >>> 0;
    }
    return `${pts.length}:${h}`;
}

/** Joiners never run full getAircraftPositionAtRadarUpdate (early return); sector/label code still needs leg lengths from ac.points. */
function buildTrackCacheForAircraftPointsIfNeeded(ac) {
    if (!ac || !Array.isArray(ac.points) || ac.points.length < 1) return;
    const geomSig = getAircraftPointsGeometrySignature(ac);
    if (ac._trackCache && ac._trackCache.geomSig === geomSig) return;
    const legsNm = [];
    const cumNm = [0];
    let sum = 0;
    for (let i = 0; i < ac.points.length - 1; i++) {
        const p0 = ac.points[i];
        const p1 = ac.points[i + 1];
        const d = calculateNauticalMiles(p0.lat, p0.lon, p1.lat, p1.lon);
        const leg = (isFinite(d) && d > 0) ? d : 0;
        legsNm.push(leg);
        sum += leg;
        cumNm.push(sum);
    }
    ac._trackCache = { n: ac.points.length, legsNm, cumNm, totalNm: sum, geomSig };
}

function getAircraftPositionAtRadarUpdate(ac, simSec, radarSec) {
    if (!ac) return null;
    if (ac._playbackState && isFinite(ac._playbackState.lat) && isFinite(ac._playbackState.lon)) {
        return {
            lat: Number(ac._playbackState.lat),
            lon: Number(ac._playbackState.lon),
            next: null,
            gs: Number.isFinite(Number(ac._playbackState.gs)) ? Number(ac._playbackState.gs) : 0,
            labelGs: Number.isFinite(Number(ac._playbackState.gs)) ? Number(ac._playbackState.gs) : null,
            traveledNm: 0,
            lastUpdateSimSec: Number.isFinite(Number(ac._playbackState.simSec)) ? Number(ac._playbackState.simSec) : simSec
        };
    }
    // Joiner: host snapshot only; if a poll omits _display*, use last held frame — never local route integration.
    if (simulationJoinedSessionId) {
        const lat = (ac._displayLat != null && isFinite(ac._displayLat)) ? ac._displayLat : ac._joinerHeldDisplayLat;
        const lon = (ac._displayLon != null && isFinite(ac._displayLon)) ? ac._displayLon : ac._joinerHeldDisplayLon;
        if (lat != null && isFinite(lat) && lon != null && isFinite(lon)) {
            const spawnJ = parseInt(ac.spawnTimeSec, 10) || 0;
            const hostSec = Math.floor(getEffectiveSimulationSimTimeMs() / 1000);
            if (!Number.isFinite(hostSec) || hostSec < spawnJ) return null;
            const gsUse = (ac._displayGs != null && isFinite(ac._displayGs))
                ? ac._displayGs
                : ((ac._joinerHeldDisplayGs != null && isFinite(ac._joinerHeldDisplayGs)) ? ac._joinerHeldDisplayGs : 200);
            const curLu = (ac._displayLastUpdateSimSec != null && isFinite(ac._displayLastUpdateSimSec))
                ? Number(ac._displayLastUpdateSimSec)
                : ((ac._joinerHeldDisplayLastUpdateSimSec != null && isFinite(ac._joinerHeldDisplayLastUpdateSimSec))
                    ? Number(ac._joinerHeldDisplayLastUpdateSimSec)
                    : null);
            // EXE/PLN/INSTR/EVAL/OBS: position reports = displayed trajectory (middle-click polyline) + host lat/lon only.
            if (isJoinerAtmDisplayClient()) {
                syncJoinerAtmRouteProgressFromHostDisplay(ac);
                const rep = computeJoinerDisplayTrajectoryPositionReport(ac, lat, lon);
                return {
                    lat,
                    lon,
                    next: rep.next,
                    gs: gsUse,
                    traveledNm: rep.traveledNm,
                    lastUpdateSimSec: curLu
                };
            }
            // PP joiner: host-pushed _display* (FMS) for trajectory/position until host model applies.
            let tNm = 0;
            let nextOut = null;
            const next = ac._displayNext || ac._joinerHeldDisplayNext || null;
            if (ac._displayTraveledNm != null && isFinite(Number(ac._displayTraveledNm))) {
                tNm = Number(ac._displayTraveledNm);
            } else if (ac._joinerHeldDisplayTraveledNm != null && isFinite(Number(ac._joinerHeldDisplayTraveledNm))) {
                tNm = Number(ac._joinerHeldDisplayTraveledNm);
            }
            nextOut = next || null;
            return {
                lat,
                lon,
                next: nextOut || null,
                gs: gsUse,
                traveledNm: tNm,
                lastUpdateSimSec: curLu
            };
        }
        return null;
    }
    if (!Array.isArray(ac.points) || ac.points.length < 1) return null;
    const spawn = parseInt(ac.spawnTimeSec, 10) || 0;
    if (!Number.isFinite(simSec) || simSec < spawn) return null;

    const interval = Math.max(1, parseInt(radarSec, 10) || 1);
    const elapsedSinceSpawn = simSec - spawn;
    const elapsedAtLastUpdate = Math.floor(elapsedSinceSpawn / interval) * interval; // quantize to radar update
    const lastUpdateSimSec = spawn + elapsedAtLastUpdate;

    const clampFl = (fl) => {
        const n = Number(fl);
        if (!isFinite(n)) return null;
        return Math.max(0, Math.min(500, Math.round(n)));
    };

    const previewKinematicsSampleAt = (tSecQuery) => {
        const m = ac._previewKinematicsBySimSec;
        if (!(m instanceof Map) || m.size === 0) return null;
        const tf = Math.max(spawn, Number(tSecQuery));
        if (!isFinite(tf)) return null;
        const t0 = Math.floor(tf);
        const t1 = Math.ceil(tf);
        const e0 = m.get(t0);
        const e1 = (t1 !== t0) ? m.get(t1) : e0;
        if (!e0 && !e1) return null;
        if (!e0) return e1;
        if (!e1 || t0 === t1) return e0;
        const f = tf - t0;
        const lerp = (a, b) => {
            const na = Number(a);
            const nb = Number(b);
            if (isFinite(na) && isFinite(nb)) return na + (nb - na) * f;
            return isFinite(na) ? na : nb;
        };
        return {
            modeCFeet: lerp(e0.modeCFeet, e1.modeCFeet),
            modeSTasKt: lerp(e0.modeSTasKt, e1.modeSTasKt)
        };
    };

    const getBestFlNowAt = (tQuery) => {
        const samp = previewKinematicsSampleAt(tQuery);
        if (samp && isFinite(samp.modeCFeet)) {
            const flFromMc = clampFl(samp.modeCFeet / 100);
            if (flFromMc != null) return flFromMc;
        }
        const mcFeet = Number(ac.publishedModeCFeet ?? ac.modeCFeet);
        const flFromMc = isFinite(mcFeet) ? clampFl(mcFeet / 100) : null;
        if (flFromMc != null) return flFromMc;
        const alv = clampFl(ac.alv);
        if (alv != null) return alv;
        const asg = clampFl(ac.assignedFl);
        if (asg != null) return asg;
        return 0;
    };

    const getGsForMovementAtSimSec = (tSec) => {
        // If a speed change is in progress (or was scheduled), compute TAS at that sim-second from the schedule.
        try {
            const start = Number(ac.speedChangeStartSimSec);
            const dur = Number(ac.speedChangeDurationSec);
            const s0 = Number(ac.speedStartKtas);
            const s1 = Number(ac.speedTargetKtas);
            if (isFinite(start) && isFinite(dur) && dur > 0 && isFinite(s0) && isFinite(s1) && isFinite(tSec)) {
                const p = Math.max(0, Math.min(1, (tSec - start) / dur));
                const ktas = s0 + (s1 - s0) * p;
                if (isFinite(ktas) && ktas > 0) return ktas;
            }
        } catch (e) {}

        // If we recently finished a speed change and the schedule fields were cleared,
        // keep using the last change record for past timestamps within that window.
        try {
            const rec = ac.lastSpeedChange;
            const start = Number(rec?.startSimSec);
            const dur = Number(rec?.durationSec);
            const s0 = Number(rec?.startKtas);
            const s1 = Number(rec?.targetKtas);
            if (isFinite(start) && isFinite(dur) && dur > 0 && isFinite(s0) && isFinite(s1) && isFinite(tSec)) {
                if (tSec >= start && tSec <= start + dur) {
                    const p = Math.max(0, Math.min(1, (tSec - start) / dur));
                    const ktas = s0 + (s1 - s0) * p;
                    if (isFinite(ktas) && ktas > 0) return ktas;
                }
            }
        } catch (e) {}

        const sampMid = previewKinematicsSampleAt(tSec);
        if (sampMid && isFinite(sampMid.modeSTasKt) && sampMid.modeSTasKt > 0) return sampMid.modeSTasKt;

        // Otherwise use current Mode-S TAS if available (no wind model, so TAS ~ GS here).
        const ktasNow = Number(ac.publishedModeSTasKt ?? ac.modeSTasKt);
        if (isFinite(ktasNow) && ktasNow > 0) return ktasNow;

        // Fallback to aircraft DB performance at current FL.
        const gsDb = computeGroundSpeedKt(ac.aircraftType, getBestFlNowAt(tSec));
        if (isFinite(gsDb) && gsDb > 0) return gsDb;

        return null;
    };

    // Route-nav distance traveled (NM):
    // Previously this was `gs * elapsedAtLastUpdate / 3600`, which made separation stay constant even after Mach/IAS commands.
    // Now we integrate per radar update using the commanded Mode-S TAS schedule (or DB GS when no command).
    let traveledNm = null;
    try {
        const nPts = Array.isArray(ac.points) ? ac.points.length : 0;
        if (ac.routeNavTravelCacheN == null || ac.routeNavTravelCacheN !== nPts) {
            ac.routeNavTravelCacheN = nPts;
            ac.routeNavTraveledNmByUpdateSec = new Map();
            ac.routeNavLastUpdateSimSec = null;
            ac.routeNavTraveledNm = 0;
        }
        if (!(ac.routeNavTraveledNmByUpdateSec instanceof Map)) ac.routeNavTraveledNmByUpdateSec = new Map();

        // Seed at spawn time.
        if (!ac.routeNavTraveledNmByUpdateSec.has(spawn)) {
            ac.routeNavTraveledNmByUpdateSec.set(spawn, 0);
        }

        let baseSec = Number(ac.routeNavLastUpdateSimSec);
        if (!isFinite(baseSec) || baseSec < spawn) baseSec = spawn;
        let baseNm = Number(ac.routeNavTraveledNmByUpdateSec.get(baseSec));
        if (!isFinite(baseNm)) baseNm = Number(ac.routeNavTraveledNm) || 0;
        if (!isFinite(baseNm)) baseNm = 0;

        if (lastUpdateSimSec > baseSec) {
            for (let tSec = baseSec + interval; tSec <= lastUpdateSimSec; tSec += interval) {
                const prevNm = Number(ac.routeNavTraveledNmByUpdateSec.get(tSec - interval));
                const prev = isFinite(prevNm) ? prevNm : baseNm;
                const gsMid = getGsForMovementAtSimSec(tSec - interval * 0.5);
                const dNm = (isFinite(gsMid) && gsMid > 0) ? (gsMid * interval) / 3600 : 0;
                const nextNm = prev + dNm;
                ac.routeNavTraveledNmByUpdateSec.set(tSec, nextNm);
                baseNm = nextNm;
            }
            ac.routeNavLastUpdateSimSec = lastUpdateSimSec;
            ac.routeNavTraveledNm = baseNm;
        }

        traveledNm = Number(ac.routeNavTraveledNmByUpdateSec.get(lastUpdateSimSec));
        if (!isFinite(traveledNm)) traveledNm = Number(ac.routeNavTraveledNm) || 0;
        if (!isFinite(traveledNm)) traveledNm = 0;
    } catch (e) {
        traveledNm = null;
    }

    const gs = getGsForMovementAtSimSec(lastUpdateSimSec);
    if (!gs || !isFinite(gs) || gs <= 0) return null;

    // Cache legs/cumulative distances (NM). Must run before heading-nav early return; otherwise heading-nav
    // exits without ever building _trackCache (sector sequence, getAircraftPositionAlongTrackAtDistanceNm, etc.).
    const geomSig = getAircraftPointsGeometrySignature(ac);
    if (!ac._trackCache || ac._trackCache.geomSig !== geomSig) {
        const legsNm = [];
        const cumNm = [0];
        let sum = 0;
        for (let i = 0; i < ac.points.length - 1; i++) {
            const p0 = ac.points[i];
            const p1 = ac.points[i + 1];
            const d = calculateNauticalMiles(p0.lat, p0.lon, p1.lat, p1.lon);
            const leg = (isFinite(d) && d > 0) ? d : 0;
            legsNm.push(leg);
            sum += leg;
            cumNm.push(sum);
        }
        ac._trackCache = { n: ac.points.length, legsNm, cumNm, totalNm: sum, geomSig };
    }

    // If this aircraft is in heading-nav mode, prefer the stored position for this radar update.
    // IMPORTANT: never fall back to route interpolation for heading-nav (it can "jump" to the end of a rewritten route).
    try {
        if (ac.navMode === 'heading' && ac.headingNavStatesByUpdateSec instanceof Map) {
            const st = ac.headingNavStatesByUpdateSec.get(lastUpdateSimSec);
            if (st && isFinite(st.lat) && isFinite(st.lon)) {
                return { lat: st.lat, lon: st.lon, next: null, gs, traveledNm: 0, lastUpdateSimSec };
            }
            if (ac.headingNavLastUpdateSimSec === lastUpdateSimSec && isFinite(ac.headingNavLat) && isFinite(ac.headingNavLon)) {
                return { lat: ac.headingNavLat, lon: ac.headingNavLon, next: null, gs, traveledNm: 0, lastUpdateSimSec };
            }
            if (isFinite(ac.headingNavLat) && isFinite(ac.headingNavLon)) {
                return { lat: ac.headingNavLat, lon: ac.headingNavLon, next: null, gs, traveledNm: 0, lastUpdateSimSec };
            }
        }
    } catch (e) {}

    if (traveledNm == null || !isFinite(traveledNm)) {
        traveledNm = (gs * elapsedAtLastUpdate) / 3600;
    }

    const { legsNm, cumNm, totalNm } = ac._trackCache;
    if (!isFinite(totalNm) || totalNm <= 0 || ac.points.length === 1) {
        const p = ac.points[0];
        return { lat: p.lat, lon: p.lon, next: null, gs, traveledNm, lastUpdateSimSec };
    }

    const t = Math.max(0, Number(traveledNm) || 0);
    if (t >= totalNm) {
        const last = ac.points[ac.points.length - 1];
        return { lat: last.lat, lon: last.lon, next: null, gs, traveledNm: totalNm, lastUpdateSimSec };
    }

    // find segment
    let segIdx = 0;
    for (let i = 0; i < legsNm.length; i++) {
        const segStart = cumNm[i];
        const segEnd = cumNm[i + 1];
        if (t >= segStart && t <= segEnd) { segIdx = i; break; }
    }

    const segStartNm = cumNm[segIdx];
    const segLenNm = legsNm[segIdx] || 0;
    const p0 = ac.points[segIdx];
    const p1 = ac.points[segIdx + 1];
    if (!p0 || !p1 || segLenNm <= 0) {
        return { lat: p0?.lat, lon: p0?.lon, next: p1 ? { lat: p1.lat, lon: p1.lon, name: p1.name || '' } : null, gs, traveledNm: t, lastUpdateSimSec };
    }

    const f = (t - segStartNm) / segLenNm;
    const pi = interpolateGreatCircle(p0.lat, p0.lon, p1.lat, p1.lon, f);
    return { lat: pi.lat, lon: pi.lon, next: { lat: p1.lat, lon: p1.lon, name: p1.name || '' }, gs, traveledNm: t, lastUpdateSimSec };
}

function getAircraftPositionAlongTrackAtDistanceNm(ac, distNm) {
    if (!ac || !Array.isArray(ac.points) || ac.points.length < 1) return null;
    const d = Math.max(0, distNm || 0);

    buildTrackCacheForAircraftPointsIfNeeded(ac);

    const cache = ac._trackCache;
    if (!cache || !isFinite(cache.totalNm) || cache.totalNm <= 0 || ac.points.length === 1) {
        const p = ac.points[0];
        return p ? { lat: p.lat, lon: p.lon } : null;
    }

    const legsNm = cache.legsNm;
    const cumNm = cache.cumNm;
    const totalNm = cache.totalNm;
    if (d >= totalNm) {
        const last = ac.points[ac.points.length - 1];
        return { lat: last.lat, lon: last.lon };
    }

    let segIdx = 0;
    for (let i = 0; i < legsNm.length; i++) {
        const segStart = cumNm[i];
        const segEnd = cumNm[i + 1];
        if (d >= segStart && d <= segEnd) { segIdx = i; break; }
    }
    const segStartNm = cumNm[segIdx];
    const segLenNm = legsNm[segIdx] || 0;
    const p0 = ac.points[segIdx];
    const p1 = ac.points[segIdx + 1];
    if (!p0 || !p1 || segLenNm <= 0) return { lat: p0?.lat, lon: p0?.lon };
    const f = (d - segStartNm) / segLenNm;
    const pi = interpolateGreatCircle(p0.lat, p0.lon, p1.lat, p1.lon, f);
    return { lat: pi.lat, lon: pi.lon };
}

/** Joiner DL: advance along the same polyline as middle-click / ATM display (not raw ac.points / host FMS). */
function getAircraftPositionAlongTrackAtDistanceNmFromPoints(pts, distNm) {
    if (!Array.isArray(pts) || pts.length < 1) return null;
    return getAircraftPositionAlongTrackAtDistanceNm({ points: pts, _trackCache: null }, distNm);
}

/** Arbitrary great-circle polyline (e.g. middle-click trajectory: current pos → remaining waypoints). */
function getPositionAlongPolylineAtDistanceNm(points, legsNm, cumNm, distNm) {
    if (!Array.isArray(points) || points.length < 1) return null;
    const d = Math.max(0, distNm || 0);
    if (points.length === 1) {
        const p = points[0];
        return p && isFinite(p.lat) && isFinite(p.lon) ? { lat: p.lat, lon: p.lon } : null;
    }
    if (!Array.isArray(legsNm) || !Array.isArray(cumNm) || legsNm.length + 1 !== points.length) return null;
    const total = cumNm[cumNm.length - 1];
    if (!isFinite(total) || total <= 0) {
        const p = points[0];
        return p && isFinite(p.lat) && isFinite(p.lon) ? { lat: p.lat, lon: p.lon } : null;
    }
    if (d >= total) {
        const last = points[points.length - 1];
        return last && isFinite(last.lat) && isFinite(last.lon) ? { lat: last.lat, lon: last.lon } : null;
    }
    let segIdx = 0;
    for (let i = 0; i < legsNm.length; i++) {
        const s0 = cumNm[i];
        const s1 = cumNm[i + 1];
        if (d >= s0 && d <= s1) {
            segIdx = i;
            break;
        }
    }
    const segStartNm = cumNm[segIdx];
    const segLenNm = legsNm[segIdx] || 0;
    const p0 = points[segIdx];
    const p1 = points[segIdx + 1];
    if (!p0 || !p1 || segLenNm <= 0) return { lat: p0?.lat, lon: p0?.lon };
    const f = (d - segStartNm) / segLenNm;
    const pi = interpolateGreatCircle(p0.lat, p0.lon, p1.lat, p1.lon, f);
    return { lat: pi.lat, lon: pi.lon };
}

function getAircraftDbClimbDescNormalFpm(aircraftType) {
    const rec = AIRCRAFT_DB?.[(aircraftType || '').trim().toUpperCase()];
    const climb = Number.isFinite(rec?.climb?.normalFpm) ? rec.climb.normalFpm : 2000;
    const desc = Number.isFinite(rec?.desc?.normalFpm) ? rec.desc.normalFpm : 2000;
    return { climb, desc };
}

/** DL joiner with merged ATM_Trajectory patch (display route differs from host FMS geometry). */
function hasAtmTrajectoryPatchForSector(ac) {
    return isJoinerAtmDisplayClient() && ac && ac._atmTrajectoryPatch && typeof ac._atmTrajectoryPatch === 'object';
}

const ROUTE_PASS_RADIUS_NM = 1.5;
const ROUTE_ABEAM_MAX_NM = 15;
const JOINER_ATM_ROUTE_PROGRESS_MAX_ADVANCE_PER_TICK = 5;
/** Host patch keys that must not drive EXE/PLN display progression (local pass/abeam index only). */
const ATM_PATCH_JOINER_LOCAL_PROGRESS_KEYS = ['routeProgressIdx', 'routeCompleted', 'navMode'];

/** EXE/PLN/INSTR/EVAL/OBS: segment index on ATM polyline; survives session GET aircraft replacement. */
let joinerAtmRouteProgressIdxById = null;
let joinerAtmRouteProgressLastRadarSecById = null;
let joinerAtmRouteProgressPointsById = null;

function ensureJoinerAtmRouteProgressMaps() {
    if (!joinerAtmRouteProgressIdxById) joinerAtmRouteProgressIdxById = new Map();
    if (!joinerAtmRouteProgressLastRadarSecById) joinerAtmRouteProgressLastRadarSecById = new Map();
    if (!joinerAtmRouteProgressPointsById) joinerAtmRouteProgressPointsById = new Map();
}

function clearJoinerAtmRouteProgressState() {
    joinerAtmRouteProgressIdxById = null;
    joinerAtmRouteProgressLastRadarSecById = null;
    joinerAtmRouteProgressPointsById = null;
}

function getJoinerAtmRouteProgressIdx(ac) {
    if (!ac || ac.id == null) return 0;
    ensureJoinerAtmRouteProgressMaps();
    const v = joinerAtmRouteProgressIdxById.get(String(ac.id));
    return Number.isFinite(v) ? Math.max(0, Math.trunc(v)) : 0;
}

function applyJoinerAtmRouteProgressToAircraft(ac, pts) {
    if (!ac) return;
    const ppts = pts || getJoinerAtmDisplayPoints(ac);
    const idx = getJoinerAtmRouteProgressIdx(ac);
    const capped = (Array.isArray(ppts) && ppts.length >= 2)
        ? Math.max(0, Math.min(ppts.length - 2, idx))
        : Math.max(0, idx);
    ac.routeProgressIdx = capped;
    ac.routeCompleted = !!(Array.isArray(ppts) && ppts.length >= 2 && capped >= ppts.length - 1);
}

function setJoinerAtmRouteProgressIdx(ac, idx, pts) {
    if (!ac || ac.id == null) return;
    ensureJoinerAtmRouteProgressMaps();
    const aid = String(ac.id);
    const ppts = pts || getJoinerAtmDisplayPoints(ac);
    const capped = (Array.isArray(ppts) && ppts.length >= 2)
        ? Math.max(0, Math.min(ppts.length - 2, Math.trunc(idx)))
        : Math.max(0, Math.trunc(idx));
    joinerAtmRouteProgressIdxById.set(aid, capped);
    if (Array.isArray(ppts) && ppts.length) {
        try {
            joinerAtmRouteProgressPointsById.set(aid, JSON.parse(JSON.stringify(ppts)));
        } catch (e) {}
    }
    applyJoinerAtmRouteProgressToAircraft(ac, ppts);
}

function joinerAtmRoutePointsMatch(a, b) {
    if (!Array.isArray(a) || !Array.isArray(b) || a.length !== b.length) return false;
    for (let i = 0; i < a.length; i++) {
        const p0 = a[i];
        const p1 = b[i];
        if (!p0 || !p1) return false;
        if (Math.round(Number(p0.lat) * 1e6) !== Math.round(Number(p1.lat) * 1e6)) return false;
        if (Math.round(Number(p0.lon) * 1e6) !== Math.round(Number(p1.lon) * 1e6)) return false;
    }
    return true;
}

/** @returns {'unchanged'|'extended'|'replace'} */
function detectJoinerAtmRoutePointsChange(prevPts, newPts) {
    if (!Array.isArray(newPts) || newPts.length < 1) return 'replace';
    if (!Array.isArray(prevPts) || !prevPts.length) return 'replace';
    if (joinerAtmRoutePointsMatch(prevPts, newPts)) return 'unchanged';
    if (newPts.length >= prevPts.length) {
        try {
            const prefix = JSON.parse(JSON.stringify(newPts.slice(0, prevPts.length)));
            if (joinerAtmRoutePointsMatch(prevPts, prefix)) return 'extended';
        } catch (e) {}
    }
    return 'replace';
}

function handleJoinerAtmRoutePointsChange(ac, pts) {
    if (!isJoinerAtmDisplayClient() || !ac || ac.id == null || !Array.isArray(pts)) return;
    ensureJoinerAtmRouteProgressMaps();
    const aid = String(ac.id);
    const prevPts = joinerAtmRouteProgressPointsById.get(aid);
    if (!prevPts) return;
    const kind = detectJoinerAtmRoutePointsChange(prevPts, pts);
    if (kind === 'unchanged') return;
    if (kind === 'extended') {
        setJoinerAtmRouteProgressIdx(ac, getJoinerAtmRouteProgressIdx(ac), pts);
        return;
    }
    joinerAtmRouteProgressLastRadarSecById.delete(aid);
    setJoinerAtmRouteProgressIdx(ac, 0, pts);
}

function resetJoinerAtmRouteProgressForAircraft(ac, idx) {
    if (!ac || ac.id == null) return;
    ensureJoinerAtmRouteProgressMaps();
    const aid = String(ac.id);
    joinerAtmRouteProgressLastRadarSecById.delete(aid);
    setJoinerAtmRouteProgressIdx(ac, idx != null ? idx : 0, getJoinerAtmDisplayPoints(ac));
}

/**
 * Shared pass / abeam progression (host FMS + joiner ATM display). Returns new segment index.
 */
function advanceRouteProgressIdxByPassAbeam(pts, idx, lat, lon, opts) {
    const o = opts && typeof opts === 'object' ? opts : {};
    const maxSteps = Number.isFinite(Number(o.maxSteps)) ? Number(o.maxSteps) : JOINER_ATM_ROUTE_PROGRESS_MAX_ADVANCE_PER_TICK;
    const passRadiusNm = Number.isFinite(Number(o.passRadiusNm)) ? Number(o.passRadiusNm) : ROUTE_PASS_RADIUS_NM;
    const abeamMaxNm = Number.isFinite(Number(o.abeamMaxNm)) ? Number(o.abeamMaxNm) : ROUTE_ABEAM_MAX_NM;
    if (!Array.isArray(pts) || pts.length < 2 || !isFinite(lat) || !isFinite(lon)) {
        return Math.max(0, parseInt(idx, 10) || 0);
    }
    let cur = Math.max(0, Math.min(pts.length - 2, parseInt(idx, 10) || 0));
    let guard = 0;
    while (cur < pts.length - 1 && guard < maxSteps) {
        const prev = pts[cur];
        const next = pts[cur + 1];
        if (!prev || !next || !isFinite(next.lat) || !isFinite(next.lon)) break;
        const dNext = calculateNauticalMiles(lat, lon, next.lat, next.lon);
        const directPass = isFinite(dNext) && dNext <= passRadiusNm;
        let abeamPass = false;
        if (!directPass && isFinite(dNext) && dNext <= abeamMaxNm && prev && isFinite(prev.lat) && isFinite(prev.lon)) {
            const dx = next.lon - prev.lon;
            const dy = next.lat - prev.lat;
            const ax = lon - next.lon;
            const ay = lat - next.lat;
            const dot = ax * dx + ay * dy;
            const legOk = (dx * dx + dy * dy) > 0;
            abeamPass = legOk && isFinite(dot) && dot > 0;
        }
        if (directPass || abeamPass) {
            cur += 1;
            guard += 1;
            continue;
        }
        break;
    }
    return cur;
}

/** Along-track NM on one segment only (forward-only; used with local joiner segment index). */
function computeTraveledNmAlongRouteOnSegmentFromPosition(pts, segIdx, lat, lon) {
    if (!Array.isArray(pts) || pts.length < 2 || !isFinite(lat) || !isFinite(lon)) return 0;
    const tmp = { points: pts, _trackCache: null };
    buildTrackCacheForAircraftPointsIfNeeded(tmp);
    const cache = tmp._trackCache;
    if (!cache || !Array.isArray(cache.cumNm) || !Array.isArray(cache.legsNm)) return 0;
    const idx = Math.max(0, Math.min(pts.length - 2, parseInt(segIdx, 10) || 0));
    const p0 = pts[idx];
    const p1 = pts[idx + 1];
    if (!p0 || !p1) return cache.cumNm[idx] || 0;
    const leg = cache.legsNm[idx] || 0;
    const segStart = cache.cumNm[idx] || 0;
    if (!(leg > 1e-9)) return segStart;
    const dlat = p1.lat - p0.lat;
    const dlon = p1.lon - p0.lon;
    const qlat = lat - p0.lat;
    const qlon = lon - p0.lon;
    const denom = dlat * dlat + dlon * dlon;
    const f = denom > 1e-18 ? Math.max(0, Math.min(1, (qlat * dlat + qlon * dlon) / denom)) : 0;
    return segStart + f * leg;
}

/** EXE/PLN ATM display polyline (not host FMS ac.points when lateral is locked). */
function getJoinerAtmDisplayPoints(ac) {
    if (!ac) return [];
    const p = ac._atmTrajectoryPatch;
    let pts = null;
    if (p && typeof p === 'object' && Array.isArray(p.points) && p.points.length) {
        pts = p.points;
    } else if (isJoinerAtmTrajectoryEditor() && joinerExeAircraftPatches) {
        const lp = joinerExeAircraftPatches[String(ac.id)];
        if (lp && Array.isArray(lp.points) && lp.points.length) pts = lp.points;
    }
    if (!pts || !pts.length) pts = ac.points;
    return Array.isArray(pts) ? pts : [];
}

/**
 * EXE/PLN: DCT to a fix truncates the ATM display polyline to that fix and all subsequent fixes (e.g. A-B-C-D → B-C-D).
 * Posted via ATM bucket so EXE and PLN stay aligned; independent of HOST/PP FMS route.
 */
function truncateJoinerAtmRouteForDirectTo(ac, srcPts, wpIdx, dctName) {
    if (!isJoinerAtmDisplayClient() || !ac || !Array.isArray(srcPts)) return null;
    const idx = parseInt(wpIdx, 10);
    if (!Number.isFinite(idx) || idx < 1 || idx >= srcPts.length) return null;
    let tail;
    try {
        tail = JSON.parse(JSON.stringify(srcPts.slice(idx)));
    } catch (e) {
        return null;
    }
    if (!tail.length) return null;
    const lat = (ac._displayLat != null && isFinite(ac._displayLat)) ? Number(ac._displayLat)
        : ((ac._joinerHeldDisplayLat != null && isFinite(ac._joinerHeldDisplayLat)) ? Number(ac._joinerHeldDisplayLat) : null);
    const lon = (ac._displayLon != null && isFinite(ac._displayLon)) ? Number(ac._displayLon)
        : ((ac._joinerHeldDisplayLon != null && isFinite(ac._joinerHeldDisplayLon)) ? Number(ac._joinerHeldDisplayLon) : null);
    const curName = (srcPts[0]?.name || '').toString().trim();
    const nextPts = (isFinite(lat) && isFinite(lon))
        ? [{ lat, lon, name: curName }, ...tail]
        : tail.slice();
    try {
        ac.points = JSON.parse(JSON.stringify(nextPts));
    } catch (e2) {
        ac.points = nextPts;
    }
    ac._trackCache = null;
    ac.routeNavTravelCacheN = null;
    if (ac.routeNavTraveledNmByUpdateSec instanceof Map) ac.routeNavTraveledNmByUpdateSec.clear();
    ac.routeCompleted = false;
    ac._atmLateralLocked = true;
    const nm = (dctName || (tail[0]?.name || '').toString().trim().toUpperCase() || `WP${idx}`).toString().trim().toUpperCase();
    ac.directToWpIdx = (isFinite(lat) && isFinite(lon) && nextPts.length >= 2) ? 1 : 0;
    ac.directToWpName = nm;
    ac.silentDirectToWpIdx = null;
    ac.silentDirectToTurnWpIdx = null;
    if (ac._atmTrajectoryPatch && typeof ac._atmTrajectoryPatch === 'object') {
        try {
            ac._atmTrajectoryPatch.points = JSON.parse(JSON.stringify(nextPts));
            ac._atmTrajectoryPatch.directToWpIdx = ac.directToWpIdx;
            ac._atmTrajectoryPatch.directToWpName = ac.directToWpName;
            ac._atmTrajectoryPatchSig = atmTrajectoryPatchSignature(ac._atmTrajectoryPatch);
        } catch (e3) {}
    }
    ensureJoinerAtmRouteProgressMaps();
    setJoinerAtmRouteProgressIdx(ac, 0, nextPts);
    delete ac._atmTrajDrawCache;
    clearAtmSectorSequenceCachesForAircraft(ac);
    return nextPts;
}

/**
 * Joiner DL: advance local ATM routeProgressIdx from host lat/lon only (pass/abeam on EXE polyline).
 * @param opts.forceAdvance When true, run pass/abeam even if radar sec unchanged (restart bootstrap).
 */
function syncJoinerAtmRouteProgressFromHostDisplay(ac, opts) {
    if (!isJoinerAtmDisplayClient() || !ac || ac.id == null) return;
    const o = opts && typeof opts === 'object' ? opts : {};
    const pts = getJoinerAtmDisplayPoints(ac);
    if (!Array.isArray(pts) || pts.length < 2) {
        applyJoinerAtmRouteProgressToAircraft(ac, pts);
        return;
    }
    handleJoinerAtmRoutePointsChange(ac, pts);
    const lat = (ac._displayLat != null && isFinite(ac._displayLat)) ? ac._displayLat : ac._joinerHeldDisplayLat;
    const lon = (ac._displayLon != null && isFinite(ac._displayLon)) ? ac._displayLon : ac._joinerHeldDisplayLon;
    const radarRaw = (ac._displayLastUpdateSimSec != null && isFinite(ac._displayLastUpdateSimSec))
        ? Number(ac._displayLastUpdateSimSec)
        : ((ac._joinerHeldDisplayLastUpdateSimSec != null && isFinite(ac._joinerHeldDisplayLastUpdateSimSec))
            ? Number(ac._joinerHeldDisplayLastUpdateSimSec)
            : null);
    ensureJoinerAtmRouteProgressMaps();
    const aid = String(ac.id);
    const hadIdx = joinerAtmRouteProgressIdxById.has(aid);
    if (!hadIdx) {
        setJoinerAtmRouteProgressIdx(ac, 0, pts);
    }
    if (!isFinite(lat) || !isFinite(lon)) {
        applyJoinerAtmRouteProgressToAircraft(ac, pts);
        return;
    }
    const lastRadar = joinerAtmRouteProgressLastRadarSecById.get(aid);
    const newRadarSample = radarRaw != null && lastRadar !== radarRaw;
    if (newRadarSample || o.forceAdvance) {
        if (radarRaw != null) joinerAtmRouteProgressLastRadarSecById.set(aid, radarRaw);
        const idx = advanceRouteProgressIdxByPassAbeam(pts, getJoinerAtmRouteProgressIdx(ac), lat, lon);
        setJoinerAtmRouteProgressIdx(ac, idx, pts);
    } else {
        applyJoinerAtmRouteProgressToAircraft(ac, pts);
    }
}

/**
 * Cumulative NM along pts[0]→…→pts[n-1] to the closest point on the polyline to (lat,lon) (planar segment projection; same family as host route sampling).
 */
function computeTraveledNmAlongRouteToClosestPoint(pts, lat, lon) {
    if (!Array.isArray(pts) || pts.length < 2 || !isFinite(lat) || !isFinite(lon)) return 0;
    let bestDistNm = Infinity;
    let bestAlongNm = 0;
    let cum = 0;
    for (let i = 0; i < pts.length - 1; i++) {
        const p0 = pts[i];
        const p1 = pts[i + 1];
        if (!p0 || !p1 || !isFinite(p0.lat) || !isFinite(p0.lon) || !isFinite(p1.lat) || !isFinite(p1.lon)) {
            continue;
        }
        const leg = calculateNauticalMiles(p0.lat, p0.lon, p1.lat, p1.lon);
        const legSafe = (isFinite(leg) && leg > 1e-9) ? leg : 0;
        let f = 0;
        if (legSafe > 1e-9) {
            const dlat = p1.lat - p0.lat;
            const dlon = p1.lon - p0.lon;
            const qlat = lat - p0.lat;
            const qlon = lon - p0.lon;
            const denom = dlat * dlat + dlon * dlon;
            f = denom > 1e-18 ? Math.max(0, Math.min(1, (qlat * dlat + qlon * dlon) / denom)) : 0;
        }
        const clat = p0.lat + f * (p1.lat - p0.lat);
        const clon = p0.lon + f * (p1.lon - p0.lon);
        const d = calculateNauticalMiles(lat, lon, clat, clon);
        const along = cum + f * legSafe;
        if (isFinite(d) && d < bestDistNm) {
            bestDistNm = d;
            bestAlongNm = along;
        }
        cum += legSafe;
    }
    return Math.max(0, isFinite(bestAlongNm) ? bestAlongNm : 0);
}

/**
 * Joiner ATM: align along-track distance with the display route (acSeq.points) when it differs from FMS geometry.
 * Host uses integrated traveledNm on ac.points; here we project radar position onto the ATM polyline for the same relationship.
 */
function getSectorSequenceStateForDisplayRoute(ac, acSeq, baseState) {
    if (!baseState) return baseState;
    if (isJoinerAtmDisplayClient() && acSeq && Array.isArray(acSeq.points) && acSeq.points.length >= 2) {
        const segIdx = getJoinerAtmRouteProgressIdx(ac);
        const tSeg = computeTraveledNmAlongRouteOnSegmentFromPosition(acSeq.points, segIdx, baseState.lat, baseState.lon);
        if (isFinite(tSeg)) return { ...baseState, traveledNm: tSeg };
        return baseState;
    }
    if (acSeq && acSeq.navMode === 'heading' && Array.isArray(acSeq.points) && acSeq.points.length >= 2) {
        return baseState;
    }
    if (!hasAtmTrajectoryPatchForSector(ac) || !acSeq) return baseState;
    const sigFms = getAircraftPointsGeometrySignature(ac);
    const sigAtm = getAircraftPointsGeometrySignature(acSeq);
    if (sigFms === sigAtm) return baseState;
    const pts = acSeq.points;
    if (!Array.isArray(pts) || pts.length < 2) return baseState;
    const tProj = computeTraveledNmAlongRouteToClosestPoint(pts, baseState.lat, baseState.lon);
    if (!isFinite(tProj)) return baseState;
    return { ...baseState, traveledNm: tProj };
}

/**
 * Estimated FL at a point along the remaining EXE route after `etaSeconds` flight time from now.
 * Uses Mode-C as start, then vertical motion toward ALV (assigned FL) and finally toward XFL (exitLevelFl / RLV).
 * When the sim publishes a significant ROC, that rate is preferred for the matching climb/descent direction.
 */
function estimateFlAtTrajectoryEta(ac, etaSeconds) {
    const T = Math.max(0, Number(etaSeconds) || 0);
    const mcFeet = Number(ac.publishedModeCFeet ?? ac.modeCFeet);
    let fl = Number.isFinite(mcFeet) ? Math.round(mcFeet / 100) : parseInt(ac.assignedFl ?? ac.alv, 10);
    if (!Number.isFinite(fl)) fl = 0;
    fl = Math.max(0, Math.min(500, fl));

    const alvN = parseInt(ac.assignedFl ?? ac.alv, 10);
    const flAlv = Number.isFinite(alvN) ? Math.max(0, Math.min(500, alvN)) : fl;
    const exitN = parseInt(ac.exitLevelFl ?? ac.rlv, 10);
    const flExit = Number.isFinite(exitN) ? Math.max(0, Math.min(500, exitN)) : flAlv;

    const { climb: cFpm, desc: dFpm } = getAircraftDbClimbDescNormalFpm(ac.aircraftType);
    const rocPub = Number(ac.publishedRocFpm ?? ac.rocFpm);
    const useLive = Number.isFinite(rocPub) && Math.abs(rocPub) > 25;

    function stepToward(from, to, tBudget) {
        if (tBudget <= 0 || Math.abs(from - to) < 0.01) return { fl: from, time: 0 };
        const needFt = (to - from) * 100;
        const climbing = needFt > 0;
        let fpm;
        if (useLive) {
            if ((climbing && rocPub > 0) || (!climbing && rocPub < 0)) fpm = Math.abs(rocPub);
            else fpm = climbing ? cFpm : dFpm;
        } else {
            fpm = climbing ? cFpm : dFpm;
        }
        if (!isFinite(fpm) || fpm <= 0) return { fl: from, time: 0 };
        const tNeed = Math.abs(needFt) / (fpm / 60);
        if (tNeed <= tBudget) {
            return { fl: to, time: tNeed };
        }
        const deltaFl = (climbing ? 1 : -1) * (fpm * tBudget) / 6000;
        return { fl: Math.max(0, Math.min(500, from + deltaFl)), time: tBudget };
    }

    let tRem = T;
    const s1 = stepToward(fl, flAlv, tRem);
    fl = s1.fl;
    tRem -= s1.time;
    if (tRem <= 0) return Math.round(fl);
    const s2 = stepToward(fl, flExit, tRem);
    fl = s2.fl;
    return Math.round(fl);
}

function buildSimulationAircraftTracks(simData) {
    const flights = simData?.flights || [];
    const waypoints = simData?.waypoints || [];
    const routes = simData?.routes || [];

    return flights.map((f, idx) => {
        const spawnTimeSec = parseInt(f?.spawnTime, 10);
        const spawn = Number.isFinite(spawnTimeSec) && spawnTimeSec >= 0 ? spawnTimeSec : 0;
        const { points: resolvedPts, error: routeErr } = computeExerciseRoutePoints(f?.route || '', waypoints, routes);
        if (routeErr) {
            try { console.warn('Exercise route:', routeErr, f?.callsign || ''); } catch (e) {}
        }
        const points = resolvedPts;
        // ALV = current level (Mode-C and initial Mode-S). PEL = assigned level (as if input; after delay Mode-S updates and climb starts), no TTS.
        const initialAlv = Number.isFinite(parseInt(f?.alv, 10)) ? parseInt(f?.alv, 10) : 0;
        const initialPel = Number.isFinite(parseInt(f?.pel, 10)) ? parseInt(f?.pel, 10) : initialAlv;
        const initialGs = computeGroundSpeedKt((f?.aircraftType || '').trim().toUpperCase(), initialAlv);
        const initialAltFeet = initialAlv * 100;
        const useDepartureProfile = !!f?.departureProfile;
        let initialKtas = (initialGs != null && isFinite(initialGs)) ? initialGs : 300;
        let initialPublishedGs = initialGs != null && isFinite(initialGs) ? Math.round(initialGs) : Math.round(initialKtas);
        if (useDepartureProfile) {
            const k160 = ktasFromKias(160, initialAltFeet);
            if (k160 != null && isFinite(k160)) {
                initialKtas = k160;
                initialPublishedGs = Math.round(k160);
            }
        }
        // Schedule Mode-S update to PEL after 3–5 sim seconds (same as ALV picker input), then climb will start
        const pendingFl = (initialPel !== initialAlv) ? initialPel : null;
        const pendingAtSimSec = (pendingFl != null) ? spawn + (3 + Math.random() * 2) : null;
        return {
            id: f?.id || `${idx}`,
            callsign: normalizeCallsign(f?.callsign || `AC${idx + 1}`),
            aircraftType: (f?.aircraftType || '').trim().toUpperCase(),
            destination: (f?.destination || '').trim().toUpperCase(),
            routeStr: (f?.route || '').toString().trim().toUpperCase(),
            alv: initialAlv,
            pel: initialPel,
            rlv: Number.isFinite(parseInt(f?.rlv, 10)) ? parseInt(f?.rlv, 10) : null,
            spawnTimeSec: spawn,
            points,
            labelOffsetX: 28,
            labelOffsetY: -28,
            // Runtime: start at ALV (Mode-C + Mode-S); assigned level = PEL; optional delayed Mode-S update to PEL then climb
            assignedFl: initialPel,
            modeSFl: initialAlv,
            modeCFeet: initialAlv * 100,
            publishedModeCFeet: initialAlv * 100,
            rocFpm: 0,
            publishedRocFpm: 0,
            rocTargetFpm: 0,
            rocRampStartSimSec: null,
            rocRampDurationSec: null,
            rocRampStartFpm: null,
            rocSelectedFpm: null,
            rocManualActive: false,
            rocReadoutMode: 'LIVE', // 'LIVE' | 'SELECTED'
            pendingModeSTargetFl: pendingFl,
            pendingModeSAtSimSec: pendingAtSimSec,
            lastPublishedRadarUpdateSimSec: null,
            // Runtime-only Exit Level override (for XLV picker); rlv remains the exercise default for physics/label fallback.
            exitLevelFl: null,
            // Runtime speed state (Mode-S speed)
            modeSTasKt: initialKtas,
            publishedModeSTasKt: initialKtas,
            publishedLabelGsKt: initialPublishedGs,
            departureProfileActive: useDepartureProfile,
            speedReadoutMode: 'IAS', // 'IAS' | 'MACH' | 'SELECTED'
            speedSelectedType: null, // 'IAS' | 'MACH'
            speedSelectedValue: null, // number
            speedChangeStartSimSec: null,
            speedChangeDurationSec: null,
            speedStartKtas: null,
            speedTargetKtas: null,
            // Runtime heading state (for DL heading commands)
            selectedHeadingDeg: null, // command/selected (HXXX)
            headingTurnTargetDeg: null,
            headingTurnStartSimSec: null,
            headingTurnRateDps: null,
            currentHeadingDeg: null,
            publishedHeadingDeg: null,
            // Destination runway + selected approach (runtime only)
            destRunwayId: null,
            destRunwayEnd: null, // 'A' | 'B'
            destRunwayEndName: null, // e.g. 34R
            selectedApproachId: null,
            selectedApproachName: null,
            approachActive: null,
            // Runtime lateral navigation state for heading commands (published on radar updates)
            navMode: 'heading', // 'route' | 'heading' (aircraft always flies turn-radius corners)
            headingNavLat: null,
            headingNavLon: null,
            headingNavLastUpdateSimSec: null,
            headingNavStatesByUpdateSec: null,
            // Route progression index for trajectory display (0 = between pts[0]->pts[1])
            // In heading-nav, this advances only when aircraft physically passes/abeam the NEXT waypoint.
            routeProgressIdx: 0,
            // Set when the aircraft has passed the final waypoint in its current trajectory.
            // When true and no manual guidance is active, we stop targeting the last point (prevents spinning).
            routeCompleted: false,
            // Direct-to (DCT) waypoint command (label shows waypoint name while active)
            directToWpIdx: null,
            directToWpName: null,
            // Runtime-only silent direct-to (guidance only; no label/TTS). Used for fly-by cornering.
            silentDirectToWpIdx: null,
            silentDirectToTurnWpIdx: null,
            holdingArm: null,
            holdingPattern: null
        };
    }).filter(a => Array.isArray(a.points) && a.points.length >= 1);
}

function validateFlightInputs(values, ignoreFlightId = null) {
    const callsign = normalizeCallsign(values.callsign);
    if (!callsign) return 'Callsign is required.';
    if (callsignHasSpaces(callsign)) return 'Callsign must not contain spaces.';
    if (!isCallsignUniqueInExercise(callsign, ignoreFlightId)) return `Callsign ${callsign} already exists in this exercise.`;

    const acType = (values.aircraftType || '').trim().toUpperCase();
    if (!acType) return 'Aircraft type is required.';
    if (!AIRCRAFT_DB[acType]) return 'Please select a valid aircraft type from the list.';

    const dep = (values.departure || '').trim().toUpperCase();
    const dest = (values.destination || '').trim().toUpperCase();
    if (!/^[A-Z0-9]{4}$/.test(dep)) return 'Departure must be 4 letters/numbers.';
    if (!/^[A-Z0-9]{4}$/.test(dest)) return 'Destination must be 4 letters/numbers.';

    const route = (values.route || '').trim();
    const segments = parseRouteSegments(route);
    if (!segments.length) return 'Route must contain at least one segment.';
    // allow free segments, but coordinates must match format if they contain '/'
    const badCoord = segments.find(s => s.includes('/') && !isValidCoordinateSegment(s));
    if (badCoord) return `Invalid coordinate segment: ${badCoord}`;

    const spawnTime = parseInt(values.spawnTime, 10);
    if (!Number.isFinite(spawnTime) || spawnTime < 0) return 'Spawn time must be a non-negative number (seconds).';
    const pel = parseInt(values.pel, 10);
    const alv = parseInt(values.alv, 10);
    const rlv = parseInt(values.rlv, 10);
    if (![pel, alv, rlv].every(n => Number.isFinite(n) && n >= 0)) return 'PEL/ALV/RLV must be non-negative numbers.';

    const sec = currentEditingSector;
    if (sec && Array.isArray(sec.waypoints) && Array.isArray(sec.routes)) {
        const { points, error } = computeExerciseRoutePoints(route, sec.waypoints, sec.routes);
        if (error) return error;
        if (!points.length) return 'Route must resolve to at least one track point.';
    }

    return null;
}

function setupAircraftTypeAutocomplete() {
    const input = document.getElementById('flightAircraftType');
    const list = document.getElementById('aircraftTypeSuggestions');
    const error = document.getElementById('aircraftTypeError');
    if (!input || !list) return;

    const render = (items) => {
        if (!items.length) {
            list.style.display = 'none';
            return;
        }
        list.innerHTML = items.map(t => `<div class="autocomplete-suggestion" data-type="${t}">${t}</div>`).join('');
        list.style.display = 'block';
        list.querySelectorAll('.autocomplete-suggestion').forEach(el => {
            el.addEventListener('mousedown', (e) => {
                e.preventDefault();
                const t = el.dataset.type;
                input.value = t;
                input.dataset.selectedType = t;
                list.style.display = 'none';
                if (error) error.style.display = 'none';
            });
        });
    };

    input.addEventListener('input', () => {
        const q = input.value.trim().toUpperCase();
        input.dataset.selectedType = '';
        if (error) error.style.display = 'none';
        if (!q) return render([]);
        const matches = AIRCRAFT_TYPES.filter(t => t.includes(q)).slice(0, 20);
        render(matches);
    });

    input.addEventListener('blur', () => {
        setTimeout(() => { list.style.display = 'none'; }, 100);
        const val = input.value.trim().toUpperCase();
        if (val && !AIRCRAFT_DB[val]) {
            if (error) error.style.display = 'block';
        }
    });
}

function getRouteSuggestionsForToken(token) {
    const t = (token || '').trim().toUpperCase();
    if (!t) return [];
    const suggestions = [];
    const sectorRoutes = currentEditingSector?.routes || [];
    sectorRoutes.forEach(r => {
        if (r?.name && r.name.toUpperCase().includes(t)) suggestions.push(r.name);
    });
    const sectorWpts = currentEditingSector?.waypoints || [];
    sectorWpts.forEach(wp => {
        if (wp?.name && wp.name.toUpperCase().includes(t)) suggestions.push(wp.name);
    });
    // de-dupe
    return Array.from(new Set(suggestions)).slice(0, 20);
}

function setupRouteAutocomplete() {
    const input = document.getElementById('flightRoute');
    const list = document.getElementById('flightRouteSuggestions');
    if (!input || !list) return;

    const render = (items) => {
        if (!items.length) {
            list.style.display = 'none';
            return;
        }
        list.innerHTML = items.map(v => `<div class="autocomplete-suggestion" data-value="${v}">${v}</div>`).join('');
        list.style.display = 'block';
        list.querySelectorAll('.autocomplete-suggestion').forEach(el => {
            el.addEventListener('mousedown', (e) => {
                e.preventDefault();
                const selected = el.dataset.value;
                const full = input.value;
                const lastSep = Math.max(full.lastIndexOf(' '), full.lastIndexOf(','));
                if (lastSep < 0) {
                    input.value = selected;
                } else {
                    let before = full.slice(0, lastSep + 1);
                    const ch = full.charAt(lastSep);
                    if (ch === ',' && !/\s$/.test(before)) before = `${before} `;
                    input.value = before + selected;
                }
                list.style.display = 'none';
            });
        });
    };

    input.addEventListener('input', () => {
        const full = input.value;
        const lastSep = Math.max(full.lastIndexOf(' '), full.lastIndexOf(','));
        const token = (lastSep >= 0 ? full.slice(lastSep + 1) : full).trim();
        const suggestions = getRouteSuggestionsForToken(token);
        render(suggestions);
    });

    input.addEventListener('blur', () => setTimeout(() => { list.style.display = 'none'; }, 100));
}

function getAirlineCallsignsSourceMap() {
    const src = window.AIRLINE_CALLSIGNS;
    return (src && typeof src === 'object') ? src : {};
}

function getAirlineCallsignsListFromDraft() {
    return Object.keys(airlinesDbDraft)
        .map(code => ({
            code: normalizeAirlineCode(code),
            callsign: normalizeAirlineCallsign(airlinesDbDraft[code])
        }))
        .filter(entry => entry.code && entry.callsign)
        .sort((a, b) => a.code.localeCompare(b.code));
}

function getAirlineCallsignsList() {
    return getAirlineCallsignsListFromDraft();
}

function normalizeAirlinesDbSearchQuery(raw) {
    return (raw || '').toString().trim().toUpperCase();
}

function getAirlinesDbSearchTerms(query) {
    const q = normalizeAirlinesDbSearchQuery(query);
    if (!q) return [];
    const terms = [q];
    const parts = q.split(/\s*[—\-]\s*/);
    if (parts[0]) terms.push(parts[0].trim());
    if (parts[1]) terms.push(parts[1].trim());
    return Array.from(new Set(terms.filter(Boolean)));
}

function airlineEntryMatchesSearch(entry, query) {
    const terms = getAirlinesDbSearchTerms(query);
    if (!terms.length) return true;
    const code = entry.code.toUpperCase();
    const callsign = entry.callsign.toUpperCase();
    const label = formatAirlineDbSearchLabel(entry).toUpperCase();
    return terms.some(term => code.includes(term) || callsign.includes(term) || label.includes(term));
}

function filterAirlineCallsignsList(query, limit = null) {
    const list = getAirlineCallsignsListFromDraft();
    const q = (query || '').toString().trim();
    if (!q) return limit ? list.slice(0, limit) : list;
    const filtered = list.filter(entry => airlineEntryMatchesSearch(entry, q));
    return limit ? filtered.slice(0, limit) : filtered;
}

function formatAirlineDbSearchLabel(entry) {
    return `${entry.code} — ${entry.callsign}`;
}

function validateAirlineDraftRowInput(codeRaw, callsignRaw, previousCode = '') {
    const code = normalizeAirlineCode(codeRaw);
    const callsign = normalizeAirlineCallsign(callsignRaw);
    const previous = normalizeAirlineCode(previousCode);
    if (!code) return 'Airline code is required.';
    if (!/^[A-Z0-9]{1,3}$/.test(code)) return 'Airline code must be 1–3 letters or digits.';
    if (!callsign) return 'Phraseology callsign is required.';
    if (code !== previous && Object.prototype.hasOwnProperty.call(airlinesDbDraft, code)) {
        return `Airline code ${code} already exists.`;
    }
    return '';
}

function renderAirlineDbRowHtml(entry) {
    const code = normalizeAirlineCode(entry.code);
    const callsign = normalizeAirlineCallsign(entry.callsign);
    const modified = isAirlineDraftRowModified(code);
    const editing = airlinesDbEditingCode === code;
    const rowClass = [
        modified ? 'airlines-db-row-modified' : '',
        editing ? 'airlines-db-row-editing' : ''
    ].filter(Boolean).join(' ');
    if (editing) {
        return (
            `<tr class="${rowClass}" data-code="${escapeHtml(code)}">`
            + `<td><input type="text" class="form-input airlines-db-row-input airlines-db-edit-code" value="${escapeHtml(code)}" maxlength="3" autocomplete="off"></td>`
            + `<td><input type="text" class="form-input airlines-db-row-input airlines-db-edit-callsign" value="${escapeHtml(callsign)}" autocomplete="off"></td>`
            + `<td><div class="airlines-db-row-actions">`
            + `<button type="button" class="btn btn-primary airlines-db-mini-btn airlines-db-row-apply-btn" data-code="${escapeHtml(code)}">Apply</button>`
            + `<button type="button" class="btn btn-tertiary airlines-db-mini-btn airlines-db-row-cancel-btn" data-code="${escapeHtml(code)}">Cancel</button>`
            + `</div></td></tr>`
        );
    }
    return (
        `<tr class="${rowClass}" data-code="${escapeHtml(code)}">`
        + `<td class="airlines-db-code">${escapeHtml(code)}</td>`
        + `<td>${escapeHtml(callsign)}</td>`
        + `<td><div class="airlines-db-row-actions">`
        + `<button type="button" class="btn btn-secondary airlines-db-mini-btn airlines-db-row-edit-btn" data-code="${escapeHtml(code)}">Edit</button>`
        + `<button type="button" class="btn btn-tertiary airlines-db-mini-btn airlines-db-row-reset-btn" data-code="${escapeHtml(code)}"${modified ? '' : ' disabled'}>Reset</button>`
        + `</div></td></tr>`
    );
}

function renderAirlinesDbList(query = '') {
    const tbody = document.getElementById('airlinesDbListBody');
    const summary = document.getElementById('airlinesDbListSummary');
    const total = getAirlineCallsignsListFromDraft().length;
    const rows = filterAirlineCallsignsList(query);
    if (tbody) {
        if (!rows.length) {
            tbody.innerHTML = '<tr><td class="airlines-db-empty" colspan="3">No airlines match your search.</td></tr>';
        } else {
            tbody.innerHTML = rows.map(entry => renderAirlineDbRowHtml(entry)).join('');
        }
    }
    if (summary) {
        const modifiedCount = Object.keys(airlinesDbDraft).filter(code => isAirlineDraftRowModified(code)).length;
        const dirtyNote = isAirlinesDbDirty() ? ' Unsaved changes.' : '';
        summary.textContent = query.trim()
            ? `Showing ${rows.length} of ${total} airline entries.${modifiedCount ? ` ${modifiedCount} modified.` : ''}${dirtyNote}`
            : `${total} airline entries.${modifiedCount ? ` ${modifiedCount} modified.` : ''} Hover a row to edit or reset.${dirtyNote}`;
    }
}

function renderAirlinesDbSearchSuggestions(query) {
    const list = document.getElementById('airlinesDbSearchSuggestions');
    if (!list) return;
    const q = (query || '').toString().trim();
    if (!q) {
        list.style.display = 'none';
        list.innerHTML = '';
        return;
    }
    const matches = filterAirlineCallsignsList(q, 20);
    if (!matches.length) {
        list.style.display = 'none';
        list.innerHTML = '';
        return;
    }
    list.innerHTML = matches.map(entry => {
        const label = formatAirlineDbSearchLabel(entry);
        return `<div class="autocomplete-suggestion" data-code="${escapeHtml(entry.code)}">${escapeHtml(label)}</div>`;
    }).join('');
    list.style.display = 'block';
    list.querySelectorAll('.autocomplete-suggestion').forEach(el => {
        el.addEventListener('mousedown', (e) => {
            e.preventDefault();
            const input = document.getElementById('airlinesDbSearchInput');
            const code = normalizeAirlineCode(el.dataset.code);
            const callsign = normalizeAirlineCallsign(airlinesDbDraft[code] || '');
            if (input) input.value = code && callsign ? formatAirlineDbSearchLabel({ code, callsign }) : code;
            list.style.display = 'none';
            renderAirlinesDbList(input?.value || '');
        });
    });
}

function setupAirlinesDbSearchAutocomplete() {
    const input = document.getElementById('airlinesDbSearchInput');
    const list = document.getElementById('airlinesDbSearchSuggestions');
    if (!input || !list || input.dataset.airlinesDbAutocompleteSetup === 'true') return;
    input.dataset.airlinesDbAutocompleteSetup = 'true';

    input.addEventListener('input', () => {
        renderAirlinesDbSearchSuggestions(input.value);
        renderAirlinesDbList(input.value);
    });

    input.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') list.style.display = 'none';
    });

    input.addEventListener('blur', () => {
        setTimeout(() => { list.style.display = 'none'; }, 120);
    });
}

function setupAirlinesDbTableActions() {
    const tbody = document.getElementById('airlinesDbListBody');
    if (!tbody || tbody.dataset.airlinesDbActionsSetup === 'true') return;
    tbody.dataset.airlinesDbActionsSetup = 'true';

    tbody.addEventListener('click', (e) => {
        const editBtn = e.target.closest('.airlines-db-row-edit-btn');
        const resetBtn = e.target.closest('.airlines-db-row-reset-btn');
        const applyBtn = e.target.closest('.airlines-db-row-apply-btn');
        const cancelBtn = e.target.closest('.airlines-db-row-cancel-btn');
        const searchQuery = document.getElementById('airlinesDbSearchInput')?.value || '';

        if (editBtn) {
            const code = normalizeAirlineCode(editBtn.dataset.code);
            if (!code) return;
            airlinesDbEditingCode = code;
            renderAirlinesDbList(searchQuery);
            const row = tbody.querySelector(`tr[data-code="${CSS.escape(code)}"]`);
            row?.querySelector('.airlines-db-edit-code')?.focus();
            return;
        }

        if (cancelBtn) {
            airlinesDbEditingCode = null;
            renderAirlinesDbList(searchQuery);
            return;
        }

        if (resetBtn && !resetBtn.disabled) {
            resetAirlineDraftRow(normalizeAirlineCode(resetBtn.dataset.code));
            renderAirlinesDbList(searchQuery);
            return;
        }

        if (applyBtn) {
            const previousCode = normalizeAirlineCode(applyBtn.dataset.code);
            const row = applyBtn.closest('tr');
            const nextCode = normalizeAirlineCode(row?.querySelector('.airlines-db-edit-code')?.value);
            const nextCallsign = normalizeAirlineCallsign(row?.querySelector('.airlines-db-edit-callsign')?.value);
            const err = validateAirlineDraftRowInput(nextCode, nextCallsign, previousCode);
            if (err) {
                alert(err);
                return;
            }
            applyAirlineDraftRowEdit(previousCode, nextCode, nextCallsign);
            airlinesDbEditingCode = null;
            renderAirlinesDbList(searchQuery);
        }
    });
}

function applyAirlineDraftRowEdit(previousCode, nextCode, nextCallsign) {
    const oldCode = normalizeAirlineCode(previousCode);
    const newCode = normalizeAirlineCode(nextCode);
    const callsign = normalizeAirlineCallsign(nextCallsign);
    const origin = normalizeAirlineCode(airlinesDbRowOrigins[oldCode] || oldCode);
    if (oldCode !== newCode) {
        delete airlinesDbDraft[oldCode];
        delete airlinesDbRowOrigins[oldCode];
    }
    airlinesDbDraft[newCode] = callsign;
    airlinesDbRowOrigins[newCode] = findDefaultAirlineKey(origin) ? origin : newCode;
}

function resetAirlineDraftRow(code) {
    const rowCode = normalizeAirlineCode(code);
    if (!rowCode) return;
    const origin = normalizeAirlineCode(airlinesDbRowOrigins[rowCode] || rowCode);
    const defKey = findDefaultAirlineKey(origin);
    delete airlinesDbDraft[rowCode];
    delete airlinesDbRowOrigins[rowCode];
    Object.keys(airlinesDbDraft).forEach((key) => {
        if (normalizeAirlineCode(airlinesDbRowOrigins[key] || key) === origin && key !== rowCode) {
            delete airlinesDbDraft[key];
            delete airlinesDbRowOrigins[key];
        }
    });
    if (defKey) {
        airlinesDbDraft[defKey] = normalizeAirlineCallsign(AIRLINE_CALLSIGNS_DEFAULT[defKey]);
        airlinesDbRowOrigins[defKey] = defKey;
    }
    if (airlinesDbEditingCode === rowCode) airlinesDbEditingCode = null;
}

function resetAirlinesDbDraftToDefaults() {
    airlinesDbDraft = { ...AIRLINE_CALLSIGNS_DEFAULT };
    rebuildAirlineDraftOriginsFromDraft();
    airlinesDbEditingCode = null;
}

function saveAirlinesDbDraft() {
    const payload = computeAirlineCallsignsPayloadFromDraft(airlinesDbDraft);
    saveAirlineCallsignsOverridesPayload(payload);
    airlineCallsignsOverridesPayload = payload;
    airlinesDbSavedPayload = cloneAirlineCallsignsPayload(payload);
    rebuildAirlineCallsignsEffective();
    cloneAirlinesDbDraftFromEffective();
    airlinesDbEditingCode = null;
}

function closeEditAirlinesDbModal(force = false) {
    if (!force && isAirlinesDbDirty()) {
        openModal('airlinesDbUnsavedConfirmModal');
        return;
    }
    airlinesDbEditingCode = null;
    closeModal('editAirlinesDbModal');
    closeModal('airlinesDbUnsavedConfirmModal');
}

function openEditAirlinesDbModal() {
    cloneAirlinesDbDraftFromEffective();
    airlinesDbSavedPayload = cloneAirlineCallsignsPayload(airlineCallsignsOverridesPayload);
    airlinesDbEditingCode = null;
    const input = document.getElementById('airlinesDbSearchInput');
    if (input) input.value = '';
    setupAirlinesDbSearchAutocomplete();
    setupAirlinesDbTableActions();
    renderAirlinesDbList('');
    renderAirlinesDbSearchSuggestions('');
    openModal('editAirlinesDbModal');
    setTimeout(() => input?.focus(), 50);
}

function openEditAircraftDbModal() {
    const text = document.getElementById('aircraftDbOverridesText');
    const summary = document.getElementById('aircraftDbOverridesSummary');
    const typeSelect = document.getElementById('aircraftDbTypeSelect');
    if (text) text.value = loadAircraftDbOverridesRaw();

    if (summary) {
        const n = Object.keys(AIRCRAFT_DB_OVERRIDES || {}).length;
        summary.textContent = n ? `Active overrides: ${n} aircraft type(s).` : 'Active overrides: none (using defaults).';
    }

    if (typeSelect) {
        const current = (typeSelect.value || '').trim().toUpperCase();
        typeSelect.innerHTML = '<option value="">-- Select Type --</option>' + AIRCRAFT_TYPES.map(t => `<option value="${t}">${t}</option>`).join('');
        if (current && AIRCRAFT_DB[current]) typeSelect.value = current;
    }

    openModal('editAircraftDbModal');
    setTimeout(() => text?.focus(), 50);
}

function setAircraftDbFormEnabled(enabled) {
    [
        'acCeilingFl',
        'acKiasLowMax', 'acKiasLowNorm', 'acKiasLowMin',
        'acKiasMidMax', 'acKiasMidNorm', 'acKiasMidMin',
        'acKiasHighMax', 'acKiasHighNorm', 'acKiasHighMin',
        'acClimbMaxFpm', 'acClimbNormalFpm',
        'acDescMaxFpm', 'acDescNormalFpm',
        'acMinMach', 'acNormalMach', 'acMaxMach'
    ].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.disabled = !enabled;
    });
    document.getElementById('updateSelectedAircraftOverrideBtn')?.toggleAttribute('disabled', !enabled);
    // remove override button state is set separately based on whether override exists
}

function fillAircraftDbFormFromRecord(rec) {
    const setVal = (id, v) => {
        const el = document.getElementById(id);
        if (el) el.value = (v ?? '') === null ? '' : String(v ?? '');
    };
    setVal('acCeilingFl', rec?.ceilingFl);
    setVal('acKiasLowMax', rec?.kias?.low?.max);
    setVal('acKiasLowNorm', rec?.kias?.low?.norm);
    setVal('acKiasLowMin', rec?.kias?.low?.min);
    setVal('acKiasMidMax', rec?.kias?.mid?.max);
    setVal('acKiasMidNorm', rec?.kias?.mid?.norm);
    setVal('acKiasMidMin', rec?.kias?.mid?.min);
    setVal('acKiasHighMax', rec?.kias?.high?.max);
    setVal('acKiasHighNorm', rec?.kias?.high?.norm);
    setVal('acKiasHighMin', rec?.kias?.high?.min);
    setVal('acClimbMaxFpm', rec?.climb?.maxFpm);
    setVal('acClimbNormalFpm', rec?.climb?.normalFpm);
    setVal('acDescMaxFpm', rec?.desc?.maxFpm);
    setVal('acDescNormalFpm', rec?.desc?.normalFpm);
    setVal('acMinMach', rec?.mach?.min);
    setVal('acNormalMach', rec?.mach?.normal);
    setVal('acMaxMach', rec?.mach?.max);
}

function readAircraftDbFormValues(type) {
    const getInt = (id) => {
        const v = document.getElementById(id)?.value;
        const n = parseInt(v, 10);
        return Number.isFinite(n) ? n : null;
    };
    const getFloat = (id) => {
        const v = document.getElementById(id)?.value;
        const n = parseFloat(v);
        return Number.isFinite(n) ? n : null;
    };
    return {
        type,
        ceilingFl: getInt('acCeilingFl'),
        kias: {
            low: { max: getInt('acKiasLowMax'), norm: getInt('acKiasLowNorm'), min: getInt('acKiasLowMin') },
            mid: { max: getInt('acKiasMidMax'), norm: getInt('acKiasMidNorm'), min: getInt('acKiasMidMin') },
            high: { max: getInt('acKiasHighMax'), norm: getInt('acKiasHighNorm'), min: getInt('acKiasHighMin') }
        },
        climb: { maxFpm: getInt('acClimbMaxFpm'), normalFpm: getInt('acClimbNormalFpm') },
        desc: { maxFpm: getInt('acDescMaxFpm'), normalFpm: getInt('acDescNormalFpm') },
        mach: { min: getFloat('acMinMach'), normal: getFloat('acNormalMach'), max: getFloat('acMaxMach') }
    };
}

function aircraftDbRecordToLine(rec) {
    if (!rec?.type) return '';
    const vals = [
        rec.type,
        rec.ceilingFl,
        rec.kias.low.max, rec.kias.low.norm, rec.kias.low.min,
        rec.kias.mid.max, rec.kias.mid.norm, rec.kias.mid.min,
        rec.kias.high.max, rec.kias.high.norm, rec.kias.high.min,
        rec.climb.maxFpm, rec.climb.normalFpm,
        rec.desc.maxFpm, rec.desc.normalFpm,
        rec.mach.min, rec.mach.normal, rec.mach.max
    ];
    return vals.map(v => String(v)).join(' ');
}

function parseOverridesRawToLineMap(raw) {
    const map = {};
    const lines = (raw || '').split('\n').map(l => l.trim()).filter(Boolean);
    lines.forEach(line => {
        const parts = line.split(/\s+/);
        if (parts.length !== 18) return;
        const type = (parts[0] || '').trim().toUpperCase();
        if (!type) return;
        map[type] = parts.join(' ');
    });
    return map;
}

function upsertOverrideLineRaw(raw, type, rec) {
    const map = parseOverridesRawToLineMap(raw);
    map[type] = aircraftDbRecordToLine(rec);
    return Object.keys(map).sort().map(k => map[k]).join('\n').trim();
}

function removeOverrideLineRaw(raw, type) {
    const map = parseOverridesRawToLineMap(raw);
    delete map[type];
    return Object.keys(map).sort().map(k => map[k]).join('\n').trim();
}

function updateAircraftDbEditorForSelectedType() {
    const type = document.getElementById('aircraftDbTypeSelect')?.value?.trim()?.toUpperCase() || '';
    const sourceEl = document.getElementById('aircraftDbTypeSource');
    const removeBtn = document.getElementById('removeSelectedAircraftOverrideBtn');

    if (!type || !AIRCRAFT_DB[type]) {
        setAircraftDbFormEnabled(false);
        if (sourceEl) sourceEl.textContent = 'Source: -';
        if (removeBtn) removeBtn.disabled = true;
        fillAircraftDbFormFromRecord(null);
        return;
    }

    setAircraftDbFormEnabled(true);
    const isOverride = !!AIRCRAFT_DB_OVERRIDES?.[type];
    if (sourceEl) sourceEl.textContent = `Source: ${isOverride ? 'override' : 'default'}`;
    if (removeBtn) removeBtn.disabled = !isOverride;
    fillAircraftDbFormFromRecord(AIRCRAFT_DB[type]);
}

function initExerciseEditorCanvas() {
    const canvas = document.getElementById('exerciseEditorCanvasElement');
    const container = document.getElementById('exerciseEditorCanvas');
    if (!canvas || !container) return;
    exerciseEditorCanvas = canvas;
    exerciseEditorCtx = canvas.getContext('2d');
    if (!exerciseEditorCtx) return;
    canvas.width = container.clientWidth;
    canvas.height = container.clientHeight;

    // Attach pan/zoom handlers once
    if (!canvas.dataset.panZoomInit) {
        canvas.dataset.panZoomInit = '1';

        canvas.addEventListener('contextmenu', (e) => {
            if (addFlightRoutePickActive) {
                e.preventDefault();
                e.stopPropagation();
                showAddFlightRoutePickContextMenu(e.clientX, e.clientY);
                return;
            }
            const rect = canvas.getBoundingClientRect();
            const clickX = e.clientX - rect.left;
            const clickY = e.clientY - rect.top;
            const callsignAircraftId = pickExercisePreviewCallsignAircraftIdAtCanvasXY(clickX, clickY);
            if (callsignAircraftId != null && currentEditingExerciseId) {
                e.preventDefault();
                e.stopPropagation();
                openExerciseAiPilotScriptModal(callsignAircraftId);
                return;
            }
            const previewFlightId = pickExercisePreviewAircraftIdAtCanvasXY(clickX, clickY);
            if (previewFlightId != null) {
                e.preventDefault();
                e.stopPropagation();
                openAddFlightModal(previewFlightId);
                return;
            }
            e.preventDefault();
        });

        canvas.addEventListener('mousedown', (e) => {
            const rect = canvas.getBoundingClientRect();
            const clickX = e.clientX - rect.left;
            const clickY = e.clientY - rect.top;
            const v = (simulationSettings?.labelMoveButton || SIM_SETTINGS_DEFAULTS.labelMoveButton || 'left').toString().toLowerCase();
            const labelMoveBtn = (v === 'middle') ? 1 : (v === 'right') ? 2 : 0;
            if (e.button === labelMoveBtn) {
                const reserved = e.button === 1 && (
                    pickExercisePreviewTrajectoryMarkerAtCanvasXY(clickX, clickY) != null ||
                    pickExercisePreviewCallsignAircraftIdAtCanvasXY(clickX, clickY) != null ||
                    pickExercisePreviewTrajectoryEstimateAircraftIdAtCanvasXY(clickX, clickY) != null
                );
                if (!reserved && tryStartExercisePreviewLabelDragAt(clickX, clickY)) {
                    e.preventDefault();
                    return;
                }
            }
            if (e.button === 0) {
                const markerPick = pickExercisePreviewScriptMarkerDragAtCanvasXY(clickX, clickY);
                if (markerPick != null) {
                    openExerciseAiPilotScriptModalForEdit(markerPick.scriptId, {
                        focusLblTin: markerPick.dragTarget === 'lblTin'
                    });
                    e.preventDefault();
                    return;
                }
            }
            if (e.button !== 0) return;
            exerciseEditorIsDragging = true;
            exerciseEditorDragStartX = e.clientX;
            exerciseEditorDragStartY = e.clientY;
            exerciseEditorDragStartPanX = exerciseEditorPanX;
            exerciseEditorDragStartPanY = exerciseEditorPanY;
        });

        window.addEventListener('mousemove', (e) => {
            if (exercisePreviewScriptDragActive && exerciseEditorCanvas && exercisePreviewScriptDragId != null) {
                const rect = exerciseEditorCanvas.getBoundingClientRect();
                const mx = e.clientX - rect.left;
                const my = e.clientY - rect.top;
                exercisePreviewScriptDragLastCanvasX = mx;
                exercisePreviewScriptDragLastCanvasY = my;
                hideExerciseScriptMarkerTooltip();
                if (exercisePreviewScriptDragRafId == null) {
                    exercisePreviewScriptDragRafId = requestAnimationFrame(() => {
                        exercisePreviewScriptDragRafId = null;
                        updateExerciseScriptMarkerDragFromCanvasXY(
                            exercisePreviewScriptDragId,
                            exercisePreviewScriptDragTarget,
                            exercisePreviewScriptDragLastCanvasX,
                            exercisePreviewScriptDragLastCanvasY
                        );
                        try { drawExerciseEditorCanvas(); } catch (err) {}
                    });
                }
                return;
            }
            if (exercisePreviewSpawnDragActive && exerciseEditorCanvas && exercisePreviewSpawnDragFlightId != null) {
                const rect = exerciseEditorCanvas.getBoundingClientRect();
                const mx = e.clientX - rect.left;
                const my = e.clientY - rect.top;
                exercisePreviewSpawnDragLastCanvasX = mx;
                exercisePreviewSpawnDragLastCanvasY = my;
                if (exercisePreviewSpawnDragRafId == null) {
                    exercisePreviewSpawnDragRafId = requestAnimationFrame(() => {
                        exercisePreviewSpawnDragRafId = null;
                        const lx = exercisePreviewSpawnDragLastCanvasX;
                        const ly = exercisePreviewSpawnDragLastCanvasY;
                        const slider = document.getElementById('exercisePreviewTimeSlider');
                        const previewSec = slider ? parseInt(slider.value, 10) : 0;
                        const flight = currentEditingFlights.find(f => f && String(f.id) === String(exercisePreviewSpawnDragFlightId));
                        const rawProj = flight ? exercisePreviewGetTargetTraveledNmForFlightAtCanvasXY(flight, lx, ly) : null;
                        const totalNm = flight ? exercisePreviewGetRouteTotalNmForFlight(flight) : null;
                        const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
                        const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
                        if (flight && rawProj != null && totalNm != null && Number.isFinite(previewSec) && previewSec > 0) {
                            const targetNm = Math.max(0, Math.min(totalNm, rawProj + exercisePreviewSpawnDragNmDelta));
                            exercisePreviewRefineSpawnTowardTargetNm(exercisePreviewSpawnDragFlightId, previewSec, targetNm, radarSec, 8);
                        }
                        try { drawExerciseEditorCanvas(); } catch (err) {}
                    });
                }
                return;
            }
            if (exercisePreviewIsDraggingLabel && exerciseEditorCanvas) {
                const rect = exerciseEditorCanvas.getBoundingClientRect();
                const mx = e.clientX - rect.left;
                const my = e.clientY - rect.top;
                const b = exercisePreviewAircraftLabelBounds.find(x => x && String(x.aircraftId) === String(exercisePreviewDraggingAircraftId));
                if (b) {
                    const newLabelX = mx - exercisePreviewLabelDragAnchorX;
                    const newLabelY = my - exercisePreviewLabelDragAnchorY;
                    const cx = newLabelX + b.w / 2;
                    const cy = newLabelY + b.h / 2;
                    const dx = cx - b.acX;
                    const dy = cy - b.acY;
                    exercisePreviewLabelOffsetsByAircraftId[b.aircraftId] = {
                        labelOffsetX: dx,
                        labelOffsetY: dy,
                        labelLeaderOffsetToCenter: true
                    };
                    if (exercisePreviewLabelDragDrawRafId == null) {
                        exercisePreviewLabelDragDrawRafId = requestAnimationFrame(() => {
                            exercisePreviewLabelDragDrawRafId = null;
                            drawExerciseEditorCanvas();
                        });
                    }
                }
                return;
            }
            if (exerciseEditorCanvas && document.getElementById('editExerciseModal')?.classList.contains('active')) {
                const rect = exerciseEditorCanvas.getBoundingClientRect();
                if (e.clientX >= rect.left && e.clientX <= rect.right && e.clientY >= rect.top && e.clientY <= rect.bottom) {
                    const mx = e.clientX - rect.left;
                    const my = e.clientY - rect.top;
                    const initialHovered = pickExercisePreviewInitialCallMarkerAtCanvasXY(mx, my);
                    const lblTinHovered = initialHovered ? null : pickExercisePreviewLblTinMarkerAtCanvasXY(mx, my);
                    const scriptHovered = (initialHovered || lblTinHovered) ? null : pickExercisePreviewScriptMarkerAtCanvasXY(mx, my);
                    if (initialHovered !== exercisePreviewInitialCallMarkerHoverId) {
                        exercisePreviewInitialCallMarkerHoverId = initialHovered;
                        try { drawExerciseEditorCanvas(); } catch (errIc) {}
                    }
                    if (lblTinHovered !== exercisePreviewLblTinMarkerHoverId) {
                        exercisePreviewLblTinMarkerHoverId = lblTinHovered;
                        try { drawExerciseEditorCanvas(); } catch (errLt) {}
                    }
                    if (scriptHovered !== exercisePreviewScriptMarkerHoverId) {
                        exercisePreviewScriptMarkerHoverId = scriptHovered;
                        try { drawExerciseEditorCanvas(); } catch (errSc) {}
                    }
                    if (initialHovered) {
                        const icScript = currentEditingAiPilotScripts.find(s => s && String(s.id) === String(initialHovered));
                        const tip = document.getElementById('exerciseScriptMarkerTooltip');
                        if (tip && icScript) {
                            const sectorName = getExerciseAtcSectorDisplayNameById(icScript.atcSectorId);
                            const callText = formatInitialPilotCallTtsForExercisePreviewDisplay(icScript.ttsMessage) || 'Initial call';
                            tip.textContent = sectorName && sectorName !== '—'
                                ? `${sectorName}: ${callText}`
                                : callText;
                            tip.hidden = false;
                            const container = document.getElementById('exerciseEditorCanvas');
                            if (container) {
                                const rct = container.getBoundingClientRect();
                                const pad = 12;
                                let left = e.clientX - rct.left + pad;
                                let top = e.clientY - rct.top + pad;
                                if (left > rct.width - 24) left = Math.max(4, e.clientX - rct.left - pad - 200);
                                if (top > rct.height - 24) top = Math.max(4, e.clientY - rct.top - pad - 40);
                                tip.style.left = `${left}px`;
                                tip.style.top = `${top}px`;
                            }
                        }
                    } else if (lblTinHovered) {
                        const ltScript = currentEditingAiPilotScripts.find(s => s && String(s.id) === String(lblTinHovered));
                        const tip = document.getElementById('exerciseScriptMarkerTooltip');
                        if (tip && ltScript) {
                            const sectorName = getExerciseAtcSectorDisplayNameById(ltScript.atcSectorId);
                            const cmd = ltScript.aiTransformedCommand || buildInitialCallLblTinTransformedCommand(ltScript.callsign, ltScript.lblTinOffsetSec);
                            const time = formatPreviewClockMMSS(getInitialCallLblTinPreviewTimeSec(ltScript));
                            tip.textContent = sectorName && sectorName !== '—'
                                ? `${sectorName}: ${cmd} @ ${time}`
                                : `${cmd} @ ${time}`;
                            tip.hidden = false;
                            const container = document.getElementById('exerciseEditorCanvas');
                            if (container) {
                                const rct = container.getBoundingClientRect();
                                const pad = 12;
                                let left = e.clientX - rct.left + pad;
                                let top = e.clientY - rct.top + pad;
                                if (left > rct.width - 24) left = Math.max(4, e.clientX - rct.left - pad - 200);
                                if (top > rct.height - 24) top = Math.max(4, e.clientY - rct.top - pad - 40);
                                tip.style.left = `${left}px`;
                                tip.style.top = `${top}px`;
                            }
                        }
                    } else if (scriptHovered) updateExerciseScriptMarkerTooltip(e.clientX, e.clientY, scriptHovered);
                    else hideExerciseScriptMarkerTooltip();
                } else if (exercisePreviewScriptMarkerHoverId != null || exercisePreviewInitialCallMarkerHoverId != null || exercisePreviewLblTinMarkerHoverId != null) {
                    exercisePreviewScriptMarkerHoverId = null;
                    exercisePreviewInitialCallMarkerHoverId = null;
                    exercisePreviewLblTinMarkerHoverId = null;
                    hideExerciseScriptMarkerTooltip();
                    try { drawExerciseEditorCanvas(); } catch (err2) {}
                }
            }
            if (!exerciseEditorIsDragging) return;
            const dx = e.clientX - exerciseEditorDragStartX;
            const dy = e.clientY - exerciseEditorDragStartY;
            exerciseEditorPanX = exerciseEditorDragStartPanX + dx;
            exerciseEditorPanY = exerciseEditorDragStartPanY + dy;
            drawExerciseEditorCanvas();
        });

        window.addEventListener('mouseup', () => {
            if (exercisePreviewScriptDragActive) {
                if (exercisePreviewScriptDragRafId != null) {
                    cancelAnimationFrame(exercisePreviewScriptDragRafId);
                    exercisePreviewScriptDragRafId = null;
                }
                updateExerciseScriptMarkerDragFromCanvasXY(
                    exercisePreviewScriptDragId,
                    exercisePreviewScriptDragTarget,
                    exercisePreviewScriptDragLastCanvasX,
                    exercisePreviewScriptDragLastCanvasY
                );
                exercisePreviewScriptDragActive = false;
                exercisePreviewScriptDragId = null;
                exercisePreviewScriptDragTarget = null;
                persistCurrentEditingAiPilotScripts();
                renderExerciseScriptsList();
                try { drawExerciseEditorCanvas(); } catch (err) {}
                return;
            }
            if (exercisePreviewSpawnDragActive) {
                if (exercisePreviewSpawnDragRafId != null) {
                    cancelAnimationFrame(exercisePreviewSpawnDragRafId);
                    exercisePreviewSpawnDragRafId = null;
                }
                const fid = exercisePreviewSpawnDragFlightId;
                exercisePreviewSpawnDragActive = false;
                exercisePreviewSpawnDragFlightId = null;
                if (fid != null) {
                    const mx = exercisePreviewSpawnDragLastCanvasX;
                    const my = exercisePreviewSpawnDragLastCanvasY;
                    const slider = document.getElementById('exercisePreviewTimeSlider');
                    const previewSec = slider ? parseInt(slider.value, 10) : 0;
                    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
                    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
                    const idx = currentEditingFlights.findIndex(f => f && String(f.id) === String(fid));
                    if (idx !== -1 && Number.isFinite(previewSec) && previewSec > 0) {
                        const flightRow = currentEditingFlights[idx];
                        const rawProj = exercisePreviewGetTargetTraveledNmForFlightAtCanvasXY(flightRow, mx, my);
                        const totalNm = exercisePreviewGetRouteTotalNmForFlight(flightRow);
                        if (rawProj != null && totalNm != null) {
                            const tgt = Math.max(0, Math.min(totalNm, rawProj + exercisePreviewSpawnDragNmDelta));
                            const refined = solveExercisePreviewSpawnForTraveledNm(flightRow, previewSec, tgt, radarSec);
                            currentEditingFlights[idx] = { ...flightRow, spawnTime: refined };
                            invalidateExercisePreviewTracksAndDerivedCaches();
                        }
                    }
                    try { renderExerciseFlightsList(); } catch (err) {}
                    if (fid != null && exercisePreviewTrajectoryOverlayHasAircraftId(fid)) {
                        try { syncExerciseInitialCallScriptsForAircraft(fid); } catch (errSync) {}
                    }
                    try { drawExerciseEditorCanvas(); } catch (err2) {}
                }
                return;
            }
            if (exercisePreviewIsDraggingLabel) {
                if (exercisePreviewLabelDragDrawRafId != null) {
                    cancelAnimationFrame(exercisePreviewLabelDragDrawRafId);
                    exercisePreviewLabelDragDrawRafId = null;
                }
                exercisePreviewIsDraggingLabel = false;
                exercisePreviewDraggingAircraftId = null;
                try { drawExerciseEditorCanvas(); } catch (e) {}
                return;
            }
            exerciseEditorIsDragging = false;
        });

        canvas.addEventListener('mouseleave', () => {
            exerciseEditorIsDragging = false;
            exercisePreviewScriptMarkerHoverId = null;
            exercisePreviewInitialCallMarkerHoverId = null;
            hideExerciseScriptMarkerTooltip();
            try { drawExerciseEditorCanvas(); } catch (e) {}
        });

        canvas.addEventListener('wheel', (e) => {
            if (!exerciseEditorCanvas) return;
            e.preventDefault();

            const rect = exerciseEditorCanvas.getBoundingClientRect();
            const mx = e.clientX - rect.left;
            const my = e.clientY - rect.top;

            const oldZoom = exerciseEditorZoom;
            const originX = exerciseEditorCanvas.width / 2 + exerciseEditorPanX;
            const originY = exerciseEditorCanvas.height / 2 + exerciseEditorPanY;
            const lonScaleWheel = getExerciseEditorLonCosScale(currentEditingSector?.waypoints || []);

            // World coords under mouse (relative lon/lat; lon scaled like Edit Airspace)
            const relLon = (mx - originX) / (oldZoom * lonScaleWheel);
            const relLat = (originY - my) / oldZoom;

            // Smooth zoom
            const factor = Math.pow(1.0015, -e.deltaY);
            const newZoom = Math.max(0.05, Math.min(20000, oldZoom * factor));
            exerciseEditorZoom = newZoom;

            // Adjust pan so the same world point stays under cursor
            const newOriginX = mx - relLon * newZoom * lonScaleWheel;
            const newOriginY = my + relLat * newZoom;
            exerciseEditorPanX = newOriginX - exerciseEditorCanvas.width / 2;
            exerciseEditorPanY = newOriginY - exerciseEditorCanvas.height / 2;

            drawExerciseEditorCanvas();
        }, { passive: false });
    }

    if (!canvas.dataset.exerciseEditorRoutePickInit) {
        canvas.dataset.exerciseEditorRoutePickInit = '1';
        canvas.addEventListener('mousedown', exerciseEditorRoutePickMouseDownCapture, true);
        canvas.addEventListener('mousemove', exerciseEditorCanvasMouseMoveRoutePickHover);
        canvas.addEventListener('auxclick', (e) => {
            if ((addFlightRoutePickActive || addFlowPickActive || flowRepositionPickActive) && e.button === 1) e.preventDefault();
        });
    }
}

function autoFitExerciseEditorZoom() {
    if (!exerciseEditorCanvas || !exerciseEditorCtx || !currentEditingSector) return;
    const wpts = (currentEditingSector.waypoints || []).filter(wp => wp && isFinite(wp.latitude) && isFinite(wp.longitude));
    if (!wpts.length) {
        exerciseEditorZoom = 1.0;
        exerciseEditorPanX = 0;
        exerciseEditorPanY = 0;
        return;
    }
    const centre = wpts.find(wp => isCenterWaypointName(wp?.name));
    let minRelLat = Infinity, maxRelLat = -Infinity;
    let minRelLon = Infinity, maxRelLon = -Infinity;
    wpts.forEach(wp => {
        const relLat = centre ? (wp.latitude - centre.latitude) : wp.latitude;
        const relLon = centre ? (wp.longitude - centre.longitude) : wp.longitude;
        minRelLat = Math.min(minRelLat, relLat);
        maxRelLat = Math.max(maxRelLat, relLat);
        minRelLon = Math.min(minRelLon, relLon);
        maxRelLon = Math.max(maxRelLon, relLon);
    });
    const airportsFit = Array.isArray(currentEditingSector.airports) ? currentEditingSector.airports : [];
    airportsFit.forEach(ap => {
        if (!ap) return;
        const arpLat = Number(ap.arpLat);
        const arpLon = Number(ap.arpLon);
        if (isFinite(arpLat) && isFinite(arpLon)) {
            const relLat = centre ? (arpLat - centre.latitude) : arpLat;
            const relLon = centre ? (arpLon - centre.longitude) : arpLon;
            minRelLat = Math.min(minRelLat, relLat);
            maxRelLat = Math.max(maxRelLat, relLat);
            minRelLon = Math.min(minRelLon, relLon);
            maxRelLon = Math.max(maxRelLon, relLon);
        }
        (Array.isArray(ap.runways) ? ap.runways : []).forEach(rw => {
            [rw?.endA, rw?.endB].forEach(end => {
                const lat = Number(end?.lat);
                const lon = Number(end?.lon);
                if (!isFinite(lat) || !isFinite(lon)) return;
                const relLat = centre ? (lat - centre.latitude) : lat;
                const relLon = centre ? (lon - centre.longitude) : lon;
                minRelLat = Math.min(minRelLat, relLat);
                maxRelLat = Math.max(maxRelLat, relLat);
                minRelLon = Math.min(minRelLon, relLon);
                maxRelLon = Math.max(maxRelLon, relLon);
            });
        });
    });
    const lonScale = getExerciseEditorLonCosScale(wpts);
    const padding = 40;
    const latRange = Math.max(maxRelLat - minRelLat, 0.01);
    const lonRange = Math.max((maxRelLon - minRelLon) * lonScale, 0.01);
    const zoomX = (exerciseEditorCanvas.width - padding * 2) / lonRange;
    const zoomY = (exerciseEditorCanvas.height - padding * 2) / latRange;
    exerciseEditorZoom = Math.max(0.1, Math.min(10000, Math.min(zoomX, zoomY)));
    // center at center waypoint/origin
    exerciseEditorPanX = 0;
    exerciseEditorPanY = 0;
}

function exerciseEditorGetPickTransform() {
    if (!exerciseEditorCanvas || !currentEditingSector) return null;
    const waypoints = currentEditingSector.waypoints || [];
    const centre = waypoints.find(wp => isCenterWaypointName(wp?.name));
    const lonScale = getExerciseEditorLonCosScale(waypoints);
    const originX = exerciseEditorCanvas.width / 2 + exerciseEditorPanX;
    const originY = exerciseEditorCanvas.height / 2 + exerciseEditorPanY;
    return { centre, lonScale, originX, originY, zoom: exerciseEditorZoom };
}

function exerciseEditorCanvasXYToLatLon(canvasX, canvasY) {
    const t = exerciseEditorGetPickTransform();
    if (!t) return null;
    const { centre, lonScale, originX, originY, zoom } = t;
    const relLon = (canvasX - originX) / (zoom * lonScale);
    const relLat = (originY - canvasY) / zoom;
    const lat = centre ? relLat + centre.latitude : relLat;
    const lon = centre ? relLon + centre.longitude : relLon;
    if (!isFinite(lat) || !isFinite(lon)) return null;
    return { lat, lon };
}

function exerciseEditorLatLonToCanvasXY(lat, lon) {
    const t = exerciseEditorGetPickTransform();
    if (!t || !isFinite(lat) || !isFinite(lon)) return null;
    const { centre, lonScale, originX, originY, zoom } = t;
    const relLat = centre ? lat - centre.latitude : lat;
    const relLon = centre ? lon - centre.longitude : lon;
    const x = originX + relLon * zoom * lonScale;
    const y = originY - relLat * zoom;
    if (!isFinite(x) || !isFinite(y)) return null;
    return { x, y };
}

function findExerciseEditorWaypointAtCanvas(canvasX, canvasY, thresholdPx) {
    const waypoints = currentEditingSector?.waypoints || [];
    let best = null;
    let bestD = Infinity;
    for (const wp of waypoints) {
        if (!wp || !isFinite(wp.latitude) || !isFinite(wp.longitude)) continue;
        const p = exerciseEditorLatLonToCanvasXY(wp.latitude, wp.longitude);
        if (!p) continue;
        const d = (p.x - canvasX) ** 2 + (p.y - canvasY) ** 2;
        if (d < bestD && d <= thresholdPx * thresholdPx) {
            bestD = d;
            best = wp;
        }
    }
    return best;
}

function findExerciseEditorRouteIdsNearCanvas(canvasX, canvasY, thresholdPx) {
    const out = [];
    const thrSq = thresholdPx * thresholdPx;
    const routes = currentEditingSector?.routes || [];
    const waypoints = currentEditingSector?.waypoints || [];
    routes.forEach(route => {
        if (!route?.id || !route.waypointIds || route.waypointIds.length < 2) return;
        const pts = [];
        for (const wid of route.waypointIds) {
            const w = waypoints.find(wp => wp && wp.id === wid);
            if (w && isFinite(w.latitude) && isFinite(w.longitude)) {
                const xy = exerciseEditorLatLonToCanvasXY(w.latitude, w.longitude);
                if (xy) pts.push(xy);
            }
        }
        if (pts.length < 2) return;
        for (let i = 0; i < pts.length - 1; i++) {
            if (distanceSquaredPointToSegment(canvasX, canvasY, pts[i].x, pts[i].y, pts[i + 1].x, pts[i + 1].y) <= thrSq) {
                out.push(route.id);
                return;
            }
        }
    });
    return out;
}

function coordinateTokenFromLatLon(lat, lon) {
    const la = formatDMS(decimalToDMS(lat, true), true);
    const lo = formatDMS(decimalToDMS(lon, false), false);
    return `${la}/${lo}`;
}

function addFlightRoutePickEntriesToRouteString() {
    return addFlightRoutePickSequence.map(e => {
        if (e.kind === 'wp') return e.name;
        if (e.kind === 'coord') return e.token;
        if (e.kind === 'route') return e.name;
        return '';
    }).filter(Boolean).join(' ');
}

function hideExerciseEditorRouteDisambigPanel() {
    addFlightRoutePickDisambigRouteIds = [];
    const panel = document.getElementById('exerciseEditorRouteDisambigPanel');
    if (panel) {
        panel.style.display = 'none';
        panel.innerHTML = '';
    }
}

function showExerciseEditorRouteDisambigPanel(routeIds, clientX, clientY) {
    hideExerciseEditorRouteDisambigPanel();
    addFlightRoutePickDisambigRouteIds = routeIds.slice();
    const panel = document.getElementById('exerciseEditorRouteDisambigPanel');
    if (!panel) return;
    const routes = currentEditingSector?.routes || [];
    routeIds.forEach(rid => {
        const route = routes.find(r => r && r.id === rid);
        const name = route?.name ? String(route.name) : String(rid);
        const box = document.createElement('button');
        box.type = 'button';
        box.className = 'sector-map-delete-route-disambig-item';
        box.textContent = name;
        box.addEventListener('click', (ev) => {
            ev.preventDefault();
            ev.stopPropagation();
            hideExerciseEditorRouteDisambigPanel();
            handleExerciseEditorAddFlightRouteLinePick(rid);
        });
        panel.appendChild(box);
    });
    panel.style.display = 'flex';
    panel.style.flexDirection = 'column';
    const place = () => {
        const w = panel.offsetWidth || 200;
        const h = panel.offsetHeight || 120;
        panel.style.left = `${Math.max(8, Math.min(clientX + 8, window.innerWidth - w - 8))}px`;
        panel.style.top = `${Math.max(8, Math.min(clientY + 8, window.innerHeight - h - 8))}px`;
    };
    place();
    requestAnimationFrame(place);
}

function hideAddFlightRoutePickContextMenu() {
    const m = document.getElementById('addFlightRoutePickContextMenu');
    if (m) m.style.display = 'none';
}

function showAddFlightRoutePickContextMenu(clientX, clientY) {
    const m = document.getElementById('addFlightRoutePickContextMenu');
    if (!m) return;
    m.style.display = 'block';
    const place = () => {
        const w = m.offsetWidth || 160;
        const h = m.offsetHeight || 80;
        m.style.left = `${Math.max(8, Math.min(clientX + 4, window.innerWidth - w - 8))}px`;
        m.style.top = `${Math.max(8, Math.min(clientY + 4, window.innerHeight - h - 8))}px`;
    };
    place();
    requestAnimationFrame(place);
}

function addFlightRoutePickWaypointOnRoute(route, wpId) {
    return !!(route?.waypointIds && route.waypointIds.includes(wpId));
}

function clearExerciseEditorAddFlightRoutePickPending() {
    addFlightRoutePickPendingRoute = null;
}

function handleExerciseEditorAddFlightRouteLinePick(routeId) {
    const routes = currentEditingSector?.routes || [];
    const route = routes.find(r => r && r.id === routeId);
    if (!route) return;

    if (addFlightRoutePickPendingRoute && addFlightRoutePickPendingRoute.routeId === routeId) {
        clearExerciseEditorAddFlightRoutePickPending();
        try { drawExerciseEditorCanvas(); } catch (e) {}
        return;
    }

    if (addFlightRoutePickTryRemoveRouteFromSequence(routeId)) {
        clearExerciseEditorAddFlightRoutePickPending();
        try { drawExerciseEditorCanvas(); } catch (e) {}
        return;
    }

    const last = addFlightRoutePickSequence[addFlightRoutePickSequence.length - 1];
    if (!last || last.kind !== 'wp') {
        alert('Select first a waypoint on this route');
        return;
    }
    if (!addFlightRoutePickWaypointOnRoute(route, last.id)) {
        alert('Select first a waypoint on this route');
        return;
    }
    addFlightRoutePickPendingRoute = {
        routeId: route.id,
        routeName: (route.name || '').toString(),
        fromWpId: last.id
    };
    try { drawExerciseEditorCanvas(); } catch (e) {}
}

function addFlightRoutePickTryRemoveRouteFromSequence(routeId) {
    for (let i = addFlightRoutePickSequence.length - 1; i >= 0; i--) {
        const e = addFlightRoutePickSequence[i];
        if (e.kind === 'route' && e.routeId === routeId) {
            const toId = e.toWpId;
            addFlightRoutePickSequence.splice(i, 1);
            if (i < addFlightRoutePickSequence.length && addFlightRoutePickSequence[i]?.kind === 'wp' && addFlightRoutePickSequence[i].id === toId) {
                addFlightRoutePickSequence.splice(i, 1);
            }
            return true;
        }
    }
    return false;
}

function commitExerciseEditorAddFlightRouteEndpoint(wp) {
    const pr = addFlightRoutePickPendingRoute;
    if (!pr || !wp) return;
    const routes = currentEditingSector?.routes || [];
    const route = routes.find(r => r && r.id === pr.routeId);
    if (!route || !addFlightRoutePickWaypointOnRoute(route, wp.id)) {
        alert('You first need to select an endpoint on this route');
        return;
    }
    if (wp.id === pr.fromWpId) {
        alert('You first need to select an endpoint for the existing route');
        return;
    }
    addFlightRoutePickSequence.push({
        kind: 'route',
        routeId: route.id,
        name: (route.name || '').toString().trim(),
        fromWpId: pr.fromWpId,
        toWpId: wp.id
    });
    addFlightRoutePickSequence.push({ kind: 'wp', id: wp.id, name: (wp.name || '').trim() });
    clearExerciseEditorAddFlightRoutePickPending();
    try { drawExerciseEditorCanvas(); } catch (e) {}
}

function addFlightRoutePickOnMiddleClickWaypoint(wp) {
    if (addFlightRoutePickPendingRoute) {
        commitExerciseEditorAddFlightRouteEndpoint(wp);
        return;
    }
    const last = addFlightRoutePickSequence[addFlightRoutePickSequence.length - 1];
    if (last && last.kind === 'wp' && last.id === wp.id) {
        addFlightRoutePickSequence.pop();
        const L = addFlightRoutePickSequence[addFlightRoutePickSequence.length - 1];
        if (L && L.kind === 'route' && (L.toWpId === wp.id || L.fromWpId === wp.id)) {
            addFlightRoutePickSequence.pop();
        }
        clearExerciseEditorAddFlightRoutePickPending();
        try { drawExerciseEditorCanvas(); } catch (e) {}
        return;
    }
    addFlightRoutePickSequence.push({ kind: 'wp', id: wp.id, name: (wp.name || '').trim() });
    try { drawExerciseEditorCanvas(); } catch (e) {}
}

function addFlightRoutePickOnMiddleClickCoordinate(lat, lon) {
    if (addFlightRoutePickPendingRoute) {
        alert('You first need to select an endpoint for the existing route');
        return;
    }
    const token = coordinateTokenFromLatLon(lat, lon);
    const last = addFlightRoutePickSequence[addFlightRoutePickSequence.length - 1];
    if (last && last.kind === 'coord' && last.token === token) {
        addFlightRoutePickSequence.pop();
        try { drawExerciseEditorCanvas(); } catch (e) {}
        return;
    }
    addFlightRoutePickSequence.push({ kind: 'coord', token, lat, lon });
    try { drawExerciseEditorCanvas(); } catch (e) {}
}

function exerciseEditorRoutePickMouseDownCapture(e) {
    if (e.button === 1 && exerciseEditorCanvas && e.target === exerciseEditorCanvas
        && document.getElementById('editExerciseModal')?.classList.contains('active')
        && !addFlightRoutePickActive && !addFlowPickActive && !flowRepositionPickActive) {
        const rect = exerciseEditorCanvas.getBoundingClientRect();
        const mx = e.clientX - rect.left;
        const my = e.clientY - rect.top;
        const scriptMarkerDrag = pickExercisePreviewScriptMarkerDragAtCanvasXY(mx, my);
        if (scriptMarkerDrag != null && tryStartExercisePreviewScriptDragAt(scriptMarkerDrag.scriptId, scriptMarkerDrag.dragTarget, mx, my)) {
            e.preventDefault();
            e.stopPropagation();
            return;
        }
        const trajEstId = pickExercisePreviewTrajectoryEstimateAircraftIdAtCanvasXY(mx, my);
        if (trajEstId != null) {
            toggleExercisePreviewTrajectoryForAircraftId(trajEstId, { forceOff: true });
            try { drawExerciseEditorCanvas(); } catch (err) {}
            e.preventDefault();
            e.stopPropagation();
            return;
        }
        const csId = pickExercisePreviewCallsignAircraftIdAtCanvasXY(mx, my);
        if (csId != null) {
            toggleExercisePreviewTrajectoryForAircraftId(csId);
            try { drawExerciseEditorCanvas(); } catch (err) {}
            e.preventDefault();
            e.stopPropagation();
            return;
        }
        if (!exercisePreviewMiddleClickHitsLabelBounds(mx, my)) {
            const aid = pickExercisePreviewAircraftIdAtCanvasXY(mx, my);
            if (aid != null && tryStartExercisePreviewSpawnDragAt(aid, mx, my)) {
                e.preventDefault();
                e.stopPropagation();
                return;
            }
        }
    }
    if (addFlowPickActive && exerciseEditorCanvas && e.target === exerciseEditorCanvas) {
        if (!document.getElementById('editExerciseModal')?.classList.contains('active')) {
            cancelAddFlowPickMode();
            return;
        }
        if (document.getElementById('addFlowDetailsModal')?.classList.contains('active')) {
            return;
        }
        if (e.button !== 1) return;
        e.preventDefault();
        e.stopPropagation();
        const rect = exerciseEditorCanvas.getBoundingClientRect();
        const mx = e.clientX - rect.left;
        const my = e.clientY - rect.top;
        const wpHit = findExerciseEditorWaypointAtCanvas(mx, my, 14);
        let lat;
        let lon;
        if (wpHit) {
            lat = wpHit.latitude;
            lon = wpHit.longitude;
        } else {
            const ll = exerciseEditorCanvasXYToLatLon(mx, my);
            if (!ll) return;
            lat = ll.lat;
            lon = ll.lon;
        }
        openAddFlowDetailsModal(lat, lon);
        return;
    }
    if (flowRepositionPickActive && exerciseEditorCanvas && e.target === exerciseEditorCanvas) {
        if (!document.getElementById('editExerciseModal')?.classList.contains('active')) {
            cancelFlowRepositionPick();
            return;
        }
        if (e.button !== 1) return;
        e.preventDefault();
        e.stopPropagation();
        const rect = exerciseEditorCanvas.getBoundingClientRect();
        const mx = e.clientX - rect.left;
        const my = e.clientY - rect.top;
        const wpHit = findExerciseEditorWaypointAtCanvas(mx, my, 14);
        let lat;
        let lon;
        if (wpHit) {
            lat = wpHit.latitude;
            lon = wpHit.longitude;
        } else {
            const ll = exerciseEditorCanvasXYToLatLon(mx, my);
            if (!ll) return;
            lat = ll.lat;
            lon = ll.lon;
        }
        const rid = flowRepositionTargetFlowId;
        if (!rid || !currentEditingSectorId) {
            cancelFlowRepositionPick();
            return;
        }
        const idx = currentEditingFlows.findIndex(f => f && f.id === rid);
        if (idx === -1) {
            cancelFlowRepositionPick();
            return;
        }
        currentEditingFlows[idx] = { ...currentEditingFlows[idx], lat, lon };
        persistSectorFlowsToCache(currentEditingSectorId, currentEditingFlows);
        pendingFlowPickLat = lat;
        pendingFlowPickLon = lon;
        flowRepositionPickActive = false;
        flowRepositionTargetFlowId = null;
        flowMapPickHoverWpId = null;
        const hint = document.getElementById('editExerciseAddFlowHint');
        if (hint) hint.style.display = 'none';
        try { drawExerciseEditorCanvas(); } catch (e) {}
        openFlowDetailsModalForEdit(rid);
        return;
    }
    if (!addFlightRoutePickActive || !exerciseEditorCanvas || e.target !== exerciseEditorCanvas) return;
    if (!document.getElementById('editExerciseModal')?.classList.contains('active')) {
        addFlightRoutePickActive = false;
        return;
    }
    if (e.button !== 1) return;
    e.preventDefault();
    e.stopPropagation();
    hideExerciseEditorRouteDisambigPanel();
    hideAddFlightRoutePickContextMenu();

    const rect = exerciseEditorCanvas.getBoundingClientRect();
    const mx = e.clientX - rect.left;
    const my = e.clientY - rect.top;

    const wpHit = findExerciseEditorWaypointAtCanvas(mx, my, 14);
    if (wpHit) {
        addFlightRoutePickOnMiddleClickWaypoint(wpHit);
        return;
    }

    const near = findExerciseEditorRouteIdsNearCanvas(mx, my, 12);
    if (near.length > 1) {
        showExerciseEditorRouteDisambigPanel(near, e.clientX, e.clientY);
        return;
    }
    if (near.length === 1) {
        handleExerciseEditorAddFlightRouteLinePick(near[0]);
        return;
    }

    const ll = exerciseEditorCanvasXYToLatLon(mx, my);
    if (ll) {
        if (!addFlightRoutePickSequence.length) {
            addFlightRoutePickOnMiddleClickCoordinate(ll.lat, ll.lon);
            return;
        }
        addFlightRoutePickOnMiddleClickCoordinate(ll.lat, ll.lon);
    }
}

function exerciseEditorCanvasMouseMoveRoutePickHover(e) {
    if ((addFlowPickActive || flowRepositionPickActive) && exerciseEditorCanvas && e.target === exerciseEditorCanvas) {
        const rect = exerciseEditorCanvas.getBoundingClientRect();
        const mx = e.clientX - rect.left;
        const my = e.clientY - rect.top;
        const wp = findExerciseEditorWaypointAtCanvas(mx, my, 14);
        const nextWp = wp?.id ?? null;
        if (nextWp === flowMapPickHoverWpId) return;
        flowMapPickHoverWpId = nextWp;
        if (addFlowPickHoverRaf != null) return;
        addFlowPickHoverRaf = requestAnimationFrame(() => {
            addFlowPickHoverRaf = null;
            if (addFlowPickActive || flowRepositionPickActive) try { drawExerciseEditorCanvas(); } catch (err) {}
        });
        return;
    }
    if (!addFlightRoutePickActive || !exerciseEditorCanvas || e.target !== exerciseEditorCanvas) return;
    const rect = exerciseEditorCanvas.getBoundingClientRect();
    const mx = e.clientX - rect.left;
    const my = e.clientY - rect.top;
    const wp = findExerciseEditorWaypointAtCanvas(mx, my, 14);
    const nextWp = wp?.id ?? null;
    const near = findExerciseEditorRouteIdsNearCanvas(mx, my, 12);
    const same = nextWp === addFlightRoutePickHoverWpId &&
        near.length === addFlightRoutePickHoverRouteIds.length &&
        near.every((id, i) => id === addFlightRoutePickHoverRouteIds[i]);
    if (same) return;
    addFlightRoutePickHoverWpId = nextWp;
    addFlightRoutePickHoverRouteIds = near;
    if (addFlightRoutePickHoverRaf != null) return;
    addFlightRoutePickHoverRaf = requestAnimationFrame(() => {
        addFlightRoutePickHoverRaf = null;
        if (addFlightRoutePickActive) try { drawExerciseEditorCanvas(); } catch (err) {}
    });
}

function drawExerciseEditorRoutePickOverlay(ctx, waypoints, routes, centre, lonScale, originX, originY) {
    const drawRoutePolyline = (route, stroke, lineWidth) => {
        const ids = route?.waypointIds || [];
        if (ids.length < 2) return;
        const pts = ids.map(id => waypoints.find(w => w && w.id === id)).filter(w => w && isFinite(w.latitude) && isFinite(w.longitude));
        if (pts.length < 2) return;
        ctx.beginPath();
        let started = false;
        pts.forEach(p => {
            const relLon = centre ? (p.longitude - centre.longitude) : p.longitude;
            const relLat = centre ? (p.latitude - centre.latitude) : p.latitude;
            const x = originX + relLon * exerciseEditorZoom * lonScale;
            const y = originY - relLat * exerciseEditorZoom;
            if (!isFinite(x) || !isFinite(y)) return;
            if (!started) { ctx.moveTo(x, y); started = true; }
            else ctx.lineTo(x, y);
        });
        if (started) {
            ctx.strokeStyle = stroke;
            ctx.lineWidth = lineWidth;
            ctx.stroke();
        }
    };

    if (addFlightRoutePickHoverRouteIds.length) {
        ctx.save();
        routes.forEach(r => {
            if (r && addFlightRoutePickHoverRouteIds.includes(r.id)) {
                drawRoutePolyline(r, 'rgba(255, 193, 7, 0.95)', 5);
            }
        });
        ctx.restore();
    }

    if (addFlightRoutePickPendingRoute) {
        const pr = addFlightRoutePickPendingRoute;
        const route = routes.find(r => r && r.id === pr.routeId);
        if (route) {
            ctx.save();
            drawRoutePolyline(route, 'rgba(255, 152, 0, 0.9)', 6);
            ctx.restore();
        }
    }

    if (addFlightRoutePickHoverWpId) {
        const w = waypoints.find(wp => wp && wp.id === addFlightRoutePickHoverWpId);
        if (w && isFinite(w.latitude) && isFinite(w.longitude)) {
            const xy = exerciseEditorLatLonToCanvasXY(w.latitude, w.longitude);
            if (xy) {
                ctx.save();
                ctx.strokeStyle = 'rgba(255, 193, 7, 0.95)';
                ctx.lineWidth = 3;
                ctx.beginPath();
                ctx.arc(xy.x, xy.y, 12, 0, Math.PI * 2);
                ctx.stroke();
                ctx.restore();
            }
        }
    }

    const rStr = addFlightRoutePickEntriesToRouteString();
    if (rStr.trim() && currentEditingSector) {
        const { points, error } = computeExerciseRoutePoints(rStr, getRouteFixesForSector(currentEditingSector), currentEditingSector.routes);
        if (!error && points.length >= 1) {
            ctx.save();
            ctx.strokeStyle = '#00c853';
            ctx.fillStyle = '#00c853';
            ctx.lineWidth = 4;
            ctx.lineJoin = 'round';
            ctx.beginPath();
            let started = false;
            points.forEach(p => {
                const xy = exerciseEditorLatLonToCanvasXY(p.lat, p.lon);
                if (!xy) return;
                if (!started) { ctx.moveTo(xy.x, xy.y); started = true; }
                else ctx.lineTo(xy.x, xy.y);
            });
            if (started) ctx.stroke();
            points.forEach(p => {
                const xy = exerciseEditorLatLonToCanvasXY(p.lat, p.lon);
                if (!xy) return;
                ctx.beginPath();
                ctx.arc(xy.x, xy.y, 5, 0, Math.PI * 2);
                ctx.fill();
                ctx.beginPath();
                ctx.strokeStyle = '#1b5e20';
                ctx.lineWidth = 2;
                ctx.arc(xy.x, xy.y, 5, 0, Math.PI * 2);
                ctx.stroke();
            });
            ctx.restore();
        }
    }
}

function startAddFlightRoutePickOnMap() {
    if (!currentEditingSector) {
        alert('No airspace loaded for this exercise.');
        return;
    }
    if (!document.getElementById('editExerciseModal')?.classList.contains('active')) {
        alert('Open Edit Exercise first so the map is visible.');
        return;
    }
    addFlightRoutePickReturnModal = 'addFlight';
    hideExerciseEditorRouteDisambigPanel();
    hideAddFlightRoutePickContextMenu();
    addFlightRoutePickActive = true;
    addFlightRoutePickSequence = [];
    clearExerciseEditorAddFlightRoutePickPending();
    addFlightRoutePickHoverWpId = null;
    addFlightRoutePickHoverRouteIds = [];
    const banner = document.getElementById('addFlightRoutePickBanner');
    if (banner) banner.style.display = 'block';
    closeModal('addFlightModal');
    setTimeout(() => {
        initExerciseEditorCanvas();
        try { drawExerciseEditorCanvas(); } catch (e) {}
    }, 80);
}

function finishAddFlightRoutePickUseRoute() {
    hideAddFlightRoutePickContextMenu();
    if (addFlightRoutePickPendingRoute) {
        alert('You first need to select an endpoint for the existing route');
        return;
    }
    const str = addFlightRoutePickEntriesToRouteString();
    if (!str.trim()) {
        alert('Pick at least one waypoint or coordinate for the route.');
        return;
    }
    if (currentEditingSector && Array.isArray(currentEditingSector.routes)) {
        const { error, points } = computeExerciseRoutePoints(str, getRouteFixesForSector(currentEditingSector), currentEditingSector.routes);
        if (error) {
            alert(error);
            return;
        }
        if (!points.length) {
            alert('Route must resolve to at least one track point.');
            return;
        }
    }
    if (addFlightRoutePickReturnModal === 'subFlow') {
        const subRoute = document.getElementById('subFlowRouteInput');
        if (subRoute) subRoute.value = str;
        addFlightRoutePickActive = false;
        addFlightRoutePickReturnModal = 'addFlight';
        const banner = document.getElementById('addFlightRoutePickBanner');
        if (banner) banner.style.display = 'none';
        hideExerciseEditorRouteDisambigPanel();
        try { drawExerciseEditorCanvas(); } catch (e) {}
        reopenFlowDetailsAndCreateSubFlowModals();
        return;
    }
    const flightRoute = document.getElementById('flightRoute');
    if (flightRoute) flightRoute.value = str;
    addFlightRoutePickActive = false;
    addFlightRoutePickReturnModal = 'addFlight';
    const banner = document.getElementById('addFlightRoutePickBanner');
    if (banner) banner.style.display = 'none';
    hideExerciseEditorRouteDisambigPanel();
    try { drawExerciseEditorCanvas(); } catch (e) {}
    openModal('addFlightModal');
}

function cancelAddFlightRoutePickMode() {
    addFlightRoutePickActive = false;
    clearExerciseEditorAddFlightRoutePickPending();
    addFlightRoutePickSequence = [];
    const banner = document.getElementById('addFlightRoutePickBanner');
    if (banner) banner.style.display = 'none';
    hideExerciseEditorRouteDisambigPanel();
    hideAddFlightRoutePickContextMenu();
    try { drawExerciseEditorCanvas(); } catch (e) {}
    const returnTo = addFlightRoutePickReturnModal;
    addFlightRoutePickReturnModal = 'addFlight';
    if (returnTo === 'subFlow') {
        reopenFlowDetailsAndCreateSubFlowModals();
    } else {
        openModal('addFlightModal');
    }
}

/** Edit Exercise preview: current positions only — horizontal < 5 NM and Mode C vertical < STCA_VERTICAL_SEP_FT ft (same rule as sim STCA at k=0). */
function computeExercisePreviewProximityConflictIds(acClones, previewSec, radarSec) {
    const conflictIds = new Set();
    if (!acClones || acClones.length < 2) return conflictIds;
    const interval = Math.max(1, parseInt(radarSec, 10) || 1);
    const hMaxNm = 5;
    const items = [];
    for (const ac of acClones) {
        if (!ac || !ac.id) continue;
        const spawn = parseInt(ac.spawnTimeSec, 10) || 0;
        if (!Number.isFinite(previewSec) || previewSec < spawn) continue;
        if (exercisePreviewAircraftHasCompletedRoute(ac)) continue;
        const st = getAircraftPositionAtRadarUpdate(ac, previewSec, interval);
        if (!st || !isFinite(st.lat) || !isFinite(st.lon)) continue;
        const ft = Number(ac.publishedModeCFeet ?? ac.modeCFeet);
        if (!isFinite(ft)) continue;
        items.push({ id: ac.id, lat: st.lat, lon: st.lon, altFeet: ft });
    }
    for (let i = 0; i < items.length; i++) {
        for (let j = i + 1; j < items.length; j++) {
            const a = items[i];
            const b = items[j];
            const distNm = calculateNauticalMiles(a.lat, a.lon, b.lat, b.lon);
            if (!isFinite(distNm) || distNm >= hMaxNm) continue;
            const vertSepFt = Math.abs(a.altFeet - b.altFeet);
            if (vertSepFt >= STCA_VERTICAL_SEP_FT) continue;
            conflictIds.add(a.id);
            conflictIds.add(b.id);
        }
    }
    return conflictIds;
}

/** Preview-time aircraft on the exercise editor map (same physics + label style as simulation). */
function drawExerciseEditorPreviewAircraftLayer(ctx, centre, lonScale, originX, originY) {
    const slider = document.getElementById('exercisePreviewTimeSlider');
    if (!slider || slider.disabled) return;
    if (!currentEditingExerciseId || !currentEditingSector) return;
    if (simulationJoinedSessionId) return;

    const previewSec = parseInt(slider.value, 10);
    if (!Number.isFinite(previewSec) || previewSec < 0) return;

    exercisePreviewAircraftLabelBounds = [];
    exercisePreviewAircraftCallsignTextBounds = [];
    exercisePreviewTrajectoryEstimateBounds = [];
    exercisePreviewAircraftSymbolBounds = [];
    exercisePreviewScriptMarkerBounds = [];
    exercisePreviewInitialCallMarkerBounds = [];
    exercisePreviewLblTinMarkerBounds = [];

    const tracks = getExercisePreviewTracksCached();
    if (!tracks.length) return;

    const trackIds = new Set(tracks.map(t => t && t.id).filter(Boolean));
    exercisePreviewLabelZOrder = exercisePreviewLabelZOrder.filter(id => trackIds.has(id));
    tracks.forEach(t => {
        if (t && t.id && !exercisePreviewLabelZOrder.includes(t.id)) exercisePreviewLabelZOrder.push(t.id);
    });

    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);

    const acClones = getExercisePreviewIntegratedClonesAtSec(previewSec, radarSec);

    const previewProximityConflictIds = computeExercisePreviewProximityConflictIds(acClones, previewSec, radarSec);
    const previewConflictLabelColor = '#dc2626';

    const acColor = simulationStyle?.aircraft?.targetColor || '#111827';
    const labelColor = simulationStyle?.labels?.textColor || '#111827';
    const modeSColor = simulationStyle?.modeS?.color || SIM_STYLE_DEFAULTS.modeS.color;
    const rPx = 6;
    const padX = 6;
    const padY = 5;
    const labelFontSize = Math.min(24, Math.max(8, parseInt(simulationMap?.labelSize ?? SIM_MAP_DEFAULTS.labelSize, 10) || SIM_MAP_DEFAULTS.labelSize));
    const lineH = Math.round(labelFontSize + 2);

    acClones.forEach(acWork => {
        if (!acWork) return;
        if (exercisePreviewAircraftHasCompletedRoute(acWork)) return;
        applyExercisePreviewSavedLabelOffset(acWork);
        const state = getAircraftPositionAtRadarUpdate(acWork, previewSec, radarSec);
        if (!state || !isFinite(state.lat) || !isFinite(state.lon)) return;
        applyExercisePreviewLabelSpeedState(acWork, state);

        let relLon = state.lon;
        let relLat = state.lat;
        if (centre && isFinite(centre.longitude) && isFinite(centre.latitude)) {
            relLon = state.lon - centre.longitude;
            relLat = state.lat - centre.latitude;
        }
        const x = originX + relLon * exerciseEditorZoom * lonScale;
        const y = originY - relLat * exerciseEditorZoom;
        if (!isFinite(x) || !isFinite(y)) return;

        if (exerciseSpeedVectorEnabled) {
            let vectorHeading = null;
            if (state.next && isFinite(state.next.lat) && isFinite(state.next.lon)) {
                vectorHeading = heading0to359(calculateBearingDegrees(state.lat, state.lon, state.next.lat, state.next.lon));
            } else if (acWork.publishedHeadingDeg != null && isFinite(acWork.publishedHeadingDeg)) {
                vectorHeading = heading0to359(acWork.publishedHeadingDeg);
            } else if (acWork.currentHeadingDeg != null && isFinite(acWork.currentHeadingDeg)) {
                vectorHeading = heading0to359(acWork.currentHeadingDeg);
            } else if (acWork.selectedHeadingDeg != null && isFinite(acWork.selectedHeadingDeg)) {
                vectorHeading = heading0to359(acWork.selectedHeadingDeg);
            }
            const gsKt = Number(state.gs ?? acWork.publishedLabelGsKt ?? acWork.publishedModeSTasKt ?? acWork.modeSTasKt);
            if (vectorHeading != null && isFinite(gsKt) && gsKt > 0) {
                const end = projectLatLonByNm(state.lat, state.lon, vectorHeading, gsKt / 60);
                if (end && isFinite(end.lat) && isFinite(end.lon)) {
                    let endLon = end.lon;
                    let endLat = end.lat;
                    if (centre && isFinite(centre.longitude) && isFinite(centre.latitude)) {
                        endLon = end.lon - centre.longitude;
                        endLat = end.lat - centre.latitude;
                    }
                    const vx = originX + endLon * exerciseEditorZoom * lonScale;
                    const vy = originY - endLat * exerciseEditorZoom;
                    if (isFinite(vx) && isFinite(vy)) {
                        ctx.strokeStyle = '#2563eb';
                        ctx.lineWidth = 2;
                        ctx.beginPath();
                        ctx.moveTo(x, y);
                        ctx.lineTo(vx, vy);
                        ctx.stroke();
                    }
                }
            }
        }

        ctx.fillStyle = acColor;
        ctx.strokeStyle = '#000000';
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.arc(x, y, rPx, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        exercisePreviewAircraftSymbolBounds.push({ aircraftId: acWork.id, x, y, r: rPx });

        drawExercisePreviewTrajectoryForAircraft(ctx, acWork, state, x, y, centre, lonScale, originX, originY, previewSec);

        const lines = getLabelLayoutLinesForAircraft(acWork, state, { showFreeText: false });
        if (!lines.length) return;
        const segLines = getLabelLayoutSegmentsForAircraft(acWork, state, { showFreeText: false });

        let maxW = 0;
        for (let li = 0; li < lines.length; li++) {
            const fs = (li === 0) ? labelFontSize : Math.min(24, Math.max(8, labelFontSize));
            ctx.font = (li === 0) ? `bold ${fs}px Arial` : `${fs}px Arial`;
            const tw = ctx.measureText(lines[li] || ' ').width;
            if (tw > maxW) maxW = tw;
        }
        const w = maxW + padX * 2;
        const h = padY * 2 + lineH * lines.length;

        let cxOff = Number.isFinite(acWork.labelOffsetX) ? acWork.labelOffsetX : 28;
        let cyOff = Number.isFinite(acWork.labelOffsetY) ? acWork.labelOffsetY : -28;
        if (!acWork.labelLeaderOffsetToCenter) {
            cxOff += w / 2;
            cyOff += h / 2;
        }
        const labelMidX = x + cxOff;
        const labelMidY = y + cyOff;
        const lx = labelMidX - w / 2;
        const ly = labelMidY - h / 2;

        const labelStcaConflict = previewProximityConflictIds.has(acWork.id);
        const labelTextColor = labelStcaConflict ? previewConflictLabelColor : labelColor;

        ctx.strokeStyle = labelTextColor;
        ctx.lineWidth = 1;
        const rx = lx;
        const ry = ly;
        const rw = w;
        const rh = h;
        const lmx = labelMidX;
        const lmy = labelMidY;
        const insideA = x >= rx && x <= rx + rw && y >= ry && y <= ry + rh;
        const insideB = lmx >= rx && lmx <= rx + rw && lmy >= ry && lmy <= ry + rh;
        ctx.beginPath();
        let drewLeader = false;
        if (!insideA && insideB) {
            const tHit = segmentFirstBoundaryT(x, y, lmx, lmy, rx, ry, rw, rh);
            if (tHit != null && isFinite(tHit)) {
                const ex = x + tHit * (lmx - x);
                const ey = y + tHit * (lmy - y);
                ctx.moveTo(x, y);
                ctx.lineTo(ex, ey);
                drewLeader = true;
            }
        } else if (!insideA && !insideB) {
            ctx.moveTo(x, y);
            ctx.lineTo(lmx, lmy);
            drewLeader = true;
        }
        if (drewLeader) ctx.stroke();

        ctx.fillStyle = hexToRgba(simulationStyle?.labels?.backgroundColor || '#ffffff', 0.92);
        ctx.strokeStyle = labelStcaConflict ? previewConflictLabelColor : 'rgba(0,0,0,0.55)';
        ctx.lineWidth = labelStcaConflict ? 2 : 1;
        ctx.beginPath();
        ctx.rect(lx, ly, w, h);
        ctx.fill();
        ctx.stroke();

        ctx.textAlign = 'left';
        ctx.textBaseline = 'top';
        let ty = ly + padY;
        for (let li = 0; li < lines.length; li++) {
            const fs = (li === 0) ? labelFontSize : Math.min(24, Math.max(8, labelFontSize));
            ctx.font = (li === 0) ? `bold ${fs}px Arial` : `${fs}px Arial`;
            const segs = Array.isArray(segLines) ? segLines[li] : null;
            if (Array.isArray(segs) && segs.length) {
                const spaceW = ctx.measureText(' ').width || 4;
                let cx = lx + padX;
                segs.forEach(seg => {
                    const txt = (seg?.text || '').toString();
                    if (!txt) return;
                    const segKind = (seg?.kind || '').toString();
                    let col = labelTextColor;
                    if (!labelStcaConflict) {
                        if (segKind === 'mode_s') col = modeSColor;
                        else if (segKind === 'selected_speed') col = seg?.color || '#F87171';
                    }
                    ctx.fillStyle = col;
                    const segW = ctx.measureText(txt).width;
                    ctx.fillText(txt, cx, ty);
                    if (seg.field === 'CALLSIGN') {
                        exercisePreviewAircraftCallsignTextBounds.push({
                            aircraftId: acWork.id,
                            x: cx,
                            y: ty,
                            w: segW,
                            h: lineH
                        });
                    }
                    cx += segW + spaceW;
                });
            } else {
                ctx.fillStyle = labelTextColor;
                ctx.fillText(lines[li] || '', lx + padX, ty);
            }
            ty += lineH;
        }

        exercisePreviewAircraftLabelBounds.push({
            aircraftId: acWork.id,
            x: lx,
            y: ly,
            w,
            h,
            acX: x,
            acY: y
        });
    });

    drawExercisePreviewScriptMarkersLayer(ctx, centre, lonScale, originX, originY, radarSec);
    drawExercisePreviewInitialCallMarkersLayer(ctx, centre, lonScale, originX, originY, radarSec);
}

function drawExerciseEditorCanvas() {
    if (!exerciseEditorCtx || !exerciseEditorCanvas) return;
    const ctx = exerciseEditorCtx;
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, exerciseEditorCanvas.width, exerciseEditorCanvas.height);
    if (!currentEditingSector) return;

    const waypoints = currentEditingSector.waypoints || [];
    const routes = currentEditingSector.routes || [];
    const boundaries = getBoundariesFromSectorForSimulation(currentEditingSector);
    const centre = waypoints.find(wp => isCenterWaypointName(wp?.name));
    const lonScale = getExerciseEditorLonCosScale(waypoints);

    const originX = exerciseEditorCanvas.width / 2 + exerciseEditorPanX;
    const originY = exerciseEditorCanvas.height / 2 + exerciseEditorPanY;

    drawExerciseEditorFlowsLayer(ctx);

    // Boundaries
    ctx.strokeStyle = '#0000ff';
    ctx.lineWidth = 2;
    (boundaries || []).forEach(b => {
        const pts = (b?.points || []).filter(p => p && isFinite(p.latitude) && isFinite(p.longitude));
        if (pts.length < 2) return;
        ctx.beginPath();
        let started = false;
        pts.forEach(p => {
            const relLon = centre ? (p.longitude - centre.longitude) : p.longitude;
            const relLat = centre ? (p.latitude - centre.latitude) : p.latitude;
            const x = originX + relLon * exerciseEditorZoom * lonScale;
            const y = originY - relLat * exerciseEditorZoom;
            if (!isFinite(x) || !isFinite(y)) return;
            if (!started) { ctx.moveTo(x, y); started = true; }
            else ctx.lineTo(x, y);
        });
        if (started) {
            // close
            const p0 = pts[0];
            const relLon0 = centre ? (p0.longitude - centre.longitude) : p0.longitude;
            const relLat0 = centre ? (p0.latitude - centre.latitude) : p0.latitude;
            ctx.lineTo(originX + relLon0 * exerciseEditorZoom * lonScale, originY - relLat0 * exerciseEditorZoom);
            ctx.stroke();
        }
    });

    // Routes
    ctx.strokeStyle = '#000000';
    ctx.lineWidth = 2;
    (routes || []).forEach(r => {
        const ids = r?.waypointIds || [];
        if (ids.length < 2) return;
        const pts = ids.map(id => waypoints.find(w => w && w.id === id)).filter(w => w && isFinite(w.latitude) && isFinite(w.longitude));
        if (pts.length < 2) return;
        ctx.beginPath();
        let started = false;
        pts.forEach(p => {
            const relLon = centre ? (p.longitude - centre.longitude) : p.longitude;
            const relLat = centre ? (p.latitude - centre.latitude) : p.latitude;
            const x = originX + relLon * exerciseEditorZoom * lonScale;
            const y = originY - relLat * exerciseEditorZoom;
            if (!isFinite(x) || !isFinite(y)) return;
            if (!started) { ctx.moveTo(x, y); started = true; }
            else ctx.lineTo(x, y);
        });
        if (started) ctx.stroke();
    });

    // Airports + runways (magenta), same style as Edit Airspace
    try {
        const MAGENTA = '#ff00ff';
        ctx.save();
        ctx.strokeStyle = MAGENTA;
        ctx.fillStyle = MAGENTA;
        ctx.lineWidth = 2;
        ctx.font = 'bold 12px Arial';
        ctx.textAlign = 'left';
        ctx.textBaseline = 'top';

        const airports = Array.isArray(currentEditingSector.airports) ? currentEditingSector.airports : [];
        airports.forEach(ap => {
            if (!ap) return;
            const icao = normalizeAirportIcao(ap.icao);
            const arpLat = Number(ap.arpLat);
            const arpLon = Number(ap.arpLon);
            if (!isFinite(arpLat) || !isFinite(arpLon)) return;
            let relLon = arpLon;
            let relLat = arpLat;
            if (centre && isFinite(centre.longitude) && isFinite(centre.latitude)) {
                relLon = arpLon - centre.longitude;
                relLat = arpLat - centre.latitude;
            }
            const px = originX + relLon * exerciseEditorZoom * lonScale;
            const py = originY - relLat * exerciseEditorZoom;
            if (!isFinite(px) || !isFinite(py)) return;

            const s = 6;
            ctx.fillRect(px - s / 2, py - s / 2, s, s);
            if (icao) ctx.fillText(icao, px + 8, py - 8);

            const runways = Array.isArray(ap.runways) ? ap.runways : [];
            runways.forEach(rw => {
                const a = rw?.endA;
                const b = rw?.endB;
                const aLat = Number(a?.lat);
                const aLon = Number(a?.lon);
                const bLat = Number(b?.lat);
                const bLon = Number(b?.lon);
                if (![aLat, aLon, bLat, bLon].every(isFinite)) return;
                let raLon = aLon;
                let raLat = aLat;
                let rbLon = bLon;
                let rbLat = bLat;
                if (centre && isFinite(centre.longitude) && isFinite(centre.latitude)) {
                    raLon = aLon - centre.longitude;
                    raLat = aLat - centre.latitude;
                    rbLon = bLon - centre.longitude;
                    rbLat = bLat - centre.latitude;
                }
                const pax = originX + raLon * exerciseEditorZoom * lonScale;
                const pay = originY - raLat * exerciseEditorZoom;
                const pbx = originX + rbLon * exerciseEditorZoom * lonScale;
                const pby = originY - rbLat * exerciseEditorZoom;
                if (![pax, pay, pbx, pby].every(isFinite)) return;

                ctx.beginPath();
                ctx.moveTo(pax, pay);
                ctx.lineTo(pbx, pby);
                ctx.stroke();

                const aName = normalizeRunwayDesignator(a?.name);
                const bName = normalizeRunwayDesignator(b?.name);
                if (aName) ctx.fillText(aName, pax + 6, pay - 10);
                if (bName) ctx.fillText(bName, pbx + 6, pby - 10);
            });
        });

        ctx.restore();
    } catch (e) {
        try { ctx.restore(); } catch (e2) {}
    }

    // Waypoints
    const waypointSymbolSize = Math.max(2, Math.round((Math.min(48, Math.max(6, parseInt(simulationMap?.waypointNames?.size ?? SIM_MAP_DEFAULTS.waypointNames.size, 10) || SIM_MAP_DEFAULTS.waypointNames.size))) * 0.4));
    const waypointTextSize = Math.min(48, Math.max(6, parseInt(simulationMap?.waypointNames?.size ?? SIM_MAP_DEFAULTS.waypointNames.size, 10) || SIM_MAP_DEFAULTS.waypointNames.size));
    waypoints.forEach(wp => {
        if (!wp || !isFinite(wp.latitude) || !isFinite(wp.longitude)) return;
        const relLon = centre ? (wp.longitude - centre.longitude) : wp.longitude;
        const relLat = centre ? (wp.latitude - centre.latitude) : wp.latitude;
        const x = originX + relLon * exerciseEditorZoom * lonScale;
        const y = originY - relLat * exerciseEditorZoom;
        if (!isFinite(x) || !isFinite(y)) return;
        ctx.fillStyle = '#000000';
        ctx.strokeStyle = '#000000';
        ctx.lineWidth = isCenterWaypointName(wp.name) ? 3 : 1;
        ctx.beginPath();
        ctx.moveTo(x, y - waypointSymbolSize * 1.35);
        ctx.lineTo(x - waypointSymbolSize, y + waypointSymbolSize);
        ctx.lineTo(x + waypointSymbolSize, y + waypointSymbolSize);
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
        if (wp.name) {
            ctx.font = `${waypointTextSize}px Arial`;
            ctx.textAlign = 'center';
            ctx.textBaseline = 'top';
            ctx.fillText(wp.name, x, y + waypointSymbolSize + 4);
        }
    });

    drawExerciseEditorFlowPickWaypointHighlight(ctx, waypoints);

    drawExerciseEditorPreviewAircraftLayer(ctx, centre, lonScale, originX, originY);

    if (addFlightRoutePickActive) {
        drawExerciseEditorRoutePickOverlay(ctx, waypoints, routes, centre, lonScale, originX, originY);
    }
}

// Populate sector select dropdown
function populateSectorSelect() {
    const select = document.getElementById('exerciseSectorSelect');
    const sectors = getSectors();
    
    // Clear existing options except the first one
    select.innerHTML = '<option value="">Select an Airspace</option>';
    
    if (sectors.length === 0) {
        select.innerHTML += '<option value="" disabled>No airspaces available. Create an airspace first.</option>';
        return;
    }
    
    sectors.forEach(sector => {
        const option = document.createElement('option');
        option.value = sector.id;
        option.textContent = sector.name;
        select.appendChild(option);
    });
}

// Populate sector select for edit
function populateSectorSelectForEdit() {
    const select = document.getElementById('sectorSelectForEdit');
    const sectors = getSectors();
    
    select.innerHTML = '<option value="">Select an Airspace</option>';
    
    if (sectors.length === 0) {
        select.innerHTML += '<option value="" disabled>No airspaces available. Create an airspace first.</option>';
        return;
    }
    
    sectors.forEach(sector => {
        const option = document.createElement('option');
        option.value = sector.id;
        option.textContent = sector.name;
        select.appendChild(option);
    });
}

