const MAP_AREA_KINDS_LIST = ['restricted', 'prohibited', 'dangerous', 'other'];
const MAP_AREA_OTHER_ACTIONS_LIST = ['do_nothing', 'delete_planes'];
const MAP_AREA_KIND_DEFAULT_LINE_COLOR = Object.freeze({
    restricted: '#e65100',
    prohibited: '#b71c1c',
    dangerous: '#f9a825',
    other: '#78909c'
});

function normalizeMapAreaKind(raw) {
    const k = String(raw || '').trim().toLowerCase();
    return MAP_AREA_KINDS_LIST.includes(k) ? k : 'restricted';
}

function normalizeMapAreaOtherAction(raw) {
    const text = String(raw || '').trim().toLowerCase().replace(/\s+/g, '_');
    if (text === 'delete_planes' || text === 'delete_plane') return 'delete_planes';
    return 'do_nothing';
}

function formatMapAreaOtherActionDisplay(otherAction) {
    const action = normalizeMapAreaOtherAction(otherAction);
    return action === 'delete_planes' ? 'Delete planes' : 'Do Nothing';
}

function sanitizeMapAreaLineColor(raw, kind) {
    const k = normalizeMapAreaKind(kind);
    const fb = MAP_AREA_KIND_DEFAULT_LINE_COLOR[k] || '#888888';
    const s = String(raw || '').trim();
    if (/^#[0-9A-Fa-f]{6}$/.test(s)) return s.toLowerCase();
    return fb.toLowerCase();
}

function formatMapAreaKindDisplay(kind, otherAction) {
    const k = normalizeMapAreaKind(kind);
    if (k === 'other') {
        return `Other (${formatMapAreaOtherActionDisplay(otherAction)})`;
    }
    return k.charAt(0).toUpperCase() + k.slice(1);
}

function normalizeMapAreaRecord(area) {
    if (!area) return area;
    const kind = normalizeMapAreaKind(area.kind);
    const normalized = {
        ...area,
        kind,
        lineColor: sanitizeMapAreaLineColor(area.lineColor, kind)
    };
    if (kind === 'other') {
        normalized.otherAction = normalizeMapAreaOtherAction(area.otherAction);
    } else {
        delete normalized.otherAction;
    }
    return normalized;
}

function syncMapAreaOtherActionUi() {
    const ks = document.getElementById('mapAreaKindSelect');
    const group = document.getElementById('mapAreaOtherActionGroup');
    if (!group) return;
    const isOther = ks && normalizeMapAreaKind(ks.value) === 'other';
    group.style.display = isOther ? '' : 'none';
}

function getSimulationMapAreasWithDeletePlanesAction() {
    return getSimulationSectorMapAreas().filter((area) =>
        normalizeMapAreaKind(area.kind) === 'other' &&
        normalizeMapAreaOtherAction(area.otherAction) === 'delete_planes'
    );
}

function getAircraftFlForMapAreaVolumeCheck(ac) {
    const mcFeet = Number(ac?.publishedModeCFeet ?? ac?.modeCFeet);
    if (isFinite(mcFeet)) return Math.max(0, Math.min(500, Math.round(mcFeet / 100)));
    const modeS = parseInt(ac?.modeSFl, 10);
    if (Number.isFinite(modeS)) return Math.max(0, Math.min(500, modeS));
    const alv = parseInt(ac?.alv, 10);
    if (Number.isFinite(alv)) return Math.max(0, Math.min(500, alv));
    return null;
}

function aircraftIsInsideMapAreaVolume(ac, area, state) {
    if (!area || !state || !isFinite(state.lat) || !isFinite(state.lon)) return false;
    const pts = area.boundary?.points;
    if (!Array.isArray(pts) || pts.length < 3) return false;
    if (!isPointInPolygonLatLon(state.lat, state.lon, pts)) return false;
    const vl = area.verticalLimits;
    if (!vl || !Number.isFinite(vl.topFl) || !Number.isFinite(vl.bottomFl)) return false;
    const fl = getAircraftFlForMapAreaVolumeCheck(ac);
    if (fl == null) return false;
    return fl >= vl.bottomFl && fl <= vl.topFl;
}

function aircraftShouldBeRemovedByMapAreaDeletePlanes(ac, state) {
    const areas = getSimulationMapAreasWithDeletePlanesAction();
    if (!areas.length) return false;
    for (let i = 0; i < areas.length; i++) {
        if (aircraftIsInsideMapAreaVolume(ac, areas[i], state)) return true;
    }
    return false;
}
let gridSpacing = 50;
let originX = 0;
let originY = 0;
const SECTOR_MAP_OPTIONS_STORAGE_KEY = 'aitc_sector_map_options_v1';
const SECTOR_MAP_OPTIONS_DEFAULTS = {
    showWaypointNames: true,
    showWaypointSymbols: true,
    showNavaidNames: true,
    showNavaidSymbols: true,
    showRoutes: true,
    renderInView: false,
    waypointNameSize: 12,
    waypointSymbolSize: 14,
    navaidNameSize: 12,
    navaidSymbolSize: 20
};
let sectorMapOptions = { ...SECTOR_MAP_OPTIONS_DEFAULTS };

function clampSectorMapOptionNumber(value, min, max, fallback) {
    const n = parseInt(value, 10);
    if (!Number.isFinite(n)) return fallback;
    return Math.min(max, Math.max(min, n));
}

function loadSectorMapOptions() {
    try {
        const raw = localStorage.getItem(SECTOR_MAP_OPTIONS_STORAGE_KEY);
        if (!raw) return;
        const parsed = JSON.parse(raw);
        sectorMapOptions = {
            ...SECTOR_MAP_OPTIONS_DEFAULTS,
            showWaypointNames: !!(parsed.showWaypointNames ?? SECTOR_MAP_OPTIONS_DEFAULTS.showWaypointNames),
            showWaypointSymbols: !!(parsed.showWaypointSymbols ?? SECTOR_MAP_OPTIONS_DEFAULTS.showWaypointSymbols),
            showNavaidNames: !!(parsed.showNavaidNames ?? SECTOR_MAP_OPTIONS_DEFAULTS.showNavaidNames),
            showNavaidSymbols: !!(parsed.showNavaidSymbols ?? SECTOR_MAP_OPTIONS_DEFAULTS.showNavaidSymbols),
            showRoutes: !!(parsed.showRoutes ?? SECTOR_MAP_OPTIONS_DEFAULTS.showRoutes),
            renderInView: !!(parsed.renderInView ?? SECTOR_MAP_OPTIONS_DEFAULTS.renderInView),
            waypointNameSize: clampSectorMapOptionNumber(parsed.waypointNameSize, 6, 36, SECTOR_MAP_OPTIONS_DEFAULTS.waypointNameSize),
            waypointSymbolSize: clampSectorMapOptionNumber(parsed.waypointSymbolSize, 6, 36, SECTOR_MAP_OPTIONS_DEFAULTS.waypointSymbolSize),
            navaidNameSize: clampSectorMapOptionNumber(parsed.navaidNameSize, 6, 36, SECTOR_MAP_OPTIONS_DEFAULTS.navaidNameSize),
            navaidSymbolSize: clampSectorMapOptionNumber(parsed.navaidSymbolSize, 8, 44, SECTOR_MAP_OPTIONS_DEFAULTS.navaidSymbolSize)
        };
    } catch (e) {
        sectorMapOptions = { ...SECTOR_MAP_OPTIONS_DEFAULTS };
    }
}

function saveSectorMapOptions() {
    try {
        localStorage.setItem(SECTOR_MAP_OPTIONS_STORAGE_KEY, JSON.stringify(sectorMapOptions));
    } catch (e) {}
}

function syncSectorMapOptionsModalFromState() {
    const setChecked = (id, value) => {
        const el = document.getElementById(id);
        if (el) el.checked = !!value;
    };
    const setRange = (id, value) => {
        const el = document.getElementById(id);
        const valueEl = document.getElementById(`${id}Value`);
        if (el) el.value = String(value);
        if (valueEl) valueEl.textContent = String(value);
    };

    setChecked('sectorMapShowWaypointNames', sectorMapOptions.showWaypointNames);
    setChecked('sectorMapShowWaypointSymbols', sectorMapOptions.showWaypointSymbols);
    setChecked('sectorMapShowNavaidNames', sectorMapOptions.showNavaidNames);
    setChecked('sectorMapShowNavaidSymbols', sectorMapOptions.showNavaidSymbols);
    setChecked('sectorMapShowRoutes', sectorMapOptions.showRoutes);
    setRange('sectorMapWaypointNameSize', sectorMapOptions.waypointNameSize);
    setRange('sectorMapWaypointSymbolSize', sectorMapOptions.waypointSymbolSize);
    setRange('sectorMapNavaidNameSize', sectorMapOptions.navaidNameSize);
    setRange('sectorMapNavaidSymbolSize', sectorMapOptions.navaidSymbolSize);
}

function updateSectorMapOptionFromInput(input) {
    if (!input || !input.id) return;
    const boolMap = {
        sectorMapShowWaypointNames: 'showWaypointNames',
        sectorMapShowWaypointSymbols: 'showWaypointSymbols',
        sectorMapShowNavaidNames: 'showNavaidNames',
        sectorMapShowNavaidSymbols: 'showNavaidSymbols',
        sectorMapShowRoutes: 'showRoutes'
    };
    const rangeMap = {
        sectorMapWaypointNameSize: ['waypointNameSize', 6, 36],
        sectorMapWaypointSymbolSize: ['waypointSymbolSize', 6, 36],
        sectorMapNavaidNameSize: ['navaidNameSize', 6, 36],
        sectorMapNavaidSymbolSize: ['navaidSymbolSize', 8, 44]
    };

    if (boolMap[input.id]) {
        sectorMapOptions[boolMap[input.id]] = !!input.checked;
    } else if (rangeMap[input.id]) {
        const [key, min, max] = rangeMap[input.id];
        sectorMapOptions[key] = clampSectorMapOptionNumber(input.value, min, max, SECTOR_MAP_OPTIONS_DEFAULTS[key]);
        const valueEl = document.getElementById(`${input.id}Value`);
        if (valueEl) valueEl.textContent = String(sectorMapOptions[key]);
    }
    saveSectorMapOptions();
    try { drawCanvas(); } catch (e) {}
}

function syncSectorRenderViewButtonState() {
    const btn = document.getElementById('sectorMapRenderViewBtn');
    if (!btn) return;
    btn.classList.toggle('active', !!sectorMapOptions.renderInView);
    btn.setAttribute('aria-pressed', sectorMapOptions.renderInView ? 'true' : 'false');
    btn.title = sectorMapOptions.renderInView
        ? 'Render View is ON: only visible map items are rendered'
        : 'Render only items currently visible on screen';
}

function buildSectorRouteFixLookup() {
    const map = new Map();
    [...(waypoints || []), ...(navaids || [])].forEach(fix => {
        if (fix && fix.id) map.set(String(fix.id), fix);
    });
    return map;
}

function sectorMapCanvasPointIsInRenderView(x, y, marginPx = 80) {
    if (!sectorMapOptions.renderInView) return true;
    return isFinite(x) && isFinite(y) &&
        x >= -marginPx &&
        x <= canvas.width + marginPx &&
        y >= -marginPx &&
        y <= canvas.height + marginPx;
}

function sectorMapRouteCanvasBoundsIntersectsView(points, marginPx = 120) {
    if (!sectorMapOptions.renderInView) return true;
    if (!Array.isArray(points) || points.length === 0) return false;
    let minX = Infinity;
    let maxX = -Infinity;
    let minY = Infinity;
    let maxY = -Infinity;
    points.forEach(point => {
        if (!point || !isFinite(point.x) || !isFinite(point.y)) return;
        minX = Math.min(minX, point.x);
        maxX = Math.max(maxX, point.x);
        minY = Math.min(minY, point.y);
        maxY = Math.max(maxY, point.y);
    });
    if (!isFinite(minX) || !isFinite(maxX) || !isFinite(minY) || !isFinite(maxY)) return false;
    return maxX >= -marginPx &&
        minX <= canvas.width + marginPx &&
        maxY >= -marginPx &&
        minY <= canvas.height + marginPx;
}

