let joinerLastAppliedHostStateSeq = null;
// STCA state computed in same tick as aircraft position update, so projections stay in sync with display
let stcaStateCache = { simSec: null, conflictIds: new Set(), firstBreachPairs: [] };

// Simulation operation mode (runtime only; resets each simulation start)
const SIM_OPERATION_MODES = [
    {
        id: 'DL',
        label: 'DL mode',
        description: 'In DL (Data link) mode all commands entered in the label of the aircraft are transmitted directly to aircraft and executed'
    },
    {
        id: 'DL_PLN',
        label: 'DL + PLN',
        description: 'In DL + PLN (Data Link + Planner), another ATCO can join the training session as planner that can assist the Executive controller'
    },
    {
        id: 'EXE_PP',
        label: 'EXE + PP',
        description: 'In EXE + PP (Executive + Pseudo-Pilot) another person plays the role of the pilot and has to input the comands given by the Executive ATCO before the aircraft takes any action'
    },
    {
        id: 'EXE_PLN_PP',
        label: 'EXE + PLN with PP',
        description: 'In EXE+PLN with PP, another person plays the role of the Planner and another the role of the Pseudo-Pilot'
    },
    {
        id: 'EXE_AI_PP',
        label: 'EXE + AI PP',
        description: 'In EXE + AI PP the Executive Controller sends commands using voice and the Artificial Inteligence Pseudo-Pilot takes action and reply using Text-to-Speech'
    },
    {
        id: 'EXE_PLN_AI_PP',
        label: 'EXE + PLN + AI PP',
        description: 'In EXE + PLN +AI PP the Executive Controller sends commands using voice and the Artificial Inteligence Pseudo-Pilot takes action and reply using Text-to-Speech, while assisted by another person in the role of the Planner'
    }
];
/** Hosted (multiplayer) sessions are always DL; host has full control. Single-user demo: DL only (other modes shown disabled). */
/** Host PUT /state and joiner GET poll interval (ms). Keep ≥250–500 on small hosts (Railway): 50ms overloads CPU/SQLite with large JSON. */
const MULTIPLAYER_STATE_SYNC_INTERVAL_MS = 500;
const HOST_SESSION_ALLOWED_MODE_IDS = ['DL'];
let simulationOperationModeId = 'DL';
let simulationSessionId = null;       // set when hosting; used to push state and delete on stop
let simulationJoinedSessionId = null; // set when joined; used to poll state
/** Host: incremented on each hosted restart; included in PUT state so joiners reset local caches. */
let hostSessionRestartSeq = 0;
/** Joiner: last applied hostSessionRestartSeq from GET state. */
let joinerLastAppliedHostSessionRestartSeq = null;
/** Joiner: skip preserving label offsets / trails on the next applySessionState after host restart. */
let joinerSkipLabelOffsetPreserveOnce = false;
/** Joiner: skip copying stale held _display* onto new aircraft rows after host restart. */
let joinerSkipHeldDisplayPreserveOnce = false;
/** Joiner EXE/PLN/…: defer ATM baseline + routeProgress until host positions have landed. */
let joinerAwaitingDeferredAtmSync = false;
let joinerDeferAtmSyncTimerId = null;
const JOINER_ATM_RESYNC_AFTER_RESTART_MS = 450;
/** Host: delay before automatic second restart (after joiners receive spawn positions). */
const HOST_DOUBLE_RESTART_DELAY_MS = JOINER_ATM_RESYNC_AFTER_RESTART_MS + MULTIPLAYER_STATE_SYNC_INTERVAL_MS + 150;
let hostRestartInProgress = false;
let hostAutoSecondRestartTimerId = null;
let simulationIsMonitorOnly = false;  // true when user joined a DL session (read-only)

/** True when this browser is hosting the live session (not joiner, not single-user with no session id). */
function isSimulationMultiplayerHost() {
    return !!simulationSessionId;
}

/** Host tab runs FMS physics (Mode-S delay, climb/descent). True even if stale joiner ids linger after hosting. */
function isSimulationHostFmsMaster() {
    return !!simulationSessionId;
}

/** Joiner-only client (polls GET state; no local vertical integration). */
function isSimulationJoinerOnlyClient() {
    return !!simulationJoinedSessionId && !simulationSessionId;
}

/** Sim seconds for host/solo FMS vertical logic (never joiner display clock). */
function getFmsVerticalSimTimeSec() {
    if (isSimulationJoinerOnlyClient()) {
        return getEffectiveSimulationSimTimeMs() / 1000;
    }
    return Math.max(0, Number(simulationSimTimeMs) || 0) / 1000;
}

/** True in any hosted (multiplayer) session — host or joiner. TTS is forced off and the strip control is hidden. */
function isSimulationHostedMultiplayerSession() {
    return !!(simulationSessionId || simulationJoinedSessionId);
}

function stopHostedSessionTts() {
    try { window.speechSynthesis.cancel(); } catch (e) {}
    simulationTtsIsSpeaking = false;
    try {
        (window.simulationData?.aircraft || []).forEach(ac => {
            if (ac) clearSimulationAircraftTtsQueue(ac);
        });
    } catch (e) {}
}

/** EXE joiner while a PP is active (heartbeating) on the same ATC sector: ALV/speed/heading/DCT affect display/trajectory only, not aircraft physics. */
function isSimulationExeWithPpAircraftRestrictions() {
    return !!simulationJoinedSessionId
        && String(simulationJoinRole || '').toUpperCase() === 'EXE'
        && !!simulationJoinPpPresentOnMySector;
}

/**
 * EXE joiner: host pushes full state every poll; without this, label + trajectory edits disappear immediately.
 * We re-apply a per-aircraft patch of user-intent fields after each sync (not host physics: Mode-C, position, etc.).
 */
let joinerExeAircraftPatches = null;
/** OBS (non-editor): ATM vertical-only POST queue (no joinerExeAircraftPatches lateral cache). */
let _joinerAtmVerticalOnlyPending = null;
let _joinerAtmVerticalOnlyTimer = null;

function isJoinerExeClient() {
    return !!simulationJoinedSessionId && String(simulationJoinRole || '').toUpperCase() === 'EXE';
}

function isJoinerPpClient() {
    return !!simulationJoinedSessionId && String(simulationJoinRole || '').toUpperCase() === 'PP';
}

/** HOST + PP flight-status (ASM/transfer) is separate from EXE/PLN atmTrajectory metadata. */
function usesPpFmsFlightStatusDomain() {
    return isJoinerPpClient() || (!!simulationSessionId && !simulationJoinedSessionId);
}

function getAcTransferFromAtcSectorId(ac) {
    if (!ac) return null;
    if (usesPpFmsFlightStatusDomain()) return ac.ppTransferFromAtcSectorId;
    return ac.transferFromAtcSectorId;
}

function getAcTransferToSectorNameNorm(ac) {
    if (!ac) return null;
    if (usesPpFmsFlightStatusDomain()) return ac.ppTransferToSectorNameNorm;
    return ac.transferToSectorNameNorm;
}

function getAcTransferReceiverAssumed(ac) {
    if (!ac) return false;
    if (usesPpFmsFlightStatusDomain()) return !!ac.ppTransferReceiverAssumed;
    return !!ac.transferReceiverAssumed;
}

function isJoinerExeOrPlnClient() {
    if (!simulationJoinedSessionId) return false;
    const r = String(simulationJoinRole || '').toUpperCase();
    return r === 'EXE' || r === 'PLN';
}

/** Resolve live aircraft after session GET replaces simulationData.aircraft with new clones (picker handlers must not keep stale refs). */
function getSimulationAircraftById(aircraftId) {
    if (aircraftId == null || !window.simulationData || !Array.isArray(window.simulationData.aircraft)) return null;
    const idStr = String(aircraftId);
    return window.simulationData.aircraft.find((a) => a && String(a.id) === idStr) || null;
}

/** DL roles that share ATM_Trajectory (display). FMS remains host + PP only. */
const JOIN_ATM_TRAJECTORY_DISPLAY_ROLES = new Set(['EXE', 'PLN', 'INSTR', 'EVAL', 'OBS']);
const JOIN_ATM_TRAJECTORY_EDITOR_ROLES = new Set(['EXE', 'PLN', 'INSTR', 'EVAL']);

/** Session ATM bucket + explicit POSTs own handoff / ASM; host FMS route sync must not push these (stale TOU/TIN overwrites joiner nulls). */
const ATM_FLIGHT_METADATA_KEYS = ['transferFromAtcSectorId', 'transferToSectorNameNorm', 'transferReceiverAssumed', 'exeFlightStatus', 'exeFlightStatusAtcSectorId'];
const ATM_TRANSFER_METADATA_KEYS = ['transferFromAtcSectorId', 'transferToSectorNameNorm', 'transferReceiverAssumed'];
const ATM_FLIGHT_METADATA_PATCH_KEYS = new Set(ATM_FLIGHT_METADATA_KEYS);
/** PP/HOST ASM + transfer (pp-flight-status bucket; never read by EXE/PLN tinting). */
const PP_FLIGHT_STATUS_KEYS = ['ppFlightStatus', 'ppFlightStatusAtcSectorId', 'ppTransferFromAtcSectorId', 'ppTransferToSectorNameNorm', 'ppTransferReceiverAssumed'];
const PP_FLIGHT_STATUS_PATCH_KEYS = new Set(PP_FLIGHT_STATUS_KEYS);
/** EXE/PLN ROC/D label intent (synced via ATM bucket; not host/PP physics). */
const ATM_ROC_DISPLAY_PATCH_KEYS = ['rocSelectedFpm', 'rocReadoutMode'];
/** EXE/PLN/INSTR/EVAL/OBS cleared level (synced via ATM bucket; not host/PP FMS assignedFl). */
const ATM_ALV_DISPLAY_PATCH_KEYS = ['assignedFl'];
/** XFL (exit flight level) shared laterally between EXE/PLN peers via the ATM bucket (not host FMS). */
const ATM_XFL_DISPLAY_PATCH_KEYS = ['exitLevelFl'];

/** Exercise PEL for ATM ALV at join/bootstrap (matches host FMS assignedFl at spawn; falls back to ALV). */
function getExercisePelFlForAtmDisplay(ac) {
    if (!ac) return null;
    const pel = parseInt(ac.pel, 10);
    if (Number.isFinite(pel)) return Math.max(0, Math.min(500, pel));
    const alv = parseInt(ac.alv, 10);
    if (Number.isFinite(alv)) return Math.max(0, Math.min(500, alv));
    return null;
}

/** EXE/PLN hold-label display + holding list timing (synced via ATM bucket; not FMS hold). */
const ATM_HOLD_EXE_PLN_PATCH_KEYS = [
    'atmHoldLabelWaypointId', 'atmHoldLabelWaypointName',
    'atmHoldEntrySimSec', 'atmHoldEntryWaypointId', 'atmHoldMaxTiHMin'
];
const ATM_HOLD_LABEL_PATCH_KEYS = ['atmHoldLabelWaypointId', 'atmHoldLabelWaypointName'];

/** HDG/DCT label on EXE/PLN only — never from host/PP FMS; synced EXE↔PLN via ATM bucket. */
const ATM_JOINER_DCT_LABEL_KEYS = [
    'selectedHeadingDeg', 'directToWpIdx', 'directToWpName',
    'silentDirectToWpIdx', 'silentDirectToTurnWpIdx',
    'selectedApproachId', 'selectedApproachName', 'approachActive'
];

/** Heading-nav command state shared EXE↔PLN when either issues HDG/DCT (not host FMS). */
const ATM_JOINER_PEER_NAV_STATE_KEYS = [
    'headingNavLat', 'headingNavLon', 'headingNavLastUpdateSimSec',
    'headingTurnTargetDeg', 'headingTurnStartSimSec', 'headingTurnRateDps', 'currentHeadingDeg',
    '_headingNavStatesEntries'
];

/** Host ATM sync must never push these (joiner-local or EXE/PLN command domain). */
const ATM_HOST_OMIT_ATM_PATCH_KEYS = new Set([
    ...ATM_JOINER_DCT_LABEL_KEYS,
    ...ATM_JOINER_PEER_NAV_STATE_KEYS,
    'routeProgressIdx', 'routeCompleted', 'navMode',
    'destRunwayId', 'destRunwayEnd', 'destRunwayEndName'
]);

/** Runway label — HOST/PP via FMS state; EXE/PLN via ATM bucket peer sync. */
const RUNWAY_LABEL_KEYS = ['destRunwayId', 'destRunwayEnd', 'destRunwayEndName'];
const RUNWAY_LABEL_KEY_SET = new Set(RUNWAY_LABEL_KEYS);

/** Route polyline + EXE/PLN runway label (peer lateral via ATM bucket). */
const ATM_PATCH_ROUTE_GEOMETRY_KEYS = new Set([
    'points',
    ...RUNWAY_LABEL_KEYS
]);

/** Route + EXE/PLN command fields (peer sync via ATM bucket). */
const ATM_PATCH_LATERAL_GEOMETRY_KEYS = new Set([
    ...ATM_PATCH_ROUTE_GEOMETRY_KEYS,
    ...ATM_JOINER_DCT_LABEL_KEYS,
    ...ATM_JOINER_PEER_NAV_STATE_KEYS
]);

function isJoinerAtmDisplayClient() {
    if (!simulationJoinedSessionId || isJoinerPpClient()) return false;
    return JOIN_ATM_TRAJECTORY_DISPLAY_ROLES.has(String(simulationJoinRole || '').toUpperCase());
}

function isJoinerAtmTrajectoryEditor() {
    if (!simulationJoinedSessionId || isJoinerPpClient()) return false;
    return JOIN_ATM_TRAJECTORY_EDITOR_ROLES.has(String(simulationJoinRole || '').toUpperCase());
}

let _atmTrajectoryPostTimer = null;
/** EXE: metadata-only ATM updates (XLV, ASSUME) queue POST per aircraft id — never broadcast full joinerExeAircraftPatches. */
let _joinerAtmMetadataPostPendingIds = null;
let _joinerAtmMetadataPostTimer = null;
/** TIN→ASM on receiving sector: ignore stale GET atmTrajectory until server bucket matches (avoids TIN flash + XLV clobber from metadata POST). */
let _joinerAtmReceiverAssumeStickyByAid = {};
/** After sender TOU rollback: prefer joinerExe over stale bucket until GET reflects cleared transfer; cleared on new transfer or when server patch has no outbound handoff. */
let _joinerAtmTouRollbackPendingByAid = {};
/** EXE/PLN hold-label cancel POST not yet in session bucket: ignore stale GET hold fields until server clears them. */
let _joinerAtmHoldLabelClearPendingByAid = {};
/** Outbound transfer POST not yet in session bucket: do not copy transfer fields from ac→joinerExe during sync (stale ac would wipe joinerExe TOU before applyJoinerExePatchesAfterStateSync). Cleared when bucket patch p shows active transfer. */
let _joinerAtmOutboundTransferPostPendingByAid = {};
/** EXE: only these aircraft ids are POSTed on the next trajectory batch (DCT/route edits must not re-push stale patches for other aircraft). */
let _joinerAtmTrajectoryPostPendingIds = null;

/** Keep local EXE/PLN ALV/ROC until GET atmTrajectory bucket matches what we posted. */
function markJoinerAtmTrajectoryPostPending(aid) {
    if (aid == null || aid === '') return;
    if (!_joinerAtmTrajectoryPostPendingIds) _joinerAtmTrajectoryPostPendingIds = new Set();
    _joinerAtmTrajectoryPostPendingIds.add(String(aid));
}

function joinerAtmDisplayPatchMatchesJoinerExe(ac, keys) {
    if (!ac || ac.id == null || !joinerExeAircraftPatches) return false;
    const jp = joinerExeAircraftPatches[String(ac.id)];
    const sp = ac._atmTrajectoryPatch;
    if (!jp || !sp || typeof jp !== 'object' || typeof sp !== 'object') return false;
    for (const k of keys) {
        if (!Object.prototype.hasOwnProperty.call(jp, k)) continue;
        if (!Object.prototype.hasOwnProperty.call(sp, k)) return false;
        const a = jp[k];
        const b = sp[k];
        if (typeof a === 'number' || typeof b === 'number') {
            if (Number(a) !== Number(b)) return false;
        } else if (String(a) !== String(b)) return false;
    }
    return true;
}

function joinerAtmPatchFieldEqual(key, a, b) {
    if (key === 'points') {
        return getAircraftPointsGeometrySignature({ points: a }) === getAircraftPointsGeometrySignature({ points: b });
    }
    if (key === '_headingNavStatesEntries' || key === 'approachActive') {
        try {
            return JSON.stringify(a) === JSON.stringify(b);
        } catch (e) {
            return a === b;
        }
    }
    if (typeof a === 'number' || typeof b === 'number') return Number(a) === Number(b);
    return String(a ?? '') === String(b ?? '');
}

/** Strip joiner-local progress from incoming ATM bucket; preserve EXE/PLN peer HDG/DCT (host cannot POST these keys). */
function sanitizeJoinerIncomingAtmPatch(ac, rawPatch, pendingLocalPost, hostDctSnap) {
    if (!rawPatch || typeof rawPatch !== 'object') return rawPatch;
    let p;
    try {
        p = JSON.parse(JSON.stringify(rawPatch));
    } catch (e) {
        return rawPatch;
    }
    if (!isJoinerAtmDisplayClient() || !ac || ac.id == null) return p;
    const aid = String(ac.id);
    const jp = joinerExeAircraftPatches && joinerExeAircraftPatches[aid];
    for (const k of ATM_JOINER_DCT_LABEL_KEYS) {
        if (!Object.prototype.hasOwnProperty.call(p, k)) continue;
        if (pendingLocalPost && jp && Object.prototype.hasOwnProperty.call(jp, k)) {
            p[k] = jp[k];
        }
    }
    for (const k of ATM_JOINER_PEER_NAV_STATE_KEYS) {
        if (!Object.prototype.hasOwnProperty.call(p, k)) continue;
        if (pendingLocalPost && jp && Object.prototype.hasOwnProperty.call(jp, k)) {
            p[k] = jp[k];
        }
    }
    for (const k of ATM_PATCH_JOINER_LOCAL_PROGRESS_KEYS) {
        delete p[k];
    }
    return p;
}

function serverAtmPatchExplicitlyClearsJoinerDctDisplay(rawPatch) {
    if (!rawPatch || typeof rawPatch !== 'object') return false;
    let sawKey = false;
    for (const k of ATM_JOINER_DCT_LABEL_KEYS) {
        if (!Object.prototype.hasOwnProperty.call(rawPatch, k)) continue;
        sawKey = true;
        const v = rawPatch[k];
        if (v != null && v !== '') return false;
    }
    return sawKey;
}

function extractAtmDctDisplayFieldsFromPatch(patch) {
    const out = {};
    if (!patch || typeof patch !== 'object') return out;
    for (const k of [...ATM_JOINER_DCT_LABEL_KEYS, ...ATM_JOINER_PEER_NAV_STATE_KEYS]) {
        if (!Object.prototype.hasOwnProperty.call(patch, k)) continue;
        try {
            out[k] = JSON.parse(JSON.stringify(patch[k]));
        } catch (e) {
            out[k] = patch[k];
        }
    }
    return out;
}

function joinerExeDctDisplayDiffersFromServer(ac) {
    if (!ac || ac.id == null) return false;
    const sp = ac._atmTrajectoryPatch;
    const jp = joinerExeAircraftPatches && joinerExeAircraftPatches[String(ac.id)];
    const dct = extractAtmDctDisplayFieldsFromPatch(sp);
    if (Object.keys(dct).length) {
        if (!jp || typeof jp !== 'object') return true;
        for (const [k, v] of Object.entries(dct)) {
            if (!Object.prototype.hasOwnProperty.call(jp, k)) return true;
            if (!joinerAtmPatchFieldEqual(k, jp[k], v)) return true;
        }
        return false;
    }
    if (!jp || typeof jp !== 'object') return false;
    for (const k of ATM_JOINER_DCT_LABEL_KEYS) {
        if (Object.prototype.hasOwnProperty.call(jp, k) && jp[k] != null && jp[k] !== '') return true;
    }
    return false;
}

function applyJoinerExeDctDisplayFieldsToAircraft(ac, jp) {
    if (!ac) return;
    const src = (jp && typeof jp === 'object') ? jp : {};
    for (const k of ATM_JOINER_DCT_LABEL_KEYS) {
        ac[k] = Object.prototype.hasOwnProperty.call(src, k) ? src[k] : null;
    }
    if (Object.prototype.hasOwnProperty.call(src, '_headingNavStatesEntries') && Array.isArray(src._headingNavStatesEntries)) {
        ac.headingNavStatesByUpdateSec = new Map(
            src._headingNavStatesEntries.map(([kk, vv]) => [kk, vv && typeof vv === 'object' ? { ...vv } : vv])
        );
    }
    for (const k of ATM_JOINER_PEER_NAV_STATE_KEYS) {
        if (k === '_headingNavStatesEntries') continue;
        if (Object.prototype.hasOwnProperty.call(src, k)) ac[k] = src[k];
    }
}

/**
 * EXE↔PLN: mirror HDG/DCT label + peer heading-nav from ATM bucket (every poll when peer edits).
 * Uses the raw session patch when provided — bucket DCT keys are EXE/PLN-only (host POST omits them).
 */
function syncJoinerExeDctDisplayFromServerAtmPatch(ac, rawServerPatch) {
    if (!isJoinerAtmTrajectoryEditor() || !ac || ac.id == null) return false;
    const aid = String(ac.id);
    if (_joinerAtmTrajectoryPostPendingIds && _joinerAtmTrajectoryPostPendingIds.has(aid)) return false;
    const sourcePatch = (rawServerPatch && typeof rawServerPatch === 'object')
        ? rawServerPatch
        : ac._atmTrajectoryPatch;
    const dctFields = extractAtmDctDisplayFieldsFromPatch(sourcePatch);
    const jp = joinerExeAircraftPatches && joinerExeAircraftPatches[aid];
    if (Object.keys(dctFields).length) {
        if (jp && typeof jp === 'object') {
            let same = true;
            for (const [k, v] of Object.entries(dctFields)) {
                if (!Object.prototype.hasOwnProperty.call(jp, k)) { same = false; break; }
                if (!joinerAtmPatchFieldEqual(k, jp[k], v)) { same = false; break; }
            }
            if (same) return false;
        }
    } else if (!joinerExeDctDisplayDiffersFromServer(ac)) {
        return false;
    }
    if (!joinerExeAircraftPatches) joinerExeAircraftPatches = {};
    const prev = joinerExeAircraftPatches[aid] || {};
    const next = { ...prev };
    if (Object.keys(dctFields).length) {
        Object.assign(next, dctFields);
    } else if (serverAtmPatchExplicitlyClearsJoinerDctDisplay(sourcePatch)) {
        for (const k of [...ATM_JOINER_DCT_LABEL_KEYS, ...ATM_JOINER_PEER_NAV_STATE_KEYS]) {
            delete next[k];
        }
    } else {
        return false;
    }
    joinerExeAircraftPatches[aid] = next;
    applyJoinerExeDctDisplayFieldsToAircraft(ac, next);
    clearAtmSectorSequenceCachesForAircraft(ac);
    return true;
}

function joinerExeDctDisplayMatchesServerPatch(ac) {
    if (!ac || ac.id == null || !joinerExeAircraftPatches) return false;
    const jp = joinerExeAircraftPatches[String(ac.id)];
    const sp = ac._atmTrajectoryPatch;
    if (!jp || !sp || typeof jp !== 'object' || typeof sp !== 'object') return false;
    let compared = false;
    for (const k of [...ATM_JOINER_DCT_LABEL_KEYS, ...ATM_JOINER_PEER_NAV_STATE_KEYS]) {
        const onServer = Object.prototype.hasOwnProperty.call(sp, k);
        const onLocal = Object.prototype.hasOwnProperty.call(jp, k);
        if (!onServer && !onLocal) continue;
        compared = true;
        if (!onServer || !onLocal) return false;
        if (!joinerAtmPatchFieldEqual(k, jp[k], sp[k])) return false;
    }
    return compared;
}

/** Lateral route fields from server ATM bucket (excludes joiner-local progress keys). */
function extractAtmLateralFieldsFromPatch(patch) {
    const out = {};
    if (!patch || typeof patch !== 'object') return out;
    for (const k of ATM_PATCH_LATERAL_GEOMETRY_KEYS) {
        if (ATM_PATCH_JOINER_LOCAL_PROGRESS_KEYS.includes(k)) continue;
        if (!Object.prototype.hasOwnProperty.call(patch, k)) continue;
        try {
            out[k] = JSON.parse(JSON.stringify(patch[k]));
        } catch (e) {
            out[k] = patch[k];
        }
    }
    return out;
}

function joinerExeLateralMatchesServerPatch(ac) {
    if (!ac || ac.id == null || !joinerExeAircraftPatches) return false;
    const jp = joinerExeAircraftPatches[String(ac.id)];
    const sp = ac._atmTrajectoryPatch;
    if (!jp || !sp || typeof jp !== 'object' || typeof sp !== 'object') return false;
    let compared = false;
    for (const k of ATM_PATCH_ROUTE_GEOMETRY_KEYS) {
        if (!Object.prototype.hasOwnProperty.call(sp, k)) continue;
        compared = true;
        if (!Object.prototype.hasOwnProperty.call(jp, k)) return false;
        if (!joinerAtmPatchFieldEqual(k, jp[k], sp[k])) return false;
    }
    return compared;
}

/**
 * EXE/PLN/INSTR/EVAL: after GET atmTrajectory from peer editor, mirror lateral route into joinerExeAircraftPatches + ac.points.
 * Route progress idx stays local per client; only polyline / DCT / heading-nav geometry is shared.
 */
function syncJoinerExeLateralFromServerAtmPatch(ac) {
    if (!isJoinerAtmTrajectoryEditor() || !ac || ac.id == null) return false;
    const aid = String(ac.id);
    if (_joinerAtmTrajectoryPostPendingIds && _joinerAtmTrajectoryPostPendingIds.has(aid)) return false;
    const serverPatch = ac._atmTrajectoryPatch;
    if (!serverPatch || typeof serverPatch !== 'object') return false;
    const lateral = extractAtmLateralFieldsFromPatch(serverPatch);
    if (!Object.keys(lateral).length) return false;
    if (joinerExeLateralMatchesServerPatch(ac)) return false;
    if (!joinerExeAircraftPatches) joinerExeAircraftPatches = {};
    joinerExeAircraftPatches[aid] = { ...(joinerExeAircraftPatches[aid] || {}), ...lateral };
    if (Array.isArray(lateral.points) && lateral.points.length) {
        ac._atmLateralLocked = true;
        handleJoinerAtmRoutePointsChange(ac, lateral.points);
        try {
            const ptsClone = JSON.parse(JSON.stringify(lateral.points));
            ac.points = ptsClone;
            ac._trackCache = null;
            ac.routeNavTravelCacheN = null;
            if (ac.routeNavTraveledNmByUpdateSec instanceof Map) ac.routeNavTraveledNmByUpdateSec.clear();
        } catch (e) {}
        syncJoinerAtmRouteProgressFromHostDisplay(ac, { forceAdvance: true });
    }
    clearAtmSectorSequenceCachesForAircraft(ac);
    delete ac._atmTrajDrawCache;
    return true;
}

function maybeClearJoinerAtmTrajectoryPostPending(ac) {
    if (!ac || ac.id == null || !_joinerAtmTrajectoryPostPendingIds) return;
    const aid = String(ac.id);
    if (!_joinerAtmTrajectoryPostPendingIds.has(aid)) return;
    const jp = joinerExeAircraftPatches && joinerExeAircraftPatches[aid];
    if (!jp || !ac._atmTrajectoryPatch) return;
    if (joinerExeLateralMatchesServerPatch(ac) || joinerExeDctDisplayMatchesServerPatch(ac)) {
        _joinerAtmTrajectoryPostPendingIds.delete(aid);
        return;
    }
    const checkKeys = [];
    if (Object.prototype.hasOwnProperty.call(jp, 'assignedFl')) {
        checkKeys.push(...ATM_ALV_DISPLAY_PATCH_KEYS);
    }
    for (const k of ATM_ROC_DISPLAY_PATCH_KEYS) {
        if (Object.prototype.hasOwnProperty.call(jp, k)) checkKeys.push(k);
    }
    for (const k of ATM_XFL_DISPLAY_PATCH_KEYS) {
        if (Object.prototype.hasOwnProperty.call(jp, k)) checkKeys.push(k);
    }
    if (!checkKeys.length) return;
    if (joinerAtmDisplayPatchMatchesJoinerExe(ac, checkKeys)) {
        _joinerAtmTrajectoryPostPendingIds.delete(aid);
    }
}

function applyJoinerAtmDisplayPatchToLocalAircraft(ac, patch) {
    if (!ac || !patch || typeof patch !== 'object') return;
    try {
        ac._atmTrajectoryPatch = JSON.parse(JSON.stringify(patch));
        ac._atmTrajectoryPatchSig = atmTrajectoryPatchSignature(ac._atmTrajectoryPatch);
    } catch (e) {
        return;
    }
    applyAtmAlvDisplayFromPatchToAircraft(ac, patch);
    applyAtmRocDisplayFromPatchToAircraft(ac, patch);
}

/** Push one aircraft ATM patch immediately (ROC/D, ALV EXE↔PLN sync). */
function flushJoinerAtmTrajectoryPatchForAircraftId(aid) {
    if (!isJoinerAtmTrajectoryEditor() || !simulationJoinedSessionId || !joinerExeAircraftPatches) return;
    const sid = String(aid);
    const p = joinerExeAircraftPatches[sid];
    if (!p || typeof p !== 'object') return;
    markJoinerAtmTrajectoryPostPending(sid);
    let patch = null;
    try {
        patch = JSON.parse(JSON.stringify(p));
    } catch (e) {
        return;
    }
    const sessionId = simulationJoinedSessionId;
    fetch('/api/sessions/' + encodeURIComponent(sessionId) + '/atm-trajectory', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            clientId: getOrCreateJoinClientId(),
            role: String(simulationJoinRole || '').toUpperCase(),
            patches: { [sid]: patch }
        })
    })
        .then((r) => (r.ok ? r.json().catch(() => ({})) : null))
        .then(() => {
            if (!simulationJoinedSessionId || simulationJoinedSessionId !== sessionId) return;
            const ac = getSimulationAircraftById(sid);
            if (ac && patch) {
                try {
                    ac._atmTrajectoryPatch = JSON.parse(JSON.stringify(patch));
                    ac._atmTrajectoryPatchSig = atmTrajectoryPatchSignature(ac._atmTrajectoryPatch);
                } catch (e) {}
                maybeClearJoinerAtmTrajectoryPostPending(ac);
            }
        })
        .catch(() => {});
}

function schedulePostAtmTrajectoryPatches(aid) {
    if (!isJoinerAtmTrajectoryEditor() || !simulationJoinedSessionId) return;
    if (aid == null || aid === '') return;
    if (!_joinerAtmTrajectoryPostPendingIds) _joinerAtmTrajectoryPostPendingIds = new Set();
    _joinerAtmTrajectoryPostPendingIds.add(String(aid));
    if (_atmTrajectoryPostTimer) clearTimeout(_atmTrajectoryPostTimer);
    _atmTrajectoryPostTimer = setTimeout(() => {
        _atmTrajectoryPostTimer = null;
        const ids = _joinerAtmTrajectoryPostPendingIds ? [..._joinerAtmTrajectoryPostPendingIds] : [];
        _joinerAtmTrajectoryPostPendingIds = null;
        if (!joinerExeAircraftPatches || !ids.length) return;
        const patches = {};
        for (const sid of ids) {
            const p = joinerExeAircraftPatches[sid];
            if (p && typeof p === 'object') {
                try {
                    patches[sid] = JSON.parse(JSON.stringify(p));
                } catch (e) {}
            }
        }
        if (!Object.keys(patches).length) return;
        fetch('/api/sessions/' + encodeURIComponent(simulationJoinedSessionId) + '/atm-trajectory', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                clientId: getOrCreateJoinClientId(),
                role: String(simulationJoinRole || '').toUpperCase(),
                patches
            })
        })
            .then((r) => (r.ok ? r.json().catch(() => ({})) : null))
            .then(() => {
                if (!simulationJoinedSessionId) return;
                for (const sid of ids) {
                    const ac = getSimulationAircraftById(sid);
                    const patch = patches[sid];
                    if (ac && patch) {
                        try {
                            applyJoinerAtmDisplayPatchToLocalAircraft(ac, patch);
                        } catch (e) {}
                        maybeClearJoinerAtmTrajectoryPostPending(ac);
                    }
                }
            })
            .catch(() => {});
    }, 450);
}

function flushJoinerAtmMetadataPatchesOnly() {
    _joinerAtmMetadataPostTimer = null;
    if (!_joinerAtmMetadataPostPendingIds || !simulationJoinedSessionId || !joinerExeAircraftPatches) return;
    const ids = [..._joinerAtmMetadataPostPendingIds];
    _joinerAtmMetadataPostPendingIds = null;
    const patches = {};
    for (const id of ids) {
        const p = joinerExeAircraftPatches[id];
        if (p && typeof p === 'object') {
            try {
                patches[id] = JSON.parse(JSON.stringify(p));
            } catch (e) {}
        }
    }
    if (!Object.keys(patches).length) return;
    fetch('/api/sessions/' + encodeURIComponent(simulationJoinedSessionId) + '/atm-trajectory', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            clientId: getOrCreateJoinClientId(),
            role: String(simulationJoinRole || '').toUpperCase(),
            patches
        })
    }).catch(() => {});
}

function queueJoinerAtmMetadataPatchPostForAircraftId(aidStr) {
    if (!isJoinerAtmTrajectoryEditor() || !simulationJoinedSessionId) return;
    if (!_joinerAtmMetadataPostPendingIds) _joinerAtmMetadataPostPendingIds = new Set();
    _joinerAtmMetadataPostPendingIds.add(String(aidStr));
    if (_joinerAtmMetadataPostTimer) clearTimeout(_joinerAtmMetadataPostTimer);
    _joinerAtmMetadataPostTimer = setTimeout(flushJoinerAtmMetadataPatchesOnly, 450);
}

function flushJoinerAtmVerticalOnlyPatch() {
    _joinerAtmVerticalOnlyTimer = null;
    if (!_joinerAtmVerticalOnlyPending || !simulationJoinedSessionId) return;
    const patches = _joinerAtmVerticalOnlyPending;
    _joinerAtmVerticalOnlyPending = null;
    fetch('/api/sessions/' + encodeURIComponent(simulationJoinedSessionId) + '/atm-trajectory', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            clientId: getOrCreateJoinClientId(),
            role: String(simulationJoinRole || '').toUpperCase(),
            patches
        })
    }).catch(() => {});
}

/**
 * Joiner EXE/PLN/INSTR/EVAL/OBS: POST ATM metadata / vertical fields without replacing route geometry (`points`, FMS nav, etc.).
 * Server merges shallowly. EXE posts only this aircraft’s patch (not all of joinerExeAircraftPatches). Used for XLV, ASSUME (ASM), etc.
 */
function postJoinerAtmTrajectoryVerticalFields(ac, fields) {
    if (!isJoinerAtmDisplayClient() || isJoinerPpClient() || !simulationJoinedSessionId || !ac || ac.id == null) return;
    if (!fields || typeof fields !== 'object') return;
    const id = String(ac.id);
    if (isJoinerAtmTrajectoryEditor()) {
        if (!joinerExeAircraftPatches) joinerExeAircraftPatches = {};
        const merged = { ...(joinerExeAircraftPatches[id] || {}), ...fields };
        ATM_PATCH_ROUTE_GEOMETRY_KEYS.forEach((k) => { delete merged[k]; });
        for (const k of ATM_PATCH_JOINER_LOCAL_PROGRESS_KEYS) delete merged[k];
        // Do not carry stale exitLevelFl when this POST is not an explicit XLV edit (ASSUME/transfer/etc. would re-send rlv and overwrite the bucket).
        if (!Object.prototype.hasOwnProperty.call(fields, 'exitLevelFl')) delete merged.exitLevelFl;
        joinerExeAircraftPatches[id] = merged;
        clearAtmSectorSequenceCachesForAircraft(ac);
        queueJoinerAtmMetadataPatchPostForAircraftId(id);
    } else {
        _joinerAtmVerticalOnlyPending = _joinerAtmVerticalOnlyPending || {};
        const merged = { ...(_joinerAtmVerticalOnlyPending[id] || {}), ...fields };
        if (!Object.prototype.hasOwnProperty.call(fields, 'exitLevelFl')) delete merged.exitLevelFl;
        _joinerAtmVerticalOnlyPending[id] = merged;
        if (_joinerAtmVerticalOnlyTimer) clearTimeout(_joinerAtmVerticalOnlyTimer);
        _joinerAtmVerticalOnlyTimer = setTimeout(flushJoinerAtmVerticalOnlyPatch, 450);
    }
}

/**
 * Serialize ATM-relevant fields from a live aircraft (host FMS or joiner). Used for joiner POST and host→server ATM sync.
 * @param opts.skipVerticalForPp When true, omit keys in JOINER_SYNC_VERTICAL_KEYS (EXE+PP same sector).
 * @param opts.skipExitLevelFl When true, omit exitLevelFl (host sync must not push XLV — host never merges ATM bucket into ac,
 *   so ac.exitLevelFl would stay spawn rlv and overwrite deliberate joiner XLV on the server).
 * @param opts.skipPointsForHostSync When true, omit points (host FMS must not overwrite session ATM on each position sync;
 *   canonical lateral is state.atmTrajectory.patches[].points after bootstrap; joiners sync ac.points from GET).
 * @param opts.skipAtmFlightMetadataKeys When true, omit transfer + exeFlightStatus keys (host route sync; use false for explicit rollback/ASM push).
 * @param opts.skipJoinerLocalProgressKeys When true, omit routeProgressIdx/routeCompleted/navMode (joiner-local only).
 * @param opts.skipJoinerDctLabelKeys When true, omit HDG/DCT label keys (never seed from host FMS baseline).
 * @param opts.skipHostFmsAtmPatchKeys When true, omit all host-only ATM keys (HDG/DCT + peer nav + progress).
 */
function buildAtmTrajectoryPatchObjectFromAircraft(ac, opts) {
    const o = opts && typeof opts === 'object' ? opts : {};
    const skipVerticalForPp = !!o.skipVerticalForPp;
    const skipExitLevelFl = !!o.skipExitLevelFl;
    const skipPointsForHostSync = !!o.skipPointsForHostSync;
    const skipAtmFlightMetadataKeys = !!o.skipAtmFlightMetadataKeys;
    const skipAtmAlvDisplayKeys = !!o.skipAtmAlvDisplayKeys;
    const skipJoinerLocalProgressKeys = !!o.skipJoinerLocalProgressKeys;
    const skipJoinerDctLabelKeys = !!o.skipJoinerDctLabelKeys;
    const skipHostFmsAtmPatchKeys = !!o.skipHostFmsAtmPatchKeys;
    const includeExePlnRunwayLabelKeys = !!o.includeExePlnRunwayLabelKeys;
    if (!ac || ac.id == null) return null;
    const p = {};
    const copyIfDefined = (k) => {
        if (skipVerticalForPp && JOINER_SYNC_VERTICAL_KEYS.has(k)) return;
        if (skipExitLevelFl && k === 'exitLevelFl') return;
        if (skipAtmFlightMetadataKeys && ATM_FLIGHT_METADATA_PATCH_KEYS.has(k)) return;
        if (skipAtmAlvDisplayKeys && ATM_ALV_DISPLAY_PATCH_KEYS.includes(k)) return;
        if (skipJoinerLocalProgressKeys && ATM_PATCH_JOINER_LOCAL_PROGRESS_KEYS.includes(k)) return;
        if (skipJoinerDctLabelKeys && ATM_JOINER_DCT_LABEL_KEYS.includes(k)) return;
        if (skipHostFmsAtmPatchKeys && ATM_HOST_OMIT_ATM_PATCH_KEYS.has(k)) return;
        const v = ac[k];
        if (v !== undefined) p[k] = v;
    };
    [
        'assignedFl', 'alv', 'pel',
        'selectedHeadingDeg', 'directToWpIdx', 'directToWpName',
        'silentDirectToWpIdx', 'silentDirectToTurnWpIdx',
        'routeProgressIdx', 'routeCompleted', 'navMode',
        'headingNavLat', 'headingNavLon', 'headingNavLastUpdateSimSec',
        'headingTurnTargetDeg', 'headingTurnStartSimSec', 'headingTurnRateDps', 'currentHeadingDeg',
        'speedSelectedType', 'speedSelectedValue', 'speedReadoutMode', 'speedReadoutManualBand',
        'speedChangeStartSimSec', 'speedChangeDurationSec', 'speedStartKtas', 'speedTargetKtas',
        'rocSelectedFpm', 'rocReadoutMode',
        'exitLevelFl',
        'pendingModeSTargetFl', 'pendingModeSAtSimSec',
        'selectedApproachId', 'selectedApproachName',
        'atmHoldLabelWaypointId', 'atmHoldLabelWaypointName',
        'atmHoldEntrySimSec', 'atmHoldEntryWaypointId', 'atmHoldMaxTiHMin',
        'exeFlightStatus', 'exeFlightStatusAtcSectorId',
        'transferFromAtcSectorId', 'transferToSectorNameNorm', 'transferReceiverAssumed'
    ].forEach(copyIfDefined);
    if (includeExePlnRunwayLabelKeys) {
        RUNWAY_LABEL_KEYS.forEach(copyIfDefined);
    }
    if (Array.isArray(ac.points) && !skipPointsForHostSync) {
        try { p.points = JSON.parse(JSON.stringify(ac.points)); } catch (e) {}
    }
    if (ac.headingNavStatesByUpdateSec instanceof Map && ac.headingNavStatesByUpdateSec.size) {
        p._headingNavStatesEntries = Array.from(ac.headingNavStatesByUpdateSec.entries()).map(([kk, vv]) => [
            kk,
            vv && typeof vv === 'object' ? { lat: vv.lat, lon: vv.lon, hdg: vv.hdg } : vv
        ]);
    }
    if (ac.approachActive && typeof ac.approachActive === 'object') {
        try { p.approachActive = JSON.parse(JSON.stringify(ac.approachActive)); } catch (e2) {}
    }
    if (!skipVerticalForPp && ac.lastSpeedChange && typeof ac.lastSpeedChange === 'object') {
        try { p.lastSpeedChange = JSON.parse(JSON.stringify(ac.lastSpeedChange)); } catch (e3) {}
    }
    return p;
}

/** Host: push FMS-aligned ATM patch (same shape as joiner EXE patches) after waypoint progression / PP lateral. Debounced per aircraft. */
let _hostAtmSyncTimersByAid = {};
function scheduleHostAtmTrajectorySyncToServer(ac) {
    if (!isSimulationMultiplayerHost() || simulationJoinedSessionId || !ac || ac.id == null) return;
    const aid = String(ac.id);
    if (_hostAtmSyncTimersByAid[aid]) clearTimeout(_hostAtmSyncTimersByAid[aid]);
    _hostAtmSyncTimersByAid[aid] = setTimeout(() => {
        _hostAtmSyncTimersByAid[aid] = null;
        hostPushAtmTrajectoryPatchFromHostNow(ac);
    }, 200);
}

function hostPushAtmTrajectoryPatchFromHostNow(ac, opts) {
    if (!simulationSessionId || simulationJoinedSessionId || !ac || ac.id == null) return;
    const o = opts && typeof opts === 'object' ? opts : {};
    /** Default true: do not push handoff/ASM keys from host FMS (joiner ATM bucket + explicit rollback control those). */
    const skipMeta = o.skipAtmFlightMetadataKeys !== false;
    const patch = buildAtmTrajectoryPatchObjectFromAircraft(ac, {
        skipVerticalForPp: false,
        skipExitLevelFl: true,
        skipPointsForHostSync: true,
        skipAtmFlightMetadataKeys: skipMeta,
        skipAtmAlvDisplayKeys: true,
        skipHostFmsAtmPatchKeys: true
    });
    if (!patch || typeof patch !== 'object') return;
    const id = String(ac.id);
    fetch('/api/sessions/' + encodeURIComponent(simulationSessionId) + '/atm-trajectory', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            clientId: 'host',
            role: 'HOST',
            patches: { [id]: patch }
        })
    }).catch(() => {});
}

function atmTrajectoryPatchSignature(p) {
    if (!p || typeof p !== 'object') return '';
    try {
        return JSON.stringify(p);
    } catch (e) {
        return '';
    }
}

/** Sector sequence + CIN cache keys depend on ATM_Trajectory; clear when ATM patch content changes (local or from server). */
function clearAtmSectorSequenceCachesForAircraft(ac) {
    if (!ac) return;
    try {
        ac._cinFtCacheKey = null;
        ac._cinFtResult = null;
        if ('_advancedLabelSectorSequence' in ac) delete ac._advancedLabelSectorSequence;
        if ('_atmTrajDrawCache' in ac) delete ac._atmTrajDrawCache;
    } catch (e) {}
}

/** EXE editor: keep joinerExeAircraftPatches flight/transfer fields aligned with ac so the next applyJoinerExePatchesAfterStateSync does not restore stale TOU/TIN. */
function syncJoinerExeAircraftPatchesFlightMetadataFromAircraft(ac) {
    if (!isJoinerAtmTrajectoryEditor() || !joinerExeAircraftPatches || !ac || ac.id == null) return;
    const aidStr = String(ac.id);
    const jp = joinerExeAircraftPatches[aidStr];
    if (!jp || typeof jp !== 'object') return;
    const outboundPending = !!_joinerAtmOutboundTransferPostPendingByAid[aidStr];
    let next = null;
    for (const k of ATM_FLIGHT_METADATA_KEYS) {
        if (ATM_TRANSFER_METADATA_KEYS.includes(k) && outboundPending && aircraftTransferInProgress(jp) && !aircraftTransferInProgress(ac)) {
            continue;
        }
        if (Object.prototype.hasOwnProperty.call(ac, k) && jp[k] !== ac[k]) {
            if (!next) next = { ...jp };
            next[k] = ac[k];
        }
    }
    if (next) joinerExeAircraftPatches[aidStr] = next;
}

/** Transfer + flight-status metadata in ATM bucket (GET fans out to every EXE/PLN/INSTR/EVAL/OBS on the session). */
/** ROC/D display from ATM bucket (EXE ↔ PLN); does not change host/PP vertical physics. */
function applyAtmRocDisplayFromPatchToAircraft(ac, p) {
    if (!isJoinerAtmDisplayClient() || !ac) return;
    const patch = p && typeof p === 'object' ? p : {};
    const hasRocKeys = ATM_ROC_DISPLAY_PATCH_KEYS.some((k) => Object.prototype.hasOwnProperty.call(patch, k));
    if (!hasRocKeys && Object.keys(patch).length > 0) return;

    if (Object.prototype.hasOwnProperty.call(patch, 'rocSelectedFpm')) {
        const v = patch.rocSelectedFpm;
        ac.rocSelectedFpm = (v != null && Number.isFinite(Number(v))) ? Number(v) : null;
    } else if (!hasRocKeys && Object.keys(patch).length === 0) {
        ac.rocSelectedFpm = null;
    }
    if (Object.prototype.hasOwnProperty.call(patch, 'rocReadoutMode')) {
        const m = patch.rocReadoutMode;
        ac.rocReadoutMode = (m != null && String(m).trim() !== '') ? String(m).trim().toUpperCase() : 'LIVE';
    } else if (!hasRocKeys && Object.keys(patch).length === 0) {
        ac.rocReadoutMode = 'LIVE';
    }
    ac.rocManualActive = false;
    syncJoinerExeRocDisplayFromPatch(ac, patch);
}

/** ALV on label (ATM cleared level) from session bucket; host/PP FMS must not drive this on EXE/PLN. */
function applyAtmAlvDisplayFromPatchToAircraft(ac, p) {
    if (!isJoinerAtmDisplayClient() || isJoinerPpClient() || !ac) return;
    const patch = p && typeof p === 'object' ? p : {};
    const hasAlvKeys = ATM_ALV_DISPLAY_PATCH_KEYS.some((k) => Object.prototype.hasOwnProperty.call(patch, k));
    if (!hasAlvKeys && Object.keys(patch).length > 0) return;

    if (Object.prototype.hasOwnProperty.call(patch, 'assignedFl')) {
        const v = patch.assignedFl;
        const pelFallback = getExercisePelFlForAtmDisplay(ac);
        ac.assignedFl = (v != null && Number.isFinite(Number(v)))
            ? Math.max(0, Math.min(500, Math.trunc(Number(v))))
            : (pelFallback != null ? pelFallback : 0);
    } else if (!hasAlvKeys && Object.keys(patch).length === 0) {
        const pelFl = getExercisePelFlForAtmDisplay(ac);
        if (pelFl != null) ac.assignedFl = pelFl;
    }
    syncJoinerExeAlvDisplayFromPatch(ac, patch);
}

/** RWY on label (ATM bucket) from EXE/PLN peer sync; host/PP FMS runway must not drive this field. */
function applyAtmRunwayDisplayFromPatchToAircraft(ac, p) {
    if (!isJoinerAtmDisplayClient() || isJoinerPpClient() || !ac) return;
    const patch = p && typeof p === 'object' ? p : {};
    const hasRwy = RUNWAY_LABEL_KEYS.some((k) => Object.prototype.hasOwnProperty.call(patch, k));
    if (!hasRwy) return;
    const aid = String(ac.id);
    if (_joinerAtmTrajectoryPostPendingIds && _joinerAtmTrajectoryPostPendingIds.has(aid)) {
        const jp = joinerExeAircraftPatches && joinerExeAircraftPatches[aid];
        if (jp) applyRunwayLabelFieldsFromPatchObjectToAircraft(ac, jp);
        return;
    }
    applyRunwayLabelFieldsFromPatchObjectToAircraft(ac, patch);
    syncJoinerExeRunwayDisplayFromPatch(ac, patch);
}

function syncJoinerExeRunwayDisplayFromPatch(ac, p) {
    if (!isJoinerAtmTrajectoryEditor() || !joinerExeAircraftPatches || !ac || ac.id == null) return;
    if (!p || typeof p !== 'object') return;
    const aid = String(ac.id);
    const jp = joinerExeAircraftPatches[aid];
    if (!jp || typeof jp !== 'object') return;
    let next = null;
    for (const k of RUNWAY_LABEL_KEYS) {
        if (!Object.prototype.hasOwnProperty.call(p, k)) continue;
        if (!next) next = { ...jp };
        next[k] = p[k];
    }
    if (next) joinerExeAircraftPatches[aid] = next;
}

function restoreAtmRunwayDisplayAfterHostStateReplace() {
    if (!isJoinerAtmDisplayClient() || isJoinerPpClient() || !window.simulationData?.aircraft) return;
    window.simulationData.aircraft.forEach((ac) => {
        if (!ac || ac.id == null) return;
        const aid = String(ac.id);
        if (_joinerAtmTrajectoryPostPendingIds && _joinerAtmTrajectoryPostPendingIds.has(aid)) {
            const jp = joinerExeAircraftPatches && joinerExeAircraftPatches[aid];
            if (jp) applyRunwayLabelFieldsFromPatchObjectToAircraft(ac, jp);
            return;
        }
        const patch = ac._atmTrajectoryPatch;
        if (patch && RUNWAY_LABEL_KEYS.some((k) => Object.prototype.hasOwnProperty.call(patch, k))) {
            applyRunwayLabelFieldsFromPatchObjectToAircraft(ac, patch);
            return;
        }
        const jp = joinerExeAircraftPatches && joinerExeAircraftPatches[aid];
        if (jp && RUNWAY_LABEL_KEYS.some((k) => Object.prototype.hasOwnProperty.call(jp, k))) {
            applyRunwayLabelFieldsFromPatchObjectToAircraft(ac, jp);
        }
    });
}

function syncJoinerExeAlvDisplayFromPatch(ac, p) {
    if (!isJoinerAtmTrajectoryEditor() || !joinerExeAircraftPatches || !ac || ac.id == null) return;
    if (!p || typeof p !== 'object') return;
    const aid = String(ac.id);
    const jp = joinerExeAircraftPatches[aid];
    if (!jp || typeof jp !== 'object') return;
    let next = null;
    for (const k of ATM_ALV_DISPLAY_PATCH_KEYS) {
        if (!Object.prototype.hasOwnProperty.call(p, k)) continue;
        if (!next) next = { ...jp };
        next[k] = p[k];
    }
    if (next) joinerExeAircraftPatches[aid] = next;
}

function syncJoinerExeRocDisplayFromPatch(ac, p) {
    if (!isJoinerAtmTrajectoryEditor() || !joinerExeAircraftPatches || !ac || ac.id == null) return;
    if (!p || typeof p !== 'object') return;
    const aid = String(ac.id);
    const jp = joinerExeAircraftPatches[aid];
    if (!jp || typeof jp !== 'object') return;
    let next = null;
    for (const k of ATM_ROC_DISPLAY_PATCH_KEYS) {
        if (!Object.prototype.hasOwnProperty.call(p, k)) continue;
        if (!next) next = { ...jp };
        next[k] = p[k];
    }
    if (next) joinerExeAircraftPatches[aid] = next;
}

/** Mirror a peer's XFL (from the ATM bucket) into this editor's local patch so the post-merge
 * overlay (applyJoinerExePatchesAfterStateSync) does not stomp it back to a stale/baseline value. */
function syncJoinerExeXflDisplayFromPatch(ac, p) {
    if (!isJoinerAtmTrajectoryEditor() || !joinerExeAircraftPatches || !ac || ac.id == null) return;
    if (!p || typeof p !== 'object') return;
    if (!Object.prototype.hasOwnProperty.call(p, 'exitLevelFl')) return;
    const aid = String(ac.id);
    const jp = joinerExeAircraftPatches[aid];
    if (!jp || typeof jp !== 'object') return;
    joinerExeAircraftPatches[aid] = { ...jp, exitLevelFl: p.exitLevelFl };
}

function applyAtmFlightMetadataFromPatchToAircraft(ac, p) {
    if (!ac || !p || typeof p !== 'object') return;
    /** EXE/PLN/INSTR/EVAL: joinerExeAircraftPatches is applied after merge (applyJoinerExePatchesAfterStateSync) and
     * would otherwise stomp server-derived transfer/ASM metadata (e.g. transferReceiverAssumed stays false → TOU never clears). */
    const syncJoinerExeFlightMetaFromAc = () => syncJoinerExeAircraftPatchesFlightMetadataFromAircraft(ac);
    for (const k of ATM_FLIGHT_METADATA_KEYS) {
        if (Object.prototype.hasOwnProperty.call(p, k)) {
            ac[k] = p[k];
        }
    }
    const aidForRollback = String(ac.id);
    if (!aircraftTransferInProgress(p)) {
        delete _joinerAtmTouRollbackPendingByAid[aidForRollback];
    }
    if (aircraftTransferInProgress(p)) {
        delete _joinerAtmOutboundTransferPostPendingByAid[aidForRollback];
    }
    /** Server bucket may lag one GET behind a local TOU-rollback POST; next merge would apply stale TOU to ac and sync would copy it into joinerExe. Prefer joinerExe only while _joinerAtmTouRollbackPendingByAid is set (cleared on new transfer). */
    if (_joinerAtmTouRollbackPendingByAid[aidForRollback] && isJoinerAtmTrajectoryEditor() && joinerExeAircraftPatches) {
        const jp = joinerExeAircraftPatches[aidForRollback];
        if (jp && typeof jp === 'object' && aircraftTransferInProgress(p) && !aircraftTransferInProgress(jp)) {
            for (const k of ATM_FLIGHT_METADATA_KEYS) {
                if (Object.prototype.hasOwnProperty.call(jp, k)) {
                    ac[k] = jp[k];
                    if (ac._atmTrajectoryPatch && typeof ac._atmTrajectoryPatch === 'object') {
                        ac._atmTrajectoryPatch[k] = jp[k];
                    }
                }
            }
            try {
                if (ac._atmTrajectoryPatch && typeof ac._atmTrajectoryPatch === 'object') {
                    ac._atmTrajectoryPatchSig = atmTrajectoryPatchSignature(ac._atmTrajectoryPatch);
                }
            } catch (eSig) {}
        }
    }
    if (Object.prototype.hasOwnProperty.call(p, 'exitLevelFl') && p.exitLevelFl != null) {
        const xlvN = parseInt(p.exitLevelFl, 10);
        if (Number.isFinite(xlvN)) {
            ac.exitLevelFl = xlvN;
            // Keep the local EXE/PLN patch in step with the peer's XFL so the post-merge overlay
            // does not revert it (this is what surfaces the laterally-propagated XFL in EN-MGMT too).
            syncJoinerExeXflDisplayFromPatch(ac, { exitLevelFl: xlvN });
        }
    }
    const aid = String(ac.id);
    const sticky = _joinerAtmReceiverAssumeStickyByAid[aid];
    if (!sticky || sticky.exeFlightStatusAtcSectorId == null) {
        syncJoinerExeFlightMetaFromAc();
        return;
    }
    if (!aircraftTransferInProgress(ac)) {
        delete _joinerAtmReceiverAssumeStickyByAid[aid];
        syncJoinerExeFlightMetaFromAc();
        return;
    }
    const serverAsmOk = p.exeFlightStatus === 'ASM' &&
        String(p.exeFlightStatusAtcSectorId) === String(sticky.exeFlightStatusAtcSectorId) &&
        p.transferReceiverAssumed === true;
    if (serverAsmOk) {
        delete _joinerAtmReceiverAssumeStickyByAid[aid];
        syncJoinerExeFlightMetaFromAc();
        return;
    }
    ac.transferReceiverAssumed = true;
    ac.exeFlightStatus = 'ASM';
    ac.exeFlightStatusAtcSectorId = sticky.exeFlightStatusAtcSectorId;
    const patch = ac._atmTrajectoryPatch;
    if (patch && typeof patch === 'object') {
        patch.transferReceiverAssumed = true;
        patch.exeFlightStatus = 'ASM';
        patch.exeFlightStatusAtcSectorId = sticky.exeFlightStatusAtcSectorId;
    }
    syncJoinerExeFlightMetaFromAc();
}

function mergeAtmTrajectoryFromSessionState(state, hostDctSnapshots) {
    if (!isJoinerAtmDisplayClient() || !state || !state.atmTrajectory || !state.atmTrajectory.patches) return;
    try {
        simulationSessionAtmMasterClientId = state.atmTrajectory.masterClientId != null
            ? String(state.atmTrajectory.masterClientId)
            : null;
    } catch (e) {
        simulationSessionAtmMasterClientId = null;
    }
    const patches = state.atmTrajectory.patches;
    const list = window.simulationData?.aircraft;
    if (!Array.isArray(list)) return;
    for (const ac of list) {
        if (!ac || ac.id == null) continue;
        const key = String(ac.id);
        const p = patches[key] ?? patches[ac.id];
        const prevSig = ac._atmTrajectoryPatchSig ?? '';
        let nextSig = '';
        const pendingLocalAtmPost = _joinerAtmTrajectoryPostPendingIds && _joinerAtmTrajectoryPostPendingIds.has(key);
        const hostDctSnap = (hostDctSnapshots && hostDctSnapshots.get)
            ? hostDctSnapshots.get(key)
            : null;
        if (p && typeof p === 'object') {
            try {
                const sanitized = sanitizeJoinerIncomingAtmPatch(ac, p, pendingLocalAtmPost, hostDctSnap);
                // Full server patch including points — canonical ATM lateral for all DL sectors (EXE/PLN/INSTR/EVAL/OBS).
                ac._atmTrajectoryPatch = JSON.parse(JSON.stringify(sanitized));
                nextSig = atmTrajectoryPatchSignature(ac._atmTrajectoryPatch);
                applyAtmFlightMetadataFromPatchToAircraft(ac, p);
                applyAtmHoldLabelDisplayFromPatchToAircraft(ac, p);
                if (!pendingLocalAtmPost) {
                    applyAtmAlvDisplayFromPatchToAircraft(ac, p);
                    applyAtmRocDisplayFromPatchToAircraft(ac, p);
                }
                applyAtmRunwayDisplayFromPatchToAircraft(ac, p);
            } catch (e) {
                delete ac._atmTrajectoryPatch;
            }
        } else {
            delete ac._atmTrajectoryPatch;
            applyAtmHoldLabelDisplayFromPatchToAircraft(ac, {});
            if (!pendingLocalAtmPost) {
                applyAtmAlvDisplayFromPatchToAircraft(ac, {});
                applyAtmRocDisplayFromPatchToAircraft(ac, {});
            }
        }
        ac._atmTrajectoryPatchSig = nextSig;
        if (prevSig !== nextSig) clearAtmSectorSequenceCachesForAircraft(ac);
        maybeClearJoinerAtmTrajectoryPostPending(ac);
        const stillPendingLocalAtmPost = _joinerAtmTrajectoryPostPendingIds && _joinerAtmTrajectoryPostPendingIds.has(key);
        if (!stillPendingLocalAtmPost) {
            syncJoinerExeDctDisplayFromServerAtmPatch(ac, p);
        }
        if (!stillPendingLocalAtmPost && p && typeof p === 'object' && prevSig !== nextSig) {
            syncJoinerExeLateralFromServerAtmPatch(ac);
        } else if (!stillPendingLocalAtmPost && p && typeof p === 'object' && Array.isArray(p.points) && p.points.length) {
            const curPts = getJoinerAtmDisplayPoints(ac);
            if (!joinerAtmRoutePointsMatch(curPts, p.points)) {
                syncJoinerExeLateralFromServerAtmPatch(ac);
            }
        }
    }
}

/**
 * After mergeAtmTrajectoryFromSessionState: apply server bucket points to ac.points so every sector/browser matches.
 * Skips aircraft with a pending trajectory POST (local edit not yet on server).
 */
function syncCanonicalAtmPointsFromServerPatches(state) {
    if (!isJoinerAtmDisplayClient() || !state || !state.atmTrajectory || !state.atmTrajectory.patches) return;
    const patches = state.atmTrajectory.patches;
    const list = window.simulationData?.aircraft;
    if (!Array.isArray(list)) return;
    for (const ac of list) {
        if (!ac || ac.id == null) continue;
        const key = String(ac.id);
        const p = patches[key] ?? patches[ac.id];
        if (!p || !Array.isArray(p.points) || p.points.length < 1) continue;
        if (_joinerAtmTrajectoryPostPendingIds && _joinerAtmTrajectoryPostPendingIds.has(key)) continue;
        try {
            const ptsClone = JSON.parse(JSON.stringify(p.points));
            ac.points = ptsClone;
            ac._trackCache = null;
            ac.routeNavTravelCacheN = null;
            if (ac.routeNavTraveledNmByUpdateSec instanceof Map) ac.routeNavTraveledNmByUpdateSec.clear();
            if (isJoinerAtmTrajectoryEditor()) {
                if (!joinerExeAircraftPatches) joinerExeAircraftPatches = {};
                joinerExeAircraftPatches[key] = { ...(joinerExeAircraftPatches[key] || {}), points: JSON.parse(JSON.stringify(ptsClone)) };
            }
            ac._atmLateralLocked = true;
            if (isJoinerAtmDisplayClient()) {
                handleJoinerAtmRoutePointsChange(ac, ptsClone);
                applyJoinerAtmRouteProgressToAircraft(ac, ptsClone);
            }
        } catch (e) {}
    }
}

/**
 * Host session replace overwrites ac.points with host FMS; re-apply ATM line when lateral is locked.
 */
function restoreJoinerLockedAtmPointsAfterHostStateReplace(state) {
    if (!isJoinerAtmDisplayClient() || !state?.atmTrajectory?.patches) return;
    const patches = state.atmTrajectory.patches;
    const list = window.simulationData?.aircraft;
    if (!Array.isArray(list)) return;
    for (const ac of list) {
        if (!ac || ac.id == null || !ac._atmLateralLocked) continue;
        const key = String(ac.id);
        const p = patches[key] ?? patches[ac.id];
        if (p && Array.isArray(p.points) && p.points.length) continue;
        try {
            const patchPts = ac._atmTrajectoryPatch && ac._atmTrajectoryPatch.points;
            if (Array.isArray(patchPts) && patchPts.length) {
                ac.points = JSON.parse(JSON.stringify(patchPts));
                ac._trackCache = null;
                ac.routeNavTravelCacheN = null;
                if (ac.routeNavTraveledNmByUpdateSec instanceof Map) ac.routeNavTraveledNmByUpdateSec.clear();
                continue;
            }
            if (isJoinerAtmTrajectoryEditor() && joinerExeAircraftPatches) {
                const lp = joinerExeAircraftPatches[key];
                if (lp && Array.isArray(lp.points) && lp.points.length) {
                    ac.points = JSON.parse(JSON.stringify(lp.points));
                    ac._trackCache = null;
                    ac.routeNavTravelCacheN = null;
                    if (ac.routeNavTraveledNmByUpdateSec instanceof Map) ac.routeNavTraveledNmByUpdateSec.clear();
                }
            }
        } catch (e) {}
    }
}

/** @deprecated alias — use syncJoinerAtmRouteProgressFromHostDisplay */
function recomputeJoinerRouteProgressIdxFromAtm(ac) {
    syncJoinerAtmRouteProgressFromHostDisplay(ac);
}

/** ATM display geometry (non-FMS) for sector sequence and trajectory overlay on DL clients. */
function getAircraftForAtmTrajectorySequence(ac) {
    if (!isJoinerAtmDisplayClient() || !ac) return ac;
    const p = ac._atmTrajectoryPatch;
    if (!p || typeof p !== 'object') {
        applyJoinerAtmRouteProgressToAircraft(ac, getJoinerAtmDisplayPoints(ac));
        return ac;
    }
    const pts = getJoinerAtmDisplayPoints(ac);
    if (!Array.isArray(pts) || pts.length < 1) return ac;
    const patchSansProgress = { ...p };
    for (const k of ATM_PATCH_JOINER_LOCAL_PROGRESS_KEYS) delete patchSansProgress[k];
    for (const k of ATM_JOINER_DCT_LABEL_KEYS) delete patchSansProgress[k];
    for (const k of ATM_JOINER_PEER_NAV_STATE_KEYS) delete patchSansProgress[k];
    const localIdx = getJoinerAtmRouteProgressIdx(ac);
    const jp = (isJoinerAtmTrajectoryEditor() && joinerExeAircraftPatches)
        ? joinerExeAircraftPatches[String(ac.id)]
        : null;
    const dctOverlay = {};
    if (jp && typeof jp === 'object') {
        for (const k of [...ATM_JOINER_DCT_LABEL_KEYS, ...ATM_JOINER_PEER_NAV_STATE_KEYS]) {
            if (Object.prototype.hasOwnProperty.call(jp, k)) dctOverlay[k] = jp[k];
        }
    }
    return {
        ...ac,
        ...patchSansProgress,
        ...dctOverlay,
        points: pts,
        routeProgressIdx: localIdx,
        routeCompleted: pts.length >= 2 && localIdx >= pts.length - 1
    };
}

/** DCT left-click list + right-click path mode: same trajectory as ATM overlay on joiner EXE/PLN/INSTR/EVAL/OBS. */
function getAircraftForDctTrajectoryUi(ac) {
    return getAircraftForAtmTrajectorySequence(ac);
}

/**
 * DL joiners: "next" reporting fix from current ATM polyline + host aircraft position (not host FMS / _displayNext).
 */
function computeJoinerAtmNextFromDisplayPosition(ac, lat, lon) {
    if (!isJoinerAtmDisplayClient() || !ac || !isFinite(lat) || !isFinite(lon)) return null;
    const pts = getJoinerAtmDisplayPoints(ac);
    if (!Array.isArray(pts) || pts.length < 2) return null;
    const segIdx = getJoinerAtmRouteProgressIdx(ac);
    const nextIdx = segIdx + 1;
    if (nextIdx >= pts.length) return null;
    const p1 = pts[nextIdx];
    if (!p1 || !isFinite(p1.lat) || !isFinite(p1.lon)) return null;
    return { lat: p1.lat, lon: p1.lon, name: (p1.name || '').toString() };
}

/**
 * EXE/PLN/INSTR/EVAL/OBS joiners: next fix + along-track NM from the displayed trajectory only (same polyline as
 * middle-click overlay). Uses host lat/lon only for where the aircraft is; ignores HOST/PP _displayNext / _displayTraveledNm.
 */
function computeJoinerDisplayTrajectoryPositionReport(ac, lat, lon) {
    if (!isJoinerAtmDisplayClient() || !ac || !isFinite(lat) || !isFinite(lon)) {
        return { next: null, traveledNm: 0 };
    }
    const pts = getJoinerAtmDisplayPoints(ac);
    if (!Array.isArray(pts) || pts.length < 2) {
        return { next: null, traveledNm: 0 };
    }
    const segIdx = getJoinerAtmRouteProgressIdx(ac);
    const tNm = computeTraveledNmAlongRouteOnSegmentFromPosition(pts, segIdx, lat, lon);
    const next = computeJoinerAtmNextFromDisplayPosition(ac, lat, lon);
    return { next: next || null, traveledNm: isFinite(tNm) ? Math.max(0, tNm) : 0 };
}

/** Wall-clock delay after EXE ALV picker input before comparing ALV to Mode-S FL (debug log + label flash). */
const EXE_ALV_MODES_CHECK_DELAY_MS = 7000;
/** Wall-clock delay after continuous ALV≠Mode-S before EXE starts flashing ALV red. */
const EXE_ALV_MODES_DISCREPANCY_FLASH_DELAY_MS = 8000;
/** EXE: ALV flash must live outside aircraft objects — session GET replaces aircraft with new clones every poll. */
const exeAlvModeSMismatchFlashById = new Map();
/** EXE: when continuous discrepancy started (ms since epoch), per aircraft id — reset when values match. */
const exeAlvDiscrepancyFirstSeenMsById = new Map();
/** EXE: keys `${aircraftId}:${radarBoundarySec}` — logged one discrepancy line per radar boundary (after flash delay). */
const exeAlvMismatchRadarLogKeys = new Set();

function clearExeAlvModeSVerifyTimer(ac) {
    if (!ac) return;
    if (ac._exeAlvVerifyTimeoutId != null) {
        clearTimeout(ac._exeAlvVerifyTimeoutId);
        ac._exeAlvVerifyTimeoutId = null;
    }
}

function clearAllExeAlvModeSVerifyTimersFromList(list) {
    if (!Array.isArray(list)) return;
    list.forEach((a) => {
        if (!a) return;
        const sid = String(a.id);
        clearExeAlvModeSVerifyTimer(a);
        exeAlvModeSMismatchFlashById.delete(sid);
        exeAlvDiscrepancyFirstSeenMsById.delete(sid);
    });
}

/**
 * EXE only: 7s after local ALV selection, log ALV vs modeSFl (incl. pending Mode-S). ALV flash uses syncExeAlvModeSMismatchFlashForExe each draw.
 */
function resetAtmAlvModeSMismatchFlashTracking(ac) {
    if (!ac || ac.id == null || !isJoinerExeOrPlnClient()) return;
    const sid = String(ac.id);
    exeAlvModeSMismatchFlashById.delete(sid);
    exeAlvDiscrepancyFirstSeenMsById.delete(sid);
    for (const k of [...exeAlvMismatchRadarLogKeys]) {
        if (k.startsWith(`${sid}:`)) exeAlvMismatchRadarLogKeys.delete(k);
    }
}

function scheduleExeAlvModeSVerifyAfterInput(ac) {
    if (!isJoinerExeClient() || !ac || ac.id == null) return;
    clearExeAlvModeSVerifyTimer(ac);
    resetAtmAlvModeSMismatchFlashTracking(ac);
    const aid = ac.id;
    ac._exeAlvVerifyTimeoutId = setTimeout(() => {
        ac._exeAlvVerifyTimeoutId = null;
        const live = (window.simulationData?.aircraft || []).find((x) => x && x.id === aid);
        if (!live || !isJoinerExeClient()) return;
        const alvNum = parseInt(live.assignedFl ?? live.alv, 10);
        const msNum = parseInt(live.modeSFl, 10);
        const alvOk = Number.isFinite(alvNum);
        const msOk = Number.isFinite(msNum);
        const match = alvOk && msOk && alvNum === msNum;
        const pend = live.pendingModeSTargetFl;
        const msg = `EXE ALV/Mode-S check (7s after ALV input): ALV(assignedFl|alv)=${alvOk ? alvNum : '?'}` +
            ` modeSFl=${msOk ? msNum : '?'}` +
            ` pendingModeSTargetFl=${pend != null && pend !== '' ? pend : '—'}` +
            ` | MATCH=${match ? 'YES' : 'NO'}`;
        try {
            pushSimulationDebugLog('LOG', live, msg);
        } catch (e) {}
        // Flash is updated every canvas pass + each radar boundary in syncExeAlvModeSMismatchFlashForExe (not here).
        try {
            if (document.getElementById('simulationModal')?.classList.contains('active')) drawSimulationCanvas();
        } catch (e2) {}
    }, EXE_ALV_MODES_CHECK_DELAY_MS);
}

function alvModesMismatchFlashActive(ac) {
    if (!isJoinerExeOrPlnClient() || !ac || ac.id == null) return false;
    return exeAlvModeSMismatchFlashById.get(String(ac.id)) === true;
}

/**
 * EXE/PLN: every label draw, compare ATM ALV to host Mode-S. After ALV≠Mode-S continuously for EXE_ALV_MODES_DISCREPANCY_FLASH_DELAY_MS,
 * flash red; reset timer if values match or either is invalid. Radar debug log runs once per boundary only after that delay.
 */
function syncExeAlvModeSMismatchFlashForExe(ac, simSec, radarSec) {
    if (!ac || ac.id == null) return;
    if (!isJoinerExeOrPlnClient()) return;
    const sid = String(ac.id);

    const alvNum = parseInt(ac.assignedFl ?? ac.alv, 10);
    const msNum = parseInt(ac.modeSFl, 10);
    const alvOk = Number.isFinite(alvNum);
    const msOk = Number.isFinite(msNum);

    if (!alvOk || !msOk) {
        exeAlvModeSMismatchFlashById.delete(sid);
        exeAlvDiscrepancyFirstSeenMsById.delete(sid);
        return;
    }

    if (alvNum !== msNum) {
        const now = Date.now();
        let t0 = exeAlvDiscrepancyFirstSeenMsById.get(sid);
        if (t0 == null) {
            t0 = now;
            exeAlvDiscrepancyFirstSeenMsById.set(sid, t0);
        }
        const elapsed = now - t0;
        if (elapsed >= EXE_ALV_MODES_DISCREPANCY_FLASH_DELAY_MS) {
            exeAlvModeSMismatchFlashById.set(sid, true);
            const spawn = parseInt(ac.spawnTimeSec, 10) || 0;
            const interval = Math.max(1, parseInt(radarSec, 10) || 1);
            if (Number.isFinite(simSec) && simSec >= spawn) {
                const boundary = spawn + Math.floor((simSec - spawn) / interval) * interval;
                const key = `${sid}:${boundary}`;
                if (!exeAlvMismatchRadarLogKeys.has(key)) {
                    exeAlvMismatchRadarLogKeys.add(key);
                    try {
                        pushSimulationDebugLog(
                            'LOG',
                            ac,
                            `${simulationJoinRole || 'ATM'} ALV/Mode-S radar: discrepancy ALV=${alvNum} modeSFl=${msNum}`
                        );
                    } catch (eLog) {}
                    if (exeAlvMismatchRadarLogKeys.size > 800) exeAlvMismatchRadarLogKeys.clear();
                }
            }
        } else {
            exeAlvModeSMismatchFlashById.delete(sid);
        }
    } else {
        exeAlvModeSMismatchFlashById.delete(sid);
        exeAlvDiscrepancyFirstSeenMsById.delete(sid);
        for (const k of [...exeAlvMismatchRadarLogKeys]) {
            if (k.startsWith(`${sid}:`)) exeAlvMismatchRadarLogKeys.delete(k);
        }
    }
}

/** PP no longer uses pp-vertical (empty payload). Speed/ALV go via pp-lateral to host. */
const PP_VERTICAL_PROPAGATION_KEYS = [];

/** Host vertical truth on GET merge (EXE+PP: do not re-apply stale EXE patch for these). Not included: speed *selection* (EXE-only) or assignedFl/alv/pel. */
const JOINER_SYNC_VERTICAL_KEYS = new Set([
    'lastSpeedChange',
    'modeSFl', 'pendingModeSTargetFl', 'pendingModeSAtSimSec',
    'modeCFeet', 'publishedModeCFeet', 'rocFpm', 'rocTargetFpm', 'rocRampStartSimSec', 'rocRampDurationSec', 'rocRampStartFpm', 'publishedRocFpm',
    'modeSTasKt', 'publishedModeSTasKt', 'publishedLabelGsKt'
]);

/**
 * Joiners read altitude/speed/ROC from polled session state only (host is master).
 */
function shouldSkipJoinerVerticalSpeedIntegration() {
    if (isSimulationHostFmsMaster()) return false;
    if (!simulationJoinedSessionId) return false;
    return true;
}

/** PP: host is master for trajectory + Mode-C + Gxxx; merge full aircraft from GET, keep label offsets + local speed readout (IAS/MACH/SELECTED) only. */
function applySessionStateForPpJoiner(state) {
    if (state.simulationIsPaused != null) simulationIsPaused = state.simulationIsPaused;
    if (state.simulationOperationModeId) simulationOperationModeId = state.simulationOperationModeId;
    syncJoinerClockFromHostState(state);
    const inc = state.simulationData;
    const prev = window.simulationData;
    if (!inc || !prev || !Array.isArray(prev.aircraft)) return;
    ['waypoints', 'routes', 'boundaries', 'sector', 'exercise', 'flights'].forEach((k) => {
        if (inc[k] !== undefined) prev[k] = inc[k];
    });
    const incList = Array.isArray(inc.aircraft) ? inc.aircraft : [];
    const labelOffsetsById = new Map();
    /** PP-only: IAS/MACH/SELECTED readout toggle is local; host state would reset it every poll. */
    const ppSpeedReadoutPrefsById = new Map();
    /** Host-sampled history dots: preserve ring buffer across poll-driven aircraft replace. */
    const joinerTrailById = new Map();
    prev.aircraft.forEach((ac) => {
        if (!ac || ac.id == null) return;
        labelOffsetsById.set(ac.id, {
            labelOffsetX: ac.labelOffsetX,
            labelOffsetY: ac.labelOffsetY
        });
        ppSpeedReadoutPrefsById.set(ac.id, {
            speedReadoutMode: ac.speedReadoutMode,
            speedReadoutManualBand: ac.speedReadoutManualBand,
            rocReadoutMode: ac.rocReadoutMode,
            rocSelectedFpm: ac.rocSelectedFpm,
            rocManualActive: ac.rocManualActive
        });
        if (Array.isArray(ac._joinerTrailSamples) && ac._joinerTrailSamples.length) {
            joinerTrailById.set(ac.id, ac._joinerTrailSamples.map((s) => ({
                simSec: Number(s.simSec),
                lat: s.lat,
                lon: s.lon
            })));
        }
    });
    const nextAircraft = [];
    incList.forEach((inAc) => {
        if (!inAc || inAc.id == null) return;
        let clone;
        try {
            clone = JSON.parse(JSON.stringify(inAc));
        } catch (e) {
            return;
        }
        const lo = labelOffsetsById.get(inAc.id);
        if (lo) {
            if (Number.isFinite(lo.labelOffsetX)) clone.labelOffsetX = lo.labelOffsetX;
            if (Number.isFinite(lo.labelOffsetY)) clone.labelOffsetY = lo.labelOffsetY;
        }
        const rp = ppSpeedReadoutPrefsById.get(inAc.id);
        if (rp) {
            const m = rp.speedReadoutMode;
            if (m != null && String(m).trim() !== '') clone.speedReadoutMode = m;
            if (rp.speedReadoutManualBand != null && rp.speedReadoutManualBand !== '') {
                clone.speedReadoutManualBand = rp.speedReadoutManualBand;
            }
        }
        const aidStr = String(inAc.id);
        const pendingRocH = ppJoinerPendingRocHundredsById[aidStr];
        const hostRocH = (clone.rocManualActive && Number.isFinite(Number(clone.rocSelectedFpm)))
            ? Math.round(Number(clone.rocSelectedFpm) / 100 / 5) * 5
            : null;
        if (Number.isFinite(pendingRocH)) {
            if (hostRocH === pendingRocH) {
                delete ppJoinerPendingRocHundredsById[aidStr];
            } else {
                clone.rocSelectedFpm = pendingRocH * 100;
                clone.rocReadoutMode = 'SELECTED';
                clone.rocManualActive = true;
            }
        }
        const pendingAlvFl = ppJoinerPendingAlvFlById[aidStr];
        const hostAlvFl = Number.isFinite(Number(clone.assignedFl))
            ? Math.trunc(Number(clone.assignedFl))
            : (Number.isFinite(Number(clone.alv)) ? Math.trunc(Number(clone.alv)) : null);
        if (Number.isFinite(pendingAlvFl)) {
            if (hostAlvFl === pendingAlvFl) {
                delete ppJoinerPendingAlvFlById[aidStr];
            } else {
                clone.assignedFl = pendingAlvFl;
            }
        }
        const pendingRwy = ppJoinerPendingDestRunwayById[aidStr];
        if (pendingRwy && pendingRwy.rwId != null && pendingRwy.rwEnd && pendingRwy.rwName) {
            const hostRwyOk = String(clone.destRunwayId) === String(pendingRwy.rwId)
                && String(clone.destRunwayEnd) === String(pendingRwy.rwEnd)
                && String(clone.destRunwayEndName || '').toUpperCase() === String(pendingRwy.rwName).toUpperCase();
            if (hostRwyOk) {
                delete ppJoinerPendingDestRunwayById[aidStr];
            } else {
                clone.destRunwayId = String(pendingRwy.rwId);
                clone.destRunwayEnd = pendingRwy.rwEnd;
                clone.destRunwayEndName = String(pendingRwy.rwName).toUpperCase();
                clone.selectedApproachId = null;
                clone.selectedApproachName = null;
            }
        }
        if (!Number.isFinite(pendingRocH) && rp) {
            const rm = (rp.rocReadoutMode != null && String(rp.rocReadoutMode).trim() !== '')
                ? String(rp.rocReadoutMode).trim().toUpperCase()
                : null;
            const localSelFpm = Number.isFinite(Number(rp.rocSelectedFpm)) ? Number(rp.rocSelectedFpm) : null;
            const hostHasManualRoc = !!(clone.rocManualActive && Number.isFinite(Number(clone.rocSelectedFpm)));
            if (rm) clone.rocReadoutMode = rm;
            if (localSelFpm != null && (rm === 'SELECTED' || rp.rocManualActive) && !hostHasManualRoc) {
                clone.rocSelectedFpm = localSelFpm;
                clone.rocReadoutMode = rm || 'SELECTED';
                clone.rocManualActive = true;
            }
        }
        const tr = joinerTrailById.get(inAc.id);
        if (tr && tr.length) clone._joinerTrailSamples = tr;
        nextAircraft.push(clone);
    });
    preserveJoinerHeldDisplayAcrossAircraftReplace(prev.aircraft, nextAircraft);
    prev.aircraft = nextAircraft;
    mergePpFlightStatusFromSessionState(state);
    maybeRefreshPpSectorPeersThrottled(simulationJoinedSessionId);
}

function applyPpFlightStatusPatchToAircraft(ac, patch) {
    if (!ac || !patch || typeof patch !== 'object') return;
    ac._ppFlightStatusPatch = patch;
    PP_FLIGHT_STATUS_KEYS.forEach((k) => {
        if (Object.prototype.hasOwnProperty.call(patch, k)) ac[k] = patch[k];
    });
}

function mergePpFlightStatusFromSessionState(state) {
    if (!usesPpFmsFlightStatusDomain()) return;
    const patches = state?.ppFlightStatus?.patches;
    if (!patches || typeof patches !== 'object') return;
    const list = window.simulationData?.aircraft;
    if (!Array.isArray(list)) return;
    list.forEach((ac) => {
        if (!ac || ac.id == null) return;
        const p = patches[String(ac.id)];
        if (p && typeof p === 'object') applyPpFlightStatusPatchToAircraft(ac, p);
    });
}

function postPpFlightStatusFields(ac, fields) {
    if (!ac || ac.id == null || !fields || typeof fields !== 'object') return;
    if (!ac._ppFlightStatusPatch || typeof ac._ppFlightStatusPatch !== 'object') ac._ppFlightStatusPatch = {};
    Object.assign(ac._ppFlightStatusPatch, fields);
    PP_FLIGHT_STATUS_KEYS.forEach((k) => {
        if (Object.prototype.hasOwnProperty.call(fields, k)) ac[k] = fields[k];
    });
    const sid = simulationJoinedSessionId || simulationSessionId;
    if (!sid) return;
    const clientId = simulationJoinClientId || 'host';
    fetch('/api/sessions/' + encodeURIComponent(sid) + '/pp-flight-status', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ clientId, aircraft: { [String(ac.id)]: fields } })
    }).catch(() => {});
}

function buildPpVerticalPushPayload() {
    // Speed/ALV use pp-lateral to host; pp-vertical merge is disabled server-side.
    return { aircraft: {} };
}

function startJoinPpVerticalPush() {
    if (simulationJoinPpVerticalPushIntervalId) {
        clearInterval(simulationJoinPpVerticalPushIntervalId);
        simulationJoinPpVerticalPushIntervalId = null;
    }
    if (!isJoinerPpClient() || !simulationJoinedSessionId || !simulationJoinClientId) return;
    const sid = simulationJoinedSessionId;
    const cid = simulationJoinClientId;
    const tick = () => {
        if (!simulationJoinedSessionId || simulationJoinedSessionId !== sid) return;
        if (!isJoinerPpClient()) return;
        const { aircraft } = buildPpVerticalPushPayload();
        if (!aircraft || !Object.keys(aircraft).length) return;
        fetch('/api/sessions/' + encodeURIComponent(sid) + '/pp-vertical', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ clientId: cid, aircraft })
        }).catch(() => {});
    };
    tick();
    simulationJoinPpVerticalPushIntervalId = setInterval(tick, 450);
}

let simulationHostPpLateralPollIntervalId = null;
let hostPpLateralPollInFlight = false;
let hostLastAppliedPpLateralSeqById = {};
let ppJoinerLateralCmdSeqById = {};
/** PP ROC/D POST not yet reflected in host state (label stays SELECTED until host applies). */
let ppJoinerPendingRocHundredsById = {};
/** PP ALV POST not yet reflected in host state (label stays until host assignedFl matches). */
let ppJoinerPendingAlvFlById = {};
/** PP RWY POST not yet reflected in host state (label stays until host destRunway matches). */
let ppJoinerPendingDestRunwayById = {};

function ppJoinerPostLateralCommand(aircraftId, cmd) {
    if (!isJoinerPpClient() || !simulationJoinedSessionId || !simulationJoinClientId || aircraftId == null || !cmd) return;
    const sid = String(aircraftId);
    const ctype = String(cmd.type || '').toUpperCase();
    if (ctype === 'ROC') {
        const rv = parseInt(cmd.value, 10);
        if (Number.isFinite(rv)) ppJoinerPendingRocHundredsById[sid] = rv;
    } else if (ctype === 'ALV') {
        delete ppJoinerPendingRocHundredsById[sid];
        const tf = parseInt(cmd.targetFl, 10);
        if (Number.isFinite(tf)) ppJoinerPendingAlvFlById[sid] = Math.max(0, Math.min(500, tf));
    } else if (ctype === 'RWY') {
        const rwId = cmd.rwId != null ? String(cmd.rwId) : null;
        const rwEnd = (cmd.rwEnd === 'A' || cmd.rwEnd === 'B') ? cmd.rwEnd : null;
        const rwName = cmd.rwName != null ? String(cmd.rwName).trim().toUpperCase() : null;
        if (rwId && rwEnd && rwName) {
            ppJoinerPendingDestRunwayById[sid] = { rwId, rwEnd, rwName };
        }
    }
    ppJoinerLateralCmdSeqById[sid] = (ppJoinerLateralCmdSeqById[sid] || 0) + 1;
    const cmdSeq = ppJoinerLateralCmdSeqById[sid];
    const sessionId = simulationJoinedSessionId;
    fetch('/api/sessions/' + encodeURIComponent(sessionId) + '/pp-lateral', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ clientId: simulationJoinClientId, aircraft: { [sid]: { cmdSeq, cmd } } })
    })
        .then((r) => r.json().then((data) => ({ ok: r.ok, data })).catch(() => ({ ok: r.ok, data: null })))
        .then(({ ok, data }) => {
            if (!ok || !data || !data.ok) {
                try {
                    pushSimulationDebugLog('LOG', null, `PP lateral POST failed (${ctype})`);
                } catch (eLog) {}
                return;
            }
            const stored = data.stored && typeof data.stored === 'object' ? data.stored[sid] : null;
            if (stored && Number.isFinite(Number(stored.cmdSeq))) {
                ppJoinerLateralCmdSeqById[sid] = Number(stored.cmdSeq);
            }
        })
        .catch(() => {
            try {
                pushSimulationDebugLog('LOG', null, `PP lateral POST network error (${ctype})`);
            } catch (eNet) {}
        });
}

/** Host runs DL heading command (used for PP → host HDG). */
function applySimulationDlHeadingCommandFromDeg(ac, headingDeg, opts = {}) {
    if (!ac || simulationOperationModeId !== 'DL') return;
    const immediate = !!opts.immediate;
    const suppressTts = !!opts.suppressTts;
    const h = Math.round(Number(headingDeg));
    if (!Number.isFinite(h)) return;
    ac.selectedHeadingDeg = h;
    ac.directToWpIdx = null;
    ac.directToWpName = null;
    ac.selectedApproachId = null;
    ac.selectedApproachName = null;
    ac.approachActive = null;

    abandonSimulationHoldingsForNewLateralNav(ac);

    const simTimeSec = getEffectiveSimulationSimTimeMs() / 1000;
    const delaySec = immediate ? 0 : (5 + Math.random() * 5);
    ac.headingTurnTargetDeg = heading0to359(ac.selectedHeadingDeg);
    ac.headingTurnStartSimSec = simTimeSec + delaySec;
    ac.headingTurnRateDps = pickTurnRateDpsForAircraft(ac);

    try {
        const simSec = getSimulationClockSeconds();
        const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
        const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
        const stNow = getAircraftPositionAtRadarUpdate(ac, simSec, radarSec);
        const spawn = parseInt(ac.spawnTimeSec, 10) || 0;
        const elapsedSinceSpawn = Math.max(0, simSec - spawn);
        const elapsedAtLastUpdate = Math.floor(elapsedSinceSpawn / radarSec) * radarSec;
        const lastUpdateSimSec = spawn + elapsedAtLastUpdate;
        const baseLat = (stNow && isFinite(stNow.lat)) ? stNow.lat : (isFinite(ac.headingNavLat) ? ac.headingNavLat : null);
        const baseLon = (stNow && isFinite(stNow.lon)) ? stNow.lon : (isFinite(ac.headingNavLon) ? ac.headingNavLon : null);
        const baseUpdateSec = (stNow && stNow.lastUpdateSimSec != null) ? stNow.lastUpdateSimSec : lastUpdateSimSec;

        if (baseLat != null && baseLon != null) {
            ac.navMode = 'heading';
            ac.headingNavLat = baseLat;
            ac.headingNavLon = baseLon;
            ac.headingNavLastUpdateSimSec = baseUpdateSec;
            if (!(ac.headingNavStatesByUpdateSec instanceof Map)) ac.headingNavStatesByUpdateSec = new Map();
            for (const k of ac.headingNavStatesByUpdateSec.keys()) {
                if (k > baseUpdateSec) ac.headingNavStatesByUpdateSec.delete(k);
            }
            let hdgSeed = null;
            try {
                if (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg)) hdgSeed = heading0to359(Number(ac.publishedHeadingDeg));
                else if (ac.currentHeadingDeg != null && isFinite(ac.currentHeadingDeg)) hdgSeed = heading0to359(Number(ac.currentHeadingDeg));
                else if (stNow?.next && isFinite(stNow.lat) && isFinite(stNow.lon) && isFinite(stNow.next.lat) && isFinite(stNow.next.lon)) {
                    hdgSeed = heading0to359(calculateBearingDegrees(stNow.lat, stNow.lon, stNow.next.lat, stNow.next.lon));
                }
            } catch (eH0) {}
            if (hdgSeed == null || !isFinite(hdgSeed)) hdgSeed = 0;
            ac.headingNavStatesByUpdateSec.set(baseUpdateSec, { lat: baseLat, lon: baseLon, hdg: hdgSeed });

            if (ac.currentHeadingDeg == null || !isFinite(ac.currentHeadingDeg)) {
                if (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg)) {
                    ac.currentHeadingDeg = heading0to359(ac.publishedHeadingDeg);
                } else if (stNow?.next && isFinite(stNow.lat) && isFinite(stNow.lon) && isFinite(stNow.next.lat) && isFinite(stNow.next.lon)) {
                    ac.currentHeadingDeg = heading0to359(calculateBearingDegrees(stNow.lat, stNow.lon, stNow.next.lat, stNow.next.lon));
                } else {
                    ac.currentHeadingDeg = heading0to359(ac.selectedHeadingDeg);
                }
            }
        }
    } catch (e) {}

    if (!suppressTts) {
        try {
            const targetHdg = heading0to359(ac.selectedHeadingDeg);
            let curHdg = null;
            if (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg)) curHdg = Number(ac.publishedHeadingDeg);
            else if (ac.currentHeadingDeg != null && isFinite(ac.currentHeadingDeg)) curHdg = Number(ac.currentHeadingDeg);
            const side = (curHdg != null) ? getSimulationTurnSide(curHdg, targetHdg) : null;
            const hdgDigits = formatHeadingFrom0to359(targetHdg).split('').join(' ');
            const msg = side ? `turning ${side} heading ${hdgDigits}` : `heading ${hdgDigits}`;
            queueSimulationAircraftTtsReply(ac, 'HDG', msg);
        } catch (e) {}
    }
    try {
        const hdgTxt = formatHeadingFrom0to359(heading0to359(ac.selectedHeadingDeg));
        pushSimulationDebugLog('CMD', ac, `HDG ${hdgTxt} (PP→host replay=${!!suppressTts})`);
        recordSimulationSubtitleEvent(ac, `HDG input > ${hdgTxt}`, { command: 'HDG', value: hdgTxt });
    } catch (e) {}
    captureJoinerExePatchFromAircraft(ac);
}

function formatRocLabelFromFpm(fpm) {
    const roc = Number(fpm);
    if (!isFinite(roc) || Math.abs(roc) < 10) return '*0';
    const arrow = roc > 0 ? '↑' : '↓';
    const two = Math.min(99, Math.floor(Math.abs(roc) / 100));
    return `${arrow}${String(two).padStart(2, '0')}`;
}

function rocPickerLabelFromHundreds(hundreds) {
    const h = Number(hundreds);
    if (!Number.isFinite(h) || h === 0) return '0';
    return h > 0 ? `+${h}` : String(h);
}

const ROC_ALV_CAPTURE_FT = 1000;
const ROC_EXE_PLN_DISCREPANCY_FPM = 500;

function canUseSimulationLabelFieldPickers() {
    return !simulationIsMonitorOnly
        && (simulationOperationModeId === 'DL' || isJoinerAtmTrajectoryEditor());
}

function clearAircraftRocManualSelection(ac) {
    clearAircraftRocDisplaySelection(ac);
}

function clearAircraftRocDisplaySelection(ac) {
    if (!ac) return;
    ac.rocManualActive = false;
    ac.rocSelectedFpm = null;
    ac.rocReadoutMode = 'LIVE';
    ac.rocRampStartFpm = null;
}

function getAircraftRocSelectedDisplayColor(ac) {
    if (!aircraftHasRocSelectedDisplay(ac)) return '#22C55E';
    if (isJoinerPpClient()) return '#22C55E';
    const selected = Number(ac.rocSelectedFpm);
    const live = Number(ac?.publishedRocFpm ?? ac?.rocFpm);
    if (!Number.isFinite(selected) || !Number.isFinite(live)) return '#22C55E';
    return Math.abs(selected - live) > ROC_EXE_PLN_DISCREPANCY_FPM ? '#F87171' : '#22C55E';
}

/** EXE/PLN: clear ROC/D label when aircraft has reached assigned ALV (Mode-C equals ALV). */
function maybeClearExePlnRocDisplayAtAlv(ac) {
    if (!isJoinerExeOrPlnClient() || !ac) return;
    if (!Number.isFinite(Number(ac.rocSelectedFpm))) return;
    const alv = getAircraftAlvFlForDisplay(ac);
    const mc = getAircraftModeCFlForDisplay(ac);
    if (alv == null || mc == null || alv !== mc) return;
    clearAircraftRocDisplaySelection(ac);
    captureJoinerExePatchFromAircraft(ac);
    flushJoinerAtmTrajectoryPatchForAircraftId(ac.id);
}

function aircraftHasRocSelectedDisplay(ac) {
    return Number.isFinite(Number(ac?.rocSelectedFpm))
        && String(ac?.rocReadoutMode || '').toUpperCase() === 'SELECTED';
}

function getAircraftAlvTargetFeet(ac) {
    const alv = getAircraftAlvFlForDisplay(ac);
    return alv != null ? alv * 100 : null;
}

function getAircraftRemainingFeetToAlv(ac) {
    const alvFeet = getAircraftAlvTargetFeet(ac);
    const mcFeet = Number(ac?.modeCFeet);
    if (alvFeet == null || !isFinite(mcFeet)) return null;
    return alvFeet - mcFeet;
}

function getAircraftNormalRocFpmTowardAlv(ac) {
    const remaining = getAircraftRemainingFeetToAlv(ac);
    if (remaining == null || Math.abs(remaining) < 1) return 0;
    const { climb, desc } = getAircraftDbClimbDescNormalFpm(ac?.aircraftType);
    return remaining > 0 ? climb : -Math.abs(desc);
}

function isAircraftWithinRocAlvCaptureZone(ac) {
    const rem = getAircraftRemainingFeetToAlv(ac);
    if (rem == null) return false;
    const absRem = Math.abs(rem);
    return absRem < ROC_ALV_CAPTURE_FT && absRem >= 1;
}

function selectedRocExceedsNormalTowardAlv(ac) {
    if (!Number.isFinite(Number(ac?.rocSelectedFpm))) return false;
    const selected = Number(ac.rocSelectedFpm);
    const normal = getAircraftNormalRocFpmTowardAlv(ac);
    if (!Number.isFinite(normal) || normal === 0) return false;
    if (normal > 0) return selected > normal;
    return selected < normal;
}

function clearAircraftRocRampState(ac) {
    if (!ac) return;
    ac.rocRampStartSimSec = null;
    ac.rocRampDurationSec = null;
    ac.rocRampStartFpm = null;
}

function startAircraftRocRamp(ac, targetRocFpm, simTimeSec) {
    if (!ac) return;
    const startRoc = Number(ac.rocFpm);
    ac.rocRampStartFpm = Number.isFinite(startRoc) ? startRoc : 0;
    ac.rocTargetFpm = targetRocFpm;
    ac.rocRampStartSimSec = simTimeSec;
    ac.rocRampDurationSec = 5 + Math.random() * 5;
}

function stepAircraftRocRamp(ac, simTimeSec, dtSimSec) {
    const targetRoc = Number(ac.rocTargetFpm);
    if (ac.rocRampStartSimSec != null && ac.rocRampDurationSec != null) {
        const t = (simTimeSec + dtSimSec) - ac.rocRampStartSimSec;
        const p = Math.max(0, Math.min(1, t / ac.rocRampDurationSec));
        const from = Number(ac.rocRampStartFpm);
        const startVal = Number.isFinite(from) ? from : 0;
        ac.rocFpm = startVal + (targetRoc - startVal) * p;
        if (p >= 1) {
            clearAircraftRocRampState(ac);
            ac.rocFpm = targetRoc;
        }
        return;
    }
    ac.rocFpm = targetRoc;
}

/**
 * Within 1000 ft of ALV: leave manual ROC/D, ramp to normal rate if needed, climb/descend to ALV and level off.
 */
function applyAircraftRocAlvCaptureStep(ac, simTimeSec, dtSimSec) {
    const alvFeet = getAircraftAlvTargetFeet(ac);
    if (alvFeet == null) return false;
    const remaining = getAircraftRemainingFeetToAlv(ac);
    if (remaining == null) return false;

    if (Math.abs(remaining) < 1) {
        ac.modeCFeet = alvFeet;
        ac.rocFpm = 0;
        ac.rocTargetFpm = 0;
        clearAircraftRocRampState(ac);
        clearAircraftRocManualSelection(ac);
        return true;
    }

    if (!isAircraftWithinRocAlvCaptureZone(ac)) return false;

    const normalRoc = getAircraftNormalRocFpmTowardAlv(ac);
    ac.rocManualActive = false;

    const curRoc = Number(ac.rocFpm);
    const exceedsNormal = selectedRocExceedsNormalTowardAlv(ac);
    const needsRamp = exceedsNormal && (!Number.isFinite(curRoc) || Math.abs(curRoc - normalRoc) > 25);
    if (needsRamp) {
        if (ac.rocRampStartSimSec == null || Number(ac.rocTargetFpm) !== normalRoc) {
            startAircraftRocRamp(ac, normalRoc, simTimeSec);
        }
    } else {
        ac.rocFpm = normalRoc;
        ac.rocTargetFpm = normalRoc;
        clearAircraftRocRampState(ac);
    }

    stepAircraftRocRamp(ac, simTimeSec, dtSimSec);

    let nextFeet = Number(ac.modeCFeet) + (Number(ac.rocFpm) * dtSimSec) / 60;
    if (!isFinite(nextFeet)) nextFeet = Number(ac.modeCFeet);
    if ((remaining > 0 && nextFeet >= alvFeet) || (remaining < 0 && nextFeet <= alvFeet)) {
        nextFeet = alvFeet;
        ac.modeCFeet = nextFeet;
        ac.rocFpm = 0;
        ac.rocTargetFpm = 0;
        clearAircraftRocRampState(ac);
        clearAircraftRocManualSelection(ac);
        return true;
    }
    if (nextFeet < 0) nextFeet = 0;
    ac.modeCFeet = nextFeet;
    return true;
}

/**
 * Allowed ROC/D picker values (hundreds of fpm) from ALV vs Mode-C.
 * null = level flight (ALV equals Mode-C) — no picker options.
 */
function getAircraftRocPickerAllowedHundreds(ac) {
    if (!ac) return null;
    const alv = getAircraftAlvFlForDisplay(ac);
    const mc = getAircraftModeCFlForDisplay(ac);
    if (alv == null || mc == null) return null;
    if (alv === mc) return null;
    const out = [];
    if (alv < mc) {
        for (let h = -5; h >= -50; h -= 5) out.push(h);
    } else {
        for (let h = 5; h <= 50; h += 5) out.push(h);
    }
    return out;
}

function canOpenSimulationRocPicker(ac) {
    if (isAircraftWithinRocAlvCaptureZone(ac)) return false;
    const allowed = getAircraftRocPickerAllowedHundreds(ac);
    return Array.isArray(allowed) && allowed.length > 0;
}

function isAircraftRocPickerValueAllowed(ac, valueHundreds) {
    const allowed = getAircraftRocPickerAllowedHundreds(ac);
    if (!allowed || !allowed.length) return false;
    const h = Math.trunc(Number(valueHundreds));
    return Number.isFinite(h) && allowed.includes(h);
}

function getAircraftRocPickerHundreds(ac) {
    if (ac?.rocManualActive && Number.isFinite(Number(ac.rocSelectedFpm))) {
        return Math.max(-50, Math.min(50, Math.round(Number(ac.rocSelectedFpm) / 100 / 5) * 5));
    }
    const roc = Number(ac?.publishedRocFpm ?? ac?.rocFpm);
    if (!isFinite(roc) || Math.abs(roc) < 10) return 0;
    const sign = roc > 0 ? 1 : -1;
    const mag = Math.min(50, Math.round(Math.abs(roc) / 100 / 5) * 5);
    return sign * mag;
}

function getAircraftRocLabelText(ac) {
    if (!ac) return '';
    let rocMode = (ac.rocReadoutMode || 'LIVE').toString().toUpperCase();
    const hasRocSel = aircraftHasRocSelectedDisplay(ac);
    if (rocMode === 'SELECTED' && !hasRocSel) rocMode = 'LIVE';
    const fpm = (rocMode === 'SELECTED')
        ? Number(ac.rocSelectedFpm)
        : Number(ac?.publishedRocFpm ?? ac?.rocFpm);
    return formatRocLabelFromFpm(fpm);
}

function cycleAircraftRocReadoutMode(ac) {
    if (!ac || !Number.isFinite(Number(ac.rocSelectedFpm))) return;
    const cur = (ac.rocReadoutMode || 'LIVE').toString().toUpperCase();
    ac.rocReadoutMode = (cur === 'SELECTED') ? 'LIVE' : 'SELECTED';
    if (isJoinerAtmTrajectoryEditor()) {
        captureJoinerExePatchFromAircraft(ac);
        flushJoinerAtmTrajectoryPatchForAircraftId(ac.id);
    }
}

/** EXE/PLN hosted: ROC/D on label only (ATM patch); host/PP keep physics. */
function applySimulationRocDisplayFpmSelectionToAircraft(ac, fpm, opts = {}) {
    if (!ac || !isJoinerExeOrPlnClient()) return;
    const f = Math.trunc(Number(fpm));
    if (!Number.isFinite(f) || f === 0) return;
    if (!isAircraftRocFpmAllowed(ac, f)) return;
    ac.rocManualActive = false;
    ac.rocSelectedFpm = f;
    ac.rocReadoutMode = 'SELECTED';
    try {
        recordSimulationSubtitleEvent(ac, `ROC/D input > ${formatRocCommandSubtitleLabel(f)}`, { command: 'ROC', value: f, displayOnly: true });
    } catch (e) {}
    captureJoinerExePatchFromAircraft(ac);
    flushJoinerAtmTrajectoryPatchForAircraftId(ac.id);
}

/** EXE/PLN hosted: ROC/D on label only (ATM patch); host/PP keep physics. */
function applySimulationRocDisplaySelectionToAircraft(ac, valueHundreds, opts = {}) {
    applySimulationRocFpmSelectionToAircraft(ac, Math.trunc(Number(valueHundreds)) * 100, opts);
}

/**
 * Apply ROC/D selection at exact fpm. Ramps actual ROC over 5–10 s.
 */
function applySimulationRocFpmSelectionToAircraft(ac, fpm, opts = {}) {
    if (!ac) return;
    if (isJoinerExeOrPlnClient()) {
        applySimulationRocDisplayFpmSelectionToAircraft(ac, fpm, opts);
        return;
    }
    if (simulationOperationModeId !== 'DL') return;
    const f = Math.trunc(Number(fpm));
    if (!Number.isFinite(f) || f === 0) return;
    if (!isAircraftRocFpmAllowed(ac, f)) return;
    const simTimeSec = getEffectiveSimulationSimTimeMs() / 1000;

    ac.rocManualActive = true;
    ac.rocSelectedFpm = f;
    ac.rocReadoutMode = 'SELECTED';
    ac.rocTargetFpm = f;
    const startRoc = Number(ac.rocFpm);
    ac.rocRampStartFpm = Number.isFinite(startRoc) ? startRoc : 0;
    ac.rocRampStartSimSec = simTimeSec;
    ac.rocRampDurationSec = 5 + Math.random() * 5;

    try {
        recordSimulationSubtitleEvent(ac, `ROC/D input > ${formatRocCommandSubtitleLabel(f)}`, { command: 'ROC', value: f });
        pushSimulationDebugLog('CMD', ac, `ROC/D ${formatRocCommandSubtitleLabel(f)}`);
    } catch (e) {}

    if (isJoinerAtmTrajectoryEditor()) captureJoinerExePatchFromAircraft(ac);
}

/**
 * Apply ROC/D selection (picker value in hundreds: -50..50 step 5 → fpm). Ramps actual ROC over 5–10 s.
 */
function applySimulationRocSelectionToAircraft(ac, valueHundreds, opts = {}) {
    applySimulationRocFpmSelectionToAircraft(ac, Math.trunc(Number(valueHundreds)) * 100, opts);
}

/** Host: apply PP ROC/D (PP already validated picker range). */
function applyHostRocCommandFromPp(ac, valueHundreds) {
    if (!ac || simulationOperationModeId !== 'DL') return false;
    const h = Math.max(-50, Math.min(50, Math.trunc(Number(valueHundreds))));
    if (!Number.isFinite(h) || (h % 5) !== 0) return false;
    const fpm = h * 100;
    const simTimeSec = getEffectiveSimulationSimTimeMs() / 1000;
    ac.rocManualActive = true;
    ac.rocSelectedFpm = fpm;
    ac.rocReadoutMode = 'SELECTED';
    ac.rocTargetFpm = fpm;
    const startRoc = Number(ac.rocFpm);
    ac.rocRampStartFpm = Number.isFinite(startRoc) ? startRoc : 0;
    ac.rocRampStartSimSec = simTimeSec;
    ac.rocRampDurationSec = 5 + Math.random() * 5;
    try {
        pushSimulationDebugLog('CMD', ac, `ROC/D PP→host ${rocPickerLabelFromHundreds(h)} (${fpm} fpm)`);
        recordSimulationSubtitleEvent(ac, `ROC/D input > ${rocPickerLabelFromHundreds(h)}`, { command: 'ROC', value: h, fromPp: true });
    } catch (e) {}
    return true;
}

/** Host: push state immediately after PP lateral apply so joiners see vertical changes without waiting for the next interval. */
function pushHostSessionStateNowIfHosting() {
    if (!simulationSessionId || simulationJoinedSessionId || hostStatePutInFlight || hostReconnectPhase) return;
    const state = buildSessionState();
    if (!state) return;
    const sid = simulationSessionId;
    hostStatePutInFlight = true;
    fetch('/api/sessions/' + encodeURIComponent(sid) + '/state', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(state)
    })
        .then((r) => r.json().then((data) => ({ ok: r.ok, data })).catch(() => ({ ok: r.ok, data: null })))
        .then(({ ok, data }) => {
            hostStatePutInFlight = false;
            if (ok && data && data.ppLateral) applyHostPpLateralSnapshotToLocalSim({ aircraft: data.ppLateral });
            if (ok && data && data.ppFlightStatus) mergePpFlightStatusFromSessionState({ ppFlightStatus: data.ppFlightStatus });
        })
        .catch(() => { hostStatePutInFlight = false; });
}

/** EXE/PLN: ALV label only (ATM bucket); does not change host FMS vertical physics. */
function applySimulationAlvDisplaySelectionToAircraft(ac, targetFl) {
    if (!ac || !isJoinerExeOrPlnClient()) return false;
    const next = Math.max(0, Math.min(500, Math.trunc(Number(targetFl))));
    if (!Number.isFinite(next) || next % 10 !== 0) return false;
    const alvNow = Math.max(0, Math.min(500, parseInt(ac.assignedFl ?? ac.alv, 10) || 0));
    if (next === alvNow) return false;
    ac.assignedFl = next;
    if (ac._atmTrajectoryPatch && typeof ac._atmTrajectoryPatch === 'object') {
        ac._atmTrajectoryPatch.assignedFl = next;
        try { ac._atmTrajectoryPatchSig = atmTrajectoryPatchSignature(ac._atmTrajectoryPatch); } catch (e) {}
    }
    try {
        recordSimulationSubtitleEvent(ac, `ALV input > ${String(next).padStart(3, '0')}`, { command: 'ALV', value: next, displayOnly: true });
    } catch (e) {}
    captureJoinerExePatchFromAircraft(ac);
    flushJoinerAtmTrajectoryPatchForAircraftId(ac.id);
    return true;
}

/**
 * Host/solo FMS ALV: label updates immediately; Mode-S follows after 3–6 s; then Mode-C climbs/descends.
 * Returns false when level unchanged (ALV and Mode-S already match).
 */
function applySimulationAlvLevelToAircraft(ac, targetFl, opts = {}) {
    if (isJoinerExeOrPlnClient()) {
        return applySimulationAlvDisplaySelectionToAircraft(ac, targetFl);
    }
    if (!ac || simulationOperationModeId !== 'DL') return false;
    const next = Math.max(0, Math.min(500, Math.trunc(Number(targetFl))));
    if (!Number.isFinite(next) || next % 10 !== 0) return false;
    const alvNow = Math.max(0, Math.min(500, parseInt(ac.assignedFl ?? ac.alv, 10) || 0));
    const msNow = Math.max(0, Math.min(500, parseInt(ac.modeSFl ?? ac.alv, 10) || 0));
    if (next === alvNow && next === msNow) return false;

    const playTts = opts.playTts !== false && !opts.suppressTts;
    if (playTts) {
        try {
            const mcFeetNow = Number(ac?.publishedModeCFeet ?? ac?.modeCFeet);
            const flNow = isFinite(mcFeetNow) ? Math.round(mcFeetNow / 100) : msNow;
            const flTxt = String(Math.max(0, Math.min(999, Math.trunc(next)))).padStart(3, '0');
            const flSpoken = flTxt.split('').join(' ');
            const msg = (Number.isFinite(flNow) && next < flNow)
                ? `Descending to Flight Level ${flSpoken}`
                : `Climbing to Flight Level ${flSpoken}`;
            queueSimulationAircraftTtsReply(ac, 'ALV', msg);
        } catch (e) {}
    }

    clearAircraftRocManualSelection(ac);
    ac.assignedFl = next;
    ac.rocFpm = 0;
    ac.rocTargetFpm = 0;
    ac.rocRampStartSimSec = null;
    ac.rocRampDurationSec = null;
    ac.rocRampStartFpm = null;

    if (!isSimulationExeWithPpAircraftRestrictions()) {
        const simTimeSec = getFmsVerticalSimTimeSec();
        ac.pendingModeSTargetFl = next;
        ac.pendingModeSAtSimSec = simTimeSec + (3 + Math.random() * 2);
    }

    try {
        recordSimulationSubtitleEvent(ac, `ALV input > ${String(next).padStart(3, '0')}`, { command: 'ALV', value: next });
    } catch (e) {}
    return true;
}

/** Host applies PP ALV selection (Mode-S delay + ROC reset same as local ALV picker). */
function applyHostAlvLevelCommandFromPp(ac, targetFl, opts = {}) {
    const suppressTts = !!opts.suppressTts;
    const applied = applySimulationAlvLevelToAircraft(ac, targetFl, { suppressTts, playTts: !suppressTts });
    if (!applied) return;
    try {
        pushSimulationDebugLog('CMD', ac, `ALV PP→host FL${String(Math.trunc(Number(targetFl))).padStart(3, '0')}`);
    } catch (e) {}
    pushHostSessionStateNowIfHosting();
}

/**
 * Apply IAS/MACH speed selection (same as speed picker). Used by host, PP (optimistic), and host PP replay.
 */
function applySimulationSpeedSelectionToAircraft(ac, speedType, rawValue, opts = {}) {
    if (!ac || simulationOperationModeId !== 'DL') return;
    try { ac.departureProfileActive = false; } catch (e) {}
    const playTts = opts.playTts !== false;
    const st = String(speedType || '').toUpperCase();
    if (st !== 'IAS' && st !== 'MACH') return;

    const mcFeetPub = Number(ac.publishedModeCFeet ?? ac.modeCFeet ?? ((parseInt(ac.assignedFl ?? ac.alv ?? 0, 10) || 0) * 100));
    const flPub = isFinite(mcFeetPub) ? Math.round(mcFeetPub / 100) : parseInt(ac.assignedFl ?? ac.alv ?? 0, 10);
    const altFeetSpeed = isFinite(mcFeetPub) ? mcFeetPub : (flPub * 100);
    const ktasNow = (ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) ? Number(ac.modeSTasKt) : null;
    const iasNow = (ktasNow != null) ? kiasFromKtas(ktasNow, altFeetSpeed) : null;
    const machNow = (ktasNow != null) ? machFromKtas(ktasNow, altFeetSpeed) : null;

    const simTimeSec = getEffectiveSimulationSimTimeMs() / 1000;
    let targetKtas;
    let nextVal;
    if (st === 'MACH') {
        nextVal = normalizeAiPilotMachSpeedValue(rawValue);
        if (nextVal == null) return;
        targetKtas = knotsFromMach(nextVal, altFeetSpeed);
    } else {
        nextVal = parseInt(rawValue, 10);
        if (!Number.isFinite(nextVal)) return;
        targetKtas = ktasFromKias(nextVal, altFeetSpeed);
    }
    if (!isFinite(targetKtas)) return;

    if (playTts) {
        try {
            if (st === 'MACH') {
                const cur = (machNow != null && isFinite(machNow)) ? Number(machNow.toFixed(2)) : 0.80;
                const curMach = (machNow != null && isFinite(machNow)) ? Number(machNow.toFixed(2)) : cur;
                const dir = (nextVal > curMach) ? 'Increasing' : (nextVal < curMach) ? 'Reducing' : 'Maintaining';
                const spoken = getSimulationSpokenMach(nextVal);
                const msg = (dir === 'Maintaining') ? `${dir} ${spoken}` : `${dir} to ${spoken}`;
                queueSimulationAircraftTtsReply(ac, 'SPD', msg);
            } else {
                const cur = (iasNow != null && isFinite(iasNow)) ? Math.round(Number(iasNow) / 10) * 10 : 280;
                const curIas = (iasNow != null && isFinite(iasNow)) ? Math.round(Number(iasNow) / 10) * 10 : cur;
                const dir = (nextVal > curIas) ? 'Increasing' : (nextVal < curIas) ? 'Reducing' : 'Maintaining';
                const spoken = getSimulationSpokenKnots(nextVal);
                const msg = (dir === 'Maintaining') ? `${dir} ${spoken}` : `${dir} to ${spoken}`;
                queueSimulationAircraftTtsReply(ac, 'SPD', msg);
            }
        } catch (e) {}
    }

    const start = (ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) ? Number(ac.modeSTasKt) : targetKtas;
    const delta = Math.abs(targetKtas - start);

    ac.speedSelectedType = st;
    ac.speedSelectedValue = nextVal;
    ac.speedReadoutMode = 'SELECTED';
    const subtitleSpeedValue = st === 'MACH' ? Number(nextVal).toFixed(2) : String(Math.round(nextVal)).padStart(3, '0');
    recordSimulationSubtitleEvent(ac, `Speed adjustment > ${st} ${subtitleSpeedValue}`, { command: 'SPD', speedType: st, value: nextVal });
    if (delta < 0.25) {
        ac.modeSTasKt = targetKtas;
        ac.speedChangeStartSimSec = null;
        ac.speedChangeDurationSec = null;
        ac.speedStartKtas = null;
        ac.speedTargetKtas = null;
    } else {
        const dur = Math.max(10, Math.min(30, 10 + 20 * Math.min(1, delta / 100)));
        ac.speedChangeStartSimSec = simTimeSec;
        ac.speedChangeDurationSec = dur;
        ac.speedStartKtas = start;
        ac.speedTargetKtas = targetKtas;
    }

    const mcFeet = Number(ac?.publishedModeCFeet ?? ac?.modeCFeet ?? altFeetSpeed);
    const fl = isFinite(mcFeet) ? Math.round(mcFeet / 100) : parseInt(ac?.assignedFl ?? ac?.alv ?? 0, 10);
    const band = (Number.isFinite(fl) && fl > 315) ? 'HIGH' : 'LOW';
    ac.speedReadoutManualBand = band;

    captureJoinerExePatchFromAircraft(ac);
}

function applyHostPpLateralSnapshotToLocalSim(data) {
    if (!simulationSessionId || !window.simulationData || !Array.isArray(window.simulationData.aircraft) || !data) return false;
    const map = data.aircraft;
    if (!map || typeof map !== 'object') return false;
    let anyApplied = false;
    for (const [idStr, entry] of Object.entries(map)) {
        if (!entry || typeof entry !== 'object') continue;
        const seq = Number(entry.cmdSeq);
        if (!Number.isFinite(seq)) continue;
        const last = Number(hostLastAppliedPpLateralSeqById[idStr]) || 0;
        if (seq <= last) continue;
        const ac = window.simulationData.aircraft.find(a => a && String(a.id) === idStr);
        if (!ac) continue;
        const cmd = entry.cmd;
        if (!cmd || !cmd.type) continue;
        const t = String(cmd.type).toUpperCase();
        let applied = false;
        try {
            if (t === 'DCT') {
                const wpIdx = parseInt(cmd.wpIdx, 10);
                if (!Number.isFinite(wpIdx)) continue;
                issueSimulationDirectTo(ac, wpIdx, { immediate: cmd.immediate !== false, suppressTts: true });
                applied = true;
            } else if (t === 'HDG') {
                const hd = parseInt(cmd.headingDeg, 10);
                if (!Number.isFinite(hd)) continue;
                applySimulationDlHeadingCommandFromDeg(ac, hd, { immediate: cmd.immediate !== false, suppressTts: true });
                applied = true;
            } else if (t === 'DCT_PATH') {
                const pts = cmd.pathPoints;
                const rj = parseInt(cmd.rejoinPointIdx, 10);
                if (!Array.isArray(pts) || !Number.isFinite(rj)) continue;
                applyDctPathToAircraft(ac, pts, rj);
                applied = true;
            } else if (t === 'APPLY_PATH') {
                const pts = cmd.pathPoints;
                if (!Array.isArray(pts) || !pts.length) continue;
                applyPathToAircraft(ac, pts);
                applied = true;
            } else if (t === 'ALV') {
                const tf = parseInt(cmd.targetFl, 10);
                if (!Number.isFinite(tf)) continue;
                applyHostAlvLevelCommandFromPp(ac, tf, { suppressTts: true });
                applied = true;
            } else if (t === 'SPD') {
                const st = String(cmd.speedType || '').toUpperCase();
                const v = cmd.value;
                if ((st !== 'IAS' && st !== 'MACH') || v === undefined || v === null) continue;
                applySimulationSpeedSelectionToAircraft(ac, st, v, { playTts: false });
                applied = true;
            } else if (t === 'ROC') {
                const rv = parseInt(cmd.value, 10);
                if (!Number.isFinite(rv)) continue;
                applied = applyHostRocCommandFromPp(ac, rv);
            } else if (t === 'HOLD_ARM') {
                const wid = (cmd.waypointId || '').toString().trim();
                if (!wid) continue;
                if (ac.holdingPattern) clearSimulationHoldings(ac, true);
                else ac.holdingArm = null;
                ac.holdingArm = { waypointId: wid };
                attachSectorWpIdsToSimTrajectoryPoints(ac.points);
                clearSilentDirectToIfBypassesArmedHoldFix(ac, wid);
                applied = true;
            } else if (t === 'HOLD_CANCEL') {
                issueSimulationHoldCancel(ac, { fromHost: true });
                applied = true;
            } else if (t === 'RWY') {
                const rwId = cmd.rwId != null ? String(cmd.rwId) : null;
                const rwEnd = (cmd.rwEnd === 'A' || cmd.rwEnd === 'B') ? cmd.rwEnd : null;
                const rwName = cmd.rwName != null ? String(cmd.rwName).trim().toUpperCase() : null;
                if (!rwId || !rwEnd || !rwName) continue;
                applySimulationDestRunwaySelectionToAircraft(ac, rwId, rwEnd, rwName);
                applied = true;
            }
        } catch (e) {
            applied = false;
        }
        if (!applied) continue;
        hostLastAppliedPpLateralSeqById[idStr] = seq;
        anyApplied = true;
        try {
            scheduleHostAtmTrajectorySyncToServer(ac);
        } catch (e2) {}
    }
    return anyApplied;
}

function hostPollPpLateralOnce() {
    if (!simulationSessionId || hostPpLateralPollInFlight) return;
    const sid = simulationSessionId;
    hostPpLateralPollInFlight = true;
    fetch('/api/sessions/' + encodeURIComponent(sid) + '/pp-lateral')
        .then(r => (r.ok ? r.json() : null))
        .then(data => {
            hostPpLateralPollInFlight = false;
            if (!data || !data.ok) return;
            let applied = false;
            if (data.aircraft) applied = applyHostPpLateralSnapshotToLocalSim(data);
            if (data.ppFlightStatus) {
                mergePpFlightStatusFromSessionState({ ppFlightStatus: data.ppFlightStatus });
                if (document.getElementById('simulationModal')?.classList.contains('active')) drawSimulationCanvas();
            }
            if (applied) pushHostSessionStateNowIfHosting();
        })
        .catch(() => { hostPpLateralPollInFlight = false; });
}

function startHostPpLateralPoll() {
    if (simulationHostPpLateralPollIntervalId) {
        clearInterval(simulationHostPpLateralPollIntervalId);
        simulationHostPpLateralPollIntervalId = null;
    }
    if (!simulationSessionId) return;
    const sid = simulationSessionId;
    hostPollPpLateralOnce();
    simulationHostPpLateralPollIntervalId = setInterval(() => {
        if (simulationSessionId !== sid) return;
        hostPollPpLateralOnce();
    }, 320);
}

function stopHostPpLateralPoll() {
    if (simulationHostPpLateralPollIntervalId) {
        clearInterval(simulationHostPpLateralPollIntervalId);
        simulationHostPpLateralPollIntervalId = null;
    }
    hostPpLateralPollInFlight = false;
    hostLastAppliedPpLateralSeqById = {};
}

function clearJoinerExeAircraftPatches() {
    joinerExeAircraftPatches = null;
    clearJoinerAtmRouteProgressState();
    _joinerAtmTrajectoryPostPendingIds = null;
    _joinerAtmVerticalOnlyPending = null;
    if (_joinerAtmVerticalOnlyTimer) {
        clearTimeout(_joinerAtmVerticalOnlyTimer);
        _joinerAtmVerticalOnlyTimer = null;
    }
    _joinerAtmMetadataPostPendingIds = null;
    if (_joinerAtmMetadataPostTimer) {
        clearTimeout(_joinerAtmMetadataPostTimer);
        _joinerAtmMetadataPostTimer = null;
    }
    if (_atmTrajectoryPostTimer) {
        clearTimeout(_atmTrajectoryPostTimer);
        _atmTrajectoryPostTimer = null;
    }
    try {
        _joinerAtmReceiverAssumeStickyByAid = {};
        _joinerAtmTouRollbackPendingByAid = {};
        _joinerAtmOutboundTransferPostPendingByAid = {};
        _joinerAtmHoldLabelClearPendingByAid = {};
        (window.simulationData?.aircraft || []).forEach((ac) => {
            if (ac && '_atmTrajectoryPatch' in ac) delete ac._atmTrajectoryPatch;
            if (ac && '_atmTrajectoryPatchSig' in ac) delete ac._atmTrajectoryPatchSig;
            if (ac && '_atmLateralLocked' in ac) delete ac._atmLateralLocked;
            clearAtmSectorSequenceCachesForAircraft(ac);
        });
    } catch (e) {}
    try {
        clearAllExeAlvModeSVerifyTimersFromList(window.simulationData?.aircraft);
        exeAlvModeSMismatchFlashById.clear();
        exeAlvDiscrepancyFirstSeenMsById.clear();
        exeAlvMismatchRadarLogKeys.clear();
    } catch (e) {}
}

function captureJoinerExePatchFromAircraft(ac) {
    if (!isJoinerAtmTrajectoryEditor() || !ac || ac.id == null) return;
    ac = getSimulationAircraftById(ac.id) || ac;
    if (!joinerExeAircraftPatches) joinerExeAircraftPatches = {};
    const id = String(ac.id);
    const p = buildAtmTrajectoryPatchObjectFromAircraft(ac, {
        skipVerticalForPp: isSimulationExeWithPpAircraftRestrictions(),
        skipJoinerLocalProgressKeys: true,
        includeExePlnRunwayLabelKeys: true
    });
    if (!p || !Object.keys(p).length) return;
    joinerExeAircraftPatches[id] = p;
    applyJoinerExeDctDisplayFieldsToAircraft(ac, p);
    if (Array.isArray(p.points) && p.points.length) {
        ac._atmLateralLocked = true;
        handleJoinerAtmRoutePointsChange(ac, p.points);
        syncJoinerAtmRouteProgressFromHostDisplay(ac, { forceAdvance: true });
    }
    clearAtmSectorSequenceCachesForAircraft(ac);
    flushJoinerAtmTrajectoryPatchForAircraftId(id);
}

/** First ATM patch per aircraft: lateral/route only — never seed assignedFl from host FMS. */
function captureJoinerExeBaselinePatchFromAircraft(ac) {
    if (!isJoinerAtmTrajectoryEditor() || !ac || ac.id == null) return;
    if (!joinerExeAircraftPatches) joinerExeAircraftPatches = {};
    const id = String(ac.id);
    if (joinerExeAircraftPatches[id]) return;
    const p = buildAtmTrajectoryPatchObjectFromAircraft(ac, {
        skipVerticalForPp: isSimulationExeWithPpAircraftRestrictions(),
        skipAtmAlvDisplayKeys: true,
        skipJoinerLocalProgressKeys: true,
        skipJoinerDctLabelKeys: true
    });
    if (!p || !Object.keys(p).length) return;
    const pelFl = getExercisePelFlForAtmDisplay(ac);
    if (pelFl != null) p.assignedFl = pelFl;
    joinerExeAircraftPatches[id] = p;
    if (Array.isArray(p.points) && p.points.length) ac._atmLateralLocked = true;
    clearAtmSectorSequenceCachesForAircraft(ac);
}

/**
 * EXE joiner: first time we see an aircraft (no patch yet), snapshot host state into joinerExeAircraftPatches
 * so PP-driven host updates do not overwrite label/trajectory until EXE edits (same as after first user input).
 */
function ensureJoinerExeBaselinePatchForEachAircraft() {
    if (!isJoinerAtmTrajectoryEditor() || !window.simulationData || !Array.isArray(window.simulationData.aircraft)) return;
    for (const ac of window.simulationData.aircraft) {
        if (!ac || ac.id == null) continue;
        const id = String(ac.id);
        if (joinerExeAircraftPatches && joinerExeAircraftPatches[id]) continue;
        captureJoinerExeBaselinePatchFromAircraft(ac);
    }
}

function applyJoinerExePatchesAfterStateSync() {
    if (!isJoinerAtmTrajectoryEditor() || !joinerExeAircraftPatches) return;
    const list = window.simulationData && window.simulationData.aircraft;
    if (!Array.isArray(list)) return;
    for (const ac of list) {
        if (!ac || ac.id == null) continue;
        const p = joinerExeAircraftPatches[String(ac.id)];
        if (!p) continue;
        for (const [k, v] of Object.entries(p)) {
            if (isSimulationExeWithPpAircraftRestrictions() && JOINER_SYNC_VERTICAL_KEYS.has(k)) continue;
            if (k === '_headingNavStatesEntries' && Array.isArray(v)) {
                ac.headingNavStatesByUpdateSec = new Map(
                    v.map(([kk, vv]) => [kk, vv && typeof vv === 'object' ? { ...vv } : vv])
                );
                continue;
            }
            if (k === 'points' && Array.isArray(v)) {
                if (joinerAtmLateralLocked(ac)) continue;
                const patchPts = ac._atmTrajectoryPatch && ac._atmTrajectoryPatch.points;
                if (Array.isArray(patchPts) && patchPts.length > 0) continue;
                try {
                    ac.points = JSON.parse(JSON.stringify(v));
                    ac._trackCache = null;
                    ac.routeNavTravelCacheN = null;
                    if (ac.routeNavTraveledNmByUpdateSec instanceof Map) ac.routeNavTraveledNmByUpdateSec.clear();
                } catch (e) {}
                continue;
            }
            if (ATM_PATCH_ROUTE_GEOMETRY_KEYS.has(k) && k !== 'points') {
                const serverPatch = ac._atmTrajectoryPatch;
                if (serverPatch && Object.prototype.hasOwnProperty.call(serverPatch, k)) continue;
            }
            if (ATM_JOINER_DCT_LABEL_KEYS.includes(k) || ATM_JOINER_PEER_NAV_STATE_KEYS.includes(k)) {
                ac[k] = v;
                continue;
            }
            if (ac._atmLateralLocked && k === 'routeProgressIdx') continue;
            if (isJoinerAtmDisplayClient() && ATM_PATCH_JOINER_LOCAL_PROGRESS_KEYS.includes(k)) continue;
            if (ATM_HOLD_EXE_PLN_PATCH_KEYS.includes(k)) {
                if (_joinerAtmHoldLabelClearPendingByAid[String(ac.id)]) {
                    ac[k] = v;
                    continue;
                }
                const patch = ac._atmTrajectoryPatch;
                if (patch && Object.prototype.hasOwnProperty.call(patch, k)) continue;
            }
            if (ATM_ROC_DISPLAY_PATCH_KEYS.includes(k) || ATM_ALV_DISPLAY_PATCH_KEYS.includes(k) || ATM_XFL_DISPLAY_PATCH_KEYS.includes(k)) {
                const aidStr = String(ac.id);
                if (_joinerAtmTrajectoryPostPendingIds && _joinerAtmTrajectoryPostPendingIds.has(aidStr)) {
                    ac[k] = v;
                    continue;
                }
                const serverPatch = ac._atmTrajectoryPatch;
                if (serverPatch && Object.prototype.hasOwnProperty.call(serverPatch, k)) {
                    const sv = serverPatch[k];
                    const lv = v;
                    const nums = Number.isFinite(Number(lv)) && Number.isFinite(Number(sv));
                    if (nums ? Number(lv) !== Number(sv) : String(lv) !== String(sv)) {
                        ac[k] = v;
                        continue;
                    }
                    continue;
                }
            }
            ac[k] = v;
        }
        for (const k of ATM_JOINER_DCT_LABEL_KEYS) {
            if (!Object.prototype.hasOwnProperty.call(p, k)) ac[k] = null;
        }
    }
}

