// Render mode options into a container (for run-type Host/Single). allowedModeIds optional: if set, only those modes are listed (e.g. host = DL only).
// options.singleUserDemo: list all modes; only DL is selectable; others are styled disabled with demo tag.
function renderSimulationModeOptionsInContainer(containerId, selectedModeId, onSelect, allowedModeIds = null, options = null) {
    const wrap = document.getElementById(containerId);
    if (!wrap) return;
    wrap.innerHTML = '';
    const opts = options && typeof options === 'object' ? options : {};
    const singleUserDemo = !!opts.singleUserDemo;
    const currentMode = selectedModeId || simulationOperationModeId;
    let modes;
    if (singleUserDemo) {
        modes = SIM_OPERATION_MODES;
    } else if (Array.isArray(allowedModeIds) && allowedModeIds.length) {
        modes = SIM_OPERATION_MODES.filter(m => allowedModeIds.includes(m.id));
    } else {
        modes = SIM_OPERATION_MODES;
    }
    modes.forEach(m => {
        const item = document.createElement('div');
        const isDisabled = singleUserDemo && m.id !== 'DL';
        if (isDisabled) {
            item.className = 'sim-mode-option sim-mode-option-disabled';
            item.dataset.modeId = m.id;
            item.setAttribute('aria-disabled', 'true');
        } else {
            item.className = 'sim-mode-option' + (m.id === currentMode ? ' active' : '');
            item.dataset.modeId = m.id;
        }
        const titleHtml = escapeHtml(m.label) + (isDisabled
            ? ' <span class="sim-mode-option-demo-tag">(NOT AVAILABLE IN DEMO MODE)</span>'
            : '');
        item.innerHTML = `
            <div class="sim-mode-option-title">${titleHtml}</div>
            <div class="sim-mode-option-desc">${escapeHtml(m.description)}</div>
        `;
        if (!isDisabled) {
            item.addEventListener('click', () => {
                if (onSelect) onSelect(m.id);
                wrap.querySelectorAll('.sim-mode-option:not(.sim-mode-option-disabled)').forEach(el => el.classList.remove('active'));
                item.classList.add('active');
            });
        }
        wrap.appendChild(item);
    });
}

function escapeHtml(s) {
    if (s == null) return '';
    const t = String(s);
    return t.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

