async function prepareRunTypeSingleAtcSectorSelect(exercise) {
    const sel = document.getElementById('runTypeSingleAtcSectorSelect');
    const errEl = document.getElementById('runTypeSingleAtcSectorError');
    const startBtn = document.getElementById('runTypeSingleStartBtn');
    runTypeSingleSelectedAtcSectorId = null;
    if (errEl) {
        errEl.style.display = 'none';
        errEl.textContent = '';
    }
    if (!sel) return;
    sel.disabled = true;
    sel.innerHTML = '<option value="">Loading ATC sectors…</option>';
    if (startBtn) startBtn.disabled = true;

    if (!exercise?.sectorId) {
        sel.innerHTML = '<option value="">No airspace linked to this exercise</option>';
        if (errEl) {
            errEl.textContent = 'This exercise has no linked airspace.';
            errEl.style.display = 'block';
        }
        return;
    }

    let sector = getCachedSector(exercise.sectorId);
    if (sectorNeedsFullLoad(sector)) {
        try {
            sector = await loadSectorFromServer(exercise.sectorId);
        } catch (e) {
            sel.innerHTML = '<option value="">Could not load airspace</option>';
            if (errEl) {
                errEl.textContent = 'Could not load the airspace for this exercise.';
                errEl.style.display = 'block';
            }
            return;
        }
    }

    const opts = getJoinAtcSectorPickerOptions(sector);
    if (!opts.length) {
        sel.innerHTML = '<option value="">No ATC sectors defined</option>';
        if (errEl) {
            errEl.textContent = 'This exercise airspace has no ATC sectors. Add them in Edit Airspace first.';
            errEl.style.display = 'block';
        }
        return;
    }

    sel.innerHTML = opts.map(o =>
        `<option value="${escapeHtml(String(o.atcSectorId))}">${escapeHtml(o.name)}</option>`
    ).join('');
    sel.disabled = false;
    runTypeSingleSelectedAtcSectorId = opts[0].atcSectorId;
    sel.value = String(runTypeSingleSelectedAtcSectorId);
    if (startBtn) startBtn.disabled = false;
}

function runTypeFetchSessions() {
    const listEl = document.getElementById('runTypeJoinList');
    const emptyEl = document.getElementById('runTypeJoinEmpty');
    const joinBtn = document.getElementById('runTypeJoinJoinBtn');
    if (!listEl) return;
    listEl.innerHTML = '';
    runTypeJoinSelectedId = null;
    if (joinBtn) joinBtn.disabled = true;
    fetch('/api/sessions').then(r => r.json()).then(data => {
        const sessions = data.sessions || [];
        if (sessions.length === 0) {
            if (emptyEl) emptyEl.style.display = 'block';
            return;
        }
        if (emptyEl) emptyEl.style.display = 'none';
        sessions.forEach(s => {
            const item = document.createElement('div');
            item.className = 'run-type-join-item';
            item.dataset.sessionId = s.id;
            item.innerHTML = `<span><strong>${escapeHtml(s.name || 'Unnamed')}</strong> · ${escapeHtml(s.mode || 'DL')} · ${escapeHtml(s.exerciseName || '')} / ${escapeHtml(s.sectorName || '')}</span>`;
            item.addEventListener('click', () => {
                listEl.querySelectorAll('.run-type-join-item').forEach(el => el.classList.remove('selected'));
                item.classList.add('selected');
                runTypeJoinSelectedId = s.id;
                if (joinBtn) joinBtn.disabled = false;
            });
            listEl.appendChild(item);
        });
    }).catch(() => {
        if (emptyEl) { emptyEl.style.display = 'block'; emptyEl.textContent = 'Could not load sessions.'; }
    });
}

function buildSessionState() {
    if (!window.simulationData) return null;
    const simSec = getSimulationClockSeconds();
    const radarSec = Math.max(1, parseInt(simulationSettings?.radarUpdateSeconds, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
    const data = JSON.parse(JSON.stringify(window.simulationData));
    const aircraft = data.aircraft || [];
    aircraft.forEach(ac => {
        if (!ac) return;
        const live = window.simulationData.aircraft.find(a => a && a.id === ac.id);
        const state = getAircraftPositionAtRadarUpdate(live, simSec, radarSec);
        if (state && isFinite(state.lat) && isFinite(state.lon)) {
            ac._displayLat = state.lat;
            ac._displayLon = state.lon;
            ac._displayGs = state.gs;
            ac._displayLastUpdateSimSec = state.lastUpdateSimSec;
            ac._displayNext = state.next ? { lat: state.next.lat, lon: state.next.lon, name: state.next.name || '' } : null;
            if (state.traveledNm != null && isFinite(Number(state.traveledNm))) {
                ac._displayTraveledNm = Number(state.traveledNm);
            }
        }
    });
    return {
        simulationData: data,
        simulationSimTimeMs: simulationSimTimeMs,
        simulationIsPaused: simulationIsPaused,
        simulationOperationModeId: simulationOperationModeId,
        simulationRate: simulationRate,
        hostSessionRestartSeq: hostSessionRestartSeq
    };
}

/** Normalize aircraft id for trajectory Set (JSON may use number or string). */
function normalizeTrajectoryAircraftId(id) {
    if (id == null) return '';
    return String(id);
}

function simulationTrajectoryOverlayHasAircraftId(aircraftId) {
    const k = normalizeTrajectoryAircraftId(aircraftId);
    return simulationTrajectoryAircraftIds.has(k);
}

function applyLocalTrajectoryToggleOnly(aircraftId, opts = {}) {
    const forceOff = !!opts.forceOff;
    const k = normalizeTrajectoryAircraftId(aircraftId);
    if (!k) return;
    if (forceOff) simulationTrajectoryAircraftIds.delete(k);
    else if (simulationTrajectoryAircraftIds.has(k)) simulationTrajectoryAircraftIds.delete(k);
    else simulationTrajectoryAircraftIds.add(k);
}

/** Middle-click trajectory display is local to this browser only (not synced to host or other clients). */
function toggleSimulationTrajectoryForAircraftId(aircraftId, opts = {}) {
    const forceOff = !!opts.forceOff;
    applyLocalTrajectoryToggleOnly(aircraftId, { forceOff });
    return Promise.resolve();
}

/** EXE/PLN: host FMS ROC/D must not drive joiner physics; label ROC comes from ATM bucket on next merge. */
function stripIncomingHostRocForAtmJoiner() {
    if (!isJoinerExeOrPlnClient() || !simulationJoinedSessionId || !window.simulationData || !Array.isArray(window.simulationData.aircraft)) return;
    window.simulationData.aircraft.forEach((ac) => {
        if (!ac) return;
        ac.rocManualActive = false;
        ac.rocTargetFpm = 0;
        ac.rocRampStartSimSec = null;
        ac.rocRampDurationSec = null;
        ac.rocRampStartFpm = null;
    });
}

/** After host GET: drop FMS assignedFl on ATM clients; ALV label uses ATM bucket / exercise PEL only. */
function restoreAtmAssignedFlAfterHostStateReplace() {
    if (!isJoinerAtmDisplayClient() || isJoinerPpClient() || !window.simulationData || !Array.isArray(window.simulationData.aircraft)) return;
    window.simulationData.aircraft.forEach((ac) => {
        if (!ac || ac.id == null) return;
        const aid = String(ac.id);
        if (_joinerAtmTrajectoryPostPendingIds && _joinerAtmTrajectoryPostPendingIds.has(aid)) {
            const jp = joinerExeAircraftPatches && joinerExeAircraftPatches[aid];
            if (jp && Number.isFinite(Number(jp.assignedFl))) {
                ac.assignedFl = Math.max(0, Math.min(500, Math.trunc(Number(jp.assignedFl))));
            }
            return;
        }
        const jpAlv = joinerExeAircraftPatches && joinerExeAircraftPatches[aid];
        const patch = ac._atmTrajectoryPatch;
        const serverFl = (patch && Object.prototype.hasOwnProperty.call(patch, 'assignedFl'))
            ? Number(patch.assignedFl) : null;
        const localFl = (jpAlv && Number.isFinite(Number(jpAlv.assignedFl))) ? Number(jpAlv.assignedFl) : null;
        if (Number.isFinite(localFl) && (!Number.isFinite(serverFl) || localFl !== serverFl)) {
            ac.assignedFl = Math.max(0, Math.min(500, Math.trunc(localFl)));
            return;
        }
        if (patch && Object.prototype.hasOwnProperty.call(patch, 'assignedFl') && Number.isFinite(Number(patch.assignedFl))) {
            ac.assignedFl = Math.max(0, Math.min(500, Math.trunc(Number(patch.assignedFl))));
            return;
        }
        const pelFl = getExercisePelFlForAtmDisplay(ac);
        if (pelFl != null) ac.assignedFl = pelFl;
    });
}

/** EXE: never show PP/host "selected speed" — only Mode-S IAS/MACH from host; EXE patch restores SELECTED if EXE picked it. */
function stripIncomingSpeedSelectionForExeJoiner() {
    if (!isJoinerExeClient() || !simulationJoinedSessionId || !window.simulationData || !Array.isArray(window.simulationData.aircraft)) return;
    window.simulationData.aircraft.forEach((ac) => {
        if (!ac) return;
        delete ac.speedSelectedType;
        delete ac.speedSelectedValue;
        ac.speedReadoutMode = 'IAS';
        delete ac.speedReadoutManualBand;
        ac.speedChangeStartSimSec = null;
        ac.speedChangeDurationSec = null;
        ac.speedStartKtas = null;
        ac.speedTargetKtas = null;
    });
}

function applySessionState(state) {
    if (!state) return;
    if (shouldIgnoreJoinerIncomingState(state)) return;
    handleHostSessionRestartIfNeeded(state);
    // PP: host master for trajectory + Mode-C + GS; poll replaces aircraft from GET (label offsets preserved).
    if (isJoinerPpClient() && !simulationJoinPpAwaitingFullState && window.simulationData && Array.isArray(window.simulationData.aircraft)) {
        applySessionStateForPpJoiner(state);
        if (joinerSkipHeldDisplayPreserveOnce) {
            joinerSkipHeldDisplayPreserveOnce = false;
            seedJoinerDisplayFromHostAfterRestart();
        }
        if (window.simulationData && Array.isArray(window.simulationData.aircraft)) {
            window.simulationData.aircraft.forEach(ac => {
                syncJoinerHeldDisplayFromAircraft(ac);
                appendJoinerTrailSampleFromHostDisplay(ac);
            });
        }
        return;
    }
    // Joiner: preserve our local label positions so they don't reset on each poll
    let joinerLabelOffsetsById = null;
    let joinerTrailById = null;
    if (joinerSkipLabelOffsetPreserveOnce) {
        joinerSkipLabelOffsetPreserveOnce = false;
    } else if (simulationJoinedSessionId && window.simulationData && Array.isArray(window.simulationData.aircraft)) {
        joinerLabelOffsetsById = new Map();
        joinerTrailById = new Map();
        window.simulationData.aircraft.forEach(ac => {
            if (!ac || !ac.id) return;
            if (Number.isFinite(ac.labelOffsetX) || Number.isFinite(ac.labelOffsetY)) {
                joinerLabelOffsetsById.set(ac.id, { labelOffsetX: ac.labelOffsetX, labelOffsetY: ac.labelOffsetY });
            }
            if (Array.isArray(ac._joinerTrailSamples) && ac._joinerTrailSamples.length) {
                joinerTrailById.set(ac.id, ac._joinerTrailSamples.map(s => ({
                    simSec: Number(s.simSec),
                    lat: s.lat,
                    lon: s.lon
                })));
            }
        });
    }
    if (state.simulationData) {
        const prevSimData = window.simulationData;
        window.simulationData = state.simulationData;
        if (simulationJoinedSessionId && prevSimData && Array.isArray(prevSimData.aircraft) && window.simulationData && Array.isArray(window.simulationData.aircraft)) {
            if (!joinerSkipHeldDisplayPreserveOnce) {
                preserveJoinerAtmLateralLockAcrossAircraftReplace(prevSimData.aircraft, window.simulationData.aircraft);
            }
            if (joinerSkipHeldDisplayPreserveOnce) {
                joinerSkipHeldDisplayPreserveOnce = false;
            } else {
                preserveJoinerHeldDisplayAcrossAircraftReplace(prevSimData.aircraft, window.simulationData.aircraft);
            }
        }
    }
    if (simulationJoinedSessionId && isJoinerAtmDisplayClient() && window.simulationData && Array.isArray(window.simulationData.aircraft)) {
        joinerHostFmsDctSnapshotByAid = new Map();
        window.simulationData.aircraft.forEach((ac) => {
            if (!ac || ac.id == null) return;
            joinerHostFmsDctSnapshotByAid.set(String(ac.id), snapshotHostFmsDctFieldsFromAircraft(ac));
        });
        stripJoinerAtmDisplayHostFmsReportingFields();
        stripJoinerHostFmsDctDisplayFields();
        stripJoinerHostFmsRunwayDisplayFields();
    }
    if (joinerAwaitingDeferredAtmSync && isJoinerAtmDisplayClient()) {
        seedJoinerDisplayFromHostAfterRestart();
    }
    if (state.simulationSimTimeMs != null && !simulationJoinedSessionId) simulationSimTimeMs = state.simulationSimTimeMs;
    if (state.simulationIsPaused != null) simulationIsPaused = state.simulationIsPaused;
    if (state.simulationOperationModeId) simulationOperationModeId = state.simulationOperationModeId;
    syncJoinerClockFromHostState(state);
    if (joinerLabelOffsetsById && window.simulationData && Array.isArray(window.simulationData.aircraft)) {
        window.simulationData.aircraft.forEach(ac => {
            if (!ac || !ac.id) return;
            const saved = joinerLabelOffsetsById.get(ac.id);
            if (saved) {
                if (Number.isFinite(saved.labelOffsetX)) ac.labelOffsetX = saved.labelOffsetX;
                if (Number.isFinite(saved.labelOffsetY)) ac.labelOffsetY = saved.labelOffsetY;
            }
        });
    }
    if (joinerTrailById && window.simulationData && Array.isArray(window.simulationData.aircraft)) {
        window.simulationData.aircraft.forEach(ac => {
            if (!ac || !ac.id) return;
            const tr = joinerTrailById.get(ac.id);
            if (tr && tr.length) ac._joinerTrailSamples = tr;
        });
    }
    stripIncomingSpeedSelectionForExeJoiner();
    stripIncomingHostRocForAtmJoiner();
    mergeAtmTrajectoryFromSessionState(state, joinerHostFmsDctSnapshotByAid);
    joinerHostFmsDctSnapshotByAid = null;
    restoreAtmAssignedFlAfterHostStateReplace();
    restoreAtmRunwayDisplayAfterHostStateReplace();
    syncCanonicalAtmPointsFromServerPatches(state);
    restoreJoinerLockedAtmPointsAfterHostStateReplace(state);
    if (joinerAwaitingDeferredAtmSync && isJoinerAtmDisplayClient()) {
        scheduleJoinerAtmSyncAfterHostRestart();
    } else {
        ensureJoinerExeBaselinePatchForEachAircraft();
        applyJoinerExePatchesAfterStateSync();
        if (simulationJoinedSessionId && window.simulationData && Array.isArray(window.simulationData.aircraft)) {
            window.simulationData.aircraft.forEach((ac) => {
                if (ac && isJoinerAtmDisplayClient()) syncJoinerAtmRouteProgressFromHostDisplay(ac);
            });
        }
    }
    if (simulationJoinedSessionId && window.simulationData && Array.isArray(window.simulationData.aircraft)) {
        window.simulationData.aircraft.forEach(ac => {
            syncJoinerHeldDisplayFromAircraft(ac);
            if (!joinerAwaitingDeferredAtmSync) appendJoinerTrailSampleFromHostDisplay(ac);
        });
    }
    if (isJoinerPpClient()) simulationJoinPpAwaitingFullState = false;
}

let _cachedJoinClientId = null;
function getOrCreateJoinClientId() {
    if (_cachedJoinClientId) return _cachedJoinClientId;
    try {
        let id = localStorage.getItem('atcJoinClientId');
        if (!id || String(id).length < 8) {
            id = 'cl_' + Date.now().toString() + '_' + Math.random().toString(16).slice(2, 12);
            try {
                localStorage.setItem('atcJoinClientId', id);
            } catch (e2) {
                /* private mode: keep in-memory id only */
            }
        }
        _cachedJoinClientId = id;
        return id;
    } catch (e) {
        _cachedJoinClientId = 'cl_' + Date.now().toString() + '_' + Math.random().toString(16).slice(2, 12);
        return _cachedJoinClientId;
    }
}

/** Picker rows: { atcSectorId, name, boundaryId } for slot keys + map filter */
function getJoinAtcSectorPickerOptions(sector) {
    if (!sector) return [];
    if (Array.isArray(sector.atcSectors) && sector.atcSectors.length) {
        return sector.atcSectors.filter(s => s && s.boundary && s.boundary.id).map(s => ({
            atcSectorId: String(s.id),
            name: ((s.name || 'ATC Sector').toString().trim()) || 'ATC Sector',
            boundaryId: s.boundary.id
        }));
    }
    const bs = getBoundariesFromSectorForSimulation(sector) || [];
    return bs.map((b, i) => ({
        atcSectorId: b && b.id ? `legacy_bd_${b.id}` : `legacy_idx_${i}_${sector.id || 's'}`,
        name: ((sector.name || 'Airspace').toString()) + (bs.length > 1 ? ` (${i + 1})` : ''),
        boundaryId: b && b.id
    })).filter(o => o.boundaryId);
}

/**
 * Whose sector "counts" for flight-status (CIN): joiner = joined slot; solo host = simulationHostAtcScope.
 * ALL SECTORS => mode 'all' (no CIN tint).
 */
function getSimulationUserAtcSectorContext() {
    if (simulationJoinedSessionId && simulationJoinAtcSectorId) {
        const sec = window.simulationData?.sector;
        const list = Array.isArray(sec?.atcSectors) ? sec.atcSectors : [];
        const atc = list.find(s => s && String(s.id) === String(simulationJoinAtcSectorId));
        if (!atc) return { mode: 'all' };
        const nm = (atc?.name || atc?.id || '').toString().trim();
        return { mode: 'single', atcSectorId: String(simulationJoinAtcSectorId), sectorNameNorm: nm.toUpperCase() };
    }
    if (!simulationJoinedSessionId) {
        const scope = simulationHostAtcScope == null ? 'all' : String(simulationHostAtcScope);
        if (scope === 'all' || scope === '') return { mode: 'all' };
        const sec = window.simulationData?.sector;
        const list = Array.isArray(sec?.atcSectors) ? sec.atcSectors : [];
        const atc = list.find(s => s && String(s.id) === String(scope));
        if (!atc) return { mode: 'all' };
        const nm = (atc?.name || atc?.id || '').toString().trim();
        return { mode: 'single', atcSectorId: String(scope), sectorNameNorm: nm.toUpperCase() };
    }
    return { mode: 'all' };
}

function syncSimulationHostAtcScopeSelect() {
    const sel = document.getElementById('simulationHostAtcScopeSelect');
    const label = document.getElementById('simulationHostAtcScopeLabel');
    if (!sel) return;
    if (simulationJoinedSessionId) {
        sel.style.display = 'none';
        sel.setAttribute('aria-hidden', 'true');
        if (label) label.style.display = 'none';
        return;
    }
    sel.style.display = '';
    sel.removeAttribute('aria-hidden');
    if (label) label.style.display = '';
    const sector = window.simulationData?.sector;
    const opts = getJoinAtcSectorPickerOptions(sector);

    if (isSimulationSingleUserAtcSectorLocked()) {
        const cur = String(simulationHostAtcScope || '');
        const match = opts.find(o => String(o.atcSectorId) === cur);
        if (match) {
            sel.innerHTML = `<option value="${escapeHtml(String(match.atcSectorId))}">${escapeHtml(match.name)}</option>`;
            sel.value = String(match.atcSectorId);
        } else {
            sel.innerHTML = '<option value="">—</option>';
            sel.value = '';
        }
        sel.disabled = true;
        sel.classList.add('is-locked');
        sel.title = 'ATC sector locked for this Single User run';
        if (label) {
            label.title = 'Your ATC sector for this Single User run (locked until you stop the simulation)';
        }
        syncSimulationHostUsersBtnVisibility();
        return;
    }

    sel.disabled = false;
    sel.classList.remove('is-locked');
    sel.removeAttribute('title');
    if (label) {
        label.title = 'Single-user: restrict flight-status (CIN) to one ATC sector, or ALL SECTORS. Joiners use the sector chosen when joining.';
    }
    const parts = ['<option value="all">ALL SECTORS</option>'];
    opts.forEach((o) => {
        parts.push(`<option value="${escapeHtml(String(o.atcSectorId))}">${escapeHtml(o.name)}</option>`);
    });
    sel.innerHTML = parts.join('');
    let cur = simulationHostAtcScope == null ? 'all' : String(simulationHostAtcScope);
    if (cur !== 'all' && !opts.some(o => String(o.atcSectorId) === cur)) {
        cur = 'all';
        simulationHostAtcScope = 'all';
        try { localStorage.setItem('simulationHostAtcScope', 'all'); } catch (e) {}
    }
    sel.value = cur;
    syncSimulationHostUsersBtnVisibility();
}

/** HOST only: show USERS button when hosting a multiplayer session. */
function syncSimulationHostUsersBtnVisibility() {
    const btn = document.getElementById('simulationUsersBtn');
    if (!btn) return;
    if (simulationJoinedSessionId || !simulationSessionId) {
        btn.style.display = 'none';
        btn.setAttribute('aria-hidden', 'true');
        return;
    }
    btn.style.display = '';
    btn.removeAttribute('aria-hidden');
}

function renderSimulationConnectedUsersList(data) {
    const listEl = document.getElementById('simulationConnectedUsersList');
    const statusEl = document.getElementById('simulationConnectedUsersStatus');
    if (!listEl) return;
    const sectorOpts = getJoinAtcSectorPickerOptions(window.simulationData?.sector);
    const taken = Array.isArray(data?.taken) ? data.taken : [];
    const ppPresence = Array.isArray(data?.ppPresence) ? data.ppPresence : [];
    const bySector = new Map();
    sectorOpts.forEach((o) => {
        bySector.set(String(o.atcSectorId), { name: o.name, users: [] });
    });
    taken.forEach((row) => {
        if (!row || !row.atcSectorId || !row.clientId) return;
        const sid = String(row.atcSectorId);
        if (!bySector.has(sid)) bySector.set(sid, { name: sid, users: [] });
        bySector.get(sid).users.push({ role: String(row.role || '').toUpperCase(), clientId: String(row.clientId) });
    });
    ppPresence.forEach((row) => {
        if (!row || !row.atcSectorId || !row.clientId) return;
        const sid = String(row.atcSectorId);
        if (!bySector.has(sid)) bySector.set(sid, { name: sid, users: [] });
        bySector.get(sid).users.push({ role: 'PP', clientId: String(row.clientId) });
    });
    const totalUsers = taken.filter((r) => r && r.clientId).length
        + ppPresence.filter((r) => r && r.clientId).length;
    if (statusEl) {
        statusEl.textContent = totalUsers
            ? `${totalUsers} active connection(s) — refreshed ${new Date().toLocaleTimeString()}`
            : 'No users connected.';
    }
    if (!sectorOpts.length) {
        listEl.innerHTML = '<p class="hint-text">No ATC sectors in this exercise.</p>';
        return;
    }
    const parts = [];
    sectorOpts.forEach((o) => {
        const entry = bySector.get(String(o.atcSectorId));
        const users = entry?.users || [];
        const ppUsers = users.filter((u) => u.role === 'PP');
        parts.push('<section class="sim-connected-users-sector">');
        parts.push(`<h3 class="sim-connected-users-sector-name">${escapeHtml(o.name)}</h3>`);
        if (!users.length) {
            parts.push('<div class="sim-connected-users-empty">— none —</div>');
        } else {
            users.forEach((u) => {
                parts.push(
                    `<div class="sim-connected-users-row">`
                    + `<span class="sim-connected-users-role">${escapeHtml(u.role)}</span> `
                    + `<code>${escapeHtml(u.clientId)}</code></div>`
                );
            });
            if (ppUsers.length > 1) {
                parts.push('<div class="sim-connected-users-multi">(multiple users)</div>');
            }
        }
        parts.push('</section>');
    });
    listEl.innerHTML = parts.join('');
}

function refreshSimulationConnectedUsersModal() {
    const statusEl = document.getElementById('simulationConnectedUsersStatus');
    const listEl = document.getElementById('simulationConnectedUsersList');
    if (!simulationSessionId || simulationJoinedSessionId) {
        if (statusEl) statusEl.textContent = 'Available only while hosting a session.';
        if (listEl) listEl.innerHTML = '';
        return Promise.resolve();
    }
    if (statusEl) statusEl.textContent = 'Loading…';
    if (listEl) listEl.innerHTML = '';
    const sid = simulationSessionId;
    return fetch('/api/sessions/' + encodeURIComponent(sid) + '/join-slots')
        .then((r) => r.json().then((data) => ({ ok: r.ok, data })).catch(() => ({ ok: r.ok, data: null })))
        .then(({ ok, data }) => {
            if (!ok || !data) throw new Error('fetch failed');
            renderSimulationConnectedUsersList(data);
        })
        .catch(() => {
            if (statusEl) statusEl.textContent = 'Could not load connected users.';
            if (listEl) listEl.innerHTML = '';
        });
}

function openSimulationConnectedUsersModal() {
    if (!simulationSessionId || simulationJoinedSessionId) return;
    openModal('simulationConnectedUsersModal');
    refreshSimulationConnectedUsersModal();
}

function releaseJoinSlotsOnServer(sessionId, clientId) {
    if (!sessionId || !clientId) return;
    fetch('/api/sessions/' + encodeURIComponent(sessionId) + '/join-slots/release', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ clientId })
    }).catch(() => {});
}

function stopJoinPpAndExeSidecars() {
    if (simulationJoinExePpPollIntervalId) {
        clearInterval(simulationJoinExePpPollIntervalId);
        simulationJoinExePpPollIntervalId = null;
    }
    if (simulationJoinPpPresenceHeartbeatIntervalId) {
        clearInterval(simulationJoinPpPresenceHeartbeatIntervalId);
        simulationJoinPpPresenceHeartbeatIntervalId = null;
    }
    if (simulationJoinPpVerticalPushIntervalId) {
        clearInterval(simulationJoinPpVerticalPushIntervalId);
        simulationJoinPpVerticalPushIntervalId = null;
    }
    simulationJoinPpPresentOnMySector = false;
    ppSectorPeerClientIds = [];
    ppServerWorkloadAssignmentById = new Map();
}

function updateJoinPpPresentFlagFromSnapshot(ppSectors) {
    const mine = simulationJoinAtcSectorId;
    if (!mine) {
        simulationJoinPpPresentOnMySector = false;
        return;
    }
    simulationJoinPpPresentOnMySector = !!(Array.isArray(ppSectors) && ppSectors.some(id => String(id) === String(mine)));
}

function fetchJoinSlotsSnapshot(sessionId) {
    const cid = encodeURIComponent(getOrCreateJoinClientId());
    return fetch('/api/sessions/' + encodeURIComponent(sessionId) + '/join-slots?clientId=' + cid)
        .then(r => (r.ok ? r.json() : { taken: [], ppSectors: [], ppPresence: [] }))
        .then(d => ({
            taken: Array.isArray(d.taken) ? d.taken : [],
            ppSectors: Array.isArray(d.ppSectors) ? d.ppSectors : [],
            ppPresence: Array.isArray(d.ppPresence) ? d.ppPresence : []
        }))
        .catch(() => ({ taken: [], ppSectors: [], ppPresence: [] }));
}

function updatePpSectorPeerClientIdsFromSnapshot(ppPresence) {
    mergePpSectorPeerClientIds(null, ppPresence);
}

/** Union peer ids from heartbeat response (ppPeersOnSector) and join-slots snapshot rows. */
function mergePpSectorPeerClientIds(directPeerClientIds, ppPresenceRows) {
    const mine = simulationJoinAtcSectorId;
    if (!mine || !isJoinerPpClient()) {
        ppSectorPeerClientIds = [];
        return;
    }
    const ids = new Set();
    if (Array.isArray(directPeerClientIds)) {
        directPeerClientIds.forEach((cid) => {
            if (cid != null && String(cid).trim() !== '') ids.add(String(cid));
        });
    }
    if (Array.isArray(ppPresenceRows)) {
        ppPresenceRows.forEach((row) => {
            if (!row || !row.clientId || !row.atcSectorId) return;
            if (String(row.atcSectorId) === String(mine)) ids.add(String(row.clientId));
        });
    }
    if (simulationJoinClientId) ids.add(String(simulationJoinClientId));
    ppSectorPeerClientIds = Array.from(ids).sort();
}

/** @deprecated use mergePpSectorPeerClientIds */
function updatePpSectorPeerClientIdsFromPresenceList(peerClientIds, isDirectClientIdList) {
    if (isDirectClientIdList) mergePpSectorPeerClientIds(peerClientIds, null);
    else mergePpSectorPeerClientIds(null, peerClientIds);
}

function maybeRefreshPpSectorPeersThrottled(sessionId) {
    if (!isJoinerPpClient() || !sessionId) return;
    const now = Date.now();
    if (now - ppSectorPeersLastRefreshMs < 2500) return;
    ppSectorPeersLastRefreshMs = now;
    fetchJoinSlotsSnapshot(sessionId)
        .then((snap) => mergePpSectorPeerClientIds(null, snap.ppPresence))
        .catch(() => {});
}

/** Aircraft whose remaining route includes the user's sector, or currently inside / handling it. */
function aircraftEligibleForPpSectorWorkloadSplit(ac) {
    const ctx = getSimulationUserAtcSectorContext();
    if (!ctx || ctx.mode !== 'single' || !ctx.sectorNameNorm || !ctx.atcSectorId) return false;
    const seq = computeAdvancedLabelSectorSequence(ac);
    const target = ctx.sectorNameNorm;
    if (Array.isArray(seq) && seq.some((n) => (n || '').toString().trim().toUpperCase() === target)) return true;
    if (aircraftIsInsideAtcSectorBoundaryById(ac, ctx.atcSectorId)) return true;
    if (aircraftTransferInProgress(ac)) {
        if (String(getAcTransferFromAtcSectorId(ac) || '') === String(ctx.atcSectorId)) return true;
        if (getAcTransferToSectorNameNorm(ac) === ctx.sectorNameNorm) return true;
    }
    const { status, sectorId } = resolveAsmFlightStatusFromAircraft(ac);
    if (status === 'ASM' && String(sectorId || '') === String(ctx.atcSectorId)) return true;
    return false;
}

function collectPpSectorEligibleAircraftIds() {
    const ids = [];
    (window.simulationData?.aircraft || []).forEach((ac) => {
        if (!ac || ac.id == null) return;
        if (!aircraftEligibleForPpSectorWorkloadSplit(ac)) return;
        ids.push(String(ac.id));
    });
    ids.sort((a, b) => a.localeCompare(b, undefined, { numeric: true }));
    return ids;
}

function applyPpServerWorkloadAssignments(raw) {
    ppServerWorkloadAssignmentById = new Map();
    if (!raw || typeof raw !== 'object') return;
    Object.entries(raw).forEach(([aid, cid]) => {
        if (aid != null && cid != null && String(cid).trim() !== '') {
            ppServerWorkloadAssignmentById.set(String(aid), String(cid));
        }
    });
}

function ppWorkloadRectVisibleStrokeColor(secondary) {
    const c = (secondary || '').toString().trim();
    if (!c) return '#888888';
    const u = c.toUpperCase();
    if (u === '#FFFFFF' || u === '#FFF' || u === 'WHITE') return '#555555';
    if (u === '#ADD8E6') return '#2563EB';
    return c;
}

function startJoinPpPresenceHeartbeat() {
    if (simulationJoinPpPresenceHeartbeatIntervalId) {
        clearInterval(simulationJoinPpPresenceHeartbeatIntervalId);
        simulationJoinPpPresenceHeartbeatIntervalId = null;
    }
    if (String(simulationJoinRole || '').toUpperCase() !== 'PP' || !simulationJoinedSessionId || !simulationJoinClientId) return;
    const sid = simulationJoinedSessionId;
    const cid = simulationJoinClientId;
    const atcId = simulationJoinAtcSectorId;
    if (!atcId) return;
    const tick = () => {
        if (!simulationJoinedSessionId || simulationJoinedSessionId !== sid) return;
        fetch('/api/sessions/' + encodeURIComponent(sid) + '/join-slots/pp-presence', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                clientId: cid,
                atcSectorId: atcId,
                eligibleAircraftIds: collectPpSectorEligibleAircraftIds()
            })
        })
            .then((r) => r.json().then((data) => ({ ok: r.ok, data })).catch(() => ({ ok: r.ok, data: null })))
            .then(({ ok, data }) => {
                const directPeers = (ok && data && Array.isArray(data.ppPeersOnSector)) ? data.ppPeersOnSector : null;
                if (ok && data && data.ppWorkloadAssignments) {
                    applyPpServerWorkloadAssignments(data.ppWorkloadAssignments);
                } else if (directPeers && directPeers.length < 2) {
                    applyPpServerWorkloadAssignments(null);
                }
                return fetchJoinSlotsSnapshot(sid).then((snap) => ({ snap, directPeers }));
            })
            .then(({ snap, directPeers }) => {
                mergePpSectorPeerClientIds(directPeers, snap?.ppPresence);
                if (ppSectorPeerClientIds.length < 2) applyPpServerWorkloadAssignments(null);
                if (document.getElementById('simulationModal')?.classList.contains('active')) {
                    try { drawSimulationCanvas(); } catch (e) {}
                }
            })
            .catch(() => {});
    };
    tick();
    simulationJoinPpPresenceHeartbeatIntervalId = setInterval(tick, 3000);
}

function startJoinExePpPresencePoll() {
    if (simulationJoinExePpPollIntervalId) {
        clearInterval(simulationJoinExePpPollIntervalId);
        simulationJoinExePpPollIntervalId = null;
    }
    if (String(simulationJoinRole || '').toUpperCase() !== 'EXE' || !simulationJoinedSessionId) return;
    const sid = simulationJoinedSessionId;
    const tick = () => {
        if (!simulationJoinedSessionId || simulationJoinedSessionId !== sid) return;
        fetchJoinSlotsSnapshot(sid).then(snap => updateJoinPpPresentFlagFromSnapshot(snap.ppSectors));
    };
    tick();
    simulationJoinExePpPollIntervalId = setInterval(tick, 4000);
}

function startJoinExclusiveSlotHeartbeat() {
    if (simulationJoinSlotHeartbeatIntervalId) {
        clearInterval(simulationJoinSlotHeartbeatIntervalId);
        simulationJoinSlotHeartbeatIntervalId = null;
    }
    if (!simulationJoinedSessionId || !simulationJoinClientId) return;
    const role = (simulationJoinRole || '').toUpperCase();
    if (role === 'OBS' || role === 'PP' || !JOIN_ASSIGN_EXCLUSIVE_ROLES.includes(role)) return;
    const sid = simulationJoinedSessionId;
    const cid = simulationJoinClientId;
    const atcId = simulationJoinAtcSectorId;
    const tick = () => {
        if (!simulationJoinedSessionId || simulationJoinedSessionId !== sid) return;
        fetch('/api/sessions/' + encodeURIComponent(sid) + '/join-slots/heartbeat', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ clientId: cid, atcSectorId: atcId, role })
        }).catch(() => {});
    };
    tick();
    simulationJoinSlotHeartbeatIntervalId = setInterval(tick, 3000);
}

function applySessionStateAndOpenSimAsJoiner(sessionId, joinOpts = null) {
    fetch('/api/sessions/' + encodeURIComponent(sessionId)).then(r => {
        if (!r.ok) throw new Error(r.statusText);
        return r.json();
    }).then(data => {
        const state = data.state;
        if (!state) throw new Error('No state');
        // Set join identity before applySessionState so EXE label/trajectory patch logic runs on first sync.
        simulationJoinedSessionId = sessionId;
        simulationSessionId = null;
        if (joinOpts && joinOpts.clientId) {
            simulationJoinClientId = joinOpts.clientId;
            simulationJoinAtcSectorId = joinOpts.atcSectorId || null;
            simulationJoinRole = (joinOpts.role || 'OBS').toUpperCase();
            simulationJoinBoundaryIdFilter = joinOpts.boundaryId || null;
        } else {
            simulationJoinClientId = null;
            simulationJoinAtcSectorId = null;
            simulationJoinRole = null;
            simulationJoinBoundaryIdFilter = null;
        }
        const joinRoleU = String(simulationJoinRole || 'OBS').toUpperCase();
        simulationIsMonitorOnly = (data.mode === 'DL') && !JOIN_DL_INTERACTIVE_ROLES.has(joinRoleU);
        stopJoinPpAndExeSidecars();
        clearJoinerExeAircraftPatches();
        if (joinRoleU === 'PP') {
            simulationJoinPpAwaitingFullState = true;
            ppJoinerLateralCmdSeqById = {};
            ppJoinerPendingRocHundredsById = {};
            ppJoinerPendingAlvFlById = {};
            ppJoinerPendingDestRunwayById = {};
        }
        applySessionState(state);
        const atcSectorLabel = getJoinerSelectedAtcSectorDisplayName();
        document.getElementById('simulationTitle').textContent = formatJoinerSimulationTitle(
            data.exerciseName,
            data.sectorName,
            atcSectorLabel,
            simulationJoinRole
        );
        updateSimulationOperationModeUi();
        startSimulationClock(false);
        updateSimulationSpeedStatusUI();
        updateSimulationClockUI();
        openModal('simulationModal');
        syncSimulationPlaybackButtonsVisibility();
        try { syncSimulationHostAtcScopeSelect(); } catch (e) {}
        setTimeout(() => { initSimulationCanvas(); }, 100);
        startJoinExclusiveSlotHeartbeat();
        startJoinPpPresenceHeartbeat();
        startJoinExePpPresencePoll();
        startJoinPpVerticalPush();
        simulationJoinPollIntervalId = setInterval(() => {
            if (!simulationJoinedSessionId) return;
            fetch('/api/sessions/' + encodeURIComponent(simulationJoinedSessionId)).then(r => r.ok ? r.json() : null).then(data => {
                if (!data || !data.state) return;
                applySessionState(data.state);
                updateSimulationClockUI();
                updateSimulationSpeedStatusUI();
                const modalActive = document.getElementById('simulationModal')?.classList.contains('active');
                // Joiner DL: avoid stacking a full redraw on top of label-drag rAF work (main-thread contention + twitching).
                if (modalActive && !(simulationIsDraggingAircraftLabel && isJoinerAtmDisplayClient())) {
                    drawSimulationCanvas();
                }
            }).catch(() => {});
        }, MULTIPLAYER_STATE_SYNC_INTERVAL_MS);
    }).catch(err => {
        alert('Could not join session: ' + (err.message || 'Unknown error'));
    });
}

function stopJoinAssignModalPolling() {
    if (joinAssignModalPollIntervalId) {
        clearInterval(joinAssignModalPollIntervalId);
        joinAssignModalPollIntervalId = null;
    }
    if (joinAssignSessionLoadTimerId) {
        clearTimeout(joinAssignSessionLoadTimerId);
        joinAssignSessionLoadTimerId = null;
    }
}

function fetchJoinSlotsTaken(sessionId) {
    return fetchJoinSlotsSnapshot(sessionId).then(s => s.taken);
}

function refreshJoinSessionAssignSlots() {
    const sid = joinAssignPendingSessionId;
    if (!sid) return;
    fetchJoinSlotsTaken(sid).then(t => {
        joinAssignTakenSlots = t;
        renderJoinSessionAssignModalUi();
    });
}

function renderJoinSessionAssignModalUi() {
    const loading = document.getElementById('joinSessionAssignLoading');
    const content = document.getElementById('joinSessionAssignContent');
    const sectorList = document.getElementById('joinSessionSectorList');
    const roleRow = document.getElementById('joinSessionRoleRow');
    const errEl = document.getElementById('joinSessionAssignError');
    const confirmBtn = document.getElementById('joinSessionAssignConfirmBtn');
    if (errEl) { errEl.style.display = 'none'; errEl.textContent = ''; }
    if (!sectorList || !roleRow) return;
    if (!joinAssignOptions.length) {
        if (loading) loading.textContent = 'This session has no ATC sector boundaries to join.';
        if (content) content.style.display = 'none';
        if (confirmBtn) confirmBtn.disabled = true;
        return;
    }
    if (loading) loading.style.display = 'none';
    if (content) content.style.display = 'block';
    const myId = getOrCreateJoinClientId();
    sectorList.innerHTML = '';
    joinAssignOptions.forEach(opt => {
        const row = document.createElement('div');
        row.className = 'join-session-sector-item' + (joinAssignSelectedAtcId === opt.atcSectorId ? ' selected' : '');
        row.dataset.atcId = opt.atcSectorId;
        row.innerHTML = `<input type="radio" name="joinAssignSector" ${joinAssignSelectedAtcId === opt.atcSectorId ? 'checked' : ''} style="accent-color:#22c55e" /> <span>${escapeHtml(opt.name)}</span>`;
        row.addEventListener('click', () => {
            joinAssignSelectedAtcId = opt.atcSectorId;
            renderJoinSessionAssignModalUi();
        });
        sectorList.appendChild(row);
    });
    roleRow.innerHTML = '';
    const selAtc = joinAssignSelectedAtcId;
    JOIN_ASSIGN_ALL_ROLES.forEach(role => {
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'join-session-role-btn';
        btn.textContent = role;
        const taken = joinAssignTakenSlots.find(
            t => t && String(t.atcSectorId) === String(selAtc) && String(t.role).toUpperCase() === role
        );
        const takenByOther = !!(taken && JOIN_ASSIGN_EXCLUSIVE_ROLES.includes(role) && (
            taken.occupiedByOther === true ||
            (taken.clientId && String(taken.clientId) !== String(myId))
        ));
        if (JOIN_ASSIGN_EXCLUSIVE_ROLES.includes(role) && takenByOther) {
            btn.classList.add('taken');
            btn.disabled = true;
            btn.title = 'In use by another participant';
        } else {
            btn.addEventListener('click', () => {
                joinAssignSelectedRole = role;
                renderJoinSessionAssignModalUi();
            });
        }
        if (joinAssignSelectedRole === role) btn.classList.add('selected');
        roleRow.appendChild(btn);
    });
    const canJoin = !!(selAtc && joinAssignSelectedRole && joinAssignOptions.some(o => String(o.atcSectorId) === String(selAtc)));
    let exclusiveBlocked = false;
    if (canJoin && JOIN_ASSIGN_EXCLUSIVE_ROLES.includes(joinAssignSelectedRole)) {
        const t = joinAssignTakenSlots.find(
            x => x && String(x.atcSectorId) === String(selAtc) && String(x.role).toUpperCase() === joinAssignSelectedRole
        );
        exclusiveBlocked = !!(t && (
            t.occupiedByOther === true ||
            (t.clientId && String(t.clientId) !== String(myId))
        ));
    }
    if (confirmBtn) confirmBtn.disabled = !canJoin || exclusiveBlocked;
}

function openJoinSessionAssignModal(sessionId) {
    joinAssignPendingSessionId = sessionId;
    joinAssignOptions = [];
    joinAssignSelectedAtcId = null;
    joinAssignSelectedRole = null;
    joinAssignTakenSlots = [];
    const loading = document.getElementById('joinSessionAssignLoading');
    const content = document.getElementById('joinSessionAssignContent');
    if (loading) {
        loading.style.display = 'block';
        loading.textContent = 'Loading session…';
    }
    if (content) content.style.display = 'none';
    stopJoinAssignModalPolling();
    openModal('joinSessionAssignModal');

    let waitAttempts = 0;
    const maxWaitAttempts = 90;

    const loadWhenReady = () => {
        fetch('/api/sessions/' + encodeURIComponent(sessionId))
            .then(r => r.json().then(data => ({ ok: r.ok, status: r.status, data })))
            .then(({ ok, status, data }) => {
                if (joinAssignPendingSessionId !== sessionId) return;
                const state = data && data.state;
                const hasSim = state && state.simulationData;
                if (!ok || !hasSim) {
                    const errLower = (data && data.error) ? String(data.error).toLowerCase() : '';
                    if (status === 404 && errLower.includes('not found')) {
                        throw new Error(data.error || 'Session not found');
                    }
                    const waitingHost = status === 404 && errLower.includes('no state');
                    if (waitingHost && waitAttempts < maxWaitAttempts) {
                        waitAttempts++;
                        if (loading) loading.textContent = 'Waiting for host simulation to start…';
                        joinAssignSessionLoadTimerId = setTimeout(loadWhenReady, 1000);
                        return;
                    }
                    throw new Error((data && data.error) || 'Session has no simulation data yet');
                }
                const sector = state.simulationData.sector;
                joinAssignOptions = getJoinAtcSectorPickerOptions(sector);
                return fetchJoinSlotsTaken(sessionId);
            })
            .then(taken => {
                if (joinAssignPendingSessionId !== sessionId) return;
                joinAssignTakenSlots = taken;
                if (joinAssignOptions.length && !joinAssignSelectedAtcId) {
                    joinAssignSelectedAtcId = joinAssignOptions[0].atcSectorId;
                }
                renderJoinSessionAssignModalUi();
                joinAssignModalPollIntervalId = setInterval(() => {
                    if (!document.getElementById('joinSessionAssignModal')?.classList.contains('active')) return;
                    if (joinAssignPendingSessionId !== sessionId) return;
                    fetchJoinSlotsTaken(sessionId).then(t => {
                        joinAssignTakenSlots = t;
                        renderJoinSessionAssignModalUi();
                    });
                }, 2000);
            })
            .catch(err => {
                alert('Could not open join dialog: ' + (err.message || 'Unknown error'));
                closeModal('joinSessionAssignModal');
            });
    };

    loadWhenReady();
}

/** Avoid r.json() rejection on HTML/empty error pages (shows real status to user). */
function parseFetchJsonResponse(r) {
    return r.text().then(text => {
        let data = {};
        if (text && text.trim()) {
            try {
                data = JSON.parse(text);
            } catch (e) {
                const snippet = text.replace(/\s+/g, ' ').slice(0, 180);
                throw new Error(`Server returned HTTP ${r.status} (not JSON). ${snippet || '(empty body)'}`);
            }
        }
        return { ok: r.ok, status: r.status, data };
    });
}

function confirmJoinSessionAssign() {
    const sessionId = joinAssignPendingSessionId;
    if (!sessionId || !joinAssignSelectedAtcId || !joinAssignSelectedRole) return;
    const opt = joinAssignOptions.find(o => String(o.atcSectorId) === String(joinAssignSelectedAtcId));
    if (!opt) return;
    const clientId = getOrCreateJoinClientId();
    const role = (joinAssignSelectedRole || '').toString().trim().toUpperCase();
    const errEl = document.getElementById('joinSessionAssignError');
    if (errEl) { errEl.style.display = 'none'; errEl.textContent = ''; }

    function finishJoinAfterClaim() {
        stopJoinAssignModalPolling();
        closeModal('joinSessionAssignModal');
        applySessionStateAndOpenSimAsJoiner(sessionId, {
            clientId,
            atcSectorId: String(joinAssignSelectedAtcId),
            role,
            boundaryId: opt.boundaryId
        });
    }

    if (JOIN_ASSIGN_SKIP_CLAIM_ROLES.includes(role)) {
        finishJoinAfterClaim();
        return;
    }

    fetch('/api/sessions/' + encodeURIComponent(sessionId) + '/join-slots/claim', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            clientId,
            atcSectorId: String(joinAssignSelectedAtcId),
            role
        })
    })
        .then(r => parseFetchJsonResponse(r))
        .then(({ ok, status, data }) => {
            if (!ok) {
                const msg = (data && data.error) || (status === 409 ? 'That role is already taken for this sector.' : `Could not claim role (HTTP ${status}).`);
                if (errEl) {
                    errEl.textContent = msg;
                    errEl.style.display = 'block';
                }
                return fetchJoinSlotsTaken(sessionId).then(t => {
                    joinAssignTakenSlots = t;
                    renderJoinSessionAssignModalUi();
                });
            }
            finishJoinAfterClaim();
        })
        .catch(err => {
            console.error('join-slots/claim failed', err);
            if (errEl) {
                errEl.textContent = (err && err.message) ? err.message : 'Network error — check that the app is open from the same server URL as the host and the server was restarted after updating.';
                errEl.style.display = 'block';
            }
        });
}

function formatHHMMSS(totalSeconds) {
    const s = Math.max(0, Math.floor(totalSeconds || 0));
    const hh = String(Math.floor(s / 3600)).padStart(2, '0');
    const mm = String(Math.floor((s % 3600) / 60)).padStart(2, '0');
    const ss = String(s % 60).padStart(2, '0');
    return `${hh}:${mm}:${ss}`;
}

function formatSimHHMM(totalSeconds) {
    const s = Math.max(0, Math.floor(Number(totalSeconds) || 0));
    const hh = String(Math.floor(s / 3600)).padStart(2, '0');
    const mm = String(Math.floor((s % 3600) / 60)).padStart(2, '0');
    return `${hh}:${mm}`;
}

/** Current simulation time (ms): host/solo use local `simulationSimTimeMs`; joiners use only host state (`joinerHostDisplaySimTimeMs`). */
function getEffectiveSimulationSimTimeMs() {
    if (isSimulationJoinerOnlyClient()) {
        if (joinerHostDisplaySimTimeMs != null && isFinite(Number(joinerHostDisplaySimTimeMs))) {
            return Math.max(0, Number(joinerHostDisplaySimTimeMs));
        }
        return 0;
    }
    return Math.max(0, simulationSimTimeMs);
}

function getSimulationClockSeconds() {
    return Math.floor(getEffectiveSimulationSimTimeMs() / 1000);
}

function updateSimulationSpeedStatusUI() {
    const el = document.getElementById('simulationSpeedStatus');
    if (!el) return;
    if (simulationRate > 1) el.textContent = `SPEED UP x${simulationRate}`;
    else if (simulationRate < -1) el.textContent = `REWIND x${Math.abs(simulationRate)}`;
    else el.textContent = '';
}

function updateSimulationClockUI() {
    const el = document.getElementById('simulationClock');
    if (!el) return;
    el.textContent = formatHHMMSS(getSimulationClockSeconds());
}

function updateSimulationClockFlashUI() {
    const el = document.getElementById('simulationClock');
    if (!el) return;
    // Flash red at 1Hz only in SPEED UP mode (forward rate > 1)
    if (simulationRate > 1) {
        const beatOn = (Math.floor(Date.now() / 1000) % 2) === 0;
        el.classList.toggle('sim-clock-flash-red', beatOn);
    } else {
        el.classList.remove('sim-clock-flash-red');
    }
}

function simulationClockTick() {
    const now = Date.now();
    if (!simulationLastRealTickMs) simulationLastRealTickMs = now;
    const dt = now - simulationLastRealTickMs;
    simulationLastRealTickMs = now;

    if (!simulationIsPaused) {
        if (!isSimulationJoinerOnlyClient()) {
            simulationSimTimeMs += dt * simulationRate;
            if (simulationSimTimeMs < 0) simulationSimTimeMs = 0;
        }
    }
    // Joiners: no local clock UI — master time updates only on host GET (MULTIPLAYER_STATE_SYNC_INTERVAL_MS).
    if (!isSimulationJoinerOnlyClient()) {
        updateSimulationClockUI();
    }
    updateSimulationClockFlashUI();

    // Joiners: no local sim-second integration or tick-based redraw; host poll applies state + clock + draw.
    if (isSimulationJoinerOnlyClient()) {
        return;
    }

    // Redraw the simulation at least once per sim-second so spawns (e.g. 10s) appear without user interaction.
    try {
        const modal = document.getElementById('simulationModal');
        if (modal && modal.classList.contains('active')) {
            // Update aircraft altitude/ROC/heading only when not paused (pause stops everything)
            try {
                const dtSimSec = (dt * simulationRate) / 1000;
                if (!simulationIsPaused && dtSimSec > 0 && simulationOperationModeId === 'DL') {
                    updateSimulationAircraftAltitudes(dtSimSec);
                    updateSimulationAircraftSpeeds(dtSimSec);
                    updateSimulationAircraftHeadings(dtSimSec);
                }
            } catch (e) {}
            const sec = getSimulationClockSeconds();
            if (simulationLastDrawnSecond === null || sec !== simulationLastDrawnSecond) {
                simulationLastDrawnSecond = sec;
                // Compute STCA in same tick as aircraft updates so projections match displayed positions
                updateStcaStateCache(sec);
                drawSimulationCanvas();
                recordSimulationAircraftSnapshot();
                try { updateAiPpPilotCallOnFrequencyChecks(); } catch (ePilot) {}
                try { updateAiPpScriptTriggers(); } catch (eScript) {}
            }
        }
    } catch (e) {}
}

function startSimulationClock(reset = true) {
    if (reset) {
        simulationSimTimeMs = 0;
        simulationRate = 1;
        simulationIsPaused = false;
        simulationLastDrawnSecond = null;
    }
    simulationLastRealTickMs = Date.now();
    if (simulationClockTimerId) clearInterval(simulationClockTimerId);
    simulationClockTimerId = setInterval(simulationClockTick, 250);
    updateSimulationClockUI();
    updateSimulationClockFlashUI();
    updateSimulationSpeedStatusUI();
    updatePauseButtonUI();
}

function stopSimulationClock(resetUI = false) {
    if (simulationClockTimerId) {
        clearInterval(simulationClockTimerId);
        simulationClockTimerId = null;
    }
    simulationSimTimeMs = 0;
    simulationLastRealTickMs = 0;
    simulationRate = 1;
    simulationIsPaused = false;
    simulationLastDrawnSecond = null;
    joinerHostDisplaySimTimeMs = null;
    joinerLastAppliedHostSimTimeMs = null;
    joinerLastAppliedHostStateSeq = null;
    if (resetUI) {
        const el = document.getElementById('simulationClock');
        if (el) el.textContent = '00:00:00';
        if (el) el.classList.remove('sim-clock-flash-red');
        const st = document.getElementById('simulationSpeedStatus');
        if (st) st.textContent = '';
        const overlay = document.getElementById('simulationPausedOverlay');
        if (overlay) overlay.style.display = 'none';
        updatePauseButtonUI();
    }
}

function updatePauseButtonUI() {
    const btn = document.getElementById('pauseSimulationBtn');
    if (!btn) return;
    if (simulationIsPaused) btn.textContent = 'PLAY';
    else if (simulationRate !== 1) btn.textContent = 'PLAY X1';
    else btn.textContent = 'Pause';
}

/** Hosted DL: host/single-user playback controls; joiners follow the host clock. */
function syncSimulationPlaybackButtonsVisibility() {
    const hide = !!simulationJoinedSessionId;
    ['pauseSimulationBtn', 'rewindSimulationBtn', 'fastForwardSimulationBtn'].forEach((id) => {
        const el = document.getElementById(id);
        if (!el) return;
        el.style.display = hide ? 'none' : '';
    });
    const restartBtn = document.getElementById('restartSimulationBtn');
    if (restartBtn) {
        const showRestart = !simulationJoinedSessionId && !!window.simulationData;
        restartBtn.style.display = showRestart ? '' : 'none';
    }
}

function setSimulationPaused(paused) {
    simulationIsPaused = !!paused;
    const overlay = document.getElementById('simulationPausedOverlay');
    if (overlay) overlay.style.display = simulationIsPaused ? 'block' : 'none';
    updatePauseButtonUI();
    updateSimulationClockUI();
    updateSimulationClockFlashUI();
}

function setSimulationRate(nextRate) {
    simulationRate = nextRate;
    // When entering speed/rewind mode, ensure we're not paused
    if (simulationRate !== 1 && simulationIsPaused) {
        simulationIsPaused = false;
        const overlay = document.getElementById('simulationPausedOverlay');
        if (overlay) overlay.style.display = 'none';
    }
    updateSimulationSpeedStatusUI();
    updatePauseButtonUI();
    updateSimulationClockFlashUI();
}

function stopSimulation() {
    try { finishSimulationRecording('stop'); } catch (e) {}
    window.removeEventListener('resize', handleSimulationResize);
    clearHostReconnectTimers();
    if (simulationHostStateIntervalId) {
        clearInterval(simulationHostStateIntervalId);
        simulationHostStateIntervalId = null;
    }
    stopHostPpLateralPoll();
    if (simulationJoinPollIntervalId) {
        clearInterval(simulationJoinPollIntervalId);
        simulationJoinPollIntervalId = null;
    }
    if (simulationSessionId) {
        const sid = simulationSessionId;
        simulationSessionId = null;
        fetch('/api/sessions/' + encodeURIComponent(sid), { method: 'DELETE' }).catch(() => {});
    }
    simulationSessionAtmMasterClientId = null;
    if (simulationJoinedSessionId && simulationJoinClientId) {
        releaseJoinSlotsOnServer(simulationJoinedSessionId, simulationJoinClientId);
    }
    if (simulationJoinSlotHeartbeatIntervalId) {
        clearInterval(simulationJoinSlotHeartbeatIntervalId);
        simulationJoinSlotHeartbeatIntervalId = null;
    }
    stopJoinPpAndExeSidecars();
    clearJoinerExeAircraftPatches();
    ppJoinerPendingRocHundredsById = {};
    ppJoinerPendingAlvFlById = {};
    ppJoinerPendingDestRunwayById = {};
    stopJoinAssignModalPolling();
    joinerHostDisplaySimTimeMs = null;
    joinerLastAppliedHostSimTimeMs = null;
    joinerLastAppliedHostStateSeq = null;
    joinerLastAppliedHostSessionRestartSeq = null;
    joinerSkipLabelOffsetPreserveOnce = false;
    joinerSkipHeldDisplayPreserveOnce = false;
    joinerAwaitingDeferredAtmSync = false;
    if (joinerDeferAtmSyncTimerId) {
        clearTimeout(joinerDeferAtmSyncTimerId);
        joinerDeferAtmSyncTimerId = null;
    }
    if (hostAutoSecondRestartTimerId) {
        clearTimeout(hostAutoSecondRestartTimerId);
        hostAutoSecondRestartTimerId = null;
    }
    hostRestartInProgress = false;
    hostSessionRestartSeq = 0;
    simulationJoinedSessionId = null;
    simulationIsMonitorOnly = false;
    simulationJoinClientId = null;
    simulationJoinAtcSectorId = null;
    simulationJoinRole = null;
    simulationJoinBoundaryIdFilter = null;
    simulationJoinPpAwaitingFullState = false;
    simulationSingleUserAtcSectorLocked = false;
    syncSimulationPlaybackButtonsVisibility();
    closeModal('simulationModal');
    closeModal('simulationColorsModal');
    closeModal('simulationMapModal');
    closeModal('simulationSettingsModal');
    closeModal('simulationEnMgmtRoutesModal');
    closeModal('simulationEnMgmtMergeRoutesModal');
    closeModal('simulationEnMgmtAddRouteModal');
    closeModal('simulationEnMgmtIdentifierModal');
    closeModal('simulationEnMgmtRulesModal');
    closeModal('simulationEnMgmtLevelsModal');
    closeModal('simulationEnMgmtSaveRoutesModal');
    closeModal('simulationEnMgmtSaveRoutesOverwriteModal');
    closeModal('simulationEnMgmtLoadRoutesModal');
    closeModal('simulationEnMgmtLoadRoutesDeleteConfirmModal');
    closeModal('simulationEnMgmtDeleteRoutesModal');
    closeModal('simulationEnMgmtDeleteRouteConfirmModal');
    closeModal('stopSimulationConfirmModal');
    closeModal('restartSimulationConfirmModal');
    window.simulationData = null;
    simulationAspectRatio = null;
    try { stopSimulationClock(true); } catch (e) {}
    try { setSimulationPaused(false); } catch (e) {}
    try { resetSimulationGlobalTtsState(); } catch (e) {}
    try { syncAdvancedLabelPanel(); } catch (e) {}
    try { hideSimulationEnMgmtUi(); } catch (e) {}
    try { updateSimulationTtsUi(); } catch (e) {}
}

/**
 * Host closed tab/window without Stop Simulation: DELETE session so Join list does not keep it forever.
 * fetch(..., { keepalive: true }) is designed to complete during page unload (unlike plain fetch).
 */
function sendHostSessionDeleteKeepalive() {
    const sid = simulationSessionId;
    if (!sid) return;
    try {
        fetch('/api/sessions/' + encodeURIComponent(sid), { method: 'DELETE', keepalive: true }).catch(() => {});
    } catch (e) {}
}

function installHostSessionAbandonHandlers() {
    window.addEventListener('pagehide', (ev) => {
        if (ev.persisted) return;
        sendHostSessionDeleteKeepalive();
    });
    window.addEventListener('beforeunload', () => {
        sendHostSessionDeleteKeepalive();
    });
}

function clearHostReconnectTimers() {
    if (hostReconnectTimeoutId != null) {
        clearTimeout(hostReconnectTimeoutId);
        hostReconnectTimeoutId = null;
    }
    hostReconnectPhase = false;
    hostStatePutInFlight = false;
}

/**
 * Hosted session: push state to Railway on an interval. One PUT in flight at a time; on failure, retry with
 * backoff then stop gracefully (avoids tight loops that overload the server and local connection pools).
 */
function startHostSessionStatePushInterval() {
    if (simulationHostStateIntervalId) {
        clearInterval(simulationHostStateIntervalId);
        simulationHostStateIntervalId = null;
    }
    clearHostReconnectTimers();
    if (!simulationSessionId) return;
    simulationHostStateIntervalId = setInterval(() => {
        if (!simulationSessionId || !window.simulationData || hostReconnectPhase) return;
        if (hostStatePutInFlight) return;
        const state = buildSessionState();
        if (!state) return;
        const sid = simulationSessionId;
        hostStatePutInFlight = true;
        fetch('/api/sessions/' + encodeURIComponent(sid) + '/state', { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(state) })
            .then((r) => r.json().then((data) => ({ ok: r.ok, status: r.status, data })).catch(() => ({ ok: r.ok, status: r.status, data: null })))
            .then(({ ok, status, data }) => {
                hostStatePutInFlight = false;
                if (!ok) {
                    if (status === 404) {
                        handleHostSessionConnectionLostFinal('Session no longer exists on the server.');
                        return;
                    }
                    beginHostReconnectAfterPutFailure();
                    return;
                }
                if (data && data.ppLateral) {
                    const applied = applyHostPpLateralSnapshotToLocalSim({ aircraft: data.ppLateral });
                    if (applied) pushHostSessionStateNowIfHosting();
                }
                if (data && data.ppFlightStatus) mergePpFlightStatusFromSessionState({ ppFlightStatus: data.ppFlightStatus });
                if (document.getElementById('simulationModal')?.classList.contains('active')) drawSimulationCanvas();
            })
            .catch(() => {
                hostStatePutInFlight = false;
                beginHostReconnectAfterPutFailure();
            });
    }, MULTIPLAYER_STATE_SYNC_INTERVAL_MS);
}

function beginHostReconnectAfterPutFailure() {
    if (!simulationSessionId || simulationJoinedSessionId) return;
    if (hostReconnectPhase) return;
    hostReconnectPhase = true;
    if (simulationHostStateIntervalId) {
        clearInterval(simulationHostStateIntervalId);
        simulationHostStateIntervalId = null;
    }
    stopHostPpLateralPoll();
    hostReconnectStartedAtMs = Date.now();
    try {
        const t = document.getElementById('simulationTitle');
        if (t) t.textContent = (t.textContent || '').replace(/\s*\(reconnecting[^)]*\)/i, '') + ' (reconnecting…)';
    } catch (e) {}
    hostReconnectTimeoutId = setTimeout(() => hostReconnectTickAttempt(), HOST_STATE_RECONNECT_INTERVAL_MS);
}

function hostReconnectTickAttempt() {
    hostReconnectTimeoutId = null;
    if (!hostReconnectPhase || !simulationSessionId || simulationJoinedSessionId) return;
    if (Date.now() - hostReconnectStartedAtMs > HOST_STATE_MAX_RECONNECT_MS) {
        handleHostSessionConnectionLostFinal('Could not reconnect to the server. Hosted session ended.');
        return;
    }
    const state = buildSessionState();
    if (!state) {
        hostReconnectTimeoutId = setTimeout(() => hostReconnectTickAttempt(), HOST_STATE_RECONNECT_INTERVAL_MS);
        return;
    }
    const sid = simulationSessionId;
    fetch('/api/sessions/' + encodeURIComponent(sid) + '/state', { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(state) })
        .then((r) => {
            if (r.ok) {
                hostReconnectPhase = false;
                clearHostReconnectTimers();
                startHostSessionStatePushInterval();
                startHostPpLateralPoll();
                try {
                    const t = document.getElementById('simulationTitle');
                    if (t) t.textContent = (t.textContent || '').replace(/\s*\(reconnecting[^)]*\)/i, '').trim();
                } catch (e) {}
                if (document.getElementById('simulationModal')?.classList.contains('active')) drawSimulationCanvas();
                return;
            }
            if (r.status === 404) {
                handleHostSessionConnectionLostFinal('Session no longer exists on the server.');
                return;
            }
            hostReconnectTimeoutId = setTimeout(() => hostReconnectTickAttempt(), HOST_STATE_RECONNECT_INTERVAL_MS);
        })
        .catch(() => {
            hostReconnectTimeoutId = setTimeout(() => hostReconnectTickAttempt(), HOST_STATE_RECONNECT_INTERVAL_MS);
        });
}

function handleHostSessionConnectionLostFinal(message) {
    clearHostReconnectTimers();
    if (simulationHostStateIntervalId) {
        clearInterval(simulationHostStateIntervalId);
        simulationHostStateIntervalId = null;
    }
    stopHostPpLateralPoll();
    if (!simulationSessionId || simulationJoinedSessionId) return;
    const msg = message || 'Connection to the server was lost.';
    try {
        alert(msg + ' The simulation will close.');
    } catch (e) {}
    stopSimulation();
}

/** Host only: pause when this tab is hidden (avoids timer throttling while backgrounded; joiners get pause via PUT state). */
function installHostAutoPauseWhenTabHidden() {
    document.addEventListener('visibilitychange', () => {
        if (document.visibilityState !== 'hidden') return;
        if (!simulationSessionId || simulationJoinedSessionId) return;
        const modal = document.getElementById('simulationModal');
        if (!modal || !modal.classList.contains('active')) return;
        if (!window.simulationData) return;
        if (simulationIsPaused) return;
        try {
            if (simulationRate !== 1) setSimulationRate(1);
            setSimulationPaused(true);
        } catch (e) {}
    });
}

