function createEmptyAdminFstLabelEntry() {
    return { nonHover: '', hover: '' };
}

function createEmptyAdminFstLabelSetupIds() {
    return Object.fromEntries(FLIGHT_STATUS_FST_KEYS.map(k => [k, createEmptyAdminFstLabelEntry()]));
}

function normalizeAdminFstLabelSetupIds(raw) {
    const out = createEmptyAdminFstLabelSetupIds();
    if (!raw || typeof raw !== 'object') return out;
    for (const key of FLIGHT_STATUS_FST_KEYS) {
        const val = raw[key];
        if (typeof val === 'string') {
            out[key].nonHover = val;
        } else if (val && typeof val === 'object') {
            out[key].nonHover = (val.nonHover || '').toString();
            out[key].hover = (val.hover || '').toString();
        }
    }
    return out;
}

function createEmptyHostedSessionsRoleLabelSetupIds() {
    return Object.fromEntries(HOSTED_SESSION_LABEL_ROLES.map(role => [role, createEmptyAdminFstLabelSetupIds()]));
}

function normalizeHostedSessionsRoleLabelSetupIds(raw, legacyFst) {
    const out = createEmptyHostedSessionsRoleLabelSetupIds();
    if (raw && typeof raw === 'object') {
        for (const role of HOSTED_SESSION_LABEL_ROLES) {
            if (raw[role]) out[role] = normalizeAdminFstLabelSetupIds(raw[role]);
        }
    }
    if (legacyFst && typeof legacyFst === 'object') {
        const legacy = normalizeAdminFstLabelSetupIds(legacyFst);
        const anySet = HOSTED_SESSION_LABEL_ROLES.some(role =>
            FLIGHT_STATUS_FST_KEYS.some(key => (out[role]?.[key]?.nonHover || out[role]?.[key]?.hover))
        );
        if (!anySet) {
            for (const role of HOSTED_SESSION_LABEL_ROLES) {
                out[role] = JSON.parse(JSON.stringify(legacy));
            }
        }
    }
    return out;
}

function normalizeHostedSessionsLabelProfilesFromServer(profiles) {
    if (!Array.isArray(profiles)) return [];
    return profiles.filter(p => p && typeof p === 'object' && p.id && p.name).map(p => ({
        id: (p.id || '').toString(),
        name: (p.name || '').toString(),
        roleLabelSetupIds: normalizeHostedSessionsRoleLabelSetupIds(
            p.roleLabelSetupIds,
            p.fstLabelSetupIds
        ),
        createdAt: p.createdAt,
        updatedAt: p.updatedAt
    }));
}

