const EN_MGMT_DETACHED_POS_KEY = 'atc_sim_en_mgmt_detached_pos_v1';
const EN_MGMT_DETACHED_ROUTES_POS_KEY = 'atc_sim_en_mgmt_detached_routes_pos_v1';
const EN_MGMT_RULE_DEBUG_POS_KEY = 'atc_sim_en_mgmt_rule_debug_pos_v1';

