function installAdvancedLabelPanelDrag() {
    const panel = document.getElementById('simulationAdvancedLabel');
    const header = document.getElementById('simulationAdvancedLabelHeader');
    if (!panel || !header || header._advLabelDragInstalled) return;
    header._advLabelDragInstalled = true;
    let drag = null;
    header.addEventListener('mousedown', (e) => {
        if (e.button !== 0) return;
        const r = panel.getBoundingClientRect();
        drag = { startX: e.clientX, startY: e.clientY, origLeft: r.left, origTop: r.top };
        e.preventDefault();
        e.stopPropagation();
        header.style.cursor = 'grabbing';
    });
    window.addEventListener('mousemove', (e) => {
        if (!drag) return;
        const dx = e.clientX - drag.startX;
        const dy = e.clientY - drag.startY;
        let left = drag.origLeft + dx;
        let top = drag.origTop + dy;
        const w = panel.offsetWidth || 280;
        const h = panel.offsetHeight || 88;
        left = Math.max(8, Math.min(left, window.innerWidth - w - 8));
        top = Math.max(8, Math.min(top, window.innerHeight - h - 8));
        panel.style.left = `${left}px`;
        panel.style.top = `${top}px`;
    });
    window.addEventListener('mouseup', () => {
        if (!drag) return;
        saveAdvancedLabelPosition(panel);
        drag = null;
        header.style.cursor = 'grab';
    });
}
