// Simulation debug log (runtime only)
let simulationDebugLogEntries = []; // [{tSec:number, kind:string, aircraftId:string, callsign:string, msg:string, data?:object}]
let simulationDebugLogIntervalId = null;
const SIM_DEBUG_LOG_MAX = 2000;

// Simulation recording (persisted server-side to /recordings when the run ends)
let simulationRecording = null;
let simulationRecordingLastSnapshotSecond = null;
let simulationRecordingMeasurementSeq = 0;
let simulationRecordingActiveMeasurement = null;

function simulationRecordingRoundNumber(value, digits = 6) {
    if (value == null) return null;
    const n = Number(value);
    if (!Number.isFinite(n)) return null;
    const p = Math.pow(10, digits);
    return Math.round(n * p) / p;
}

function simulationRecordingClone(value, fallback = null) {
    try {
        return JSON.parse(JSON.stringify(value));
    } catch (e) {
        return fallback;
    }
}

const SIM_RECORDING_LABEL_STATE_FIELDS = [
    'callsign', 'aircraftType', 'destination',
    'assignedFl', 'alv', 'pel', 'rlv', 'modeSFl', 'pendingModeSTargetFl', 'pendingModeSAtSimSec',
    'modeCFeet', 'publishedModeCFeet', 'rocFpm', 'publishedRocFpm',
    'modeSTasKt', 'publishedModeSTasKt', 'publishedLabelGsKt',
    'speedReadoutMode', 'speedReadoutManualBand', 'speedSelectedType', 'speedSelectedValue',
    'speedChangeStartSimSec', 'speedChangeDurationSec', 'speedStartKtas', 'speedTargetKtas',
    'selectedHeadingDeg', 'publishedHeadingDeg', 'currentHeadingDeg',
    'directToWpIdx', 'directToWpName',
    'exitLevelFl',
    'destRunwayId', 'destRunwayEnd', 'destRunwayEndName',
    'selectedApproachId', 'selectedApproachName',
    'atmHoldLabelWaypointId', 'atmHoldLabelWaypointName',
    'atmHoldEntrySimSec', 'atmHoldEntryWaypointId', 'atmHoldMaxTiHMin',
    'exeFlightStatus', 'exeFlightStatusAtcSectorId'
];

function getSimulationRecordingLabelState(ac) {
    const out = {};
    if (!ac) return out;
    SIM_RECORDING_LABEL_STATE_FIELDS.forEach(key => {
        if (Object.prototype.hasOwnProperty.call(ac, key)) out[key] = ac[key];
    });
    return simulationRecordingClone(out, {});
}

function startSimulationRecording(exercise, sector) {
    if (!isAdminRecordSimulationsEnabled()) return;
    const startedAt = new Date().toISOString();
    simulationRecording = {
        format: 'AiTC-simulation-recording',
        version: 1,
        metadata: {
            exerciseId: exercise?.id != null ? String(exercise.id) : '',
            exerciseName: (exercise?.name || 'Untitled exercise').toString(),
            sectorId: sector?.id != null ? String(sector.id) : '',
            sectorName: (sector?.name || 'Untitled airspace').toString(),
            operationMode: simulationOperationModeId || '',
            sessionId: simulationSessionId || simulationJoinedSessionId || '',
            startedAt,
            endedAt: null,
            durationSimSec: null
        },
        playbackData: {
            simulationData: simulationRecordingClone(window.simulationData, null),
            simulationSettings: simulationRecordingClone(simulationSettings, null),
            simulationMap: simulationRecordingClone(simulationMap, null),
            simulationStyle: simulationRecordingClone(simulationStyle, null),
            labelZOrder: simulationRecordingClone(simulationLabelZOrder, [])
        },
        events: []
    };
    simulationRecordingLastSnapshotSecond = null;
    simulationRecordingMeasurementSeq = 0;
    simulationRecordingActiveMeasurement = null;
    recordSimulationEvent('recording_started', {
        zoom: simulationRecordingRoundNumber(simulationZoomLevel, 3),
        panX: simulationRecordingRoundNumber(simulationPanX, 2),
        panY: simulationRecordingRoundNumber(simulationPanY, 2)
    });
}

function recordSimulationEvent(type, data = {}, ac = null) {
    if (!simulationRecording) return;
    try {
        const ident = getSimulationAircraftIdent(ac);
        simulationRecording.events.push({
            wallTime: new Date().toISOString(),
            simSec: simulationRecordingRoundNumber(getSimulationClockSeconds(), 2),
            type: (type || 'event').toString(),
            aircraftId: ident.aircraftId,
            callsign: ident.callsign,
            data: (data && typeof data === 'object') ? data : {}
        });
    } catch (e) {}
}

function recordSimulationSubtitleEvent(ac, text, data = {}) {
    const subtitleText = (text || '').toString().trim();
    if (!subtitleText) return;
    recordSimulationEvent('subtitle', {
        ...(data && typeof data === 'object' ? data : {}),
        text: subtitleText
    }, ac);
}

function recordSimulationAircraftSnapshot(force = false) {
    if (!simulationRecording || !Array.isArray(simulationAircraftScreenStates)) return;
    const sec = Math.floor(getSimulationClockSeconds());
    if (!force && simulationRecordingLastSnapshotSecond === sec) return;
    simulationRecordingLastSnapshotSecond = sec;
    const liveById = new Map((window.simulationData?.aircraft || []).filter(Boolean).map(ac => [String(ac.id), ac]));
    const aircraft = simulationAircraftScreenStates
        .filter(a => a && a.aircraftId != null)
        .map(a => {
            const ac = liveById.get(String(a.aircraftId));
            let labelLines = [];
            try {
                const radarSec = Math.max(1, parseInt(simulationSettings?.radarUpdateSeconds, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
                const state = ac ? getAircraftPositionAtRadarUpdate(ac, getSimulationClockSeconds(), radarSec) : null;
                const showFreeText = isSimulationAircraftLabelHovered(ac);
                labelLines = ac && state ? getLabelLayoutLinesForAircraft(ac, state, { showFreeText, hover: showFreeText }) : [];
            } catch (e) {
                labelLines = [];
            }
            return {
                aircraftId: String(a.aircraftId),
                callsign: (ac?.callsign || a.callsign || '').toString(),
                lat: simulationRecordingRoundNumber(a.lat, 6),
                lon: simulationRecordingRoundNumber(a.lon, 6),
                x: simulationRecordingRoundNumber(a.x, 2),
                y: simulationRecordingRoundNumber(a.y, 2),
                gs: simulationRecordingRoundNumber(a.gs ?? ac?.publishedLabelGsKt ?? ac?.publishedModeSTasKt, 1),
                heading: simulationRecordingRoundNumber(ac?.publishedHeadingDeg ?? ac?.currentHeadingDeg ?? ac?.selectedHeadingDeg, 1),
                modeCFeet: Number.isFinite(Number(ac?.publishedModeCFeet ?? ac?.modeCFeet)) ? Math.round(Number(ac?.publishedModeCFeet ?? ac?.modeCFeet)) : null,
                labelOffsetX: simulationRecordingRoundNumber(ac?.labelOffsetX, 2),
                labelOffsetY: simulationRecordingRoundNumber(ac?.labelOffsetY, 2),
                labelLeaderOffsetToCenter: !!ac?.labelLeaderOffsetToCenter,
                hideLabel: !!ac?.hideLabel,
                freeText: (simulationAircraftFreeTextById?.[String(a.aircraftId)] || '').toString(),
                labelState: getSimulationRecordingLabelState(ac),
                labelLines
            };
        });
    recordSimulationEvent('aircraft_snapshot', {
        count: aircraft.length,
        aircraft
    });
}

function finishSimulationRecording(reason = 'stop') {
    if (!simulationRecording) return;
    const recording = simulationRecording;
    try {
        recordSimulationAircraftSnapshot(true);
    } catch (e) {}
    simulationRecording = null;
    simulationRecordingLastSnapshotSecond = null;
    simulationRecordingActiveMeasurement = null;
    recording.metadata.endedAt = new Date().toISOString();
    recording.metadata.durationSimSec = simulationRecordingRoundNumber(getSimulationClockSeconds(), 2);
    recording.events.push({
        wallTime: recording.metadata.endedAt,
        simSec: recording.metadata.durationSimSec,
        type: 'recording_finished',
        aircraftId: '',
        callsign: '',
        data: { reason }
    });
    fetch('/api/recordings', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ recording })
    }).catch(() => {});
}

function getSimulationAircraftIdent(ac) {
    if (!ac) return { aircraftId: '', callsign: '' };
    const aircraftId = (ac.id != null) ? String(ac.id) : '';
    const callsign = (ac.callsign != null) ? String(ac.callsign).trim().toUpperCase() : '';
    return { aircraftId, callsign };
}

function pushSimulationDebugLog(kind, ac, msg, data = null) {
    try {
        const tSec = getSimulationClockSeconds();
        const ident = getSimulationAircraftIdent(ac);
        const entry = {
            tSec,
            kind: (kind || '').toString().trim().toUpperCase() || 'LOG',
            aircraftId: ident.aircraftId,
            callsign: ident.callsign,
            msg: (msg || '').toString(),
            data: (data && typeof data === 'object') ? data : null
        };
        simulationDebugLogEntries.push(entry);
        recordSimulationEvent('debug_log', entry, ac);
        if (simulationDebugLogEntries.length > SIM_DEBUG_LOG_MAX) {
            simulationDebugLogEntries.splice(0, simulationDebugLogEntries.length - SIM_DEBUG_LOG_MAX);
        }
        // Live refresh if the modal is open.
        try {
            const m = document.getElementById('simulationDebugLogModal');
            if (m && m.classList.contains('active')) {
                renderSimulationDebugLogToTextarea(true);
            }
        } catch (e2) {}
    } catch (e) {}
}

function buildSimulationDebugLogText() {
    const lines = [];
    for (const e of simulationDebugLogEntries) {
        if (!e) continue;
        const ts = formatHHMMSS(e.tSec);
        const who = (e.callsign || e.aircraftId) ? `${(e.callsign || '').padEnd(8, ' ')}${e.aircraftId ? ` (${e.aircraftId})` : ''}`.trim() : '';
        const prefix = `[${ts}] ${String(e.kind || 'LOG').padEnd(3, ' ')}`;
        const mid = who ? ` ${who}:` : '';
        const msg = (e.msg || '').toString();
        lines.push(`${prefix}${mid} ${msg}`.trimEnd());
    }
    return lines.join('\n');
}

function renderSimulationDebugLogToTextarea(scrollToBottom = false) {
    const ta = document.getElementById('simulationDebugLogText');
    if (!ta) return;
    const txt = buildSimulationDebugLogText();
    ta.value = txt;
    if (scrollToBottom) {
        ta.scrollTop = ta.scrollHeight;
    }
}

function openSimulationDebugLogModal() {
    renderSimulationDebugLogToTextarea(true);
    openModal('simulationDebugLogModal');
    if (simulationDebugLogIntervalId) clearInterval(simulationDebugLogIntervalId);
    simulationDebugLogIntervalId = setInterval(() => {
        try {
            const m = document.getElementById('simulationDebugLogModal');
            if (!m || !m.classList.contains('active')) return;
            renderSimulationDebugLogToTextarea(false);
        } catch (e) {}
    }, 500);
}

function closeSimulationDebugLogModal() {
    closeModal('simulationDebugLogModal');
    if (simulationDebugLogIntervalId) {
        clearInterval(simulationDebugLogIntervalId);
        simulationDebugLogIntervalId = null;
    }
}

async function copySimulationDebugLogToClipboard() {
    const txt = buildSimulationDebugLogText();
    try {
        if (navigator.clipboard && navigator.clipboard.writeText) {
            await navigator.clipboard.writeText(txt);
            pushSimulationDebugLog('LOG', null, 'Debug log copied to clipboard');
            return true;
        }
    } catch (e) {}
    // Fallback
    try {
        const ta = document.getElementById('simulationDebugLogText');
        if (ta) {
            ta.focus();
            ta.select();
            document.execCommand('copy');
            pushSimulationDebugLog('LOG', null, 'Debug log copied to clipboard');
            return true;
        }
    } catch (e2) {}
    return false;
}

function getNextMeasurementColor() {
    const color = MEASUREMENT_COLORS[measurementColorCounter % MEASUREMENT_COLORS.length];
    measurementColorCounter += 1;
    return color;
}
let isDragging = false;
let dragStartX = 0;
let dragStartY = 0;
let dragStartPanX = 0;
let dragStartPanY = 0;

function isCenterWaypointName(name) {
    const n = (name || '').trim().toUpperCase();
    return n === 'CENTRE' || n === 'CENTER';
}

function clamp01(n) {
    if (!isFinite(n)) return 1;
    return Math.min(1, Math.max(0, n));
}

function getRouteKey(route, index) {
    if (route && (typeof route.id === 'string' || typeof route.id === 'number')) {
        return String(route.id);
    }
    if (route && typeof route.name === 'string' && route.name.trim()) {
        return `name:${route.name.trim()}`;
    }
    return `idx:${index}`;
}

// Resolve route key(s) to display names for popup. Returns array of unique names.
function getRouteDisplayNames(routeKeys) {
    if (!routeKeys || !Array.isArray(routeKeys)) return [];
    const simData = window.simulationData;
    if (!simData || !Array.isArray(simData.routes)) return [];
    const names = [];
    const seen = new Set();
    for (let idx = 0; idx < simData.routes.length; idx++) {
        const route = simData.routes[idx];
        const key = getRouteKey(route, idx);
        if (routeKeys.indexOf(key) >= 0 && route) {
            const name = (route.name && String(route.name).trim()) ? String(route.name).trim() : `Route ${idx + 1}`;
            if (!seen.has(name)) { seen.add(name); names.push(name); }
        }
    }
    return names;
}

// Set of waypoint names (uppercase) from an aircraft's trajectory (ac.points). Used for same/crossing route probing.
function waypointNameSetFromAircraft(ac) {
    const set = new Set();
    if (!ac || !Array.isArray(ac.points)) return set;
    for (const p of ac.points) {
        if (!p) continue;
        const n = (p.name || '').toString().trim();
        if (n.length > 0) set.add(n.toUpperCase());
    }
    return set;
}

// Find route object and index by route key. Returns { route, index } or null.
function getRouteByKey(routeKey) {
    const simData = window.simulationData;
    if (!simData || !Array.isArray(simData.routes)) return null;
    for (let idx = 0; idx < simData.routes.length; idx++) {
        const route = simData.routes[idx];
        if (getRouteKey(route, idx) === routeKey) return { route, index: idx };
    }
    return null;
}

let dctRouteNamesPopupEl = null;
let dctRouteNamesPopupClose = null;
let dctRouteNamesPopupEscape = null;

// Called when user clicks a route name in the arrow popup: close routes popup and show Route-End popup.
function onDctRouteNameClicked(routeKey, routeName, center, target, clientX, clientY) {
    hideDctRouteNamesPopup();
    if (center && target && routeKey) showRouteEndPopup(routeKey, center, target, clientX, clientY);
}

function showRouteEndPopup(routeKey, center, target, clientX, clientY) {
    const found = getRouteByKey(routeKey);
    if (!found || !found.route || !Array.isArray(found.route.waypointIds)) return;
    const waypointIds = found.route.waypointIds;
    const simWaypoints = window.simulationData?.waypoints || [];
    const wpById = new Map(simWaypoints.filter(w => w && w.id).map(w => [w.id, w]));
    const centerIdx = waypointIds.indexOf(center.id);
    const targetIdx = waypointIds.indexOf(target.id);
    if (centerIdx < 0 || targetIdx < 0) return;
    let routeEndWaypoints = [];
    if (targetIdx === centerIdx - 1) {
        for (let i = centerIdx - 1; i >= 0; i--) {
            const w = wpById.get(waypointIds[i]);
            if (w && isFinite(w.latitude) && isFinite(w.longitude)) {
                routeEndWaypoints.push({
                    lat: w.latitude,
                    lon: w.longitude,
                    name: (w.name && String(w.name).trim()) ? String(w.name).trim().toUpperCase() : ''
                });
            }
        }
    } else if (targetIdx === centerIdx + 1) {
        for (let i = centerIdx + 1; i < waypointIds.length; i++) {
            const w = wpById.get(waypointIds[i]);
            if (w && isFinite(w.latitude) && isFinite(w.longitude)) {
                routeEndWaypoints.push({
                    lat: w.latitude,
                    lon: w.longitude,
                    name: (w.name && String(w.name).trim()) ? String(w.name).trim().toUpperCase() : ''
                });
            }
        }
    }
    if (!routeEndWaypoints.length) return;
    const canvasWrap = document.getElementById('simulationCanvas');
    if (!canvasWrap) return;
    const r = canvasWrap.getBoundingClientRect();
    const offsetX = 12;
    const offsetY = 8;
    dctRouteNamesPopupEl = document.createElement('div');
    dctRouteNamesPopupEl.className = 'sim-alv-picker sim-dct-picker';
    dctRouteNamesPopupEl.setAttribute('id', 'dctRouteEndPopup');
    dctRouteNamesPopupEl.style.display = 'block';
    dctRouteNamesPopupEl.style.left = '0';
    dctRouteNamesPopupEl.style.top = '0';
    dctRouteNamesPopupEl.style.zIndex = '100';
    dctRouteNamesPopupEl._routeEndWaypoints = routeEndWaypoints;
    const header = document.createElement('div');
    header.className = 'sim-alv-picker-header';
    header.textContent = 'Route-End';
    dctRouteNamesPopupEl.appendChild(header);
    const list = document.createElement('div');
    list.className = 'sim-alv-picker-list';
    routeEndWaypoints.forEach((wp, idx) => {
        const item = document.createElement('div');
        item.className = 'sim-alv-item';
        item.textContent = wp.name || `WP${idx + 1}`;
        item.dataset.routeEndIndex = String(idx);
        item.addEventListener('mousedown', (e) => {
            e.preventDefault();
            e.stopPropagation();
            const waypoints = dctRouteNamesPopupEl._routeEndWaypoints;
            if (!waypoints || !Array.isArray(waypoints)) return;
            const clickIdx = parseInt(item.dataset.routeEndIndex, 10);
            if (!Number.isFinite(clickIdx) || clickIdx < 0) return;
            const acId = simulationDctPathDrawingAircraftId;
            const ac = acId && window.simulationData && Array.isArray(window.simulationData.aircraft)
                ? window.simulationData.aircraft.find(a => a && a.id === acId) : null;
            if (!ac) { hideDctRouteNamesPopup(); return; }
            const segmentUpToClicked = waypoints.slice(0, clickIdx + 1);
            const userPath = Array.isArray(simulationDctPathPoints) ? simulationDctPathPoints.map(p => ({
                lat: Number(p.lat),
                lon: Number(p.lon),
                name: (p.name && String(p.name).trim()) ? String(p.name).trim() : null
            })) : [];
            const fullPath = userPath.concat(segmentUpToClicked);
            if (isJoinerPpClient()) {
                const pathSnap = fullPath.map(p => ({
                    lat: Number(p.lat),
                    lon: Number(p.lon),
                    name: (p.name && String(p.name).trim()) ? String(p.name).trim().toUpperCase() : ''
                }));
                ppJoinerPostLateralCommand(ac.id, { type: 'APPLY_PATH', pathPoints: pathSnap });
            } else {
                applyPathToAircraft(ac, fullPath);
            }
            cancelDctPathMode();
            hideDctRouteNamesPopup();
            drawSimulationCanvas();
        });
        list.appendChild(item);
    });
    dctRouteNamesPopupEl.appendChild(list);
    canvasWrap.appendChild(dctRouteNamesPopupEl);
    const pw = dctRouteNamesPopupEl.offsetWidth || 160;
    const ph = dctRouteNamesPopupEl.offsetHeight || 120;
    let left = clientX - r.left + offsetX;
    let top = clientY - r.top + offsetY;
    if (left + pw > r.width) left = r.width - pw - 4;
    if (left < 4) left = 4;
    if (top + ph > r.height) top = r.height - ph - 4;
    if (top < 4) top = 4;
    dctRouteNamesPopupEl.style.left = `${left}px`;
    dctRouteNamesPopupEl.style.top = `${top}px`;
    dctRouteNamesPopupEscape = (e) => { if (e.key === 'Escape') hideDctRouteNamesPopup(); };
    document.addEventListener('keydown', dctRouteNamesPopupEscape);
    dctRouteNamesPopupClose = (e) => {
        if (dctRouteNamesPopupEl && e.target && !dctRouteNamesPopupEl.contains(e.target)) hideDctRouteNamesPopup();
    };
    setTimeout(() => document.addEventListener('mousedown', dctRouteNamesPopupClose, true), 0);
}

function showDctRouteNamesPopup(routeKeys, clientX, clientY, center, target) {
    hideDctRouteNamesPopup();
    if (!routeKeys || !routeKeys.length) return;
    const canvasWrap = document.getElementById('simulationCanvas');
    if (!canvasWrap) return;
    const container = canvasWrap;
    const r = canvasWrap.getBoundingClientRect();
    const offsetX = 12;
    const offsetY = 8;
    dctRouteNamesPopupEl = document.createElement('div');
    dctRouteNamesPopupEl.className = 'sim-alv-picker sim-dct-picker';
    dctRouteNamesPopupEl.setAttribute('id', 'dctRouteNamesPopup');
    dctRouteNamesPopupEl.style.display = 'block';
    dctRouteNamesPopupEl.style.left = '0';
    dctRouteNamesPopupEl.style.top = '0';
    dctRouteNamesPopupEl.style.zIndex = '100';
    if (center) dctRouteNamesPopupEl._center = center;
    if (target) dctRouteNamesPopupEl._target = target;
    const header = document.createElement('div');
    header.className = 'sim-alv-picker-header';
    header.textContent = 'Routes';
    dctRouteNamesPopupEl.appendChild(header);
    const list = document.createElement('div');
    list.className = 'sim-alv-picker-list';
    routeKeys.forEach((routeKey) => {
        const names = getRouteDisplayNames([routeKey]);
        const routeName = names.length ? names[0] : routeKey;
        const item = document.createElement('div');
        item.className = 'sim-alv-item';
        item.textContent = routeName;
        item.dataset.routeKey = routeKey;
        item.dataset.routeName = routeName;
        item.addEventListener('mousedown', (e) => {
            e.preventDefault();
            e.stopPropagation();
            const cen = dctRouteNamesPopupEl._center;
            const tgt = dctRouteNamesPopupEl._target;
            try { onDctRouteNameClicked(routeKey, routeName, cen, tgt, e.clientX, e.clientY); } catch (err) {}
        });
        list.appendChild(item);
    });
    dctRouteNamesPopupEl.appendChild(list);
    container.appendChild(dctRouteNamesPopupEl);
    const pw = dctRouteNamesPopupEl.offsetWidth || 160;
    const ph = dctRouteNamesPopupEl.offsetHeight || 120;
    let left = clientX - r.left + offsetX;
    let top = clientY - r.top + offsetY;
    if (left + pw > r.width) left = r.width - pw - 4;
    if (left < 4) left = 4;
    if (top + ph > r.height) top = r.height - ph - 4;
    if (top < 4) top = 4;
    dctRouteNamesPopupEl.style.left = `${left}px`;
    dctRouteNamesPopupEl.style.top = `${top}px`;
    dctRouteNamesPopupEscape = (e) => { if (e.key === 'Escape') hideDctRouteNamesPopup(); };
    document.addEventListener('keydown', dctRouteNamesPopupEscape);
    dctRouteNamesPopupClose = (e) => {
        if (dctRouteNamesPopupEl && e.target && !dctRouteNamesPopupEl.contains(e.target)) hideDctRouteNamesPopup();
    };
    setTimeout(() => document.addEventListener('mousedown', dctRouteNamesPopupClose, true), 0);
}

function hideDctRouteNamesPopup() {
    if (dctRouteNamesPopupEl && dctRouteNamesPopupEl.parentNode) {
        dctRouteNamesPopupEl.parentNode.removeChild(dctRouteNamesPopupEl);
        dctRouteNamesPopupEl = null;
    }
    if (dctRouteNamesPopupClose) {
        document.removeEventListener('mousedown', dctRouteNamesPopupClose, true);
        dctRouteNamesPopupClose = null;
    }
    if (dctRouteNamesPopupEscape) {
        document.removeEventListener('keydown', dctRouteNamesPopupEscape);
        dctRouteNamesPopupEscape = null;
    }
}

// All unique directions (prev/next) at this waypoint across all routes; each direction has list of route keys.
// Returns { center: { id, lat, lon, name }, segments: [ { target: { id, lat, lon, name }, routeKeys: string[] }, ... ] }.
function findAllRouteDirections(waypointId) {
    const simData = window.simulationData;
    if (!simData || !Array.isArray(simData.routes)) return null;
    const simWaypoints = simData.waypoints || [];
    const wpById = new Map(simWaypoints.filter(w => w && w.id).map(w => [w.id, w]));
    const toWp = (id) => {
        const w = wpById.get(id);
        if (!w || !isFinite(w.latitude) || !isFinite(w.longitude)) return null;
        return { id: w.id, lat: w.latitude, lon: w.longitude, name: (w.name || '').toString().trim().toUpperCase() || null };
    };
    const centerWp = wpById.get(waypointId);
    if (!centerWp || !isFinite(centerWp.latitude) || !isFinite(centerWp.longitude)) return null;
    const center = { id: centerWp.id, lat: centerWp.latitude, lon: centerWp.longitude, name: (centerWp.name || '').toString().trim().toUpperCase() || null };
    const dirMap = new Map(); // key = target id (or lat,lon string) -> { target, routeKeys }
    const keyOf = (wp) => wp.id != null ? String(wp.id) : `${wp.lat},${wp.lon}`;
    for (let idx = 0; idx < simData.routes.length; idx++) {
        const route = simData.routes[idx];
        if (!route || !Array.isArray(route.waypointIds)) continue;
        const i = route.waypointIds.indexOf(waypointId);
        if (i < 0) continue;
        const routeKey = getRouteKey(route, idx);
        const prev = i > 0 ? toWp(route.waypointIds[i - 1]) : null;
        const next = i < route.waypointIds.length - 1 ? toWp(route.waypointIds[i + 1]) : null;
        if (prev) {
            const k = keyOf(prev);
            if (!dirMap.has(k)) dirMap.set(k, { target: prev, routeKeys: [] });
            dirMap.get(k).routeKeys.push(routeKey);
        }
        if (next) {
            const k = keyOf(next);
            if (!dirMap.has(k)) dirMap.set(k, { target: next, routeKeys: [] });
            dirMap.get(k).routeKeys.push(routeKey);
        }
    }
    const segments = Array.from(dirMap.values());
    if (!segments.length) return null;
    return { center, segments };
}

// Distance from point (px, py) to line segment (x1,y1)-(x2,y2) in pixels.
function distanceToSegment(px, py, x1, y1, x2, y2) {
    const dx = x2 - x1;
    const dy = y2 - y1;
    const lenSq = dx * dx + dy * dy;
    if (lenSq === 0) return Math.hypot(px - x1, py - y1);
    let t = ((px - x1) * dx + (py - y1) * dy) / lenSq;
    t = Math.max(0, Math.min(1, t));
    const qx = x1 + t * dx;
    const qy = y1 + t * dy;
    return Math.hypot(px - qx, py - qy);
}

// Resolve (lat, lon) or name to a sector waypoint for route lookup. Returns { id, lat, lon, name } or null.
function getSectorWaypointForRouteLookup(lat, lon, name) {
    const simWaypoints = window.simulationData?.waypoints || [];
    const nameNorm = (name && String(name).trim().toUpperCase()) || null;
    const POS_EPS = 1e-5;
    for (const w of simWaypoints) {
        if (!w || !w.id || !isFinite(w.latitude) || !isFinite(w.longitude)) continue;
        if (lat != null && lon != null && Math.abs(w.latitude - lat) < POS_EPS && Math.abs(w.longitude - lon) < POS_EPS)
            return { id: w.id, lat: w.latitude, lon: w.longitude, name: (w.name || '').toString().trim().toUpperCase() || null };
        if (nameNorm && (w.name || '').toString().trim().toUpperCase() === nameNorm)
            return { id: w.id, lat: w.latitude, lon: w.longitude, name: nameNorm };
    }
    return null;
}

/** After DCT path / reroute hacks, trajectory points often lack wpId — restore from sector waypoint name or lat/lon. */
function attachSectorWpIdsToSimTrajectoryPoints(pts) {
    if (!Array.isArray(pts)) return;
    for (let i = 0; i < pts.length; i++) {
        const p = pts[i];
        if (!p || !isFinite(Number(p.lat)) || !isFinite(Number(p.lon))) continue;
        if (p.wpId != null && String(p.wpId).trim() !== '') continue;
        const nm = (p.name || '').toString().trim();
        if (!nm && i === 0) continue;
        try {
            const sw = getSectorWaypointForRouteLookup(Number(p.lat), Number(p.lon), nm || null);
            if (sw && sw.id != null && String(sw.id).trim()) p.wpId = String(sw.id).trim();
        } catch (e) {}
    }
}

function loadSimulationMap() {
    try {
        const raw = localStorage.getItem(SIM_MAP_STORAGE_KEY);
        if (!raw) return;
        const parsed = JSON.parse(raw);
        if (!parsed || typeof parsed !== 'object') return;
        simulationMap = {
            waypointNames: {
                enabled: !!(parsed.waypointNames?.enabled ?? SIM_MAP_DEFAULTS.waypointNames.enabled),
                size: Math.min(48, Math.max(6, parseInt(parsed.waypointNames?.size ?? SIM_MAP_DEFAULTS.waypointNames.size, 10) || SIM_MAP_DEFAULTS.waypointNames.size))
            },
            waypointTriangles: {
                enabled: !!(parsed.waypointTriangles?.enabled ?? SIM_MAP_DEFAULTS.waypointTriangles.enabled),
                size: Math.min(60, Math.max(2, parseInt(parsed.waypointTriangles?.size ?? SIM_MAP_DEFAULTS.waypointTriangles.size, 10) || SIM_MAP_DEFAULTS.waypointTriangles.size))
            },
            labelSize: Math.min(24, Math.max(8, parseInt(parsed.labelSize ?? SIM_MAP_DEFAULTS.labelSize, 10) || SIM_MAP_DEFAULTS.labelSize)),
            routes: {
                enabled: !!(parsed.routes?.enabled ?? SIM_MAP_DEFAULTS.routes.enabled),
                selectedKeys: Array.isArray(parsed.routes?.selectedKeys) ? parsed.routes.selectedKeys.map(String) : null
            },
            boundaries: {
                enabled: !!(parsed.boundaries?.enabled ?? SIM_MAP_DEFAULTS.boundaries.enabled)
            },
            latLonLines: {
                enabled: !!(parsed.latLonLines?.enabled ?? SIM_MAP_DEFAULTS.latLonLines.enabled)
            },
            centerWaypoint: {
                enabled: !!(parsed.centerWaypoint?.enabled ?? SIM_MAP_DEFAULTS.centerWaypoint.enabled)
            },
            airports: {
                enabled: !!(parsed.airports?.enabled ?? SIM_MAP_DEFAULTS.airports.enabled),
                selectedIcaos: Array.isArray(parsed.airports?.selectedIcaos) ? parsed.airports.selectedIcaos.map(String) : null
            },
            runways: {
                enabled: !!(parsed.runways?.enabled ?? SIM_MAP_DEFAULTS.runways.enabled),
                namesEnabled: !!(parsed.runways?.namesEnabled ?? SIM_MAP_DEFAULTS.runways.namesEnabled),
                selectedKeys: Array.isArray(parsed.runways?.selectedKeys) ? parsed.runways.selectedKeys.map(String) : null
            },
            areas: {
                enabled: !!(parsed.areas?.enabled ?? SIM_MAP_DEFAULTS.areas.enabled),
                selectedIds: Array.isArray(parsed.areas?.selectedIds) ? parsed.areas.selectedIds.map(String) : null
            },
            holdings: {
                enabled: !!(parsed.holdings?.enabled ?? SIM_MAP_DEFAULTS.holdings.enabled),
                selectedIds: Array.isArray(parsed.holdings?.selectedIds) ? parsed.holdings.selectedIds.map(String) : null
            },
            backgrounds: {
                enabled: !!(parsed.backgrounds?.enabled ?? SIM_MAP_DEFAULTS.backgrounds.enabled),
                selectedIds: Array.isArray(parsed.backgrounds?.selectedIds) ? parsed.backgrounds.selectedIds.map(String) : null
            },
            runwayExtendedCenterline: normalizeSimulationRunwayExtendedCenterline(
                parsed.runwayExtendedCenterline ?? SIM_MAP_DEFAULTS.runwayExtendedCenterline
            )
        };
    } catch (e) {
        // ignore
    }
}

function loadSimulationSettings() {
    try {
        const raw = localStorage.getItem(SIM_SETTINGS_STORAGE_KEY);
        if (raw) {
            const obj = JSON.parse(raw);
            if (obj && typeof obj === 'object') {
                simulationSettings = { ...SIM_SETTINGS_DEFAULTS, ...obj };
            } else {
                simulationSettings = JSON.parse(JSON.stringify(SIM_SETTINGS_DEFAULTS));
            }
        } else {
            simulationSettings = JSON.parse(JSON.stringify(SIM_SETTINGS_DEFAULTS));
        }
    } catch (e) {
        simulationSettings = JSON.parse(JSON.stringify(SIM_SETTINGS_DEFAULTS));
    }

    // sanitize
    const v = parseInt(simulationSettings.radarUpdateSeconds, 10);
    simulationSettings.radarUpdateSeconds = (Number.isFinite(v) && v >= 1 && v <= 60) ? v : SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;

    const hd = parseInt(simulationSettings.historyDots, 10);
    simulationSettings.historyDots = (Number.isFinite(hd) && hd >= 0 && hd <= 7) ? hd : SIM_SETTINGS_DEFAULTS.historyDots;

    simulationSettings.spvEnabled = !!(simulationSettings.spvEnabled ?? SIM_SETTINGS_DEFAULTS.spvEnabled);
    const spv = parseInt(simulationSettings.spvMinutes, 10);
    simulationSettings.spvMinutes = (Number.isFinite(spv) && spv >= 0 && spv <= 60) ? spv : SIM_SETTINGS_DEFAULTS.spvMinutes;

    simulationSettings.ttsEnabled = !!(simulationSettings.ttsEnabled ?? SIM_SETTINGS_DEFAULTS.ttsEnabled);

    const tdm = (simulationSettings.trajectoryDisplayMode || SIM_SETTINGS_DEFAULTS.trajectoryDisplayMode).toString().toLowerCase();
    simulationSettings.trajectoryDisplayMode = (tdm === 'turn_radius' || tdm === 'point_to_point') ? tdm : SIM_SETTINGS_DEFAULTS.trajectoryDisplayMode;

    const tsl = (simulationSettings.trajectoryShowLabels || SIM_SETTINGS_DEFAULTS.trajectoryShowLabels).toString().toLowerCase();
    simulationSettings.trajectoryShowLabels = (tsl === 'estimates_only' || tsl === 'estimates_and_fl') ? tsl : SIM_SETTINGS_DEFAULTS.trajectoryShowLabels;

    const zs = parseInt(simulationSettings.zoomSensitivity, 10);
    simulationSettings.zoomSensitivity = (Number.isFinite(zs) && zs >= 1 && zs <= 10) ? zs : SIM_SETTINGS_DEFAULTS.zoomSensitivity;

    const lmb = (simulationSettings.labelMoveButton || SIM_SETTINGS_DEFAULTS.labelMoveButton).toString().toLowerCase();
    simulationSettings.labelMoveButton = (lmb === 'middle' || lmb === 'right' || lmb === 'left') ? lmb : SIM_SETTINGS_DEFAULTS.labelMoveButton;

    const hsi = parseInt(simulationSettings.headingSelectIncrement, 10);
    simulationSettings.headingSelectIncrement = (hsi === 1 || hsi === 5 || hsi === 10) ? hsi : SIM_SETTINGS_DEFAULTS.headingSelectIncrement;

    const md = parseInt(simulationSettings.minLocApproachDistNm, 10);
    simulationSettings.minLocApproachDistNm = (Number.isFinite(md) && md >= 1 && md <= 15) ? md : SIM_SETTINGS_DEFAULTS.minLocApproachDistNm;

    const plm = (simulationSettings.probingLevelMode || SIM_SETTINGS_DEFAULTS.probingLevelMode).toString().toLowerCase();
    simulationSettings.probingLevelMode = (plm === 'on' || plm === 'same_route' || plm === 'same_crossing_routes' || plm === 'off') ? plm : SIM_SETTINGS_DEFAULTS.probingLevelMode;

    const isHex6 = (s) => /^#[0-9a-fA-F]{6}$/.test((s || '').toString().trim());
    simulationSettings.probingHighlightColor = isHex6(simulationSettings.probingHighlightColor)
        ? simulationSettings.probingHighlightColor
        : SIM_SETTINGS_DEFAULTS.probingHighlightColor;
    simulationSettings.probingDimColor = isHex6(simulationSettings.probingDimColor)
        ? simulationSettings.probingDimColor
        : SIM_SETTINGS_DEFAULTS.probingDimColor;

    simulationSettings.selectedAircraftRingColor = isHex6(simulationSettings.selectedAircraftRingColor)
        ? simulationSettings.selectedAircraftRingColor
        : SIM_SETTINGS_DEFAULTS.selectedAircraftRingColor;
    const ringT = parseInt(simulationSettings.selectedAircraftRingThicknessPx, 10);
    simulationSettings.selectedAircraftRingThicknessPx = (Number.isFinite(ringT) && ringT >= 1 && ringT <= 12)
        ? ringT
        : SIM_SETTINGS_DEFAULTS.selectedAircraftRingThicknessPx;

    const mergedFsc = {};
    const srcFsc = simulationSettings.flightStatusColors;
    for (const key of FLIGHT_STATUS_FST_KEYS) {
        const def = SIM_SETTINGS_DEFAULTS.flightStatusColors[key];
        const row = srcFsc && typeof srcFsc === 'object' ? srcFsc[key] : null;
        mergedFsc[key] = {
            primary: isHex6(row?.primary) ? row.primary : def.primary,
            secondary: isHex6(row?.secondary) ? row.secondary : def.secondary
        };
    }
    simulationSettings.flightStatusColors = mergedFsc;

    const stcaNm = parseFloat(simulationSettings.stcaGeneralNm, 10);
    simulationSettings.stcaGeneralNm = (Number.isFinite(stcaNm) && stcaNm >= 0) ? stcaNm : SIM_SETTINGS_DEFAULTS.stcaGeneralNm;
    const stcaSec = parseInt(simulationSettings.stcaLookAheadSeconds, 10);
    simulationSettings.stcaLookAheadSeconds = (Number.isFinite(stcaSec) && stcaSec >= 1) ? stcaSec : SIM_SETTINGS_DEFAULTS.stcaLookAheadSeconds;
    const stcaType = (simulationSettings.stcaType || SIM_SETTINGS_DEFAULTS.stcaType).toString().toLowerCase();
    simulationSettings.stcaType = (stcaType === 'on_trajectory' || stcaType === 'on_track_and_trajectory' || stcaType === 'on_track') ? stcaType : SIM_SETTINGS_DEFAULTS.stcaType;
    const stcaShowTrigger = (simulationSettings.stcaShowTrigger || SIM_SETTINGS_DEFAULTS.stcaShowTrigger).toString().toLowerCase();
    simulationSettings.stcaShowTrigger = (stcaShowTrigger === 'on' || stcaShowTrigger === 'off') ? stcaShowTrigger : SIM_SETTINGS_DEFAULTS.stcaShowTrigger;

    // label setup + layout
    simulationSettings.labelSetupId = (simulationSettings.labelSetupId || '').toString();
    const layout = Array.isArray(simulationSettings.labelLayout) ? simulationSettings.labelLayout : null;
    // Back-compat: previously was an array of 5 row objects => treat as first column
    if (layout && layout.length === 5 && !Array.isArray(layout[0])) {
        const migrated = JSON.parse(JSON.stringify(SIM_SETTINGS_DEFAULTS.labelLayout));
        for (let r = 0; r < 5; r++) {
            migrated[r][0].field = (layout[r]?.field || '').toString();
            migrated[r][0].freeText = (layout[r]?.freeText || '').toString();
        }
        simulationSettings.labelLayout = migrated;
    } else if (!layout || layout.length !== 5 || !layout.every(row => Array.isArray(row) && row.length === 5)) {
        simulationSettings.labelLayout = JSON.parse(JSON.stringify(SIM_SETTINGS_DEFAULTS.labelLayout));
    } else {
        simulationSettings.labelLayout = layout.map(row => row.map(cell => ({
            field: (cell?.field || '').toString(),
            freeText: (cell?.freeText || '').toString()
        })));
    }

    // If the user hasn't explicitly placed RWY yet, default it to 2nd item on first line,
    // and shift EXIT_WAYPOINT to 3rd (as requested).
    try {
        const hasRwy = simulationSettings.labelLayout.some(row => row.some(cell => (cell?.field || '') === 'RWY'));
        if (!hasRwy) {
            const row0 = simulationSettings.labelLayout[0];
            if (row0 && row0.length === 5) {
                // Find EXIT_WAYPOINT on row 0 if present
                const exitIdx = row0.findIndex(c => (c?.field || '') === 'EXIT_WAYPOINT');
                // Put RWY at col 1
                row0[1].field = 'RWY';
                row0[1].freeText = '';
                // If EXIT_WAYPOINT was at col 1, move it to col 2
                if (exitIdx === 1) {
                    row0[2].field = 'EXIT_WAYPOINT';
                    row0[2].freeText = '';
                }
            }
        }
    } catch (e) {}
}

function saveSimulationSettings() {
    try {
        localStorage.setItem(SIM_SETTINGS_STORAGE_KEY, JSON.stringify(simulationSettings));
    } catch (e) {}
}

// --- Sim settings presets (Load all / Save all) - stored on server, shared for all users ---
function collectCurrentSimPreset() {
    applySimulationSettingsFromControls();
    return {
        simulationSettings: JSON.parse(JSON.stringify(simulationSettings)),
        simulationMap: JSON.parse(JSON.stringify(simulationMap)),
        simulationStyle: JSON.parse(JSON.stringify(simulationStyle))
    };
}

function applySimPreset(preset) {
    const s = preset?.settings;
    if (!s || typeof s !== 'object') return;
    try {
        if (s.simulationSettings && typeof s.simulationSettings === 'object') {
            localStorage.setItem(SIM_SETTINGS_STORAGE_KEY, JSON.stringify(s.simulationSettings));
        }
        if (s.simulationMap && typeof s.simulationMap === 'object') {
            localStorage.setItem(SIM_MAP_STORAGE_KEY, JSON.stringify(s.simulationMap));
        }
        if (s.simulationStyle && typeof s.simulationStyle === 'object') {
            localStorage.setItem(SIM_STYLE_STORAGE_KEY, JSON.stringify(s.simulationStyle));
        }
        loadSimulationSettings();
        loadSimulationMap();
        loadSimulationStyle();
        syncSimulationSettingsControlsFromState();
        saveSimulationSettings();
        saveSimulationMap();
        saveSimulationStyle();
        updateSpvUi();
        if (document.getElementById('simulationModal')?.classList.contains('active')) {
            drawSimulationCanvas();
        }
    } catch (e) {}
}

function hasAnyLocalSimSettingsStorage() {
    try {
        return !!(
            localStorage.getItem(SIM_SETTINGS_STORAGE_KEY) ||
            localStorage.getItem(SIM_MAP_STORAGE_KEY) ||
            localStorage.getItem(SIM_STYLE_STORAGE_KEY)
        );
    } catch (e) {
        return false;
    }
}

function tryApplyDefaultSimSettingsPresetFromServer() {
    return fetch('/api/sim-settings-presets')
        .then((r) => r.json())
        .then((data) => {
            const presets = Array.isArray(data?.presets) ? data.presets : [];
            const preset = presets.find((p) => p && (String(p.name || '').trim() === 'Default_Settings' || p.id === 'default'));
            if (preset && preset.settings) {
                applySimPreset(preset);
            }
        })
        .catch(() => {});
}

function getFirstFlightStatusActionForAircraftId(aircraftId) {
    const ac = (window.simulationData?.aircraft || []).find((a) => a && a.id === aircraftId);
    if (!ac) return null;
    if (aircraftShowAssumeInFlightStatusMenu(ac) && !aircraftIsAsmActiveForCurrentUserContext(ac)) {
        return 'assume';
    }
    return 'transfer';
}

function runPpFlightStatusAction(aircraftId, action) {
    if (action === 'assume') {
        const ac2 = window.simulationData.aircraft.find((a) => a && a.id === aircraftId);
        if (!ac2) return;
        const ctx = getSimulationUserAtcSectorContext();
        if (ctx.mode !== 'single' || !ctx.sectorNameNorm) return;
        if (!aircraftShowAssumeInFlightStatusMenu(ac2)) return;
        const tinReceive = aircraftTransferInProgress(ac2) && !getAcTransferReceiverAssumed(ac2) &&
            ctx.sectorNameNorm === getAcTransferToSectorNameNorm(ac2);
        const senderTouRollback = aircraftTransferInProgress(ac2) && !getAcTransferReceiverAssumed(ac2) &&
            String(ctx.atcSectorId) === String(getAcTransferFromAtcSectorId(ac2));
        if (senderTouRollback) {
            ac2.ppTransferFromAtcSectorId = null;
            ac2.ppTransferToSectorNameNorm = null;
            ac2.ppTransferReceiverAssumed = false;
            ac2.ppFlightStatus = 'ASM';
            ac2.ppFlightStatusAtcSectorId = ctx.atcSectorId;
            try { ac2._cinFtCacheKey = null; } catch (e) {}
            postPpFlightStatusFields(ac2, {
                ppFlightStatus: 'ASM',
                ppFlightStatusAtcSectorId: ctx.atcSectorId,
                ppTransferFromAtcSectorId: null,
                ppTransferToSectorNameNorm: null,
                ppTransferReceiverAssumed: false
            });
            drawSimulationCanvas();
            return;
        }
        ac2.ppFlightStatus = 'ASM';
        ac2.ppFlightStatusAtcSectorId = ctx.atcSectorId;
        const asmPatch = {
            ppFlightStatus: 'ASM',
            ppFlightStatusAtcSectorId: ctx.atcSectorId
        };
        if (tinReceive) {
            ac2.ppTransferReceiverAssumed = true;
            asmPatch.ppTransferReceiverAssumed = true;
        }
        try { ac2._cinFtCacheKey = null; } catch (e) {}
        postPpFlightStatusFields(ac2, asmPatch);
        drawSimulationCanvas();
    } else if (action === 'transfer') {
        const ac2 = window.simulationData.aircraft.find((a) => a && a.id === aircraftId);
        if (!ac2) return;
        const ctx = getSimulationUserAtcSectorContext();
        if (ctx.mode !== 'single') return;
        if (aircraftTransferInProgress(ac2) && !getAcTransferReceiverAssumed(ac2)) return;
        if (!aircraftIsRawAsmForCurrentUserContext(ac2)) return;
        const nextNm = getNextSectorNameNormAfterUserInSequence(ac2);
        if (!nextNm) return;
        ac2.ppTransferFromAtcSectorId = ctx.atcSectorId;
        ac2.ppTransferToSectorNameNorm = nextNm;
        ac2.ppTransferReceiverAssumed = false;
        try { ac2._cinFtCacheKey = null; } catch (e3) {}
        postPpFlightStatusFields(ac2, {
            ppTransferFromAtcSectorId: ctx.atcSectorId,
            ppTransferToSectorNameNorm: nextNm,
            ppTransferReceiverAssumed: false
        });
        drawSimulationCanvas();
    }
}

function runSimulationFlightStatusAction(aircraftId, action) {
    if (usesPpFmsFlightStatusDomain()) {
        runPpFlightStatusAction(aircraftId, action);
        return;
    }
    if (action === 'assume') {
        const ac2 = window.simulationData.aircraft.find((a) => a && a.id === aircraftId);
        if (!ac2) return;
        const ctx = getSimulationUserAtcSectorContext();
        if (ctx.mode !== 'single' || !ctx.sectorNameNorm) return;
        if (!aircraftShowAssumeInFlightStatusMenu(ac2)) return;
        const tinReceive = aircraftTransferInProgress(ac2) && !ac2.transferReceiverAssumed &&
            ctx.sectorNameNorm === ac2.transferToSectorNameNorm;
        const senderTouRollback = aircraftTransferInProgress(ac2) && !ac2.transferReceiverAssumed &&
            String(ctx.atcSectorId) === String(ac2.transferFromAtcSectorId);
        // Transferring sector (TOU): ASSUME cancels outbound handoff — clear transfer metadata for all clients; sender stays ASM.
        // Receiver (TIN) UI reverts to route-based FST (CIN/UIN/UOU) once transfer fields clear. If receiver already assumed
        // (transferReceiverAssumed), aircraftShowAssumeInFlightStatusMenu does not offer this path — unchanged behavior.
        // Edge: simultaneous ASSUME on both sides — last ATM patch wins; avoid testing two browsers on same aircraft id without sync.
        if (senderTouRollback) {
            if (_joinerAtmReceiverAssumeStickyByAid[String(ac2.id)]) {
                delete _joinerAtmReceiverAssumeStickyByAid[String(ac2.id)];
            }
            if (simulationJoinedSessionId) {
                _joinerAtmTouRollbackPendingByAid[String(ac2.id)] = true;
            }
            delete _joinerAtmOutboundTransferPostPendingByAid[String(ac2.id)];
            ac2.transferFromAtcSectorId = null;
            ac2.transferToSectorNameNorm = null;
            ac2.transferReceiverAssumed = false;
            ac2.exeFlightStatus = 'ASM';
            ac2.exeFlightStatusAtcSectorId = ctx.atcSectorId;
            try { ac2._cinFtCacheKey = null; } catch (e) {}
            clearAtmSectorSequenceCachesForAircraft(ac2);
            if (isJoinerAtmDisplayClient() && ac2._atmTrajectoryPatch && typeof ac2._atmTrajectoryPatch === 'object') {
                ac2._atmTrajectoryPatch.transferFromAtcSectorId = null;
                ac2._atmTrajectoryPatch.transferToSectorNameNorm = null;
                ac2._atmTrajectoryPatch.transferReceiverAssumed = false;
                ac2._atmTrajectoryPatch.exeFlightStatus = 'ASM';
                ac2._atmTrajectoryPatch.exeFlightStatusAtcSectorId = ctx.atcSectorId;
                try { ac2._atmTrajectoryPatchSig = atmTrajectoryPatchSignature(ac2._atmTrajectoryPatch); } catch (eP) {}
            }
            const rollbackPatch = {
                exeFlightStatus: 'ASM',
                exeFlightStatusAtcSectorId: ctx.atcSectorId,
                transferFromAtcSectorId: null,
                transferToSectorNameNorm: null,
                transferReceiverAssumed: false
            };
            try { postJoinerAtmTrajectoryVerticalFields(ac2, rollbackPatch); } catch (e2) {}
            try { syncJoinerExeAircraftPatchesFlightMetadataFromAircraft(ac2); } catch (eSync) {}
            try {
                if (simulationSessionId && !simulationJoinedSessionId) {
                    hostPushAtmTrajectoryPatchFromHostNow(ac2, { skipAtmFlightMetadataKeys: false });
                }
            } catch (eH) {}
            drawSimulationCanvas();
            return;
        }
        ac2.exeFlightStatus = 'ASM';
        ac2.exeFlightStatusAtcSectorId = ctx.atcSectorId;
        if (tinReceive) ac2.transferReceiverAssumed = true;
        if (tinReceive) {
            _joinerAtmReceiverAssumeStickyByAid[String(ac2.id)] = { exeFlightStatusAtcSectorId: ctx.atcSectorId };
        }
        if (isJoinerAtmDisplayClient() && ac2._atmTrajectoryPatch && typeof ac2._atmTrajectoryPatch === 'object') {
            ac2._atmTrajectoryPatch.exeFlightStatus = 'ASM';
            ac2._atmTrajectoryPatch.exeFlightStatusAtcSectorId = ctx.atcSectorId;
            if (tinReceive) ac2._atmTrajectoryPatch.transferReceiverAssumed = true;
            try { ac2._atmTrajectoryPatchSig = atmTrajectoryPatchSignature(ac2._atmTrajectoryPatch); } catch (eP) {}
        }
        try { ac2._cinFtCacheKey = null; } catch (e) {}
        const asmPatch = {
            exeFlightStatus: 'ASM',
            exeFlightStatusAtcSectorId: ctx.atcSectorId
        };
        if (tinReceive) asmPatch.transferReceiverAssumed = true;
        try { postJoinerAtmTrajectoryVerticalFields(ac2, asmPatch); } catch (e2) {}
        drawSimulationCanvas();
    } else if (action === 'transfer') {
        const ac2 = window.simulationData.aircraft.find((a) => a && a.id === aircraftId);
        if (!ac2) return;
        const ctx = getSimulationUserAtcSectorContext();
        if (ctx.mode !== 'single') return;
        if (aircraftTransferInProgress(ac2) && !ac2.transferReceiverAssumed) return;
        if (!aircraftIsRawAsmForCurrentUserContext(ac2)) return;
        const nextNm = getNextSectorNameNormAfterUserInSequence(ac2);
        if (!nextNm) return;
        delete _joinerAtmTouRollbackPendingByAid[String(ac2.id)];
        if (simulationJoinedSessionId) {
            _joinerAtmOutboundTransferPostPendingByAid[String(ac2.id)] = true;
        }
        ac2.transferFromAtcSectorId = ctx.atcSectorId;
        ac2.transferToSectorNameNorm = nextNm;
        ac2.transferReceiverAssumed = false;
        try { ac2._cinFtCacheKey = null; } catch (e3) {}
        try {
            postJoinerAtmTrajectoryVerticalFields(ac2, {
                transferFromAtcSectorId: ctx.atcSectorId,
                transferToSectorNameNorm: nextNm,
                transferReceiverAssumed: false
            });
        } catch (e4) {}
        drawSimulationCanvas();
    }
}

function fillLoadSimSettingsPresetsList() {
    const listEl = document.getElementById('loadSimSettingsPresetsList');
    const emptyEl = document.getElementById('loadSimSettingsPresetsEmpty');
    if (!listEl || !emptyEl) return;
    listEl.innerHTML = '';
    emptyEl.style.display = 'none';
    emptyEl.textContent = 'No saved presets yet. Use "Save all settings" to create one.';
    fetch('/api/sim-settings-presets')
        .then(r => r.json())
        .then(data => {
            const presets = Array.isArray(data?.presets) ? data.presets : [];
            if (!presets.length) {
                emptyEl.style.display = 'block';
                return;
            }
            presets.forEach((p) => {
                const li = document.createElement('li');
                li.className = 'sim-preset-row';
                const name = (p.name || 'Unnamed').trim() || 'Unnamed';
                const pid = (p.id || '').toString();
                const nameSpan = document.createElement('span');
                nameSpan.className = 'sim-preset-name';
                nameSpan.textContent = name;
                nameSpan.addEventListener('click', () => {
                    applySimPreset(p);
                    closeModal('loadSimSettingsPresetsModal');
                });
                const delBtn = document.createElement('button');
                delBtn.type = 'button';
                delBtn.className = 'btn btn-danger sim-preset-delete-btn';
                delBtn.textContent = 'Delete';
                delBtn.setAttribute('aria-label', `Delete preset ${name}`);
                delBtn.addEventListener('click', (ev) => {
                    ev.stopPropagation();
                    if (!confirm(`Delete saved preset "${name}"?`)) return;
                    fetch('/api/sim-settings-presets/' + encodeURIComponent(pid), { method: 'DELETE' })
                        .then((r) => r.json().then((body) => ({ ok: r.ok, status: r.status, body })))
                        .then(({ ok, body }) => {
                            if (ok && body && body.ok) {
                                fillLoadSimSettingsPresetsList();
                                return;
                            }
                            alert((body && body.error) || 'Could not delete preset.');
                        })
                        .catch(() => alert('Could not delete preset.'));
                });
                li.appendChild(nameSpan);
                li.appendChild(delBtn);
                listEl.appendChild(li);
            });
        })
        .catch(() => {
            emptyEl.style.display = 'block';
            emptyEl.textContent = 'Could not load presets from server.';
        });
}

function openLoadSimSettingsPresetsModal() {
    fillLoadSimSettingsPresetsList();
    openModal('loadSimSettingsPresetsModal');
}

function openSaveSimSettingsPresetModal() {
    const nameEl = document.getElementById('saveSimSettingsPresetName');
    if (nameEl) { nameEl.value = ''; nameEl.focus(); }
    openModal('saveSimSettingsPresetModal');
}

function isSimulationSpvVisibleForAircraftId(aircraftId) {
    if (aircraftId == null) return false;
    if (!!simulationSettings?.spvEnabled) return true;
    return simulationSpvAircraftIds.has(aircraftId);
}

function toggleSimulationSpvForAircraftId(aircraftId) {
    if (aircraftId == null || !!simulationSettings?.spvEnabled) return;
    if (simulationSpvAircraftIds.has(aircraftId)) {
        simulationSpvAircraftIds.delete(aircraftId);
    } else {
        simulationSpvAircraftIds.add(aircraftId);
        const cur = Math.max(0, parseInt(simulationSettings?.spvMinutes, 10) || 0);
        if (cur < 1) {
            simulationSettings.spvMinutes = 1;
            saveSimulationSettings();
        }
    }
    updateSpvUi();
}

function updateSpvUi() {
    const valueEl = document.getElementById('spvValueText');
    if (!valueEl) return;
    const mins = Math.max(0, parseInt(simulationSettings.spvMinutes, 10) || 0);
    if (!simulationSettings?.spvEnabled) {
        valueEl.textContent = (simulationSpvAircraftIds.size > 0) ? String(mins) : 'OFF';
    } else {
        valueEl.textContent = String(mins);
    }
}

function isSimulationTtsSupported() {
    return (typeof window !== 'undefined') && ('speechSynthesis' in window) && (typeof SpeechSynthesisUtterance !== 'undefined');
}

let simulationTtsIsSpeaking = false;
const SIMULATION_TTS_POST_GAP_MS = 2000;
const AI_PP_PILOT_CALL_MAX_MINUTES = 2;
/** Resolved at TTS playback for initial pilot calls (live Mode C). */
const INITIAL_CALL_TTS_MODE_C_TOKEN = '{{MODE_C_LEVEL}}';
/** Resolved at TTS playback for initial pilot calls (proceeding waypoint). */
const INITIAL_CALL_TTS_WAYPOINT_TOKEN = '{{WAYPOINT}}';
let simulationGlobalTtsQueue = [];
let simulationTtsGapUntilMs = 0;
let aiPpDeferStackUntilMs = 0;
let simulationGlobalTtsPumpTimerId = null;
const AI_PP_PTT_STORAGE_KEY = 'aitc_ai_pp_ptt_key_v1';
let aiPpEnabled = false;
let aiPpPttKey = null; // { key, code, label }
let aiPpPendingPttKey = null;
let aiPpSelectingKey = false;
let aiPpMediaStream = null;
let aiPpMediaRecorder = null;
let aiPpAudioChunks = [];
let aiPpPttPressed = false;
let aiPpTranscribing = false;
let aiPpDiscardCurrentRecording = false;
let aiPpRxTimerId = null;
let aiPpOpenAiSessionId = '';
let aiPpOpenAiSessionInitPromise = null;
let aiPpOpenAiInitializing = false;
let aiPpOpenAiResponding = false;
let aiPpPttPrimePromise = null;
let aiPpVccsDetailsVisible = false;
let aiPpPttBlockedByTts = false;
let aiPpPttBlockBeepCtx = null;
let aiPpPttBlockBeepOsc = null;
/** Single User: ICAO callsign keys (compact upper) currently checked in on the user's sector frequency. */
let aiPpOnFrequencyCallsigns = new Set();
let aiPpOnFrequencyNotifyQueue = [];
let aiPpOnFrequencyNotifyPumpActive = false;
let simulationAiPilotScripts = [];
let simulationAiPilotScriptsFiredIds = new Set();
let simulationAiPilotScriptsLblTinFiredIds = new Set();
let simulationAiPilotScriptQueue = [];
let simulationAiPilotScriptProcessing = false;

function setAiPpVccsDetailsVisible(visible) {
    aiPpVccsDetailsVisible = !!visible;
    const details = document.getElementById('simulationAiPpVccsDetails');
    const btn = document.getElementById('simulationAiPpVccsDetailsToggle');
    if (details) details.hidden = !aiPpVccsDetailsVisible;
    if (btn) {
        btn.textContent = aiPpVccsDetailsVisible ? '−' : '+';
        btn.setAttribute('aria-expanded', aiPpVccsDetailsVisible ? 'true' : 'false');
        btn.title = aiPpVccsDetailsVisible
            ? 'Hide transcript, TTS, command and AI response'
            : 'Show transcript, TTS, command and AI response';
    }
}

function toggleAiPpVccsDetails() {
    setAiPpVccsDetailsVisible(!aiPpVccsDetailsVisible);
}

function isSimulationTtsSpeakingNow() {
    if (isSimulationHostedMultiplayerSession()) return false;
    try {
        if (!isSimulationTtsSupported()) return false;
        return !!(simulationTtsIsSpeaking || window.speechSynthesis.speaking);
    } catch (e) {
        return simulationTtsIsSpeaking;
    }
}

function isAiPpPttActive() {
    return !!(aiPpEnabled && aiPpPttPressed);
}

function isAiPpUserVoiceBusy() {
    if (!aiPpEnabled) return false;
    if (isAiPpPttActive()) return true;
    if (aiPpTranscribing || aiPpOpenAiResponding) return true;
    try {
        return !!(aiPpMediaRecorder && aiPpMediaRecorder.state === 'recording');
    } catch (e) {
        return false;
    }
}

/** True when aircraft / AI_PP TTS must not start (defer queued replies). */
function isSimulationTtsPlaybackBlocked() {
    return isSimulationTtsSpeakingNow() || isAiPpUserVoiceBusy();
}

function startAiPpPttBlockBeep() {
    try {
        if (aiPpPttBlockBeepOsc) return;
        const Ctx = window.AudioContext || window.webkitAudioContext;
        if (!Ctx) return;
        if (!aiPpPttBlockBeepCtx) aiPpPttBlockBeepCtx = new Ctx();
        const ctx = aiPpPttBlockBeepCtx;
        if (ctx.state === 'suspended') ctx.resume().catch(() => {});
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.type = 'sine';
        osc.frequency.value = 880;
        gain.gain.value = 0.14;
        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start(0);
        aiPpPttBlockBeepOsc = { osc, gain };
    } catch (e) {}
}

function stopAiPpPttBlockBeep() {
    try {
        if (!aiPpPttBlockBeepOsc) return;
        aiPpPttBlockBeepOsc.osc.stop();
    } catch (e) {}
    aiPpPttBlockBeepOsc = null;
}

function loadAiPpPttKey() {
    try {
        const parsed = JSON.parse(localStorage.getItem(AI_PP_PTT_STORAGE_KEY) || 'null');
        if (!parsed || typeof parsed !== 'object') return null;
        const key = (parsed.key || '').toString();
        const code = (parsed.code || '').toString();
        const label = (parsed.label || key || code || '').toString();
        if (!key && !code) return null;
        return { key, code, label };
    } catch (e) {
        return null;
    }
}

function saveAiPpPttKey(keyInfo) {
    aiPpPttKey = keyInfo && typeof keyInfo === 'object' ? {
        key: (keyInfo.key || '').toString(),
        code: (keyInfo.code || '').toString(),
        label: (keyInfo.label || keyInfo.key || keyInfo.code || '').toString()
    } : null;
    try {
        if (aiPpPttKey) localStorage.setItem(AI_PP_PTT_STORAGE_KEY, JSON.stringify(aiPpPttKey));
        else localStorage.removeItem(AI_PP_PTT_STORAGE_KEY);
    } catch (e) {}
}

function formatAiPpKeyLabel(evOrInfo) {
    const key = (evOrInfo?.key || '').toString();
    const code = (evOrInfo?.code || '').toString();
    if (key === 'Control') return 'CTRL';
    if (key === 'Meta') return 'CMD';
    if (key === ' ') return 'SPACE';
    if (key && key.length === 1) return key.toUpperCase();
    return key || code || 'Selected key';
}

function isAiPpAvailableInCurrentRun() {
    return !getAiPpAvailabilityBlocker();
}

function getAiPpAvailabilityBlocker() {
    if (isSimulationHostedMultiplayerSession()) return 'AI_PP is only available in Single User, not hosted or joined sessions.';
    if (simulationOperationModeId !== 'DL') return 'AI_PP is available in DL mode only.';
    if (simulationIsMonitorOnly) return 'AI_PP is not available while monitoring a session.';
    return '';
}

function setAiPpStatus(text) {
    const el = document.getElementById('simulationAiPpStatus');
    if (el) el.textContent = (text || '').toString();
}

function setAiPpTranscriptDisplay(transcript) {
    const el = document.getElementById('simulationAiPpTranscriptText');
    const text = (transcript || '').toString().trim();
    if (el) el.textContent = text || '—';
}

function setAiPpReplyDisplay(tts, command, result = null, rawAiResponse = '') {
    const ttsEl = document.getElementById('simulationAiPpTtsText');
    const cmdEl = document.getElementById('simulationAiPpCommandText');
    const rawEl = document.getElementById('simulationAiPpRawText');
    const ttsText = (tts || '').toString().trim();
    const cmdText = (command || '').toString().trim();
    const rawText = (rawAiResponse || '').toString();
    if (ttsEl) ttsEl.textContent = ttsText || '—';
    if (cmdEl) {
        let suffix = '';
        if (result && Array.isArray(result.actions)) {
            suffix = `\nApplied: ${result.applied}/${result.actions.length}`;
        }
        cmdEl.textContent = cmdText ? `${cmdText}${suffix}` : '—';
    }
    if (rawEl) rawEl.value = rawText.trim() || '—';
}

function setAiPpTxRx(tx, rx, opts = {}) {
    const txEl = document.getElementById('simulationAiPpTx');
    const rxEl = document.getElementById('simulationAiPpRx');
    const blocked = !!opts.blocked;
    if (txEl) {
        txEl.classList.toggle('active', !!tx && !blocked);
        txEl.classList.toggle('blocked', blocked);
    }
    if (rxEl) rxEl.classList.toggle('active', !!rx);
}

function updateAiPpConfigDisplay() {
    const display = document.getElementById('aiPpSelectedKeyDisplay');
    if (display) display.textContent = aiPpPendingPttKey ? `Selected: ${aiPpPendingPttKey.label}` : 'No key selected';
}

function updateAiPpUi() {
    const btn = document.getElementById('simulationAiPpToggleBtn');
    const value = document.getElementById('simulationAiPpValue');
    const vccs = document.getElementById('simulationAiPpVccs');
    if (!btn || !value) return;

    const available = isAiPpAvailableInCurrentRun();
    btn.style.display = available ? '' : 'none';
    btn.disabled = !available;
    btn.classList.toggle('sim-tts-disabled', !available);
    btn.classList.toggle('sim-tts-on', available && aiPpEnabled);
    value.textContent = aiPpEnabled ? 'ON' : 'OFF';
    btn.title = available ? 'AI pseudo-pilot push-to-talk' : 'AI_PP is available in Single User only';
    if (!available && aiPpEnabled) {
        disableAiPp();
        return;
    }
    if (vccs) vccs.style.display = (available && aiPpEnabled) ? '' : 'none';
}

function openAiPpPttModal() {
    aiPpPendingPttKey = aiPpPttKey || loadAiPpPttKey();
    aiPpSelectingKey = false;
    updateAiPpConfigDisplay();
    const hint = document.getElementById('aiPpPttHint');
    if (hint) hint.textContent = 'Press Select key, then press the desired keyboard key.';
    openModal('aiPpPttModal');
    const modal = document.getElementById('aiPpPttModal');
    if (modal) modal.style.zIndex = '1300';
}

function closeAiPpPttModal() {
    aiPpSelectingKey = false;
    closeModal('aiPpPttModal');
}

function confirmAiPpPttModal() {
    if (!aiPpPendingPttKey) {
        alert('Please select a Push-to-Talk key first.');
        return;
    }
    saveAiPpPttKey(aiPpPendingPttKey);
    closeAiPpPttModal();
    enableAiPp();
}

async function initializeAiPpOpenAiSession() {
    if (aiPpOpenAiSessionId) return aiPpOpenAiSessionId;
    if (aiPpOpenAiSessionInitPromise) return aiPpOpenAiSessionInitPromise;
    aiPpOpenAiSessionInitPromise = (async () => {
        aiPpOpenAiInitializing = true;
        setAiPpStatus('Initializing AI Pilot context...');
        try {
            const exerciseId = window.simulationData?.exercise?.id || '';
            const onFrequencyCallsigns = Array.from(aiPpOnFrequencyCallsigns);
            const resp = await fetchWithTimeout('/api/ai-pp/session/start', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ exerciseId, onFrequencyCallsigns })
            }, 60000);
            const data = await resp.json().catch(() => ({}));
            if (!resp.ok || data.ok === false) throw new Error(data.error || 'Could not initialize AI Pilot.');
            aiPpOpenAiSessionId = (data.sessionId || '').toString();
            if (!aiPpOpenAiSessionId) throw new Error('AI Pilot session id was not returned.');
            const instrLen = Number(data.instructionsLength) || 0;
            if (instrLen > 0) {
                pushSimulationDebugLog('LOG', null, `AI_PP session started (${instrLen} chars of instructions sent once)`);
            }
            return aiPpOpenAiSessionId;
        } finally {
            aiPpOpenAiInitializing = false;
        }
    })();
    try {
        return await aiPpOpenAiSessionInitPromise;
    } catch (err) {
        aiPpOpenAiSessionInitPromise = null;
        throw err;
    }
}

async function warmAiPpTranscriptionModel() {
    try {
        setAiPpStatus('Loading speech model...');
        const resp = await fetchWithTimeout('/api/ai-pp/transcribe/warmup', { method: 'POST' }, 120000);
        const data = await resp.json().catch(() => ({}));
        if (!resp.ok || data.ok === false) {
            throw new Error(data.error || 'Speech model is unavailable.');
        }
    } catch (err) {
        pushSimulationDebugLog('WARN', null, `AI_PP speech model: ${err?.message || err}`);
        throw err;
    }
}

async function enableAiPp() {
    if (!isAiPpAvailableInCurrentRun()) {
        alert('AI_PP is only available in Single User.');
        return;
    }
    if (!aiPpPttKey) {
        openAiPpPttModal();
        return;
    }
    try {
        await initializeAiPpOpenAiSession();
        await warmAiPpTranscriptionModel();
    } catch (err) {
        alert(err?.message || 'Could not initialize AI Pilot.');
        setAiPpStatus(err?.message || 'AI Pilot initialization failed');
        return;
    }
    aiPpEnabled = true;
    if (simulationSettings) {
        simulationSettings.ttsEnabled = true;
        saveSimulationSettings();
    }
    updateSimulationTtsUi();
    updateAiPpUi();
    setAiPpTxRx(false, false);
    setAiPpReplyDisplay('', '');
    setAiPpTranscriptDisplay('');
    setAiPpStatus(`PTT: ${aiPpPttKey.label}`);
    try { updateAiPpScriptTriggers(); } catch (e) {}
}

function endAiPpOpenAiSession() {
    const sid = aiPpOpenAiSessionId;
    aiPpOpenAiSessionId = '';
    aiPpOpenAiSessionInitPromise = null;
    if (!sid) return;
    try {
        fetch('/api/ai-pp/session/end', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ sessionId: sid }),
            keepalive: true
        }).catch(() => {});
    } catch (e) {}
    try { pushSimulationDebugLog('LOG', null, 'AI_PP session ended (cleanup)'); } catch (e) {}
}

function disableAiPp() {
    aiPpEnabled = false;
    aiPpPttPressed = false;
    aiPpPttBlockedByTts = false;
    stopAiPpPttBlockBeep();
    endAiPpOpenAiSession();
    aiPpOpenAiInitializing = false;
    aiPpOpenAiResponding = false;
    aiPpPttPrimePromise = null;
    try { resetAiPpOnFrequencyCallsigns(); } catch (e) {}
    stopAiPpRecording(true);
    if (aiPpRxTimerId) {
        clearTimeout(aiPpRxTimerId);
        aiPpRxTimerId = null;
    }
    try {
        if (aiPpMediaStream) aiPpMediaStream.getTracks().forEach(track => track.stop());
    } catch (e) {}
    aiPpMediaStream = null;
    setAiPpTxRx(false, false);
    setAiPpReplyDisplay('', '');
    setAiPpTranscriptDisplay('');
    aiPpDeferStackUntilMs = 0;
    updateAiPpUi();
}

function aiPpEventMatchesPtt(e) {
    if (!aiPpPttKey || !e) return false;
    const key = (e.key || '').toString();
    const code = (e.code || '').toString();
    if (aiPpPttKey.key === 'Control') return key === 'Control';
    if (aiPpPttKey.key === 'Meta') return key === 'Meta';
    return (!!aiPpPttKey.code && code === aiPpPttKey.code) || (!!aiPpPttKey.key && key === aiPpPttKey.key);
}

async function ensureAiPpMediaStream() {
    if (aiPpMediaStream) return aiPpMediaStream;
    if (!navigator.mediaDevices?.getUserMedia) {
        throw new Error('Microphone recording is not supported in this browser.');
    }
    aiPpMediaStream = await navigator.mediaDevices.getUserMedia({ audio: true });
    return aiPpMediaStream;
}

async function startAiPpRecording() {
    if (!aiPpEnabled || aiPpMediaRecorder || aiPpTranscribing) return;
    try {
        if (typeof MediaRecorder === 'undefined') {
            throw new Error('Audio recording is not supported in this browser.');
        }
        const stream = await ensureAiPpMediaStream();
        aiPpAudioChunks = [];
        aiPpDiscardCurrentRecording = false;
        const opts = {};
        if (MediaRecorder.isTypeSupported?.('audio/webm')) {
            opts.mimeType = 'audio/webm';
        }
        aiPpMediaRecorder = new MediaRecorder(stream, opts);
        aiPpMediaRecorder.ondataavailable = (ev) => {
            if (ev.data && ev.data.size > 0) aiPpAudioChunks.push(ev.data);
        };
        aiPpMediaRecorder.onstop = () => {
            const mime = aiPpMediaRecorder?.mimeType || 'audio/webm';
            const discard = aiPpDiscardCurrentRecording;
            aiPpDiscardCurrentRecording = false;
            aiPpMediaRecorder = null;
            const blob = new Blob(aiPpAudioChunks, { type: mime });
            aiPpAudioChunks = [];
            if (discard) return;
            if (blob.size > 0) {
                transcribeAiPpAudio(blob);
            } else {
                setAiPpStatus(aiPpPttKey ? `PTT: ${aiPpPttKey.label}` : 'No audio captured');
            }
        };
        aiPpMediaRecorder.start(250);
        setAiPpTxRx(true, false);
        setAiPpStatus('Transmitting...');
    } catch (err) {
        aiPpMediaRecorder = null;
        aiPpPttPressed = false;
        setAiPpTxRx(false, false);
        setAiPpStatus(err?.message || 'Microphone error');
    }
}

function stopAiPpRecording(discard = false) {
    try {
        if (aiPpMediaRecorder && aiPpMediaRecorder.state !== 'inactive') {
            aiPpDiscardCurrentRecording = !!discard;
            try { aiPpMediaRecorder.requestData(); } catch (e) {}
            aiPpMediaRecorder.stop();
        }
    } catch (e) {
        aiPpMediaRecorder = null;
    }
    setAiPpTxRx(false, false);
}

async function fetchWithTimeout(url, options, timeoutMs = 60000) {
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), timeoutMs);
    try {
        return await fetch(url, { ...(options || {}), signal: controller.signal });
    } catch (err) {
        if (err && err.name === 'AbortError') {
            throw new Error(`Request timed out after ${Math.round(timeoutMs / 1000)}s`);
        }
        throw err;
    } finally {
        clearTimeout(timer);
    }
}

function normalizeAiPpCallsignKey(callsign) {
    return (callsign || '').toString().trim().toUpperCase().replace(/\s+/g, '');
}

function resetAiPpOnFrequencyCallsigns() {
    aiPpOnFrequencyCallsigns = new Set();
    aiPpOnFrequencyNotifyQueue = [];
}

function buildAiPpAircraftListBlockForApi() {
    const callsigns = getExerciseAiPpCallsignList();
    const lines = [
        'EXERCISE AIRCRAFT LIST:',
        'These are the ONLY valid aircraft callsigns for this session.'
    ];
    if (!callsigns.length) {
        lines.push('  (none)');
        return lines.join('\n');
    }
    callsigns.forEach(cs => {
        const on = isAiPpCallsignOnFrequency(cs) ? 'yes' : 'no';
        lines.push(`  - ${cs} onFrequency=${on}`);
    });
    return lines.join('\n');
}

function buildAiPpOnFrequencyEventMessage(callsign, event) {
    const cs = normalizeAiPpCallsignKey(callsign);
    const on = event === 'off' ? 'no' : 'yes';
    return [
        '[ON FREQUENCY EVENT]',
        `Aircraft ${cs} is now onFrequency=${on}.`,
        'Updated exercise aircraft list:',
        buildAiPpAircraftListBlockForApi(),
        'Respond {"tts":"","command":""} — context update only; no pilot readback.'
    ].join('\n');
}

function queueAiPpOnFrequencyEventNotify(callsign, event) {
    if (!aiPpEnabled) return;
    const cs = normalizeAiPpCallsignKey(callsign);
    if (!cs) return;
    aiPpOnFrequencyNotifyQueue.push({ callsign: cs, event: event === 'off' ? 'off' : 'on' });
    pumpAiPpOnFrequencyEventNotifyQueue();
}

async function sendAiPpOnFrequencyEventToAi(callsign, event) {
    const text = buildAiPpOnFrequencyEventMessage(callsign, event);
    const sessionId = await initializeAiPpOpenAiSession();
    if (!sessionId) return;
    aiPpOpenAiResponding = true;
    try {
        const resp = await fetchWithTimeout('/api/ai-pp/respond', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                sessionId: aiPpOpenAiSessionId,
                text,
                mode: 'onFrequencyEvent'
            })
        }, 90000);
        const data = await resp.json().catch(() => ({}));
        if (!resp.ok || data.ok === false) throw new Error(data.error || 'AI Pilot on-frequency update failed.');
        pushSimulationDebugLog('LOG', null, `AI_PP on-frequency event sent: ${callsign} ${event}`);
    } catch (err) {
        pushSimulationDebugLog('WARN', null, `AI_PP on-frequency event failed: ${err?.message || err}`);
    } finally {
        aiPpOpenAiResponding = false;
        pumpAiPpOnFrequencyEventNotifyQueue();
    }
}

async function pumpAiPpOnFrequencyEventNotifyQueue() {
    if (aiPpOnFrequencyNotifyPumpActive) return;
    if (aiPpOpenAiResponding || aiPpTranscribing || aiPpOpenAiInitializing) {
        setTimeout(pumpAiPpOnFrequencyEventNotifyQueue, 250);
        return;
    }
    if (!aiPpOnFrequencyNotifyQueue.length) return;
    aiPpOnFrequencyNotifyPumpActive = true;
    try {
        while (aiPpOnFrequencyNotifyQueue.length && !aiPpOpenAiResponding && !aiPpTranscribing && !aiPpOpenAiInitializing) {
            const item = aiPpOnFrequencyNotifyQueue.shift();
            await sendAiPpOnFrequencyEventToAi(item.callsign, item.event);
        }
    } finally {
        aiPpOnFrequencyNotifyPumpActive = false;
        if (aiPpOnFrequencyNotifyQueue.length) setTimeout(pumpAiPpOnFrequencyEventNotifyQueue, 250);
    }
}

function setAiPpCallsignOnFrequency(callsign) {
    const key = normalizeAiPpCallsignKey(callsign);
    if (!key) return;
    if (aiPpOnFrequencyCallsigns.has(key)) return;
    aiPpOnFrequencyCallsigns.add(key);
    pushSimulationDebugLog('LOG', null, `AI_PP on frequency: ${key}`);
    queueAiPpOnFrequencyEventNotify(key, 'on');
}

function clearAiPpCallsignOnFrequency(callsign) {
    const key = normalizeAiPpCallsignKey(callsign);
    if (!key) return;
    if (!aiPpOnFrequencyCallsigns.delete(key)) return;
    pushSimulationDebugLog('LOG', null, `AI_PP off frequency: ${key}`);
    queueAiPpOnFrequencyEventNotify(key, 'off');
}

function isAiPpCallsignOnFrequency(callsign) {
    const key = normalizeAiPpCallsignKey(callsign);
    return !!(key && aiPpOnFrequencyCallsigns.has(key));
}

function getExerciseAiPpCallsignList() {
    const flights = window.simulationData?.exercise?.flights || [];
    const seen = new Set();
    const list = [];
    flights.forEach(f => {
        const cs = normalizeAiPpCallsignKey(f?.callsign);
        if (cs && !seen.has(cs)) {
            seen.add(cs);
            list.push(cs);
        }
    });
    return list.sort();
}

function extractCallsignDigitPortion(callsign) {
    const cs = normalizeAiPpCallsignKey(callsign);
    const m = cs.match(/^[A-Z]*(\d+)[A-Z]*$/);
    return m ? m[1] : '';
}

const AI_PP_SPOKEN_DIGIT_WORDS = {
    zero: '0', oh: '0', one: '1', two: '2', three: '3', four: '4', five: '5',
    six: '6', seven: '7', eight: '8', nine: '9', niner: '9'
};

function extractSpokenDigitStreamFromText(text) {
    const tokens = (text || '').toLowerCase().replace(/[^a-z0-9\s]/g, ' ').split(/\s+/).filter(Boolean);
    let out = '';
    tokens.forEach(tok => {
        if (/^\d+$/.test(tok)) {
            out += tok;
            return;
        }
        const d = AI_PP_SPOKEN_DIGIT_WORDS[tok];
        if (d != null) out += d;
    });
    return out;
}

function transcriptContainsSpokenDigitGroup(text, digitGroup) {
    const wanted = (digitGroup || '').toString();
    if (!wanted) return false;
    const stream = extractSpokenDigitStreamFromText(text);
    if (stream.includes(wanted)) return true;
    const compact = (text || '').replace(/\D/g, '');
    return compact.includes(wanted);
}

function identifyAddressedCallsignFromTranscript(transcript, callsignList) {
    const list = Array.isArray(callsignList) ? callsignList : getExerciseAiPpCallsignList();
    if (!list.length) return null;
    const compactTranscript = (transcript || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
    const matches = [];
    list.forEach(cs => {
        if (compactTranscript.includes(cs)) {
            matches.push({ cs, score: 3 });
            return;
        }
        const digits = extractCallsignDigitPortion(cs);
        if (digits && transcriptContainsSpokenDigitGroup(transcript, digits)) {
            matches.push({ cs, score: 2, digits });
        }
    });
    if (!matches.length) return null;
    matches.sort((a, b) => b.score - a.score);
    const bestScore = matches[0].score;
    const top = matches.filter(m => m.score === bestScore);
    if (top.length === 1) return top[0].cs;
    const digitSets = new Set(top.map(m => m.digits || extractCallsignDigitPortion(m.cs)));
    if (digitSets.size === 1) return top[0].cs;
    return null;
}

function findOffFrequencyAddressedCallsignInTranscript(transcript) {
    const addressed = identifyAddressedCallsignFromTranscript(transcript);
    if (!addressed) return null;
    return isAiPpCallsignOnFrequency(addressed) ? null : addressed;
}

function transcriptLooksLikeContactHandoff(transcript) {
    const t = (transcript || '').toLowerCase();
    if (!/\bcontact\b/.test(t)) return false;
    return /\bpoint\b/.test(t) || /\bdecimal\b/.test(t) || /\d/.test(t);
}

function buildAiPpAtcSectorFrequencyLines() {
    return getSimulationAtcSectorsList().map(s => {
        const name = (s?.name || s?.id || '').toString().trim();
        const freq = normalizeAtcSectorFrequency(s?.frequency);
        return freq ? `${name}: ${freq} MHz` : `${name}: (no frequency defined)`;
    });
}

function buildAiPpLiveStateSuffixForApi() {
    const callsigns = getExerciseAiPpCallsignList();
    const aircraftLines = callsigns.map(cs => {
        const on = isAiPpCallsignOnFrequency(cs) ? 'yes' : 'no';
        return `  - ${cs} onFrequency=${on}`;
    });
    const freqLines = buildAiPpAtcSectorFrequencyLines();
    return [
        '',
        '[LIVE SESSION STATE]',
        'Exercise aircraft on-frequency status (Single User — checked in on your sector frequency):',
        ...(aircraftLines.length ? aircraftLines : ['  (none)']),
        '',
        'ATC sector frequencies in this exercise airspace (MHz):',
        ...(freqLines.length ? freqLines.map(line => `  - ${line}`) : ['  (none defined)'])
    ].join('\n');
}

function enforceAiPpOffFrequencySilence(transcript, aiResult) {
    const addressed = identifyAddressedCallsignFromTranscript(transcript);
    if (!addressed || isAiPpCallsignOnFrequency(addressed)) return aiResult;
    return { tts: '', command: '', raw: '{"tts":"","command":""}' };
}

function sendAiPpPttGeneralInstructionsPrime() {
    if (!aiPpEnabled) return null;
    aiPpPttPrimePromise = (async () => {
        try {
            const sessionId = await initializeAiPpOpenAiSession();
            if (!sessionId) return;
            const resp = await fetchWithTimeout('/api/ai-pp/respond', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    sessionId: aiPpOpenAiSessionId,
                    text: '[PTT PRESSED — refresh AI Pilot General Instructions for the upcoming controller transmission. Respond {"tts":"","command":""}.]',
                    mode: 'pttPrime'
                })
            }, 90000);
            const data = await resp.json().catch(() => ({}));
            if (!resp.ok || data.ok === false) throw new Error(data.error || 'AI Pilot PTT prime failed.');
            pushSimulationDebugLog('LOG', null, 'AI_PP general instructions primed (PTT press)');
        } catch (err) {
            pushSimulationDebugLog('WARN', null, `AI_PP PTT prime failed: ${err?.message || err}`);
        }
    })();
    return aiPpPttPrimePromise;
}

async function requestAiPpOpenAiResponse(transcript) {
    const text = (transcript || '').toString().trim();
    if (!text) return null;

    const offFreq = findOffFrequencyAddressedCallsignInTranscript(text);
    if (offFreq) {
        pushSimulationDebugLog('LOG', null, `AI_PP blocked off-frequency: ${offFreq}`);
        return { tts: '', command: '', raw: '{"tts":"","command":""}' };
    }

    const sessionId = await initializeAiPpOpenAiSession();
    if (!sessionId) throw new Error('AI Pilot session is not initialized.');
    if (aiPpPttPrimePromise) {
        try {
            await aiPpPttPrimePromise;
        } catch (_) { /* logged in sendAiPpPttGeneralInstructionsPrime */ }
        aiPpPttPrimePromise = null;
    }
    aiPpOpenAiResponding = true;
    setAiPpStatus('AI Pilot responding...');
    try {
        const liveState = buildAiPpLiveStateSuffixForApi();
        const resp = await fetchWithTimeout('/api/ai-pp/respond', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ sessionId: aiPpOpenAiSessionId, text, liveState })
        }, 90000);
        const data = await resp.json().catch(() => ({}));
        if (!resp.ok || data.ok === false) throw new Error(data.error || 'AI Pilot response failed.');
        const raw = (data.raw || '').toString().trim();
        let tts = (data.tts || '').toString().trim();
        let command = (data.command || '').toString().trim();
        const rawDisplay = raw || JSON.stringify({ tts, command }, null, 2);
        let result = { tts, command, raw: rawDisplay };
        result = enforceAiPpOffFrequencySilence(text, result);
        if (result.tts && transcriptLooksLikeContactHandoff(text)) {
            const handoffCs = identifyAddressedCallsignFromTranscript(text);
            if (handoffCs) clearAiPpCallsignOnFrequency(handoffCs);
        }
        return result;
    } catch (err) {
        aiPpOpenAiSessionId = '';
        throw err;
    } finally {
        aiPpOpenAiResponding = false;
        pumpAiPpOnFrequencyEventNotifyQueue();
    }
}

function resetSimulationAiPilotScriptState(exercise) {
    simulationAiPilotScripts = normalizeExerciseAiPilotScriptsFromExercise(
        exercise || window.simulationData?.exercise
    );
    simulationAiPilotScriptsFiredIds = new Set();
    simulationAiPilotScriptsLblTinFiredIds = new Set();
    simulationAiPilotScriptQueue = [];
    simulationAiPilotScriptProcessing = false;
    resetAiPpOnFrequencyCallsigns();
}

function buildAiPpScriptEventUserInput(script) {
    const callsign = (script.callsign || '').trim();
    const timeSec = Math.max(0, parseInt(script.previewTimeSec, 10) || 0);
    const timeLabel = formatPreviewClockMMSS(timeSec);
    const silent = !!script.aiInformationSilent;
    const useAiTts = !!script.ttsUseAiResponse;
    const presetTts = (script.ttsMessage || '').trim();
    const transformed = (script.aiTransformedCommand || '').trim();
    const instruction = (script.aiInformation || '').trim() || (script.commandForAi || '').trim();
    const mainLine = callsign && instruction ? `${callsign} ${instruction}` : (instruction || callsign);

    const lines = [
        '[SCRIPT EVENT]',
        `Simulation time: ${timeLabel} (${timeSec} s)`,
        `Silent: ${silent ? 'yes' : 'no'}`,
        `Use AI response for TTS: ${useAiTts ? 'yes' : 'no'}`
    ];
    if (silent) {
        lines.push('Silent=yes — context only; respond {"tts":"","command":""}; simulator applies pre-approved command if any.');
    } else {
        lines.push('Silent=no — respond with JSON; spoken readback required unless Use AI response for TTS=no and preset TTS is used.');
        if (!useAiTts) {
            lines.push(presetTts
                ? `Preset TTS (spoken by simulator, not your tts field): ${presetTts}`
                : 'Preset TTS: (none)');
        }
    }
    if (transformed) {
        lines.push(`Pre-approved transformed command (simulator applies this directly): ${transformed}`);
    } else {
        lines.push('Pre-approved transformed command: none — derive command from instruction if a simulator action is required.');
    }
    lines.push('Precedence: newer information for this aircraft supersedes older context.');
    lines.push('');
    lines.push(mainLine);
    return lines.join('\n');
}

async function requestAiPpOpenAiScriptEvent(scriptMessage, opts = {}) {
    const text = (scriptMessage || '').toString().trim();
    if (!text) return null;
    const sessionId = await initializeAiPpOpenAiSession();
    if (!sessionId) throw new Error('AI Pilot session is not initialized.');
    aiPpOpenAiResponding = true;
    try {
        const resp = await fetchWithTimeout('/api/ai-pp/respond', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                sessionId: aiPpOpenAiSessionId,
                text,
                mode: 'script',
                silent: !!opts.silent
            })
        }, 90000);
        const data = await resp.json().catch(() => ({}));
        if (!resp.ok || data.ok === false) throw new Error(data.error || 'AI Pilot script event failed.');
        const raw = (data.raw || '').toString().trim();
        const tts = (data.tts || '').toString().trim();
        const command = (data.command || '').toString().trim();
        const rawDisplay = raw || JSON.stringify({ tts, command }, null, 2);
        return { tts, command, raw: rawDisplay };
    } catch (err) {
        aiPpOpenAiSessionId = '';
        throw err;
    } finally {
        aiPpOpenAiResponding = false;
        pumpAiPpOnFrequencyEventNotifyQueue();
    }
}

function enqueueSimulationAiPilotScript(script) {
    if (!script) return;
    simulationAiPilotScriptQueue.push(script);
    pumpSimulationAiPilotScriptQueue();
}

async function pumpSimulationAiPilotScriptQueue() {
    if (simulationAiPilotScriptProcessing) return;
    simulationAiPilotScriptProcessing = true;
    try {
        while (simulationAiPilotScriptQueue.length) {
            const script = simulationAiPilotScriptQueue.shift();
            await processSimulationAiPilotScript(script);
        }
    } finally {
        simulationAiPilotScriptProcessing = false;
    }
}

async function processSimulationAiPilotScript(script) {
    if (isExerciseInitialCallScript(script)) {
        processSimulationInitialPilotCallScript(script);
        return;
    }

    if (!aiPpEnabled) {
        pushSimulationDebugLog('WARN', null, 'AI_PP script skipped: AI Pilot is off');
        return;
    }

    const silent = !!script.aiInformationSilent;
    const useAiTts = !!script.ttsUseAiResponse;
    const presetTts = (script.ttsMessage || '').trim();
    const transformed = (script.aiTransformedCommand || '').trim();
    const timeLabel = formatPreviewClockMMSS(script.previewTimeSec);
    const callsign = (script.callsign || '').trim();
    const userInput = buildAiPpScriptEventUserInput(script);

    pushSimulationDebugLog('LOG', null, `AI_PP script @ ${timeLabel} ${callsign}: firing`);

    let aiTts = '';
    let aiCommand = '';
    let aiRaw = '';
    try {
        const ai = await requestAiPpOpenAiScriptEvent(userInput, { silent });
        if (ai) {
            aiTts = (ai.tts || '').trim();
            aiCommand = (ai.command || '').trim();
            aiRaw = (ai.raw || '').trim();
        }
    } catch (err) {
        pushSimulationDebugLog('WARN', null, `AI_PP script failed: ${err?.message || err}`);
        return;
    }

    const commandToApply = transformed || aiCommand;
    let commandResult = null;
    if (commandToApply) {
        commandResult = applyAiPilotCommandTextToSimulator(commandToApply);
        pushSimulationDebugLog(
            'CMD',
            null,
            `AI_PP script command: ${commandToApply} (applied ${commandResult.applied}/${commandResult.actions.length})`
        );
    }

    let ttsToSpeak = '';
    if (!silent) {
        ttsToSpeak = useAiTts ? aiTts : presetTts;
    }
    const spokenTts = resolveAiPpTtsPlaceholders(ttsToSpeak, commandToApply);
    if (spokenTts && simulationSettings?.ttsEnabled && isSimulationTtsSupported()) {
        speakAiPpReadback(spokenTts);
    }
    if (!silent) {
        setAiPpReplyDisplay(spokenTts || aiTts, commandToApply, commandResult, aiRaw);
    }
}

function processSimulationInitialPilotCallScript(script) {
    const template = (script.ttsMessage || '').trim();
    const timeLabel = formatPreviewClockMMSS(script.previewTimeSec);
    const callsign = (script.callsign || '').trim();
    pushSimulationDebugLog('LOG', null, `AI_PP initial call @ ${timeLabel} ${callsign}: firing`);
    if (shouldRunSimulationInitialCallForUserSector(script) && callsign) {
        setAiPpCallsignOnFrequency(callsign);
    }
    if (!template || !simulationSettings?.ttsEnabled || !isSimulationTtsSupported()) return;
    enqueueSimulationGlobalTts(template, {
        source: 'pilotCall',
        priority: false,
        resolveText: () => resolveInitialPilotCallTtsTemplate(template, script)
    });
}

function processSimulationInitialCallLblTin(script) {
    const spawn = getExerciseFlightSpawnSecForScript(script);
    const lblSec = getInitialCallLblTinPreviewTimeSec(script, spawn);
    const timeLabel = formatPreviewClockMMSS(lblSec != null ? lblSec : script.previewTimeSec);
    const callsign = (script.callsign || '').trim();
    pushSimulationDebugLog('LOG', null, `AI_PP LBL_TIN @ ${timeLabel} ${callsign}: firing`);
    const ok = applyInitialCallLblTinTransfer(script);
    if (!ok) {
        pushSimulationDebugLog('WARN', null, `AI_PP LBL_TIN @ ${timeLabel} ${callsign}: apply failed`);
    }
}

function shouldRunSimulationInitialCallForUserSector(script) {
    if (!isExerciseInitialCallScript(script)) return true;
    const ctx = getSimulationUserAtcSectorContext();
    if (ctx.mode === 'all') return true;
    const scriptSectorId = String(script?.atcSectorId || '').trim();
    if (!scriptSectorId) return false;
    return scriptSectorId === String(ctx.atcSectorId || '');
}

function updateAiPpScriptTriggers() {
    if (isSimulationHostedMultiplayerSession()) return;
    if (simulationOperationModeId !== 'DL' || simulationIsMonitorOnly) return;
    if (simulationIsPaused) return;
    if (!simulationAiPilotScripts.length) return;
    if (aiPpOpenAiResponding || aiPpTranscribing) return;

    const sec = getSimulationClockSeconds();
    const due = simulationAiPilotScripts.filter(s => {
        if (!s || !s.id) return false;
        return true;
    });
    if (!due.length) return;

    due.forEach(s => {
        if (isExerciseInitialCallScript(s)) {
            const spawn = getExerciseFlightSpawnSecForScript(s);
            const lblSec = getInitialCallLblTinPreviewTimeSec(s, spawn);
            if (lblSec != null && lblSec <= sec && !simulationAiPilotScriptsLblTinFiredIds.has(s.id)) {
                simulationAiPilotScriptsLblTinFiredIds.add(s.id);
                if (shouldRunSimulationInitialCallForUserSector(s)) {
                    processSimulationInitialCallLblTin(s);
                }
            }
            const callSec = Math.max(0, parseInt(s.previewTimeSec, 10) || 0);
            if (callSec <= sec && !simulationAiPilotScriptsFiredIds.has(s.id)) {
                simulationAiPilotScriptsFiredIds.add(s.id);
                if (shouldRunSimulationInitialCallForUserSector(s)) {
                    enqueueSimulationAiPilotScript(s);
                }
            }
            return;
        }
        if (simulationAiPilotScriptsFiredIds.has(s.id)) return;
        if ((Number(s.previewTimeSec) || 0) > sec) return;
        simulationAiPilotScriptsFiredIds.add(s.id);
        enqueueSimulationAiPilotScript(s);
    });
}

function findSimulationAircraftByAiPilotCallsign(callsign) {
    const wanted = (callsign || '').toString().trim().toUpperCase().replace(/\s+/g, '');
    if (!wanted) return null;
    const list = window.simulationData?.aircraft || [];
    return list.find(ac => ac && (ac.callsign || '').toString().trim().toUpperCase().replace(/\s+/g, '') === wanted) || null;
}

function findSimulationWaypointByName(name) {
    const wanted = (name || '').toString().trim().toUpperCase();
    if (!wanted) return null;
    const list = window.simulationData?.waypoints || [];
    return list.find(wp => wp && (wp.name || '').toString().trim().toUpperCase() === wanted) || null;
}

function findAircraftTrajectoryWaypointIndexByName(ac, waypointName) {
    const wanted = (waypointName || '').toString().trim().toUpperCase();
    if (!ac || !wanted || !Array.isArray(ac.points)) return null;
    const idx = ac.points.findIndex(pt => pt && (pt.name || '').toString().trim().toUpperCase() === wanted);
    return idx >= 0 ? idx : null;
}

function applyAiPilotActionToSimulator(action) {
    if (!action || action.action === 'unknown') return false;
    const ac = findSimulationAircraftByAiPilotCallsign(action.callsign);
    if (!ac) {
        try { pushSimulationDebugLog('WARN', null, `AI_PP command ignored: aircraft ${action.callsign || '?'} not found`); } catch (e) {}
        return false;
    }

    try {
        if (action.action === 'heading') {
            applySimulationDlHeadingCommandFromDeg(ac, action.heading, { immediate: true, suppressTts: true });
            return true;
        }
        if (action.action === 'direct') {
            const idx = findAircraftTrajectoryWaypointIndexByName(ac, action.waypoint);
            if (idx != null && idx >= 1) {
                issueSimulationDirectTo(ac, idx, { immediate: true, suppressTts: true });
                return true;
            }
            const wp = findSimulationWaypointByName(action.waypoint);
            if (wp && isFinite(wp.latitude) && isFinite(wp.longitude)) {
                applyPathToAircraft(ac, [{ lat: Number(wp.latitude), lon: Number(wp.longitude), name: (wp.name || action.waypoint).toString().toUpperCase(), wpId: wp.id }]);
                recordSimulationSubtitleEvent(ac, `DCT to > ${(wp.name || action.waypoint).toString().toUpperCase()}`, { command: 'DCT', waypointName: (wp.name || action.waypoint).toString().toUpperCase() });
                return true;
            }
            return false;
        }
        if (action.action === 'reroute') {
            const points = (action.route || []).map(name => {
                const wp = findSimulationWaypointByName(name);
                return wp && isFinite(wp.latitude) && isFinite(wp.longitude)
                    ? { lat: Number(wp.latitude), lon: Number(wp.longitude), name: (wp.name || name).toString().toUpperCase(), wpId: wp.id }
                    : null;
            }).filter(Boolean);
            if (!points.length) return false;
            applyPathToAircraft(ac, points);
            recordSimulationSubtitleEvent(ac, `Rerouting input > ${points.map(p => p.name).join(' ')}`, { command: 'RTE', route: points.map(p => p.name) });
            return true;
        }
        if (action.action === 'hold') {
            const wp = findSimulationWaypointByName(action.waypoint);
            if (!wp || wp.id == null) return false;
            return issueSimulationHoldArmWaypoint(ac, wp.id);
        }
        if (action.action === 'exitHold') {
            return issueSimulationHoldCancel(ac, { immediate: false });
        }
        if (action.action === 'altitude') {
            const fl = normalizeAiPilotAlvToFl(action.value);
            if (fl == null) return false;
            applyHostAlvLevelCommandFromPp(ac, fl, { suppressTts: true });
            return true;
        }
        if (action.action === 'speed') {
            applySimulationSpeedSelectionToAircraft(ac, action.input, action.value, { playTts: false });
            return true;
        }
        if (action.action === 'roc') {
            return applyAiPilotRocCommandToAircraft(ac, action.value);
        }
        if (action.action === 'approach') {
            const ok = issueSimulationApproachClearance(ac, action.approachName, { suppressTts: true });
            if (ok) {
                recordSimulationSubtitleEvent(ac, `Cleared > ${normalizeApproachName(action.approachName)}`, {
                    command: 'APP',
                    approachName: normalizeApproachName(action.approachName)
                });
            }
            return ok;
        }
    } catch (err) {
        try { pushSimulationDebugLog('WARN', ac, `AI_PP command failed: ${err?.message || err}`); } catch (e) {}
        return false;
    } finally {
        try { drawSimulationCanvas(); } catch (e) {}
    }
    return false;
}

function applyAiPilotCommandTextToSimulator(commandText) {
    const actions = parseAiPilotCommandTextToActions(commandText);
    let applied = 0;
    actions.forEach(action => {
        if (applyAiPilotActionToSimulator(action)) applied += 1;
    });
    return { actions, applied };
}

async function transcribeAiPpAudio(blob) {
    if (!blob || !blob.size) return;
    aiPpTranscribing = true;
    setAiPpStatus('Transcribing...');
    try {
        const fd = new FormData();
        fd.append('audio', blob, 'ai_pp_ptt.webm');
        const resp = await fetchWithTimeout('/api/ai-pp/transcribe', { method: 'POST', body: fd }, 120000);
        const data = await resp.json().catch(() => ({}));
        if (!resp.ok || data.ok === false) {
            throw new Error(data.error || `Transcription failed (${resp.status})`);
        }
        const text = (data.text || '').toString().trim();
        if (!text) {
            setAiPpStatus('No speech detected');
            return;
        }
        pushSimulationDebugLog('LOG', null, `AI_PP transcript: ${text}`);
        setAiPpTranscriptDisplay(text);
        const ai = await requestAiPpOpenAiResponse(text);
        const tts = (ai?.tts || '').toString().trim();
        const command = (ai?.command || '').toString().trim();
        let commandResult = null;
        if (command) {
            commandResult = applyAiPilotCommandTextToSimulator(command);
            pushSimulationDebugLog('CMD', null, `AI_PP command: ${command} (applied ${commandResult.applied}/${commandResult.actions.length})`);
        }
        const spokenTts = resolveAiPpTtsPlaceholders(tts, command);
        setAiPpReplyDisplay(spokenTts, command, commandResult, ai?.raw || '');
        if (spokenTts) {
            setAiPpStatus(`Readback: ${spokenTts}`);
            speakAiPpReadback(spokenTts);
        } else if (!command) {
            const offFreq = findOffFrequencyAddressedCallsignInTranscript(text);
            setAiPpStatus(offFreq ? `Off frequency: ${offFreq}` : 'AI Pilot returned no readback');
        } else {
            setAiPpStatus(`Command: ${command}`);
        }
    } catch (err) {
        setAiPpStatus(err?.message || 'AI_PP failed');
    } finally {
        aiPpTranscribing = false;
    }
}

function speakAiPpReadback(text) {
    if (!text) return;
    setAiPpTxRx(false, true);
    if (aiPpRxTimerId) {
        clearTimeout(aiPpRxTimerId);
        aiPpRxTimerId = null;
    }
    enqueueSimulationGlobalTts(text, {
        priority: true,
        source: 'aiPp',
        onComplete: () => {
            setAiPpTxRx(false, false);
            if (aiPpEnabled && aiPpPttKey) setAiPpStatus(`PTT: ${aiPpPttKey.label}`);
        }
    });
}

function handleAiPpGlobalKeyDown(e) {
    if (aiPpSelectingKey) {
        e.preventDefault();
        aiPpPendingPttKey = { key: e.key || '', code: e.code || '', label: formatAiPpKeyLabel(e) };
        aiPpSelectingKey = false;
        updateAiPpConfigDisplay();
        const hint = document.getElementById('aiPpPttHint');
        if (hint) hint.textContent = 'Key captured. Press OK to enable AI_PP.';
        return;
    }
    if (!aiPpEnabled || e.repeat || !aiPpEventMatchesPtt(e)) return;
    e.preventDefault();
    aiPpPttPressed = true;
    if (isSimulationTtsSpeakingNow()) {
        aiPpPttBlockedByTts = true;
        setAiPpTxRx(true, false, { blocked: true });
        startAiPpPttBlockBeep();
        setAiPpStatus('PTT blocked — readback in progress');
        return;
    }
    startAiPpRecording();
    sendAiPpPttGeneralInstructionsPrime();
}

function handleAiPpGlobalKeyUp(e) {
    if (!aiPpEnabled || !aiPpPttPressed || !aiPpEventMatchesPtt(e)) return;
    e.preventDefault();
    aiPpPttPressed = false;
    if (aiPpPttBlockedByTts) {
        aiPpPttBlockedByTts = false;
        stopAiPpPttBlockBeep();
        setAiPpTxRx(false, false);
        if (aiPpPttKey) setAiPpStatus(`PTT: ${aiPpPttKey.label}`);
        return;
    }
    stopAiPpRecording();
}

function simulationSpeakNow(text, opts = {}) {
    try {
        if (isSimulationHostedMultiplayerSession()) return;
        if (simulationOperationModeId !== 'DL' || simulationIsMonitorOnly) return;
        if (!simulationSettings?.ttsEnabled) return;
        if (!isSimulationTtsSupported()) return;
        if (opts.immediate) {
            try { window.speechSynthesis.cancel(); } catch (e) {}
            resetSimulationGlobalTtsState();
            const u = new SpeechSynthesisUtterance((text || '').toString());
            u.rate = 1;
            u.pitch = 1;
            u.volume = 1;
            u.onstart = () => { simulationTtsIsSpeaking = true; };
            u.onend = () => { simulationTtsIsSpeaking = false; };
            u.onerror = () => { simulationTtsIsSpeaking = false; };
            try { window.speechSynthesis.resume(); } catch (e) {}
            window.speechSynthesis.speak(u);
            return;
        }
        enqueueSimulationGlobalTts(text, opts);
    } catch (e) {}
}

function getSimulationSpokenCallsign(callsignRaw) {
    const cs = (callsignRaw || '').toString().trim().toUpperCase().replace(/\s+/g, '');
    if (!cs) return '';
    const phon = (window.AVIATION_PHONETIC && typeof window.AVIATION_PHONETIC === 'object') ? window.AVIATION_PHONETIC : {};
    const airlines = (window.AIRLINE_CALLSIGNS && typeof window.AIRLINE_CALLSIGNS === 'object') ? window.AIRLINE_CALLSIGNS : {};

    const title = (w) => {
        const s = (w || '').toString();
        if (!s) return '';
        return s.charAt(0).toUpperCase() + s.slice(1);
    };

    const speakChar = (ch) => {
        const c = (ch || '').toString().toUpperCase();
        if (!c) return '';
        if (/[0-9]/.test(c)) return c; // digits spoken individually (e.g. "1 2 3")
        if (/[A-Z]/.test(c)) return (phon[c] || c.toLowerCase());
        return '';
    };

    const prefix = cs.slice(0, 3);
    const rest = cs.slice(3);
    if (/^[A-Z]{3}$/.test(prefix) && airlines[prefix]) {
        const airline = airlines[prefix];
        const restSpoken = rest.split('').map(speakChar).filter(Boolean).map(title).join(' ');
        return `${airline}${restSpoken ? ' ' + restSpoken : ''}`.trim();
    }

    return cs.split('').map(speakChar).filter(Boolean).map(title).join(' ').trim();
}

function getSimulationSpokenWaypointName(rawName) {
    const nm = (rawName || '').toString().trim().toUpperCase().replace(/\s+/g, '');
    if (!nm) return '';
    const phon = (window.AVIATION_PHONETIC && typeof window.AVIATION_PHONETIC === 'object') ? window.AVIATION_PHONETIC : {};
    const title = (w) => {
        const s = (w || '').toString();
        if (!s) return '';
        return s.charAt(0).toUpperCase() + s.slice(1);
    };
    // If exactly 5 letters (A-Z), pronounce as a word (not letter-by-letter).
    if (/^[A-Z]{5}$/.test(nm)) {
        return title(nm.toLowerCase());
    }
    const speakChar = (ch) => {
        const c = (ch || '').toString().toUpperCase();
        if (!c) return '';
        if (/[0-9]/.test(c)) return c;
        if (/[A-Z]/.test(c)) return title(phon[c] || c.toLowerCase());
        return '';
    };
    return nm.split('').map(speakChar).filter(Boolean).join(' ').trim();
}

function getSimulationSpokenApproachName(rawName) {
    const nm = (rawName || '').toString().trim().toUpperCase().replace(/[^A-Z0-9]/g, '');
    if (!nm) return '';

    const lettersSpaced = (s) => (s || '').split('').filter(ch => /[A-Z]/.test(ch)).join(' ').trim();
    const digitsSpaced = (s) => (s || '').split('').filter(ch => /[0-9]/.test(ch)).join(' ').trim();

    // Expected pattern: TYPE(3 letters) + RWY(2 digits) + optional side (R/L/C)
    const m = nm.match(/^([A-Z]{3})(\d{1,2})([LRC])?$/);
    if (m) {
        const typ = lettersSpaced(m[1]);
        const rwy = digitsSpaced(m[2].padStart(2, '0'));
        const side = (m[3] || '').toUpperCase();
        const sideSpoken = side === 'R' ? 'Right' : side === 'L' ? 'Left' : side === 'C' ? 'Center' : '';
        return `${typ}${rwy ? ' ' + rwy : ''}${sideSpoken ? ' ' + sideSpoken : ''}`.trim();
    }

    // Fallback: speak as letters/digits individually
    const parts = nm.split('').map(ch => {
        if (/[A-Z]/.test(ch)) return ch;
        if (/[0-9]/.test(ch)) return ch;
        return '';
    }).filter(Boolean);
    return parts.join(' ').trim();
}

function getSimulationTurnSide(fromDeg, toDeg) {
    const wrap360 = (deg) => {
        const d = Number(deg);
        if (!isFinite(d)) return null;
        return ((d % 360) + 360) % 360;
    };
    const a = wrap360(fromDeg);
    const b = wrap360(toDeg);
    if (a == null || b == null) return null;
    let d = b - a;
    while (d > 180) d -= 360;
    while (d < -180) d += 360;
    if (d > 0) return 'right';
    if (d < 0) return 'left';
    return null;
}

function signedHeadingDelta(fromDeg, toDeg) {
    const wrap360 = (deg) => {
        const d = Number(deg);
        if (!isFinite(d)) return null;
        return ((d % 360) + 360) % 360;
    };
    const a = wrap360(fromDeg);
    const b = wrap360(toDeg);
    if (a == null || b == null) return null;
    let d = b - a;
    while (d > 180) d -= 360;
    while (d < -180) d += 360;
    return d;
}

function smallestHeadingDeltaAbs(fromDeg, toDeg) {
    const wrap360 = (deg) => {
        const d = Number(deg);
        if (!isFinite(d)) return null;
        return ((d % 360) + 360) % 360;
    };
    const a = wrap360(fromDeg);
    const b = wrap360(toDeg);
    if (a == null || b == null) return null;
    let d = b - a;
    while (d > 180) d -= 360;
    while (d < -180) d += 360;
    return Math.abs(d);
}

function getSimulationSpokenKnots(kts) {
    const n = Math.max(0, Math.min(999, Math.round(Number(kts))));
    const digits = String(n).padStart(3, '0').split('').join(' ');
    return `${digits} knots`;
}

function getSimulationSpokenMach(mach) {
    const m = Number(mach);
    if (!isFinite(m)) return '';
    const s = m.toFixed(2); // e.g. "0.83"
    const parts = s.split('.');
    const after = (parts[1] || '').slice(0, 2);
    const digits = after.split('').join(' ').trim();
    return `Mach Point ${digits}`.trim();
}

function getSimulationTransitionFlForAtcSector(sector) {
    const tr = Number(sector?.verticalLimits?.transitionFl);
    return Number.isFinite(tr) ? tr : 60;
}

function getAiPpActiveTransitionFl() {
    try {
        const sectors = getSimulationAtcSectorsList();
        if (sectors && sectors.length) {
            const ctx = (typeof getSimulationUserAtcSectorContext === 'function') ? getSimulationUserAtcSectorContext() : null;
            if (ctx && ctx.atcSectorId) {
                const s = sectors.find(x => x && String(x.id) === String(ctx.atcSectorId));
                if (s) return getSimulationTransitionFlForAtcSector(s);
            }
            return getSimulationTransitionFlForAtcSector(sectors[0]);
        }
    } catch (e) {}
    return 60;
}

/**
 * Expand AI Pilot tts placeholders ({CALLSIGN}, {ALVnnn}, {TLHnnn}, {TRHnnn}, {HDGnnn}, {IASnnn}, {Mnnn})
 * into spoken phraseology using the same helpers and live aircraft state the simulator uses for its own
 * readbacks. The AI provides only the cleared value via the placeholder; the simulator decides
 * climb/descend/maintain, turn direction, and increase/reduce here so it always matches aircraft state.
 * Text without placeholders is returned unchanged (back-compatible with plain-spoken instructions).
 */
function resolveAiPpTtsPlaceholders(ttsText, commandText) {
    let text = (ttsText || '').toString();
    if (!text || text.indexOf('{') === -1) return text;

    const cmd = (commandText || '').toString().trim();
    const firstToken = cmd.split(/[\s;]+/).filter(Boolean)[0] || '';
    const icao = firstToken.toUpperCase();
    const ac = icao ? findSimulationAircraftByAiPilotCallsign(icao) : null;

    const spaceDigits = (s) => String(s).split('').join(' ');

    const getCurrentIasMach = () => {
        if (!ac) return { ias: null, mach: null };
        const mcFeet = Number(ac.publishedModeCFeet ?? ac.modeCFeet ?? ((parseInt(ac.assignedFl ?? ac.alv ?? 0, 10) || 0) * 100));
        const altFeet = isFinite(mcFeet) ? mcFeet : 0;
        const ktasNow = (ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) ? Number(ac.modeSTasKt) : null;
        if (ktasNow == null) return { ias: null, mach: null };
        let ias = null, mach = null;
        try { ias = (typeof kiasFromKtas === 'function') ? kiasFromKtas(ktasNow, altFeet) : null; } catch (e) {}
        try { mach = (typeof machFromKtas === 'function') ? machFromKtas(ktasNow, altFeet) : null; } catch (e) {}
        return { ias, mach };
    };

    text = text.replace(/\{\s*CALLSIGN\s*\}/gi, () => getSimulationSpokenCallsign(icao) || icao);

    text = text.replace(/\{\s*ALV\s*(\d{2,5})\s*\}/gi, (_m, d) => {
        const targetFl = normalizeAiPilotAlvToFl(d);
        if (targetFl == null) return '';
        const phrase = formatPilotCallLevelPhrase(targetFl, getAiPpActiveTransitionFl());
        let curFl = ac ? getAircraftModeCFlForDisplay(ac) : null;
        if (curFl == null && ac) curFl = getAircraftAlvFlForDisplay(ac);
        let verb = 'maintain';
        if (curFl != null) verb = (targetFl > curFl) ? 'climb' : (targetFl < curFl) ? 'descend' : 'maintain';
        return `${verb} ${phrase}`;
    });

    text = text.replace(/\{\s*TLH\s*(\d{3})\s*\}/gi, (_m, d) => `turn left heading ${spaceDigits(d)}`);
    text = text.replace(/\{\s*TRH\s*(\d{3})\s*\}/gi, (_m, d) => `turn right heading ${spaceDigits(d)}`);

    text = text.replace(/\{\s*HDG\s*(\d{3})\s*\}/gi, (_m, d) => {
        const target = parseInt(d, 10);
        let curHdg = null;
        if (ac) {
            if (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg)) curHdg = Number(ac.publishedHeadingDeg);
            else if (ac.currentHeadingDeg != null && isFinite(ac.currentHeadingDeg)) curHdg = Number(ac.currentHeadingDeg);
        }
        const side = (curHdg != null) ? getSimulationTurnSide(curHdg, target) : null;
        return side ? `turn ${side} heading ${spaceDigits(d)}` : `fly heading ${spaceDigits(d)}`;
    });

    text = text.replace(/\{\s*IAS\s*(\d{2,3})\s*\}/gi, (_m, d) => {
        const next = parseInt(d, 10);
        const spoken = getSimulationSpokenKnots(next);
        const { ias } = getCurrentIasMach();
        if (ias == null || !isFinite(ias)) return `speed ${spoken}`;
        const cur = Math.round(Number(ias) / 10) * 10;
        if (next > cur) return `increase speed to ${spoken}`;
        if (next < cur) return `reduce speed to ${spoken}`;
        return `maintain speed ${spoken}`;
    });

    text = text.replace(/\{\s*M\s*(\d{2,3})\s*\}/gi, (_m, d) => {
        const mval = normalizeAiPilotMachFromTokenDigits(d);
        if (mval == null) return '';
        const spoken = getSimulationSpokenMach(mval);
        const { mach } = getCurrentIasMach();
        if (mach == null || !isFinite(mach)) return spoken;
        const cur = Number(Number(mach).toFixed(2));
        if (mval > cur) return `increase to ${spoken}`;
        if (mval < cur) return `reduce to ${spoken}`;
        return `maintain ${spoken}`;
    });

    text = text.replace(/[{}]/g, '');
    text = text.replace(/\s{2,}/g, ' ').replace(/\s+([,.])/g, '$1').trim();
    return text;
}

function formatPilotCallLevelPhrase(fl, transitionFl) {
    const n = Number(fl);
    if (!Number.isFinite(n)) return '';
    const tr = Number(transitionFl);
    if (Number.isFinite(tr) && n < tr) {
        const feet = Math.round(n * 100);
        return `${feet} feet`;
    }
    const digits = String(Math.max(0, Math.min(500, Math.round(n)))).padStart(3, '0').split('').join(' ');
    return `flight level ${digits}`;
}

function getAircraftProceedingWaypointName(ac) {
    const pts = ac?.points;
    if (!Array.isArray(pts) || pts.length < 2) return '';
    const idx = Math.max(0, Math.min(pts.length - 2, parseInt(ac.routeProgressIdx, 10) || 0));
    const next = pts[idx + 1];
    return (next?.name || '').toString().trim().toUpperCase();
}

function computePilotCallSectorEntryInfo(ac, atcSectorsOverride = null) {
    const atcSectors = atcSectorsOverride || getSimulationAtcSectorsList();
    if (!atcSectors.length || !ac) return null;
    const acSeq = getAircraftForAtmTrajectorySequence(ac);
    const baseState = getAircraftStateForAdvancedLabel(ac);
    if (!baseState || !isFinite(baseState.lat) || !isFinite(baseState.lon)) return null;
    const state = getSectorSequenceStateForDisplayRoute(ac, acSeq, baseState);
    const poly = buildRemainingTrajectoryPolylineForSectorSequence(acSeq, state);
    if (!poly?.points?.length || !isFinite(poly.totalNm) || poly.totalNm <= 0) return null;

    const verticalMeta = buildAtcSectorVerticalMeta(atcSectors);
    const gsKt = getTrajectoryGsKtForSector(ac);
    if (!isFinite(gsKt) || gsKt <= 0) return null;

    const fl0 = getTrajectoryFlForSectorSequenceAtRemainingNm(acSeq, 0, poly.totalNm, state);
    if (!isFinite(fl0)) return null;
    const sector0 = findAtcSectorIndexForSample(state.lat, state.lon, fl0, atcSectors, verticalMeta);

    let stepNm = 0.25;
    const maxSamples = 4000;
    if (poly.totalNm / stepNm > maxSamples) stepNm = poly.totalNm / maxSamples;

    let entryNm = null;
    let entrySectorIdx = null;

    if (sector0 >= 0) {
        for (let d = stepNm; d <= poly.totalNm + 1e-9; d += stepNm) {
            const pos = getPositionAlongPolylineAtDistanceNm(poly.points, poly.legsNm, poly.cumNm, d);
            if (!pos || !isFinite(pos.lat) || !isFinite(pos.lon)) continue;
            const fl = getTrajectoryFlForSectorSequenceAtRemainingNm(acSeq, d, poly.totalNm, state);
            const sec = findAtcSectorIndexForSample(pos.lat, pos.lon, fl, atcSectors, verticalMeta);
            if (sec >= 0 && sec !== sector0) {
                entryNm = d;
                entrySectorIdx = sec;
                break;
            }
        }
    } else {
        for (let d = 0; d <= poly.totalNm + 1e-9; d += stepNm) {
            const pos = getPositionAlongPolylineAtDistanceNm(poly.points, poly.legsNm, poly.cumNm, d);
            if (!pos || !isFinite(pos.lat) || !isFinite(pos.lon)) continue;
            const fl = getTrajectoryFlForSectorSequenceAtRemainingNm(acSeq, d, poly.totalNm, state);
            const sec = findAtcSectorIndexForSample(pos.lat, pos.lon, fl, atcSectors, verticalMeta);
            if (sec >= 0) {
                entryNm = d;
                entrySectorIdx = sec;
                break;
            }
        }
    }

    if (entrySectorIdx == null || entryNm == null || entryNm <= 0.001) return null;
    const minutes = (entryNm / gsKt) * 60;
    return {
        sectorIdx: entrySectorIdx,
        sector: atcSectors[entrySectorIdx],
        entryNm,
        minutes
    };
}

/** Last planned exit from a given ATC sector volume along the remaining route (handles re-entry). */
function computeAircraftAtcSectorLastExitInfo(ac, atcSectorId) {
    if (!ac || atcSectorId == null || atcSectorId === '') return null;
    const atcSectors = getSimulationAtcSectorsList();
    const targetIdx = atcSectors.findIndex((s) => s && String(s.id) === String(atcSectorId));
    if (targetIdx < 0) return null;

    const acSeq = getAircraftForAtmTrajectorySequence(ac);
    const baseState = getAircraftStateForAdvancedLabel(ac);
    if (!baseState || !isFinite(baseState.lat) || !isFinite(baseState.lon)) return null;
    const state = getSectorSequenceStateForDisplayRoute(ac, acSeq, baseState);
    const poly = buildRemainingTrajectoryPolylineForSectorSequence(acSeq, state);
    if (!poly?.points?.length) return null;

    const totalNm = poly.totalNm;
    if (!isFinite(totalNm) || totalNm <= 0) return null;

    const verticalMeta = buildAtcSectorVerticalMeta(atcSectors);
    const gsKt = getTrajectoryGsKtForSector(ac);
    if (!isFinite(gsKt) || gsKt <= 0) return null;

    let stepNm = 0.25;
    const maxSamples = 4000;
    if (totalNm / stepNm > maxSamples) stepNm = totalNm / maxSamples;

    const distSamples = [];
    for (let d = 0; d <= totalNm + 1e-9; d += stepNm) distSamples.push(d);
    if (!distSamples.length || distSamples[distSamples.length - 1] < totalNm - 1e-9) {
        distSamples.push(totalNm);
    }

    let insideTarget = false;
    let lastExitNm = null;

    for (let i = 0; i < distSamples.length; i += 1) {
        const d = distSamples[i];
        const pos = getPositionAlongPolylineAtDistanceNm(poly.points, poly.legsNm, poly.cumNm, d);
        if (!pos || !isFinite(pos.lat) || !isFinite(pos.lon)) continue;
        const fl = getTrajectoryFlForSectorSequenceAtRemainingNm(acSeq, d, totalNm, state);
        if (!isFinite(fl)) continue;
        const sec = findAtcSectorIndexForSample(pos.lat, pos.lon, fl, atcSectors, verticalMeta);
        const inTarget = sec === targetIdx;
        if (!inTarget && insideTarget) lastExitNm = d;
        insideTarget = inTarget;
    }

    if (lastExitNm == null) return null;

    const simSecNow = getSimulationClockSeconds();
    const exitSimSec = simSecNow + (lastExitNm / gsKt) * 3600;
    return {
        exitNm: lastExitNm,
        minutes: (lastExitNm / gsKt) * 60,
        simSec: exitSimSec
    };
}

function buildExerciseInitialPilotCallTtsTemplate(ac, sector) {
    const callsign = getSimulationSpokenCallsign(ac?.callsign);
    if (!callsign) return '';
    return `${callsign} at ${INITIAL_CALL_TTS_MODE_C_TOKEN}, inbound ${INITIAL_CALL_TTS_WAYPOINT_TOKEN}`;
}

function formatPilotCallProceedingWaypointForInitialCallTts(ac) {
    if (!ac) return '';
    return getSimulationSpokenWaypointName(getAircraftProceedingWaypointName(ac));
}

function formatPilotCallModeCLevelForInitialCallTts(modeCFl, transitionFl) {
    const n = Number(modeCFl);
    if (!Number.isFinite(n)) return '';
    const tr = Number(transitionFl);
    if (Number.isFinite(tr) && n < tr) {
        return `altitude ${Math.round(n * 100)}`;
    }
    const digits = String(Math.max(0, Math.min(500, Math.round(n)))).padStart(3, '0').split('').join(' ');
    return `flight level ${digits}`;
}

function findSimulationAtcSectorById(atcSectorId) {
    const list = getSimulationAtcSectorsList();
    if (!list.length || atcSectorId == null || atcSectorId === '') return null;
    const wanted = String(atcSectorId);
    const byId = list.find(s => s && String(s.id) === wanted);
    if (byId) return byId;
    const idx = parseInt(wanted, 10);
    if (Number.isFinite(idx) && idx >= 0 && idx < list.length) return list[idx];
    return null;
}

function getPreviousAtcSectorIdBeforeEntryAtcSectorId(ac, entryAtcSectorId) {
    if (!ac || entryAtcSectorId == null || entryAtcSectorId === '') return null;
    const list = getSimulationAtcSectorsList();
    const entry = findSimulationAtcSectorById(entryAtcSectorId);
    const entryNm = (entry?.name || entry?.id || '').toString().trim().toUpperCase();
    if (!entryNm) return null;
    const seq = computeAdvancedLabelSectorSequence(ac);
    const idx = seq.findIndex(n => (n || '').toString().trim().toUpperCase() === entryNm);
    if (idx <= 0) return null;
    const prevNm = (seq[idx - 1] || '').toString().trim().toUpperCase();
    const prev = list.find(s => ((s?.name || s?.id || '').toString().trim().toUpperCase()) === prevNm);
    return prev ? String(prev.id) : null;
}

function applySimulationInboundTransferToAtcSector(ac, fromAtcSectorId, toSectorNameNorm) {
    if (!ac || !fromAtcSectorId || !toSectorNameNorm) return false;
    const toNm = String(toSectorNameNorm).trim().toUpperCase();
    if (!toNm) return false;
    if (usesPpFmsFlightStatusDomain()) {
        ac.ppTransferFromAtcSectorId = fromAtcSectorId;
        ac.ppTransferToSectorNameNorm = toNm;
        ac.ppTransferReceiverAssumed = false;
        try { ac._cinFtCacheKey = null; } catch (e) {}
        postPpFlightStatusFields(ac, {
            ppTransferFromAtcSectorId: fromAtcSectorId,
            ppTransferToSectorNameNorm: toNm,
            ppTransferReceiverAssumed: false
        });
        drawSimulationCanvas();
        return true;
    }
    delete _joinerAtmTouRollbackPendingByAid[String(ac.id)];
    ac.transferFromAtcSectorId = fromAtcSectorId;
    ac.transferToSectorNameNorm = toNm;
    ac.transferReceiverAssumed = false;
    try { ac._cinFtCacheKey = null; } catch (e) {}
    clearAtmSectorSequenceCachesForAircraft(ac);
    const patch = {
        transferFromAtcSectorId: fromAtcSectorId,
        transferToSectorNameNorm: toNm,
        transferReceiverAssumed: false
    };
    if (isJoinerAtmDisplayClient() && ac._atmTrajectoryPatch && typeof ac._atmTrajectoryPatch === 'object') {
        ac._atmTrajectoryPatch.transferFromAtcSectorId = fromAtcSectorId;
        ac._atmTrajectoryPatch.transferToSectorNameNorm = toNm;
        ac._atmTrajectoryPatch.transferReceiverAssumed = false;
        try { ac._atmTrajectoryPatchSig = atmTrajectoryPatchSignature(ac._atmTrajectoryPatch); } catch (eP) {}
    }
    try { postJoinerAtmTrajectoryVerticalFields(ac, patch); } catch (e2) {}
    try {
        if (simulationSessionId && !simulationJoinedSessionId) {
            hostPushAtmTrajectoryPatchFromHostNow(ac, { skipAtmFlightMetadataKeys: false });
        }
    } catch (eH) {}
    try { syncJoinerExeAircraftPatchesFlightMetadataFromAircraft(ac); } catch (eSync) {}
    drawSimulationCanvas();
    return true;
}

function applyInitialCallLblTinTransfer(script) {
    if (!script?.atcSectorId) return false;
    const ac = findSimulationAircraftByAiPilotCallsign(script.callsign);
    if (!ac) {
        try { pushSimulationDebugLog('WARN', null, `AI_PP LBL_TIN ignored: aircraft ${script.callsign || '?'} not found`); } catch (e) {}
        return false;
    }
    const entrySector = findSimulationAtcSectorById(script.atcSectorId);
    const toNm = (entrySector?.name || entrySector?.id || '').toString().trim().toUpperCase();
    if (!toNm) return false;
    const fromId = getPreviousAtcSectorIdBeforeEntryAtcSectorId(ac, script.atcSectorId);
    if (!fromId) return false;
    return applySimulationInboundTransferToAtcSector(ac, fromId, toNm);
}

function resolveInitialPilotCallTtsTemplate(template, script) {
    const tpl = (template || '').toString().trim();
    if (!tpl) return '';

    let ac = null;
    if (script?.aircraftId) {
        ac = (window.simulationData?.aircraft || []).find(a => a && String(a.id) === String(script.aircraftId));
    }
    if (!ac && script?.callsign) {
        ac = findSimulationAircraftByAiPilotCallsign(script.callsign);
    }

    let result = tpl;
    if (result.includes(INITIAL_CALL_TTS_MODE_C_TOKEN)) {
        let levelPhrase = '';
        if (ac) {
            const sector = findSimulationAtcSectorById(script?.atcSectorId);
            const transitionFl = getSimulationTransitionFlForAtcSector(sector);
            const modeCFl = getAircraftModeCFlForDisplay(ac);
            levelPhrase = formatPilotCallModeCLevelForInitialCallTts(modeCFl, transitionFl);
        }
        result = result.split(INITIAL_CALL_TTS_MODE_C_TOKEN).join(levelPhrase);
    }
    if (result.includes(INITIAL_CALL_TTS_WAYPOINT_TOKEN)) {
        const wpPhrase = formatPilotCallProceedingWaypointForInitialCallTts(ac);
        result = result.split(INITIAL_CALL_TTS_WAYPOINT_TOKEN).join(wpPhrase);
    }
    return result.replace(/\s+/g, ' ').trim();
}

function formatInitialPilotCallTtsForExercisePreviewDisplay(template) {
    const tpl = (template || '').toString().trim();
    if (!tpl) return '';
    return tpl
        .split(INITIAL_CALL_TTS_MODE_C_TOKEN).join('[level]')
        .split(INITIAL_CALL_TTS_WAYPOINT_TOKEN).join('[waypoint]')
        .replace(/\s+/g, ' ').trim();
}

function buildAiPpPilotCallOnFrequencyMessage(ac, sector) {
    const transitionFl = getSimulationTransitionFlForAtcSector(sector);
    const modeCFl = getAircraftModeCFlForDisplay(ac);
    const alvFl = getAircraftAlvFlForDisplay(ac);
    if (modeCFl == null || alvFl == null) return '';
    const callsign = getSimulationSpokenCallsign(ac.callsign);
    const wpSpoken = getSimulationSpokenWaypointName(getAircraftProceedingWaypointName(ac));
    const currentLevel = formatPilotCallLevelPhrase(modeCFl, transitionFl);
    const targetLevel = formatPilotCallLevelPhrase(alvFl, transitionFl);
    if (!callsign || !currentLevel || !targetLevel || !wpSpoken) return '';

    let trend = '';
    if (alvFl > modeCFl) trend = `climbing ${targetLevel}`;
    else if (alvFl < modeCFl) trend = `descending ${targetLevel}`;
    else trend = `maintaining ${targetLevel}`;

    return `${callsign} at ${currentLevel} ${trend} inbound ${wpSpoken}`;
}

function resetSimulationGlobalTtsState() {
    simulationGlobalTtsQueue = [];
    simulationTtsGapUntilMs = 0;
    aiPpDeferStackUntilMs = 0;
    if (simulationGlobalTtsPumpTimerId) {
        clearTimeout(simulationGlobalTtsPumpTimerId);
        simulationGlobalTtsPumpTimerId = null;
    }
    try { window.speechSynthesis.cancel(); } catch (e) {}
    simulationTtsIsSpeaking = false;
}

function shouldDeferSimulationGlobalTtsStack() {
    if (isSimulationHostedMultiplayerSession()) return true;
    if (simulationOperationModeId !== 'DL' || simulationIsMonitorOnly) return true;
    if (!simulationSettings?.ttsEnabled) return true;
    if (!isSimulationTtsSupported()) return true;
    if (isSimulationTtsSpeakingNow()) return true;
    if (isAiPpUserVoiceBusy()) return true;
    if (Date.now() < simulationTtsGapUntilMs) return true;
    if (Date.now() < aiPpDeferStackUntilMs) return true;
    return false;
}

function enqueueSimulationGlobalTts(text, opts = {}) {
    const msg = (text || '').toString().trim();
    if (!msg) return;
    if (isSimulationHostedMultiplayerSession()) return;
    if (simulationOperationModeId !== 'DL' || simulationIsMonitorOnly) return;
    if (!simulationSettings?.ttsEnabled) return;
    if (!isSimulationTtsSupported()) return;
    try { window.speechSynthesis.resume(); } catch (e) {}
    const item = {
        text: msg,
        priority: !!opts.priority,
        source: (opts.source || '').toString(),
        resolveText: typeof opts.resolveText === 'function' ? opts.resolveText : null,
        onComplete: typeof opts.onComplete === 'function' ? opts.onComplete : null
    };
    if (item.priority) simulationGlobalTtsQueue.unshift(item);
    else simulationGlobalTtsQueue.push(item);
    ensureSimulationGlobalTtsPump();
}

function ensureSimulationGlobalTtsPump() {
    if (simulationGlobalTtsPumpTimerId) return;
    pumpSimulationGlobalTtsOnce();
}

function pumpSimulationGlobalTtsOnce() {
    simulationGlobalTtsPumpTimerId = null;
    if (shouldDeferSimulationGlobalTtsStack()) {
        simulationGlobalTtsPumpTimerId = setTimeout(pumpSimulationGlobalTtsOnce, 200);
        return;
    }
    const item = simulationGlobalTtsQueue.shift();
    if (!item) return;
    playSimulationGlobalTtsItem(item);
}

function playSimulationGlobalTtsItem(item) {
    try {
        let text = (item.text || '').toString().trim();
        if (item.resolveText) {
            try {
                const resolved = (item.resolveText() || '').toString().trim();
                if (resolved) text = resolved;
            } catch (e) {}
        }
        if (!text) {
            pumpSimulationGlobalTtsOnce();
            return;
        }
        if (item.source === 'pilotCall') {
            pushSimulationDebugLog('LOG', null, `AI_PP pilot call: ${text}`);
        }
        const u = new SpeechSynthesisUtterance(text);
        u.rate = 1;
        u.pitch = 1;
        u.volume = 1;
        const finish = () => {
            simulationTtsIsSpeaking = false;
            simulationTtsGapUntilMs = Date.now() + SIMULATION_TTS_POST_GAP_MS;
            if (item.source === 'aiPp') aiPpDeferStackUntilMs = simulationTtsGapUntilMs;
            try { item.onComplete?.(); } catch (e) {}
            pumpSimulationGlobalTtsOnce();
        };
        u.onstart = () => { simulationTtsIsSpeaking = true; };
        u.onend = finish;
        u.onerror = finish;
        window.speechSynthesis.speak(u);
    } catch (e) {
        pumpSimulationGlobalTtsOnce();
    }
}

function updateAiPpPilotCallOnFrequencyChecks() {
    // Initial pilot calls are scheduled exercise scripts (scriptKind initialCall), not auto-detected here.
    return;
    if (!aiPpEnabled) return;
    if (isSimulationHostedMultiplayerSession()) return;
    if (simulationOperationModeId !== 'DL' || simulationIsMonitorOnly) return;
    if (!simulationSettings?.ttsEnabled) return;
    if (!isSimulationTtsSupported()) return;
    if (simulationIsPaused) return;

    const list = window.simulationData?.aircraft || [];
    list.forEach(ac => {
        if (!ac || ac.routeCompleted) return;
        if (!Array.isArray(ac._aiPpPilotCallFiredSectorIds)) ac._aiPpPilotCallFiredSectorIds = [];

        const entry = computePilotCallSectorEntryInfo(ac);
        if (!entry?.sector) return;
        const sectorId = String(entry.sector.id || entry.sectorIdx);
        if (ac._aiPpPilotCallFiredSectorIds.includes(sectorId)) return;
        if (entry.minutes > AI_PP_PILOT_CALL_MAX_MINUTES) return;

        const msg = buildAiPpPilotCallOnFrequencyMessage(ac, entry.sector);
        if (!msg) return;
        ac._aiPpPilotCallFiredSectorIds.push(sectorId);
        enqueueSimulationGlobalTts(msg, { source: 'pilotCall', priority: false });
        pushSimulationDebugLog('LOG', ac, `AI_PP pilot call: ${msg}`);
    });
}

function clearSimulationAircraftTtsQueue(ac) {
    try {
        if (!ac) return;
        if (ac._ttsReplyTimerId) {
            clearTimeout(ac._ttsReplyTimerId);
            ac._ttsReplyTimerId = null;
        }
        if (ac._ttsPumpTimerId) {
            clearTimeout(ac._ttsPumpTimerId);
            ac._ttsPumpTimerId = null;
        }
        ac._ttsPendingByType = null;
        ac._ttsPendingTypeOrder = null;
        ac._ttsInputInProgress = null; // Set<string>
        ac._ttsEarliestSpeakAtMs = null;
        ac._ttsLatestSpeakAtMs = null;
    } catch (e) {}
}

function isSimulationLabelHoveredForAircraftId(aircraftId) {
    const id = (aircraftId || '').toString();
    if (!id) return false;
    if (simulationHoveredAircraftLabelId && simulationHoveredAircraftLabelId === id) return true;
    if (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId === id) return true;
    return false;
}

function bumpSimulationAircraftTtsDueTimes(ac) {
    if (!ac) return;
    const now = Date.now();
    ac._ttsEarliestSpeakAtMs = now + 2000;
    ac._ttsLatestSpeakAtMs = now + 5000;
}

function ensureSimulationAircraftTtsPump(ac) {
    try {
        if (!ac) return;
        if (isSimulationHostedMultiplayerSession()) return;
        if (simulationOperationModeId !== 'DL' || simulationIsMonitorOnly) return;
        if (!simulationSettings?.ttsEnabled) return;
        if (!isSimulationTtsSupported()) return;

        if (ac._ttsPumpTimerId) {
            clearTimeout(ac._ttsPumpTimerId);
            ac._ttsPumpTimerId = null;
        }

        const tick = () => {
            try {
                if (isSimulationHostedMultiplayerSession()) {
                    clearSimulationAircraftTtsQueue(ac);
                    return;
                }
                if (simulationOperationModeId !== 'DL' || !simulationSettings?.ttsEnabled || !isSimulationTtsSupported()) {
                    clearSimulationAircraftTtsQueue(ac);
                    return;
                }

                const byType = (ac._ttsPendingByType && typeof ac._ttsPendingByType === 'object') ? ac._ttsPendingByType : {};
                const order = Array.isArray(ac._ttsPendingTypeOrder) ? ac._ttsPendingTypeOrder : [];
                const parts = order.map(k => (byType[k] || '').toString().trim()).filter(Boolean);
                if (!parts.length) {
                    clearSimulationAircraftTtsQueue(ac);
                    return;
                }

                if (isSimulationTtsPlaybackBlocked()) {
                    ac._ttsPumpTimerId = setTimeout(tick, 200);
                    return;
                }

                const inProg = (ac._ttsInputInProgress instanceof Set) ? ac._ttsInputInProgress : new Set();
                ac._ttsInputInProgress = inProg;
                if (inProg.size > 0) {
                    ac._ttsPumpTimerId = setTimeout(tick, 200);
                    return;
                }

                const now = Date.now();
                const earliest = Number(ac._ttsEarliestSpeakAtMs);
                const latest = Number(ac._ttsLatestSpeakAtMs);
                const eOk = isFinite(earliest) ? earliest : (now + 2000);
                const lOk = isFinite(latest) ? latest : (now + 5000);

                if (now < eOk) {
                    ac._ttsPumpTimerId = setTimeout(tick, Math.max(25, Math.min(250, eOk - now)));
                    return;
                }

                const hovered = isSimulationLabelHoveredForAircraftId(ac.id);
                if (hovered && now < lOk) {
                    // If still hovered at 2s mark, wait up to total 5s.
                    ac._ttsPumpTimerId = setTimeout(tick, Math.max(50, Math.min(250, lOk - now)));
                    return;
                }

                // Speak now (2s + unhover) OR at 5s max (unless blocked by input-in-progress, handled above).
                const spokenCs = getSimulationSpokenCallsign(ac.callsign);
                if (!spokenCs) { clearSimulationAircraftTtsQueue(ac); return; }
                const full = `${parts.join(', ')}, ${spokenCs}`.trim();
                clearSimulationAircraftTtsQueue(ac);
                if (full) enqueueSimulationGlobalTts(full, { source: 'readback' });
            } catch (e) {
                clearSimulationAircraftTtsQueue(ac);
            }
        };

        ac._ttsPumpTimerId = setTimeout(tick, 50);
    } catch (e) {}
}

function markSimulationAircraftTtsInputStart(ac, type) {
    try {
        if (!ac) return;
        if (isSimulationHostedMultiplayerSession()) return;
        if (simulationOperationModeId !== 'DL' || simulationIsMonitorOnly) return;
        if (!simulationSettings?.ttsEnabled) return;
        if (!isSimulationTtsSupported()) return;
        const t = (type || '').toString().trim().toUpperCase();
        if (!t) return;
        if (!(ac._ttsInputInProgress instanceof Set)) ac._ttsInputInProgress = new Set();
        ac._ttsInputInProgress.add(t);
        bumpSimulationAircraftTtsDueTimes(ac);
        ensureSimulationAircraftTtsPump(ac);
    } catch (e) {}
}

function markSimulationAircraftTtsInputEnd(ac, type) {
    try {
        if (!ac) return;
        const t = (type || '').toString().trim().toUpperCase();
        if (ac._ttsInputInProgress instanceof Set && t) ac._ttsInputInProgress.delete(t);
        bumpSimulationAircraftTtsDueTimes(ac);
        ensureSimulationAircraftTtsPump(ac);
    } catch (e) {}
}

function queueSimulationAircraftTtsReply(ac, type, message) {
    try {
        if (isSimulationHostedMultiplayerSession()) return;
        if (simulationOperationModeId !== 'DL' || simulationIsMonitorOnly) return;
        if (!simulationSettings?.ttsEnabled) return;
        if (!isSimulationTtsSupported()) return;
        if (!ac) return;

        const t = (type || '').toString().trim().toUpperCase();
        const msg = (message || '').toString().trim();
        if (!t) return;
        if (!msg) return; // don't queue empty messages

        // Some browsers require a "resume" call from a user gesture for delayed speech to work reliably.
        try { window.speechSynthesis.resume(); } catch (e) {}

        if (!ac._ttsPendingByType || typeof ac._ttsPendingByType !== 'object') ac._ttsPendingByType = {};
        if (!Array.isArray(ac._ttsPendingTypeOrder)) ac._ttsPendingTypeOrder = [];

        if (!Object.prototype.hasOwnProperty.call(ac._ttsPendingByType, t)) {
            ac._ttsPendingTypeOrder.push(t);
        }
        // Overwrite message for same type, so the latest command wins.
        ac._ttsPendingByType[t] = msg;

        bumpSimulationAircraftTtsDueTimes(ac);
        ensureSimulationAircraftTtsPump(ac);
    } catch (e) {}
}

function updateSimulationTtsUi() {
    const btn = document.getElementById('simulationTtsToggleBtn');
    const valueEl = document.getElementById('simulationTtsValue');
    if (!btn || !valueEl) return;

    if (isSimulationHostedMultiplayerSession()) {
        stopHostedSessionTts();
        btn.style.display = 'none';
        btn.disabled = true;
        btn.setAttribute('aria-hidden', 'true');
        valueEl.textContent = 'OFF';
        btn.classList.remove('sim-tts-on');
        btn.classList.add('sim-tts-disabled');
        btn.title = 'Text-to-Speech is off in hosted sessions';
        updateAiPpUi();
        return;
    }
    btn.disabled = false;
    btn.removeAttribute('aria-hidden');

    const inDl = (simulationOperationModeId === 'DL') && !simulationIsMonitorOnly;
    btn.style.display = inDl ? '' : 'none';
    if (!inDl) {
        updateAiPpUi();
        return;
    }

    const supported = isSimulationTtsSupported();
    const enabled = !!simulationSettings?.ttsEnabled;
    valueEl.textContent = enabled ? 'ON' : 'OFF';
    btn.classList.toggle('sim-tts-disabled', !supported);
    btn.classList.toggle('sim-tts-on', supported && enabled);
    btn.title = supported ? 'Text-to-Speech (DL mode)' : 'Text-to-Speech not supported in this browser';
    updateAiPpUi();
}

