    const tsl = (document.getElementById('simulationTrajectoryShowSelect')?.value || '').toString().toLowerCase();
    simulationSettings.trajectoryShowLabels = (tsl === 'estimates_only' || tsl === 'estimates_and_fl') ? tsl : SIM_SETTINGS_DEFAULTS.trajectoryShowLabels;

    const zs = document.getElementById('simulationZoomSensitivity');
    const z = parseInt(zs?.value, 10);
    simulationSettings.zoomSensitivity = (Number.isFinite(z) && z >= 1 && z <= 10) ? z : SIM_SETTINGS_DEFAULTS.zoomSensitivity;

    const lmb = document.getElementById('simulationLabelMoveSelect');
    const mv = (lmb?.value || '').toString().toLowerCase();
    simulationSettings.labelMoveButton = (mv === 'middle' || mv === 'right' || mv === 'left') ? mv : SIM_SETTINGS_DEFAULTS.labelMoveButton;

    const hsi = document.getElementById('simulationHeadingSelectIncrement');
    const inc = parseInt(hsi?.value, 10);
    simulationSettings.headingSelectIncrement = (inc === 1 || inc === 5 || inc === 10) ? inc : SIM_SETTINGS_DEFAULTS.headingSelectIncrement;

    const md = document.getElementById('simulationMinLocApproachDistNm');
    const m = parseInt(md?.value, 10);
    simulationSettings.minLocApproachDistNm = (Number.isFinite(m) && m >= 1 && m <= 15) ? m : SIM_SETTINGS_DEFAULTS.minLocApproachDistNm;

    const plm = document.getElementById('simulationProbingLevelSelect');
    const pm = (plm?.value || '').toString().toLowerCase();
    simulationSettings.probingLevelMode = (pm === 'on' || pm === 'same_route' || pm === 'same_crossing_routes' || pm === 'off') ? pm : SIM_SETTINGS_DEFAULTS.probingLevelMode;

    const ph = document.getElementById('simulationProbingHighlightColor');
    const pd = document.getElementById('simulationProbingDimColor');
    const isHex6 = (s) => /^#[0-9a-fA-F]{6}$/.test((s || '').toString().trim());
    simulationSettings.probingHighlightColor = isHex6(ph?.value) ? ph.value : SIM_SETTINGS_DEFAULTS.probingHighlightColor;
    simulationSettings.probingDimColor = isHex6(pd?.value) ? pd.value : SIM_SETTINGS_DEFAULTS.probingDimColor;

    const srCol = document.getElementById('simulationSelectedAircraftRingColor');
