function renderSimulationRoutesCheckboxes() {
    const list = document.getElementById('simRoutesCheckboxList');
    if (!list) return;
    list.innerHTML = '';

    const routes = window.simulationData?.routes || [];
    if (!routes.length) {
        list.innerHTML = '<div style="color: rgba(245, 247, 250, 0.7); font-size: 0.85rem;">No routes in this sector.</div>';
        return;
    }

    const selected = new Set(simulationMap.routes.selectedKeys || []);

    routes.forEach((route, idx) => {
        const key = getRouteKey(route, idx);
        const label = (route && route.name) ? route.name : `Route ${idx + 1}`;

        const row = document.createElement('label');
        row.className = 'sim-route-checkbox';

        const cb = document.createElement('input');
        cb.type = 'checkbox';
        cb.checked = simulationMap.routes.selectedKeys ? selected.has(key) : true;
        cb.dataset.routeKey = key;

        cb.addEventListener('change', () => {
            // if we're in "all routes" mode, switch to selective with all checked first
            if (!simulationMap.routes.selectedKeys) {
                simulationMap.routes.selectedKeys = routes.map((r, i) => getRouteKey(r, i));
            }
            const s = new Set(simulationMap.routes.selectedKeys);
            if (cb.checked) s.add(key);
            else s.delete(key);
            simulationMap.routes.selectedKeys = Array.from(s);
            saveSimulationMap();
            updateSimulationMapSummary();
            drawSimulationCanvas();
        });

        const text = document.createElement('span');
        text.textContent = label;

        row.appendChild(cb);
        row.appendChild(text);
        list.appendChild(row);
    });
}

function renderSimulationAirportsCheckboxes() {
    const list = document.getElementById('simAirportsCheckboxList');
    if (!list) return;
    list.innerHTML = '';

    const airports = getSimulationSectorAirports();
    if (!airports.length) {
        list.innerHTML = '<div style="color: rgba(245, 247, 250, 0.7); font-size: 0.85rem;">No airports in this sector.</div>';
        return;
    }
    const selected = new Set(simulationMap.airports.selectedIcaos || []);

    airports.forEach(ap => {
        const icao = normalizeAirportIcao(ap?.icao);
        if (!icao) return;
        const row = document.createElement('label');
        row.className = 'sim-route-checkbox';
        const cb = document.createElement('input');
        cb.type = 'checkbox';
        cb.checked = simulationMap.airports.selectedIcaos ? selected.has(icao) : true;
        cb.dataset.icao = icao;
        cb.addEventListener('change', () => {
            if (!simulationMap.airports.selectedIcaos) {
                simulationMap.airports.selectedIcaos = airports.map(a => normalizeAirportIcao(a?.icao)).filter(Boolean);
            }
            const s = new Set(simulationMap.airports.selectedIcaos);
            if (cb.checked) s.add(icao);
            else s.delete(icao);
            simulationMap.airports.selectedIcaos = Array.from(s);
            saveSimulationMap();
            updateSimulationAirportsSummary();
            drawSimulationCanvas();
        });
        const text = document.createElement('span');
        text.textContent = icao;
        row.appendChild(cb);
        row.appendChild(text);
        list.appendChild(row);
    });
}

function renderSimulationRunwaysCheckboxes() {
    const list = document.getElementById('simRunwaysCheckboxList');
    if (!list) return;
    list.innerHTML = '';

    const airports = getSimulationSectorAirports();
    const rows = [];
    airports.forEach(ap => {
        const icao = normalizeAirportIcao(ap?.icao);
        (Array.isArray(ap?.runways) ? ap.runways : []).forEach(rw => rows.push({ icao, rw }));
    });

    if (!rows.length) {
        list.innerHTML = '<div style="color: rgba(245, 247, 250, 0.7); font-size: 0.85rem;">No runways in this sector.</div>';
        return;
    }

    const selected = new Set(simulationMap.runways.selectedKeys || []);
    rows.forEach(({ icao, rw }) => {
        const key = getSimulationRunwayKey(icao, rw);
        const a = normalizeRunwayDesignator(rw?.endA?.name);
        const b = normalizeRunwayDesignator(rw?.endB?.name);
        const label = `${icao} ${a}/${b}`;

        const row = document.createElement('label');
        row.className = 'sim-route-checkbox';
        const cb = document.createElement('input');
        cb.type = 'checkbox';
        cb.checked = simulationMap.runways.selectedKeys ? selected.has(key) : true;
        cb.dataset.runwayKey = key;
        cb.addEventListener('change', () => {
            if (!simulationMap.runways.selectedKeys) {
                simulationMap.runways.selectedKeys = rows.map(r => getSimulationRunwayKey(r.icao, r.rw));
            }
            const s = new Set(simulationMap.runways.selectedKeys);
            if (cb.checked) s.add(key);
            else s.delete(key);
            simulationMap.runways.selectedKeys = Array.from(s);
            saveSimulationMap();
            updateSimulationRunwaysSummary();
            drawSimulationCanvas();
        });
        const text = document.createElement('span');
        text.textContent = label;
        row.appendChild(cb);
        row.appendChild(text);
        list.appendChild(row);
    });
}

