function renderSimulationHoldingsCheckboxes() {
    const list = document.getElementById('simHoldingsCheckboxList');
    if (!list) return;
    list.innerHTML = '';
    if (!simulationMap.holdings) simulationMap.holdings = JSON.parse(JSON.stringify(SIM_MAP_DEFAULTS.holdings));

    const holdings = getSimulationSectorHoldings();
    const wps = Array.isArray(window.simulationData?.waypoints) ? window.simulationData.waypoints : [];
    if (!holdings.length) {
        list.innerHTML = '<div style="color: rgba(245, 247, 250, 0.7); font-size: 0.85rem;">No holdings in this airspace.</div>';
        return;
    }

    const selected = new Set(simulationMap.holdings?.selectedIds || []);

    holdings.forEach(h => {
        const id = String(h.id);
        const wp = wps.find(w => w && String(w.id) === String(h.waypointId));
        const nm = (wp && wp.name) ? String(wp.name).trim() : `wp ${String(h.waypointId).slice(0, 8)}`;
        const trk = clampSectorHoldingInboundTrackDeg(h.inboundTrackDeg);
        const trkStr = Number.isFinite(trk) ? String(trk).padStart(3, '0') : '—';
        const turn = normalizeSectorHoldingTurnDirection(h.turnDirection);
        const label = `${nm} · ${trkStr}° · ${turn}`;

        const row = document.createElement('label');
        row.className = 'sim-route-checkbox';
        const cb = document.createElement('input');
        cb.type = 'checkbox';
        cb.checked = simulationMap.holdings?.selectedIds ? selected.has(id) : true;
        cb.dataset.holdingId = id;
        cb.addEventListener('change', () => {
            if (!simulationMap.holdings) simulationMap.holdings = JSON.parse(JSON.stringify(SIM_MAP_DEFAULTS.holdings));
            if (!simulationMap.holdings.selectedIds) {
                simulationMap.holdings.selectedIds = holdings.map(x => String(x.id));
            }
            const s = new Set(simulationMap.holdings.selectedIds);
            if (cb.checked) s.add(id);
            else s.delete(id);
            simulationMap.holdings.selectedIds = Array.from(s);
            saveSimulationMap();
            updateSimulationHoldingsSummary();
            drawSimulationCanvas();
        });
        const text = document.createElement('span');
        text.textContent = label;
        row.appendChild(cb);
        row.appendChild(text);
        list.appendChild(row);
    });
}

function syncSimulationMapControlsFromState() {
    if (!simulationMap.areas) simulationMap.areas = JSON.parse(JSON.stringify(SIM_MAP_DEFAULTS.areas));
    if (!simulationMap.holdings) simulationMap.holdings = JSON.parse(JSON.stringify(SIM_MAP_DEFAULTS.holdings));
    if (!simulationMap.backgrounds) simulationMap.backgrounds = JSON.parse(JSON.stringify(SIM_MAP_DEFAULTS.backgrounds));
    const wpNamesEnabled = document.getElementById('simWpNamesEnabled');
    const wpNameSize = document.getElementById('simWpNameSize');
    const wpTriEnabled = document.getElementById('simWpTriangleEnabled');
    const wpTriSize = document.getElementById('simWpTriangleSize');
    const routesEnabled = document.getElementById('simRoutesEnabled');
    const boundariesEnabled = document.getElementById('simBoundariesEnabled');
    const latLonLinesEnabled = document.getElementById('simLatLonLinesEnabled');
    const centerWpEnabled = document.getElementById('simCenterWpEnabled');
    const airportsEnabled = document.getElementById('simAirportsEnabled');
    const runwaysEnabled = document.getElementById('simRunwaysEnabled');
    const runwayNamesEnabled = document.getElementById('simRunwayNamesEnabled');
    const runwayExtendedCenterlineEnabled = document.getElementById('simRunwayExtendedCenterlineEnabled');
    const areasEnabled = document.getElementById('simAreasEnabled');
    const holdingsEnabled = document.getElementById('simHoldingsEnabled');
    const backgroundsEnabled = document.getElementById('simBackgroundsEnabled');
    const labelSize = document.getElementById('simLabelSize');

    if (wpNamesEnabled) wpNamesEnabled.checked = !!simulationMap.waypointNames.enabled;
    if (wpNameSize) wpNameSize.value = String(simulationMap.waypointNames.size);
    const wpNameSizeValue = document.getElementById('simWpNameSizeValue');
    if (wpNameSizeValue) wpNameSizeValue.textContent = String(simulationMap.waypointNames.size);

    if (wpTriEnabled) wpTriEnabled.checked = !!simulationMap.waypointTriangles.enabled;
    if (wpTriSize) wpTriSize.value = String(simulationMap.waypointTriangles.size);
    const wpTriSizeValue = document.getElementById('simWpTriangleSizeValue');
    if (wpTriSizeValue) wpTriSizeValue.textContent = String(simulationMap.waypointTriangles.size);

    if (routesEnabled) routesEnabled.checked = !!simulationMap.routes.enabled;
    if (boundariesEnabled) boundariesEnabled.checked = !!simulationMap.boundaries.enabled;
    if (latLonLinesEnabled) latLonLinesEnabled.checked = !!simulationMap.latLonLines.enabled;
    if (centerWpEnabled) centerWpEnabled.checked = !!simulationMap.centerWaypoint.enabled;
    if (airportsEnabled) airportsEnabled.checked = !!simulationMap.airports.enabled;
    if (runwaysEnabled) runwaysEnabled.checked = !!simulationMap.runways.enabled;
    if (runwayNamesEnabled) runwayNamesEnabled.checked = simulationMap.runways.namesEnabled !== false;
    if (runwayExtendedCenterlineEnabled) {
        runwayExtendedCenterlineEnabled.checked = !!ensureSimulationMapRunwayExtendedCenterline().enabled;
    }
    if (areasEnabled) areasEnabled.checked = !!simulationMap.areas.enabled;
    if (holdingsEnabled) holdingsEnabled.checked = !!simulationMap.holdings.enabled;
    if (backgroundsEnabled) backgroundsEnabled.checked = !!simulationMap.backgrounds.enabled;

    if (labelSize) labelSize.value = String(simulationMap.labelSize ?? SIM_MAP_DEFAULTS.labelSize);
    const labelSizeValue = document.getElementById('simLabelSizeValue');
    if (labelSizeValue) labelSizeValue.textContent = String(simulationMap.labelSize ?? SIM_MAP_DEFAULTS.labelSize);

    updateSimulationMapSummary();
    updateSimulationAirportsSummary();
    updateSimulationRunwaysSummary();
    updateSimulationAreasSummary();
    updateSimulationHoldingsSummary();
    updateSimulationBackgroundsSummary();
    renderSimulationRoutesCheckboxes();
    renderSimulationAirportsCheckboxes();
    renderSimulationRunwaysCheckboxes();
    renderSimulationAreasCheckboxes();
    renderSimulationHoldingsCheckboxes();
    renderSimulationBackgroundsCheckboxes();
}

function applySimulationMapFromControls() {
    const wpNamesEnabled = document.getElementById('simWpNamesEnabled');
    const wpNameSize = document.getElementById('simWpNameSize');
    const wpTriEnabled = document.getElementById('simWpTriangleEnabled');
    const wpTriSize = document.getElementById('simWpTriangleSize');
    const routesEnabled = document.getElementById('simRoutesEnabled');
    const boundariesEnabled = document.getElementById('simBoundariesEnabled');
    const latLonLinesEnabled = document.getElementById('simLatLonLinesEnabled');
    const centerWpEnabled = document.getElementById('simCenterWpEnabled');
    const airportsEnabled = document.getElementById('simAirportsEnabled');
    const runwaysEnabled = document.getElementById('simRunwaysEnabled');
    const runwayNamesEnabled = document.getElementById('simRunwayNamesEnabled');
    const runwayExtendedCenterlineEnabled = document.getElementById('simRunwayExtendedCenterlineEnabled');
    const areasEnabled = document.getElementById('simAreasEnabled');
    const holdingsEnabled = document.getElementById('simHoldingsEnabled');
    const backgroundsEnabled = document.getElementById('simBackgroundsEnabled');
    const labelSize = document.getElementById('simLabelSize');

    if (wpNamesEnabled) simulationMap.waypointNames.enabled = !!wpNamesEnabled.checked;
    if (wpNameSize) simulationMap.waypointNames.size = Math.min(48, Math.max(6, parseInt(wpNameSize.value, 10) || SIM_MAP_DEFAULTS.waypointNames.size));
    if (wpTriEnabled) simulationMap.waypointTriangles.enabled = !!wpTriEnabled.checked;
    if (wpTriSize) simulationMap.waypointTriangles.size = Math.min(60, Math.max(2, parseInt(wpTriSize.value, 10) || SIM_MAP_DEFAULTS.waypointTriangles.size));
    if (routesEnabled) simulationMap.routes.enabled = !!routesEnabled.checked;
    if (boundariesEnabled) simulationMap.boundaries.enabled = !!boundariesEnabled.checked;
    if (latLonLinesEnabled) simulationMap.latLonLines.enabled = !!latLonLinesEnabled.checked;
    if (centerWpEnabled) simulationMap.centerWaypoint.enabled = !!centerWpEnabled.checked;
    if (!simulationMap.areas) simulationMap.areas = JSON.parse(JSON.stringify(SIM_MAP_DEFAULTS.areas));
    if (!simulationMap.holdings) simulationMap.holdings = JSON.parse(JSON.stringify(SIM_MAP_DEFAULTS.holdings));
    if (!simulationMap.backgrounds) simulationMap.backgrounds = JSON.parse(JSON.stringify(SIM_MAP_DEFAULTS.backgrounds));
    if (airportsEnabled) simulationMap.airports.enabled = !!airportsEnabled.checked;
    if (runwaysEnabled) simulationMap.runways.enabled = !!runwaysEnabled.checked;
    if (runwayNamesEnabled) simulationMap.runways.namesEnabled = !!runwayNamesEnabled.checked;
    if (runwayExtendedCenterlineEnabled) {
        ensureSimulationMapRunwayExtendedCenterline().enabled = !!runwayExtendedCenterlineEnabled.checked;
    }
    if (areasEnabled) simulationMap.areas.enabled = !!areasEnabled.checked;
    if (holdingsEnabled) simulationMap.holdings.enabled = !!holdingsEnabled.checked;
    if (backgroundsEnabled) simulationMap.backgrounds.enabled = !!backgroundsEnabled.checked;
    if (labelSize) simulationMap.labelSize = Math.min(24, Math.max(8, parseInt(labelSize.value, 10) || SIM_MAP_DEFAULTS.labelSize));

    const wpNameSizeValue = document.getElementById('simWpNameSizeValue');
    if (wpNameSizeValue) wpNameSizeValue.textContent = String(simulationMap.waypointNames.size);
    const wpTriSizeValue = document.getElementById('simWpTriangleSizeValue');
    if (wpTriSizeValue) wpTriSizeValue.textContent = String(simulationMap.waypointTriangles.size);
    const labelSizeValue = document.getElementById('simLabelSizeValue');
    if (labelSizeValue) labelSizeValue.textContent = String(simulationMap.labelSize);

    saveSimulationMap();
    updateSimulationMapSummary();
    updateSimulationAirportsSummary();
    updateSimulationRunwaysSummary();
    updateSimulationAreasSummary();
    updateSimulationHoldingsSummary();
    updateSimulationBackgroundsSummary();

    if (document.getElementById('simulationModal')?.classList.contains('active')) {
        drawSimulationCanvas();
    }
}

function hexToRgba(hex, alpha) {
    const a = clamp01(alpha);
    const h = (hex || '').replace('#', '').trim();
    if (h.length !== 6) return `rgba(0,0,0,${a})`;
    const r = parseInt(h.slice(0, 2), 16);
    const g = parseInt(h.slice(2, 4), 16);
    const b = parseInt(h.slice(4, 6), 16);
    if (![r, g, b].every(v => Number.isFinite(v))) return `rgba(0,0,0,${a})`;
    return `rgba(${r},${g},${b},${a})`;
}

function loadSimulationStyle() {
    try {
        const raw = localStorage.getItem(SIM_STYLE_STORAGE_KEY);
        if (!raw) return;
        const parsed = JSON.parse(raw);
        if (!parsed || typeof parsed !== 'object') return;
        simulationStyle = {
            waypoints: {
                color: parsed.waypoints?.color || SIM_STYLE_DEFAULTS.waypoints.color,
                alpha: clamp01((parsed.waypoints?.alpha ?? SIM_STYLE_DEFAULTS.waypoints.alpha))
            },
            routes: {
                color: parsed.routes?.color || SIM_STYLE_DEFAULTS.routes.color,
                alpha: clamp01((parsed.routes?.alpha ?? SIM_STYLE_DEFAULTS.routes.alpha)),
                width: Math.min(10, Math.max(1, parseInt(parsed.routes?.width ?? SIM_STYLE_DEFAULTS.routes.width, 10) || SIM_STYLE_DEFAULTS.routes.width))
            },
            boundaries: {
                color: parsed.boundaries?.color || SIM_STYLE_DEFAULTS.boundaries.color,
                alpha: clamp01((parsed.boundaries?.alpha ?? SIM_STYLE_DEFAULTS.boundaries.alpha)),
                width: Math.min(10, Math.max(1, parseInt(parsed.boundaries?.width ?? SIM_STYLE_DEFAULTS.boundaries.width, 10) || SIM_STYLE_DEFAULTS.boundaries.width))
            },
            background: {
                color: parsed.background?.color || SIM_STYLE_DEFAULTS.background.color
            },
            labels: {
                textColor: parsed.labels?.textColor || SIM_STYLE_DEFAULTS.labels.textColor,
                backgroundColor: parsed.labels?.backgroundColor || SIM_STYLE_DEFAULTS.labels.backgroundColor
            },
            modeS: {
                color: parsed.modeS?.color || SIM_STYLE_DEFAULTS.modeS.color
            },
            aircraft: {
                targetColor: parsed.aircraft?.targetColor || SIM_STYLE_DEFAULTS.aircraft.targetColor
            },
            trajectory: {
                color: parsed.trajectory?.color || SIM_STYLE_DEFAULTS.trajectory.color
            }
        };
    } catch (e) {
        // ignore
    }
}

function saveSimulationStyle() {
    try {
        localStorage.setItem(SIM_STYLE_STORAGE_KEY, JSON.stringify(simulationStyle));
    } catch (e) {
        // ignore
    }
}

function applySimulationStyleFromControls() {
    const wpColor = document.getElementById('simWaypointColor');
    const wpAlpha = document.getElementById('simWaypointAlpha');
    const rtColor = document.getElementById('simRouteColor');
    const rtAlpha = document.getElementById('simRouteAlpha');
    const rtWidth = document.getElementById('simRouteWidth');
    const bdColor = document.getElementById('simBoundaryColor');
    const bdAlpha = document.getElementById('simBoundaryAlpha');
    const bdWidth = document.getElementById('simBoundaryWidth');
    const bgColor = document.getElementById('simBackgroundColor');
    const lblText = document.getElementById('simLabelTextColor');
    const lblBg = document.getElementById('simLabelBackgroundColor');
    const modeSColor = document.getElementById('simModeSColor');
    const acTarget = document.getElementById('simAircraftTargetColor');
    const trajColor = document.getElementById('simTrajectoryColor');

    if (wpColor) simulationStyle.waypoints.color = wpColor.value || SIM_STYLE_DEFAULTS.waypoints.color;
    if (wpAlpha) simulationStyle.waypoints.alpha = clamp01((parseInt(wpAlpha.value, 10) || 0) / 100);

    if (rtColor) simulationStyle.routes.color = rtColor.value || SIM_STYLE_DEFAULTS.routes.color;
    if (rtAlpha) simulationStyle.routes.alpha = clamp01((parseInt(rtAlpha.value, 10) || 0) / 100);
    if (rtWidth) simulationStyle.routes.width = Math.min(10, Math.max(1, parseInt(rtWidth.value, 10) || SIM_STYLE_DEFAULTS.routes.width));

    if (bdColor) simulationStyle.boundaries.color = bdColor.value || SIM_STYLE_DEFAULTS.boundaries.color;
    if (bdAlpha) simulationStyle.boundaries.alpha = clamp01((parseInt(bdAlpha.value, 10) || 0) / 100);
    if (bdWidth) simulationStyle.boundaries.width = Math.min(10, Math.max(1, parseInt(bdWidth.value, 10) || SIM_STYLE_DEFAULTS.boundaries.width));
    if (bgColor) simulationStyle.background.color = bgColor.value || SIM_STYLE_DEFAULTS.background.color;
    if (lblText) simulationStyle.labels.textColor = lblText.value || SIM_STYLE_DEFAULTS.labels.textColor;
    if (lblBg) simulationStyle.labels.backgroundColor = lblBg.value || SIM_STYLE_DEFAULTS.labels.backgroundColor;
    if (modeSColor) simulationStyle.modeS.color = modeSColor.value || SIM_STYLE_DEFAULTS.modeS.color;
    if (acTarget) simulationStyle.aircraft.targetColor = acTarget.value || SIM_STYLE_DEFAULTS.aircraft.targetColor;
    if (trajColor) simulationStyle.trajectory.color = trajColor.value || SIM_STYLE_DEFAULTS.trajectory.color;

    // update value labels
    const setText = (id, text) => { const el = document.getElementById(id); if (el) el.textContent = text; };
    if (wpAlpha) setText('simWaypointAlphaValue', `${parseInt(wpAlpha.value, 10) || 0}%`);
    if (rtAlpha) setText('simRouteAlphaValue', `${parseInt(rtAlpha.value, 10) || 0}%`);
    if (bdAlpha) setText('simBoundaryAlphaValue', `${parseInt(bdAlpha.value, 10) || 0}%`);
    if (rtWidth) setText('simRouteWidthValue', `${parseInt(rtWidth.value, 10) || 1}`);
    if (bdWidth) setText('simBoundaryWidthValue', `${parseInt(bdWidth.value, 10) || 1}`);

    saveSimulationStyle();

    // redraw if simulation visible
    if (document.getElementById('simulationModal')?.classList.contains('active')) {
        drawSimulationCanvas();
    }
}

function syncSimulationStyleControlsFromState() {
    const wpColor = document.getElementById('simWaypointColor');
    const wpAlpha = document.getElementById('simWaypointAlpha');
    const rtColor = document.getElementById('simRouteColor');
    const rtAlpha = document.getElementById('simRouteAlpha');
    const rtWidth = document.getElementById('simRouteWidth');
    const bdColor = document.getElementById('simBoundaryColor');
    const bdAlpha = document.getElementById('simBoundaryAlpha');
    const bdWidth = document.getElementById('simBoundaryWidth');
    const bgColor = document.getElementById('simBackgroundColor');
    const lblText = document.getElementById('simLabelTextColor');
    const lblBg = document.getElementById('simLabelBackgroundColor');
    const modeSColor = document.getElementById('simModeSColor');
    const acTarget = document.getElementById('simAircraftTargetColor');
    const trajColor = document.getElementById('simTrajectoryColor');

    if (wpColor) wpColor.value = simulationStyle.waypoints.color;
    if (wpAlpha) wpAlpha.value = String(Math.round(clamp01(simulationStyle.waypoints.alpha) * 100));
    if (rtColor) rtColor.value = simulationStyle.routes.color;
    if (rtAlpha) rtAlpha.value = String(Math.round(clamp01(simulationStyle.routes.alpha) * 100));
    if (rtWidth) rtWidth.value = String(simulationStyle.routes.width);
    if (bdColor) bdColor.value = simulationStyle.boundaries.color;
    if (bdAlpha) bdAlpha.value = String(Math.round(clamp01(simulationStyle.boundaries.alpha) * 100));
    if (bdWidth) bdWidth.value = String(simulationStyle.boundaries.width);
    if (bgColor) bgColor.value = simulationStyle.background?.color || SIM_STYLE_DEFAULTS.background.color;
    if (lblText) lblText.value = simulationStyle.labels?.textColor || SIM_STYLE_DEFAULTS.labels.textColor;
    if (lblBg) lblBg.value = simulationStyle.labels?.backgroundColor || SIM_STYLE_DEFAULTS.labels.backgroundColor;
    if (modeSColor) modeSColor.value = simulationStyle.modeS?.color || SIM_STYLE_DEFAULTS.modeS.color;
    if (acTarget) acTarget.value = simulationStyle.aircraft?.targetColor || SIM_STYLE_DEFAULTS.aircraft.targetColor;
    if (trajColor) trajColor.value = simulationStyle.trajectory?.color || SIM_STYLE_DEFAULTS.trajectory.color;

    applySimulationStyleFromControls();
}

// DMS conversion functions
function DMSToDecimal(degrees, minutes, seconds, direction) {
    let decimal = degrees + (minutes / 60) + (seconds / 3600);
    if (direction === 'S' || direction === 'W') {
        decimal = -decimal;
    }
    return decimal;
}

function decimalToDMS(decimal, isLatitude) {
    const absDecimal = Math.abs(decimal);
    const degrees = Math.floor(absDecimal);
    const minutesFloat = (absDecimal - degrees) * 60;
    const minutes = Math.floor(minutesFloat);
    const seconds = Math.round((minutesFloat - minutes) * 60);
    
    let direction;
    if (isLatitude) {
        direction = decimal >= 0 ? 'N' : 'S';
    } else {
        direction = decimal >= 0 ? 'E' : 'W';
    }
    
    return {
        degrees: degrees,
        minutes: minutes,
        seconds: seconds,
        direction: direction
    };
}

function formatDMS(dms, isLatitude) {
    const degPad = isLatitude ? 2 : 3;
    const degStr = String(dms.degrees).padStart(degPad, '0');
    const minStr = String(dms.minutes).padStart(2, '0');
    const secStr = String(dms.seconds).padStart(2, '0');
    return `${degStr}${minStr}${secStr}${dms.direction}`;
}

// Parse bulk route format: <route name> <waypoint name> <waypoint name> ...
function parseBulkRouteLine(line) {
    line = line.trim();
    if (!line) return null;
    
    // Split by whitespace
    const parts = line.split(/\s+/).filter(p => p.trim());
    
    // Need at least: route name + 2 waypoints
    if (parts.length < 3) {
        return { error: `Route must have at least 2 waypoints: ${line}` };
    }
    
    // Get route name (first part)
    const routeName = parts[0].trim();
    if (!routeName) {
        return { error: `Missing route name: ${line}` };
    }
    
    // Get waypoint names (remaining parts)
    const waypointNames = parts.slice(1).map(name => name.trim()).filter(name => name);
    
    if (waypointNames.length < 2) {
        return { error: `Route must have at least 2 waypoints: ${line}` };
    }
    
    return {
        name: routeName,
        waypointNames: waypointNames
    };
}

// Parse bulk waypoint format: <name> <name> <DDMMSSN> <DDDMMSSE> D P E
function parseBulkWaypointLine(line) {
    line = line.trim();
    if (!line) return null;
    
    // Split by whitespace
    const parts = line.split(/\s+/);
    
    // Need at least: name name lat lon (and possibly D P E)
    if (parts.length < 4) {
        return { error: `Invalid format: ${line}` };
    }
    
    // Get waypoint name (first occurrence, ignore duplicate)
    const name = parts[0].trim();
    if (!name) {
        return { error: `Missing waypoint name: ${line}` };
    }
    
    // Get latitude (format: DDMMSSN or DDMMSSS)
    const latStr = parts[2].trim().toUpperCase();
    if (!latStr || latStr.length < 7) {
        return { error: `Invalid latitude format: ${line}` };
    }
    
    // Parse latitude: DDMMSSN
    const latDegrees = parseInt(latStr.substring(0, 2));
    const latMinutes = parseInt(latStr.substring(2, 4));
    const latSeconds = parseInt(latStr.substring(4, 6));
    const latDirection = latStr.substring(6, 7); // N or S
    
    if (isNaN(latDegrees) || latDegrees < 0 || latDegrees > 89) {
        return { error: `Invalid latitude degrees (0-89): ${line}` };
    }
    if (isNaN(latMinutes) || latMinutes < 0 || latMinutes > 59) {
        return { error: `Invalid latitude minutes (0-59): ${line}` };
    }
    if (isNaN(latSeconds) || latSeconds < 0 || latSeconds > 59) {
        return { error: `Invalid latitude seconds (0-59): ${line}` };
    }
    if (latDirection !== 'N' && latDirection !== 'S') {
        return { error: `Invalid latitude direction (N/S): ${line}` };
    }
    
    // Get longitude (format: DDDMMSSE or DDDMMSSW)
    const lonStr = parts[3].trim().toUpperCase();
    if (!lonStr || lonStr.length < 8) {
        return { error: `Invalid longitude format: ${line}` };
    }
    
    // Parse longitude: DDDMMSSE
    const lonDegrees = parseInt(lonStr.substring(0, 3));
    const lonMinutes = parseInt(lonStr.substring(3, 5));
    const lonSeconds = parseInt(lonStr.substring(5, 7));
    const lonDirection = lonStr.substring(7, 8); // E or W
    
    if (isNaN(lonDegrees) || lonDegrees < 0 || lonDegrees > 179) {
        return { error: `Invalid longitude degrees (0-179): ${line}` };
    }
    if (isNaN(lonMinutes) || lonMinutes < 0 || lonMinutes > 59) {
        return { error: `Invalid longitude minutes (0-59): ${line}` };
    }
    if (isNaN(lonSeconds) || lonSeconds < 0 || lonSeconds > 59) {
        return { error: `Invalid longitude seconds (0-59): ${line}` };
    }
    if (lonDirection !== 'E' && lonDirection !== 'W') {
        return { error: `Invalid longitude direction (E/W): ${line}` };
    }
    
    // Convert to decimal degrees
    const latitude = DMSToDecimal(latDegrees, latMinutes, latSeconds, latDirection);
    const longitude = DMSToDecimal(lonDegrees, lonMinutes, lonSeconds, lonDirection);
    
    return {
        name: name,
        latitude: latitude,
        longitude: longitude
    };
}

const NAVAID_TYPES = ['DME', 'NDB', 'TACAN', 'VOR', 'VOR/DME', 'VORTAC', 'OTHER'];

function normalizeNavaidType(type) {
    const t = (type || '').toString().trim().toUpperCase();
    return NAVAID_TYPES.includes(t) ? t : 'OTHER';
}

function getSectorRouteFixes() {
    return [...(waypoints || []), ...(navaids || [])].filter(fix =>
        fix &&
        fix.id &&
        fix.name &&
        typeof fix.latitude === 'number' &&
        typeof fix.longitude === 'number' &&
        isFinite(fix.latitude) &&
        isFinite(fix.longitude)
    );
}

function getRouteFixesForSector(sector) {
    return [...(sector?.waypoints || []), ...(sector?.navaids || [])].filter(fix =>
        fix &&
        fix.id &&
        fix.name &&
        typeof fix.latitude === 'number' &&
        typeof fix.longitude === 'number' &&
        isFinite(fix.latitude) &&
        isFinite(fix.longitude)
    );
}

function findSectorRouteFixById(id) {
    const key = id != null ? String(id) : '';
    if (!key) return null;
    return getSectorRouteFixes().find(fix => String(fix.id) === key) || null;
}

function findSectorRouteFixByName(name) {
    const key = (name || '').toString().trim().toUpperCase();
    if (!key) return null;
    return getSectorRouteFixes().find(fix => (fix.name || '').toString().trim().toUpperCase() === key) || null;
}

function findSectorRouteFixAtCanvasPixel(canvasX, canvasY) {
    return findSectorWaypointAtCanvasPixel(canvasX, canvasY) || findSectorNavaidAtCanvasPixel(canvasX, canvasY);
}

// Parse bulk NAVAID format: <name> (<type>) <DDMMSSN> <DDDMMSSE>
function parseBulkNavaidLine(line) {
    line = line.trim();
    if (!line) return null;
    const parts = line.split(/\s+/);
    if (parts.length < 4) return { error: `Invalid format: ${line}` };

    const name = parts[0].trim();
    const typeMatch = (parts[1] || '').toString().trim().match(/^\((.*)\)$/);
    if (!typeMatch) return { error: `Type must be in brackets, for example (VOR): ${line}` };
    const type = normalizeNavaidType(typeMatch[1]);
    if (!name) return { error: `Missing NAVAID name: ${line}` };

    const parsed = parseBulkWaypointLine(`${name} ${name} ${parts[2]} ${parts[3]}`);
    if (!parsed || parsed.error) return parsed;
    return {
        name,
        type,
        latitude: parsed.latitude,
        longitude: parsed.longitude
    };
}

// Parse boundary point format: <name> <DDMMSSN> <DDDMMSSE>
function parseBoundaryPointLine(line) {
    line = line.trim();
    if (!line) return null;
    
    // Split by whitespace
    const parts = line.split(/\s+/);
    
    // Need at least: name lat lon
    if (parts.length < 3) {
        return { error: `Invalid format: ${line}` };
    }
    
    // Get boundary point name (first part)
    const name = parts[0].trim();
    if (!name) {
        return { error: `Missing point name: ${line}` };
    }
    
    // Get latitude (format: DDMMSSN)
    const latStr = parts[1].trim().toUpperCase();
    if (!latStr || latStr.length < 7) {
        return { error: `Invalid latitude format: ${line}` };
    }
    
    // Parse latitude: DDMMSSN
    const latDegrees = parseInt(latStr.substring(0, 2));
    const latMinutes = parseInt(latStr.substring(2, 4));
    const latSeconds = parseInt(latStr.substring(4, 6));
    const latDirection = latStr.substring(6, 7); // N or S
    
    if (isNaN(latDegrees) || latDegrees < 0 || latDegrees > 89) {
        return { error: `Invalid latitude degrees (0-89): ${line}` };
    }
    if (isNaN(latMinutes) || latMinutes < 0 || latMinutes > 59) {
        return { error: `Invalid latitude minutes (0-59): ${line}` };
    }
    if (isNaN(latSeconds) || latSeconds < 0 || latSeconds > 59) {
        return { error: `Invalid latitude seconds (0-59): ${line}` };
    }
    if (latDirection !== 'N' && latDirection !== 'S') {
        return { error: `Invalid latitude direction (N/S): ${line}` };
    }
    
    // Get longitude (format: DDDMMSSE)
    const lonStr = parts[2].trim().toUpperCase();
    if (!lonStr || lonStr.length < 8) {
        return { error: `Invalid longitude format: ${line}` };
    }
    
    // Parse longitude: DDDMMSSE
    const lonDegrees = parseInt(lonStr.substring(0, 3));
    const lonMinutes = parseInt(lonStr.substring(3, 5));
    const lonSeconds = parseInt(lonStr.substring(5, 7));
    const lonDirection = lonStr.substring(7, 8); // E or W
    
    if (isNaN(lonDegrees) || lonDegrees < 0 || lonDegrees > 179) {
        return { error: `Invalid longitude degrees (0-179): ${line}` };
    }
    if (isNaN(lonMinutes) || lonMinutes < 0 || lonMinutes > 59) {
        return { error: `Invalid longitude minutes (0-59): ${line}` };
    }
    if (isNaN(lonSeconds) || lonSeconds < 0 || lonSeconds > 59) {
        return { error: `Invalid longitude seconds (0-59): ${line}` };
    }
    if (lonDirection !== 'E' && lonDirection !== 'W') {
        return { error: `Invalid longitude direction (E/W): ${line}` };
    }
    
    // Convert to decimal degrees
    const latitude = DMSToDecimal(latDegrees, latMinutes, latSeconds, latDirection);
    const longitude = DMSToDecimal(lonDegrees, lonMinutes, lonSeconds, lonDirection);
    
    return {
        name: name,
        latitude: latitude,
        longitude: longitude
    };
}

// Initialize canvas
function initCanvas() {
    canvas = document.getElementById('sectorCanvas');
    if (!canvas) return;
    
    ctx = canvas.getContext('2d');
    
    // Set canvas size to match container
    const container = document.getElementById('visualizationCanvas');
    canvas.width = container.clientWidth;
    canvas.height = container.clientHeight;
    
    // Reset zoom and pan
    zoomLevel = 1.0;
    panX = 0;
    panY = 0;
    
    // Find CENTRE waypoint
    updateCentreWaypoint();
    
    // Set origin based on CENTRE waypoint or center of canvas
    if (centreWaypoint) {
        originX = canvas.width / 2;
        originY = canvas.height / 2;
    } else {
        originX = canvas.width / 2;
        originY = canvas.height / 2;
    }
    
    // Auto-fit zoom
    autoFitZoom();
    
    // Add event listeners for zoom and pan
    setupCanvasInteractions();
    ensureSectorMapCanvasExtras();
    ensureVisualizationCanvasContextMenu();

    drawCanvas();
}

// Initialize simulation canvas
function initSimulationCanvas() {
    // IMPORTANT: Replace the canvas node on each sim start.
    // This guarantees we never accumulate duplicate event listeners across runs
    // (which can cause middle-click trajectory toggles to "flip twice" and appear broken).
    const oldCanvas = document.getElementById('simulationCanvasElement');
    if (!oldCanvas) return;
    try {
        const fresh = oldCanvas.cloneNode(true);
        oldCanvas.parentNode?.replaceChild(fresh, oldCanvas);
        simulationCanvas = fresh;
    } catch (e) {
        simulationCanvas = oldCanvas;
    }
    if (!simulationCanvas) return;
    
    const container = document.getElementById('simulationCanvas');
    if (!container) return;
    
    simulationCtx = simulationCanvas.getContext('2d');
    if (!simulationCtx) return;
    
    // Calculate and store geographic aspect ratio first
    calculateSimulationAspectRatio();
    
    // Set canvas size maintaining aspect ratio
    resizeSimulationCanvas();
    
    // Ensure canvas has valid dimensions before proceeding
    if (simulationCanvas.width <= 0 || simulationCanvas.height <= 0) {
        console.error('Canvas dimensions invalid:', simulationCanvas.width, simulationCanvas.height);
        return;
    }
    
    // Reset zoom and pan first
    simulationZoomLevel = 1.0;
    simulationPanX = 0;
    simulationPanY = 0;
    
    // Auto-fit zoom for simulation (this will also ensure pan is set to 0 to center at CENTRE)
    autoFitSimulationZoom();
    
    // Explicitly ensure pan is 0 to center at CENTRE waypoint
    simulationPanX = 0;
    simulationPanY = 0;
    
    // Add event listeners for zoom and pan
    setupSimulationCanvasInteractions();

    // Add resize handler (remove any existing one first)
    window.removeEventListener('resize', handleSimulationResize);
    window.addEventListener('resize', handleSimulationResize);
    
    // Initial draw
    drawSimulationCanvas();
    if (simulationRecording?.metadata && !simulationRecording.metadata.initialView) {
        const viewport = {
            width: simulationCanvas.width,
            height: simulationCanvas.height,
            aspectRatio: simulationRecordingRoundNumber(simulationCanvas.width / Math.max(1, simulationCanvas.height), 6)
        };
        simulationRecording.metadata.initialView = {
            zoom: simulationRecordingRoundNumber(simulationZoomLevel, 3),
            panX: simulationRecordingRoundNumber(simulationPanX, 2),
            panY: simulationRecordingRoundNumber(simulationPanY, 2),
            viewport
        };
        simulationRecording.metadata.viewport = viewport;
        recordSimulationEvent('map_initial_view', simulationRecording.metadata.initialView);
    }
    recordSimulationAircraftSnapshot(true);
}

// Calculate geographic aspect ratio from waypoints
function calculateSimulationAspectRatio() {
    if (!window.simulationData) {
        simulationAspectRatio = null;
        return;
    }
    
    const simWaypoints = window.simulationData.waypoints || [];
    const validWaypoints = simWaypoints.filter(wp => 
        wp && 
        typeof wp.latitude === 'number' && 
        typeof wp.longitude === 'number' &&
        isFinite(wp.latitude) && 
        isFinite(wp.longitude)
    );
    
    if (validWaypoints.length === 0) {
        simulationAspectRatio = null;
        return;
    }
    
    // Find CENTER/CENTRE waypoint
    const simCentreWaypoint = validWaypoints.find(wp => isCenterWaypointName(wp?.name));
    
    // Calculate bounds relative to CENTRE waypoint
    let minRelLat = Infinity, maxRelLat = -Infinity;
    let minRelLon = Infinity, maxRelLon = -Infinity;
    
    validWaypoints.forEach(wp => {
        let relLat = wp.latitude;
        let relLon = wp.longitude;
        
        if (simCentreWaypoint) {
            relLat = wp.latitude - simCentreWaypoint.latitude;
            relLon = wp.longitude - simCentreWaypoint.longitude;
        }
        
        if (isFinite(relLat) && isFinite(relLon)) {
            minRelLat = Math.min(minRelLat, relLat);
            maxRelLat = Math.max(maxRelLat, relLat);
            minRelLon = Math.min(minRelLon, relLon);
            maxRelLon = Math.max(maxRelLon, relLon);
        }
    });
    
    const latRange = Math.max(maxRelLat - minRelLat, 0.01);
    const lonRange = Math.max(maxRelLon - minRelLon, 0.01);

    let refLatDeg = null;
    if (simCentreWaypoint && isFinite(simCentreWaypoint.latitude)) refLatDeg = simCentreWaypoint.latitude;
    else {
        let sum = 0;
        let n = 0;
        validWaypoints.forEach((wp) => {
            if (isFinite(wp.latitude)) {
                sum += wp.latitude;
                n++;
            }
        });
        if (n > 0) refLatDeg = sum / n;
    }
    const cosLat = refLatDeg != null && isFinite(refLatDeg) ? Math.cos((refLatDeg * Math.PI) / 180) : 1;
    const safeCos = isFinite(cosLat) && Math.abs(cosLat) > 1e-10 ? cosLat : 1;

    // Aspect ratio in distance-like units (scale lon by cos φ₀)
    simulationAspectRatio = (lonRange * safeCos) / latRange;
    
    // Ensure aspect ratio is finite
    if (!isFinite(simulationAspectRatio) || simulationAspectRatio <= 0) {
        simulationAspectRatio = 1.0;
    }
}

// Resize simulation canvas - always fill container, adjust zoom to maintain aspect ratio
function resizeSimulationCanvas() {
    if (!simulationCanvas) return;
    
    const container = document.getElementById('simulationCanvas');
    if (!container) return;
    
    const containerWidth = container.clientWidth;
    const containerHeight = container.clientHeight;
    
    // Always fill the container
    simulationCanvas.width = containerWidth;
    simulationCanvas.height = containerHeight;
    simulationCanvas.style.marginLeft = '0px';
    simulationCanvas.style.marginTop = '0px';
}

// Handle simulation canvas resize
function handleSimulationResize() {
    if (!document.getElementById('simulationModal')?.classList.contains('active')) {
        return; // Only handle resize when simulation modal is active
    }
    
    if (!simulationCanvas) return;
    
    // Resize canvas maintaining aspect ratio
    resizeSimulationCanvas();
    
    // Recalculate zoom and pan to maintain view
    autoFitSimulationZoom();
    
    // Redraw
    drawSimulationCanvas();
}

// Auto-fit zoom for simulation - maintains geographic aspect ratio while filling container
function autoFitSimulationZoom() {
    if (!simulationCanvas || !simulationCtx || !window.simulationData) {
        return;
    }
    
    // Ensure canvas has valid dimensions
    if (simulationCanvas.width <= 0 || simulationCanvas.height <= 0) {
        return;
    }
    
    const simWaypoints = window.simulationData.waypoints || [];
    const validWaypoints = simWaypoints.filter(wp => 
        wp && 
        typeof wp.latitude === 'number' && 
        typeof wp.longitude === 'number' &&
        isFinite(wp.latitude) && 
        isFinite(wp.longitude)
    );
    
    if (validWaypoints.length === 0) {
        simulationZoomLevel = 1.0;
        simulationPanX = 0;
        simulationPanY = 0;
        return;
    }
    
    // Find CENTER/CENTRE waypoint
    const simCentreWaypoint = validWaypoints.find(wp => isCenterWaypointName(wp?.name));
    
    if (!simCentreWaypoint) {
        // No CENTRE waypoint - center at bounds center
        let minLat = Infinity, maxLat = -Infinity;
        let minLon = Infinity, maxLon = -Infinity;
        
        validWaypoints.forEach(wp => {
            if (isFinite(wp.latitude) && isFinite(wp.longitude)) {
                minLat = Math.min(minLat, wp.latitude);
                maxLat = Math.max(maxLat, wp.latitude);
                minLon = Math.min(minLon, wp.longitude);
                maxLon = Math.max(maxLon, wp.longitude);
            }
        });
        
        const centerLat = (minLat + maxLat) / 2;
        const centerLon = (minLon + maxLon) / 2;
        const latRange = Math.max(maxLat - minLat, 0.01);
        const lonRange = Math.max(maxLon - minLon, 0.01);
        
        const containerWidth = simulationCanvas.width;
        const containerHeight = simulationCanvas.height;
        const padding = 50;
        const cosLat = Math.cos((centerLat * Math.PI) / 180);
        const safeCos = isFinite(cosLat) && Math.abs(cosLat) > 1e-10 ? cosLat : 1;
        const zoomX = (containerWidth - padding * 2) / (lonRange * safeCos);
        const zoomY = (containerHeight - padding * 2) / latRange;
        simulationZoomLevel = Math.min(zoomX, zoomY);
        
        // Center at bounds center (not ideal, but better than nothing)
        simulationPanX = 0;
        simulationPanY = 0;
        return;
    }
    
    // Calculate bounds relative to CENTRE waypoint
    let minRelLat = Infinity, maxRelLat = -Infinity;
    let minRelLon = Infinity, maxRelLon = -Infinity;
    
    validWaypoints.forEach(wp => {
        const relLat = wp.latitude - simCentreWaypoint.latitude;
        const relLon = wp.longitude - simCentreWaypoint.longitude;
        
        if (isFinite(relLat) && isFinite(relLon)) {
            minRelLat = Math.min(minRelLat, relLat);
            maxRelLat = Math.max(maxRelLat, relLat);
            minRelLon = Math.min(minRelLon, relLon);
            maxRelLon = Math.max(maxRelLon, relLon);
        }
    });
    
    // Calculate geographic ranges
    const padding = 50;
    const latRange = Math.max(maxRelLat - minRelLat, 0.01);
    const lonRange = Math.max(maxRelLon - minRelLon, 0.01);

    const refLatDeg = isFinite(simCentreWaypoint.latitude) ? simCentreWaypoint.latitude : 0;
    const cosLat = Math.cos((refLatDeg * Math.PI) / 180);
    const safeCos = isFinite(cosLat) && Math.abs(cosLat) > 1e-10 ? cosLat : 1;

    // Get container dimensions
    const containerWidth = simulationCanvas.width;
    const containerHeight = simulationCanvas.height;
    const containerAspectRatio = containerWidth / containerHeight;
    
    // Calculate zoom to maintain geographic aspect ratio while filling container
    // Canvas always fills container, zoom adjusts to show more/less content while maintaining aspect ratio
    const zoomX = (containerWidth - padding * 2) / (lonRange * safeCos);
    const zoomY = (containerHeight - padding * 2) / latRange;
    
    if (simulationAspectRatio && isFinite(simulationAspectRatio)) {
        // Geographic aspect ratio exists - maintain it by fitting to the limiting dimension
        if (containerAspectRatio > simulationAspectRatio) {
            // Container is wider than geographic content - fit to height (vertical is limiting)
            // This means horizontal will show more content (zoom out horizontally)
            simulationZoomLevel = zoomY;
        } else {
            // Container is taller than geographic content - fit to width (horizontal is limiting)
            // This means vertical will show more content (zoom out vertically)
            simulationZoomLevel = zoomX;
        }
    } else {
        // No aspect ratio constraint - fit to container (use smaller zoom to fit everything)
        simulationZoomLevel = Math.min(zoomX, zoomY);
    }
    
    // Ensure zoom is finite and reasonable
    if (!isFinite(simulationZoomLevel) || simulationZoomLevel <= 0) {
        simulationZoomLevel = 1.0;
    }
    if (simulationZoomLevel > 10000) simulationZoomLevel = 10000;
    if (simulationZoomLevel < 0.1) simulationZoomLevel = 0.1;
    
    // IMPORTANT: Center the view at CENTRE waypoint
    // CENTRE waypoint is at (0, 0) relative to itself
    // Canvas center is at (width/2, height/2)
    // effectiveOriginX = width/2 + panX, effectiveOriginY = height/2 + panY
    // For CENTRE: x = effectiveOriginX + 0*zoom = effectiveOriginX, y = effectiveOriginY - 0*zoom = effectiveOriginY
    // To center CENTRE at (width/2, height/2): panX = 0, panY = 0
    simulationPanX = 0;
    simulationPanY = 0;
}

// Center map at CENTRE waypoint
function centerMapAtCentre() {
    if (!simulationCanvas || !window.simulationData) {
        return;
    }
    
    const simWaypoints = window.simulationData.waypoints || [];
    const simCentreWaypoint = simWaypoints.find(wp => isCenterWaypointName(wp?.name));
    
    if (!simCentreWaypoint) {
        return; // No CENTER/CENTRE waypoint to center on
    }
    
    const oldPanX = simulationPanX;
    const oldPanY = simulationPanY;
    // Reset pan to center at CENTRE waypoint (0, 0 relative to CENTRE)
    // CENTRE waypoint is at (0, 0) relative to itself
    // Canvas center is at (width/2, height/2)
    // effectiveOriginX = width/2 + panX, effectiveOriginY = height/2 + panY
    // For CENTRE (relLon=0, relLat=0): x = effectiveOriginX, y = effectiveOriginY
    // To center: x = width/2, y = height/2, so panX = 0, panY = 0
    simulationPanX = 0;
    simulationPanY = 0;
    
    // Redraw
    drawSimulationCanvas();
    recordSimulationEvent('map_center', {
        oldPanX: simulationRecordingRoundNumber(oldPanX, 2),
        oldPanY: simulationRecordingRoundNumber(oldPanY, 2),
        newPanX: simulationRecordingRoundNumber(simulationPanX, 2),
        newPanY: simulationRecordingRoundNumber(simulationPanY, 2)
    });
}

// Setup simulation canvas interactions (zoom and pan)
function setupSimulationCanvasInteractions() {
    if (!simulationCanvas) return;

    // Remove any previously bound handlers (within this page session).
    try {
        const prev = simulationCanvas._simHandlers;
        if (prev) {
            if (prev.wheel) simulationCanvas.removeEventListener('wheel', prev.wheel);
            if (prev.mousedown) simulationCanvas.removeEventListener('mousedown', prev.mousedown);
            if (prev.mousemove) simulationCanvas.removeEventListener('mousemove', prev.mousemove);
            if (prev.mouseup) simulationCanvas.removeEventListener('mouseup', prev.mouseup);
            if (prev.mouseleave) simulationCanvas.removeEventListener('mouseleave', prev.mouseleave);
            if (prev.contextmenu) simulationCanvas.removeEventListener('contextmenu', prev.contextmenu);
        }
    } catch (e) {}
    const handlers = {};
    try { simulationCanvas._simHandlers = handlers; } catch (e) {}
    
    let isDragging = false;
    let dragStartX = 0;
    let dragStartY = 0;
    let dragStartPanX = 0;
    let dragStartPanY = 0;
    let panDragStarted = false;
    let labelDragRecordingStart = null;
    
    const labelMoveMouseButton = () => {
        const v = (simulationSettings?.labelMoveButton || SIM_SETTINGS_DEFAULTS.labelMoveButton || 'left').toString().toLowerCase();
        if (v === 'middle') return 1;
        if (v === 'right') return 2;
        return 0;
    };

    const tryStartLabelDragAt = (clickX, clickY) => {
        for (let i = simulationAircraftLabelBounds.length - 1; i >= 0; i--) {
            const b = simulationAircraftLabelBounds[i];
            if (!b) continue;
            if (clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
                simulationIsDraggingAircraftLabel = true;
                simulationDraggingAircraftId = b.aircraftId;
                simulationLabelDragAnchorX = clickX - b.x;
                simulationLabelDragAnchorY = clickY - b.y;
                // Bring to front when grabbed
                if (simulationDraggingAircraftId) {
                    simulationLabelZOrder = simulationLabelZOrder.filter(id => id !== simulationDraggingAircraftId);
                    simulationLabelZOrder.push(simulationDraggingAircraftId);
                }
                labelDragRecordingStart = {
                    aircraftId: b.aircraftId,
                    labelOffsetX: simulationRecordingRoundNumber((window.simulationData?.aircraft || []).find(a => a && a.id === b.aircraftId)?.labelOffsetX, 2),
                    labelOffsetY: simulationRecordingRoundNumber((window.simulationData?.aircraft || []).find(a => a && a.id === b.aircraftId)?.labelOffsetY, 2),
                    x: simulationRecordingRoundNumber(b.x, 2),
                    y: simulationRecordingRoundNumber(b.y, 2)
                };
                recordSimulationEvent('label_drag_start', labelDragRecordingStart, (window.simulationData?.aircraft || []).find(a => a && a.id === b.aircraftId));
                return true;
            }
        }
        return false;
    };

    // Mouse wheel zoom
    handlers.wheel = function(e) {
        e.preventDefault();
        const oldZoom = simulationZoomLevel;
        const oldPanX = simulationPanX;
        const oldPanY = simulationPanY;

        // Zoom sensitivity (1..10). Use exponential mapping for smoothness across mouse types.
        const sens = Math.max(1, Math.min(10, parseInt(simulationSettings?.zoomSensitivity, 10) || SIM_SETTINGS_DEFAULTS.zoomSensitivity));
        const k = 0.0010 * sens; // higher => more zoom per wheel delta
        const zoomFactor = Math.exp(-e.deltaY * k);
        const newZoom = simulationZoomLevel * zoomFactor;
        
        if (newZoom >= 0.1 && newZoom <= 10000) {
            const centerX = simulationCanvas.width / 2;
            const centerY = simulationCanvas.height / 2;
            
            const simOriginX = simulationCanvas.width / 2;
            const simOriginY = simulationCanvas.height / 2;
            const lonScale = getSimulationLonCosScale();

            const worldX = (centerX - simOriginX - simulationPanX) / (simulationZoomLevel * lonScale);
            const worldY = -(centerY - simOriginY - simulationPanY) / simulationZoomLevel;
            
            simulationZoomLevel = newZoom;
            
            simulationPanX = centerX - simOriginX - worldX * simulationZoomLevel * lonScale;
            simulationPanY = centerY - simOriginY + worldY * simulationZoomLevel;
            
            drawSimulationCanvas();
            recordSimulationEvent(e.deltaY < 0 ? 'map_zoom_in' : 'map_zoom_out', {
                oldZoom: simulationRecordingRoundNumber(oldZoom, 3),
                newZoom: simulationRecordingRoundNumber(simulationZoomLevel, 3),
                oldPanX: simulationRecordingRoundNumber(oldPanX, 2),
                oldPanY: simulationRecordingRoundNumber(oldPanY, 2),
                newPanX: simulationRecordingRoundNumber(simulationPanX, 2),
                newPanY: simulationRecordingRoundNumber(simulationPanY, 2),
                deltaY: simulationRecordingRoundNumber(e.deltaY, 2)
            });
        }
    };
    simulationCanvas.addEventListener('wheel', handlers.wheel);
    
    // Right-click measuring tool state
    let rightMouseDown = false;

    const getAircraftAtScreenPoint = (sx, sy) => {
        const r = 10; // slightly larger than symbol
        for (let i = simulationAircraftScreenStates.length - 1; i >= 0; i--) {
            const a = simulationAircraftScreenStates[i];
            if (!a) continue;
            const dx = sx - a.x;
            const dy = sy - a.y;
            if ((dx * dx + dy * dy) <= r * r) return a;
        }
        return null;
    };
    
    // Mouse drag panning (left click only)
    handlers.mousedown = function(e) {
        const rect = simulationCanvas.getBoundingClientRect();
        const clickX = e.clientX - rect.left;
        const clickY = e.clientY - rect.top;

        // Heading selector: while active, left-click commits, right-click cancels.
        if (simulationIsSelectingHeading) {
            if (e.button === 0) {
                e.preventDefault();
                e.stopPropagation();
                try {
                    const id = simulationSelectingHeadingAircraftId;
                    const ac = (window.simulationData?.aircraft || []).find(a => a && a.id === id);
                    if (ac) {
                        // Convert click to lat/lon
                        const simWaypoints = window.simulationData?.waypoints || [];
                        const simCentreWaypoint = simWaypoints.find(wp => isCenterWaypointName(wp?.name));
                        const simOriginX = simulationCanvas.width / 2;
                        const simOriginY = simulationCanvas.height / 2;
                        const effectiveOriginX = simOriginX + simulationPanX;
                        const effectiveOriginY = simOriginY + simulationPanY;
                        const lonScale = getSimulationLonCosScale();
                        const relLon = (clickX - effectiveOriginX) / (simulationZoomLevel * lonScale);
                        const relLat = -(clickY - effectiveOriginY) / simulationZoomLevel;
                        let lat = relLat;
                        let lon = relLon;
                        if (simCentreWaypoint) {
                            lat = relLat + simCentreWaypoint.latitude;
                            lon = relLon + simCentreWaypoint.longitude;
                        }

                        const aState = simulationAircraftScreenStates.find(s => s && s.aircraftId === id);
                        if (aState && isFinite(aState.lat) && isFinite(aState.lon)) {
                            const brgRaw = heading0to359(calculateBearingDegrees(aState.lat, aState.lon, lat, lon));
                            const inc = parseInt(simulationSettings?.headingSelectIncrement ?? SIM_SETTINGS_DEFAULTS.headingSelectIncrement, 10) || 1;
                            const brg = roundHeadingToIncrement(brgRaw, inc);
                            ac.selectedHeadingDeg = Math.round(brg);
                            ac.directToWpIdx = null;
                            ac.directToWpName = null;
                            clearExePlnAtmHoldLabelIfActive(ac);
                            ac.selectedApproachId = null;
                            ac.selectedApproachName = null;
                            ac.approachActive = null;
                            // TTS reply (DL only): aggregated (2s after last input), callsign spoken once at end.
                            try {
                                const targetHdg = heading0to359(ac.selectedHeadingDeg);
                                // Determine current heading for left/right wording.
                                let curHdg = null;
                                if (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg)) curHdg = Number(ac.publishedHeadingDeg);
                                else if (ac.currentHeadingDeg != null && isFinite(ac.currentHeadingDeg)) curHdg = Number(ac.currentHeadingDeg);
                                else {
                                    const simSec = getSimulationClockSeconds();
                                    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
                                    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
                                    const stNow = getAircraftPositionAtRadarUpdate(ac, simSec, radarSec);
                                    if (stNow?.next && isFinite(stNow.lat) && isFinite(stNow.lon) && isFinite(stNow.next.lat) && isFinite(stNow.next.lon)) {
                                        curHdg = heading0to359(calculateBearingDegrees(stNow.lat, stNow.lon, stNow.next.lat, stNow.next.lon));
                                    }
                                }
                                const side = (curHdg != null) ? getSimulationTurnSide(curHdg, targetHdg) : null;
                                // Phraseology: 000 should be read back as 360
                                const hdgDigits = formatHeadingFrom0to359(targetHdg).split('').join(' ');
                                const msg = side ? `turning ${side} heading ${hdgDigits}` : `heading ${hdgDigits}`;
                                queueSimulationAircraftTtsReply(ac, 'HDG', msg);
                            } catch (e) {}

                            // DL heading command: after random delay, start turning to target at an altitude-banded random rate.
                            if (simulationOperationModeId === 'DL' && isJoinerPpClient()) {
                                ppJoinerPostLateralCommand(ac.id, { type: 'HDG', headingDeg: Math.round(brg), immediate: true });
                            } else if (simulationOperationModeId === 'DL' && !isSimulationExeWithPpAircraftRestrictions()) {
                                const simTimeSec = getEffectiveSimulationSimTimeMs() / 1000;
                                const delaySec = 5 + Math.random() * 5; // 5–10s
                                ac.headingTurnTargetDeg = heading0to359(ac.selectedHeadingDeg);
                                ac.headingTurnStartSimSec = simTimeSec + delaySec;
                                ac.headingTurnRateDps = pickTurnRateDpsForAircraft(ac);

                                try {
                                    const hdgTxt = formatHeadingFrom0to359(heading0to359(ac.selectedHeadingDeg));
                                    pushSimulationDebugLog('CMD', ac, `HDG ${hdgTxt} (delay ${delaySec.toFixed(1)}s, rate ${Number(ac.headingTurnRateDps).toFixed(2)} dps)`);
                                } catch (e) {}

                                // Enter/continue heading-nav mode: from now on, lateral movement is driven by heading (published on radar updates).
                                try {
                                    const simSec = getSimulationClockSeconds();
                                    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
                                    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
                                    // Re-base from the aircraft's CURRENT published position (do NOT snap back to the original route).
                                    const stNow = getAircraftPositionAtRadarUpdate(ac, simSec, radarSec);
                                    const spawn = parseInt(ac.spawnTimeSec, 10) || 0;
                                    const elapsedSinceSpawn = Math.max(0, simSec - spawn);
                                    const elapsedAtLastUpdate = Math.floor(elapsedSinceSpawn / radarSec) * radarSec;
                                    const lastUpdateSimSec = spawn + elapsedAtLastUpdate;
                                    const baseLat = (stNow && isFinite(stNow.lat)) ? stNow.lat : aState.lat;
                                    const baseLon = (stNow && isFinite(stNow.lon)) ? stNow.lon : aState.lon;
                                    const baseUpdateSec = (stNow && stNow.lastUpdateSimSec != null) ? stNow.lastUpdateSimSec : lastUpdateSimSec;

                                    ac.navMode = 'heading';
                                    ac.headingNavLat = baseLat;
                                    ac.headingNavLon = baseLon;
                                    ac.headingNavLastUpdateSimSec = baseUpdateSec;
                                    if (!(ac.headingNavStatesByUpdateSec instanceof Map)) {
                                        ac.headingNavStatesByUpdateSec = new Map();
                                    }
                                    // Drop any future heading-nav points; continue from "now".
                                    for (const k of ac.headingNavStatesByUpdateSec.keys()) {
                                        if (k > baseUpdateSec) ac.headingNavStatesByUpdateSec.delete(k);
                                    }
                                    ac.headingNavStatesByUpdateSec.set(baseUpdateSec, { lat: baseLat, lon: baseLon });

                                    // Seed current heading from where it's going NOW (never seed from the target, or you'll get an instant jump).
                                    if (ac.currentHeadingDeg == null || !isFinite(ac.currentHeadingDeg)) {
                                        if (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg)) {
                                            ac.currentHeadingDeg = heading0to359(ac.publishedHeadingDeg);
                                        } else if (stNow?.next && isFinite(stNow.lat) && isFinite(stNow.lon) && isFinite(stNow.next.lat) && isFinite(stNow.next.lon)) {
                                            ac.currentHeadingDeg = heading0to359(calculateBearingDegrees(stNow.lat, stNow.lon, stNow.next.lat, stNow.next.lon));
                                        } else {
                                            ac.currentHeadingDeg = heading0to359(ac.selectedHeadingDeg);
                                        }
                                    }
                                } catch (e) {}
                            }
                        }
                    }
                } catch (err) {}
                const idHeadingDone = simulationSelectingHeadingAircraftId;
                const acHeadingDone = idHeadingDone ? (window.simulationData?.aircraft || []).find(a => a && a.id === idHeadingDone) : null;
                try {
                    if (acHeadingDone) markSimulationAircraftTtsInputEnd(acHeadingDone, 'HDG');
                } catch (e) {}
                simulationIsSelectingHeading = false;
                simulationSelectingHeadingAircraftId = null;
                simulationHeadingSelectMouse = null;
                if (acHeadingDone) captureJoinerExePatchFromAircraft(acHeadingDone);
                drawSimulationCanvas();
                return;
            }
            if (e.button === 2) {
                e.preventDefault();
                e.stopPropagation();
                simulationSuppressNextContextMenu = true;
                try {
                    const id = simulationSelectingHeadingAircraftId;
                    const ac = id ? (window.simulationData?.aircraft || []).find(a => a && a.id === id) : null;
                    if (ac) markSimulationAircraftTtsInputEnd(ac, 'HDG');
                } catch (e) {}
                simulationIsSelectingHeading = false;
                simulationSelectingHeadingAircraftId = null;
                simulationHeadingSelectMouse = null;
                drawSimulationCanvas();
                return;
            }
        }

        // Flight status menu: left-click on callsign (DL only; before label drag)
        if (e.button === 0 && simulationOperationModeId === 'DL' && !simulationIsMonitorOnly) {
            const flightStatusId = resolveCallsignHitAircraftId(clickX, clickY);
            if (flightStatusId != null) {
                const fsPopup = document.getElementById('simulationFlightStatusPopup');
                const fsOpen = fsPopup && fsPopup.style.display !== 'none';
                if (fsOpen && simulationFlightStatusPopupAircraftId === flightStatusId) {
                    const firstAction = getFirstFlightStatusActionForAircraftId(flightStatusId);
                    hideSimulationFlightStatusPopup();
                    if (firstAction) runSimulationFlightStatusAction(flightStatusId, firstAction);
                    e.preventDefault();
                    e.stopPropagation();
                    return;
                }
                openSimulationFlightStatusPopup(flightStatusId, e.clientX, e.clientY);
                e.preventDefault();
                e.stopPropagation();
                return;
            }
        }

        // Label drag only with configured mouse button.
        // But: preserve middle-click special actions (trajectory toggle/removal) even when label-move is set to Middle Click.
        const labelMoveBtn = labelMoveMouseButton();
        const hitXlv = () => {
            if (!simulationAircraftXlvTextBounds.length) return false;
            const xlvById = new Map(simulationAircraftXlvTextBounds.map(b => [b.aircraftId, b]));
            const opaqueId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId)
                ? simulationDraggingAircraftId
                : simulationHoveredAircraftLabelId;
            if (!opaqueId) return false;
            const b = xlvById.get(opaqueId);
            if (!b) return false;
            return (clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h);
        };
        const hitCallsign = () => {
            if (!simulationAircraftCallsignTextBounds.length) return false;
            const csById = new Map(simulationAircraftCallsignTextBounds.map(b => [b.aircraftId, b]));
            const isInside = (b) => b && clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h;

            // Prefer actively dragged label, otherwise use z-order (topmost first).
            const preferredId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId) ? simulationDraggingAircraftId : null;
            if (preferredId) {
                const b = csById.get(preferredId);
                if (isInside(b)) return true;
            }
            for (let zi = simulationLabelZOrder.length - 1; zi >= 0; zi--) {
                const id = simulationLabelZOrder[zi];
                const b = csById.get(id);
                if (isInside(b)) return true;
            }
            return false;
        };
        const hitTrajectoryEstimate = () => {
            for (let i = simulationTrajectoryEstimateBounds.length - 1; i >= 0; i--) {
                const b = simulationTrajectoryEstimateBounds[i];
                if (!b) continue;
                if (clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) return true;
            }
            return false;
        };
        const hitHdgDct = () => {
            if (!simulationAircraftHdgDctTextBounds.length) return false;
            const hdgById = new Map(simulationAircraftHdgDctTextBounds.map(b => [b.aircraftId, b]));
            const opaqueId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId)
                ? simulationDraggingAircraftId
                : simulationHoveredAircraftLabelId;
            if (!opaqueId) return false;
            const b = hdgById.get(opaqueId);
            if (!b) return false;
            return (clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h);
        };

        if (e.button === labelMoveBtn) {
            // Reserve label inputs from initiating label drag.
            const reserved =
                (e.button === 1 && (hitCallsign() || hitTrajectoryEstimate() || hitXlv() || hitHdgDct())) ||
                (e.button === 0 && hitHdgDct());
            if (!reserved) {
                if (tryStartLabelDragAt(clickX, clickY)) {
                    e.preventDefault();
                    e.stopPropagation();
                    return;
                }
            }
        }

        // (old block replaced)
        if (false) {
            if (tryStartLabelDragAt(clickX, clickY)) {
                e.preventDefault();
                e.stopPropagation();
                return;
            }
        }

        if (e.button === 0) { // Left mouse button
            // DCT path drawing: left-click adds point (snap to waypoint if < 1 NM) or rejoin on trajectory waypoint; route prev/next lines clickable
            if (simulationDctPathDrawingAircraftId) {
                e.preventDefault();
                e.stopPropagation();
                const ac = (window.simulationData?.aircraft || []).find(a => a && a.id === simulationDctPathDrawingAircraftId);
                const acSeq = ac ? getAircraftForDctTrajectoryUi(ac) : null;
                if (!ac || !acSeq || !Array.isArray(acSeq.points)) { cancelDctPathMode(); drawSimulationCanvas(); return; }
                const ll = simulationScreenToLatLon(clickX, clickY);
                if (!ll) { drawSimulationCanvas(); return; }
                const SNAP_NM = 1;
                const REJOIN_PIXEL_RADIUS = 18;
                const ROUTE_LINE_HIT_PX = 14;

                // 1) Click on route direction arrow -> popup with all route names for that direction
                if (simulationDctRouteLookupSegments.length && simulationDctRouteLookup && simulationDctRouteLookup.center) {
                    for (let si = 0; si < simulationDctRouteLookupSegments.length; si++) {
                        const seg = simulationDctRouteLookupSegments[si];
                        const d = distanceToSegment(clickX, clickY, seg.x1, seg.y1, seg.x2, seg.y2);
                        if (d <= ROUTE_LINE_HIT_PX) {
                            const routeKeys = seg.routeKeys || [];
                            const target = simulationDctRouteLookup.segments[si] ? simulationDctRouteLookup.segments[si].target : null;
                            if (routeKeys.length) {
                                showDctRouteNamesPopup(routeKeys, e.clientX, e.clientY, simulationDctRouteLookup.center, target);
                            }
                            drawSimulationCanvas();
                            return;
                        }
                    }
                }

                // 2) Click on existing trajectory waypoint (rejoin)
                for (let i = 0; i < acSeq.points.length; i++) {
                    const p = acSeq.points[i];
                    if (!p || !isFinite(p.lat) || !isFinite(p.lon)) continue;
                    const sc = simulationLatLonToScreen(p.lat, p.lon);
                    if (sc && isFinite(sc.x) && isFinite(sc.y)) {
                        const dx = clickX - sc.x;
                        const dy = clickY - sc.y;
                        if (dx * dx + dy * dy <= REJOIN_PIXEL_RADIUS * REJOIN_PIXEL_RADIUS) {
                            if (isJoinerPpClient()) {
                                const pathSnap = simulationDctPathPoints.map(pt => ({
                                    lat: Number(pt.lat),
                                    lon: Number(pt.lon),
                                    name: (pt.name && String(pt.name).trim()) ? String(pt.name).trim().toUpperCase() : ''
                                }));
                                ppJoinerPostLateralCommand(ac.id, { type: 'DCT_PATH', pathPoints: pathSnap, rejoinPointIdx: i });
                            } else {
                                applyDctPathToAircraft(ac, simulationDctPathPoints, i);
                            }
                            cancelDctPathMode();
                            drawSimulationCanvas();
                            return;
                        }
                    }
                }

                // 3) Click on existing user path circle -> show route prev/next if waypoint is on a route (no new point)
                for (const pt of simulationDctPathPoints) {
                    const sc = simulationLatLonToScreen(pt.lat, pt.lon);
                    if (!sc || !isFinite(sc.x) || !isFinite(sc.y)) continue;
                    const dx = clickX - sc.x;
                    const dy = clickY - sc.y;
                    if (dx * dx + dy * dy <= REJOIN_PIXEL_RADIUS * REJOIN_PIXEL_RADIUS) {
                        const centerWp = getSectorWaypointForRouteLookup(pt.lat, pt.lon, pt.name);
                        if (centerWp) {
                            const all = findAllRouteDirections(centerWp.id);
                            if (all && all.segments.length) {
                                simulationDctRouteLookup = { center: centerWp, segments: all.segments };
                                simulationDctPathMouse = { x: clickX, y: clickY };
                                drawSimulationCanvas();
                                return;
                            }
                        }
                        break; // only one circle under cursor
                    }
                }

                // 4) Click on trajectory waypoint (no path points yet) -> show route prev/next only
                if (simulationDctPathPoints.length === 0) {
                    const segIdxDct = Math.max(0, Math.min(acSeq.points.length - 2, parseInt(acSeq.routeProgressIdx, 10) || 0));
                    for (let i = segIdxDct + 1; i < acSeq.points.length; i++) {
                        const p = acSeq.points[i];
                        if (!p || !isFinite(p.lat) || !isFinite(p.lon)) continue;
                        const sc = simulationLatLonToScreen(p.lat, p.lon);
                        if (!sc || !isFinite(sc.x) || !isFinite(sc.y)) continue;
                        const dx = clickX - sc.x;
                        const dy = clickY - sc.y;
                        if (dx * dx + dy * dy <= REJOIN_PIXEL_RADIUS * REJOIN_PIXEL_RADIUS) {
                            const centerWp = getSectorWaypointForRouteLookup(p.lat, p.lon, p.name);
                            if (centerWp) {
                                const all = findAllRouteDirections(centerWp.id);
                                if (all && all.segments.length) {
                                    simulationDctRouteLookup = { center: centerWp, segments: all.segments };
                                    simulationDctPathMouse = { x: clickX, y: clickY };
                                    drawSimulationCanvas();
                                    return;
                                }
                            }
                            break;
                        }
                    }
                }

                // 5) Add new point (snap to sector waypoint if within 1 NM)
                const simWaypoints = window.simulationData?.waypoints || [];
                let snapped = null;
                for (const wp of simWaypoints) {
                    if (!wp || !isFinite(wp.latitude) || !isFinite(wp.longitude)) continue;
                    const d = calculateNauticalMiles(ll.lat, ll.lon, wp.latitude, wp.longitude);
                    if (d < SNAP_NM) {
                        snapped = { lat: wp.latitude, lon: wp.longitude, name: (wp.name || '').toString().trim().toUpperCase() };
                        break;
                    }
                }
                if (snapped) {
                    simulationDctPathPoints.push(snapped);
                    const centerWp = getSectorWaypointForRouteLookup(snapped.lat, snapped.lon, snapped.name);
                    if (centerWp) {
                        const all = findAllRouteDirections(centerWp.id);
                        simulationDctRouteLookup = (all && all.segments.length) ? { center: centerWp, segments: all.segments } : null;
                    } else simulationDctRouteLookup = null;
                } else {
                    simulationDctPathPoints.push({ lat: ll.lat, lon: ll.lon, name: null });
                    simulationDctRouteLookup = null;
                }
                simulationDctPathMouse = { x: clickX, y: clickY };
                drawSimulationCanvas();
                return;
            }

            // Check if clicking on a measurement text label
            // (rect/clickX/clickY computed above)

            // ALV click (DL mode only, not monitor-only) — open before outside-close so the open press does not dismiss the list
            if (simulationOperationModeId === 'DL' && !simulationIsMonitorOnly && simulationAircraftAlvTextBounds.length) {
                const alvById = new Map(simulationAircraftAlvTextBounds.map(b => [b.aircraftId, b]));
                for (let zi = simulationLabelZOrder.length - 1; zi >= 0; zi--) {
                    const id = simulationLabelZOrder[zi];
                    const b = alvById.get(id);
                    if (!b) continue;
                    if (clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
                        openSimulationAlvPicker(id, e.clientX, e.clientY);
                        e.preventDefault();
                        e.stopPropagation();
                        return;
                    }
                }
            }

            // If ALV picker is open and press is outside, close it (no action)
            const alvPickerEl = document.getElementById('simulationAlvPicker');
            if (alvPickerEl && alvPickerEl.style.display !== 'none' && Date.now() >= simulationAlvPickerSuppressOutsideUntil) {
                const pr = alvPickerEl.getBoundingClientRect();
                if (!(e.clientX >= pr.left && e.clientX <= pr.right && e.clientY >= pr.top && e.clientY <= pr.bottom)) {
                    hideSimulationAlvPicker();
                }
            }
            // If XLV picker is open and click is outside, close it (no action)
            const xlvPickerEl = document.getElementById('simulationXlvPicker');
            if (xlvPickerEl && xlvPickerEl.style.display !== 'none') {
                const pr = xlvPickerEl.getBoundingClientRect();
                if (!(e.clientX >= pr.left && e.clientX <= pr.right && e.clientY >= pr.top && e.clientY <= pr.bottom)) {
                    hideSimulationXlvPicker();
                }
            }
            // If DCT picker is open and click is outside, close it (no action)
            const dctPickerEl = document.getElementById('simulationDctPicker');
            if (dctPickerEl && dctPickerEl.style.display !== 'none') {
                const pr = dctPickerEl.getBoundingClientRect();
                if (!(e.clientX >= pr.left && e.clientX <= pr.right && e.clientY >= pr.top && e.clientY <= pr.bottom)) {
                    hideSimulationDctPicker();
                }
            }
            // If RWY picker is open and click is outside, close it (no action)
            const rwyPickerEl = document.getElementById('simulationRwyPicker');
            if (rwyPickerEl && rwyPickerEl.style.display !== 'none') {
                const pr = rwyPickerEl.getBoundingClientRect();
                if (!(e.clientX >= pr.left && e.clientX <= pr.right && e.clientY >= pr.top && e.clientY <= pr.bottom)) {
                    hideSimulationRwyPicker();
                }
            }
            const rocPickerEl = document.getElementById('simulationRocPicker');
            if (rocPickerEl && rocPickerEl.style.display !== 'none') {
                const pr = rocPickerEl.getBoundingClientRect();
                if (!(e.clientX >= pr.left && e.clientX <= pr.right && e.clientY >= pr.top && e.clientY <= pr.bottom)) {
                    hideSimulationRocPicker();
                }
            }
            const flightStatusEl = document.getElementById('simulationFlightStatusPopup');
            if (flightStatusEl && flightStatusEl.style.display !== 'none') {
                const pr = flightStatusEl.getBoundingClientRect();
                if (!(e.clientX >= pr.left && e.clientX <= pr.right && e.clientY >= pr.top && e.clientY <= pr.bottom)) {
                    hideSimulationFlightStatusPopup();
                }
            }

            // XLV click (DL mode only, not monitor-only) - open selector (topmost label first)
            if (simulationOperationModeId === 'DL' && !simulationIsMonitorOnly && simulationAircraftXlvTextBounds.length) {
                const xlvById = new Map(simulationAircraftXlvTextBounds.map(b => [b.aircraftId, b]));
                for (let zi = simulationLabelZOrder.length - 1; zi >= 0; zi--) {
                    const id = simulationLabelZOrder[zi];
                    const b = xlvById.get(id);
                    if (!b) continue;
                    if (clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
                        openSimulationXlvPicker(id, e.clientX, e.clientY);
                        e.preventDefault();
                        e.stopPropagation();
                        return;
                    }
                }
            }

            // RWY click (DL mode, not monitor-only): left-click on RW segment opens runway picker (opaque label only)
            if (simulationOperationModeId === 'DL' && !simulationIsMonitorOnly && simulationAircraftRwyTextBounds.length) {
                if (isSimulationTtsSpeakingNow()) return;
                const rwById = new Map(simulationAircraftRwyTextBounds.map(b => [b.aircraftId, b]));
                const opaqueId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId)
                    ? simulationDraggingAircraftId
                    : simulationHoveredAircraftLabelId;
                if (opaqueId) {
                    const b = rwById.get(opaqueId);
                    if (b && clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
                        openSimulationRwyPicker(opaqueId, e.clientX, e.clientY);
                        e.preventDefault();
                        e.stopPropagation();
                        return;
                    }
                }
            }

            // DCT click (DL mode, not monitor-only): left-click on HDG/DCT field opens waypoint picker (opaque label only)
            if (simulationOperationModeId === 'DL' && !simulationIsMonitorOnly && simulationAircraftHdgDctTextBounds.length) {
                if (isSimulationTtsSpeakingNow()) return;
                const hdgById = new Map(simulationAircraftHdgDctTextBounds.map(b => [b.aircraftId, b]));
                const opaqueId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId)
                    ? simulationDraggingAircraftId
                    : simulationHoveredAircraftLabelId;
                if (opaqueId) {
                    const b = hdgById.get(opaqueId);
                    if (b && clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
                        openSimulationDctPicker(opaqueId, e.clientX, e.clientY);
                        e.preventDefault();
                        e.stopPropagation();
                        return;
                    }
                }
            }

            // Speed select (left click on IAS/MACH field) opens IAS/MACH picker (not monitor-only)
            if (simulationOperationModeId === 'DL' && !simulationIsMonitorOnly && simulationAircraftSpeedTextBounds.length) {
                if (isSimulationTtsSpeakingNow()) return;
                const spById = new Map(simulationAircraftSpeedTextBounds.map(b => [b.aircraftId, b]));
                const opaqueId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId)
                    ? simulationDraggingAircraftId
                    : simulationHoveredAircraftLabelId;
                if (opaqueId) {
                    const b = spById.get(opaqueId);
                    if (b && clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
                        openSimulationSpeedPicker(opaqueId, e.clientX, e.clientY);
                        e.preventDefault();
                        e.stopPropagation();
                        return;
                    }
                }
            }

            // ROC/D select (left click on rate-of-climb field) opens ROC/D picker
            if (canUseSimulationLabelFieldPickers() && simulationAircraftRocTextBounds.length) {
                if (isSimulationTtsSpeakingNow()) return;
                const rocById = new Map(simulationAircraftRocTextBounds.map(b => [b.aircraftId, b]));
                const opaqueId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId)
                    ? simulationDraggingAircraftId
                    : simulationHoveredAircraftLabelId;
                if (opaqueId) {
                    const b = rocById.get(opaqueId);
                    if (b && clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
                        const rocAc = (window.simulationData?.aircraft || []).find(a => a && a.id === opaqueId);
                        if (rocAc && canOpenSimulationRocPicker(rocAc)) {
                            openSimulationRocPicker(opaqueId, e.clientX, e.clientY);
                            e.preventDefault();
                            e.stopPropagation();
                            return;
                        }
                    }
                }
            }

            // Free-text icon click (topmost label first; disabled when monitor-only)
            if (!simulationIsMonitorOnly && labelLayoutHasFreeText() && simulationAircraftFreeTextIconBounds.length) {
                const iconById = new Map(simulationAircraftFreeTextIconBounds.map(b => [b.aircraftId, b]));
                for (let zi = simulationLabelZOrder.length - 1; zi >= 0; zi--) {
                    const id = simulationLabelZOrder[zi];
                    const b = iconById.get(id);
                    if (!b) continue;
                    if (clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
                        openSimulationFreeTextModal(id);
                        e.preventDefault();
                        e.stopPropagation();
                        return;
                    }
                }
            }

            // Left-click aircraft symbol (not on label box): select for ring highlight
            {
                const symHit = getAircraftAtScreenPoint(clickX, clickY);
                if (symHit && symHit.aircraftId != null) {
                    const boundsById = new Map(simulationAircraftLabelBounds.map((b) => [b.aircraftId, b]));
                    const lb = boundsById.get(symHit.aircraftId);
                    const onLabelRect = lb
                        && clickX >= lb.x
                        && clickX <= lb.x + lb.w
                        && clickY >= lb.y
                        && clickY <= lb.y + lb.h;
                    if (!onLabelRect) {
                        simulationSelectedAircraftId = symHit.aircraftId;
                        drawSimulationCanvas();
                        syncAdvancedLabelPanel();
                        try { syncSimulationEnMgmtSelectedAircraftHighlight({ scrollIntoView: true }); } catch (eEn) {}
                        e.preventDefault();
                        e.stopPropagation();
                        return;
                    }
                }
            }
            
            // If label move is configured to left click, label drag has already been handled above.

            // Otherwise, start dragging (map pan) — clear aircraft selection
            simulationSelectedAircraftId = null;
            syncAdvancedLabelPanel();
            try { syncSimulationEnMgmtSelectedAircraftHighlight({ scrollIntoView: false }); } catch (eEn) {}
            isDragging = true;
            panDragStarted = true;
            dragStartX = e.clientX;
            dragStartY = e.clientY;
            dragStartPanX = simulationPanX;
            dragStartPanY = simulationPanY;
            recordSimulationEvent('map_pan_start', {
                panX: simulationRecordingRoundNumber(simulationPanX, 2),
                panY: simulationRecordingRoundNumber(simulationPanY, 2),
                x: simulationRecordingRoundNumber(clickX, 2),
                y: simulationRecordingRoundNumber(clickY, 2)
            });
        } else if (e.button === 2) { // Right mouse button - start measuring
            e.preventDefault();

            // If the mouse is on an aircraft label, do NOT trigger measuring.
            // (Prevents accidental measuring while working around labels.)
            if (simulationAircraftLabelBounds.length) {
                // Prefer hovered label, but also fall back to any label under cursor
                const boundsById = new Map(simulationAircraftLabelBounds.map(b => [b.aircraftId, b]));
                const hb = simulationHoveredAircraftLabelId ? boundsById.get(simulationHoveredAircraftLabelId) : null;
                const isInside = (b) => b && clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h;
                let onLabel = isInside(hb);
                if (!onLabel) {
                    for (let zi = simulationLabelZOrder.length - 1; zi >= 0; zi--) {
                        const id = simulationLabelZOrder[zi];
                        const b = boundsById.get(id);
                        if (isInside(b)) { onLabel = true; break; }
                    }
                }
                if (onLabel) {
                    // Right-click on DCT field starts DCT path drawing (define path with waypoints, then rejoin on trajectory)
                    if (simulationOperationModeId === 'DL' && !simulationIsMonitorOnly && simulationAircraftHdgDctTextBounds.length) {
                        const hdgById = new Map(simulationAircraftHdgDctTextBounds.map(b => [b.aircraftId, b]));
                        const opaqueId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId)
                            ? simulationDraggingAircraftId
                            : simulationHoveredAircraftLabelId;
                        if (opaqueId) {
                            const b = hdgById.get(opaqueId);
                            if (b && clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
                                const ac = (window.simulationData?.aircraft || []).find(a => a && a.id === opaqueId);
                                const acDct = ac ? getAircraftForDctTrajectoryUi(ac) : null;
                                if (ac && acDct && Array.isArray(acDct.points) && acDct.points.length >= 1) {
                                    simulationDctPathDrawingAircraftId = opaqueId;
                                    simulationDctPathPoints = [];
                                    simulationDctPathMouse = { x: clickX, y: clickY };
                                    try { markSimulationAircraftTtsInputStart(ac, 'DCT'); } catch (e) {}
                                    drawSimulationCanvas();
                                    rightMouseDown = false;
                                    return;
                                }
                            }
                        }
                    }
                    // Right-click on speed field cycles IAS/MACH/SELECTED for the opaque label
                    if (simulationOperationModeId === 'DL' && !simulationIsMonitorOnly && simulationAircraftSpeedTextBounds.length) {
                        const spById = new Map(simulationAircraftSpeedTextBounds.map(b => [b.aircraftId, b]));
                        const opaqueId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId)
                            ? simulationDraggingAircraftId
                            : simulationHoveredAircraftLabelId;
                        if (opaqueId) {
                            const sb = spById.get(opaqueId);
                            if (sb && clickX >= sb.x && clickX <= sb.x + sb.w && clickY >= sb.y && clickY <= sb.y + sb.h) {
                                const ac = (window.simulationData.aircraft || []).find(a => a && a.id === opaqueId);
                                if (ac) {
                                    cycleAircraftSpeedReadoutMode(ac);
                                    drawSimulationCanvas();
                                }
                                rightMouseDown = false;
                                return;
                            }
                        }
                    }
                    // Right-click on ROC/D toggles LIVE vs SELECTED readout
                    if (canUseSimulationLabelFieldPickers() && simulationAircraftRocTextBounds.length) {
                        const rocById = new Map(simulationAircraftRocTextBounds.map(b => [b.aircraftId, b]));
                        const opaqueId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId)
                            ? simulationDraggingAircraftId
                            : simulationHoveredAircraftLabelId;
                        if (opaqueId) {
                            const rb = rocById.get(opaqueId);
                            if (rb && clickX >= rb.x && clickX <= rb.x + rb.w && clickY >= rb.y && clickY <= rb.y + rb.h) {
                                const ac = (window.simulationData.aircraft || []).find(a => a && a.id === opaqueId);
                                if (ac) {
                                    cycleAircraftRocReadoutMode(ac);
                                    drawSimulationCanvas();
                                }
                                rightMouseDown = false;
                                return;
                            }
                        }
                    }
                    rightMouseDown = false;
                    return;
                }
            }
            // Right-click while in DCT path mode: discard all inputs and exit
            if (simulationDctPathDrawingAircraftId) {
                e.preventDefault();
                e.stopPropagation();
                simulationSuppressNextContextMenu = true; // prevent browser "Inspect" menu
                cancelDctPathMode();
                drawSimulationCanvas();
                rightMouseDown = false;
                return;
            }

            rightMouseDown = true;
            
            if (!window.simulationData) return;
            
            const rect = simulationCanvas.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;

            const hit = getAircraftAtScreenPoint(x, y);
            if (hit && hit.aircraftId) {
                measureStartEndpoint = { type: 'aircraft', aircraftId: hit.aircraftId };
            } else {
                // Convert screen coordinates to geographic coordinates
                const simWaypoints = window.simulationData.waypoints || [];
                const simCentreWaypoint = simWaypoints.find(wp => isCenterWaypointName(wp?.name));
                
                const simOriginX = simulationCanvas.width / 2;
                const simOriginY = simulationCanvas.height / 2;
                const effectiveOriginX = simOriginX + simulationPanX;
                const effectiveOriginY = simOriginY + simulationPanY;
                const lonScale = getSimulationLonCosScale();

                const relLon = (x - effectiveOriginX) / (simulationZoomLevel * lonScale);
                const relLat = -(y - effectiveOriginY) / simulationZoomLevel;
                
                let lat = relLat;
                let lon = relLon;
                if (simCentreWaypoint) {
                    lat = relLat + simCentreWaypoint.latitude;
                    lon = relLon + simCentreWaypoint.longitude;
                }
                measureStartEndpoint = { type: 'coord', lat, lon };
            }

            isMeasuring = true;
            measureEndEndpoint = null;
            measureCurrentMousePos = { x, y };
            measureCurrentEndAircraftId = null;
            activeMeasurementColor = getNextMeasurementColor();
            if (simulationRecording) {
                simulationRecordingActiveMeasurement = {
                    id: `m_${++simulationRecordingMeasurementSeq}`,
                    visibleFromSimSec: getSimulationClockSeconds()
                };
            }
            recordSimulationEvent('measurement_start', {
                id: simulationRecordingActiveMeasurement?.id || '',
                start: measureStartEndpoint,
                color: activeMeasurementColor,
                x: simulationRecordingRoundNumber(x, 2),
                y: simulationRecordingRoundNumber(y, 2)
            });
            
            drawSimulationCanvas();
        } else if (e.button === 1) { // Middle mouse button
            e.preventDefault();
            if (!window.simulationData) return;
            // (rect/clickX/clickY computed above)

            // Middle-click on HDG/DCT starts heading select (opaque label only; not monitor-only)
            if (simulationOperationModeId === 'DL' && !simulationIsMonitorOnly && simulationAircraftHdgDctTextBounds.length) {
                if (isSimulationTtsSpeakingNow()) return;
                const hdgById = new Map(simulationAircraftHdgDctTextBounds.map(b => [b.aircraftId, b]));
                const opaqueId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId)
                    ? simulationDraggingAircraftId
                    : simulationHoveredAircraftLabelId;
                if (opaqueId) {
                    const b = hdgById.get(opaqueId);
                    if (b && clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
                        simulationIsSelectingHeading = true;
                        simulationSelectingHeadingAircraftId = opaqueId;
                        simulationHeadingSelectMouse = { x: clickX, y: clickY };
                        try {
                            const ac = (window.simulationData?.aircraft || []).find(a => a && a.id === opaqueId);
                            if (ac) markSimulationAircraftTtsInputStart(ac, 'HDG');
                        } catch (e) {}
                        drawSimulationCanvas();
                        return;
                    }
                }
            }

            // Hold-to-probe XLV: middle-click and hold on XLV value
            const probingMode = (simulationSettings?.probingLevelMode || SIM_SETTINGS_DEFAULTS.probingLevelMode || 'off').toString().toLowerCase();
            if ((probingMode === 'on' || probingMode === 'same_route' || probingMode === 'same_crossing_routes') && simulationAircraftXlvTextBounds.length) {
                const xlvById = new Map(simulationAircraftXlvTextBounds.map(b => [b.aircraftId, b]));
                const opaqueId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId)
                    ? simulationDraggingAircraftId
                    : simulationHoveredAircraftLabelId;
                if (opaqueId) {
                    const b = xlvById.get(opaqueId);
                    if (b && clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
                        const ac = (window.simulationData.aircraft || []).find(a => a && a.id === opaqueId);
                        const fl = parseInt(ac?.exitLevelFl ?? ac?.rlv, 10);
                        if (Number.isFinite(fl)) {
                            simulationXlvHoldProbeActive = true;
                            simulationXlvHoldProbeSourceId = opaqueId;
                            simulationXlvHoldProbeFl = fl;
                            drawSimulationCanvas();
                            return; // reserve middle-click for this label input
                        }
                    }
                }
            }

            // Middle-click on any ETA estimate removes trajectory for that aircraft
            for (let i = simulationTrajectoryEstimateBounds.length - 1; i >= 0; i--) {
                const b = simulationTrajectoryEstimateBounds[i];
                if (!b) continue;
                if (clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h) {
                    toggleSimulationTrajectoryForAircraftId(b.aircraftId, { forceOff: true }).then(() => drawSimulationCanvas());
                    return;
                }
            }

            // Middle-click on callsign toggles trajectory for the topmost label under cursor
            if (simulationAircraftCallsignTextBounds.length) {
                const csById = new Map(simulationAircraftCallsignTextBounds.map(b => [b.aircraftId, b]));
                const isInside = (b) => b && clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h;

                // Prefer the actively dragged label (if any), otherwise use z-order.
                const preferredId = (simulationIsDraggingAircraftLabel && simulationDraggingAircraftId) ? simulationDraggingAircraftId : null;
                if (preferredId) {
                    const b = csById.get(preferredId);
                    if (isInside(b)) {
                        toggleSimulationTrajectoryForAircraftId(preferredId).then(() => drawSimulationCanvas());
                        return;
                    }
                }
                for (let zi = simulationLabelZOrder.length - 1; zi >= 0; zi--) {
                    const id = simulationLabelZOrder[zi];
                    const b = csById.get(id);
                    if (!isInside(b)) continue;
                    toggleSimulationTrajectoryForAircraftId(id).then(() => drawSimulationCanvas());
                    return;
                }
            }

            // Middle-click on aircraft symbol only (not on label box): cycle label anchor clockwise (45° steps, same leader length)
            {
                const symHit = getAircraftAtScreenPoint(clickX, clickY);
                if (symHit && symHit.aircraftId != null) {
                    const boundsById = new Map(simulationAircraftLabelBounds.map((b) => [b.aircraftId, b]));
                    const lb = boundsById.get(symHit.aircraftId);
                    const onLabelRect =
                        lb &&
                        clickX >= lb.x &&
                        clickX <= lb.x + lb.w &&
                        clickY >= lb.y &&
                        clickY <= lb.y + lb.h;
                    if (!onLabelRect) {
                        const ac = (window.simulationData.aircraft || []).find((a) => a && a.id === symHit.aircraftId);
                        if (ac && !ac.hideLabel) {
                            advanceSimulationLabelAnchorClockwise(ac);
                            drawSimulationCanvas();
                            return;
                        }
                    }
                }
            }

            // Middle-click on leader line toggles per-aircraft SPV when global SPV is off
            if (!simulationSettings?.spvEnabled && simulationAircraftLeaderLineBounds.length) {
                const LEADER_HIT_PX = 6;
                const AC_SYMBOL_SKIP_PX = 8;
                const leaderById = new Map(simulationAircraftLeaderLineBounds.map((b) => [b.aircraftId, b]));
                for (let zi = simulationLabelZOrder.length - 1; zi >= 0; zi--) {
                    const id = simulationLabelZOrder[zi];
                    const lb = leaderById.get(id);
                    if (!lb) continue;
                    if (Math.hypot(clickX - lb.x1, clickY - lb.y1) <= AC_SYMBOL_SKIP_PX) continue;
                    if (distanceToSegment(clickX, clickY, lb.x1, lb.y1, lb.x2, lb.y2) <= LEADER_HIT_PX) {
                        toggleSimulationSpvForAircraftId(id);
                        drawSimulationCanvas();
                        return;
                    }
                }
            }

            // Middle-click deletes measurements ONLY when not interacting with a hovered label.
            // (In hover mode, middle-click is reserved for label inputs like callsign/trajectory.)
            const isClickOnAnyLabel = () => {
                if (!simulationAircraftLabelBounds.length) return false;
                const boundsById = new Map(simulationAircraftLabelBounds.map(b => [b.aircraftId, b]));
                const isInside = (b) => b && clickX >= b.x && clickX <= b.x + b.w && clickY >= b.y && clickY <= b.y + b.h;
                // z-order aware (topmost first)
                for (let zi = simulationLabelZOrder.length - 1; zi >= 0; zi--) {
                    const id = simulationLabelZOrder[zi];
                    const b = boundsById.get(id);
                    if (isInside(b)) return true;
                }
                return false;
            };

            if (!isClickOnAnyLabel()) {
                // Middle-click on measurement text removes that measurement
                // (Check in reverse order to handle overlapping measurement labels)
                for (let i = measurementTextBounds.length - 1; i >= 0; i--) {
                    const bounds = measurementTextBounds[i];
                    if (!bounds) continue;
                    const padding = 2;
                    if (clickX >= bounds.x - padding && clickX <= bounds.x + bounds.width + padding &&
                        clickY >= bounds.y - padding && clickY <= bounds.y + bounds.height + padding) {
                        const removedMeasurement = measurements[bounds.index] ? JSON.parse(JSON.stringify(measurements[bounds.index])) : null;
                        measurements.splice(bounds.index, 1);
                        recordSimulationEvent('measurement_delete', {
                            index: bounds.index,
                            id: removedMeasurement?.id || '',
                            hiddenAtSimSec: getSimulationClockSeconds(),
                            measurement: removedMeasurement
                        });
                        drawSimulationCanvas();
                        return;
                    }
                }
            }
        }
    };
    simulationCanvas.addEventListener('mousedown', handlers.mousedown);
    
    handlers.mousemove = function(e) {
        if (simulationIsSelectingHeading) {
            const rect = simulationCanvas.getBoundingClientRect();
            const mx = e.clientX - rect.left;
            const my = e.clientY - rect.top;
            simulationHeadingSelectMouse = { x: mx, y: my };
            drawSimulationCanvas();
            return;
        }
        if (simulationDctPathDrawingAircraftId) {
            const rect = simulationCanvas.getBoundingClientRect();
            const mx = e.clientX - rect.left;
            const my = e.clientY - rect.top;
            simulationDctPathMouse = { x: mx, y: my };
            drawSimulationCanvas();
            return;
        }
        if (simulationIsDraggingAircraftLabel && window.simulationData) {
            const rect = simulationCanvas.getBoundingClientRect();
            const mx = e.clientX - rect.left;
            const my = e.clientY - rect.top;

            // Find current bound entry for this aircraft (contains current aircraft x/y)
            const b = simulationAircraftLabelBounds.find(x => x && x.aircraftId === simulationDraggingAircraftId);
            if (b) {
                const newLabelX = mx - simulationLabelDragAnchorX;
                const newLabelY = my - simulationLabelDragAnchorY;
                // Offsets are aircraft → label center (top-left of box + half size)
                const cx = newLabelX + b.w / 2;
                const cy = newLabelY + b.h / 2;
                const dx = cx - b.acX;
                const dy = cy - b.acY;

                const ac = (window.simulationData.aircraft || []).find(a => a && a.id === simulationDraggingAircraftId);
                if (ac) {
                    ac.labelOffsetX = dx;
                    ac.labelOffsetY = dy;
                    ac.labelLeaderOffsetToCenter = true;
                }
                if (simulationLabelDragDrawRafId == null) {
                    simulationLabelDragDrawRafId = requestAnimationFrame(() => {
                        simulationLabelDragDrawRafId = null;
                        drawSimulationCanvas();
                    });
                }
            }
            return;
        }

        if (isDragging) {
            const deltaX = e.clientX - dragStartX;
            const deltaY = e.clientY - dragStartY;
            
            simulationPanX = dragStartPanX + deltaX;
            simulationPanY = dragStartPanY + deltaY;
            
            drawSimulationCanvas();
        } else if (isMeasuring && rightMouseDown) {
            // Update measurement line while dragging
            const rect = simulationCanvas.getBoundingClientRect();
            const mouseX = e.clientX - rect.left;
            const mouseY = e.clientY - rect.top;
            
            measureCurrentMousePos = { x: mouseX, y: mouseY };
            const hit = getAircraftAtScreenPoint(mouseX, mouseY);
            measureCurrentEndAircraftId = hit?.aircraftId || null;
            drawSimulationCanvas();
        }

        // Hover detection for aircraft label background
        if (!window.simulationData) return;
        const rect = simulationCanvas.getBoundingClientRect();
        const mx = e.clientX - rect.left;
        const my = e.clientY - rect.top;

        // Determine hovered label by z-order (topmost first)
        let hovered = null;
        const boundsById = new Map(simulationAircraftLabelBounds.map(b => [b.aircraftId, b]));
        for (let zi = simulationLabelZOrder.length - 1; zi >= 0; zi--) {
            const id = simulationLabelZOrder[zi];
            const b = boundsById.get(id);
            if (!b) continue;
            if (mx >= b.x && mx <= b.x + b.w && my >= b.y && my <= b.y + b.h) {
                hovered = id;
                break;
            }
        }

        if (String(hovered ?? '') !== String(simulationHoveredAircraftLabelId ?? '')) {
            simulationHoveredAircraftLabelId = hovered;
            // Bring last-hovered to front (top layer)
            if (hovered) {
                simulationLabelZOrder = simulationLabelZOrder.filter(id => id !== hovered);
                simulationLabelZOrder.push(hovered);
            }
            drawSimulationCanvas();
        }
    };
    simulationCanvas.addEventListener('mousemove', handlers.mousemove);
    
    handlers.mouseup = function(e) {
        // Release hold-to-probe XLV on middle button up
        if (e.button === 1 && simulationXlvHoldProbeActive) {
            simulationXlvHoldProbeActive = false;
            simulationXlvHoldProbeSourceId = null;
            simulationXlvHoldProbeFl = null;
            drawSimulationCanvas();
        }

        // End label dragging on mouseup (any button) so it works for left/middle/right selection
        if (simulationIsDraggingAircraftLabel) {
            const endedAircraftId = simulationDraggingAircraftId;
            const endedAc = (window.simulationData?.aircraft || []).find(a => a && a.id === endedAircraftId);
            recordSimulationEvent('label_drag_end', {
                start: labelDragRecordingStart,
                labelOffsetX: simulationRecordingRoundNumber(endedAc?.labelOffsetX, 2),
                labelOffsetY: simulationRecordingRoundNumber(endedAc?.labelOffsetY, 2)
            }, endedAc);
            labelDragRecordingStart = null;
            if (simulationLabelDragDrawRafId != null) {
                cancelAnimationFrame(simulationLabelDragDrawRafId);
                simulationLabelDragDrawRafId = null;
            }
            simulationIsDraggingAircraftLabel = false;
            simulationDraggingAircraftId = null;
            isDragging = false;
            drawSimulationCanvas();
            return;
        }

        if (e.button === 0) { // Left mouse button
            if (isDragging && panDragStarted) {
                recordSimulationEvent('map_pan_end', {
                    oldPanX: simulationRecordingRoundNumber(dragStartPanX, 2),
                    oldPanY: simulationRecordingRoundNumber(dragStartPanY, 2),
                    newPanX: simulationRecordingRoundNumber(simulationPanX, 2),
                    newPanY: simulationRecordingRoundNumber(simulationPanY, 2),
                    deltaX: simulationRecordingRoundNumber(simulationPanX - dragStartPanX, 2),
                    deltaY: simulationRecordingRoundNumber(simulationPanY - dragStartPanY, 2)
                });
            }
            isDragging = false;
            panDragStarted = false;
        } else if (e.button === 2 && isMeasuring && rightMouseDown) { // Right mouse button - finish measuring
            e.preventDefault();
            rightMouseDown = false;
            
            const rect = simulationCanvas.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;

            const hit = getAircraftAtScreenPoint(x, y);
            if (hit && hit.aircraftId) {
                measureEndEndpoint = { type: 'aircraft', aircraftId: hit.aircraftId };
            } else {
                // Convert screen coordinates to geographic coordinates
                const simWaypoints = window.simulationData.waypoints || [];
                const simCentreWaypoint = simWaypoints.find(wp => isCenterWaypointName(wp?.name));
                
                const simOriginX = simulationCanvas.width / 2;
                const simOriginY = simulationCanvas.height / 2;
                const effectiveOriginX = simOriginX + simulationPanX;
                const effectiveOriginY = simOriginY + simulationPanY;
                const lonScale = getSimulationLonCosScale();

                const relLon = (x - effectiveOriginX) / (simulationZoomLevel * lonScale);
                const relLat = -(y - effectiveOriginY) / simulationZoomLevel;
                
                let lat = relLat;
                let lon = relLon;
                if (simCentreWaypoint) {
                    lat = relLat + simCentreWaypoint.latitude;
                    lon = relLon + simCentreWaypoint.longitude;
                }
                measureEndEndpoint = { type: 'coord', lat, lon };
            }

            if (measureStartEndpoint && measureEndEndpoint) {
                const measurement = {
                    id: simulationRecordingActiveMeasurement?.id || `m_${++simulationRecordingMeasurementSeq}`,
                    visibleFromSimSec: simulationRecordingActiveMeasurement?.visibleFromSimSec ?? getSimulationClockSeconds(),
                    start: { ...measureStartEndpoint },
                    end: { ...measureEndEndpoint },
                    color: activeMeasurementColor || getNextMeasurementColor()
                };
                measurements.push(measurement);
                recordSimulationEvent('measurement_add', {
                    measurement: JSON.parse(JSON.stringify(measurement)),
                    index: measurements.length - 1,
                    id: measurement.id,
                    visibleFromSimSec: measurement.visibleFromSimSec
                });
            }
            
            isMeasuring = false;
            measureStartEndpoint = null;
            measureEndEndpoint = null;
            measureCurrentMousePos = null;
            measureCurrentEndAircraftId = null;
            activeMeasurementColor = null;
            simulationRecordingActiveMeasurement = null;
            
            drawSimulationCanvas();
        }
    };
    simulationCanvas.addEventListener('mouseup', handlers.mouseup);
    
    handlers.mouseleave = function() {
        if (isDragging && panDragStarted) {
            recordSimulationEvent('map_pan_end', {
                oldPanX: simulationRecordingRoundNumber(dragStartPanX, 2),
                oldPanY: simulationRecordingRoundNumber(dragStartPanY, 2),
                newPanX: simulationRecordingRoundNumber(simulationPanX, 2),
                newPanY: simulationRecordingRoundNumber(simulationPanY, 2),
                deltaX: simulationRecordingRoundNumber(simulationPanX - dragStartPanX, 2),
                deltaY: simulationRecordingRoundNumber(simulationPanY - dragStartPanY, 2),
                reason: 'mouseleave'
            });
        }
        if (simulationIsDraggingAircraftLabel) {
            const endedAircraftId = simulationDraggingAircraftId;
            const endedAc = (window.simulationData?.aircraft || []).find(a => a && a.id === endedAircraftId);
            recordSimulationEvent('label_drag_end', {
                start: labelDragRecordingStart,
                labelOffsetX: simulationRecordingRoundNumber(endedAc?.labelOffsetX, 2),
                labelOffsetY: simulationRecordingRoundNumber(endedAc?.labelOffsetY, 2),
                reason: 'mouseleave'
            }, endedAc);
            labelDragRecordingStart = null;
        }
        isDragging = false;
        panDragStarted = false;
        simulationIsDraggingAircraftLabel = false;
        simulationDraggingAircraftId = null;
        if (simulationIsSelectingHeading) {
            try {
                const id = simulationSelectingHeadingAircraftId;
                const ac = id ? (window.simulationData?.aircraft || []).find(a => a && a.id === id) : null;
                if (ac) markSimulationAircraftTtsInputEnd(ac, 'HDG');
            } catch (e) {}
            simulationIsSelectingHeading = false;
            simulationSelectingHeadingAircraftId = null;
            simulationHeadingSelectMouse = null;
        }
        if (simulationDctPathDrawingAircraftId) {
            if (dctRouteNamesPopupEl && dctRouteNamesPopupEl.parentNode) {
                // Route names popup is open: don't cancel so user can move to it and select a route
            } else {
                cancelDctPathMode();
                drawSimulationCanvas();
            }
        }
        if (simulationXlvHoldProbeActive) {
            simulationXlvHoldProbeActive = false;
            simulationXlvHoldProbeSourceId = null;
            simulationXlvHoldProbeFl = null;
        }
        if (simulationHoveredAircraftLabelId !== null) {
            simulationHoveredAircraftLabelId = null;
            drawSimulationCanvas();
        }
    };
    simulationCanvas.addEventListener('mouseleave', handlers.mouseleave);
    
    // Prevent context menu on right-click when measuring or interacting with labels
    handlers.contextmenu = function(e) {
        if (simulationSuppressNextContextMenu) {
            simulationSuppressNextContextMenu = false;
            e.preventDefault();
            return;
        }
        if (simulationIsSelectingHeading) {
            e.preventDefault();
            return;
        }
        if (simulationDctPathDrawingAircraftId) {
            e.preventDefault();
            return;
        }
        // Always block browser context menu when on a label (prevents "Inspect")
        try {
            const rect = simulationCanvas.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;
            const boundsById = new Map(simulationAircraftLabelBounds.map(b => [b.aircraftId, b]));
            const hb = simulationHoveredAircraftLabelId ? boundsById.get(simulationHoveredAircraftLabelId) : null;
            const isInside = (b) => b && x >= b.x && x <= b.x + b.w && y >= b.y && y <= b.y + b.h;
            let onLabel = isInside(hb);
            if (!onLabel) {
                for (let zi = simulationLabelZOrder.length - 1; zi >= 0; zi--) {
                    const id = simulationLabelZOrder[zi];
                    const b = boundsById.get(id);
                    if (isInside(b)) { onLabel = true; break; }
                }
            }
            if (onLabel) {
                e.preventDefault();
                return;
            }
        } catch (err) {}

        if (rightMouseDown || isMeasuring) e.preventDefault();
    };
    simulationCanvas.addEventListener('contextmenu', handlers.contextmenu);
    
    // Keyboard shortcut: 'S' key to center map at CENTRE waypoint
    // Store handler reference to avoid duplicate listeners
    if (!window.simulationCenterKeyHandler) {
        window.simulationCenterKeyHandler = function(e) {
            // Only handle if simulation modal is active
            const simulationModal = document.getElementById('simulationModal');
            if (!simulationModal || !simulationModal.classList.contains('active')) {
                return;
            }
            
            // Don't trigger if user is typing in an input field
            if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable) {
                return;
            }
            
            if (e.key === 'S' || e.key === 's') {
                e.preventDefault();
                e.stopPropagation();
                centerMapAtCentre();
            }
        };
        
        // Add keyboard listener to document
        document.addEventListener('keydown', window.simulationCenterKeyHandler);
    }
}

// Calculate distance in nautical miles between two geographic points using Haversine formula
function calculateNauticalMiles(lat1, lon1, lat2, lon2) {
    if (!isFinite(lat1) || !isFinite(lon1) || !isFinite(lat2) || !isFinite(lon2)) {
        return 0;
    }
    
    // Convert degrees to radians
    const R = 3440.065; // Earth's radius in nautical miles
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLon / 2) * Math.sin(dLon / 2);
    
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    const distance = R * c;
    
    return isFinite(distance) ? distance : 0;
}

/** cos(refLat) for equirectangular X: lon × cos φ₀ so east–west and north–south NM match on screen near CENTRE. */
function getSimulationLonCosScale() {
    const wps = window.simulationData?.waypoints;
    if (!Array.isArray(wps) || wps.length === 0) return 1;
    const centre = wps.find((wp) => isCenterWaypointName(wp?.name));
    let refLat = null;
    if (centre && isFinite(centre.latitude)) refLat = centre.latitude;
    else {
        let sum = 0;
        let n = 0;
        for (let i = 0; i < wps.length; i++) {
            const wp = wps[i];
            if (wp && isFinite(wp.latitude)) {
                sum += wp.latitude;
                n++;
            }
        }
        if (n > 0) refLat = sum / n;
    }
    if (refLat == null || !isFinite(refLat)) return 1;
    const c = Math.cos((refLat * Math.PI) / 180);
    if (!isFinite(c) || Math.abs(c) < 1e-10) return 1;
    return c;
}

/** cos(refLat) for Edit Airspace map — equirectangular lon × cos φ₀ (same idea as simulation). */
function getSectorMapLonCosScale() {
    updateCentreWaypoint();
    if (centreWaypoint && isFinite(centreWaypoint.latitude)) {
        const c = Math.cos((centreWaypoint.latitude * Math.PI) / 180);
        if (isFinite(c) && Math.abs(c) >= 1e-10) return c;
        return 1;
    }
    if (!Array.isArray(waypoints) || waypoints.length === 0) return 1;
    let sum = 0;
    let n = 0;
    for (let i = 0; i < waypoints.length; i++) {
        const wp = waypoints[i];
        if (wp && isFinite(wp.latitude)) {
            sum += wp.latitude;
            n++;
        }
    }
    if (n === 0) return 1;
    const refLat = sum / n;
    const c = Math.cos((refLat * Math.PI) / 180);
    if (!isFinite(c) || Math.abs(c) < 1e-10) return 1;
    return c;
}

/** Equirectangular lon scale for Edit Exercise map (same cos(refLat) idea as {@link getSectorMapLonCosScale}). */
function getExerciseEditorLonCosScale(waypointsList) {
    const wps = Array.isArray(waypointsList) ? waypointsList : [];
    const centre = wps.find(wp => isCenterWaypointName(wp?.name));
    if (centre && isFinite(centre.latitude)) {
        const c = Math.cos((centre.latitude * Math.PI) / 180);
        if (isFinite(c) && Math.abs(c) >= 1e-10) return c;
        return 1;
    }
    let sum = 0;
    let n = 0;
    for (let i = 0; i < wps.length; i++) {
        const wp = wps[i];
        if (wp && isFinite(wp.latitude)) {
            sum += wp.latitude;
            n++;
        }
    }
    if (n === 0) return 1;
    const refLat = sum / n;
    const c = Math.cos((refLat * Math.PI) / 180);
    if (!isFinite(c) || Math.abs(c) < 1e-10) return 1;
    return c;
}

// Simulation canvas: screen (canvas) coords to lat/lon
function simulationScreenToLatLon(screenX, screenY) {
    if (!simulationCanvas || !window.simulationData) return null;
    const simWaypoints = window.simulationData.waypoints || [];
    const simCentreWaypoint = simWaypoints.find(wp => isCenterWaypointName(wp?.name));
    const simOriginX = simulationCanvas.width / 2;
    const simOriginY = simulationCanvas.height / 2;
    const effectiveOriginX = simOriginX + simulationPanX;
    const effectiveOriginY = simOriginY + simulationPanY;
    const lonScale = getSimulationLonCosScale();
    const relLon = (screenX - effectiveOriginX) / (simulationZoomLevel * lonScale);
    const relLat = -(screenY - effectiveOriginY) / simulationZoomLevel;
    let lat = relLat;
    let lon = relLon;
    if (simCentreWaypoint && isFinite(simCentreWaypoint.latitude) && isFinite(simCentreWaypoint.longitude)) {
        lat = relLat + simCentreWaypoint.latitude;
        lon = relLon + simCentreWaypoint.longitude;
    }
    return isFinite(lat) && isFinite(lon) ? { lat, lon } : null;
}

// Simulation canvas: lat/lon to screen (canvas) coords
function simulationLatLonToScreen(lat, lon) {
    if (!simulationCanvas || !window.simulationData || !isFinite(lat) || !isFinite(lon)) return null;
    const simWaypoints = window.simulationData.waypoints || [];
    const simCentreWaypoint = simWaypoints.find(wp => isCenterWaypointName(wp?.name));
    const simOriginX = simulationCanvas.width / 2;
    const simOriginY = simulationCanvas.height / 2;
    const effectiveOriginX = simOriginX + simulationPanX;
    const effectiveOriginY = simOriginY + simulationPanY;
    let rLon = lon;
    let rLat = lat;
    if (simCentreWaypoint && isFinite(simCentreWaypoint.latitude) && isFinite(simCentreWaypoint.longitude)) {
        rLon = lon - simCentreWaypoint.longitude;
        rLat = lat - simCentreWaypoint.latitude;
    }
    const lonScale = getSimulationLonCosScale();
    const x = effectiveOriginX + rLon * simulationZoomLevel * lonScale;
    const y = effectiveOriginY - rLat * simulationZoomLevel;
    return isFinite(x) && isFinite(y) ? { x, y } : null;
}

/**
 * Eight label directions: clockwise from screen-up (0°=up, 45°, …, 315°).
 * Exact unit vectors — avoids Math.sin/cos float error at 90°/270° breaking atan2 recovery.
 */
const SIM_LABEL_ANCHOR_K = Math.SQRT1_2;
const SIM_LABEL_ANCHOR_UX = [0, SIM_LABEL_ANCHOR_K, 1, SIM_LABEL_ANCHOR_K, 0, -SIM_LABEL_ANCHOR_K, -1, -SIM_LABEL_ANCHOR_K];
const SIM_LABEL_ANCHOR_UY = [-1, -SIM_LABEL_ANCHOR_K, 0, SIM_LABEL_ANCHOR_K, 1, SIM_LABEL_ANCHOR_K, 0, -SIM_LABEL_ANCHOR_K];

/** Smallest t in (0,1] where segment A→B meets the rectangle boundary (for A outside, B inside label). */
function segmentFirstBoundaryT(ax, ay, bx, by, rx, ry, rw, rh) {
    const dx = bx - ax;
    const dy = by - ay;
    if (dx * dx + dy * dy < 1e-12) return null;
    const x0 = rx;
    const x1 = rx + rw;
    const y0 = ry;
    const y1 = ry + rh;
    let tMin = Infinity;
    const tryVert = (xv) => {
        if (Math.abs(dx) < 1e-12) return;
        const t = (xv - ax) / dx;
        if (t < 1e-9 || t > 1) return;
        const y = ay + t * dy;
        if (y >= y0 - 1e-6 && y <= y1 + 1e-6) tMin = Math.min(tMin, t);
    };
    const tryHoriz = (yv) => {
        if (Math.abs(dy) < 1e-12) return;
        const t = (yv - ay) / dy;
        if (t < 1e-9 || t > 1) return;
        const x = ax + t * dx;
        if (x >= x0 - 1e-6 && x <= x1 + 1e-6) tMin = Math.min(tMin, t);
    };
    tryVert(x0);
    tryVert(x1);
    tryHoriz(y0);
    tryHoriz(y1);
    if (!isFinite(tMin) || tMin > 1) return null;
    return tMin;
}

function labelAnchorIndexFromOffset(dx, dy) {
    const L = Math.hypot(dx, dy);
    if (L < 1e-9) return 0;
    const ux = dx / L;
    const uy = dy / L;
    let best = 0;
    let bestD = Infinity;
    for (let i = 0; i < 8; i++) {
        const d =
            (ux - SIM_LABEL_ANCHOR_UX[i]) * (ux - SIM_LABEL_ANCHOR_UX[i]) +
            (uy - SIM_LABEL_ANCHOR_UY[i]) * (uy - SIM_LABEL_ANCHOR_UY[i]);
        if (d < bestD) {
            bestD = d;
            best = i;
        }
    }
    return best;
}

function advanceSimulationLabelAnchorClockwise(ac) {
    if (!ac) return;
    const dx0 = Number.isFinite(ac.labelOffsetX) ? ac.labelOffsetX : 28;
    const dy0 = Number.isFinite(ac.labelOffsetY) ? ac.labelOffsetY : -28;
    // Offsets are aircraft → label center (after migration). Hypot = leader length.
    const L = Math.max(Math.hypot(dx0, dy0), 1e-3);
    const curIdx = labelAnchorIndexFromOffset(dx0, dy0);
    const nextIdx = (curIdx + 1) % 8;
    ac.labelOffsetX = L * SIM_LABEL_ANCHOR_UX[nextIdx];
    ac.labelOffsetY = L * SIM_LABEL_ANCHOR_UY[nextIdx];
    ac.labelLeaderOffsetToCenter = true;
}

function cancelDctPathMode() {
    const id = simulationDctPathDrawingAircraftId;
    simulationDctPathDrawingAircraftId = null;
    simulationDctPathPoints = [];
    simulationDctPathMouse = null;
    simulationDctRouteLookup = null;
    simulationDctRouteLookupSegments = [];
    simulationDctRouteLookupHoveredSegmentIndex = null;
    try { hideDctRouteNamesPopup(); } catch (e) {}
    try {
        const ac = id ? (window.simulationData?.aircraft || []).find(a => a && a.id === id) : null;
        if (ac) markSimulationAircraftTtsInputEnd(ac, 'DCT');
    } catch (e) {}
}

// Apply user-defined DCT path: new trajectory = (current pos) + path points (WP01 for unnamed) then rejoin waypoint then rest of old trajectory
// Prepend current position as hidden points[0] so segment 0 is current -> first path waypoint (first waypoint is not skipped)
function applyDctPathToAircraft(ac, pathPoints, rejoinPointIdx) {
    if (!ac) return;
    const acSeq = getAircraftForAtmTrajectorySequence(ac);
    const oldPoints = Array.isArray(acSeq.points) ? acSeq.points : ac.points;
    if (!Array.isArray(oldPoints) || !Array.isArray(pathPoints) || !Number.isFinite(rejoinPointIdx) || rejoinPointIdx < 0 || rejoinPointIdx >= oldPoints.length) return;
    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
    const simSec = getSimulationClockSeconds();
    const state = getAircraftPositionAtRadarUpdate(ac, simSec, radarSec);
    const curLat = (state && isFinite(state.lat)) ? state.lat : (isFinite(ac.headingNavLat) ? ac.headingNavLat : null);
    const curLon = (state && isFinite(state.lon)) ? state.lon : (isFinite(ac.headingNavLon) ? ac.headingNavLon : null);
    if (curLat == null || curLon == null) return;
    abandonSimulationHoldingsForNewLateralNav(ac);
    clearExePlnAtmHoldLabelIfActive(ac);
    let randomCounter = 0;
    const pathPart = pathPoints.map(p => ({
        lat: Number(p.lat),
        lon: Number(p.lon),
        name: (p.name && String(p.name).trim()) ? String(p.name).trim().toUpperCase() : `WP${String(++randomCounter).padStart(2, '0')}`
    }));
    const rejoinWp = oldPoints[rejoinPointIdx];
    if (rejoinWp && isFinite(rejoinWp.lat) && isFinite(rejoinWp.lon)) {
        pathPart.push({ lat: rejoinWp.lat, lon: rejoinWp.lon, name: (rejoinWp.name || '').toString().trim().toUpperCase() || `WP${rejoinPointIdx}` });
    }
    for (let i = rejoinPointIdx + 1; i < oldPoints.length; i++) {
        const p = oldPoints[i];
        if (p && isFinite(p.lat) && isFinite(p.lon)) {
            pathPart.push({ lat: p.lat, lon: p.lon, name: (p.name || '').toString().trim().toUpperCase() || `WP${i}` });
        }
    }
    ac.points = [{ lat: curLat, lon: curLon, name: '' }, ...pathPart];
    attachSectorWpIdsToSimTrajectoryPoints(ac.points);
    ac._trackCache = null;
    ac.routeNavTravelCacheN = null;
    if (ac.routeNavTraveledNmByUpdateSec instanceof Map) ac.routeNavTraveledNmByUpdateSec.clear();
    ac.routeNavLastUpdateSimSec = null;
    ac.routeNavTraveledNm = 0;
    ac.routeProgressIdx = 0;
    ac.directToWpIdx = null;
    ac.directToWpName = null;
    ac.silentDirectToWpIdx = null;
    ac.silentDirectToTurnWpIdx = null;
    ac.routeCompleted = false;
    releaseSimulationManualHeadingForNewLateralNav(ac);
    ac.headingTurnTargetDeg = null;
    ac.headingTurnStartSimSec = getEffectiveSimulationSimTimeMs() / 1000;
    ac.headingTurnRateDps = getMinTurnRateDpsForAircraft(ac);
    rebaseSimulationHeadingNavAtCurrentPosition(ac);
    try { pushSimulationDebugLog('CMD', ac, `DCT path applied: ${pathPoints.length} new points, rejoin at idx ${rejoinPointIdx}`); } catch (e) {}
    const rerouteNames = pathPart.map(p => (p?.name || '').toString().trim().toUpperCase()).filter(Boolean);
    recordSimulationSubtitleEvent(ac, `Rerouting input > ${rerouteNames.join(' ')}`, { command: 'DCT_REROUTE', waypointNames: rerouteNames, rejoinPointIdx });
    captureJoinerExePatchFromAircraft(ac);
}

// Apply path to aircraft (no rejoin): trajectory = current position + path points. Used when user picks Route-End waypoint.
function releaseSimulationManualHeadingForNewLateralNav(ac) {
    if (!ac) return;
    ac.selectedHeadingDeg = null;
    ac.pendingApproachArm = null;
}

function rebaseSimulationHeadingNavAtCurrentPosition(ac) {
    if (!ac) return;
    try {
        const simSec = getSimulationClockSeconds();
        const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
        const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
        const stNow = getAircraftPositionAtRadarUpdate(ac, simSec, radarSec);
        const spawn = parseInt(ac.spawnTimeSec, 10) || 0;
        const elapsedSinceSpawn = Math.max(0, simSec - spawn);
        const elapsedAtLastUpdate = Math.floor(elapsedSinceSpawn / radarSec) * radarSec;
        const lastUpdateSimSec = spawn + elapsedAtLastUpdate;
        const baseLat = (stNow && isFinite(stNow.lat)) ? stNow.lat : (isFinite(ac.headingNavLat) ? ac.headingNavLat : null);
        const baseLon = (stNow && isFinite(stNow.lon)) ? stNow.lon : (isFinite(ac.headingNavLon) ? ac.headingNavLon : null);
        const baseUpdateSec = (stNow && stNow.lastUpdateSimSec != null) ? stNow.lastUpdateSimSec : lastUpdateSimSec;
        if (baseLat == null || baseLon == null) return;
        ac.navMode = 'heading';
        ac.headingNavLat = baseLat;
        ac.headingNavLon = baseLon;
        ac.headingNavLastUpdateSimSec = baseUpdateSec;
        if (!(ac.headingNavStatesByUpdateSec instanceof Map)) ac.headingNavStatesByUpdateSec = new Map();
        for (const k of ac.headingNavStatesByUpdateSec.keys()) {
            if (k > baseUpdateSec) ac.headingNavStatesByUpdateSec.delete(k);
        }
        let hdgSeed = null;
        try {
            if (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg)) hdgSeed = heading0to359(Number(ac.publishedHeadingDeg));
            else if (ac.currentHeadingDeg != null && isFinite(ac.currentHeadingDeg)) hdgSeed = heading0to359(Number(ac.currentHeadingDeg));
            else if (stNow?.next && isFinite(stNow.lat) && isFinite(stNow.lon) && isFinite(stNow.next.lat) && isFinite(stNow.next.lon)) {
                hdgSeed = heading0to359(calculateBearingDegrees(stNow.lat, stNow.lon, stNow.next.lat, stNow.next.lon));
            }
        } catch (eH0) {}
        if (hdgSeed == null || !isFinite(hdgSeed)) hdgSeed = 0;
        ac.headingNavStatesByUpdateSec.set(baseUpdateSec, { lat: baseLat, lon: baseLon, hdg: hdgSeed });
    } catch (e) {}
}

function applyPathToAircraft(ac, pathPoints) {
    if (!ac || !Array.isArray(pathPoints)) return;
    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
    const simSec = getSimulationClockSeconds();
    const state = getAircraftPositionAtRadarUpdate(ac, simSec, radarSec);
    const curLat = (state && isFinite(state.lat)) ? state.lat : (isFinite(ac.headingNavLat) ? ac.headingNavLat : null);
    const curLon = (state && isFinite(state.lon)) ? state.lon : (isFinite(ac.headingNavLon) ? ac.headingNavLon : null);
    if (curLat == null || curLon == null) return;
    abandonSimulationHoldingsForNewLateralNav(ac);
    clearExePlnAtmHoldLabelIfActive(ac);
    let randomCounter = 0;
    const pathPart = pathPoints.map(p => ({
        lat: Number(p.lat),
        lon: Number(p.lon),
        name: (p.name && String(p.name).trim()) ? String(p.name).trim().toUpperCase() : `WP${String(++randomCounter).padStart(2, '0')}`
    }));
    ac.points = [{ lat: curLat, lon: curLon, name: '' }, ...pathPart];
    attachSectorWpIdsToSimTrajectoryPoints(ac.points);
    ac._trackCache = null;
    ac.routeNavTravelCacheN = null;
    if (ac.routeNavTraveledNmByUpdateSec instanceof Map) ac.routeNavTraveledNmByUpdateSec.clear();
    ac.routeNavLastUpdateSimSec = null;
    ac.routeNavTraveledNm = 0;
    ac.routeProgressIdx = 0;
    ac.directToWpIdx = null;
    ac.directToWpName = null;
    ac.silentDirectToWpIdx = null;
    ac.silentDirectToTurnWpIdx = null;
    ac.routeCompleted = false;
    releaseSimulationManualHeadingForNewLateralNav(ac);
    ac.headingTurnTargetDeg = null;
    ac.headingTurnStartSimSec = getEffectiveSimulationSimTimeMs() / 1000;
    ac.headingTurnRateDps = getMinTurnRateDpsForAircraft(ac);
    rebaseSimulationHeadingNavAtCurrentPosition(ac);
    try { pushSimulationDebugLog('CMD', ac, `Path applied: ${pathPoints.length} points (user + route-end)`); } catch (e) {}
    const rerouteNames = pathPart.map(p => (p?.name || '').toString().trim().toUpperCase()).filter(Boolean);
    recordSimulationSubtitleEvent(ac, `Rerouting input > ${rerouteNames.join(' ')}`, { command: 'DCT_REROUTE', waypointNames: rerouteNames });
    captureJoinerExePatchFromAircraft(ac);
}

// Direction (bearing) from point 1 to point 2.
// Definition per sim UI: angle from vertical (north) measured clockwise, 0..359 with 0 displayed as 360.
function calculateBearingDegrees(lat1, lon1, lat2, lon2) {
    if (![lat1, lon1, lat2, lon2].every(isFinite)) return 0;
    const φ1 = lat1 * Math.PI / 180;
    const φ2 = lat2 * Math.PI / 180;
    const Δλ = (lon2 - lon1) * Math.PI / 180;

    const y = Math.sin(Δλ) * Math.cos(φ2);
    const x = Math.cos(φ1) * Math.sin(φ2) - Math.sin(φ1) * Math.cos(φ2) * Math.cos(Δλ);
    const θ = Math.atan2(y, x); // radians, -pi..pi
    const deg = (θ * 180 / Math.PI + 360) % 360; // 0..359.999
    return isFinite(deg) ? deg : 0;
}

// Destination point from (lat, lon) given bearing (degrees) and distance (nautical miles).
function destinationPointNm(lat, lon, bearingDeg, distanceNm) {
    if (!isFinite(lat) || !isFinite(lon) || !isFinite(bearingDeg) || !isFinite(distanceNm) || distanceNm <= 0) return null;
    const R = 3440.065; // Earth radius in NM
    const dRad = distanceNm / R;
    const φ1 = lat * Math.PI / 180;
    const λ1 = lon * Math.PI / 180;
    const brgRad = bearingDeg * Math.PI / 180;
    const φ2 = Math.asin(Math.sin(φ1) * Math.cos(dRad) + Math.cos(φ1) * Math.sin(dRad) * Math.cos(brgRad));
    const λ2 = λ1 + Math.atan2(Math.sin(brgRad) * Math.sin(dRad) * Math.cos(φ1), Math.cos(dRad) - Math.sin(φ1) * Math.sin(φ2));
    return { lat: φ2 * 180 / Math.PI, lon: λ2 * 180 / Math.PI };
}

function distancePointToSegmentNm(pLat, pLon, aLat, aLon, bLat, bLon, refLatDeg) {
    if (![pLat, pLon, aLat, aLon, bLat, bLon].every(isFinite)) return null;
    const refLat = (refLatDeg != null && isFinite(refLatDeg)) ? Number(refLatDeg) : Number(pLat);
    const P = latLonToLocalXY(pLat, pLon, refLat);
    const A = latLonToLocalXY(aLat, aLon, refLat);
    const B = latLonToLocalXY(bLat, bLon, refLat);
    const ABx = B.x - A.x;
    const ABy = B.y - A.y;
    const APx = P.x - A.x;
    const APy = P.y - A.y;
    const ab2 = ABx * ABx + ABy * ABy;
    if (!isFinite(ab2) || ab2 <= 1e-18) {
        const dDeg = Math.hypot(APx, APy);
        return isFinite(dDeg) ? dDeg * 60 : null;
    }
    let t = (APx * ABx + APy * ABy) / ab2;
    if (!isFinite(t)) t = 0;
    t = Math.max(0, Math.min(1, t));
    const Qx = A.x + ABx * t;
    const Qy = A.y + ABy * t;
    const dDeg = Math.hypot(P.x - Qx, P.y - Qy);
    return isFinite(dDeg) ? dDeg * 60 : null;
}

// Project a point from (lat,lon) given bearing (deg) and distance (nautical miles).
function projectLatLonByNm(lat, lon, bearingDeg, distNm) {
    if (![lat, lon, bearingDeg, distNm].every(isFinite)) return { lat, lon };
    const R = 3440.065; // Earth radius in NM
    const δ = distNm / R;
    const θ = (bearingDeg % 360) * Math.PI / 180;
    const φ1 = lat * Math.PI / 180;
    const λ1 = lon * Math.PI / 180;

    const sinφ1 = Math.sin(φ1);
    const cosφ1 = Math.cos(φ1);
    const sinδ = Math.sin(δ);
    const cosδ = Math.cos(δ);

    const sinφ2 = sinφ1 * cosδ + cosφ1 * sinδ * Math.cos(θ);
    const φ2 = Math.asin(Math.max(-1, Math.min(1, sinφ2)));
    const y = Math.sin(θ) * sinδ * cosφ1;
    const x = cosδ - sinφ1 * Math.sin(φ2);
    const λ2 = λ1 + Math.atan2(y, x);

    const outLat = φ2 * 180 / Math.PI;
    const outLon = ((λ2 * 180 / Math.PI + 540) % 360) - 180; // normalize -180..180
    return { lat: outLat, lon: outLon };
}

// STCA On Track: project one aircraft forward (position + altitude) for lookAheadSec in steps of radarSec.
// Returns array of { lat, lon, altFeet } for instance 0 (current), 1, 2, ... up to lookAheadSec.
// Uses current GS, current heading, current Mode-C. Altitude uses actual rate of climb/descent (rocFpm): each
// step adds vsFpm * (radarSec/60) feet, clamped to ALV (assignedFl) when set.
function computeStcaOnTrackProjection(ac, simSec, radarSec, lookAheadSec) {
    const state = getAircraftPositionAtRadarUpdate(ac, simSec, radarSec);
    if (!state || !isFinite(state.lat) || !isFinite(state.lon)) return [];
    const interval = Math.max(1, parseInt(radarSec, 10) || 1);
    const gs = (state.gs != null && isFinite(state.gs)) ? Number(state.gs) : (state.labelGs != null && isFinite(state.labelGs)) ? Number(state.labelGs) : null;
    if (!gs || gs <= 0) return [];
    let hdg = (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg)) ? heading0to359(Number(ac.publishedHeadingDeg))
        : (ac.currentHeadingDeg != null && isFinite(ac.currentHeadingDeg)) ? heading0to359(Number(ac.currentHeadingDeg)) : null;
    if (hdg == null && state.next && isFinite(state.next.lat) && isFinite(state.next.lon)) {
        hdg = heading0to359(calculateBearingDegrees(state.lat, state.lon, state.next.lat, state.next.lon));
    }
    if (hdg == null) hdg = 0;
    const altFeetNow = Number(ac.publishedModeCFeet ?? ac.modeCFeet);
    const altNow = isFinite(altFeetNow) ? altFeetNow : 0;
    const alvFl = parseInt(ac.assignedFl, 10);
    const targetFeet = (Number.isFinite(alvFl) && alvFl > 0) ? alvFl * 100 : null;
    // Use actual rate of climb/descent (fpm). Per radar interval: delta = vsFpm * (radarSec/60).
    const vsFpm = Number(ac.publishedRocFpm ?? ac.rocFpm);
    const vsFpmValid = isFinite(vsFpm) ? vsFpm : 0;
    const numSteps = Math.max(0, Math.floor(lookAheadSec / interval));
    const out = [];
    let prevAlt = altNow;
    for (let k = 0; k <= numSteps; k++) {
        const tSec = k * interval;
        const distNm = (gs * tSec) / 3600;
        const pos = k === 0 ? { lat: state.lat, lon: state.lon } : projectLatLonByNm(state.lat, state.lon, hdg, distNm);
        let alt = prevAlt;
        if (k > 0) {
            const dFeet = (vsFpmValid * interval) / 60;
            alt = prevAlt + dFeet;
            if (targetFeet != null && isFinite(targetFeet)) {
                if (dFeet >= 0 && alt >= targetFeet) alt = targetFeet;
                else if (dFeet < 0 && alt <= targetFeet) alt = targetFeet;
            }
            alt = Math.max(0, alt);
            prevAlt = alt;
        }
        out.push({ lat: pos.lat, lon: pos.lon, altFeet: alt });
    }
    return out;
}

const STCA_VERTICAL_SEP_FT = 1000;
const STCA_NEARBY_NM = 25;

// STCA On Track: compute set of aircraft ids in conflict and first-breach positions per pair.
// Returns { conflictIds: Set, firstBreachPairs: [{ idA, idB, posA: {lat,lon,altFeet}, posB }] }.
// Only compares pairs within 25 NM at that instance; conflict = horizontal < generalStcaNm AND vertical < 1000 ft.
function computeStcaConflictsOnTrack(aircraft, simSec, radarSec, lookAheadSec, generalStcaNm) {
    const conflictIds = new Set();
    const firstBreachByPair = new Map(); // key = "idA,idB" (sorted), value = { idA, idB, posA, posB }
    if (!aircraft || aircraft.length < 2 || !Number.isFinite(generalStcaNm) || generalStcaNm <= 0) {
        return { conflictIds, firstBreachPairs: [] };
    }
    const lookAhead = Math.max(1, parseInt(lookAheadSec, 10) || 120);
    const interval = Math.max(1, parseInt(radarSec, 10) || 1);
    const numSteps = Math.max(0, Math.floor(lookAhead / interval));
    const projections = [];
    for (let i = 0; i < aircraft.length; i++) {
        const ac = aircraft[i];
        if (!ac || !ac.id) continue;
        const proj = computeStcaOnTrackProjection(ac, simSec, radarSec, lookAhead);
        if (proj.length === 0) continue;
        projections.push({ id: ac.id, proj });
    }
    for (let k = 0; k <= numSteps; k++) {
        for (let i = 0; i < projections.length; i++) {
            const pi = projections[i];
            const posI = pi.proj[k];
            if (!posI || !isFinite(posI.lat) || !isFinite(posI.lon)) continue;
            for (let j = i + 1; j < projections.length; j++) {
                const pj = projections[j];
                const posJ = pj.proj[k];
                if (!posJ || !isFinite(posJ.lat) || !isFinite(posJ.lon)) continue;
                const distNm = calculateNauticalMiles(posI.lat, posI.lon, posJ.lat, posJ.lon);
                if (!isFinite(distNm) || distNm > STCA_NEARBY_NM) continue;
                if (distNm >= generalStcaNm) continue;
                const altI = Number(posI.altFeet);
                const altJ = Number(posJ.altFeet);
                const vertSepFt = Math.abs((isFinite(altI) ? altI : 0) - (isFinite(altJ) ? altJ : 0));
                if (vertSepFt >= STCA_VERTICAL_SEP_FT) continue;
                conflictIds.add(pi.id);
                conflictIds.add(pj.id);
                const pairKey = [pi.id, pj.id].sort().join(',');
                if (!firstBreachByPair.has(pairKey)) {
                    firstBreachByPair.set(pairKey, {
                        idA: pi.id,
                        idB: pj.id,
                        posA: { lat: posI.lat, lon: posI.lon, altFeet: posI.altFeet },
                        posB: { lat: posJ.lat, lon: posJ.lon, altFeet: posJ.altFeet }
                    });
                }
            }
        }
    }
    return { conflictIds, firstBreachPairs: Array.from(firstBreachByPair.values()) };
}

// Called from simulation clock tick after aircraft updates; keeps STCA in sync with displayed positions.
function updateStcaStateCache(simSec) {
    if (!window.simulationData || !Array.isArray(window.simulationData.aircraft)) return;
    const aircraft = window.simulationData.aircraft;
    const stcaType = (simulationSettings?.stcaType || SIM_SETTINGS_DEFAULTS.stcaType || 'on_track').toString().toLowerCase();
    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
    if (stcaType !== 'on_track' || aircraft.length < 2) {
        stcaStateCache = { simSec, conflictIds: new Set(), firstBreachPairs: [] };
        return;
    }
    const lookAheadSec = Math.max(1, parseInt(simulationSettings?.stcaLookAheadSeconds, 10) || parseInt(SIM_SETTINGS_DEFAULTS.stcaLookAheadSeconds, 10) || 120);
    const generalStcaNm = Math.max(0, parseFloat(simulationSettings?.stcaGeneralNm, 10) ?? parseFloat(SIM_SETTINGS_DEFAULTS.stcaGeneralNm, 10) ?? 5);
    const result = computeStcaConflictsOnTrack(aircraft, simSec, radarSec, lookAheadSec, generalStcaNm);
    stcaStateCache = { simSec, conflictIds: result.conflictIds, firstBreachPairs: result.firstBreachPairs || [] };
}

function getSelectedRunwayEndsForAircraft(ac) {
    try {
        if (!ac || ac.destRunwayId == null || !ac.destRunwayEndName) return null;
        const destIcao = normalizeAirportIcao(ac.destination);
        const ap = destIcao ? getSimulationSectorAirports().find(a => normalizeAirportIcao(a?.icao) === destIcao) : null;
        const rwId = String(ac.destRunwayId);
        const rw = (ap && Array.isArray(ap.runways)) ? ap.runways.find(r => r && String(r.id) === rwId) : null;
        const endA = rw?.endA;
        const endB = rw?.endB;
        const selName = String(ac.destRunwayEndName || '').toUpperCase();
        const aName = String(endA?.name || '').toUpperCase();
        const bName = String(endB?.name || '').toUpperCase();
        const sel = (selName && selName === aName) ? endA : (selName && selName === bName) ? endB : null;
        const other = (sel === endA) ? endB : (sel === endB) ? endA : null;
        if (!sel || !other) return null;
        if (![sel.lat, sel.lon, other.lat, other.lon].every(isFinite)) return null;
        return { sel, other, ap, rw };
    } catch (e) {
        return null;
    }
}

function approachNameIsLocType(nameRaw) {
    const s = (nameRaw || '').toString().toUpperCase();
    return s.includes('ILS') || s.includes('LLZ') || s.includes('GPS');
}

function latLonToLocalXY(lat, lon, refLatDeg) {
    const φ0 = (Number(refLatDeg) || 0) * Math.PI / 180;
    const k = Math.cos(φ0) || 1;
    return { x: Number(lon) * k, y: Number(lat) };
}

function localXYToLatLon(x, y, refLatDeg) {
    const φ0 = (Number(refLatDeg) || 0) * Math.PI / 180;
    const k = Math.cos(φ0) || 1;
    return { lat: Number(y), lon: Number(x) / k };
}

function intersectRayWithSegment(p, r, q, s) {
    // Solve p + t r = q + u s, with t>=0 (ray), u in [0,1] (segment)
    const cross = (a, b) => a.x * b.y - a.y * b.x;
    const qp = { x: q.x - p.x, y: q.y - p.y };
    const rxs = cross(r, s);
    if (!isFinite(rxs) || Math.abs(rxs) < 1e-12) return null; // parallel
    const t = cross(qp, s) / rxs;
    const u = cross(qp, r) / rxs;
    if (!isFinite(t) || !isFinite(u)) return null;
    if (t < 0) return null;
    if (u < 0 || u > 1) return null;
    return { t, u, x: p.x + t * r.x, y: p.y + t * r.y };
}

function intersectRayWithLine(p, r, a, d) {
    // Solve p + t r = a + u d, with t>=0 (ray), u free (infinite line)
    const cross = (v1, v2) => v1.x * v2.y - v1.y * v2.x;
    const ap = { x: a.x - p.x, y: a.y - p.y };
    const rxd = cross(r, d);
    if (!isFinite(rxd) || Math.abs(rxd) < 1e-12) return null; // parallel
    const t = cross(ap, d) / rxd;
    const u = cross(ap, r) / rxd;
    if (!isFinite(t) || !isFinite(u)) return null;
    if (t < 0) return null;
    return { t, u, x: p.x + t * r.x, y: p.y + t * r.y };
}

function intersectSegmentWithLine(p, r, a, d) {
    // Solve p + t r = a + u d, with t in [0,1] (segment), u free (line)
    const cross = (v1, v2) => v1.x * v2.y - v1.y * v2.x;
    const ap = { x: a.x - p.x, y: a.y - p.y };
    const rxd = cross(r, d);
    if (!isFinite(rxd) || Math.abs(rxd) < 1e-12) return null;
    const t = cross(ap, d) / rxd;
    const u = cross(ap, r) / rxd;
    if (!isFinite(t) || !isFinite(u)) return null;
    if (t < 0 || t > 1) return null;
    return { t, u, x: p.x + t * r.x, y: p.y + t * r.y };
}

function intersectSegmentWithSegment(p, r, q, s) {
    // Solve p + t r = q + u s, with t,u in [0,1]
    const cross = (a, b) => a.x * b.y - a.y * b.x;
    const qp = { x: q.x - p.x, y: q.y - p.y };
    const rxs = cross(r, s);
    if (!isFinite(rxs) || Math.abs(rxs) < 1e-12) return null; // parallel
    const t = cross(qp, s) / rxs;
    const u = cross(qp, r) / rxs;
    if (!isFinite(t) || !isFinite(u)) return null;
    if (t < 0 || t > 1) return null;
    if (u < 0 || u > 1) return null;
    return { t, u, x: p.x + t * r.x, y: p.y + t * r.y };
}

function getSelectedRunwayForAircraftDestination(ac) {
    const destIcao = normalizeAirportIcao(ac?.destination);
    if (!destIcao) return null;
    const ap = getSimulationSectorAirports().find(a => normalizeAirportIcao(a?.icao) === destIcao);
    if (!ap) return null;
    const rwId = (ac?.destRunwayId != null) ? String(ac.destRunwayId) : null;
    const rw = (rwId && Array.isArray(ap.runways)) ? ap.runways.find(r => r && String(r.id) === rwId) : null;
    if (!rw) return null;
    const end = (ac?.destRunwayEnd || '').toString().toUpperCase(); // 'A'|'B'
    const thrSel = (end === 'B') ? rw.endB : rw.endA;
    const thrOpp = (end === 'B') ? rw.endA : rw.endB;
    if (!thrSel || !thrOpp) return null;
    if (![thrSel.lat, thrSel.lon, thrOpp.lat, thrOpp.lon].every(isFinite)) return null;
    return { airport: ap, runway: rw, thrSel, thrOpp, destIcao, end };
}

function computeExtendedCenterline50Nm(ac) {
    const rwSel = getSelectedRunwayForAircraftDestination(ac);
    if (!rwSel) return null;
    const { thrSel, thrOpp } = rwSel;
    // Inbound bearing towards selected runway end (from opposite threshold to selected threshold).
    const brgIn = heading0to359(calculateBearingDegrees(thrOpp.lat, thrOpp.lon, thrSel.lat, thrSel.lon));
    return {
        brgIn,
        runwayLat: thrSel.lat,
        runwayLon: thrSel.lon,
        thrSel: { lat: thrSel.lat, lon: thrSel.lon },
        thrOpp: { lat: thrOpp.lat, lon: thrOpp.lon }
    };
}

function getApproachWaypointsLatLon(approachObj) {
    const legs = Array.isArray(approachObj?.legs) ? approachObj.legs : [];
    const byName = new Map();
    (Array.isArray(window.simulationData?.waypoints) ? window.simulationData.waypoints : []).forEach(wp => {
        const nm = (wp?.name || '').toString().trim().toUpperCase();
        if (nm && isFinite(wp.latitude) && isFinite(wp.longitude)) {
            byName.set(nm, { lat: wp.latitude, lon: wp.longitude, name: nm });
        }
    });
    const pts = [];
    legs.forEach(l => {
        const nm = (l?.wp || '').toString().trim().toUpperCase();
        const p = byName.get(nm);
        if (p) pts.push(p);
    });
    return pts;
}


function roundHeadingToIncrement(deg, inc) {
    const d = Number(deg);
    const step = parseInt(inc, 10);
    if (!isFinite(d)) return 0;
    if (!(step === 5 || step === 10)) return heading0to359(d);
    const r = Math.round(d / step) * step;
    return heading0to359(r);
}

function heading0to359(deg) {
    const d = Math.round(deg);
    return ((d % 360) + 360) % 360; // 0..359
}

function formatHeadingFrom0to359(h) {
    const hh = ((h % 360) + 360) % 360;
    if (hh === 0) return '360';
    return String(hh).padStart(3, '0');
}

// Draw simulation canvas
/** Centered hint shown on the radar canvas while RDR draw is turned off (performance mode). */
function drawSimulationRadarOffOverlay() {
    if (!simulationCtx || !simulationCanvas) return;
    const cx = simulationCanvas.width / 2;
    const cy = simulationCanvas.height / 2;
    simulationCtx.save();
    simulationCtx.textAlign = 'center';
    simulationCtx.textBaseline = 'middle';
    simulationCtx.fillStyle = 'rgba(150, 170, 190, 0.55)';
    simulationCtx.font = '700 22px system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif';
    simulationCtx.fillText('RADAR DRAW OFF', cx, cy - 14);
    simulationCtx.fillStyle = 'rgba(150, 170, 190, 0.4)';
    simulationCtx.font = '500 13px system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif';
    simulationCtx.fillText('Enable RDR in the EN-MGMT header to resume drawing', cx, cy + 14);
    simulationCtx.restore();
}

function drawSimulationCanvas() {
    if (!simulationCtx || !simulationCanvas || !window.simulationData) return;
    
    // Validate canvas dimensions
    if (simulationCanvas.width <= 0 || simulationCanvas.height <= 0) {
        return;
    }
    
    // Validate zoom and pan values
    if (!isFinite(simulationZoomLevel) || simulationZoomLevel <= 0) {
        simulationZoomLevel = 1.0;
    }
    if (!isFinite(simulationPanX)) simulationPanX = 0;
    if (!isFinite(simulationPanY)) simulationPanY = 0;
    
    try {
        // Clear canvas with configurable background
        simulationCtx.fillStyle = simulationStyle?.background?.color || '#ffffff';
        simulationCtx.fillRect(0, 0, simulationCanvas.width, simulationCanvas.height);

        // RDR off (EN-MGMT header): skip drawing the map + aircraft for performance, but keep data panels live.
        if (!simulationRadarDrawEnabled) {
            try { drawSimulationRadarOffOverlay(); } catch (eOff) {}
            if (simulationSelectedAircraftId != null) { try { refreshAdvancedLabelPanelBody(); } catch (e) {} }
            try { refreshSimulationHoldingListPanel(); } catch (e) {}
            try { refreshSimulationEnMgmtPanelBody(); } catch (e) {}
            return;
        }

        // Saved Google Earth backgrounds (under all vector layers)
        try { drawSimulationBackgrounds(); } catch (eBg) {}
        
        const simData = window.simulationData;
        const simWaypoints = simData.waypoints || [];
        const simRoutes = simData.routes || [];
        let simBoundaries = simData.boundaries || [];
        if (simulationJoinedSessionId && simulationJoinBoundaryIdFilter) {
            simBoundaries = simBoundaries.filter(b => b && b.id === simulationJoinBoundaryIdFilter);
        }
        
        // Find CENTER/CENTRE waypoint
        const simCentreWaypoint = simWaypoints.find(wp => isCenterWaypointName(wp?.name));
        
        // Set origin to center of canvas
        const simOriginX = simulationCanvas.width / 2;
        const simOriginY = simulationCanvas.height / 2;
        
        // Apply pan offset
        const effectiveOriginX = simOriginX + simulationPanX;
        const effectiveOriginY = simOriginY + simulationPanY;
        
        // Validate effective origin
        if (!isFinite(effectiveOriginX) || !isFinite(effectiveOriginY)) {
            return;
        }

        const simLonScale = getSimulationLonCosScale();
        
        // Draw latitude/longitude lines (grid) if enabled (simulation-only)
        if (simulationMap.latLonLines.enabled) {
            const gridIntervalDegrees = 5 / 60;
            
            let refLon = 0;
            let refLat = 0;
            if (simCentreWaypoint && 
                typeof simCentreWaypoint.longitude === 'number' && 
                typeof simCentreWaypoint.latitude === 'number' &&
                isFinite(simCentreWaypoint.longitude) && 
                isFinite(simCentreWaypoint.latitude)) {
                refLon = simCentreWaypoint.longitude;
                refLat = simCentreWaypoint.latitude;
            }
            
            const topLeftRelLon = (0 - effectiveOriginX) / (simulationZoomLevel * simLonScale);
            const topLeftRelLat = -(0 - effectiveOriginY) / simulationZoomLevel;
            const bottomRightRelLon = (simulationCanvas.width - effectiveOriginX) / (simulationZoomLevel * simLonScale);
            const bottomRightRelLat = -(simulationCanvas.height - effectiveOriginY) / simulationZoomLevel;
            
            const lonMin = refLon + Math.min(topLeftRelLon, bottomRightRelLon);
            const lonMax = refLon + Math.max(topLeftRelLon, bottomRightRelLon);
            const latMin = refLat + Math.min(topLeftRelLat, bottomRightRelLat);
            const latMax = refLat + Math.max(topLeftRelLat, bottomRightRelLat);
            
            const startLon = Math.floor(lonMin / gridIntervalDegrees) * gridIntervalDegrees;
            const endLon = Math.ceil(lonMax / gridIntervalDegrees) * gridIntervalDegrees;
            const startLat = Math.floor(latMin / gridIntervalDegrees) * gridIntervalDegrees;
            const endLat = Math.ceil(latMax / gridIntervalDegrees) * gridIntervalDegrees;
            
            simulationCtx.strokeStyle = '#cccccc';
            simulationCtx.lineWidth = 1;
            
            // Vertical lines (longitude)
            for (let lon = startLon; lon <= endLon; lon += gridIntervalDegrees) {
                const relLon = lon - refLon;
                const x = effectiveOriginX + relLon * simulationZoomLevel * simLonScale;
                
                if (x >= -10 && x <= simulationCanvas.width + 10) {
                    simulationCtx.beginPath();
                    simulationCtx.moveTo(x, 0);
                    simulationCtx.lineTo(x, simulationCanvas.height);
                    simulationCtx.stroke();
                }
            }
            
            // Horizontal lines (latitude)
            for (let lat = startLat; lat <= endLat; lat += gridIntervalDegrees) {
                const relLat = lat - refLat;
                const y = effectiveOriginY - relLat * simulationZoomLevel;
                
                if (y >= -10 && y <= simulationCanvas.height + 10) {
                    simulationCtx.beginPath();
                    simulationCtx.moveTo(0, y);
                    simulationCtx.lineTo(simulationCanvas.width, y);
                    simulationCtx.stroke();
                }
            }
        }
        
        // Draw axes + labels if lat/lon lines enabled (simulation-only)
        if (simulationMap.latLonLines.enabled) {
            simulationCtx.strokeStyle = '#000000';
            simulationCtx.lineWidth = 2;
            
            // X axis (Longitude)
            simulationCtx.beginPath();
            simulationCtx.moveTo(0, effectiveOriginY);
            simulationCtx.lineTo(simulationCanvas.width, effectiveOriginY);
            simulationCtx.stroke();
            
            // Y axis (Latitude)
            simulationCtx.beginPath();
            simulationCtx.moveTo(effectiveOriginX, 0);
            simulationCtx.lineTo(effectiveOriginX, simulationCanvas.height);
            simulationCtx.stroke();
            
            // Draw axis labels
            simulationCtx.fillStyle = '#000000';
            simulationCtx.font = '14px Arial';
            simulationCtx.textAlign = 'center';
            simulationCtx.fillText('Longitude', simulationCanvas.width / 2, effectiveOriginY - 10);
            
            simulationCtx.save();
            simulationCtx.translate(effectiveOriginX - 30, simulationCanvas.height / 2);
            simulationCtx.rotate(-Math.PI / 2);
            simulationCtx.fillText('Latitude', 0, 0);
            simulationCtx.restore();
        }
        
        // Draw map areas (Restricted / Prohibited / Dangerous) — visibility matches Simulation MAP popup
        const areasMapCfg = simulationMap.areas || SIM_MAP_DEFAULTS.areas;
        if (areasMapCfg.enabled) {
            const mapAreasSim = getSimulationSectorMapAreas();
            const selectedAreaIds = (areasMapCfg.selectedIds && Array.isArray(areasMapCfg.selectedIds))
                ? new Set(areasMapCfg.selectedIds.map(String))
                : null;
            simulationCtx.save();
            simulationCtx.lineWidth = 2;
            mapAreasSim.forEach(area => {
                if (!area || !area.boundary || !area.boundary.points || area.boundary.points.length < 2) return;
                if (selectedAreaIds && !selectedAreaIds.has(String(area.id))) return;
                const strokeColor = sanitizeMapAreaLineColor(area.lineColor, area.kind);
                const validPoints = area.boundary.points.filter(point =>
                    point &&
                    typeof point.latitude === 'number' &&
                    typeof point.longitude === 'number' &&
                    isFinite(point.latitude) &&
                    isFinite(point.longitude)
                );
                if (validPoints.length < 2) return;

                simulationCtx.beginPath();
                let isFirstPoint = true;
                let hasValidPoints = false;

                validPoints.forEach(point => {
                    let relLon = point.longitude;
                    let relLat = point.latitude;
                    if (simCentreWaypoint) {
                        relLon = point.longitude - simCentreWaypoint.longitude;
                        relLat = point.latitude - simCentreWaypoint.latitude;
                    }
                    const x = effectiveOriginX + relLon * simulationZoomLevel * simLonScale;
                    const y = effectiveOriginY - relLat * simulationZoomLevel;
                    if (isNaN(x) || isNaN(y) || !isFinite(x) || !isFinite(y)) return;
                    if (isFirstPoint) {
                        simulationCtx.moveTo(x, y);
                        isFirstPoint = false;
                        hasValidPoints = true;
                    } else {
                        simulationCtx.lineTo(x, y);
                    }
                });

                if (hasValidPoints && validPoints.length >= 2) {
                    const fp = validPoints[0];
                    let relLon = fp.longitude;
                    let relLat = fp.latitude;
                    if (simCentreWaypoint) {
                        relLon = fp.longitude - simCentreWaypoint.longitude;
                        relLat = fp.latitude - simCentreWaypoint.latitude;
                    }
                    const x = effectiveOriginX + relLon * simulationZoomLevel * simLonScale;
                    const y = effectiveOriginY - relLat * simulationZoomLevel;
                    if (isFinite(x) && isFinite(y)) simulationCtx.lineTo(x, y);
                    simulationCtx.strokeStyle = strokeColor;
                    simulationCtx.stroke();
                }
            });
            simulationCtx.restore();
        }

        // Holdings (racetrack) — MAP popup toggles mirror Edit Airspace
        drawSimulationHoldingsPatterns(simulationCtx, effectiveOriginX, effectiveOriginY, simulationZoomLevel, simLonScale, simCentreWaypoint, simWaypoints);

        // Draw boundaries (style-controlled)
        if (!simulationMap.boundaries.enabled) {
            // skip
        } else {
        simulationCtx.strokeStyle = hexToRgba(simulationStyle.boundaries.color, simulationStyle.boundaries.alpha);
        simulationCtx.lineWidth = simulationStyle.boundaries.width;
        
        simBoundaries.forEach(boundary => {
            if (!boundary || !boundary.points || boundary.points.length < 2) return;
            
            const validPoints = boundary.points.filter(point => 
                point && 
                typeof point.latitude === 'number' && 
                typeof point.longitude === 'number' &&
                isFinite(point.latitude) && 
                isFinite(point.longitude)
            );
            
            if (validPoints.length < 2) return;
            
            simulationCtx.beginPath();
            let isFirstPoint = true;
            let hasValidPoints = false;
            
            validPoints.forEach(point => {
                let relLon = point.longitude;
                let relLat = point.latitude;
                
                if (simCentreWaypoint) {
                    relLon = point.longitude - simCentreWaypoint.longitude;
                    relLat = point.latitude - simCentreWaypoint.latitude;
                }
                
                const x = effectiveOriginX + relLon * simulationZoomLevel * simLonScale;
                const y = effectiveOriginY - relLat * simulationZoomLevel;
                
                if (isNaN(x) || isNaN(y) || !isFinite(x) || !isFinite(y)) return;
                
                if (isFirstPoint) {
                    simulationCtx.moveTo(x, y);
                    isFirstPoint = false;
                    hasValidPoints = true;
                } else {
                    simulationCtx.lineTo(x, y);
                }
            });
            
            // Close boundary
            if (hasValidPoints && validPoints.length >= 2) {
                const firstPointData = validPoints[0];
                let relLon = firstPointData.longitude;
                let relLat = firstPointData.latitude;
                
                if (simCentreWaypoint) {
                    relLon = firstPointData.longitude - simCentreWaypoint.longitude;
                    relLat = firstPointData.latitude - simCentreWaypoint.latitude;
                }
                
                const x = effectiveOriginX + relLon * simulationZoomLevel * simLonScale;
                const y = effectiveOriginY - relLat * simulationZoomLevel;
                
                if (isFinite(x) && isFinite(y)) {
                    simulationCtx.lineTo(x, y);
                }
                simulationCtx.stroke();
            }
        });
        }
        
        // Draw routes (style-controlled)
        if (simulationMap.routes.enabled) {
            simulationCtx.strokeStyle = hexToRgba(simulationStyle.routes.color, simulationStyle.routes.alpha);
            simulationCtx.lineWidth = simulationStyle.routes.width;
            
            const selectedKeys = simulationMap.routes.selectedKeys ? new Set(simulationMap.routes.selectedKeys) : null;
            
            simRoutes.forEach((route, idx) => {
            if (!route || !route.waypointIds || route.waypointIds.length < 2) return;
            if (selectedKeys && !selectedKeys.has(getRouteKey(route, idx))) return;
            
            const validWaypoints = [];
            for (const waypointId of route.waypointIds) {
                const waypoint = simWaypoints.find(w => w && w.id === waypointId);
                if (waypoint && typeof waypoint.latitude === 'number' && typeof waypoint.longitude === 'number') {
                    validWaypoints.push(waypoint);
                }
            }
            
            if (validWaypoints.length < 2) return;
            
            simulationCtx.beginPath();
            let firstPoint = true;
            
            validWaypoints.forEach(waypoint => {
                let relLon = waypoint.longitude;
                let relLat = waypoint.latitude;
                
                if (simCentreWaypoint) {
                    relLon = waypoint.longitude - simCentreWaypoint.longitude;
                    relLat = waypoint.latitude - simCentreWaypoint.latitude;
                }
                
                const x = effectiveOriginX + relLon * simulationZoomLevel * simLonScale;
                const y = effectiveOriginY - relLat * simulationZoomLevel;
                
                if (isNaN(x) || isNaN(y) || !isFinite(x) || !isFinite(y)) return;
                
                if (firstPoint) {
                    simulationCtx.moveTo(x, y);
                    firstPoint = false;
                } else {
                    simulationCtx.lineTo(x, y);
                }
            });
            
            if (!firstPoint) {
                simulationCtx.stroke();
            }
            });
        }
        
        // Draw waypoints (triangles) - draw before measurements so measurements appear on top
        simWaypoints.forEach(waypoint => {
            if (!waypoint || typeof waypoint.latitude !== 'number' || typeof waypoint.longitude !== 'number') return;
            if (isNaN(waypoint.latitude) || isNaN(waypoint.longitude) || 
                !isFinite(waypoint.latitude) || !isFinite(waypoint.longitude)) return;
            
            // Optionally hide the center waypoint marker/label (still used as reference)
            if (isCenterWaypointName(waypoint.name) && !simulationMap.centerWaypoint.enabled) {
                return;
            }

            // Calculate relative coordinates to CENTRE waypoint
            let relLon = waypoint.longitude;
            let relLat = waypoint.latitude;
            
            if (simCentreWaypoint) {
                relLon = waypoint.longitude - simCentreWaypoint.longitude;
                relLat = waypoint.latitude - simCentreWaypoint.latitude;
            }
            
            // Calculate screen coordinates
            // effectiveOriginX/Y is the canvas center + pan offset
            // For CENTRE waypoint (relLon=0, relLat=0), this should be at canvas center when panX=0, panY=0
            const x = effectiveOriginX + relLon * simulationZoomLevel * simLonScale;
            const y = effectiveOriginY - relLat * simulationZoomLevel; // Negative because Y axis is flipped
            
            if (isNaN(x) || isNaN(y) || !isFinite(x) || !isFinite(y)) return;
            
            // Draw triangle
            const wpColor = hexToRgba(simulationStyle.waypoints.color, simulationStyle.waypoints.alpha);
            if (simulationMap.waypointTriangles.enabled) {
                if (isCenterWaypointName(waypoint.name)) {
                    simulationCtx.fillStyle = wpColor;
                    simulationCtx.strokeStyle = wpColor;
                    simulationCtx.lineWidth = 3;
                } else {
                    simulationCtx.fillStyle = wpColor;
                    simulationCtx.strokeStyle = wpColor;
                    simulationCtx.lineWidth = 1;
                }
                
                const triSize = Math.max(2, simulationMap.waypointTriangles.size);
                simulationCtx.beginPath();
                simulationCtx.moveTo(x, y - triSize);
                simulationCtx.lineTo(x - Math.round(triSize * 0.75), y + Math.round(triSize * 0.75));
                simulationCtx.lineTo(x + Math.round(triSize * 0.75), y + Math.round(triSize * 0.75));
                simulationCtx.closePath();
                simulationCtx.fill();
                simulationCtx.stroke();
            }
            
            // Draw waypoint name
            if (waypoint.name && simulationMap.waypointNames.enabled) {
                simulationCtx.fillStyle = wpColor;
                const fontSize = Math.min(48, Math.max(6, simulationMap.waypointNames.size));
                simulationCtx.font = `${fontSize}px Arial`;
                simulationCtx.textAlign = 'center';
                simulationCtx.textBaseline = 'top';
                const nameYOffset = simulationMap.waypointTriangles.enabled ? (Math.max(2, simulationMap.waypointTriangles.size) + 2) : 6;
                simulationCtx.fillText(waypoint.name, x, y + nameYOffset);
            }
        });

        // Draw Airports (ARP) + Runways in magenta (simulation-only)
        try {
            const MAGENTA = '#ff00ff';
            const airports = getSimulationSectorAirports();
            const airportsSelected = (simulationMap.airports.selectedIcaos && Array.isArray(simulationMap.airports.selectedIcaos))
                ? new Set(simulationMap.airports.selectedIcaos.map(String))
                : null;
            const runwaysSelected = (simulationMap.runways.selectedKeys && Array.isArray(simulationMap.runways.selectedKeys))
                ? new Set(simulationMap.runways.selectedKeys.map(String))
                : null;

            // Use label size as a base for airport text sizing
            const labelFontSize = Math.min(24, Math.max(8, parseInt(simulationMap?.labelSize ?? SIM_MAP_DEFAULTS.labelSize, 10) || SIM_MAP_DEFAULTS.labelSize));

            simulationCtx.save();
            simulationCtx.strokeStyle = MAGENTA;
            simulationCtx.fillStyle = MAGENTA;
            simulationCtx.lineWidth = 2;
            simulationCtx.font = `bold ${Math.max(10, Math.min(18, labelFontSize))}px Arial`;
            simulationCtx.textAlign = 'left';
            simulationCtx.textBaseline = 'top';

            airports.forEach(ap => {
                const icao = normalizeAirportIcao(ap?.icao);

                // ARP
                if (simulationMap.airports.enabled) {
                    if (!airportsSelected || airportsSelected.has(icao)) {
                        const lat = Number(ap?.arpLat);
                        const lon = Number(ap?.arpLon);
                        if (isFinite(lat) && isFinite(lon)) {
                            let relLon = lon;
                            let relLat = lat;
                            if (simCentreWaypoint) {
                                relLon = lon - simCentreWaypoint.longitude;
                                relLat = lat - simCentreWaypoint.latitude;
                            }
                            const x = effectiveOriginX + relLon * simulationZoomLevel * simLonScale;
                            const y = effectiveOriginY - relLat * simulationZoomLevel;
                            if (isFinite(x) && isFinite(y)) {
                                const s = 6;
                                simulationCtx.fillRect(x - s / 2, y - s / 2, s, s);
                                if (icao) simulationCtx.fillText(icao, x + 8, y - 8);
                            }
                        }
                    }
                }

                // Runways
                if (simulationMap.runways.enabled) {
                    (Array.isArray(ap?.runways) ? ap.runways : []).forEach(rw => {
                        const key = getSimulationRunwayKey(icao, rw);
                        if (runwaysSelected && !runwaysSelected.has(key)) return;
                        const a = rw?.endA;
                        const b = rw?.endB;
                        const aLat = Number(a?.lat);
                        const aLon = Number(a?.lon);
                        const bLat = Number(b?.lat);
                        const bLon = Number(b?.lon);
                        if (![aLat, aLon, bLat, bLon].every(isFinite)) return;

                        let raLon = aLon, raLat = aLat, rbLon = bLon, rbLat = bLat;
                        if (simCentreWaypoint) {
                            raLon = aLon - simCentreWaypoint.longitude;
                            raLat = aLat - simCentreWaypoint.latitude;
                            rbLon = bLon - simCentreWaypoint.longitude;
                            rbLat = bLat - simCentreWaypoint.latitude;
                        }
                        const ax = effectiveOriginX + raLon * simulationZoomLevel * simLonScale;
                        const ay = effectiveOriginY - raLat * simulationZoomLevel;
                        const bx = effectiveOriginX + rbLon * simulationZoomLevel * simLonScale;
                        const by = effectiveOriginY - rbLat * simulationZoomLevel;
                        if (![ax, ay, bx, by].every(isFinite)) return;

                        simulationCtx.beginPath();
                        simulationCtx.moveTo(ax, ay);
                        simulationCtx.lineTo(bx, by);
                        simulationCtx.stroke();

                        if (simulationMap.runways.namesEnabled !== false) {
                            const aName = normalizeRunwayDesignator(a?.name);
                            const bName = normalizeRunwayDesignator(b?.name);
                            if (aName) simulationCtx.fillText(aName, ax + 6, ay - 10);
                            if (bName) simulationCtx.fillText(bName, bx + 6, by - 10);
                        }
                    });
                }
            });

            drawSimulationRunwayExtendedCenterlines(simulationCtx, {
                originX: effectiveOriginX,
                originY: effectiveOriginY,
                zoom: simulationZoomLevel,
                lonScale: simLonScale,
                centreWp: simCentreWaypoint,
                airports,
                runwaysSelected,
                color: MAGENTA
            });

            simulationCtx.restore();
        } catch (e) {
            try { simulationCtx.restore(); } catch (e2) {}
        }

        // Draw aircraft (fixed-size circles) - position updates at radar interval
        const aircraft = simData.aircraft || [];
        const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
        const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
        const simSec = getSimulationClockSeconds();

        const aircraftTargetColor = simulationStyle?.aircraft?.targetColor || '#111827';
        const aircraftGreyColor = '#9CA3AF';
        const labelBaseColor = simulationStyle?.labels?.textColor || '#111827';
        simulationCtx.fillStyle = aircraftTargetColor;
        simulationCtx.strokeStyle = '#000000';
        simulationCtx.lineWidth = 1;
        const rPx = 6;
        const trailDots = Math.max(0, Math.min(7, parseInt(simulationSettings?.historyDots, 10) || 0));
        const trailRPx = 2.5;
        const spvGlobalEnabled = !!(simulationSettings?.spvEnabled);
        const spvMinutes = Math.max(0, parseInt(simulationSettings?.spvMinutes, 10) || 0);

        simulationAircraftLabelBounds = [];
        simulationAircraftLeaderLineBounds = [];
        simulationAircraftScreenStates = [];
        simulationAircraftFreeTextIconBounds = [];
        simulationAircraftAlvTextBounds = [];
        simulationAircraftXlvTextBounds = [];
        simulationAircraftCallsignTextBounds = [];
        simulationAircraftSpeedTextBounds = [];
        simulationAircraftRocTextBounds = [];
        simulationAircraftRwyTextBounds = [];
        simulationAircraftHdgDctTextBounds = [];
        simulationTrajectoryEstimateBounds = [];
        const labelItems = []; // collect then draw by z-order
        const ppWorkloadAssignmentByAircraftId = (isJoinerPpClient() && ppSectorPeerClientIds.length >= 2)
            ? ppServerWorkloadAssignmentById
            : null;
        const ppMyClientId = simulationJoinClientId ? String(simulationJoinClientId) : '';

        // STCA On Track: use cache when it was computed for this simSec (same tick as aircraft update), else compute
        let stcaConflictAircraftIds = new Set();
        let stcaFirstBreachPairs = [];
        const stcaType = (simulationSettings?.stcaType || SIM_SETTINGS_DEFAULTS.stcaType || 'on_track').toString().toLowerCase();
        const lookAheadSec = Math.max(1, parseInt(simulationSettings?.stcaLookAheadSeconds, 10) || parseInt(SIM_SETTINGS_DEFAULTS.stcaLookAheadSeconds, 10) || 120);
        if (stcaType === 'on_track' && aircraft.length >= 2) {
            if (stcaStateCache.simSec === simSec && stcaStateCache.conflictIds && stcaStateCache.firstBreachPairs) {
                stcaConflictAircraftIds = stcaStateCache.conflictIds;
                stcaFirstBreachPairs = stcaStateCache.firstBreachPairs;
            } else {
                const generalStcaNm = Math.max(0, parseFloat(simulationSettings?.stcaGeneralNm, 10) ?? parseFloat(SIM_SETTINGS_DEFAULTS.stcaGeneralNm, 10) ?? 5);
                const stcaResult = computeStcaConflictsOnTrack(aircraft, simSec, radarSec, lookAheadSec, generalStcaNm);
                stcaConflictAircraftIds = stcaResult.conflictIds;
                stcaFirstBreachPairs = stcaResult.firstBreachPairs || [];
                stcaStateCache = { simSec, conflictIds: stcaConflictAircraftIds, firstBreachPairs: stcaFirstBreachPairs };
            }
        }
        // First-breach visualization (On Track): line between first breach positions + circles and FL at each end
        if (stcaType === 'on_track' && stcaFirstBreachPairs.length > 0) {
            const labelFontSize = Math.min(24, Math.max(8, parseInt(simulationMap?.labelSize ?? SIM_MAP_DEFAULTS.labelSize, 10) || SIM_MAP_DEFAULTS.labelSize));
            simulationCtx.strokeStyle = '#dc2626';
            simulationCtx.lineWidth = 2;
            simulationCtx.fillStyle = '#dc2626';
            simulationCtx.font = `bold ${labelFontSize}px Arial`;
            stcaFirstBreachPairs.forEach(pair => {
                const scA = simulationLatLonToScreen(pair.posA.lat, pair.posA.lon);
                const scB = simulationLatLonToScreen(pair.posB.lat, pair.posB.lon);
                if (![scA.x, scA.y, scB.x, scB.y].every(isFinite)) return;
                simulationCtx.beginPath();
                simulationCtx.moveTo(scA.x, scA.y);
                simulationCtx.lineTo(scB.x, scB.y);
                simulationCtx.stroke();
                const distNm = calculateNauticalMiles(pair.posA.lat, pair.posA.lon, pair.posB.lat, pair.posB.lon);
                const midX = (scA.x + scB.x) / 2;
                const midY = (scA.y + scB.y) / 2;
                if (isFinite(distNm)) {
                    const distTxt = Number(distNm).toFixed(1) + ' NM';
                    simulationCtx.textAlign = 'center';
                    simulationCtx.textBaseline = 'middle';
                    simulationCtx.fillText(distTxt, midX, midY);
                    simulationCtx.textAlign = 'start';
                    simulationCtx.textBaseline = 'alphabetic';
                }
                const drawCircleAndFl = (sc, altFeet) => {
                    simulationCtx.beginPath();
                    simulationCtx.arc(sc.x, sc.y, 5, 0, 2 * Math.PI);
                    simulationCtx.fill();
                    if (altFeet != null && isFinite(altFeet)) {
                        const modeCTxt = altFeet >= 10000 ? 'FL' + Math.round(altFeet / 100) : String(Math.round(altFeet));
                        simulationCtx.fillText(modeCTxt, sc.x + 6, sc.y + labelFontSize * 0.35);
                    }
                };
                drawCircleAndFl(scA, pair.posA.altFeet);
                drawCircleAndFl(scB, pair.posB.altFeet);
            });
            simulationCtx.strokeStyle = '#000000';
            simulationCtx.lineWidth = 1;
        }
        // Show STCA trigger: draw projected positions as small red circles + expected Mode-C when On Track and setting is On
        const showStcaTrigger = (simulationSettings?.stcaShowTrigger ?? SIM_SETTINGS_DEFAULTS.stcaShowTrigger ?? 'off').toString().toLowerCase();
        if (stcaType === 'on_track' && showStcaTrigger === 'on' && aircraft.length > 0) {
            simulationCtx.fillStyle = '#dc2626';
            simulationCtx.font = '10px Arial';
            aircraft.forEach(ac => {
                if (!ac) return;
                const proj = computeStcaOnTrackProjection(ac, simSec, radarSec, lookAheadSec);
                proj.forEach(p => {
                    if (!isFinite(p.lat) || !isFinite(p.lon)) return;
                    const sc = simulationLatLonToScreen(p.lat, p.lon);
                    if (!isFinite(sc.x) || !isFinite(sc.y)) return;
                    simulationCtx.beginPath();
                    simulationCtx.arc(sc.x, sc.y, 3, 0, 2 * Math.PI);
                    simulationCtx.fill();
                    // Expected Mode-C at this projected position (flight level or feet)
                    const altFeet = p.altFeet != null && isFinite(p.altFeet) ? Math.round(Number(p.altFeet)) : null;
                    if (altFeet != null) {
                        const modeCTxt = altFeet >= 10000 ? 'FL' + Math.round(altFeet / 100) : String(altFeet);
                        simulationCtx.fillText(modeCTxt, sc.x + 5, sc.y + 4);
                    }
                });
            });
        }

        const removeAircraftIds = new Set();
        aircraft.forEach(ac => {
            if (!ac) return;
            let state = getAircraftPositionAtRadarUpdate(ac, simSec, radarSec);
            if (!state || !isFinite(state.lat) || !isFinite(state.lon)) return;

            try { syncExeAlvModeSMismatchFlashForExe(ac, simSec, radarSec); } catch (eAlvClr) {}

            // If in heading-nav mode, advance and publish positions at radar updates (host/single/PP; other joiners follow host state only).
            try {
                if (!simulationJoinedSessionId && ac.navMode === 'heading') {
                    if (!(ac.headingNavStatesByUpdateSec instanceof Map)) ac.headingNavStatesByUpdateSec = new Map();

                    const desiredUpdateSec = state.lastUpdateSimSec;
                    if (desiredUpdateSec != null) {
                        // Ensure we have a base position.
                        if (ac.headingNavLastUpdateSimSec == null || !isFinite(ac.headingNavLat) || !isFinite(ac.headingNavLon)) {
                            ac.headingNavLastUpdateSimSec = desiredUpdateSec;
                            ac.headingNavLat = state.lat;
                            ac.headingNavLon = state.lon;
                            // Seed with a best-effort heading.
                            let hdgSeed = null;
                            try {
                                if (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg)) hdgSeed = heading0to359(Number(ac.publishedHeadingDeg));
                                else if (ac.currentHeadingDeg != null && isFinite(ac.currentHeadingDeg)) hdgSeed = heading0to359(Number(ac.currentHeadingDeg));
                                else if (Array.isArray(ac.points) && ac.points.length >= 2 && ac.points[0] && ac.points[1]) {
                                    hdgSeed = heading0to359(calculateBearingDegrees(ac.points[0].lat, ac.points[0].lon, ac.points[1].lat, ac.points[1].lon));
                                }
                            } catch (eH0) {}
                            if (hdgSeed == null || !isFinite(hdgSeed)) hdgSeed = 0;
                            ac.headingNavStatesByUpdateSec.set(desiredUpdateSec, { lat: state.lat, lon: state.lon, hdg: hdgSeed });
                        }

                        const baseSec = ac.headingNavLastUpdateSimSec;
                        if (isFinite(baseSec) && desiredUpdateSec > baseSec) {
                            // Step one or more radar intervals forward.
                            for (let tSec = baseSec + radarSec; tSec <= desiredUpdateSec; tSec += radarSec) {
                                const prev = ac.headingNavStatesByUpdateSec.get(tSec - radarSec) || { lat: ac.headingNavLat, lon: ac.headingNavLon, hdg: ac.publishedHeadingDeg };

                                const mcFeetNow = Number(ac.publishedModeCFeet ?? ac.modeCFeet);
                                const flNow = isFinite(mcFeetNow) ? Math.max(0, Math.min(500, Math.round(mcFeetNow / 100))) : null;
                                let gsStepKt = (ac.publishedLabelGsKt != null && isFinite(ac.publishedLabelGsKt))
                                    ? Number(ac.publishedLabelGsKt)
                                    : (ac.modeSTasKt != null && isFinite(ac.modeSTasKt))
                                        ? Number(ac.modeSTasKt)
                                        : (flNow != null ? (computeGroundSpeedKt(ac.aircraftType, flNow) || state.gs) : state.gs);

                                // Landing rollout:
                                // - When armed, snap to runway threshold on the NEXT radar update.
                                // - After snap: hide label/leaderline, continue on runway heading, slow down toward opposite end.
                                // - Remove aircraft after 4 radar updates (regardless of speed).
                                try {
                                    const roll = ac.landingRollout;
                                    if (roll && roll.active) {
                                        // Snap to runway on the first radar update after arming.
                                        if (roll.snapPending && roll.snapArmedUpdateSec != null && isFinite(roll.snapArmedUpdateSec) && tSec > Number(roll.snapArmedUpdateSec)) {
                                            roll.snapPending = false;
                                            roll.snapDoneAtUpdateSec = tSec;
                                            roll.updatesSinceSnap = 0;
                                            roll._lastCountedUpdateSec = null;

                                            if (isFinite(roll.startLat) && isFinite(roll.startLon)) {
                                                const snap = { lat: Number(roll.startLat), lon: Number(roll.startLon) };
                                                const hdgSnap = (roll.runwayHeadingDeg != null && isFinite(roll.runwayHeadingDeg)) ? heading0to359(Number(roll.runwayHeadingDeg)) : (isFinite(prev?.hdg) ? heading0to359(prev.hdg) : 0);
                                                ac.headingNavStatesByUpdateSec.set(tSec, { ...snap, hdg: hdgSnap });
                                                ac.headingNavLat = snap.lat;
                                                ac.headingNavLon = snap.lon;
                                                ac.headingNavLastUpdateSimSec = tSec;
                                            }

                                            // Hide label + leaderline from the runway point onward.
                                            ac.hideLabel = true;

                                            // Lock runway heading and cancel any turning.
                                            if (roll.runwayHeadingDeg != null && isFinite(roll.runwayHeadingDeg)) {
                                                const hh = heading0to359(Number(roll.runwayHeadingDeg));
                                                ac.currentHeadingDeg = hh;
                                                ac.publishedHeadingDeg = hh;
                                                ac.headingTurnTargetDeg = null;
                                                ac.headingTurnStartSimSec = null;
                                                ac.headingTurnRateDps = null;
                                            }
                                        }

                                        // After snap, count radar updates and remove after 4.
                                        if (roll.snapDoneAtUpdateSec != null && isFinite(roll.snapDoneAtUpdateSec) && tSec >= Number(roll.snapDoneAtUpdateSec)) {
                                            if (roll._lastCountedUpdateSec !== tSec) {
                                                roll._lastCountedUpdateSec = tSec;
                                                roll.updatesSinceSnap = (Number(roll.updatesSinceSnap) || 0) + 1;
                                            }
                                            if ((Number(roll.updatesSinceSnap) || 0) >= 4) {
                                                ac._removeAfterRollout = true;
                                            }
                                        }

                                        // Slowdown model toward opposite end (if defined).
                                        if (isFinite(roll.endLat) && isFinite(roll.endLon) && isFinite(roll.startSpeedKt) && isFinite(roll.totalNm) && roll.totalNm > 0) {
                                            const remNm = calculateNauticalMiles(prev.lat, prev.lon, Number(roll.endLat), Number(roll.endLon));
                                            const frac = (isFinite(remNm) ? Math.max(0, Math.min(1, remNm / Number(roll.totalNm))) : 0);
                                            gsStepKt = Math.max(0, Number(roll.startSpeedKt) * frac);
                                            roll.currentSpeedKt = gsStepKt;
                                            roll.remainingNm = remNm;
                                        }
                                    }
                                } catch (eR) {}

                                // During approach intercept ("to_temp"), the aircraft must *only* fly the held heading to INTC,
                                // regardless of any published/turning heading state.
                                const proc = ac.approachActive;
                                const holdHdg = (proc && proc.mode === 'to_temp' && (Number(proc.idx) || 0) === 0 && proc.holdHeadingDeg != null && isFinite(proc.holdHeadingDeg))
                                    ? heading0to359(Number(proc.holdHeadingDeg))
                                    : null;

                                // Heading integration for this radar interval:
                                // - We integrate turn rate (deg/sec) so aircraft follows an arc consistent with GS + turn rate.
                                // - Guidance target is recomputed at the start of the interval (sufficient for small intervals).
                                let hdgNow = (prev && prev.hdg != null && isFinite(prev.hdg))
                                    ? heading0to359(Number(prev.hdg))
                                    : (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg))
                                        ? heading0to359(Number(ac.publishedHeadingDeg))
                                        : (ac.currentHeadingDeg != null && isFinite(ac.currentHeadingDeg))
                                            ? heading0to359(Number(ac.currentHeadingDeg))
                                            : (ac.selectedHeadingDeg != null && isFinite(ac.selectedHeadingDeg) ? heading0to359(Number(ac.selectedHeadingDeg)) : 0);

                                // Determine guidance target heading.
                                let targetHdg = null;
                                try {
                                    const roll = ac.landingRollout;
                                    if (roll && roll.active && roll.runwayHeadingDeg != null && isFinite(roll.runwayHeadingDeg)) {
                                        targetHdg = heading0to359(Number(roll.runwayHeadingDeg));
                                    } else if (holdHdg != null && isFinite(holdHdg)) {
                                        targetHdg = heading0to359(Number(holdHdg));
                                    } else if ((ac.silentDirectToWpIdx != null || ac.directToWpIdx != null) && Array.isArray(ac.points)) {
                                        // DCT guidance (manual or silent fly-by DCT):
                                        // - aim at the DCT waypoint normally
                                        // - if a subsequent leg exists after the DCT waypoint, apply fly-by lead + aim to a look-ahead point on outbound leg
                                        const dctIdxRaw = (ac.silentDirectToWpIdx != null) ? ac.silentDirectToWpIdx : ac.directToWpIdx;
                                        const dctIdx = parseInt(dctIdxRaw, 10);
                                        const wp = Number.isFinite(dctIdx) ? ac.points[dctIdx] : null;
                                        const nextAfter = (Number.isFinite(dctIdx) ? ac.points[dctIdx + 1] : null);
                                        if (wp && isFinite(wp.lat) && isFinite(wp.lon) && isFinite(prev.lat) && isFinite(prev.lon)) {
                                            const brgToWp = heading0to359(calculateBearingDegrees(prev.lat, prev.lon, wp.lat, wp.lon));
                                            targetHdg = brgToWp;

                                            const holdArmWp = ac.holdingArm?.waypointId ? String(ac.holdingArm.waypointId).trim() : '';
                                            const suppressDctLead = !!ac.holdingPattern
                                                || !!(holdArmWp && waypointIdMatchesTrajectoryPoint(holdArmWp, wp))
                                                || simulationHoldArmSuppressPredictiveFlyBy(ac, dctIdx);

                                            // Fly-by for DCT if the DCT waypoint is part of a longer trajectory.
                                            if (!suppressDctLead && nextAfter && isFinite(nextAfter.lat) && isFinite(nextAfter.lon)) {
                                                const distToWpNm = calculateNauticalMiles(prev.lat, prev.lon, wp.lat, wp.lon);
                                                const outCourse = heading0to359(calculateBearingDegrees(wp.lat, wp.lon, nextAfter.lat, nextAfter.lon));
                                                const leadNm = computeFlyByLeadDistanceNm(ac, gsStepKt, brgToWp, outCourse);
                                                if (leadNm > 0 && isFinite(distToWpNm) && distToWpNm <= leadNm) {
                                                    const aim = projectLatLonByNm(wp.lat, wp.lon, outCourse, 40);
                                                    targetHdg = heading0to359(calculateBearingDegrees(prev.lat, prev.lon, aim.lat, aim.lon));
                                                }
                                            }
                                        }
                                    } else if (ac.selectedHeadingDeg != null && isFinite(ac.selectedHeadingDeg)) {
                                        targetHdg = heading0to359(Number(ac.selectedHeadingDeg));
                                    } else if (ac.holdingPattern && isFinite(prev.lat) && isFinite(prev.lon)) {
                                        const hp = ac.holdingPattern;
                                        if (isFinite(hp.fixLat) && isFinite(hp.fixLon)) {
                                            if (hp.phase === 'outbound_turn' || hp.phase === 'outbound_leg') {
                                                targetHdg = heading0to359(Number(hp.outboundHdg));
                                            } else if (hp.phase === 'parallel_out_turn' || hp.phase === 'parallel_out_leg') {
                                                targetHdg = heading0to359(Number(hp.outboundHdg));
                                            } else if (hp.phase === 'tear_out_turn' || hp.phase === 'tear_out_leg') {
                                                if (hp.teardropHdg != null && isFinite(Number(hp.teardropHdg))) {
                                                    targetHdg = heading0to359(Number(hp.teardropHdg));
                                                }
                                            } else if (hp.phase === 'inbound_turn' || hp.phase === 'parallel_to_fix_turn' || hp.phase === 'tear_to_fix_turn') {
                                                targetHdg = heading0to359(calculateBearingDegrees(prev.lat, prev.lon, hp.fixLat, hp.fixLon));
                                            }
                                        }
                                    } else if (Array.isArray(ac.points) && ac.points.length >= 2 && !ac.routeCompleted) {
                                        // Auto route-follow (fly-by): guide to next WP, then aim at a look-ahead point on outbound leg within lead distance.
                                        const pts = ac.points;
                                        // If we're in the middle of a fly-by, let guidance behave as if we've already progressed past the turning waypoint.
                                        let idx = Math.max(0, Math.min(pts.length - 2, parseInt(ac.routeProgressIdx, 10) || 0));
                                        try {
                                            const turnIdx = parseInt(ac.silentDirectToTurnWpIdx, 10);
                                            const silentIdx = parseInt(ac.silentDirectToWpIdx, 10);
                                            if (Number.isFinite(turnIdx) && Number.isFinite(silentIdx) && silentIdx === turnIdx + 1) {
                                                idx = Math.max(idx, turnIdx);
                                            }
                                        } catch (eShift) {}
                                        const nextWp = pts[idx + 1];
                                        const nextAfter = pts[idx + 2];
                                        const prevWp = pts[idx];
                                        if (nextWp && prevWp && isFinite(prevWp.lat) && isFinite(prevWp.lon) && isFinite(nextWp.lat) && isFinite(nextWp.lon) && isFinite(prev.lat) && isFinite(prev.lon)) {
                                            const brgToNext = heading0to359(calculateBearingDegrees(prev.lat, prev.lon, nextWp.lat, nextWp.lon));
                                            targetHdg = brgToNext;
                                            const holdArmWp2 = ac.holdingArm?.waypointId ? String(ac.holdingArm.waypointId).trim() : '';
                                            const suppressRfLead = !!ac.holdingPattern
                                                || !!(holdArmWp2 && waypointIdMatchesTrajectoryPoint(holdArmWp2, nextWp))
                                                || simulationHoldArmSuppressPredictiveFlyBy(ac, idx + 1);
                                            if (!suppressRfLead && nextAfter && isFinite(nextAfter.lat) && isFinite(nextAfter.lon)) {
                                                const distToNextNm = calculateNauticalMiles(prev.lat, prev.lon, nextWp.lat, nextWp.lon);
                                                const outCourse = heading0to359(calculateBearingDegrees(nextWp.lat, nextWp.lon, nextAfter.lat, nextAfter.lon));
                                                // Use the fixed inbound leg course (prevWp->nextWp) so lead distance matches the displayed geometry.
                                                const inCourse = heading0to359(calculateBearingDegrees(prevWp.lat, prevWp.lon, nextWp.lat, nextWp.lon));
                                                const leadNm = computeFlyByLeadDistanceNm(ac, gsStepKt, inCourse, outCourse);
                                                if (leadNm > 0 && isFinite(distToNextNm) && distToNextNm <= leadNm) {
                                                    // As soon as we start the fly-by, silently "Proceed direct" to the waypoint AFTER the turning waypoint.
                                                    // This should behave like the manual DCT action (updates routeProgressIdx, rebases nav),
                                                    // but without posting the waypoint in the label/TTS.
                                                    if (ac.silentDirectToWpIdx == null) {
                                                        issueSimulationDirectTo(ac, idx + 2, {
                                                            silent: true,
                                                            immediate: true,
                                                            preserveApproach: true,
                                                            preserveManualHeading: true,
                                                            silentTurnWpIdx: idx + 1
                                                        });
                                                    }
                                                    // If the outbound leg ends at the selected runway threshold, aim at the runway itself.
                                                    // This avoids a tiny parallel offset that can miss the rollout trigger at high GS.
                                                    let isNextRunway = false;
                                                    try {
                                                        const rwInfo = getSelectedRunwayEndsForAircraft(ac);
                                                        if (rwInfo && rwInfo.sel) {
                                                            const dNm = calculateNauticalMiles(Number(nextAfter.lat), Number(nextAfter.lon), Number(rwInfo.sel.lat), Number(rwInfo.sel.lon));
                                                            isNextRunway = isFinite(dNm) && dNm <= 0.05;
                                                        }
                                                    } catch (eRw2) {}
                                                    if (isNextRunway) {
                                                        targetHdg = heading0to359(calculateBearingDegrees(prev.lat, prev.lon, nextAfter.lat, nextAfter.lon));
                                                    } else {
                                                        const aim = projectLatLonByNm(nextWp.lat, nextWp.lon, outCourse, 40);
                                                        targetHdg = heading0to359(calculateBearingDegrees(prev.lat, prev.lon, aim.lat, aim.lon));
                                                    }
                                                }
                                            }
                                        }
                                    }
                                } catch (eT) {}

                                // Turn rate policy:
                                // - Manual user commands (HDG or manual DCT): keep the randomized banded rate already assigned.
                                // - Everything else (route waypoint turns, silent fly-by DCT, approach intercept): fixed (min band) rate.
                                const manualHdgActive = (ac.selectedHeadingDeg != null && isFinite(ac.selectedHeadingDeg));
                                const manualDctActive = (ac.directToWpIdx != null && isFinite(ac.directToWpIdx));
                                const silentDctActive = (ac.silentDirectToWpIdx != null && isFinite(ac.silentDirectToWpIdx));
                                const forceFixed = silentDctActive || !!(ac.approachActive && typeof ac.approachActive === 'object') || (holdHdg != null && isFinite(holdHdg)) || !!ac.holdingPattern;
                                const allowRandom = !forceFixed && (manualHdgActive || manualDctActive);

                                const rateDps = allowRandom
                                    ? ((ac.headingTurnRateDps != null && isFinite(ac.headingTurnRateDps) && Number(ac.headingTurnRateDps) > 0)
                                        ? Number(ac.headingTurnRateDps)
                                        : pickTurnRateDpsForAircraft(ac))
                                    : getMinTurnRateDpsForAircraft(ac);
                                const dtTotal = radarSec;
                                const subStepSec = 1; // 1-second substeps gives a smooth arc at normal radar intervals
                                const nSteps = Math.max(1, Math.round(dtTotal / subStepSec));
                                const dt = dtTotal / nSteps;

                                let latNow = Number(prev.lat);
                                let lonNow = Number(prev.lon);
                                for (let si = 0; si < nSteps; si++) {
                                    if (targetHdg != null && isFinite(targetHdg) && isFinite(rateDps) && rateDps > 0) {
                                        const cur = heading0to359(hdgNow);
                                        let d = signedHeadingDelta(cur, targetHdg);
                                        try {
                                            if (ac.holdingPattern != null && isFinite(targetHdg)) {
                                                const hpH = ac.holdingPattern;
                                                const pr = !!(hpH.turnRight);
                                                if (hpH.phase === 'outbound_turn' || hpH.phase === 'outbound_leg') {
                                                    d = proceduralSignedHeadingDeltaForHold(cur, targetHdg, pr);
                                                } else if (hpH.phase === 'parallel_out_turn' || hpH.phase === 'parallel_to_fix_turn') {
                                                    // Parallel-entry procedure: turns opposite to published holding direction (>180° when needed).
                                                    d = proceduralSignedHeadingDeltaParallelHoldTurn(cur, targetHdg, pr);
                                                } else if (hpH.phase === 'parallel_out_leg') {
                                                    d = signedHeadingDelta(cur, targetHdg);
                                                } else if (hpH.phase === 'tear_out_turn' || hpH.phase === 'tear_out_leg') {
                                                    // Teardrop initial turn: shortest path to IB ± 150°.
                                                    d = signedHeadingDelta(cur, targetHdg);
                                                } else if (hpH.phase === 'tear_to_fix_turn') {
                                                    // Teardrop inbound: published holding turn sense toward fix.
                                                    d = proceduralSignedHeadingDeltaForHold(cur, targetHdg, pr);
                                                }
                                            }
                                        } catch (eHoldD) {}
                                        const step = rateDps * dt;
                                        if (Math.abs(d) <= step) hdgNow = targetHdg;
                                        else hdgNow = heading0to359(cur + Math.sign(d) * step);
                                    }
                                    const distNm = (isFinite(gsStepKt) && gsStepKt > 0) ? (gsStepKt * dt) / 3600 : 0;
                                    if (distNm > 0 && isFinite(latNow) && isFinite(lonNow) && isFinite(hdgNow)) {
                                        const nxt = projectLatLonByNm(latNow, lonNow, hdgNow, distNm);
                                        latNow = nxt.lat;
                                        lonNow = nxt.lon;
                                    }
                                }

                                const nxt = { lat: latNow, lon: lonNow, hdg: hdgNow };

                                if (isFinite(nxt.lat) && isFinite(nxt.lon)) {
                                    ac.headingNavStatesByUpdateSec.set(tSec, { lat: nxt.lat, lon: nxt.lon, hdg: (isFinite(nxt.hdg) ? heading0to359(nxt.hdg) : hdgNow) });
                                    ac.headingNavLat = nxt.lat;
                                    ac.headingNavLon = nxt.lon;
                                    ac.headingNavLastUpdateSimSec = tSec;
                                }
                            }
                        }

                        const published = ac.headingNavStatesByUpdateSec.get(desiredUpdateSec);
                        if (published && isFinite(published.lat) && isFinite(published.lon)) {
                            state = { ...state, lat: published.lat, lon: published.lon, next: null };
                            // Publish heading consistent with the movement integration.
                            if (published.hdg != null && isFinite(published.hdg)) {
                                const hh = heading0to359(Number(published.hdg));
                                ac.currentHeadingDeg = hh;
                                ac.publishedHeadingDeg = hh;
                            }
                        }
                    }
                }
            } catch (e) {}

            // Publish MODE-C + ROC only when the radar/position updates (same cadence as aircraft position)
            if (state.lastUpdateSimSec != null) {
                if (ac.lastPublishedRadarUpdateSimSec == null || ac.lastPublishedRadarUpdateSimSec !== state.lastUpdateSimSec) {
                    ac.lastPublishedRadarUpdateSimSec = state.lastUpdateSimSec;
                    ac.publishedModeCFeet = Number.isFinite(Number(ac.modeCFeet)) ? Number(ac.modeCFeet) : ac.publishedModeCFeet;
                    ac.publishedRocFpm = Number.isFinite(Number(ac.rocFpm)) ? Number(ac.rocFpm) : ac.publishedRocFpm;
                    // Publish heading only on radar updates (UI should change only then)
                    if (ac.currentHeadingDeg != null && isFinite(ac.currentHeadingDeg)) {
                        ac.publishedHeadingDeg = heading0to359(ac.currentHeadingDeg);
                    }
                    // Publish route progression index for trajectory display.
                    // - In route-nav, follow the planned track by traveledNm.
                    // - In heading-nav, advance only when physically passing/abeam the NEXT waypoint (position-based).
                    try {
                        const pts = ac.points || [];
                        const cache = ac._trackCache;
                        const cumNm = cache?.cumNm;
                        const legsNm = cache?.legsNm;
                        if (Array.isArray(pts) && pts.length >= 2 && Array.isArray(cumNm) && Array.isArray(legsNm)) {
                            if (ac.navMode === 'heading') {
                                let idx = Math.max(0, Math.min(pts.length - 2, parseInt(ac.routeProgressIdx, 10) || 0));
                                const PASS_RADIUS_NM = 1.5;
                                const ABEAM_MAX_NM = 15;
                                let guard = 0;
                                while (idx < pts.length - 1 && guard < 5) {
                                    const prev = pts[idx];
                                    const next = pts[idx + 1];
                                    if (!prev || !next || !isFinite(next.lat) || !isFinite(next.lon)) break;
                                    const dNext = calculateNauticalMiles(state.lat, state.lon, next.lat, next.lon);
                                    const directPass = isFinite(dNext) && dNext <= PASS_RADIUS_NM;

                                    let abeamPass = false;
                                    if (!directPass && isFinite(dNext) && dNext <= ABEAM_MAX_NM && prev && isFinite(prev.lat) && isFinite(prev.lon)) {
                                        // Planar dot-product test using the sim's lat/lon-as-cartesian convention.
                                        const dx = next.lon - prev.lon;
                                        const dy = next.lat - prev.lat;
                                        const ax = state.lon - next.lon;
                                        const ay = state.lat - next.lat;
                                        const dot = ax * dx + ay * dy;
                                        const legOk = (dx * dx + dy * dy) > 0;
                                        abeamPass = legOk && isFinite(dot) && dot > 0;
                                    }

                                    const armWp = ac.holdingArm?.waypointId ? String(ac.holdingArm.waypointId).trim() : '';
                                    const holdApproachWp = !!(armWp && waypointIdMatchesTrajectoryPoint(armWp, next));
                                    if (holdApproachWp && !directPass) {
                                        abeamPass = false;
                                    }

                                    if (directPass || abeamPass) {
                                        if (directPass && holdApproachWp) {
                                            tryEnterSimulationHoldingPatternAtPassedWaypoint(ac, next);
                                        }
                                        idx += 1;
                                        guard += 1;
                                        continue;
                                    }
                                    break;
                                }
                                ac.routeProgressIdx = idx;
                                if (ac.holdingPattern && ac.holdingPattern.freezeRouteProgressIdx != null) {
                                    const fz = parseInt(ac.holdingPattern.freezeRouteProgressIdx, 10);
                                    if (Number.isFinite(fz)) {
                                        const cx = parseInt(ac.routeProgressIdx, 10) || 0;
                                        if (cx > fz) ac.routeProgressIdx = fz;
                                    }
                                }

                                // If we have progressed past the final waypoint, mark route complete and stop guidance to the last point.
                                try {
                                    if (idx >= pts.length - 1) {
                                        ac.routeCompleted = true;
                                        // Clear any non-manual guidance that could cause orbiting back to the last point.
                                        ac.silentDirectToWpIdx = null;
                                        ac.silentDirectToTurnWpIdx = null;
                                        ac.directToWpIdx = null;
                                        ac.directToWpName = null;
                                        if (ac.selectedHeadingDeg == null || !isFinite(ac.selectedHeadingDeg)) {
                                            ac.headingTurnTargetDeg = null;
                                            ac.headingTurnStartSimSec = null;
                                            ac.headingTurnRateDps = null;
                                        }
                                    }
                                } catch (eDone) {}

                                // Clear silent fly-by DCT once we've progressed past the turning waypoint.
                                try {
                                    const turnIdx = parseInt(ac.silentDirectToTurnWpIdx, 10);
                                    if (Number.isFinite(turnIdx) && idx >= turnIdx) {
                                        ac.silentDirectToWpIdx = null;
                                        ac.silentDirectToTurnWpIdx = null;
                                    }
                                } catch (eS) {}

                                // If a DCT waypoint is active, clear it once we have physically passed/abeam that waypoint.
                                const dctIdx = parseInt(ac.directToWpIdx, 10);
                                if (Number.isFinite(dctIdx) && idx >= dctIdx) {
                                    ac.directToWpIdx = null;
                                    ac.directToWpName = null;
                                }
                            } else {
                                const tNm = Math.max(0, Number(state.traveledNm) || 0);
                                let segIdx = 0;
                                for (let i = 0; i < legsNm.length; i++) {
                                    const s0 = cumNm[i];
                                    const s1 = cumNm[i + 1];
                                    if (tNm >= s0 && tNm <= s1) { segIdx = i; break; }
                                }
                                ac.routeProgressIdx = segIdx;
                            }
                            try {
                                if (simulationSessionId && !simulationJoinedSessionId) {
                                    const cur = parseInt(ac.routeProgressIdx, 10) || 0;
                                    if (ac._hostLastAtmSyncedRouteProgressIdx !== cur) {
                                        ac._hostLastAtmSyncedRouteProgressIdx = cur;
                                        scheduleHostAtmTrajectorySyncToServer(ac);
                                    }
                                }
                            } catch (eAtm) {}
                            try {
                                if (ac.holdingPattern && isFinite(state.lat) && isFinite(state.lon) && state.lastUpdateSimSec != null) {
                                    advanceSimulationHoldingPattern(ac, state.lastUpdateSimSec, state);
                                }
                            } catch (eHpAdv2) {}
                        }
                    } catch (e) {}
                    // Publish Mode-S speed + label GS only on radar updates (UI should change only then)
                    if (ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) {
                        ac.publishedModeSTasKt = Number(ac.modeSTasKt);
                    }
                    // Compute instantaneous GS for publishing (commanded vs default perf)
                    try {
                        const mcFeetNow = Number(ac.publishedModeCFeet ?? ac.modeCFeet);
                        const flNow = isFinite(mcFeetNow) ? Math.max(0, Math.min(500, Math.round(mcFeetNow / 100))) : null;
                        const hasSpeedCommand = !!(ac.speedSelectedType || ac.speedChangeStartSimSec != null);
                        const departureActive = !!ac.departureProfileActive;
                        if (hasSpeedCommand && ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) {
                            ac.publishedLabelGsKt = Math.round(ac.modeSTasKt);
                        } else if (departureActive && ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) {
                            ac.publishedLabelGsKt = Math.round(ac.modeSTasKt);
                        } else if (flNow != null) {
                            const gsLabel = computeGroundSpeedKt(ac.aircraftType, flNow);
                            if (gsLabel != null && isFinite(gsLabel)) ac.publishedLabelGsKt = Math.round(gsLabel);
                        }
                    } catch (e) {}

                    // Pending approach arming (wait-for-heading):
                    // If the user selected an approach while a heading command was still being flown,
                    // arm the approach only after the commanded heading is reached, and define INTC using that heading.
                    try {
                        const pend = ac.pendingApproachArm;
                        if (pend && pend.type === 'LOC_PROC' && !ac.approachActive) {
                            const cmd = (ac.selectedHeadingDeg != null && isFinite(ac.selectedHeadingDeg)) ? heading0to359(ac.selectedHeadingDeg) : null;
                            if (cmd == null) {
                                ac.pendingApproachArm = null;
                                pushSimulationDebugLog('ACT', ac, 'APP pending cleared: no commanded heading');
                            } else {
                                // Keep pending synced if heading command changes.
                                if (pend.waitForHeadingDeg != null && isFinite(pend.waitForHeadingDeg)) {
                                    const dd = smallestHeadingDeltaAbs(pend.waitForHeadingDeg, cmd);
                                    if (dd != null && isFinite(dd) && dd > 0.5) {
                                        pend.waitForHeadingDeg = cmd;
                                        pushSimulationDebugLog('ACT', ac, `APP pending: updated wait heading -> ${formatHeadingFrom0to359(cmd)}`);
                                    }
                                } else {
                                    pend.waitForHeadingDeg = cmd;
                                }

                                const curHdg = (ac.currentHeadingDeg != null && isFinite(ac.currentHeadingDeg))
                                    ? heading0to359(ac.currentHeadingDeg)
                                    : (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg))
                                        ? heading0to359(ac.publishedHeadingDeg)
                                        : null;
                                const delta = (curHdg != null) ? smallestHeadingDeltaAbs(curHdg, cmd) : null;
                                if (delta != null && isFinite(delta) && delta <= 0.5) {
                                    // Now arm using this commanded heading.
                                    const simSec = getSimulationClockSeconds();
                                    const radarSecRaw = simulationSettings?.radarUpdateSeconds ?? SIM_SETTINGS_DEFAULTS.radarUpdateSeconds;
                                    const radarSec = Math.max(1, parseInt(radarSecRaw, 10) || SIM_SETTINGS_DEFAULTS.radarUpdateSeconds);
                                    const stNow = getAircraftPositionAtRadarUpdate(ac, simSec, radarSec);
                                    const cl = computeExtendedCenterline50Nm(ac);
                                    if (stNow && cl) {
                                        const refLat = cl.runwayLat;
                                        const far = projectLatLonByNm(cl.thrSel.lat, cl.thrSel.lon, cl.brgIn, 50);
                                        const segStart = latLonToLocalXY(cl.thrOpp.lat, cl.thrOpp.lon, refLat);
                                        const segEnd = latLonToLocalXY(far.lat, far.lon, refLat);
                                        const segDir = { x: segEnd.x - segStart.x, y: segEnd.y - segStart.y };

                                        const p0 = latLonToLocalXY(stNow.lat, stNow.lon, refLat);
                                        const p1ll = projectLatLonByNm(stNow.lat, stNow.lon, cmd, 1);
                                        const p1 = latLonToLocalXY(p1ll.lat, p1ll.lon, refLat);
                                        const rayDir = { x: p1.x - p0.x, y: p1.y - p0.y };

                                        const hit = intersectRayWithSegment(p0, rayDir, segStart, segDir);
                                        if (hit) {
                                            const ll = localXYToLatLon(hit.x, hit.y, refLat);
                                            const distToRunwayNm = calculateNauticalMiles(ll.lat, ll.lon, cl.runwayLat, cl.runwayLon);
                                            pushSimulationDebugLog('ACT', ac, `APP pending arm: intersect at HDG ${formatHeadingFrom0to359(cmd)} distToRWY=${isFinite(distToRunwayNm) ? distToRunwayNm.toFixed(1) : 'NaN'}nm`);
                                            if (isFinite(distToRunwayNm) && distToRunwayNm <= 50) {
                                                const minNm = Number(simulationSettings?.minLocApproachDistNm ?? SIM_SETTINGS_DEFAULTS.minLocApproachDistNm);
                                                if (distToRunwayNm < minNm) {
                                                    // blocked
                                                    try {
                                                        queueSimulationAircraftTtsReply(ac, 'APP_UNABLE', 'Unable to start the approach, too close to the runway on that heading');
                                                    } catch (eT) {}
                                                    pushSimulationDebugLog('ACT', ac, `APP blocked (pending): INTC ${distToRunwayNm.toFixed(1)}nm < ${isFinite(minNm) ? minNm : 5}nm`);
                                                } else {
                                                    // Arm + rewrite trajectory.
                                                    const appObj = pend.appObj || null;
                                                    const appPts = getApproachWaypointsLatLon(appObj);
                                                    const keptPts = (Array.isArray(appPts) ? appPts : []).filter(p => {
                                                        if (!p || !isFinite(p.lat) || !isFinite(p.lon)) return false;
                                                        const dWp = calculateNauticalMiles(p.lat, p.lon, cl.runwayLat, cl.runwayLon);
                                                        return isFinite(dWp) && dWp < distToRunwayNm;
                                                    });
                                                    const rwName = (ac.destRunwayEndName || 'RWY').toString().trim().toUpperCase() || 'RWY';
                                                    const rwPt = { lat: cl.runwayLat, lon: cl.runwayLon, name: rwName };
                                                    const seq = [{ lat: ll.lat, lon: ll.lon, name: 'INTC' }, ...keptPts, rwPt];

                                                    ac.approachActive = {
                                                        type: 'LOC_PROC',
                                                        name: pend.approachName,
                                                        mode: 'to_temp',
                                                        points: seq,
                                                        idx: 0,
                                                        lastDistNm: null,
                                                        gpAngleDeg: (appObj?.gpAngleDeg != null && isFinite(appObj.gpAngleDeg)) ? Number(appObj.gpAngleDeg) : null,
                                                        airportElevationFt: (() => {
                                                            try {
                                                                const destIcao = normalizeAirportIcao(ac.destination);
                                                                const ap = destIcao ? getSimulationSectorAirports().find(a => normalizeAirportIcao(a?.icao) === destIcao) : null;
                                                                return (ap?.elevationFt != null && isFinite(ap.elevationFt)) ? Number(ap.elevationFt) : 0;
                                                            } catch (e) { return 0; }
                                                        })()
                                                    };
                                                    // Commit approach selection to label only when armed.
                                                    ac.selectedApproachId = pend.approachId || null;
                                                    ac.selectedApproachName = pend.approachName || null;

                                                    // Do NOT repeat "Cleared ..." here if it was already spoken when the approach was queued.
                                                    if (!pend.ttsClearedQueued) {
                                                        try {
                                                            const spokenApp = getSimulationSpokenApproachName(pend.approachName);
                                                            queueSimulationAircraftTtsReply(ac, 'APP', `Cleared ${spokenApp || pend.approachName}`);
                                                        } catch (eT2) {}
                                                    }

                                                    try {
                                                        pushSimulationDebugLog('ACT', ac, `APP armed (pending): INTC(${distToRunwayNm.toFixed(1)}nm) + ${keptPts.length}/${(Array.isArray(appPts) ? appPts.length : 0)} WPs kept + RWY (${rwName}); direct-to INTC`);
                                                    } catch (eL) {}

                                                    try {
                                                        const cur = { lat: stNow.lat, lon: stNow.lon, name: '' };
                                                        ac.points = [cur, ...seq.map(p => ({ lat: p.lat, lon: p.lon, name: (p.name || '').toString().trim().toUpperCase() }))];
                                                        ac.routeProgressIdx = 0;
                                                        ac._trackCache = null;
                                                        ac.routeNavTravelCacheN = null;
                                                        ac.routeNavTraveledNmByUpdateSec = null;
                                                        ac.routeNavLastUpdateSimSec = null;
                                                        ac.routeNavTraveledNm = 0;
                                                    } catch (eR) {}

                                                    // Proceed direct to INTC immediately (heading already established).
                                                    try {
                                                        releaseSimulationManualHeadingForNewLateralNav(ac);
                                                        ac.directToWpIdx = 1;
                                                        ac.directToWpName = 'INTC';
                                                        ac.headingTurnStartSimSec = simTimeSec;
                                                        if (ac.headingTurnRateDps == null || !isFinite(ac.headingTurnRateDps) || ac.headingTurnRateDps <= 0) {
                                                            ac.headingTurnRateDps = pickTurnRateDpsForAircraft(ac);
                                                        }
                                                        ac.headingTurnTargetDeg = null;
                                                        ac.navMode = 'heading';

                                                        // Re-base heading-nav from current published position.
                                                        const spawn = parseInt(ac.spawnTimeSec, 10) || 0;
                                                        const elapsedSinceSpawn = Math.max(0, simSec - spawn);
                                                        const elapsedAtLastUpdate = Math.floor(elapsedSinceSpawn / radarSec) * radarSec;
                                                        const lastUpdateSimSec = spawn + elapsedAtLastUpdate;
                                                        const baseUpdateSec = (stNow.lastUpdateSimSec != null) ? stNow.lastUpdateSimSec : lastUpdateSimSec;
                                                        ac.headingNavLat = stNow.lat;
                                                        ac.headingNavLon = stNow.lon;
                                                        ac.headingNavLastUpdateSimSec = baseUpdateSec;
                                                        if (!(ac.headingNavStatesByUpdateSec instanceof Map)) ac.headingNavStatesByUpdateSec = new Map();
                                                        for (const k of ac.headingNavStatesByUpdateSec.keys()) {
                                                            if (k > baseUpdateSec) ac.headingNavStatesByUpdateSec.delete(k);
                                                        }
                                                        ac.headingNavStatesByUpdateSec.set(baseUpdateSec, { lat: stNow.lat, lon: stNow.lon });
                                                    } catch (eHB) {}
                                                }
                                            } else {
                                                // Intercept exists geometrically, but outside acceptance criteria.
                                                try {
                                                    queueSimulationAircraftTtsReply(ac, 'APP_UNABLE', 'Unable to start the approach, that heading will not intercept');
                                                } catch (eT4) {}
                                                pushSimulationDebugLog('ACT', ac, `APP pending arm: intersection outside criteria (distToRWY=${isFinite(distToRunwayNm) ? distToRunwayNm.toFixed(1) : 'NaN'}nm)`);
                                            }
                                        } else {
                                            pushSimulationDebugLog('ACT', ac, `APP pending arm: no intersection at HDG ${formatHeadingFrom0to359(cmd)}`);
                                            try {
                                                queueSimulationAircraftTtsReply(ac, 'APP_UNABLE', 'Unable to start the approach, that heading will not intercept');
                                            } catch (eT3) {}
                                        }
                                    }
                                    // Either armed/blocked/no-intersect: clear pending.
                                    ac.pendingApproachArm = null;
                                }
                            }
                        }
                    } catch (e) {}

                    // Runway landing snap/rollout arming (runway-specific behavior):
                    // If the next/target point is the selected runway threshold and the aircraft is within 0.15 NM,
                    // arm a snap on the next radar update. Do not let waypoint logic handle runway behavior.
                    try {
                        if (!ac._removeAfterRollout && !(ac.landingRollout && ac.landingRollout.active)) {
                            const rwInfo = getSelectedRunwayEndsForAircraft(ac);
                            if (rwInfo) {
                                const sel = rwInfo.sel;
                                const other = rwInfo.other;
                                const selName = String(sel?.name || ac.destRunwayEndName || '').toUpperCase();

                                // Only arm rollout if the aircraft is actually navigating to the runway point (by coordinate),
                                // so we don't affect normal waypoint behavior.
                                let nextPt = null;
                                try {
                                    const pts = Array.isArray(ac.points) ? ac.points : [];
                                    const idx = Math.max(0, Math.min(pts.length - 2, parseInt(ac.routeProgressIdx, 10) || 0));
                                    nextPt = pts[idx + 1] || null;
                                } catch (eN) {}

                                const nextLooksLikeRunway =
                                    nextPt && isFinite(nextPt.lat) && isFinite(nextPt.lon) &&
                                    (calculateNauticalMiles(Number(nextPt.lat), Number(nextPt.lon), Number(sel.lat), Number(sel.lon)) <= 0.05);

                                if (nextLooksLikeRunway) {
                                    const dRw = calculateNauticalMiles(state.lat, state.lon, Number(sel.lat), Number(sel.lon));
                                    // High-GS safeguard: if the aircraft "skips over" the 0.15 NM trigger between sweeps,
                                    // arm rollout if the swept segment between the previous plot and this plot passes within 0.15 NM.
                                    let dSeg = null;
                                    try {
                                        const t0 = (state.lastUpdateSimSec != null && isFinite(state.lastUpdateSimSec)) ? Number(state.lastUpdateSimSec) - radarSec : null;
                                        const prevSt = (t0 != null && ac.headingNavStatesByUpdateSec instanceof Map) ? ac.headingNavStatesByUpdateSec.get(t0) : null;
                                        const aLat = (prevSt && isFinite(prevSt.lat)) ? Number(prevSt.lat) : Number(state.lat);
                                        const aLon = (prevSt && isFinite(prevSt.lon)) ? Number(prevSt.lon) : Number(state.lon);
                                        dSeg = distancePointToSegmentNm(Number(sel.lat), Number(sel.lon), aLat, aLon, Number(state.lat), Number(state.lon), Number(sel.lat));
                                    } catch (eS) {}

                                    const hit = (isFinite(dRw) && dRw <= 0.15) || (dSeg != null && isFinite(dSeg) && dSeg <= 0.15);
                                    if (hit) {
                                        const runwayHeadingDeg = heading0to359(calculateBearingDegrees(sel.lat, sel.lon, other.lat, other.lon));
                                        const totalNm = calculateNauticalMiles(sel.lat, sel.lon, other.lat, other.lon);
                                        const startSpeedKt = (state?.gs != null && isFinite(state.gs)) ? Number(state.gs) : (ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) ? Number(ac.modeSTasKt) : 120;
                                        ac.landingRollout = {
                                            active: true,
                                            snapPending: true,
                                            snapArmedUpdateSec: state.lastUpdateSimSec,
                                            runwayHeadingDeg,
                                            startLat: sel.lat,
                                            startLon: sel.lon,
                                            endLat: other.lat,
                                            endLon: other.lon,
                                            totalNm: isFinite(totalNm) ? totalNm : 0,
                                            startSpeedKt: Math.max(0, startSpeedKt),
                                            startedAtSimSec: getSimulationClockSeconds()
                                        };
                                        // Ensure heading-nav stepping is active so snap/slowdown works.
                                        try {
                                            ac.navMode = 'heading';
                                            ac.headingNavLat = state.lat;
                                            ac.headingNavLon = state.lon;
                                            ac.headingNavLastUpdateSimSec = state.lastUpdateSimSec;
                                            if (!(ac.headingNavStatesByUpdateSec instanceof Map)) ac.headingNavStatesByUpdateSec = new Map();
                                            for (const k of ac.headingNavStatesByUpdateSec.keys()) {
                                                if (k > state.lastUpdateSimSec) ac.headingNavStatesByUpdateSec.delete(k);
                                            }
                                            ac.headingNavStatesByUpdateSec.set(state.lastUpdateSimSec, { lat: state.lat, lon: state.lon, hdg: (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg)) ? heading0to359(ac.publishedHeadingDeg) : 0 });
                                        } catch (eH) {}
                                        pushSimulationDebugLog('ACT', ac, `LAND snap armed: d=${dRw.toFixed(2)}nm to RWY ${selName}`);
                                    }
                                }
                            }
                        }
                    } catch (e) {}

                    // Approach procedure (ILS/LLZ/GPS) (heading case):
                    // - Fly current heading to the temporary intersection point.
                    // - Then follow approach waypoints (if any) and finally runway coordinates.
                    try {
                        const proc = ac.approachActive;
                        if (proc && proc.type === 'LOC_PROC' && Array.isArray(proc.points) && proc.points.length) {
                            const PASS_NM = 1.5;
                            const PASS_RUNWAY_NM = 0.15; // arm runway snap when within 0.15 NM
                            const simTimeSec = getEffectiveSimulationSimTimeMs() / 1000;

                            const curIdx = Math.max(0, parseInt(proc.idx, 10) || 0);
                            let didStartRunwayRollout = false;
                            const tgt = proc.points[curIdx];
                            if (tgt && isFinite(tgt.lat) && isFinite(tgt.lon)) {
                                const d = calculateNauticalMiles(state.lat, state.lon, tgt.lat, tgt.lon);
                                const last = (proc.lastDistNm != null && isFinite(proc.lastDistNm)) ? Number(proc.lastDistNm) : null;
                                proc.lastDistNm = (isFinite(d) ? d : null);
                                const isLastPoint = curIdx === (proc.points.length - 1);
                                let isRunwayLast = false;
                                if (isLastPoint) {
                                    // Detect runway by name OR by coordinate match to selected runway threshold.
                                    const nameMatch = (ac?.destRunwayEndName && String(ac.destRunwayEndName).toUpperCase() === String(tgt.name || '').toUpperCase());
                                    let coordMatch = false;
                                    try {
                                        const rwInfo = getSelectedRunwayEndsForAircraft(ac);
                                        if (rwInfo && rwInfo.sel) {
                                            const dNm = calculateNauticalMiles(Number(tgt.lat), Number(tgt.lon), Number(rwInfo.sel.lat), Number(rwInfo.sel.lon));
                                            coordMatch = isFinite(dNm) && dNm <= 0.05;
                                        }
                                    } catch (eC) {}
                                    isRunwayLast = !!(nameMatch || coordMatch);
                                }
                                const passNm = isRunwayLast ? PASS_RUNWAY_NM : PASS_NM;
                                const reached = isFinite(d) && d <= passNm;
                                const overshot = (!isRunwayLast) && (last != null) && isFinite(d) && d > last && last <= (PASS_NM + 1.0);

                                if (reached || overshot) {
                                    // Special case: last point is runway threshold -> start landing rollout instead of snapping/completing.
                                    if (isRunwayLast && reached) {
                                        try {
                                            const destIcao = normalizeAirportIcao(ac.destination);
                                            const ap = destIcao ? getSimulationSectorAirports().find(a => normalizeAirportIcao(a?.icao) === destIcao) : null;
                                            const rwId = (ac.destRunwayId != null) ? String(ac.destRunwayId) : null;
                                            const rw = (ap && rwId && Array.isArray(ap.runways)) ? ap.runways.find(r => r && String(r.id) === rwId) : null;
                                            const endA = rw?.endA;
                                            const endB = rw?.endB;
                                            const selName = String(ac.destRunwayEndName || tgt.name || '').toUpperCase();
                                            const aName = String(endA?.name || '').toUpperCase();
                                            const bName = String(endB?.name || '').toUpperCase();
                                            const sel = (selName && selName === aName) ? endA : (selName && selName === bName) ? endB : endA;
                                            const other = (sel === endA) ? endB : endA;
                                            if (sel && other && isFinite(sel.lat) && isFinite(sel.lon) && isFinite(other.lat) && isFinite(other.lon)) {
                                                const runwayHeadingDeg = heading0to359(calculateBearingDegrees(sel.lat, sel.lon, other.lat, other.lon));
                                                const totalNm = calculateNauticalMiles(sel.lat, sel.lon, other.lat, other.lon);
                                                const startSpeedKt = (state?.gs != null && isFinite(state.gs)) ? Number(state.gs) : (ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) ? Number(ac.modeSTasKt) : 120;
                                                ac.landingRollout = {
                                                    active: true,
                                                    snapPending: true,
                                                    snapArmedUpdateSec: state.lastUpdateSimSec,
                                                    runwayHeadingDeg,
                                                    startLat: sel.lat,
                                                    startLon: sel.lon,
                                                    endLat: other.lat,
                                                    endLon: other.lon,
                                                    totalNm: isFinite(totalNm) ? totalNm : 0,
                                                    startSpeedKt: Math.max(0, startSpeedKt),
                                                    startedAtSimSec: getSimulationClockSeconds()
                                                };
                                                // Clear approach guidance now; the snap + label hide happens on the next radar update.
                                                ac.approachActive = null;
                                                ac.directToWpIdx = null;
                                                ac.directToWpName = null;
                                                ac.selectedHeadingDeg = null;
                                                pushSimulationDebugLog('ACT', ac, `LAND snap armed: within ${PASS_RUNWAY_NM}nm of RWY ${selName}. Next update snap + rollout to ${String(other?.name || '').toUpperCase()}`);
                                                didStartRunwayRollout = true;
                                            }
                                        } catch (eL) {}
                                    }
                                    if (!didStartRunwayRollout) {
                                        // Arrived at this procedure point -> advance
                                        proc.idx = curIdx + 1;
                                        proc.lastDistNm = null;
                                        try {
                                            const reason = reached ? 'REACHED' : 'OVERSHOT';
                                            pushSimulationDebugLog('ACT', ac, `APP point ${reason}: idx ${curIdx} (${String(tgt.name || '').toUpperCase() || 'PT'}) -> idx ${proc.idx}`);
                                        } catch (e0) {}

                                        // If we just reached the temp intercept point (idx 0), drop manual heading command
                                        if (curIdx === 0) {
                                            ac.selectedHeadingDeg = null;
                                            // Drop DCT-to-INTC now that we are established on the procedure.
                                            ac.directToWpIdx = null;
                                            ac.directToWpName = null;
                                            ac.headingTurnTargetDeg = null;
                                            ac.headingTurnStartSimSec = null;
                                            ac.headingTurnRateDps = null;
                                            ac.directToWpIdx = null;
                                            ac.directToWpName = null;
                                            // keep heading-nav mode so movement is heading-driven (radar-step)
                                            ac.navMode = 'heading';
                                            // Re-base heading-nav from current published position
                                            try {
                                                const baseLat = state.lat;
                                                const baseLon = state.lon;
                                                const baseUpdateSec = state.lastUpdateSimSec;
                                                ac.headingNavLat = baseLat;
                                                ac.headingNavLon = baseLon;
                                                ac.headingNavLastUpdateSimSec = baseUpdateSec;
                                                if (!(ac.headingNavStatesByUpdateSec instanceof Map)) ac.headingNavStatesByUpdateSec = new Map();
                                                for (const k of ac.headingNavStatesByUpdateSec.keys()) {
                                                    if (k > baseUpdateSec) ac.headingNavStatesByUpdateSec.delete(k);
                                                }
                                                ac.headingNavStatesByUpdateSec.set(baseUpdateSec, { lat: baseLat, lon: baseLon });
                                            } catch (e) {}
                                        }
                                    }
                                }
                            }

                            // If we started runway rollout this frame, skip the remainder of approach logic
                            // but continue drawing the aircraft symbol/history.
                            if (didStartRunwayRollout) {
                                // no-op
                            } else {
                            const nextIdx = Math.max(0, parseInt(proc.idx, 10) || 0);
                            if (nextIdx >= proc.points.length) {
                                // done
                                if (ac.landingRollout && ac.landingRollout.active) {
                                    // rollout in progress; do not switch nav modes here
                                    ac.approachActive = null;
                                    try { pushSimulationDebugLog('ACT', ac, 'APP completed (runway rollout)'); } catch (e1) {}
                                } else {
                                    ac.approachActive = null;
                                // After completing the procedure at the runway point, stop heading-nav guidance.
                                // Route-nav will keep the aircraft at the last point because traveled distance exceeds total track.
                                try {
                                    ac.directToWpIdx = null;
                                    ac.directToWpName = null;
                                    ac.selectedHeadingDeg = null;
                                    ac.headingTurnTargetDeg = null;
                                    ac.headingTurnStartSimSec = null;
                                    ac.headingTurnRateDps = null;
                                    ac.navMode = 'route';
                                    ac.routeProgressIdx = Math.max(0, (Array.isArray(ac.points) ? ac.points.length - 2 : 0));
                                } catch (e0) {}
                                try { pushSimulationDebugLog('ACT', ac, 'APP completed'); } catch (e1) {}
                                }
                            } else {
                                // While flying to the temporary intercept point (idx 0), proceed DIRECT-TO INTC
                                // (INTC is `ac.points[1]` after trajectory rewrite) and do not issue any other guidance.
                                if (nextIdx === 0 && proc.mode === 'to_temp') {
                                    try {
                                        ac.selectedHeadingDeg = null;
                                        ac.directToWpIdx = 1;
                                        ac.directToWpName = 'INTC';
                                        ac.navMode = 'heading';
                                        if (ac.headingTurnStartSimSec == null || !isFinite(ac.headingTurnStartSimSec)) {
                                            ac.headingTurnStartSimSec = simTimeSec; // immediate
                                        } else if (ac.headingTurnStartSimSec > simTimeSec) {
                                            ac.headingTurnStartSimSec = simTimeSec;
                                        }
                                        if (ac.headingTurnRateDps == null || !isFinite(ac.headingTurnRateDps) || ac.headingTurnRateDps <= 0) {
                                            ac.headingTurnRateDps = pickTurnRateDpsForAircraft(ac);
                                        }
                                        // headingTurnTargetDeg is computed continuously in updateSimulationAircraftHeadings()
                                    } catch (e) {}
                                    // Throttled state log while intercepting.
                                    try {
                                        const last = Number(ac._dbgLastApproachStateLogSec);
                                        if (!isFinite(last) || (getSimulationClockSeconds() - last) >= 1) {
                                            ac._dbgLastApproachStateLogSec = getSimulationClockSeconds();
                                            pushSimulationDebugLog('ACT', ac, `APP to_temp: nav=${ac.navMode} DCT=${ac.directToWpName || ''} turnTgt=${ac.headingTurnTargetDeg != null ? formatHeadingFrom0to359(heading0to359(ac.headingTurnTargetDeg)) : 'null'} curHdg=${ac.currentHeadingDeg != null ? formatHeadingFrom0to359(heading0to359(ac.currentHeadingDeg)) : 'null'} d=${isFinite(d) ? d.toFixed(2) : 'NaN'}nm`);
                                        }
                                    } catch (e2) {}
                                    // Intentionally skip procedure guidance while intercepting.
                                } else {
                                    if (proc.mode === 'to_temp' && nextIdx > 0) {
                                        // After intercept: switch to procedure guidance
                                        proc.mode = 'procedure';
                                        try { pushSimulationDebugLog('ACT', ac, 'APP phase -> procedure'); } catch (e3) {}
                                        try {
                                            if (!proc._locEstablishedTtsSent) {
                                                proc._locEstablishedTtsSent = true;
                                                queueSimulationAircraftTtsReply(ac, 'LOC', 'Localizer established');
                                            }
                                        } catch (eLocTts) {}
                                    }
                                    const next = proc.points[nextIdx];
                                    if (next && isFinite(next.lat) && isFinite(next.lon)) {
                                        const brg = heading0to359(calculateBearingDegrees(state.lat, state.lon, next.lat, next.lon));

                                        // Only retarget when we change target index, or if we're badly off-course.
                                        const curHdg = (ac.currentHeadingDeg != null && isFinite(ac.currentHeadingDeg)) ? heading0to359(ac.currentHeadingDeg)
                                            : (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg)) ? heading0to359(ac.publishedHeadingDeg)
                                                : null;
                                        const delta = (curHdg == null) ? 999 : (() => {
                                            let d = brg - curHdg;
                                            while (d > 180) d -= 360;
                                            while (d < -180) d += 360;
                                            return Math.abs(d);
                                        })();

                                        if (proc._lastGuidanceIdx !== nextIdx || (ac.headingTurnTargetDeg == null && delta >= 5)) {
                                            proc._lastGuidanceIdx = nextIdx;
                                            ac.navMode = 'heading';
                                            ac.headingTurnTargetDeg = brg;
                                            ac.headingTurnStartSimSec = simTimeSec; // immediate
                                            if (ac.headingTurnRateDps == null || !isFinite(ac.headingTurnRateDps) || ac.headingTurnRateDps <= 0) {
                                                ac.headingTurnRateDps = pickTurnRateDpsForAircraft(ac);
                                            }
                                        }
                                    }
                                }
                            }
                            } // end didStartRunwayRollout guard
                        }
                    } catch (e) {}
                }
            }

            // Remove aircraft that completed landing rollout (speed 0)
            if (ac._removeAfterRollout) {
                removeAircraftIds.add(ac.id);
            }

            // Other map areas: delete aircraft when inside the horizontal + vertical volume
            if (!removeAircraftIds.has(ac.id)) {
                try {
                    if (aircraftShouldBeRemovedByMapAreaDeletePlanes(ac, state)) {
                        removeAircraftIds.add(ac.id);
                    }
                } catch (eMapAreaDel) {}
            }

            // Host-only on joiners: do not derive label GS or Mode-S from local performance math between polls.
            if (!simulationJoinedSessionId) {
                try { applyAutoSpeedReadoutMode(ac); } catch (e) {}
                try {
                    const mcFeet = Number(ac.publishedModeCFeet ?? ac.modeCFeet);
                    const flNow = isFinite(mcFeet) ? Math.max(0, Math.min(500, Math.round(mcFeet / 100))) : null;
                    const hasSpeedCommand = !!(ac.speedSelectedType || ac.speedChangeStartSimSec != null);
                    const departureActive = !!ac.departureProfileActive;
                    if (hasSpeedCommand && ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) {
                        state.labelGs = Math.round(ac.modeSTasKt);
                    } else if (departureActive && ac.modeSTasKt != null && isFinite(ac.modeSTasKt)) {
                        state.labelGs = Math.round(ac.modeSTasKt);
                    } else if (flNow != null) {
                        const gsLabel = computeGroundSpeedKt(ac.aircraftType, flNow);
                        if (gsLabel != null && isFinite(gsLabel)) {
                            state.labelGs = gsLabel;
                            ac.modeSTasKt = gsLabel;
                        }
                    }
                } catch (e) {}
            }
            try { maybeClearExePlnRocDisplayAtAlv(ac); } catch (e) {}

            if (ac.publishedLabelGsKt != null && isFinite(ac.publishedLabelGsKt)) {
                state.labelGs = Number(ac.publishedLabelGsKt);
            } else if (simulationJoinedSessionId && ac._displayGs != null && isFinite(ac._displayGs)) {
                state.labelGs = Math.round(Number(ac._displayGs));
            }

            // Probing Level (XLV) highlight/grey logic (active only while XLV picker is open/hovering)
            const probingMode = (simulationSettings?.probingLevelMode || SIM_SETTINGS_DEFAULTS.probingLevelMode || 'off').toString().toLowerCase();
            const probeHighlightColor = simulationSettings?.probingHighlightColor || SIM_SETTINGS_DEFAULTS.probingHighlightColor || aircraftTargetColor;
            const probeDimColor = simulationSettings?.probingDimColor || SIM_SETTINGS_DEFAULTS.probingDimColor || aircraftGreyColor;
            let probeActive = false;
            let isHighlighted = true;

            // Source aircraft is either the one that opened the XLV picker, or the one being middle-held on XLV,
            // or the EN-MGMT row hold on an unavailable XFL.
            const enMgmtHoldActive = simulationEnMgmtXflHoldProbeActive
                && simulationEnMgmtXflHoldProbeSourceId != null
                && simulationEnMgmtXflHoldProbeFl != null;
            const srcId = enMgmtHoldActive
                ? simulationEnMgmtXflHoldProbeSourceId
                : (simulationXlvPickerAircraftId || (simulationXlvHoldProbeActive ? simulationXlvHoldProbeSourceId : null));
            // Probed level is either the hovered level in the XLV popup, or the held-aircraft's current XLV
            const probedFl = enMgmtHoldActive
                ? simulationEnMgmtXflHoldProbeFl
                : ((simulationXlvPickerAircraftId && simulationXlvProbeActive && simulationXlvProbeHoveredFl != null)
                    ? simulationXlvProbeHoveredFl
                    : (simulationXlvHoldProbeActive ? simulationXlvHoldProbeFl : null));

            if (enMgmtHoldActive) {
                probeActive = true;
                isHighlighted = simulationEnMgmtXflHoldProbeAffectedIds?.has(String(ac.id)) ?? false;
            } else if ((probingMode === 'on' || probingMode === 'same_route' || probingMode === 'same_crossing_routes') && srcId && probedFl != null) {
                probeActive = true;
                const xlv = parseInt(ac.exitLevelFl ?? ac.rlv, 10);
                const matchLevel = Number.isFinite(xlv) && xlv === probedFl;

                if (probingMode === 'on') {
                    isHighlighted = matchLevel;
                } else if (probingMode === 'same_route') {
                    const src = (window.simulationData.aircraft || []).find(a => a && a.id === srcId);
                    const srcRoute = (src?.routeStr || '').toString();
                    const myRoute = (ac?.routeStr || '').toString();
                    isHighlighted = matchLevel && !!srcRoute && srcRoute === myRoute;
                } else if (probingMode === 'same_crossing_routes') {
                    const src = (window.simulationData.aircraft || []).find(a => a && a.id === srcId);
                    const srcWpSet = waypointNameSetFromAircraft(src);
                    const myWpSet = waypointNameSetFromAircraft(ac);
                    const hasCommon = srcWpSet.size > 0 && myWpSet.size > 0 && [...myWpSet].some(n => srcWpSet.has(n));
                    isHighlighted = matchLevel && hasCommon;
                }
            }

            // The aircraft we're actively editing/probing from always stays normal-colored
            const isSourceAircraft = (srcId && ac.id === srcId);
            let acColor = (isSourceAircraft || !probeActive) ? aircraftTargetColor : (isHighlighted ? probeHighlightColor : probeDimColor);
            let labelColor = (isSourceAircraft || !probeActive) ? labelBaseColor : (isHighlighted ? probeHighlightColor : probeDimColor);
            let forceLabelColor = (!isSourceAircraft && probeActive && !isHighlighted);
            let flightStatusTintActive = false;
            let flightStatusTintPrimary = null;
            let flightStatusTintSecondary = null;
            // XLV / XFL level probing (picker or hold) must win over flight-status tints so matches stay highlighted and non-matches stay dimmed.
            if (!stcaConflictAircraftIds.has(ac.id) && !probeActive) {
                const uctx = getSimulationUserAtcSectorContext();
                if (uctx.mode === 'single') {
                    const fstTint = (key) => {
                        const fsc = simulationSettings?.flightStatusColors?.[key] || SIM_SETTINGS_DEFAULTS.flightStatusColors[key];
                        const dp = SIM_SETTINGS_DEFAULTS.flightStatusColors[key];
                        flightStatusTintActive = true;
                        flightStatusTintPrimary = (fsc && fsc.primary) ? fsc.primary : (dp?.primary || '#888888');
                        flightStatusTintSecondary = (fsc && fsc.secondary) ? fsc.secondary : (dp?.secondary || '#888888');
                        acColor = flightStatusTintSecondary;
                        labelColor = flightStatusTintSecondary;
                        forceLabelColor = false;
                    };
                    const recvAsm = getAcTransferReceiverAssumed(ac);
                    const xferFromId = getAcTransferFromAtcSectorId(ac);
                    const xferToNm = getAcTransferToSectorNameNorm(ac);
                    if (recvAsm && xferFromId && String(uctx.atcSectorId) === String(xferFromId)) {
                        fstTint(aircraftIsInsideAtcSectorBoundaryById(ac, xferFromId) ? 'COU' : 'UOU');
                    } else if (aircraftTransferInProgress(ac) && !recvAsm && xferFromId && String(uctx.atcSectorId) === String(xferFromId)) {
                        fstTint('TOU');
                    } else if (aircraftTransferInProgress(ac) && !recvAsm && xferToNm && uctx.sectorNameNorm === xferToNm) {
                        fstTint('TIN');
                    } else if (aircraftIsAsmActiveForCurrentUserContext(ac)) {
                        fstTint('ASM');
                    } else if (aircraftHasCinFlightStatus(ac)) {
                        fstTint('CIN');
                    } else {
                        fstTint(aircraftIsInsideAtcSectorBoundaryById(ac, uctx.atcSectorId) ? 'UIN' : 'UOU');
                    }
                }
            }
            if (stcaConflictAircraftIds.has(ac.id)) {
                acColor = '#dc2626';
                labelColor = '#dc2626';
                forceLabelColor = true;
                flightStatusTintActive = false;
            }

            // Trail dots: host-sampled history on joiners; local route math on host/solo.
            if (trailDots > 0) {
                simulationCtx.fillStyle = hexToRgba(acColor, 0.35);
                for (let i = 1; i <= trailDots; i++) {
                    const tSec = simSec - i * radarSec;
                    if (tSec < (parseInt(ac.spawnTimeSec, 10) || 0)) continue;
                    const prev = simulationJoinedSessionId
                        ? getJoinerTrailDotAtOrBefore(ac, tSec)
                        : getAircraftPositionAtRadarUpdate(ac, tSec, radarSec);
                    if (!prev || !isFinite(prev.lat) || !isFinite(prev.lon)) continue;

                    let prLon = prev.lon;
                    let prLat = prev.lat;
                    if (simCentreWaypoint) {
                        prLon = prev.lon - simCentreWaypoint.longitude;
                        prLat = prev.lat - simCentreWaypoint.latitude;
                    }
                    const px = effectiveOriginX + prLon * simulationZoomLevel * simLonScale;
                    const py = effectiveOriginY - prLat * simulationZoomLevel;
                    if (!isFinite(px) || !isFinite(py)) continue;
                    simulationCtx.beginPath();
                    simulationCtx.arc(px, py, trailRPx, 0, Math.PI * 2);
                    simulationCtx.fill();
                }
                simulationCtx.fillStyle = acColor;
            }

            let relLon = state.lon;
            let relLat = state.lat;
            if (simCentreWaypoint) {
                relLon = state.lon - simCentreWaypoint.longitude;
                relLat = state.lat - simCentreWaypoint.latitude;
            }

            const x = effectiveOriginX + relLon * simulationZoomLevel * simLonScale;
            const y = effectiveOriginY - relLat * simulationZoomLevel;
            if (!isFinite(x) || !isFinite(y)) return;

            simulationAircraftScreenStates.push({
                aircraftId: ac.id,
                x,
                y,
                lat: state.lat,
                lon: state.lon,
                gs: (state?.labelGs != null && isFinite(state.labelGs)) ? state.labelGs : state.gs
            });

            // Speed vector (SPV): line showing distance traveled in N minutes
            const showSpvForAc = spvGlobalEnabled || simulationSpvAircraftIds.has(ac.id);
            if (showSpvForAc && spvMinutes > 0) {
                const gsVec = (state?.labelGs != null && isFinite(state.labelGs)) ? Number(state.labelGs) : (isFinite(state.gs) ? Number(state.gs) : null);
                const extraNm = (gsVec != null && isFinite(gsVec)) ? (gsVec * spvMinutes) / 60 : null;

                // If we have a published heading (only changes on radar updates), draw SPV on that heading (so turns are visible only on sweeps).
                const hdgPub = (ac.publishedHeadingDeg != null && isFinite(ac.publishedHeadingDeg)) ? Number(ac.publishedHeadingDeg) : null;
                let target = null;
                if (hdgPub != null && extraNm != null) {
                    target = projectLatLonByNm(state.lat, state.lon, hdgPub, extraNm);
                } else if (extraNm != null && isFinite(state.traveledNm)) {
                    if (simulationJoinedSessionId && isJoinerAtmDisplayClient()) {
                        const acSeq = getAircraftForAtmTrajectorySequence(ac);
                        const dpts = acSeq && acSeq.points;
                        target = (Array.isArray(dpts) && dpts.length >= 2)
                            ? getAircraftPositionAlongTrackAtDistanceNmFromPoints(dpts, state.traveledNm + extraNm)
                            : getAircraftPositionAlongTrackAtDistanceNm(ac, state.traveledNm + extraNm);
                    } else {
                        target = getAircraftPositionAlongTrackAtDistanceNm(ac, state.traveledNm + extraNm);
                    }
                }

                if (target && isFinite(target.lat) && isFinite(target.lon)) {
                    let tvLon = target.lon;
                    let tvLat = target.lat;
                    if (simCentreWaypoint) {
                        tvLon = target.lon - simCentreWaypoint.longitude;
                        tvLat = target.lat - simCentreWaypoint.latitude;
                    }
                    const tx = effectiveOriginX + tvLon * simulationZoomLevel * simLonScale;
                    const ty = effectiveOriginY - tvLat * simulationZoomLevel;
                    if (isFinite(tx) && isFinite(ty)) {
                        simulationCtx.strokeStyle = hexToRgba(acColor, 0.85);
                        simulationCtx.lineWidth = 2;
                        simulationCtx.beginPath();
                        simulationCtx.moveTo(x, y);
                        simulationCtx.lineTo(tx, ty);
                        simulationCtx.stroke();
                        simulationCtx.strokeStyle = '#000000';
                        simulationCtx.lineWidth = 1;
                    }
                }
            }

            // Always draw aircraft symbol with fixed styles (avoid leaked canvas state)
            simulationCtx.fillStyle = acColor;
            simulationCtx.strokeStyle = '#000000';
            simulationCtx.lineWidth = 1;
            simulationCtx.beginPath();
            simulationCtx.arc(x, y, rPx, 0, Math.PI * 2);
            simulationCtx.fill();
            simulationCtx.stroke();

            if (simulationSelectedAircraftId != null && String(ac.id) === String(simulationSelectedAircraftId)) {
                const ringColor = simulationSettings?.selectedAircraftRingColor ?? SIM_SETTINGS_DEFAULTS.selectedAircraftRingColor;
                const thick = Math.max(1, Math.min(12, parseInt(simulationSettings?.selectedAircraftRingThicknessPx, 10) || SIM_SETTINGS_DEFAULTS.selectedAircraftRingThicknessPx));
                const gap = 2;
                const ringR = rPx + gap + thick / 2;
                simulationCtx.save();
                simulationCtx.beginPath();
                simulationCtx.arc(x, y, ringR, 0, Math.PI * 2);
                simulationCtx.strokeStyle = ringColor;
                simulationCtx.lineWidth = thick;
                simulationCtx.stroke();
                simulationCtx.restore();
            }

            // Trajectory + ETA estimates (toggled with middle-click on callsign)
            if (simulationTrajectoryAircraftIds && simulationTrajectoryOverlayHasAircraftId(ac.id)) {
                simulationCtx.save();
                const acForTrajDraw = getAircraftForAtmTrajectorySequence(ac);
                const pts = acForTrajDraw.points || [];

                // Local cache for this draw (ATM display route may differ from FMS ac.points; do not clobber ac._trackCache).
                let trajDrawCache = null;
                try {
                    const trajGeomSig = getAircraftPointsGeometrySignature(acForTrajDraw);
                    if (!ac._atmTrajDrawCache || ac._atmTrajDrawCache.geomSig !== trajGeomSig) {
                        const legsNm = [];
                        const cumNm = [0];
                        let sum = 0;
                        for (let i = 0; i < pts.length - 1; i++) {
                            const p0 = pts[i];
                            const p1 = pts[i + 1];
                            const d = calculateNauticalMiles(p0.lat, p0.lon, p1.lat, p1.lon);
                            const leg = (isFinite(d) && d > 0) ? d : 0;
                            legsNm.push(leg);
                            sum += leg;
                            cumNm.push(sum);
                        }
                        ac._atmTrajDrawCache = { n: pts.length, legsNm, cumNm, totalNm: sum, geomSig: trajGeomSig };
                    }
                    trajDrawCache = ac._atmTrajDrawCache;
                } catch (e) {}

                const cache = trajDrawCache;
                const cumNm = cache?.cumNm;
                const legsNm = cache?.legsNm;

                if (Array.isArray(pts) && pts.length >= 2 && Array.isArray(cumNm) && Array.isArray(legsNm)) {
                    const joinerAtmTrajDraw = simulationJoinedSessionId && isJoinerAtmDisplayClient();
                    let segIdx = 0;
                    let tNm = Math.max(0, Number(state.traveledNm) || 0);
                    if (joinerAtmTrajDraw) {
                        segIdx = getJoinerAtmRouteProgressIdx(ac);
                        const tSeg = computeTraveledNmAlongRouteOnSegmentFromPosition(pts, segIdx, state.lat, state.lon);
                        if (isFinite(tSeg)) tNm = Math.max(0, tSeg);
                    } else if (acForTrajDraw.navMode === 'heading') {
                        segIdx = Math.max(0, Math.min(pts.length - 2, parseInt(acForTrajDraw.routeProgressIdx, 10) || 0));
                    } else {
                        for (let i = 0; i < legsNm.length; i++) {
                            const s0 = cumNm[i];
                            const s1 = cumNm[i + 1];
                            if (tNm >= s0 && tNm <= s1) { segIdx = i; break; }
                        }
                    }

                    // Draw polyline from current position to remaining route points
                    const trajCol = (flightStatusTintActive && flightStatusTintSecondary)
                        ? flightStatusTintSecondary
                        : (simulationStyle?.trajectory?.color || SIM_STYLE_DEFAULTS.trajectory.color);
                    simulationCtx.strokeStyle = hexToRgba(trajCol, 0.75);
                    simulationCtx.lineWidth = 2;
                    const displayMode = (simulationSettings?.trajectoryDisplayMode || SIM_SETTINGS_DEFAULTS.trajectoryDisplayMode || 'point_to_point').toString().toLowerCase();

                    // Build list of points to draw, starting at current aircraft position.
                    const drawPts = [];
                    drawPts.push({ lat: state.lat, lon: state.lon, x, y });
                    for (let i = segIdx + 1; i < pts.length; i++) {
                        const p = pts[i];
                        if (!p || !isFinite(p.lat) || !isFinite(p.lon)) continue;
                        let rLon = p.lon;
                        let rLat = p.lat;
                        if (simCentreWaypoint) {
                            rLon = p.lon - simCentreWaypoint.longitude;
                            rLat = p.lat - simCentreWaypoint.latitude;
                        }
                        const px = effectiveOriginX + rLon * simulationZoomLevel * simLonScale;
                        const py = effectiveOriginY - rLat * simulationZoomLevel;
                        if (!isFinite(px) || !isFinite(py)) continue;
                        drawPts.push({ lat: p.lat, lon: p.lon, x: px, y: py });
                    }

                    simulationCtx.beginPath();
                    simulationCtx.moveTo(x, y);
                    if (drawPts.length >= 2 && displayMode === 'turn_radius') {
                        const gsKt = Number(state.gs);
                        const simWaypoints2 = window.simulationData?.waypoints || [];
                        const simCentreWaypoint2 = simWaypoints2.find(wp => isCenterWaypointName(wp?.name));
                        const refLatDeg = (simCentreWaypoint2 && isFinite(simCentreWaypoint2.latitude)) ? simCentreWaypoint2.latitude : Number(state.lat);

                        // Build a lat/lon list starting at current position then remaining waypoints.
                        const latLonList = [];
                        latLonList.push({ lat: Number(state.lat), lon: Number(state.lon) });
                        for (let i = segIdx + 1; i < pts.length; i++) {
                            const p = pts[i];
                            if (!p || !isFinite(p.lat) || !isFinite(p.lon)) continue;
                            latLonList.push({ lat: Number(p.lat), lon: Number(p.lon) });
                        }

                        const toCanvasXY = (lat, lon) => {
                            let rLon = lon;
                            let rLat = lat;
                            if (simCentreWaypoint) {
                                rLon = lon - simCentreWaypoint.longitude;
                                rLat = lat - simCentreWaypoint.latitude;
                            }
                            return {
                                x: effectiveOriginX + rLon * simulationZoomLevel * simLonScale,
                                y: effectiveOriginY - rLat * simulationZoomLevel
                            };
                        };

                        // Emit a path that uses true turn-radius geometry (tangents + arc) in lat/lon space.
                        let cur = latLonList[0];
                        const startXY = toCanvasXY(cur.lat, cur.lon);
                        simulationCtx.lineTo(startXY.x, startXY.y);

                        for (let i = 1; i < latLonList.length - 1; i++) {
                            const A = latLonList[i - 1];
                            const B = latLonList[i];
                            const C = latLonList[i + 1];
                            const arc = computeTurnArcPointsLocalXY(acForTrajDraw, gsKt, refLatDeg, A, B, C);
                            if (!arc) {
                                const bxy = toCanvasXY(B.lat, B.lon);
                                simulationCtx.lineTo(bxy.x, bxy.y);
                                cur = B;
                                continue;
                            }

                            // Line to inbound tangent
                            const t1ll = localXYToLatLon(arc.t1.x, arc.t1.y, refLatDeg);
                            const t1xy = toCanvasXY(t1ll.lat, t1ll.lon);
                            simulationCtx.lineTo(t1xy.x, t1xy.y);

                            // Arc samples (skip first point to avoid duplicate)
                            for (let k = 1; k < arc.arcPts.length; k++) {
                                const pll = localXYToLatLon(arc.arcPts[k].x, arc.arcPts[k].y, refLatDeg);
                                const pxy = toCanvasXY(pll.lat, pll.lon);
                                simulationCtx.lineTo(pxy.x, pxy.y);
                            }

                            // Continue from outbound tangent
                            const t2ll = localXYToLatLon(arc.t2.x, arc.t2.y, refLatDeg);
                            cur = { lat: t2ll.lat, lon: t2ll.lon };
                        }

                        // Line to final waypoint
                        const lastLL = latLonList[latLonList.length - 1];
                        const lastXY = toCanvasXY(lastLL.lat, lastLL.lon);
                        simulationCtx.lineTo(lastXY.x, lastXY.y);
                    } else {
                        for (let i = 1; i < drawPts.length; i++) {
                            const p = drawPts[i];
                            simulationCtx.lineTo(p.x, p.y);
                        }
                    }
                    simulationCtx.stroke();
                    simulationCtx.lineWidth = 1;

                    // ETA at each (named) waypoint from current position using constant current GS
                    const gs = Number(state.gs);
                    if (isFinite(gs) && gs > 0) {
                        const formatHHMM = (totalSeconds) => {
                            const s = Math.max(0, Math.floor(totalSeconds || 0)) % 86400;
                            const hh = String(Math.floor(s / 3600)).padStart(2, '0');
                            const mm = String(Math.floor((s % 3600) / 60)).padStart(2, '0');
                            return `${hh}:${mm}`;
                        };
                        const base = getSimulationClockSeconds();
                        simulationCtx.font = 'bold 12px Arial';
                        const trajCol = (flightStatusTintActive && flightStatusTintSecondary)
                            ? flightStatusTintSecondary
                            : (simulationStyle?.trajectory?.color || SIM_STYLE_DEFAULTS.trajectory.color);
                        simulationCtx.fillStyle = trajCol;
                        simulationCtx.textAlign = 'left';
                        simulationCtx.textBaseline = 'top';
                        const trajShowFl = ((simulationSettings?.trajectoryShowLabels || SIM_SETTINGS_DEFAULTS.trajectoryShowLabels) === 'estimates_and_fl');

                        // Remaining distance model:
                        // - Route-nav: remaining distance along planned track = cumNm[i] - tNm.
                        // - Heading-nav: remaining distance from CURRENT position to next waypoint + remaining legs beyond.
                        const trajHeadingNav = !joinerAtmTrajDraw && acForTrajDraw.navMode === 'heading';
                        const dToNextNm = (trajHeadingNav && pts[segIdx + 1])
                            ? calculateNauticalMiles(state.lat, state.lon, pts[segIdx + 1].lat, pts[segIdx + 1].lon)
                            : null;
                        const baseAlongNm = trajHeadingNav ? (cumNm[segIdx + 1] ?? null) : null;

                        for (let i = segIdx + 1; i < pts.length; i++) {
                            const p = pts[i];
                            const name = (p?.name || '').toString().trim();
                            if (!name) continue; // only show at named waypoints
                            const alongNm = cumNm[i];
                            if (!isFinite(alongNm)) continue;
                            let remainNm = alongNm - tNm;
                            if (trajHeadingNav) {
                                if (!isFinite(dToNextNm) || dToNextNm < 0) continue;
                                const baseAl = Number(baseAlongNm);
                                if (!isFinite(baseAl)) continue;
                                // current->next + (next->i along route)
                                remainNm = dToNextNm + Math.max(0, alongNm - baseAl);
                            }
                            if (!isFinite(remainNm) || remainNm < 0) continue;
                            const etaSec = base + (remainNm / gs) * 3600;
                            const txt = formatHHMM(etaSec);
                            const dtSec = (remainNm / gs) * 3600;
                            const flFromWp = (p.fl != null && Number.isFinite(p.fl)) ? Math.round(p.fl) : null;
                            const flEst = flFromWp != null ? flFromWp : estimateFlAtTrajectoryEta(acForTrajDraw, dtSec);

                            let rLon = p.lon;
                            let rLat = p.lat;
                            if (simCentreWaypoint) {
                                rLon = p.lon - simCentreWaypoint.longitude;
                                rLat = p.lat - simCentreWaypoint.latitude;
                            }
                            const px = effectiveOriginX + rLon * simulationZoomLevel * simLonScale;
                            const py = effectiveOriginY - rLat * simulationZoomLevel;
                            if (!isFinite(px) || !isFinite(py)) continue;

                            const tx = px + 6;
                            const tyEta = py - 10;
                            if (trajShowFl) {
                                const flTxt = `FL${flEst}`;
                                const tyFl = py - 26;
                                simulationCtx.fillText(flTxt, tx, tyFl);
                                simulationCtx.fillText(txt, tx, tyEta);
                                const wFl = simulationCtx.measureText(flTxt).width;
                                const wEta = simulationCtx.measureText(txt).width;
                                const tw = Math.max(wFl, wEta);
                                simulationTrajectoryEstimateBounds.push({
                                    aircraftId: ac.id,
                                    x: tx,
                                    y: tyFl,
                                    w: tw,
                                    h: 30
                                });
                            } else {
                                simulationCtx.fillText(txt, tx, tyEta);
                                const wEta = simulationCtx.measureText(txt).width;
                                simulationTrajectoryEstimateBounds.push({
                                    aircraftId: ac.id,
                                    x: tx,
                                    y: tyEta,
                                    w: wEta,
                                    h: 14
                                });
                            }
                        }
                    }
                }
                simulationCtx.restore();
            }

            // Label with connecting line; label stays fixed offset from aircraft in screen pixels
            // Free text should only be visible while hovered/dragged (square indicates when it exists)
            if (ac.hideLabel) {
                return; // hide label + leaderline during landing rollout (but keep aircraft symbol + history visible)
            }
            const isLabelHovered = isSimulationAircraftLabelHovered(ac);
            const showFreeText = isLabelHovered;
            const lines = getLabelLayoutLinesForAircraft(ac, state, { showFreeText, hover: isLabelHovered });
            const segLines = getLabelLayoutSegmentsForAircraft(ac, state, { showFreeText, hover: isLabelHovered });
            const hasFreeTextField = labelLayoutHasFreeTextForAircraft(ac, { hover: isLabelHovered });
            if (!lines.length) {
                // nothing to show, but still keep drag bounds empty
                return;
            }
            const labelFontSize = Math.min(24, Math.max(8, parseInt(simulationMap?.labelSize ?? SIM_MAP_DEFAULTS.labelSize, 10) || SIM_MAP_DEFAULTS.labelSize));
            const padX = 6, padY = 5, lineH = Math.round(labelFontSize + 2);
            simulationCtx.font = `bold ${labelFontSize}px Arial`;
            let w = Math.max(
                ...lines.map(t => simulationCtx.measureText(t || ' ').width)
            ) + padX * 2;
            // Reserve space for the clickable free-text square so it never touches the last token
            if (hasFreeTextField) w += 16;
            const h = padY * 2 + lineH * lines.length;

            // labelOffsetX/Y = vector aircraft → label center (screen px). Legacy: top-left offset until migrated once.
            let cxOff = Number.isFinite(ac.labelOffsetX) ? ac.labelOffsetX : 28;
            let cyOff = Number.isFinite(ac.labelOffsetY) ? ac.labelOffsetY : -28;
            if (!ac.labelLeaderOffsetToCenter) {
                cxOff += w / 2;
                cyOff += h / 2;
                ac.labelOffsetX = cxOff;
                ac.labelOffsetY = cyOff;
                ac.labelLeaderOffsetToCenter = true;
            }
            const labelMidX = x + cxOff;
            const labelMidY = y + cyOff;
            const lx = labelMidX - w / 2;
            const ly = labelMidY - h / 2;
            const alvFlNum = parseInt(ac.assignedFl ?? ac.alv, 10);
            labelItems.push({
                aircraftId: ac.id,
                lx, ly, w, h,
                labelMidX,
                labelMidY,
                acX: x, acY: y,
                lines,
                segLines,
                labelColor,
                forceLabelColor,
                flightStatusTintActive,
                flightStatusTintPrimary: flightStatusTintPrimary || '#C71585',
                flightStatusTintSecondary: flightStatusTintSecondary || '#FF00FF',
                ppWorkloadRect: !!(ppWorkloadAssignmentByAircraftId &&
                    ppMyClientId &&
                    ppWorkloadAssignmentByAircraftId.get(String(ac.id)) === ppMyClientId),
                alvModesMismatchFlash: alvModesMismatchFlashActive(ac),
                alvMismatchFl: Number.isFinite(alvFlNum) ? alvFlNum : null,
                fontSize: labelFontSize,
                padX, padY, lineH,
                hasFreeTextField
            });
        });

        if (removeAircraftIds.size) {
            try {
                window.simulationData.aircraft = (window.simulationData.aircraft || []).filter(a => a && !removeAircraftIds.has(a.id));
            } catch (e) {}
            try {
                // Clean up runtime sets
                simulationTrajectoryAircraftIds = new Set(Array.from(simulationTrajectoryAircraftIds || []).filter((tid) => ![...removeAircraftIds].some((rid) => String(rid) === String(tid))));
                simulationSpvAircraftIds = new Set(Array.from(simulationSpvAircraftIds || []).filter((sid) => ![...removeAircraftIds].some((rid) => String(rid) === String(sid))));
            } catch (e) {}
            try {
                const sel = simulationSelectedAircraftId;
                if (sel != null && [...removeAircraftIds].some(rid => String(rid) === String(sel))) {
                    simulationSelectedAircraftId = null;
                    syncAdvancedLabelPanel();
                    try { syncSimulationEnMgmtSelectedAircraftHighlight({ scrollIntoView: false }); } catch (eEn) {}
                }
            } catch (e) {}
        }

        // Ensure z-order contains all active aircraft ids
        const activeIds = new Set(labelItems.map(it => it.aircraftId));
        simulationLabelZOrder = simulationLabelZOrder.filter(id => activeIds.has(id));
        labelItems.forEach(it => {
            if (!simulationLabelZOrder.includes(it.aircraftId)) simulationLabelZOrder.push(it.aircraftId);
        });

        const byId = new Map(labelItems.map(it => [it.aircraftId, it]));

        // Draw labels in z-order; background only for hovered or dragged label
        simulationLabelZOrder.forEach(id => {
            const it = byId.get(id);
            if (!it) return;
            const isDraggingThis = simulationIsDraggingAircraftLabel && simulationDraggingAircraftId === id;
            const isHoveredThis = simulationHoveredAircraftLabelId === id;
            const opaque = isHoveredThis || isDraggingThis;

            // Leader: aircraft → label center; only the segment outside the label box is drawn
            const lmx = it.labelMidX;
            const lmy = it.labelMidY;
            const leaderStroke = (it.flightStatusTintActive && it.flightStatusTintSecondary) ? it.flightStatusTintSecondary : (it.labelColor || (simulationStyle?.labels?.textColor || '#111827'));
            simulationCtx.strokeStyle = leaderStroke;
            simulationCtx.lineWidth = 1;
            const ax = it.acX;
            const ay = it.acY;
            const rx = it.lx;
            const ry = it.ly;
            const rw = it.w;
            const rh = it.h;
            const insideA = ax >= rx && ax <= rx + rw && ay >= ry && ay <= ry + rh;
            const insideB = lmx >= rx && lmx <= rx + rw && lmy >= ry && lmy <= ry + rh;
            simulationCtx.beginPath();
            let drewLeader = false;
            let leaderX2 = lmx;
            let leaderY2 = lmy;
            if (!insideA && insideB) {
                const tHit = segmentFirstBoundaryT(ax, ay, lmx, lmy, rx, ry, rw, rh);
                if (tHit != null && isFinite(tHit)) {
                    leaderX2 = ax + tHit * (lmx - ax);
                    leaderY2 = ay + tHit * (lmy - ay);
                    simulationCtx.moveTo(ax, ay);
                    simulationCtx.lineTo(leaderX2, leaderY2);
                    drewLeader = true;
                }
            } else if (!insideA && !insideB) {
                simulationCtx.moveTo(ax, ay);
                simulationCtx.lineTo(lmx, lmy);
                drewLeader = true;
            }
            if (drewLeader) {
                simulationCtx.stroke();
                simulationAircraftLeaderLineBounds.push({
                    aircraftId: id,
                    x1: ax,
                    y1: ay,
                    x2: leaderX2,
                    y2: leaderY2
                });
            }

            if (it.ppWorkloadRect && it.flightStatusTintSecondary) {
                const rectX = it.lx - 1;
                const rectY = it.ly - 1;
                const rectW = it.w + 2;
                const rectH = it.h + 2;
                const strokeCol = ppWorkloadRectVisibleStrokeColor(it.flightStatusTintSecondary);
                simulationCtx.strokeStyle = '#111827';
                simulationCtx.lineWidth = 1;
                simulationCtx.strokeRect(rectX - 0.5, rectY - 0.5, rectW + 1, rectH + 1);
                simulationCtx.strokeStyle = strokeCol;
                simulationCtx.lineWidth = 2.5;
                simulationCtx.strokeRect(rectX, rectY, rectW, rectH);
                simulationCtx.lineWidth = 1;
            }

            if (opaque) {
                simulationCtx.fillStyle = hexToRgba(simulationStyle?.labels?.backgroundColor || '#ffffff', 0.92);
                simulationCtx.strokeStyle = 'rgba(0,0,0,0.55)';
                simulationCtx.lineWidth = 1;
                simulationCtx.beginPath();
                simulationCtx.rect(it.lx, it.ly, it.w, it.h);
                simulationCtx.fill();
                simulationCtx.stroke();
            }

            // Text (draw by segments so ALV can be clicked)
            simulationCtx.textAlign = 'left';
            simulationCtx.textBaseline = 'top';
            let ty = it.ly + it.padY;
            const segLines = Array.isArray(it.segLines) ? it.segLines : [];
            for (let li = 0; li < it.lines.length; li++) {
                const fs = Math.min(24, Math.max(8, parseInt(it.fontSize, 10) || (simulationMap?.labelSize ?? SIM_MAP_DEFAULTS.labelSize) || 12));
                simulationCtx.font = (li === 0) ? `bold ${fs}px Arial` : `${fs}px Arial`;
                const segs = segLines[li];
                if (Array.isArray(segs) && segs.length) {
                    const spaceW = simulationCtx.measureText(' ').width || 4;
                    let cx = it.lx + it.padX;
                    segs.forEach((seg, si) => {
                        const txt = (seg?.text || '').toString();
                        if (!txt) return;
                        const segKind = (seg?.kind || '').toString();
                        let color = it.labelColor || (simulationStyle?.labels?.textColor || '#111827');
                        if (seg.field === 'ALV' && it.alvModesMismatchFlash) {
                            const flashOn = (Math.floor(performance.now() / 380) % 2) === 0;
                            color = flashOn ? '#dc2626' : '#991b1b';
                        } else if (segKind === 'mode_s') {
                            color = simulationStyle?.modeS?.color || SIM_STYLE_DEFAULTS.modeS.color;
                        } else if (segKind === 'selected_speed') {
                            color = seg?.color || '#F87171';
                        } else if (segKind === 'selected_roc') {
                            color = seg?.color || '#22C55E';
                        } else if (segKind === 'hold_arm_lbl') {
                            color = seg?.color || '#dc2626';
                        } else if (it.flightStatusTintActive && it.flightStatusTintPrimary && it.flightStatusTintSecondary) {
                            color = (seg.field === 'CALLSIGN') ? it.flightStatusTintPrimary : it.flightStatusTintSecondary;
                        } else if (it.forceLabelColor) {
                            color = it.labelColor || color;
                        }
                        simulationCtx.fillStyle = color;
                        const w = simulationCtx.measureText(txt).width;
                        simulationCtx.fillText(txt, cx, ty);
                        if (seg.field === 'ALV') {
                            simulationAircraftAlvTextBounds.push({
                                aircraftId: id,
                                x: cx,
                                y: ty,
                                w,
                                h: it.lineH
                            });
                        }
                        if (seg.field === 'EXIT_LEVEL') {
                            simulationAircraftXlvTextBounds.push({
                                aircraftId: id,
                                x: cx,
                                y: ty,
                                w,
                                h: it.lineH
                            });
                        }
                        if (seg.field === 'CALLSIGN') {
                            simulationAircraftCallsignTextBounds.push({
                                aircraftId: id,
                                x: cx,
                                y: ty,
                                w,
                                h: it.lineH
                            });
                        }
                        if (seg.field === 'IAS' || seg.field === 'MACH') {
                            simulationAircraftSpeedTextBounds.push({
                                aircraftId: id,
                                x: cx,
                                y: ty,
                                w,
                                h: it.lineH
                            });
                        }
                        if (seg.field === 'ROC') {
                            simulationAircraftRocTextBounds.push({
                                aircraftId: id,
                                x: cx,
                                y: ty,
                                w,
                                h: it.lineH
                            });
                        }
                        if (seg.field === 'RWY') {
                            simulationAircraftRwyTextBounds.push({
                                aircraftId: id,
                                x: cx,
                                y: ty,
                                w,
                                h: it.lineH
                            });
                        }
                        if (seg.field === 'HDG_DCT') {
                            simulationAircraftHdgDctTextBounds.push({
                                aircraftId: id,
                                x: cx,
                                y: ty,
                                w,
                                h: it.lineH
                            });
                        }
                        cx += w;
                        if (si < segs.length - 1) cx += spaceW;
                    });
                } else {
                    const rawLine = it.lines[li] || '';
                    let fillLine = it.labelColor || (simulationStyle?.labels?.textColor || '#111827');
                    if (it.alvModesMismatchFlash && it.alvMismatchFl != null) {
                        const trimmed = rawLine.trim();
                        if (/^\d{1,3}$/.test(trimmed) && parseInt(trimmed, 10) === it.alvMismatchFl) {
                            const flashOn = (Math.floor(performance.now() / 380) % 2) === 0;
                            fillLine = flashOn ? '#dc2626' : '#991b1b';
                        }
                    }
                    simulationCtx.fillStyle = fillLine;
                    simulationCtx.fillText(rawLine, it.lx + it.padX, ty);
                }
                ty += it.lineH;
            }

            const saved = (simulationAircraftFreeTextById?.[id] || '').toString().trim();
            // Free-text indicator square:
            // - If free text exists: show ALWAYS (yellow filled)
            // - If no free text: show ONLY while hovered/dragged (outline only)
            const showSquare = it.hasFreeTextField && it.lines.length && (saved || opaque);
            if (showSquare) {
                const textColor = it.labelColor || (simulationStyle?.labels?.textColor || '#111827');
                const lineIdx = Math.min(2, it.lines.length - 1);
                const fs = Math.min(24, Math.max(8, parseInt(it.fontSize, 10) || 12));
                const size = Math.min(16, Math.max(6, Math.round(fs * 0.7)));
                const lineText = (it.lines[lineIdx] || '').toString();
                // line 0 was bold; others are regular
                simulationCtx.font = (lineIdx === 0) ? `bold ${fs}px Arial` : `${fs}px Arial`;
                const tw = simulationCtx.measureText(lineText).width;
                const sw = simulationCtx.measureText(' ').width || 4; // ensure visible gap before square
                const gap = Math.max(3, Math.round(fs * 0.25));
                let sx = it.lx + it.padX + tw + sw + gap;
                const maxSx = it.lx + it.w - it.padX - size;
                if (sx > maxSx) sx = maxSx;
                const lift = Math.max(1, fs * 0.12);
                const sy = it.ly + it.padY + (lineIdx * it.lineH) + (it.lineH - size) / 2 - lift;

                simulationCtx.lineWidth = 1.5;
                simulationCtx.strokeStyle = saved ? '#FFEB3B' : textColor;
                if (saved) {
                    simulationCtx.fillStyle = '#FFEB3B'; // bright yellow
                    simulationCtx.fillRect(sx, sy, size, size);
                }
                simulationCtx.strokeRect(sx, sy, size, size);
                simulationCtx.lineWidth = 1;

                simulationAircraftFreeTextIconBounds.push({
                    aircraftId: id,
                    x: sx,
                    y: sy,
                    w: size,
                    h: size
                });
            }

            simulationAircraftLabelBounds.push({
                aircraftId: id,
                x: it.lx,
                y: it.ly,
                w: it.w,
                h: it.h,
                acX: it.acX,
                acY: it.acY
            });
        });
        
        // Draw measurements - draw after waypoints so they appear on top
        measurementTextBounds = []; // Reset bounds array

        const resolveEndpointLatLon = (ep) => {
            if (!ep || typeof ep !== 'object') return null;
            if (ep.type === 'coord') {
                if (!isFinite(ep.lat) || !isFinite(ep.lon)) return null;
                return { lat: ep.lat, lon: ep.lon };
            }
            if (ep.type === 'aircraft') {
                const id = ep.aircraftId;
                const a = simulationAircraftScreenStates.find(x => x && x.aircraftId === id);
                if (!a || !isFinite(a.lat) || !isFinite(a.lon)) return null;
                return { lat: a.lat, lon: a.lon };
            }
            return null;
        };

        measurements.forEach((measurement, index) => {
            if (!measurement || !measurement.start || !measurement.end) return;
            const measurementColor = measurement.color || MEASUREMENT_COLORS[index % MEASUREMENT_COLORS.length];

            const sLL = resolveEndpointLatLon(measurement.start);
            const eLL = resolveEndpointLatLon(measurement.end);
            if (!sLL || !eLL) return;

            const distance = calculateNauticalMiles(sLL.lat, sLL.lon, eLL.lat, eLL.lon);

            let startRelLon = sLL.lon;
            let startRelLat = sLL.lat;
            let endRelLon = eLL.lon;
            let endRelLat = eLL.lat;
            
            if (simCentreWaypoint) {
                startRelLon = sLL.lon - simCentreWaypoint.longitude;
                startRelLat = sLL.lat - simCentreWaypoint.latitude;
                endRelLon = eLL.lon - simCentreWaypoint.longitude;
                endRelLat = eLL.lat - simCentreWaypoint.latitude;
            }
            
            const startX = effectiveOriginX + startRelLon * simulationZoomLevel * simLonScale;
            const startY = effectiveOriginY - startRelLat * simulationZoomLevel;
            const endX = effectiveOriginX + endRelLon * simulationZoomLevel * simLonScale;
            const endY = effectiveOriginY - endRelLat * simulationZoomLevel;
            
            if (!isFinite(startX) || !isFinite(startY) || !isFinite(endX) || !isFinite(endY)) return;
            
            // Draw measurement line
            simulationCtx.strokeStyle = measurementColor;
            simulationCtx.lineWidth = 1;
            simulationCtx.beginPath();
            simulationCtx.moveTo(startX, startY);
            simulationCtx.lineTo(endX, endY);
            simulationCtx.stroke();
            
            // Draw distance text at end point
            if (distance !== undefined && isFinite(distance)) {
                simulationCtx.fillStyle = measurementColor;
                simulationCtx.font = 'bold 14px Arial';
                simulationCtx.textAlign = 'left';
                simulationCtx.textBaseline = 'top';
                const distanceText = `${distance.toFixed(1)}`;
                const bearing = heading0to359(calculateBearingDegrees(
                    sLL.lat, sLL.lon,
                    eLL.lat, eLL.lon
                ));
                const bearingBack = (bearing + 180) % 360;
                const directionText = `${formatHeadingFrom0to359(bearing)} ${formatHeadingFrom0to359(bearingBack)}`;

                // If measurement is exactly aircraft <-> coord, add minutes-to-go using that aircraft's GS
                let minutesText = null;
                try {
                    const sType = measurement.start?.type;
                    const eType = measurement.end?.type;
                    const isAircraftCoord = (sType === 'aircraft' && eType === 'coord') || (sType === 'coord' && eType === 'aircraft');
                    if (isAircraftCoord) {
                        const acId = (sType === 'aircraft') ? measurement.start.aircraftId : measurement.end.aircraftId;
                        const a = simulationAircraftScreenStates.find(x => x && x.aircraftId === acId);
                        const gs = Number(a?.gs);
                        if (isFinite(gs) && gs > 0 && isFinite(distance) && distance >= 0) {
                            const mins = (distance / gs) * 60;
                            minutesText = String(Math.max(0, Math.round(mins)));
                        }
                    }
                } catch (e) {}

                const distanceWidth = simulationCtx.measureText(distanceText).width;
                const directionWidth = simulationCtx.measureText(directionText).width;
                const minutesWidth = minutesText ? simulationCtx.measureText(minutesText).width : 0;
                const textWidth = Math.max(distanceWidth, directionWidth, minutesWidth);
                const lineHeight = 16;
                const blockHeight = lineHeight * (minutesText ? 3 : 2);
                
                const textX = endX + 5;
                const textY = endY - blockHeight / 2;
                const textRectWidth = textWidth + 8;
                const textRectHeight = blockHeight + 4;
                
                // Store text bounds for click detection
                measurementTextBounds.push({
                    index: index,
                    x: textX,
                    y: textY,
                    width: textRectWidth,
                    height: textRectHeight
                });
                
                // Draw text (no background rectangle)
                simulationCtx.fillStyle = measurementColor;
                simulationCtx.fillText(distanceText, textX + 4, textY + 2);
                simulationCtx.fillText(directionText, textX + 4, textY + 2 + lineHeight);
                if (minutesText) {
                    simulationCtx.fillText(minutesText, textX + 4, textY + 2 + lineHeight * 2);
                }
            }
        });
        
        // Draw active measurement (while measuring) - also on top
        if (isMeasuring && measureStartEndpoint && measureCurrentMousePos) {
            const sLL = resolveEndpointLatLon(measureStartEndpoint);
            if (!sLL) return;

            let startRelLon = sLL.lon;
            let startRelLat = sLL.lat;
            
            if (simCentreWaypoint) {
                startRelLon = sLL.lon - simCentreWaypoint.longitude;
                startRelLat = sLL.lat - simCentreWaypoint.latitude;
            }
            
            const startX = effectiveOriginX + startRelLon * simulationZoomLevel * simLonScale;
            const startY = effectiveOriginY - startRelLat * simulationZoomLevel;
            let endX = measureCurrentMousePos.x;
            let endY = measureCurrentMousePos.y;

            // If hovering an aircraft while measuring, hook end to that aircraft
            let endLat = null;
            let endLon = null;
            if (measureCurrentEndAircraftId) {
                const eLL = resolveEndpointLatLon({ type: 'aircraft', aircraftId: measureCurrentEndAircraftId });
                if (eLL) {
                    endLat = eLL.lat;
                    endLon = eLL.lon;
                    let endRelLon = eLL.lon;
                    let endRelLat = eLL.lat;
                    if (simCentreWaypoint) {
                        endRelLon = eLL.lon - simCentreWaypoint.longitude;
                        endRelLat = eLL.lat - simCentreWaypoint.latitude;
                    }
                    endX = effectiveOriginX + endRelLon * simulationZoomLevel * simLonScale;
                    endY = effectiveOriginY - endRelLat * simulationZoomLevel;
                }
            }
            
            if (isFinite(startX) && isFinite(startY) && isFinite(endX) && isFinite(endY)) {
                // Convert end screen coordinates to geographic coordinates (if not hooked to aircraft)
                if (endLat == null || endLon == null) {
                    const endRelLon = (endX - effectiveOriginX) / (simulationZoomLevel * simLonScale);
                    const endRelLat = -(endY - effectiveOriginY) / simulationZoomLevel;
                    endLat = endRelLat;
                    endLon = endRelLon;
                    if (simCentreWaypoint) {
                        endLat = endRelLat + simCentreWaypoint.latitude;
                        endLon = endRelLon + simCentreWaypoint.longitude;
                    }
                }
                
                // Calculate distance
                const distance = calculateNauticalMiles(sLL.lat, sLL.lon, endLat, endLon);
                const measurementColor = activeMeasurementColor || MEASUREMENT_COLORS[0];
                
                // Draw measurement line
                simulationCtx.strokeStyle = measurementColor;
                simulationCtx.lineWidth = 1;
                simulationCtx.beginPath();
                simulationCtx.moveTo(startX, startY);
                simulationCtx.lineTo(endX, endY);
                simulationCtx.stroke();
                
                // Draw distance text at cursor
                if (isFinite(distance)) {
                    simulationCtx.fillStyle = measurementColor;
                    simulationCtx.font = 'bold 14px Arial';
                    simulationCtx.textAlign = 'left';
                    simulationCtx.textBaseline = 'top';
                    const distanceText = `${distance.toFixed(1)}`;
                    const bearing = heading0to359(calculateBearingDegrees(
                        sLL.lat, sLL.lon,
                        endLat, endLon
                    ));
                    const bearingBack = (bearing + 180) % 360;
                    const directionText = `${formatHeadingFrom0to359(bearing)} ${formatHeadingFrom0to359(bearingBack)}`;
                    const lineHeight = 16;
                    
                    // While measuring: if it's aircraft <-> coord (mouse point, not hooked), show minutes-to-go live
                    let minutesText = null;
                    try {
                        const isStartAircraft = measureStartEndpoint?.type === 'aircraft';
                        const isEndAircraft = !!measureCurrentEndAircraftId; // hooked to aircraft while dragging
                        if (isStartAircraft && !isEndAircraft) {
                            const acId = measureStartEndpoint?.aircraftId;
                            const a = simulationAircraftScreenStates.find(x => x && x.aircraftId === acId);
                            const gs = Number(a?.gs);
                            if (isFinite(gs) && gs > 0) {
                                minutesText = String(Math.max(0, Math.round((distance / gs) * 60)));
                            }
                        }
                        // If end is hooked to aircraft (aircraft-aircraft) OR both are coords: no minutes line per spec
                    } catch (e) {}
                    
                    // Draw text (no background rectangle)
                    simulationCtx.fillStyle = measurementColor;
                    const textX = endX + 5;
                    const blockLines = minutesText ? 3 : 2;
                    const textY = endY - (lineHeight * (blockLines / 2)); // center-ish
                    simulationCtx.fillText(distanceText, textX, textY);
                    simulationCtx.fillText(directionText, textX, textY + lineHeight);
                    if (minutesText) {
                        simulationCtx.fillText(minutesText, textX, textY + lineHeight * 2);
                    }
                }
            }
        }

        // Heading selection elastic vector (DL mode)
        if (simulationIsSelectingHeading && simulationSelectingHeadingAircraftId && simulationHeadingSelectMouse) {
            const a = simulationAircraftScreenStates.find(s => s && s.aircraftId === simulationSelectingHeadingAircraftId);
            if (a && isFinite(a.x) && isFinite(a.y)) {
                const mx = simulationHeadingSelectMouse.x;
                const my = simulationHeadingSelectMouse.y;
                if (isFinite(mx) && isFinite(my)) {
                    // Compute bearing using lat/lon conversion
                    let hdg = 0;
                    try {
                        const simWaypoints = window.simulationData?.waypoints || [];
                        const simCentreWaypoint = simWaypoints.find(wp => isCenterWaypointName(wp?.name));
                        const simOriginX = simulationCanvas.width / 2;
                        const simOriginY = simulationCanvas.height / 2;
                        const effectiveOriginX = simOriginX + simulationPanX;
                        const effectiveOriginY = simOriginY + simulationPanY;
                        const relLon = (mx - effectiveOriginX) / (simulationZoomLevel * simLonScale);
                        const relLat = -(my - effectiveOriginY) / simulationZoomLevel;
                        let lat = relLat;
                        let lon = relLon;
                        if (simCentreWaypoint) {
                            lat = relLat + simCentreWaypoint.latitude;
                            lon = relLon + simCentreWaypoint.longitude;
                        }
                        hdg = heading0to359(calculateBearingDegrees(a.lat, a.lon, lat, lon));
                    } catch (e) {}
                    const inc = parseInt(simulationSettings?.headingSelectIncrement ?? SIM_SETTINGS_DEFAULTS.headingSelectIncrement, 10) || 1;
                    const hdgRounded = roundHeadingToIncrement(hdg, inc);
                    const hdgTxt = String(hdgRounded).padStart(3, '0');

                    simulationCtx.save();
                    simulationCtx.strokeStyle = simulationStyle?.labels?.textColor || '#111827';
                    simulationCtx.lineWidth = 2;
                    simulationCtx.beginPath();
                    simulationCtx.moveTo(a.x, a.y);
                    // Line follows mouse smoothly; only the readout is increment-rounded.
                    simulationCtx.lineTo(mx, my);
                    simulationCtx.stroke();
                    simulationCtx.lineWidth = 1;
                    simulationCtx.fillStyle = simulationStyle?.labels?.textColor || '#111827';
                    simulationCtx.font = 'bold 14px Arial';
                    simulationCtx.textAlign = 'left';
                    simulationCtx.textBaseline = 'top';
                    // Draw above pointer so cursor doesn't cover digits
                    simulationCtx.fillText(hdgTxt, mx + 6, my - 18);
                    simulationCtx.restore();
                }
            }
        }

        // DCT path drawing: existing trajectory (line + circles), user path (line + circles with names), line to mouse
        if (simulationDctPathDrawingAircraftId && window.simulationData) {
            const ac = (window.simulationData.aircraft || []).find(a => a && a.id === simulationDctPathDrawingAircraftId);
            const acSeq = ac ? getAircraftForDctTrajectoryUi(ac) : null;
            const aState = simulationAircraftScreenStates.find(s => s && s.aircraftId === simulationDctPathDrawingAircraftId);
            if (ac && acSeq && Array.isArray(acSeq.points) && aState && isFinite(aState.x) && isFinite(aState.y)) {
                const trajCol = simulationStyle?.trajectory?.color || SIM_STYLE_DEFAULTS.trajectory.color;
                const lineCol = hexToRgba(trajCol, 0.85);
                const circleRad = 8;
                simulationCtx.save();
                simulationCtx.strokeStyle = lineCol;
                simulationCtx.lineWidth = 2;
                simulationCtx.fillStyle = lineCol;
                // 1) Existing trajectory: only from aircraft position onward (no lines/circles for already-passed waypoints)
                const segIdx = Math.max(0, Math.min(acSeq.points.length - 2, parseInt(acSeq.routeProgressIdx, 10) || 0));
                simulationCtx.beginPath();
                simulationCtx.moveTo(aState.x, aState.y);
                for (let i = segIdx + 1; i < acSeq.points.length; i++) {
                    const p = acSeq.points[i];
                    if (!p || !isFinite(p.lat) || !isFinite(p.lon)) continue;
                    const sc = simulationLatLonToScreen(p.lat, p.lon);
                    if (sc && isFinite(sc.x) && isFinite(sc.y)) {
                        simulationCtx.lineTo(sc.x, sc.y);
                    }
                }
                simulationCtx.stroke();
                for (let i = segIdx + 1; i < acSeq.points.length; i++) {
                    const p = acSeq.points[i];
                    if (!p || !isFinite(p.lat) || !isFinite(p.lon)) continue;
                    const sc = simulationLatLonToScreen(p.lat, p.lon);
                    if (sc && isFinite(sc.x) && isFinite(sc.y)) {
                        simulationCtx.beginPath();
                        simulationCtx.arc(sc.x, sc.y, circleRad, 0, Math.PI * 2);
                        simulationCtx.fill();
                        simulationCtx.stroke();
                    }
                }
                // 2) User path: line from aircraft through each placed point, circles with optional name
                if (simulationDctPathPoints.length) {
                    simulationCtx.strokeStyle = hexToRgba('#22c55e', 0.9);
                    simulationCtx.lineWidth = 2.5;
                    simulationCtx.beginPath();
                    simulationCtx.moveTo(aState.x, aState.y);
                    for (const pt of simulationDctPathPoints) {
                        const sc = simulationLatLonToScreen(pt.lat, pt.lon);
                        if (sc && isFinite(sc.x) && isFinite(sc.y)) simulationCtx.lineTo(sc.x, sc.y);
                    }
                    simulationCtx.stroke();
                    simulationCtx.fillStyle = hexToRgba('#22c55e', 0.9);
                    for (const pt of simulationDctPathPoints) {
                        const sc = simulationLatLonToScreen(pt.lat, pt.lon);
                        if (sc && isFinite(sc.x) && isFinite(sc.y)) {
                            simulationCtx.beginPath();
                            simulationCtx.arc(sc.x, sc.y, circleRad, 0, Math.PI * 2);
                            simulationCtx.fill();
                            simulationCtx.stroke();
                            if (pt.name) {
                                simulationCtx.fillStyle = simulationStyle?.labels?.textColor || '#111827';
                                simulationCtx.font = 'bold 12px Arial';
                                simulationCtx.textAlign = 'center';
                                simulationCtx.textBaseline = 'bottom';
                                simulationCtx.fillText(pt.name, sc.x, sc.y - circleRad - 2);
                                simulationCtx.fillStyle = hexToRgba('#22c55e', 0.9);
                            }
                        }
                    }
                }
                // 3) Line from last origin (aircraft or last circle) to mouse - no label at end
                let lineStartX = aState.x;
                let lineStartY = aState.y;
                if (simulationDctPathPoints.length) {
                    const last = simulationDctPathPoints[simulationDctPathPoints.length - 1];
                    const sc = simulationLatLonToScreen(last.lat, last.lon);
                    if (sc && isFinite(sc.x) && isFinite(sc.y)) {
                        lineStartX = sc.x;
                        lineStartY = sc.y;
                    }
                }
                if (simulationDctPathMouse && isFinite(simulationDctPathMouse.x) && isFinite(simulationDctPathMouse.y)) {
                    simulationCtx.strokeStyle = simulationStyle?.labels?.textColor || '#111827';
                    simulationCtx.lineWidth = 2;
                    simulationCtx.beginPath();
                    simulationCtx.moveTo(lineStartX, lineStartY);
                    simulationCtx.lineTo(simulationDctPathMouse.x, simulationDctPathMouse.y);
                    simulationCtx.stroke();
                    // 4) Hover preview: when mouse is within 1 NM of a waypoint, show circle at waypoint with name; highlight if already in path
                    const mouseLl = simulationScreenToLatLon(simulationDctPathMouse.x, simulationDctPathMouse.y);
                    if (mouseLl && isFinite(mouseLl.lat) && isFinite(mouseLl.lon)) {
                        const HOVER_SNAP_NM = 1;
                        const candidates = [];
                        (window.simulationData.waypoints || []).forEach(wp => {
                            if (wp && isFinite(wp.latitude) && isFinite(wp.longitude)) {
                                candidates.push({ lat: wp.latitude, lon: wp.longitude, name: (wp.name || '').toString().trim().toUpperCase() || null });
                            }
                        });
                        for (let i = segIdx + 1; i < acSeq.points.length; i++) {
                            const p = acSeq.points[i];
                            if (p && isFinite(p.lat) && isFinite(p.lon)) {
                                const n = (p.name || '').toString().trim().toUpperCase() || null;
                                candidates.push({ lat: p.lat, lon: p.lon, name: n });
                            }
                        }
                        let best = null;
                        let bestD = HOVER_SNAP_NM;
                        for (const w of candidates) {
                            const d = calculateNauticalMiles(mouseLl.lat, mouseLl.lon, w.lat, w.lon);
                            if (isFinite(d) && d < bestD) {
                                bestD = d;
                                best = w;
                            }
                        }
                        if (best) {
                            const sc = simulationLatLonToScreen(best.lat, best.lon);
                            if (sc && isFinite(sc.x) && isFinite(sc.y)) {
                                const isInPath = simulationDctPathPoints.some(pt => {
                                    const d = calculateNauticalMiles(pt.lat, pt.lon, best.lat, best.lon);
                                    return isFinite(d) && d < 0.02;
                                });
                                simulationCtx.fillStyle = isInPath ? hexToRgba('#f59e0b', 0.95) : hexToRgba('#3b82f6', 0.9);
                                simulationCtx.strokeStyle = isInPath ? hexToRgba('#d97706', 1) : hexToRgba('#2563eb', 1);
                                simulationCtx.lineWidth = 2;
                                simulationCtx.beginPath();
                                simulationCtx.arc(sc.x, sc.y, circleRad, 0, Math.PI * 2);
                                simulationCtx.fill();
                                simulationCtx.stroke();
                                const label = (best.name && best.name.length > 0) ? best.name : null;
                                if (label) {
                                    simulationCtx.fillStyle = simulationStyle?.labels?.textColor || '#111827';
                                    simulationCtx.font = 'bold 12px Arial';
                                    simulationCtx.textAlign = 'center';
                                    simulationCtx.textBaseline = 'bottom';
                                    simulationCtx.fillText(label, sc.x, sc.y - circleRad - 2);
                                }
                            }
                        }
                    }
                }
                // 5) Route direction arrows: 3 NM long, thick, with arrowhead; all directions from all routes; hover highlight; clickable
                simulationDctRouteLookupSegments = [];
                simulationDctRouteLookupHoveredSegmentIndex = null;
                const ROUTE_ARROW_NM = 5;
                const ROUTE_ARROW_LINE_WIDTH = 6;
                const ROUTE_ARROW_HEAD_LEN = 14;
                const ROUTE_ARROW_HIT_PX = 14;
                const ROUTE_ARROW_NORMAL_COLOR = '#6d28d9';
                const ROUTE_ARROW_HOVER_COLOR = '#a78bfa';
                if (simulationDctRouteLookup && simulationDctRouteLookup.center && Array.isArray(simulationDctRouteLookup.segments)) {
                    const c = simulationDctRouteLookup.center;
                    const cSc = simulationLatLonToScreen(c.lat, c.lon);
                    if (cSc && isFinite(cSc.x) && isFinite(cSc.y)) {
                        simulationDctRouteLookup.segments.forEach((seg) => {
                            const t = seg.target;
                            if (!t || !isFinite(t.lat) || !isFinite(t.lon)) return;
                            const bearing = calculateBearingDegrees(c.lat, c.lon, t.lat, t.lon);
                            const endLl = destinationPointNm(c.lat, c.lon, bearing, ROUTE_ARROW_NM);
                            if (!endLl) return;
                            const endSc = simulationLatLonToScreen(endLl.lat, endLl.lon);
                            if (!endSc || !isFinite(endSc.x) || !isFinite(endSc.y)) return;
                            simulationDctRouteLookupSegments.push({ type: 'dir', x1: cSc.x, y1: cSc.y, x2: endSc.x, y2: endSc.y, routeKeys: seg.routeKeys || [] });
                        });
                        if (simulationDctPathMouse && isFinite(simulationDctPathMouse.x) && isFinite(simulationDctPathMouse.y)) {
                            let found = null;
                            for (let i = 0; i < simulationDctRouteLookupSegments.length; i++) {
                                const s = simulationDctRouteLookupSegments[i];
                                if (distanceToSegment(simulationDctPathMouse.x, simulationDctPathMouse.y, s.x1, s.y1, s.x2, s.y2) <= ROUTE_ARROW_HIT_PX) {
                                    found = i;
                                    break;
                                }
                            }
                            simulationDctRouteLookupHoveredSegmentIndex = found;
                        } else {
                            simulationDctRouteLookupHoveredSegmentIndex = null;
                        }
                        simulationDctRouteLookupSegments.forEach((s, segIdx) => {
                            const isHovered = simulationDctRouteLookupHoveredSegmentIndex === segIdx;
                            simulationCtx.strokeStyle = isHovered ? ROUTE_ARROW_HOVER_COLOR : ROUTE_ARROW_NORMAL_COLOR;
                            simulationCtx.fillStyle = isHovered ? ROUTE_ARROW_HOVER_COLOR : ROUTE_ARROW_NORMAL_COLOR;
                            simulationCtx.lineWidth = ROUTE_ARROW_LINE_WIDTH;
                            simulationCtx.lineCap = 'round';
                            simulationCtx.beginPath();
                            simulationCtx.moveTo(s.x1, s.y1);
                            simulationCtx.lineTo(s.x2, s.y2);
                            simulationCtx.stroke();
                            const dx = s.x2 - s.x1;
                            const dy = s.y2 - s.y1;
                            const len = Math.hypot(dx, dy);
                            if (len > 0) {
                                const ux = dx / len;
                                const uy = dy / len;
                                const ax = s.x2 - ux * ROUTE_ARROW_HEAD_LEN;
                                const ay = s.y2 - uy * ROUTE_ARROW_HEAD_LEN;
                                const perp = 0.4 * ROUTE_ARROW_HEAD_LEN;
                                const lx = ax + (-uy) * perp;
                                const ly = ay + ux * perp;
                                const rx = ax - (-uy) * perp;
                                const ry = ay - ux * perp;
                                simulationCtx.beginPath();
                                simulationCtx.moveTo(s.x2, s.y2);
                                simulationCtx.lineTo(lx, ly);
                                simulationCtx.lineTo(rx, ry);
                                simulationCtx.closePath();
                                simulationCtx.fill();
                                simulationCtx.stroke();
                            }
                        });
                    }
                }
                simulationCtx.restore();
            }
        }

        if (simulationSelectedAircraftId != null) {
            try { refreshAdvancedLabelPanelBody(); } catch (e) {}
        }
        try { refreshSimulationHoldingListPanel(); } catch (e) {}
        try { refreshSimulationEnMgmtPanelBody(); } catch (e) {}
        
    } catch (error) {
        console.error('Error drawing simulation canvas:', error);
    }
}

// Update CENTRE waypoint reference
function updateCentreWaypoint() {
    centreWaypoint = waypoints.find(wp => isCenterWaypointName(wp?.name));
}

// Auto-fit zoom to show all waypoints (and optional map-area boundaries)
function autoFitZoom() {
    if (!canvas || !ctx) {
        return; // Canvas not initialized
    }
    
    // Filter out invalid waypoints
    const validWaypoints = waypoints.filter(wp => 
        wp && 
        typeof wp.latitude === 'number' && 
        typeof wp.longitude === 'number' &&
        !isNaN(wp.latitude) && 
        !isNaN(wp.longitude) &&
        isFinite(wp.latitude) && 
        isFinite(wp.longitude)
    );
    
    // Update CENTRE waypoint reference before geometry
    updateCentreWaypoint();

    let minRelLat = Infinity, maxRelLat = -Infinity;
    let minRelLon = Infinity, maxRelLon = -Infinity;

    const expand = (lat, lon) => {
        if (!isFinite(lat) || !isFinite(lon)) return;
        let relLat = lat;
        let relLon = lon;
        if (centreWaypoint &&
            typeof centreWaypoint.latitude === 'number' &&
            typeof centreWaypoint.longitude === 'number') {
            relLat = lat - centreWaypoint.latitude;
            relLon = lon - centreWaypoint.longitude;
        }
        if (isFinite(relLat) && isFinite(relLon)) {
            minRelLat = Math.min(minRelLat, relLat);
            maxRelLat = Math.max(maxRelLat, relLat);
            minRelLon = Math.min(minRelLon, relLon);
            maxRelLon = Math.max(maxRelLon, relLon);
        }
    };

    validWaypoints.forEach(wp => expand(wp.latitude, wp.longitude));
    (navaids || []).forEach(nav => {
        if (nav && typeof nav.latitude === 'number' && typeof nav.longitude === 'number' &&
            isFinite(nav.latitude) && isFinite(nav.longitude)) {
            expand(nav.latitude, nav.longitude);
        }
    });

    (mapAreas || []).forEach(area => {
        const pts = area && area.boundary && Array.isArray(area.boundary.points) ? area.boundary.points : [];
        pts.forEach(p => {
            if (p && typeof p.latitude === 'number' && typeof p.longitude === 'number' &&
                isFinite(p.latitude) && isFinite(p.longitude)) {
                expand(p.latitude, p.longitude);
            }
        });
    });

    if (!isFinite(minRelLat)) {
        zoomLevel = 1.0;
        panX = 0;
        panY = 0;
        return;
    }

    const latRange = maxRelLat - minRelLat;
    const lonRange = maxRelLon - minRelLon;
    
    // If only CENTRE waypoint exists or all waypoints are at same location
    if (latRange === 0 && lonRange === 0) {
        // Default zoom for single waypoint / single coordinate set
        zoomLevel = 1000; // Reasonable default zoom
        panX = 0;
        panY = 0;
        return;
    }
    
    // Add padding (10% on each side)
    const paddedLatRange = latRange * 1.2 || 0.1;
    const paddedLonRange = lonRange * 1.2 || 0.1;
    
    // Validate ranges are finite
    if (!isFinite(paddedLatRange) || !isFinite(paddedLonRange) || paddedLatRange <= 0 || paddedLonRange <= 0) {
        zoomLevel = 1.0;
        panX = 0;
        panY = 0;
        return;
    }
    
    // Calculate zoom to fit
    const sectorLonScale = getSectorMapLonCosScale();
    const latZoom = (canvas.height * 0.8) / paddedLatRange;
    const lonZoom = (canvas.width * 0.8) / (paddedLonRange * sectorLonScale);
    zoomLevel = Math.min(latZoom, lonZoom);
    
    // Ensure minimum zoom level and validate
    if (!isFinite(zoomLevel) || zoomLevel < SECTOR_MAP_MIN_ZOOM) zoomLevel = SECTOR_MAP_MIN_ZOOM;
    if (zoomLevel > SECTOR_MAP_MAX_ZOOM) zoomLevel = SECTOR_MAP_MAX_ZOOM;
    
    // When CENTRE exists, pan should be 0 (CENTRE is at origin)
    // Otherwise, center on waypoint bounds
    if (centreWaypoint) {
        panX = 0;
        panY = 0;
    } else {
        const centerLat = (minRelLat + maxRelLat) / 2;
        const centerLon = (minRelLon + maxRelLon) / 2;
        
        if (isFinite(centerLat) && isFinite(centerLon)) {
            panX = -(centerLon * zoomLevel * sectorLonScale);
            panY = centerLat * zoomLevel;
        } else {
            panX = 0;
            panY = 0;
        }
    }
    
    // Ensure pan values are finite
    if (!isFinite(panX)) panX = 0;
    if (!isFinite(panY)) panY = 0;
}

function getNextSectorMapMeasurementColor() {
    const color = MEASUREMENT_COLORS[sectorMapMeasurementColorCounter % MEASUREMENT_COLORS.length];
    sectorMapMeasurementColorCounter += 1;
    return color;
}

function clearSectorMapMeasurements() {
    sectorMapIsMeasuring = false;
    sectorMapMeasureMiddleDown = false;
    sectorMapMeasureStartLatLon = null;
    sectorMapMeasureCurrentPx = null;
    sectorMapMeasurements = [];
    sectorMapMeasurementTextBounds = [];
    sectorMapActiveMeasurementColor = null;
    document.removeEventListener('mousemove', sectorMapMeasureDocMouseMove, true);
    document.removeEventListener('mouseup', sectorMapMeasureDocMouseUp, true);
}

function sectorMapMeasureDocMouseMove(e) {
    if (!sectorMapMeasureMiddleDown || !sectorMapIsMeasuring) return;
    const px = eventToSectorCanvasPixel(e);
    if (!px) return;
    sectorMapMeasureCurrentPx = { x: px.x, y: px.y };
    try { drawCanvas(); } catch (err) {}
}

function sectorMapMeasureDocMouseUp(e) {
    if (e.button !== 1) return;
    if (!sectorMapMeasureMiddleDown) return;
    sectorMapMeasureMiddleDown = false;
    document.removeEventListener('mousemove', sectorMapMeasureDocMouseMove, true);
    document.removeEventListener('mouseup', sectorMapMeasureDocMouseUp, true);

    if (!sectorMapIsMeasuring || !sectorMapMeasureStartLatLon || !sectorMapMeasureCurrentPx) {
        sectorMapIsMeasuring = false;
        sectorMapMeasureStartLatLon = null;
        sectorMapMeasureCurrentPx = null;
        sectorMapActiveMeasurementColor = null;
        try { drawCanvas(); } catch (err) {}
        return;
    }

    updateCentreWaypoint();
    const endLL = canvasPixelToSectorLatLon(sectorMapMeasureCurrentPx.x, sectorMapMeasureCurrentPx.y);
    const s = sectorMapMeasureStartLatLon;
    sectorMapIsMeasuring = false;
    sectorMapMeasureStartLatLon = null;
    sectorMapMeasureCurrentPx = null;
    const col = sectorMapActiveMeasurementColor || getNextSectorMapMeasurementColor();
    sectorMapActiveMeasurementColor = null;

    if (s && isFinite(s.lat) && isFinite(s.lon) && endLL && isFinite(endLL.latitude) && isFinite(endLL.longitude)) {
        sectorMapMeasurements.push({
            start: { type: 'coord', lat: s.lat, lon: s.lon },
            end: { type: 'coord', lat: endLL.latitude, lon: endLL.longitude },
            color: col
        });
    }
    try { drawCanvas(); } catch (err) {}
}

function sectorCanvasMeasurementLabelMousedownCapture(e) {
    if (e.button !== 0) return;
    if (!document.getElementById('editSectorModal')?.classList.contains('active')) return;
    const c = document.getElementById('sectorCanvas');
    if (!c || e.target !== c) return;
    if (!sectorMapMeasurementTextBounds.length) return;
    const px = eventToSectorCanvasPixel(e);
    if (!px) return;
    for (let i = sectorMapMeasurementTextBounds.length - 1; i >= 0; i--) {
        const b = sectorMapMeasurementTextBounds[i];
        if (px.x >= b.x && px.x <= b.x + b.width && px.y >= b.y && px.y <= b.y + b.height) {
            sectorMapMeasurements.splice(b.index, 1);
            e.preventDefault();
            e.stopImmediatePropagation();
            try { drawCanvas(); } catch (err) {}
            return;
        }
    }
}

// Setup canvas interactions (zoom and pan)
function setupCanvasInteractions() {
    if (!canvas) return;
    
    // Mouse wheel zoom - zoom toward the cursor position
    canvas.addEventListener('wheel', function(e) {
        e.preventDefault();
        
        // Zoom factor
        const zoomFactor = e.deltaY > 0 ? 0.9 : 1.1;
        const newZoom = zoomLevel * zoomFactor;
        
        // Limit zoom
        if (newZoom >= SECTOR_MAP_MIN_ZOOM && newZoom <= SECTOR_MAP_MAX_ZOOM) {
            // Anchor zoom at the cursor (falls back to canvas center if pointer is unavailable)
            const px = eventToSectorCanvasPixel(e);
            const anchorX = px ? px.x : canvas.width / 2;
            const anchorY = px ? px.y : canvas.height / 2;
            
            // Calculate world coordinates under the cursor before zoom
            const sectorLonScale = getSectorMapLonCosScale();
            const worldX = (anchorX - originX - panX) / (zoomLevel * sectorLonScale);
            const worldY = -(anchorY - originY - panY) / zoomLevel;
            
            // Apply new zoom
            zoomLevel = newZoom;
            
            // Adjust pan so the same world point stays under the cursor
            panX = anchorX - originX - worldX * zoomLevel * sectorLonScale;
            panY = anchorY - originY + worldY * zoomLevel;
            
            drawCanvas();
        }
    });

    canvas.addEventListener('auxclick', function(e) {
        if (e.button === 1) e.preventDefault();
    });
    
    // Mouse drag panning
    canvas.addEventListener('mousedown', function(e) {
        if (e.button === 1) {
            if (!document.getElementById('editSectorModal')?.classList.contains('active')) return;
            if (sectorMapWaypointPlacementActive || sectorMapWaypointDeleteActive || sectorMapWaypointEditActive || sectorMapNavaidDeleteActive || sectorMapNavaidEditActive || sectorMapAddRoutePickingActive || sectorMapRouteDeleteActive || sectorMapRouteEditActive || sectorMapAddAtcSectorActive || sectorMapAtcSectorEditActive || sectorMapAtcSectorDeleteActive || sectorMapAddMapAreaActive || sectorMapMapAreaPickActive()) return;
            if (e.target !== canvas) return;
            const px = eventToSectorCanvasPixel(e);
            if (!px) return;
            e.preventDefault();
            updateCentreWaypoint();
            const ll = canvasPixelToSectorLatLon(px.x, px.y);
            if (!isFinite(ll.latitude) || !isFinite(ll.longitude)) return;
            sectorMapMeasureMiddleDown = true;
            sectorMapIsMeasuring = true;
            sectorMapMeasureStartLatLon = { lat: ll.latitude, lon: ll.longitude };
            sectorMapMeasureCurrentPx = { x: px.x, y: px.y };
            sectorMapActiveMeasurementColor = getNextSectorMapMeasurementColor();
            document.addEventListener('mousemove', sectorMapMeasureDocMouseMove, true);
            document.addEventListener('mouseup', sectorMapMeasureDocMouseUp, true);
            try { drawCanvas(); } catch (err) {}
            return;
        }
        if (e.button === 0) { // Left mouse button
            if (sectorMapWaypointPlacementActive || sectorMapWaypointDeleteActive || sectorMapWaypointEditActive || sectorMapNavaidDeleteActive || sectorMapNavaidEditActive) return;
            isDragging = true;
            dragStartX = e.clientX;
            dragStartY = e.clientY;
            dragStartPanX = panX;
            dragStartPanY = panY;
            canvas.style.cursor = 'grabbing';
        }
    });
    
    canvas.addEventListener('mousemove', function(e) {
        if (sectorMapWaypointPlacementActive || sectorMapWaypointDeleteActive || sectorMapWaypointEditActive || sectorMapNavaidDeleteActive || sectorMapNavaidEditActive) {
            canvas.style.cursor = 'crosshair';
            return;
        }
        if (isDragging) {
            const deltaX = e.clientX - dragStartX;
            const deltaY = e.clientY - dragStartY;
            panX = dragStartPanX + deltaX;
            panY = dragStartPanY + deltaY;
            drawCanvas();
            canvas.style.cursor = 'grabbing';
            return;
        }
        if (sectorMapAddRoutePickingActive || sectorMapRouteDeleteActive || sectorMapRouteEditActive || sectorMapAddAtcSectorActive || sectorMapAtcSectorEditActive || sectorMapAtcSectorDeleteActive || sectorMapAddMapAreaActive || sectorMapMapAreaPickActive()) {
            canvas.style.cursor = 'crosshair';
            return;
        }
        canvas.style.cursor = 'grab';
    });
    
    canvas.addEventListener('mouseup', function(e) {
        if (e.button === 0) {
            isDragging = false;
            if (sectorMapWaypointPlacementActive || sectorMapWaypointDeleteActive || sectorMapWaypointEditActive || sectorMapNavaidDeleteActive || sectorMapNavaidEditActive || sectorMapAddRoutePickingActive || sectorMapRouteDeleteActive || sectorMapRouteEditActive || sectorMapAddAtcSectorActive || sectorMapAtcSectorEditActive || sectorMapAtcSectorDeleteActive || sectorMapAddMapAreaActive || sectorMapMapAreaPickActive()) {
                canvas.style.cursor = 'crosshair';
            } else {
                canvas.style.cursor = 'default';
            }
        }
    });
    
    canvas.addEventListener('mouseleave', function() {
        isDragging = false;
        if (sectorMapWaypointPlacementActive || sectorMapWaypointDeleteActive || sectorMapWaypointEditActive || sectorMapNavaidDeleteActive || sectorMapNavaidEditActive || sectorMapAddRoutePickingActive || sectorMapRouteDeleteActive || sectorMapRouteEditActive || sectorMapAddAtcSectorActive || sectorMapAtcSectorEditActive || sectorMapAtcSectorDeleteActive || sectorMapAddMapAreaActive || sectorMapMapAreaPickActive()) {
            canvas.style.cursor = 'crosshair';
        } else {
            canvas.style.cursor = 'default';
        }
    });
}

// Draw canvas with cartesian system
function drawCanvas() {
    if (!ctx || !canvas) return;
    
    // Validate canvas dimensions
    if (canvas.width <= 0 || canvas.height <= 0) {
        return;
    }
    
    // Validate zoom and pan values
    if (!isFinite(zoomLevel) || zoomLevel <= 0) {
        zoomLevel = 1.0;
    }
    if (!isFinite(panX)) panX = 0;
    if (!isFinite(panY)) panY = 0;
    
    try {
        // Clear canvas with white background
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        
        // Update CENTRE waypoint
        updateCentreWaypoint();
        
        // Set origin to center of canvas
        originX = canvas.width / 2;
        originY = canvas.height / 2;
        
        // Apply pan offset
        const effectiveOriginX = originX + panX;
        const effectiveOriginY = originY + panY;
        
        // Validate effective origin
        if (!isFinite(effectiveOriginX) || !isFinite(effectiveOriginY)) {
            return; // Don't draw if coordinates are invalid
        }
    } catch (error) {
        console.error('Error initializing canvas drawing:', error);
        return;
    }
    
    const effectiveOriginX = originX + panX;
    const effectiveOriginY = originY + panY;
    const sectorLonScale = getSectorMapLonCosScale();
    const sectorRouteFixById = buildSectorRouteFixLookup();

    drawSectorMapSessionBackgroundLayer();
    
    // Draw grid if enabled (every 5 minutes = 0.0833 degrees)
    if (showGrid) {
        // 5 minutes in degrees = 5/60 = 0.083333...
        const gridIntervalDegrees = 5 / 60; // 5 minutes in degrees
        
        // Get the reference point (CENTRE waypoint or 0,0)
        let refLon = 0;
        let refLat = 0;
        if (centreWaypoint && 
            typeof centreWaypoint.longitude === 'number' && 
            typeof centreWaypoint.latitude === 'number' &&
            isFinite(centreWaypoint.longitude) && 
            isFinite(centreWaypoint.latitude)) {
            refLon = centreWaypoint.longitude;
            refLat = centreWaypoint.latitude;
        }
        
        // Calculate visible geographic bounds
        // Convert canvas corners to geographic coordinates
        const topLeftRelLon = (0 - effectiveOriginX) / (zoomLevel * sectorLonScale);
        const topLeftRelLat = -(0 - effectiveOriginY) / zoomLevel; // Negative because Y is flipped
        const bottomRightRelLon = (canvas.width - effectiveOriginX) / (zoomLevel * sectorLonScale);
        const bottomRightRelLat = -(canvas.height - effectiveOriginY) / zoomLevel;
        
        const lonMin = refLon + Math.min(topLeftRelLon, bottomRightRelLon);
        const lonMax = refLon + Math.max(topLeftRelLon, bottomRightRelLon);
        const latMin = refLat + Math.min(topLeftRelLat, bottomRightRelLat);
        const latMax = refLat + Math.max(topLeftRelLat, bottomRightRelLat);
        
        // Find the grid lines that fall within visible bounds
        // Round to nearest 5-minute interval
        const startLon = Math.floor(lonMin / gridIntervalDegrees) * gridIntervalDegrees;
        const endLon = Math.ceil(lonMax / gridIntervalDegrees) * gridIntervalDegrees;
        const startLat = Math.floor(latMin / gridIntervalDegrees) * gridIntervalDegrees;
        const endLat = Math.ceil(latMax / gridIntervalDegrees) * gridIntervalDegrees;
        
        // Draw grid in light grey
        ctx.strokeStyle = '#cccccc';
        ctx.lineWidth = 1;
        
        // Draw vertical lines (longitude) - every 5 minutes
        for (let lon = startLon; lon <= endLon; lon += gridIntervalDegrees) {
            const relLon = lon - refLon;
            const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
            
            // Only draw if within canvas bounds
            if (x >= -10 && x <= canvas.width + 10) {
                ctx.beginPath();
                ctx.moveTo(x, 0);
                ctx.lineTo(x, canvas.height);
                ctx.stroke();
            }
        }
        
        // Draw horizontal lines (latitude) - every 5 minutes
        for (let lat = startLat; lat <= endLat; lat += gridIntervalDegrees) {
            const relLat = lat - refLat;
            const y = effectiveOriginY - relLat * zoomLevel; // Negative because Y is flipped
            
            // Only draw if within canvas bounds
            if (y >= -10 && y <= canvas.height + 10) {
                ctx.beginPath();
                ctx.moveTo(0, y);
                ctx.lineTo(canvas.width, y);
                ctx.stroke();
            }
        }
    }
    
    // Draw CENTER axes + labels only when grid is enabled (toggled by '#' button)
    if (showGrid) {
        // Draw axes in black
        ctx.strokeStyle = '#000000';
        ctx.lineWidth = 2;
        
        // X axis (Longitude) - through CENTRE waypoint or origin
        ctx.beginPath();
        ctx.moveTo(0, effectiveOriginY);
        ctx.lineTo(canvas.width, effectiveOriginY);
        ctx.stroke();
        
        // Y axis (Latitude) - through CENTRE waypoint or origin
        ctx.beginPath();
        ctx.moveTo(effectiveOriginX, 0);
        ctx.lineTo(effectiveOriginX, canvas.height);
        ctx.stroke();
        
        // Draw axis labels in black
        ctx.fillStyle = '#000000';
        ctx.font = '14px Arial';
        ctx.textAlign = 'center';
        
        // Longitude label (X axis)
        ctx.fillText('Longitude', canvas.width / 2, effectiveOriginY - 10);
        
        // Latitude label (Y axis)
        ctx.save();
        ctx.translate(effectiveOriginX - 30, canvas.height / 2);
        ctx.rotate(-Math.PI / 2);
        ctx.fillText('Latitude', 0, 0);
        ctx.restore();
    }
    
    // Draw routes (lines connecting waypoints); Delete / Edit pick: black first, red highlights on top
    const routeDeleteHighlight = getSectorMapRouteDeleteHighlightIdSet();
    const routeEditPickHighlight = getSectorMapRouteEditSelectHighlightIdSet();
    const shouldDrawStoredRoutes = sectorMapOptions.showRoutes || sectorMapRouteDeleteActive || (sectorMapRouteEditActive && !sectorMapRouteEditTargetRouteId);
    ctx.lineWidth = 2;

    const strokeSectorRoutePolyline = (route, strokeStyle) => {
        if (!route || !route.waypointIds || route.waypointIds.length < 2) {
            return;
        }
        ctx.strokeStyle = strokeStyle;
        const validWaypoints = [];
        const canvasPoints = [];
        for (const waypointId of route.waypointIds) {
            const waypoint = sectorRouteFixById.get(String(waypointId));
            if (waypoint && typeof waypoint.latitude === 'number' && typeof waypoint.longitude === 'number') {
                validWaypoints.push(waypoint);
            }
        }
        if (validWaypoints.length < 2) {
            return;
        }
        ctx.beginPath();
        let firstPoint = true;
        validWaypoints.forEach(waypoint => {
            let relLon = waypoint.longitude;
            let relLat = waypoint.latitude;
            if (centreWaypoint) {
                relLon = waypoint.longitude - centreWaypoint.longitude;
                relLat = waypoint.latitude - centreWaypoint.latitude;
            }
            const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
            const y = effectiveOriginY - relLat * zoomLevel;
            if (isNaN(x) || isNaN(y) || !isFinite(x) || !isFinite(y)) {
                return;
            }
            canvasPoints.push({ x, y });
            if (firstPoint) {
                ctx.moveTo(x, y);
                firstPoint = false;
            } else {
                ctx.lineTo(x, y);
            }
        });
        if (!sectorMapRouteCanvasBoundsIntersectsView(canvasPoints)) {
            return;
        }
        if (!firstPoint) {
            ctx.stroke();
        }
    };

    if (shouldDrawStoredRoutes) {
        routes.forEach(route => {
            if (sectorMapRouteEditActive && sectorMapRouteEditTargetRouteId && route.id === sectorMapRouteEditTargetRouteId) {
                return;
            }
            if (routeDeleteHighlight && routeDeleteHighlight.has(route.id)) {
                return;
            }
            if (routeEditPickHighlight && routeEditPickHighlight.has(route.id)) {
                return;
            }
            strokeSectorRoutePolyline(route, '#000000');
        });
        routes.forEach(route => {
            if (sectorMapRouteEditActive && sectorMapRouteEditTargetRouteId && route.id === sectorMapRouteEditTargetRouteId) {
                return;
            }
            const delRed = routeDeleteHighlight && routeDeleteHighlight.has(route.id);
            const pickRed = routeEditPickHighlight && routeEditPickHighlight.has(route.id);
            if (!delRed && !pickRed) {
                return;
            }
            strokeSectorRoutePolyline(route, '#c62828');
        });
    }

    // Draft route polyline while picking waypoints from context menu (Add Route)
    if (sectorMapAddRoutePickingActive && sectorMapAddRoutePickedIds.length >= 2) {
        ctx.save();
        ctx.strokeStyle = '#2e7d32';
        ctx.lineWidth = 2;
        ctx.setLineDash([6, 4]);
        ctx.beginPath();
        let firstPt = true;
        sectorMapAddRoutePickedIds.forEach(wid => {
            const waypoint = sectorRouteFixById.get(String(wid));
            if (!waypoint || typeof waypoint.latitude !== 'number' || typeof waypoint.longitude !== 'number') return;
            let relLon = waypoint.longitude;
            let relLat = waypoint.latitude;
            if (centreWaypoint && typeof centreWaypoint.latitude === 'number' && typeof centreWaypoint.longitude === 'number') {
                relLon = waypoint.longitude - centreWaypoint.longitude;
                relLat = waypoint.latitude - centreWaypoint.latitude;
            }
            const px = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
            const py = effectiveOriginY - relLat * zoomLevel;
            if (!isFinite(px) || !isFinite(py)) return;
            if (firstPt) {
                ctx.moveTo(px, py);
                firstPt = false;
            } else {
                ctx.lineTo(px, py);
            }
        });
        if (!firstPt) ctx.stroke();
        ctx.setLineDash([]);
        ctx.restore();
    }

    if (sectorMapRouteEditActive && sectorMapRouteEditTargetRouteId && sectorMapRouteEditDraftIds.length >= 2) {
        ctx.save();
        ctx.strokeStyle = '#2e7d32';
        ctx.lineWidth = 2;
        ctx.setLineDash([6, 4]);
        ctx.beginPath();
        let firstPt = true;
        sectorMapRouteEditDraftIds.forEach(wid => {
            const waypoint = sectorRouteFixById.get(String(wid));
            if (!waypoint || typeof waypoint.latitude !== 'number' || typeof waypoint.longitude !== 'number') return;
            let relLon = waypoint.longitude;
            let relLat = waypoint.latitude;
            if (centreWaypoint && typeof centreWaypoint.latitude === 'number' && typeof centreWaypoint.longitude === 'number') {
                relLon = waypoint.longitude - centreWaypoint.longitude;
                relLat = waypoint.latitude - centreWaypoint.latitude;
            }
            const px = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
            const py = effectiveOriginY - relLat * zoomLevel;
            if (!isFinite(px) || !isFinite(py)) return;
            if (firstPt) {
                ctx.moveTo(px, py);
                firstPt = false;
            } else {
                ctx.lineTo(px, py);
            }
        });
        if (!firstPt) ctx.stroke();
        ctx.setLineDash([]);
        ctx.restore();
    }
    
    // Draw map areas (Restricted / Prohibited / Dangerous) underneath ATC boundaries
    if (mapAreas && mapAreas.length) {
        ctx.save();
        ctx.lineWidth = 2;
        mapAreas.forEach(area => {
            if (!area || !area.boundary || !area.boundary.points || area.boundary.points.length < 2) return;
            const strokeColor = sanitizeMapAreaLineColor(area.lineColor, area.kind);
            const validPoints = area.boundary.points.filter(point =>
                point &&
                typeof point.latitude === 'number' &&
                typeof point.longitude === 'number' &&
                isFinite(point.latitude) &&
                isFinite(point.longitude)
            );
            if (validPoints.length < 2) return;

            ctx.beginPath();
            let isFirstPoint = true;
            let hasValidPoints = false;

            validPoints.forEach(point => {
                let relLon = point.longitude;
                let relLat = point.latitude;
                if (centreWaypoint) {
                    relLon = point.longitude - centreWaypoint.longitude;
                    relLat = point.latitude - centreWaypoint.latitude;
                }
                const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
                const y = effectiveOriginY - relLat * zoomLevel;
                if (isNaN(x) || isNaN(y) || !isFinite(x) || !isFinite(y)) return;
                if (isFirstPoint) {
                    ctx.moveTo(x, y);
                    isFirstPoint = false;
                    hasValidPoints = true;
                } else {
                    ctx.lineTo(x, y);
                }
            });

            if (hasValidPoints && validPoints.length >= 2) {
                const fp = validPoints[0];
                let relLon = fp.longitude;
                let relLat = fp.latitude;
                if (centreWaypoint) {
                    relLon = fp.longitude - centreWaypoint.longitude;
                    relLat = fp.latitude - centreWaypoint.latitude;
                }
                const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
                const y = effectiveOriginY - relLat * zoomLevel;
                if (isFinite(x) && isFinite(y)) ctx.lineTo(x, y);
                ctx.strokeStyle = strokeColor;
                ctx.stroke();
            }
        });
        ctx.restore();
    }

    drawSectorHoldingsLayer(ctx, effectiveOriginX, effectiveOriginY);
    
    // Draw boundaries (closed polygons) in blue
    ctx.strokeStyle = '#0000ff'; // Blue color
    ctx.lineWidth = 2;
    
    boundaries.forEach(boundary => {
        if (!boundary || !boundary.points || boundary.points.length < 2) {
            return; // Skip invalid boundaries
        }
        if (sectorMapAtcSectorEditActive && sectorMapAtcSectorEditTargetId) {
            const es = atcSectors.find(x => x && x.id === sectorMapAtcSectorEditTargetId);
            if (es && es.boundary && boundary.id && es.boundary.id === boundary.id) {
                return;
            }
        }
        
        // Validate all points
        const validPoints = boundary.points.filter(point => 
            point && 
            typeof point.latitude === 'number' && 
            typeof point.longitude === 'number' &&
            isFinite(point.latitude) && 
            isFinite(point.longitude)
        );
        
        // Only draw if we have at least 2 valid points
        if (validPoints.length < 2) {
            return; // Skip boundaries with invalid points
        }
        
        ctx.beginPath();
        let isFirstPoint = true;
        let hasValidPoints = false;
        
        validPoints.forEach(point => {
            // Calculate relative to CENTRE waypoint
            let relLon = point.longitude;
            let relLat = point.latitude;
            
            if (centreWaypoint) {
                relLon = point.longitude - centreWaypoint.longitude;
                relLat = point.latitude - centreWaypoint.latitude;
            }
            
            const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
            const y = effectiveOriginY - relLat * zoomLevel; // Flip Y axis
            
            // Validate coordinates are numbers
            if (isNaN(x) || isNaN(y) || !isFinite(x) || !isFinite(y)) {
                return; // Skip invalid coordinates
            }
            
            if (isFirstPoint) {
                ctx.moveTo(x, y);
                isFirstPoint = false;
                hasValidPoints = true;
            } else {
                ctx.lineTo(x, y);
            }
        });
        
        // Close the boundary (connect last point to first point)
        if (hasValidPoints && validPoints.length >= 2) {
            const firstPointData = validPoints[0];
            let relLon = firstPointData.longitude;
            let relLat = firstPointData.latitude;
            
            if (centreWaypoint) {
                relLon = firstPointData.longitude - centreWaypoint.longitude;
                relLat = firstPointData.latitude - centreWaypoint.latitude;
            }
            
            const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
            const y = effectiveOriginY - relLat * zoomLevel;
            
            if (isFinite(x) && isFinite(y)) {
                ctx.lineTo(x, y);
            }
            ctx.stroke();
        }
    });

    const atcSegHi = getSectorMapAtcSectorSegmentRedHighlightIdSet();
    if (atcSegHi && atcSegHi.size) {
        ctx.save();
        ctx.strokeStyle = '#c62828';
        ctx.lineWidth = 2;
        atcSectors.forEach(sec => {
            if (!sec || !atcSegHi.has(sec.id) || !sec.boundary || !Array.isArray(sec.boundary.points)) return;
            const validPoints = sec.boundary.points.filter(point =>
                point &&
                typeof point.latitude === 'number' &&
                typeof point.longitude === 'number' &&
                isFinite(point.latitude) &&
                isFinite(point.longitude)
            );
            if (validPoints.length < 2) return;
            ctx.beginPath();
            let isFirstPoint = true;
            let hasValidPoints = false;
            validPoints.forEach(point => {
                let relLon = point.longitude;
                let relLat = point.latitude;
                if (centreWaypoint) {
                    relLon = point.longitude - centreWaypoint.longitude;
                    relLat = point.latitude - centreWaypoint.latitude;
                }
                const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
                const y = effectiveOriginY - relLat * zoomLevel;
                if (isNaN(x) || isNaN(y) || !isFinite(x) || !isFinite(y)) return;
                if (isFirstPoint) {
                    ctx.moveTo(x, y);
                    isFirstPoint = false;
                    hasValidPoints = true;
                } else {
                    ctx.lineTo(x, y);
                }
            });
            if (hasValidPoints && validPoints.length >= 2) {
                const fp = validPoints[0];
                let relLon = fp.longitude;
                let relLat = fp.latitude;
                if (centreWaypoint) {
                    relLon = fp.longitude - centreWaypoint.longitude;
                    relLat = fp.latitude - centreWaypoint.latitude;
                }
                const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
                const y = effectiveOriginY - relLat * zoomLevel;
                if (isFinite(x) && isFinite(y)) ctx.lineTo(x, y);
                ctx.stroke();
            }
        });
        ctx.restore();
    }

    const maSegHi = getSectorMapMapAreaPickHighlightIdSet();
    if (maSegHi && maSegHi.size) {
        ctx.save();
        ctx.strokeStyle = '#c62828';
        ctx.lineWidth = 2;
        (mapAreas || []).forEach(area => {
            const validPoints = area.boundary.points.filter(point =>
                point &&
                typeof point.latitude === 'number' &&
                typeof point.longitude === 'number' &&
                isFinite(point.latitude) &&
                isFinite(point.longitude)
            );
            if (validPoints.length < 2) return;
            ctx.beginPath();
            let isFirstPoint = true;
            let hasValidPoints = false;
            validPoints.forEach(point => {
                let relLon = point.longitude;
                let relLat = point.latitude;
                if (centreWaypoint) {
                    relLon = point.longitude - centreWaypoint.longitude;
                    relLat = point.latitude - centreWaypoint.latitude;
                }
                const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
                const y = effectiveOriginY - relLat * zoomLevel;
                if (isNaN(x) || isNaN(y) || !isFinite(x) || !isFinite(y)) return;
                if (isFirstPoint) {
                    ctx.moveTo(x, y);
                    isFirstPoint = false;
                    hasValidPoints = true;
                } else {
                    ctx.lineTo(x, y);
                }
            });
            if (hasValidPoints && validPoints.length >= 2) {
                const fp = validPoints[0];
                let relLon = fp.longitude;
                let relLat = fp.latitude;
                if (centreWaypoint) {
                    relLon = fp.longitude - centreWaypoint.longitude;
                    relLat = fp.latitude - centreWaypoint.latitude;
                }
                const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
                const y = effectiveOriginY - relLat * zoomLevel;
                if (isFinite(x) && isFinite(y)) ctx.lineTo(x, y);
                ctx.stroke();
            }
        });
        ctx.restore();
    }

    if (sectorMapAddAtcSectorActive || (sectorMapAtcSectorEditActive && sectorMapAtcSectorEditTargetId)) {
        ctx.save();
        atcSectors.forEach(s => {
            if (!s || !s.boundary || !Array.isArray(s.boundary.points)) return;
            if (sectorMapAtcSectorEditActive && sectorMapAtcSectorEditTargetId && String(s.id) === String(sectorMapAtcSectorEditTargetId)) {
                return;
            }
            s.boundary.points.forEach((p, ptIndex) => {
                if (!p || typeof p.latitude !== 'number' || typeof p.longitude !== 'number') return;
                if (!isFinite(p.latitude) || !isFinite(p.longitude)) return;
                let relLon = p.longitude;
                let relLat = p.latitude;
                if (centreWaypoint) {
                    relLon = p.longitude - centreWaypoint.longitude;
                    relLat = p.latitude - centreWaypoint.latitude;
                }
                const vx = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
                const vy = effectiveOriginY - relLat * zoomLevel;
                if (!isFinite(vx) || !isFinite(vy)) return;
                const key = `${s.id}:${ptIndex}`;
                const hover = sectorMapAddAtcSectorHoverAtcKey === key || sectorMapAtcSectorEditHoverAtcKey === key ||
                    sectorMapAtcSectorEditDragAcquireAtcKey === key;
                ctx.beginPath();
                ctx.arc(vx, vy, hover ? 6 : 4, 0, Math.PI * 2);
                ctx.fillStyle = hover ? '#ffb74d' : '#5c6bc0';
                ctx.strokeStyle = hover ? '#e65100' : '#283593';
                ctx.lineWidth = hover ? 2 : 1;
                ctx.fill();
                ctx.stroke();
            });
        });
        ctx.restore();
    }

    if (sectorMapAddMapAreaActive && mapAreas && mapAreas.length) {
        ctx.save();
        mapAreas.forEach(a => {
            if (!a || !a.boundary || !Array.isArray(a.boundary.points)) return;
            a.boundary.points.forEach((p, ptIndex) => {
                if (!p || typeof p.latitude !== 'number' || typeof p.longitude !== 'number') return;
                if (!isFinite(p.latitude) || !isFinite(p.longitude)) return;
                let relLon = p.longitude;
                let relLat = p.latitude;
                if (centreWaypoint) {
                    relLon = p.longitude - centreWaypoint.longitude;
                    relLat = p.latitude - centreWaypoint.latitude;
                }
                const vx = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
                const vy = effectiveOriginY - relLat * zoomLevel;
                if (!isFinite(vx) || !isFinite(vy)) return;
                const key = `${a.id}:${ptIndex}`;
                const hover = sectorMapAddMapAreaHoverMaKey === key;
                ctx.beginPath();
                ctx.arc(vx, vy, hover ? 6 : 4, 0, Math.PI * 2);
                ctx.fillStyle = hover ? '#ffb74d' : '#26a69a';
                ctx.strokeStyle = hover ? '#e65100' : '#004d40';
                ctx.lineWidth = hover ? 2 : 1;
                ctx.fill();
                ctx.stroke();
            });
        });
        ctx.restore();
    }

    // Draw airports + runways (magenta)
    try {
        const MAGENTA = '#ff00ff';
        ctx.save();
        ctx.strokeStyle = MAGENTA;
        ctx.fillStyle = MAGENTA;
        ctx.lineWidth = 2;
        ctx.font = 'bold 12px Arial';
        ctx.textAlign = 'left';
        ctx.textBaseline = 'top';

        const airports = Array.isArray(currentSectorAirports) ? currentSectorAirports : [];
        airports.forEach(ap => {
            if (!ap) return;
            const icao = normalizeAirportIcao(ap.icao);
            const arpLat = Number(ap.arpLat);
            const arpLon = Number(ap.arpLon);
            if (!isFinite(arpLat) || !isFinite(arpLon)) return;
            const p = sectorLatLonToCanvas(arpLat, arpLon, effectiveOriginX, effectiveOriginY);
            if (!p) return;

            // ARP square
            const s = 6;
            ctx.fillRect(p.x - s / 2, p.y - s / 2, s, s);
            // ICAO label
            if (icao) ctx.fillText(icao, p.x + 8, p.y - 8);

            // Runways
            const runways = Array.isArray(ap.runways) ? ap.runways : [];
            runways.forEach(rw => {
                const a = rw?.endA;
                const b = rw?.endB;
                const aLat = Number(a?.lat);
                const aLon = Number(a?.lon);
                const bLat = Number(b?.lat);
                const bLon = Number(b?.lon);
                if (![aLat, aLon, bLat, bLon].every(isFinite)) return;
                const pa = sectorLatLonToCanvas(aLat, aLon, effectiveOriginX, effectiveOriginY);
                const pb = sectorLatLonToCanvas(bLat, bLon, effectiveOriginX, effectiveOriginY);
                if (!pa || !pb) return;

                ctx.beginPath();
                ctx.moveTo(pa.x, pa.y);
                ctx.lineTo(pb.x, pb.y);
                ctx.stroke();

                const aName = normalizeRunwayDesignator(a?.name);
                const bName = normalizeRunwayDesignator(b?.name);
                if (aName) ctx.fillText(aName, pa.x + 6, pa.y - 10);
                if (bName) ctx.fillText(bName, pb.x + 6, pb.y - 10);
            });
        });

        ctx.restore();
    } catch (e) {
        try { ctx.restore(); } catch (e2) {}
    }
    
    // Draw waypoints (triangles)
    waypoints.forEach(waypoint => {
        // Validate waypoint data
        if (!waypoint || typeof waypoint.latitude !== 'number' || typeof waypoint.longitude !== 'number') {
            return; // Skip invalid waypoints
        }
        
        if (isNaN(waypoint.latitude) || isNaN(waypoint.longitude) || 
            !isFinite(waypoint.latitude) || !isFinite(waypoint.longitude)) {
            return; // Skip waypoints with invalid coordinates
        }
        
        // Calculate relative to CENTRE waypoint
        let relLon = waypoint.longitude;
        let relLat = waypoint.latitude;
        
        if (centreWaypoint && typeof centreWaypoint.latitude === 'number' && typeof centreWaypoint.longitude === 'number') {
            relLon = waypoint.longitude - centreWaypoint.longitude;
            relLat = waypoint.latitude - centreWaypoint.latitude;
        }
        
        const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
        const y = effectiveOriginY - relLat * zoomLevel; // Flip Y axis
        
        // Validate coordinates are numbers
        if (isNaN(x) || isNaN(y) || !isFinite(x) || !isFinite(y)) {
            return; // Skip waypoints with invalid screen coordinates
        }
        if (!sectorMapCanvasPointIsInRenderView(x, y, 180)) {
            return;
        }

        const deleteHover = sectorMapWaypointDeleteActive && sectorMapDeleteHoverWaypointId && waypoint.id === sectorMapDeleteHoverWaypointId;
        const editHover = sectorMapWaypointEditActive && sectorMapEditHoverWaypointId && waypoint.id === sectorMapEditHoverWaypointId;
        const routeEditMap = sectorMapRouteEditActive && sectorMapRouteEditTargetRouteId;
        const routeEditAcquire = routeEditMap && sectorMapRouteEditDragAcquireWaypointId && waypoint.id === sectorMapRouteEditDragAcquireWaypointId;
        const routeEditDraftHover = routeEditMap && sectorMapRouteEditHoverWaypointId && waypoint.id === sectorMapRouteEditHoverWaypointId;
        const routeEditDraftPicked = routeEditMap && sectorMapRouteEditDraftIds.includes(waypoint.id);
        const addRouteHover = sectorMapAddRoutePickingActive && sectorMapAddRouteHoverWaypointId && waypoint.id === sectorMapAddRouteHoverWaypointId;
        const addRoutePicked = sectorMapAddRoutePickingActive && sectorMapAddRoutePickedIds.includes(waypoint.id);
        const addAtcHover = sectorMapAddAtcSectorActive && sectorMapAddAtcSectorHoverWaypointId && waypoint.id === sectorMapAddAtcSectorHoverWaypointId;
        const addMapAreaHover = sectorMapAddMapAreaActive && sectorMapAddMapAreaHoverWaypointId && waypoint.id === sectorMapAddMapAreaHoverWaypointId;
        const atcEditMap = sectorMapAtcSectorEditActive && sectorMapAtcSectorEditTargetId;
        const atcEditAcquire = atcEditMap && sectorMapAtcSectorEditDragAcquireWaypointId && waypoint.id === sectorMapAtcSectorEditDragAcquireWaypointId;
        const atcEditDraftHover = atcEditMap && sectorMapAtcSectorEditHoverWaypointId && waypoint.id === sectorMapAtcSectorEditHoverWaypointId;
        const atcEditDraftWp = atcEditMap && sectorMapAtcSectorEditDraftPoints.some(sel => sel && sel.kind === 'waypoint' && sel.id === waypoint.id);
        const waypointHighlight = deleteHover || editHover || routeEditAcquire || routeEditDraftHover || routeEditDraftPicked || addRouteHover || addRoutePicked || addAtcHover || addMapAreaHover || atcEditAcquire || atcEditDraftHover || atcEditDraftWp;
        const waypointSymbolSize = clampSectorMapOptionNumber(sectorMapOptions.waypointSymbolSize, 6, 36, SECTOR_MAP_OPTIONS_DEFAULTS.waypointSymbolSize);
        const wpTop = waypointSymbolSize * 0.57;
        const wpBottom = waypointSymbolSize * 0.43;
        const wpHalf = waypointSymbolSize * 0.43;
        
        // Draw triangle in black (highlight CENTER/CENTRE waypoint with thicker border)
        if (deleteHover) {
            ctx.fillStyle = '#fff59d';
            ctx.strokeStyle = '#c62828';
            ctx.lineWidth = isCenterWaypointName(waypoint.name) ? 3 : 2;
        } else if (editHover) {
            ctx.fillStyle = '#ffe0b2';
            ctx.strokeStyle = '#e65100';
            ctx.lineWidth = isCenterWaypointName(waypoint.name) ? 3 : 2;
        } else if (routeEditAcquire) {
            ctx.fillStyle = '#a5d6a7';
            ctx.strokeStyle = '#004d40';
            ctx.lineWidth = isCenterWaypointName(waypoint.name) ? 3 : 2;
        } else if (routeEditDraftHover || routeEditDraftPicked) {
            ctx.fillStyle = routeEditDraftHover ? '#c8e6c9' : '#a5d6a7';
            ctx.strokeStyle = '#1b5e20';
            ctx.lineWidth = isCenterWaypointName(waypoint.name) ? 3 : 2;
        } else if (addRouteHover) {
            ctx.fillStyle = '#c8e6c9';
            ctx.strokeStyle = '#1b5e20';
            ctx.lineWidth = isCenterWaypointName(waypoint.name) ? 3 : 2;
        } else if (addRoutePicked) {
            ctx.fillStyle = '#a5d6a7';
            ctx.strokeStyle = '#2e7d32';
            ctx.lineWidth = isCenterWaypointName(waypoint.name) ? 3 : 2;
        } else if (addAtcHover) {
            ctx.fillStyle = '#ffcdd2';
            ctx.strokeStyle = '#c62828';
            ctx.lineWidth = isCenterWaypointName(waypoint.name) ? 3 : 2;
        } else if (addMapAreaHover) {
            ctx.fillStyle = '#b2dfdb';
            ctx.strokeStyle = '#00695c';
            ctx.lineWidth = isCenterWaypointName(waypoint.name) ? 3 : 2;
        } else if (atcEditAcquire) {
            ctx.fillStyle = '#ffccbc';
            ctx.strokeStyle = '#bf360c';
            ctx.lineWidth = isCenterWaypointName(waypoint.name) ? 3 : 2;
        } else if (atcEditDraftHover || atcEditDraftWp) {
            ctx.fillStyle = atcEditDraftHover ? '#ffcdd2' : '#ef9a9a';
            ctx.strokeStyle = '#c62828';
            ctx.lineWidth = isCenterWaypointName(waypoint.name) ? 3 : 2;
        } else if (isCenterWaypointName(waypoint.name)) {
            ctx.fillStyle = '#000000'; // Black for CENTER/CENTRE
            ctx.strokeStyle = '#000000';
            ctx.lineWidth = 3; // Thicker border for CENTER/CENTRE
        } else {
            ctx.fillStyle = '#000000';
            ctx.strokeStyle = '#000000';
            ctx.lineWidth = 1;
        }
        
        if (sectorMapOptions.showWaypointSymbols || waypointHighlight) {
            ctx.beginPath();
            ctx.moveTo(x, y - wpTop);
            ctx.lineTo(x - wpHalf, y + wpBottom);
            ctx.lineTo(x + wpHalf, y + wpBottom);
            ctx.closePath();
            ctx.fill();
            ctx.stroke();
        }
        
        // Draw waypoint name in black
        if (waypoint.name && sectorMapOptions.showWaypointNames) {
            ctx.fillStyle = deleteHover ? '#b71c1c' : (editHover ? '#e65100' : (routeEditAcquire || routeEditDraftHover || routeEditDraftPicked ? '#1b5e20' : (addRouteHover ? '#1b5e20' : (addRoutePicked ? '#1b5e20' : (addAtcHover || atcEditAcquire || atcEditDraftHover || atcEditDraftWp ? '#b71c1c' : (addMapAreaHover ? '#004d40' : '#000000'))))));
            const waypointNameSize = clampSectorMapOptionNumber(sectorMapOptions.waypointNameSize, 6, 36, SECTOR_MAP_OPTIONS_DEFAULTS.waypointNameSize);
            ctx.font = waypointHighlight ? `bold ${waypointNameSize}px Arial` : `${waypointNameSize}px Arial`;
            ctx.textAlign = 'left';
            ctx.textBaseline = 'top';
            ctx.fillText(waypoint.name, x + wpHalf + 4, y - Math.max(10, waypointNameSize * 0.75));
        }
    });

    // Draw taxiways (under parking dots) and parkings (filled circles), plus live taxiway draft.
    try { drawSectorMapTaxiways(); } catch (e) {}
    try { drawSectorMapParkings(); } catch (e) {}
    try { drawSectorMapTaxiwayDraft(); } catch (e) {}
    try { drawSectorMapRunwayDraft(); } catch (e) {}

    // Draw NAVAIDs with type-specific navigation symbols.
    (navaids || []).forEach(nav => {
        if (!nav || typeof nav.latitude !== 'number' || typeof nav.longitude !== 'number') return;
        if (isNaN(nav.latitude) || isNaN(nav.longitude) || !isFinite(nav.latitude) || !isFinite(nav.longitude)) return;

        let relLon = nav.longitude;
        let relLat = nav.latitude;
        if (centreWaypoint && typeof centreWaypoint.latitude === 'number' && typeof centreWaypoint.longitude === 'number') {
            relLon = nav.longitude - centreWaypoint.longitude;
            relLat = nav.latitude - centreWaypoint.latitude;
        }

        const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
        const y = effectiveOriginY - relLat * zoomLevel;
        if (isNaN(x) || isNaN(y) || !isFinite(x) || !isFinite(y)) return;
        if (!sectorMapCanvasPointIsInRenderView(x, y, 180)) return;

        const deleteHover = sectorMapNavaidDeleteActive && sectorMapDeleteHoverNavaidId && nav.id === sectorMapDeleteHoverNavaidId;
        const editHover = sectorMapNavaidEditActive && sectorMapEditHoverNavaidId && nav.id === sectorMapEditHoverNavaidId;
        const addRouteHover = sectorMapAddRoutePickingActive && sectorMapAddRouteHoverWaypointId && nav.id === sectorMapAddRouteHoverWaypointId;
        const addRoutePicked = sectorMapAddRoutePickingActive && sectorMapAddRoutePickedIds.includes(nav.id);
        const routeEditMap = sectorMapRouteEditActive && sectorMapRouteEditTargetRouteId;
        const routeEditAcquire = routeEditMap && sectorMapRouteEditDragAcquireWaypointId && nav.id === sectorMapRouteEditDragAcquireWaypointId;
        const routeEditDraftHover = routeEditMap && sectorMapRouteEditHoverWaypointId && nav.id === sectorMapRouteEditHoverWaypointId;
        const routeEditDraftPicked = routeEditMap && sectorMapRouteEditDraftIds.includes(nav.id);
        const routeHighlight = addRouteHover || addRoutePicked || routeEditAcquire || routeEditDraftHover || routeEditDraftPicked;
        const strokeColor = deleteHover ? '#c62828' : (editHover ? '#e65100' : (routeHighlight ? '#1b5e20' : '#000000'));
        const fillColor = deleteHover ? '#fff59d' : (editHover ? '#ffe0b2' : (routeHighlight ? '#c8e6c9' : 'rgba(37, 99, 235, 0.16)'));
        const navaidSymbolSize = clampSectorMapOptionNumber(sectorMapOptions.navaidSymbolSize, 8, 44, SECTOR_MAP_OPTIONS_DEFAULTS.navaidSymbolSize);

        ctx.save();
        if (sectorMapOptions.showNavaidSymbols || deleteHover || editHover || routeHighlight) {
            drawSectorMapNavaidSymbol(ctx, x, y, nav.type, strokeColor, deleteHover || editHover || routeHighlight ? fillColor : null, navaidSymbolSize);
        }

        const label = `${nav.name || ''}${nav.type ? ` (${normalizeNavaidType(nav.type)})` : ''}`.trim();
        if (label && sectorMapOptions.showNavaidNames) {
            const navaidNameSize = clampSectorMapOptionNumber(sectorMapOptions.navaidNameSize, 6, 36, SECTOR_MAP_OPTIONS_DEFAULTS.navaidNameSize);
            ctx.fillStyle = strokeColor;
            ctx.font = deleteHover || editHover || routeHighlight ? `bold ${navaidNameSize}px Arial` : `${navaidNameSize}px Arial`;
            ctx.textAlign = 'left';
            ctx.textBaseline = 'top';
            ctx.fillText(label, x + navaidSymbolSize * 0.55 + 6, y - Math.max(10, navaidNameSize * 0.75));
        }
        ctx.restore();
    });

    if (sectorMapAddAtcSectorActive && sectorMapAddAtcSectorSelection.length) {
        const resolvedPts = [];
        for (let i = 0; i < sectorMapAddAtcSectorSelection.length; i++) {
            const row = sectorMapAddAtcSectorLatLonNameFromSelection(sectorMapAddAtcSectorSelection[i]);
            if (!row) continue;
            let relLon = row.longitude;
            let relLat = row.latitude;
            if (centreWaypoint) {
                relLon = row.longitude - centreWaypoint.longitude;
                relLat = row.latitude - centreWaypoint.latitude;
            }
            const px = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
            const py = effectiveOriginY - relLat * zoomLevel;
            if (isFinite(px) && isFinite(py)) resolvedPts.push({ x: px, y: py });
        }
        if (resolvedPts.length) {
            ctx.save();
            ctx.strokeStyle = '#c62828';
            ctx.fillStyle = '#e53935';
            ctx.lineWidth = 2;
            ctx.lineJoin = 'round';
            if (resolvedPts.length >= 2) {
                ctx.beginPath();
                ctx.moveTo(resolvedPts[0].x, resolvedPts[0].y);
                for (let j = 1; j < resolvedPts.length; j++) {
                    ctx.lineTo(resolvedPts[j].x, resolvedPts[j].y);
                }
                ctx.stroke();
            }
            const first = resolvedPts[0];
            const closeRing = sectorMapAddAtcSectorSelection.length >= 3;
            resolvedPts.forEach((p, idx) => {
                const r = (closeRing && idx === 0) ? 7 : 5;
                ctx.beginPath();
                ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
                ctx.fill();
                ctx.strokeStyle = '#b71c1c';
                ctx.lineWidth = 2;
                ctx.stroke();
                ctx.strokeStyle = '#c62828';
            });
            if (closeRing && first) {
                ctx.strokeStyle = '#ff8a80';
                ctx.setLineDash([4, 3]);
                ctx.lineWidth = 1;
                ctx.beginPath();
                ctx.arc(first.x, first.y, 11, 0, Math.PI * 2);
                ctx.stroke();
                ctx.setLineDash([]);
            }
            ctx.restore();
        }
    }

    if (sectorMapAddMapAreaActive && sectorMapAddMapAreaSelection.length) {
        const resolvedPtsMa = [];
        for (let i = 0; i < sectorMapAddMapAreaSelection.length; i++) {
            const row = sectorMapAddMapAreaLatLonNameFromSelection(sectorMapAddMapAreaSelection[i]);
            if (!row) continue;
            let relLon = row.longitude;
            let relLat = row.latitude;
            if (centreWaypoint) {
                relLon = row.longitude - centreWaypoint.longitude;
                relLat = row.latitude - centreWaypoint.latitude;
            }
            const pxa = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
            const pya = effectiveOriginY - relLat * zoomLevel;
            if (isFinite(pxa) && isFinite(pya)) resolvedPtsMa.push({ x: pxa, y: pya });
        }
        if (resolvedPtsMa.length) {
            ctx.save();
            ctx.strokeStyle = '#00695c';
            ctx.fillStyle = '#00897b';
            ctx.lineWidth = 2;
            ctx.lineJoin = 'round';
            if (resolvedPtsMa.length >= 2) {
                ctx.beginPath();
                ctx.moveTo(resolvedPtsMa[0].x, resolvedPtsMa[0].y);
                for (let j = 1; j < resolvedPtsMa.length; j++) {
                    ctx.lineTo(resolvedPtsMa[j].x, resolvedPtsMa[j].y);
                }
                ctx.stroke();
            }
            const firstMa = resolvedPtsMa[0];
            const closeRingMa = sectorMapAddMapAreaSelection.length >= 3;
            resolvedPtsMa.forEach((p, idx) => {
                const r = (closeRingMa && idx === 0) ? 7 : 5;
                ctx.beginPath();
                ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
                ctx.fill();
                ctx.strokeStyle = '#004d40';
                ctx.lineWidth = 2;
                ctx.stroke();
                ctx.strokeStyle = '#00695c';
            });
            if (closeRingMa && firstMa) {
                ctx.strokeStyle = '#80cbc4';
                ctx.setLineDash([4, 3]);
                ctx.lineWidth = 1;
                ctx.beginPath();
                ctx.arc(firstMa.x, firstMa.y, 11, 0, Math.PI * 2);
                ctx.stroke();
                ctx.setLineDash([]);
            }
            ctx.restore();
        }
    }

    if (sectorMapAtcSectorEditActive && sectorMapAtcSectorEditTargetId && sectorMapAtcSectorEditDraftPoints.length) {
        const resolvedPts = [];
        for (let i = 0; i < sectorMapAtcSectorEditDraftPoints.length; i++) {
            const row = sectorMapAddAtcSectorLatLonNameFromSelection(sectorMapAtcSectorEditDraftPoints[i]);
            if (!row) continue;
            let relLon = row.longitude;
            let relLat = row.latitude;
            if (centreWaypoint) {
                relLon = row.longitude - centreWaypoint.longitude;
                relLat = row.latitude - centreWaypoint.latitude;
            }
            const pxx = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
            const pyy = effectiveOriginY - relLat * zoomLevel;
            if (isFinite(pxx) && isFinite(pyy)) resolvedPts.push({ x: pxx, y: pyy });
        }
        if (resolvedPts.length) {
            ctx.save();
            ctx.strokeStyle = '#c62828';
            ctx.fillStyle = '#e53935';
            ctx.lineWidth = 2;
            ctx.lineJoin = 'round';
            if (resolvedPts.length >= 2) {
                ctx.beginPath();
                ctx.moveTo(resolvedPts[0].x, resolvedPts[0].y);
                for (let j = 1; j < resolvedPts.length; j++) {
                    ctx.lineTo(resolvedPts[j].x, resolvedPts[j].y);
                }
                if (resolvedPts.length >= 3) {
                    ctx.lineTo(resolvedPts[0].x, resolvedPts[0].y);
                }
                ctx.stroke();
            }
            resolvedPts.forEach(p => {
                ctx.beginPath();
                ctx.arc(p.x, p.y, 5, 0, Math.PI * 2);
                ctx.fill();
                ctx.strokeStyle = '#b71c1c';
                ctx.lineWidth = 2;
                ctx.stroke();
                ctx.strokeStyle = '#c62828';
            });
            ctx.restore();
        }
    }

    if (sectorMapAtcSectorEditDragType && sectorMapAtcSectorEditDragAnchorX != null && sectorMapAtcSectorEditDragAnchorY != null &&
        sectorMapAtcSectorEditDragCursorX != null && sectorMapAtcSectorEditDragCursorY != null &&
        isFinite(sectorMapAtcSectorEditDragAnchorX) && isFinite(sectorMapAtcSectorEditDragAnchorY) &&
        isFinite(sectorMapAtcSectorEditDragCursorX) && isFinite(sectorMapAtcSectorEditDragCursorY)) {
        ctx.save();
        ctx.strokeStyle = '#2e7d32';
        ctx.lineWidth = 2;
        ctx.setLineDash([6, 4]);
        ctx.globalAlpha = 0.92;
        ctx.lineCap = 'round';
        ctx.beginPath();
        ctx.moveTo(sectorMapAtcSectorEditDragAnchorX, sectorMapAtcSectorEditDragAnchorY);
        ctx.lineTo(sectorMapAtcSectorEditDragCursorX, sectorMapAtcSectorEditDragCursorY);
        ctx.stroke();
        ctx.restore();
    }

    if (sectorMapRouteEditDragType && sectorMapRouteEditDragAnchorX != null && sectorMapRouteEditDragAnchorY != null &&
        sectorMapRouteEditDragCursorX != null && sectorMapRouteEditDragCursorY != null &&
        isFinite(sectorMapRouteEditDragAnchorX) && isFinite(sectorMapRouteEditDragAnchorY) &&
        isFinite(sectorMapRouteEditDragCursorX) && isFinite(sectorMapRouteEditDragCursorY)) {
        ctx.save();
        ctx.strokeStyle = '#2e7d32';
        ctx.lineWidth = 2;
        ctx.setLineDash([6, 4]);
        ctx.globalAlpha = 0.92;
        ctx.lineCap = 'round';
        ctx.beginPath();
        ctx.moveTo(sectorMapRouteEditDragAnchorX, sectorMapRouteEditDragAnchorY);
        ctx.lineTo(sectorMapRouteEditDragCursorX, sectorMapRouteEditDragCursorY);
        ctx.stroke();
        ctx.restore();
    }

    // Distance measurements (middle-click drag; left-click label to remove)
    sectorMapMeasurementTextBounds = [];
    sectorMapMeasurements.forEach((measurement, index) => {
        if (!measurement?.start || !measurement?.end) return;
        if (measurement.start.type !== 'coord' || measurement.end.type !== 'coord') return;
        const sLL = { lat: measurement.start.lat, lon: measurement.start.lon };
        const eLL = { lat: measurement.end.lat, lon: measurement.end.lon };
        if (![sLL.lat, sLL.lon, eLL.lat, eLL.lon].every(isFinite)) return;

        const distance = calculateNauticalMiles(sLL.lat, sLL.lon, eLL.lat, eLL.lon);
        let startRelLon = sLL.lon;
        let startRelLat = sLL.lat;
        let endRelLon = eLL.lon;
        let endRelLat = eLL.lat;
        if (centreWaypoint && typeof centreWaypoint.latitude === 'number' && typeof centreWaypoint.longitude === 'number') {
            startRelLon = sLL.lon - centreWaypoint.longitude;
            startRelLat = sLL.lat - centreWaypoint.latitude;
            endRelLon = eLL.lon - centreWaypoint.longitude;
            endRelLat = eLL.lat - centreWaypoint.latitude;
        }
        const startX = effectiveOriginX + startRelLon * zoomLevel * sectorLonScale;
        const startY = effectiveOriginY - startRelLat * zoomLevel;
        const endX = effectiveOriginX + endRelLon * zoomLevel * sectorLonScale;
        const endY = effectiveOriginY - endRelLat * zoomLevel;
        if (!isFinite(startX) || !isFinite(startY) || !isFinite(endX) || !isFinite(endY)) return;

        const measurementColor = measurement.color || MEASUREMENT_COLORS[index % MEASUREMENT_COLORS.length];
        ctx.strokeStyle = measurementColor;
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(startX, startY);
        ctx.lineTo(endX, endY);
        ctx.stroke();

        if (!isFinite(distance)) return;
        ctx.fillStyle = measurementColor;
        ctx.font = 'bold 14px Arial';
        ctx.textAlign = 'left';
        ctx.textBaseline = 'top';
        const distanceText = `${distance.toFixed(1)}`;
        const bearing = heading0to359(calculateBearingDegrees(sLL.lat, sLL.lon, eLL.lat, eLL.lon));
        const bearingBack = (bearing + 180) % 360;
        const directionText = `${formatHeadingFrom0to359(bearing)} ${formatHeadingFrom0to359(bearingBack)}`;
        const lineHeight = 16;
        const distanceWidth = ctx.measureText(distanceText).width;
        const directionWidth = ctx.measureText(directionText).width;
        const textWidth = Math.max(distanceWidth, directionWidth);
        const blockHeight = lineHeight * 2;
        const textX = endX + 5;
        const textY = endY - blockHeight / 2;
        const textRectWidth = textWidth + 8;
        const textRectHeight = blockHeight + 4;
        sectorMapMeasurementTextBounds.push({
            index,
            x: textX,
            y: textY,
            width: textRectWidth,
            height: textRectHeight
        });
        ctx.fillText(distanceText, textX + 4, textY + 2);
        ctx.fillText(directionText, textX + 4, textY + 2 + lineHeight);
    });

    if (sectorMapIsMeasuring && sectorMapMeasureStartLatLon && sectorMapMeasureCurrentPx) {
        const sLL = sectorMapMeasureStartLatLon;
        let startRelLon = sLL.lon;
        let startRelLat = sLL.lat;
        if (centreWaypoint && typeof centreWaypoint.latitude === 'number' && typeof centreWaypoint.longitude === 'number') {
            startRelLon = sLL.lon - centreWaypoint.longitude;
            startRelLat = sLL.lat - centreWaypoint.latitude;
        }
        const startX = effectiveOriginX + startRelLon * zoomLevel * sectorLonScale;
        const startY = effectiveOriginY - startRelLat * zoomLevel;
        const endX = sectorMapMeasureCurrentPx.x;
        const endY = sectorMapMeasureCurrentPx.y;
        updateCentreWaypoint();
        const endLL = canvasPixelToSectorLatLon(endX, endY);
        if (isFinite(startX) && isFinite(startY) && isFinite(endX) && isFinite(endY) &&
            isFinite(endLL.latitude) && isFinite(endLL.longitude)) {
            const distance = calculateNauticalMiles(sLL.lat, sLL.lon, endLL.latitude, endLL.longitude);
            const measurementColor = sectorMapActiveMeasurementColor || MEASUREMENT_COLORS[0];
            ctx.strokeStyle = measurementColor;
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.moveTo(startX, startY);
            ctx.lineTo(endX, endY);
            ctx.stroke();
            if (isFinite(distance)) {
                ctx.fillStyle = measurementColor;
                ctx.font = 'bold 14px Arial';
                ctx.textAlign = 'left';
                ctx.textBaseline = 'top';
                const distanceText = `${distance.toFixed(1)}`;
                const bearing = heading0to359(calculateBearingDegrees(
                    sLL.lat, sLL.lon, endLL.latitude, endLL.longitude
                ));
                const bearingBack = (bearing + 180) % 360;
                const directionText = `${formatHeadingFrom0to359(bearing)} ${formatHeadingFrom0to359(bearingBack)}`;
                const lineHeight = 16;
                const textX = endX + 5;
                const textY = endY - lineHeight;
                ctx.fillText(distanceText, textX, textY);
                ctx.fillText(directionText, textX, textY + lineHeight);
            }
        }
    }
}

// Convert canvas coordinates to world coordinates
function canvasToWorld(canvasX, canvasY) {
    return {
        x: canvasX - originX,
        y: originY - canvasY // Flip Y axis
    };
}

function getSectorCanvasEffectiveOriginPx() {
    if (!canvas) return { ox: 0, oy: 0 };
    const ox0 = canvas.width / 2;
    const oy0 = canvas.height / 2;
    return { ox: ox0 + panX, oy: oy0 + panY };
}

function pointInTriangle(px, py, x0, y0, x1, y1, x2, y2) {
    const sign = (ax, ay, bx, by, cx, cy) => (ax - cx) * (by - cy) - (bx - cx) * (ay - cy);
    const d1 = sign(px, py, x0, y0, x1, y1);
    const d2 = sign(px, py, x1, y1, x2, y2);
    const d3 = sign(px, py, x2, y2, x0, y0);
    const hasNeg = d1 < 0 || d2 < 0 || d3 < 0;
    const hasPos = d1 > 0 || d2 > 0 || d3 > 0;
    return !(hasNeg && hasPos);
}

/** Hit-test Edit Airspace map: triangle + label box (top-most waypoint wins). */
function findSectorWaypointAtCanvasPixel(canvasX, canvasY) {
    if (!canvas || !isFinite(canvasX) || !isFinite(canvasY)) return null;
    updateCentreWaypoint();
    const { ox: effectiveOriginX, oy: effectiveOriginY } = getSectorCanvasEffectiveOriginPx();
    if (!isFinite(zoomLevel) || zoomLevel <= 0) return null;
    const sectorLonScale = getSectorMapLonCosScale();

    const labelPad = 4;

    for (let i = waypoints.length - 1; i >= 0; i--) {
        const waypoint = waypoints[i];
        if (!waypoint || typeof waypoint.latitude !== 'number' || typeof waypoint.longitude !== 'number') continue;
        if (!isFinite(waypoint.latitude) || !isFinite(waypoint.longitude)) continue;

        let relLon = waypoint.longitude;
        let relLat = waypoint.latitude;
        if (centreWaypoint && isFinite(centreWaypoint.latitude) && isFinite(centreWaypoint.longitude)) {
            relLon = waypoint.longitude - centreWaypoint.longitude;
            relLat = waypoint.latitude - centreWaypoint.latitude;
        }

        const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
        const y = effectiveOriginY - relLat * zoomLevel;
        if (!isFinite(x) || !isFinite(y)) continue;

        const waypointSymbolSize = clampSectorMapOptionNumber(sectorMapOptions.waypointSymbolSize, 6, 36, SECTOR_MAP_OPTIONS_DEFAULTS.waypointSymbolSize);
        const wpTop = waypointSymbolSize * 0.57;
        const wpBottom = waypointSymbolSize * 0.43;
        const wpHalf = waypointSymbolSize * 0.43;
        const x0 = x;
        const y0 = y - wpTop;
        const x1 = x - wpHalf;
        const y1 = y + wpBottom;
        const x2 = x + wpHalf;
        const y2 = y + wpBottom;
        if (sectorMapOptions.showWaypointSymbols && pointInTriangle(canvasX, canvasY, x0, y0, x1, y1, x2, y2)) {
            return waypoint;
        }

        const name = waypoint.name ? String(waypoint.name) : '';
        if (name && sectorMapOptions.showWaypointNames) {
            const waypointNameSize = clampSectorMapOptionNumber(sectorMapOptions.waypointNameSize, 6, 36, SECTOR_MAP_OPTIONS_DEFAULTS.waypointNameSize);
            let tw = Math.max(8, name.length * 7);
            if (ctx) {
                ctx.save();
                ctx.font = `${waypointNameSize}px Arial`;
                tw = ctx.measureText(name).width;
                ctx.restore();
            }
            const lx = x + wpHalf + 4;
            const ly = y - Math.max(10, waypointNameSize * 0.75);
            if (canvasX >= lx - labelPad && canvasX <= lx + tw + labelPad &&
                canvasY >= ly - labelPad && canvasY <= ly + waypointNameSize + 2 + labelPad) {
                return waypoint;
            }
        }
    }

    return null;
}

function findSectorNavaidAtCanvasPixel(canvasX, canvasY) {
    if (!canvas || !isFinite(canvasX) || !isFinite(canvasY)) return null;
    updateCentreWaypoint();
    const { ox: effectiveOriginX, oy: effectiveOriginY } = getSectorCanvasEffectiveOriginPx();
    if (!isFinite(zoomLevel) || zoomLevel <= 0) return null;
    const sectorLonScale = getSectorMapLonCosScale();
    const labelPad = 4;

    for (let i = (navaids || []).length - 1; i >= 0; i--) {
        const nav = navaids[i];
        if (!nav || typeof nav.latitude !== 'number' || typeof nav.longitude !== 'number') continue;
        if (!isFinite(nav.latitude) || !isFinite(nav.longitude)) continue;

        let relLon = nav.longitude;
        let relLat = nav.latitude;
        if (centreWaypoint && isFinite(centreWaypoint.latitude) && isFinite(centreWaypoint.longitude)) {
            relLon = nav.longitude - centreWaypoint.longitude;
            relLat = nav.latitude - centreWaypoint.latitude;
        }
        const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
        const y = effectiveOriginY - relLat * zoomLevel;
        if (!isFinite(x) || !isFinite(y)) continue;

        const navaidSymbolSize = clampSectorMapOptionNumber(sectorMapOptions.navaidSymbolSize, 8, 44, SECTOR_MAP_OPTIONS_DEFAULTS.navaidSymbolSize);
        const hitRadius = Math.max(6, navaidSymbolSize * 0.65);
        const dx = canvasX - x;
        const dy = canvasY - y;
        if (sectorMapOptions.showNavaidSymbols && dx * dx + dy * dy <= hitRadius * hitRadius) return nav;

        const label = `${nav.name || ''}${nav.type ? ` (${normalizeNavaidType(nav.type)})` : ''}`.trim();
        if (label && sectorMapOptions.showNavaidNames) {
            const navaidNameSize = clampSectorMapOptionNumber(sectorMapOptions.navaidNameSize, 6, 36, SECTOR_MAP_OPTIONS_DEFAULTS.navaidNameSize);
            let tw = Math.max(8, label.length * 7);
            if (ctx) {
                ctx.save();
                ctx.font = `${navaidNameSize}px Arial`;
                tw = ctx.measureText(label).width;
                ctx.restore();
            }
            const lx = x + navaidSymbolSize * 0.55 + 6;
            const ly = y - Math.max(10, navaidNameSize * 0.75);
            if (canvasX >= lx - labelPad && canvasX <= lx + tw + labelPad &&
                canvasY >= ly - labelPad && canvasY <= ly + navaidNameSize + 2 + labelPad) {
                return nav;
            }
        }
    }
    return null;
}

function drawRegularPolygon(ctx, x, y, radius, sides, rotationRad = -Math.PI / 2) {
    if (!ctx || sides < 3) return;
    ctx.beginPath();
    for (let i = 0; i < sides; i++) {
        const a = rotationRad + (Math.PI * 2 * i / sides);
        const px = x + Math.cos(a) * radius;
        const py = y + Math.sin(a) * radius;
        if (i === 0) ctx.moveTo(px, py);
        else ctx.lineTo(px, py);
    }
    ctx.closePath();
}

function drawDottedRing(ctx, x, y, radius, dotCount, dotRadius = 1.2) {
    for (let i = 0; i < dotCount; i++) {
        const a = (Math.PI * 2 * i) / dotCount;
        ctx.beginPath();
        ctx.arc(x + Math.cos(a) * radius, y + Math.sin(a) * radius, dotRadius, 0, Math.PI * 2);
        ctx.fill();
    }
}

function drawTacanSymbol(ctx, x, y, fillProtrusions = false) {
    const r = 10;
    const vertices = [];
    const protrusions = [];
    for (let i = 0; i < 6; i++) {
        const a = (Math.PI * 2 * i) / 6;
        vertices.push({ x: x + Math.cos(a) * r, y: y + Math.sin(a) * r });
    }
    const protrudeEdges = new Set([1, 3, 5]); // bottom, top-left, top-right
    ctx.beginPath();
    ctx.moveTo(vertices[0].x, vertices[0].y);
    for (let i = 0; i < 6; i++) {
        const a = vertices[i];
        const b = vertices[(i + 1) % 6];
        if (protrudeEdges.has(i)) {
            const dx = b.x - a.x;
            const dy = b.y - a.y;
            const len = Math.hypot(dx, dy) || 1;
            // Right-hand normal is outward for this vertex order in canvas coordinates.
            const nx = (dy / len) * (len / 2);
            const ny = (-dx / len) * (len / 2);
            protrusions.push([a, { x: a.x + nx, y: a.y + ny }, { x: b.x + nx, y: b.y + ny }, b]);
            ctx.lineTo(a.x + nx, a.y + ny);
            ctx.lineTo(b.x + nx, b.y + ny);
            ctx.lineTo(b.x, b.y);
        } else {
            ctx.lineTo(b.x, b.y);
        }
    }
    ctx.closePath();
    ctx.stroke();
    if (fillProtrusions) {
        protrusions.forEach(points => {
            ctx.beginPath();
            ctx.moveTo(points[0].x, points[0].y);
            points.slice(1).forEach(p => ctx.lineTo(p.x, p.y));
            ctx.closePath();
            ctx.fill();
        });
    }
}

function drawSectorMapNavaidSymbol(ctx, x, y, type, strokeColor = '#000000', highlightFill = null, symbolSize = 20) {
    const t = normalizeNavaidType(type);
    const scale = clampSectorMapOptionNumber(symbolSize, 8, 44, SECTOR_MAP_OPTIONS_DEFAULTS.navaidSymbolSize) / 20;
    ctx.save();
    ctx.translate(x, y);
    ctx.scale(scale, scale);
    x = 0;
    y = 0;
    ctx.strokeStyle = strokeColor;
    ctx.fillStyle = strokeColor;
    ctx.lineWidth = 2;

    if (highlightFill) {
        ctx.save();
        ctx.fillStyle = highlightFill;
        ctx.beginPath();
        ctx.arc(x, y, 13, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
    }

    if (t === 'VOR') {
        drawRegularPolygon(ctx, x, y, 10, 6, 0);
        ctx.stroke();
    }

    if (t === 'DME') {
        ctx.strokeRect(x - 8, y - 8, 16, 16);
    } else if (t === 'VOR/DME') {
        ctx.strokeRect(x - 10, y - 10, 20, 20);
        drawRegularPolygon(ctx, x, y, 10, 6, 0);
        ctx.stroke();
    } else if (t === 'TACAN') {
        drawTacanSymbol(ctx, x, y);
    } else if (t === 'VORTAC') {
        drawTacanSymbol(ctx, x, y, true);
    } else if (t === 'NDB') {
        [5, 9, 13].forEach((radius, idx) => drawDottedRing(ctx, x, y, radius, 10 + idx * 6, 1.1));
    } else if (t !== 'VOR' && t !== 'DME' && t !== 'VOR/DME') {
        ctx.beginPath();
        ctx.arc(x, y, 9, 0, Math.PI * 2);
        ctx.stroke();
    }

    ctx.beginPath();
    ctx.arc(x, y, 2.5, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
}

function distanceSquaredPointToSegment(px, py, x1, y1, x2, y2) {
    const dx = x2 - x1;
    const dy = y2 - y1;
    const lenSq = dx * dx + dy * dy;
    if (lenSq < 1e-6) {
        const ux = px - x1;
        const uy = py - y1;
        return ux * ux + uy * uy;
    }
    let t = ((px - x1) * dx + (py - y1) * dy) / lenSq;
    t = Math.max(0, Math.min(1, t));
    const nx = x1 + t * dx;
    const ny = y1 + t * dy;
    const ux = px - nx;
    const uy = py - ny;
    return ux * ux + uy * uy;
}

function sectorMapRouteDeleteHoverSegmentIdsEqual(nextIds) {
    const a = sectorMapRouteDeleteHoverSegmentRouteIds;
    if (a.length !== nextIds.length) return false;
    for (let i = 0; i < a.length; i++) {
        if (a[i] !== nextIds[i]) return false;
    }
    return true;
}

/** Routes whose polyline passes within thresholdPx of (canvasX, canvasY), in list order. */
function findSectorMapRouteIdsNearCanvasSegment(canvasX, canvasY, thresholdPx) {
    const out = [];
    const thrSq = thresholdPx * thresholdPx;
    if (!canvas || !isFinite(canvasX) || !isFinite(canvasY)) return out;
    updateCentreWaypoint();
    const { ox: effectiveOriginX, oy: effectiveOriginY } = getSectorCanvasEffectiveOriginPx();
    if (!isFinite(zoomLevel) || zoomLevel <= 0) return out;
    const sectorLonScale = getSectorMapLonCosScale();
    const routeFixById = buildSectorRouteFixLookup();

    routes.forEach(route => {
        if (!route || !route.id || !route.waypointIds || route.waypointIds.length < 2) return;
        const pts = [];
        for (const waypointId of route.waypointIds) {
            const waypoint = routeFixById.get(String(waypointId));
            if (waypoint && typeof waypoint.latitude === 'number' && typeof waypoint.longitude === 'number' &&
                isFinite(waypoint.latitude) && isFinite(waypoint.longitude)) {
                let relLon = waypoint.longitude;
                let relLat = waypoint.latitude;
                if (centreWaypoint && isFinite(centreWaypoint.latitude) && isFinite(centreWaypoint.longitude)) {
                    relLon = waypoint.longitude - centreWaypoint.longitude;
                    relLat = waypoint.latitude - centreWaypoint.latitude;
                }
                const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
                const y = effectiveOriginY - relLat * zoomLevel;
                if (isFinite(x) && isFinite(y)) pts.push({ x, y });
            }
        }
        if (pts.length < 2) return;
        for (let i = 0; i < pts.length - 1; i++) {
            if (distanceSquaredPointToSegment(canvasX, canvasY, pts[i].x, pts[i].y, pts[i + 1].x, pts[i + 1].y) <= thrSq) {
                out.push(route.id);
                return;
            }
        }
    });
    return out;
}

function findSectorMapAtcSectorIdsNearCanvasSegment(canvasX, canvasY, thresholdPx) {
    const out = [];
    const thrSq = thresholdPx * thresholdPx;
    if (!canvas || !isFinite(canvasX) || !isFinite(canvasY)) return out;
    updateCentreWaypoint();
    const { ox: effectiveOriginX, oy: effectiveOriginY } = getSectorCanvasEffectiveOriginPx();
    if (!isFinite(zoomLevel) || zoomLevel <= 0) return out;
    const sectorLonScale = getSectorMapLonCosScale();

    atcSectors.forEach(sec => {
        if (!sec || !sec.id || !sec.boundary || !Array.isArray(sec.boundary.points)) return;
        const raw = sec.boundary.points.filter(p =>
            p && typeof p.latitude === 'number' && typeof p.longitude === 'number' &&
            isFinite(p.latitude) && isFinite(p.longitude)
        );
        if (raw.length < 2) return;
        const pts = raw.map(p => {
            let relLon = p.longitude;
            let relLat = p.latitude;
            if (centreWaypoint && isFinite(centreWaypoint.latitude) && isFinite(centreWaypoint.longitude)) {
                relLon = p.longitude - centreWaypoint.longitude;
                relLat = p.latitude - centreWaypoint.latitude;
            }
            const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
            const y = effectiveOriginY - relLat * zoomLevel;
            return { x, y };
        }).filter(p => isFinite(p.x) && isFinite(p.y));
        if (pts.length < 2) return;
        const n = pts.length;
        for (let i = 0; i < n - 1; i++) {
            if (distanceSquaredPointToSegment(canvasX, canvasY, pts[i].x, pts[i].y, pts[i + 1].x, pts[i + 1].y) <= thrSq) {
                out.push(sec.id);
                return;
            }
        }
        if (n >= 3) {
            if (distanceSquaredPointToSegment(canvasX, canvasY, pts[n - 1].x, pts[n - 1].y, pts[0].x, pts[0].y) <= thrSq) {
                out.push(sec.id);
            }
        }
    });
    return out;
}

function sectorMapAtcEditPickHitForAcquire(canvasX, canvasY) {
    const wp = findSectorWaypointAtCanvasPixel(canvasX, canvasY);
    if (wp) return { hit: 'waypoint', waypoint: wp };
    const vtx = findAtcSectorBoundaryVertexAtCanvasPixel(canvasX, canvasY, 14);
    if (vtx) return { hit: 'atcVertex', atcId: vtx.atcId, ptIndex: vtx.ptIndex, point: vtx.point };
    return { hit: 'canvas' };
}

function sectorMapAtcEditLatLonForDraftIndex(index) {
    const sel = sectorMapAtcSectorEditDraftPoints[index];
    return sel ? sectorMapAddAtcSectorLatLonNameFromSelection(sel) : null;
}

function sectorMapAtcEditCanvasXYForDraftIndex(index) {
    const row = sectorMapAtcEditLatLonForDraftIndex(index);
    if (!row) return null;
    updateCentreWaypoint();
    const { ox: effectiveOriginX, oy: effectiveOriginY } = getSectorCanvasEffectiveOriginPx();
    if (!isFinite(zoomLevel) || zoomLevel <= 0) return null;
    const sectorLonScale = getSectorMapLonCosScale();
    let relLon = row.longitude;
    let relLat = row.latitude;
    if (centreWaypoint && isFinite(centreWaypoint.latitude) && isFinite(centreWaypoint.longitude)) {
        relLon = row.longitude - centreWaypoint.longitude;
        relLat = row.latitude - centreWaypoint.latitude;
    }
    const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
    const y = effectiveOriginY - relLat * zoomLevel;
    if (!isFinite(x) || !isFinite(y)) return null;
    return { x, y };
}

function findAtcEditDraftVertexIndexAtCanvasPixel(canvasX, canvasY, thresholdPx) {
    if (!sectorMapAtcSectorEditDraftPoints.length) return -1;
    const thrSq = thresholdPx * thresholdPx;
    let best = -1;
    let bestD = Infinity;
    for (let i = 0; i < sectorMapAtcSectorEditDraftPoints.length; i++) {
        const xy = sectorMapAtcEditCanvasXYForDraftIndex(i);
        if (!xy) continue;
        const d = (canvasX - xy.x) ** 2 + (canvasY - xy.y) ** 2;
        if (d < bestD) {
            bestD = d;
            best = i;
        }
    }
    if (best < 0 || bestD > thrSq) return -1;
    return best;
}

function findAtcEditDraftSegmentIndexNearCanvasPixel(canvasX, canvasY, thresholdPx) {
    const draft = sectorMapAtcSectorEditDraftPoints;
    const n = draft.length;
    if (n < 2 || !isFinite(canvasX) || !isFinite(canvasY)) return -1;
    const vThr = 9;
    const vThrSq = vThr * vThr;
    const thrSq = thresholdPx * thresholdPx;
    let bestI = -1;
    let bestD = Infinity;

    const distToVtx = (i) => {
        const xy = sectorMapAtcEditCanvasXYForDraftIndex(i);
        if (!xy) return Infinity;
        return (canvasX - xy.x) ** 2 + (canvasY - xy.y) ** 2;
    };

    const trySeg = (i, j) => {
        const p0 = sectorMapAtcEditCanvasXYForDraftIndex(i);
        const p1 = sectorMapAtcEditCanvasXYForDraftIndex(j);
        if (!p0 || !p1) return;
        if (distToVtx(i) <= vThrSq || distToVtx(j) <= vThrSq) return;
        const d = distanceSquaredPointToSegment(canvasX, canvasY, p0.x, p0.y, p1.x, p1.y);
        if (d < bestD) {
            bestD = d;
            bestI = i;
        }
    };

    for (let i = 0; i < n - 1; i++) trySeg(i, i + 1);
    if (n >= 3) trySeg(n - 1, 0);

    if (bestI < 0 || bestD > thrSq) return -1;
    return bestI;
}

function sectorMapAtcSectorEditPickHoverSegmentIdsEqual(nextIds) {
    const a = sectorMapAtcSectorEditPickHoverSegmentIds;
    if (a.length !== nextIds.length) return false;
    for (let i = 0; i < a.length; i++) {
        if (a[i] !== nextIds[i]) return false;
    }
    return true;
}

function getSectorMapAtcSectorEditPickHighlightIdSet() {
    if (!sectorMapAtcSectorEditActive || sectorMapAtcSectorEditTargetId) return null;
    const set = new Set();
    if (sectorMapAtcSectorEditPickBoxHoverId) {
        set.add(sectorMapAtcSectorEditPickBoxHoverId);
        return set;
    }
    if (sectorMapAtcSectorEditPickDisambigVisible && sectorMapAtcSectorEditPickDisambigIds.length) {
        sectorMapAtcSectorEditPickDisambigIds.forEach(id => set.add(id));
        return set;
    }
    sectorMapAtcSectorEditPickHoverSegmentIds.forEach(id => set.add(id));
    return set;
}

/** Red stroke for ATC boundaries: edit pick phase, or delete-ATC-sector hover/disambig. */
function getSectorMapAtcSectorSegmentRedHighlightIdSet() {
    const e = getSectorMapAtcSectorEditPickHighlightIdSet();
    if (e && e.size) return e;
    const d = getSectorMapAtcSectorDeleteHighlightIdSet();
    if (d && d.size) return d;
    return null;
}

function sectorMapAtcSectorDeleteHoverSegmentIdsEqual(nextIds) {
    const a = sectorMapAtcSectorDeleteHoverSegmentIds;
    if (a.length !== nextIds.length) return false;
    for (let i = 0; i < a.length; i++) {
        if (a[i] !== nextIds[i]) return false;
    }
    return true;
}

function getSectorMapAtcSectorDeleteHighlightIdSet() {
    if (!sectorMapAtcSectorDeleteActive) return null;
    const set = new Set();
    if (sectorMapAtcSectorDeleteBoxHoverId) {
        set.add(sectorMapAtcSectorDeleteBoxHoverId);
        return set;
    }
    if (sectorMapAtcSectorDeleteDisambigVisible && sectorMapAtcSectorDeleteDisambigIds.length) {
        sectorMapAtcSectorDeleteDisambigIds.forEach(id => set.add(id));
        return set;
    }
    sectorMapAtcSectorDeleteHoverSegmentIds.forEach(id => set.add(id));
    return set;
}

function getSectorMapRouteDeleteHighlightIdSet() {
    if (!sectorMapRouteDeleteActive) return null;
    const set = new Set();
    if (sectorMapRouteDeleteBoxHoverRouteId) {
        set.add(sectorMapRouteDeleteBoxHoverRouteId);
        return set;
    }
    if (sectorMapRouteDeleteDisambigVisible && sectorMapRouteDeleteDisambigRouteIds.length) {
        sectorMapRouteDeleteDisambigRouteIds.forEach(id => set.add(id));
        return set;
    }
    sectorMapRouteDeleteHoverSegmentRouteIds.forEach(id => set.add(id));
    return set;
}

function sectorMapRouteEditPickHoverSegmentIdsEqual(nextIds) {
    const a = sectorMapRouteEditPickHoverSegmentRouteIds;
    if (a.length !== nextIds.length) return false;
    for (let i = 0; i < a.length; i++) {
        if (a[i] !== nextIds[i]) return false;
    }
    return true;
}

function getSectorMapRouteEditSelectHighlightIdSet() {
    if (!sectorMapRouteEditActive || sectorMapRouteEditTargetRouteId) return null;
    const set = new Set();
    if (sectorMapRouteEditPickBoxHoverRouteId) {
        set.add(sectorMapRouteEditPickBoxHoverRouteId);
        return set;
    }
    if (sectorMapRouteEditPickDisambigVisible && sectorMapRouteEditPickDisambigRouteIds.length) {
        sectorMapRouteEditPickDisambigRouteIds.forEach(id => set.add(id));
        return set;
    }
    sectorMapRouteEditPickHoverSegmentRouteIds.forEach(id => set.add(id));
    return set;
}

/** Segment index i for draftIds[i]–draftIds[i+1] nearest to canvas pixel, or -1. */
function findDraftSegmentIndexNearCanvasPixel(canvasX, canvasY, draftIds, thresholdPx) {
    if (!canvas || !draftIds || draftIds.length < 2 || !isFinite(canvasX) || !isFinite(canvasY)) return -1;
    updateCentreWaypoint();
    const { ox: effectiveOriginX, oy: effectiveOriginY } = getSectorCanvasEffectiveOriginPx();
    if (!isFinite(zoomLevel) || zoomLevel <= 0) return -1;
    const sectorLonScale = getSectorMapLonCosScale();
    const thrSq = thresholdPx * thresholdPx;
    let bestI = -1;
    let bestD = Infinity;
    for (let i = 0; i < draftIds.length - 1; i++) {
        const wa = findSectorRouteFixById(draftIds[i]);
        const wb = findSectorRouteFixById(draftIds[i + 1]);
        if (!wa || !wb || typeof wa.latitude !== 'number' || typeof wb.latitude !== 'number') continue;
        let relA = wa.longitude;
        let latA = wa.latitude;
        let relB = wb.longitude;
        let latB = wb.latitude;
        if (centreWaypoint && isFinite(centreWaypoint.latitude) && isFinite(centreWaypoint.longitude)) {
            relA = wa.longitude - centreWaypoint.longitude;
            latA = wa.latitude - centreWaypoint.latitude;
            relB = wb.longitude - centreWaypoint.longitude;
            latB = wb.latitude - centreWaypoint.latitude;
        }
        const x1 = effectiveOriginX + relA * zoomLevel * sectorLonScale;
        const y1 = effectiveOriginY - latA * zoomLevel;
        const x2 = effectiveOriginX + relB * zoomLevel * sectorLonScale;
        const y2 = effectiveOriginY - latB * zoomLevel;
        if (![x1, y1, x2, y2].every(isFinite)) continue;
        const d = distanceSquaredPointToSegment(canvasX, canvasY, x1, y1, x2, y2);
        if (d < bestD) {
            bestD = d;
            bestI = i;
        }
    }
    if (bestI < 0 || bestD > thrSq) return -1;
    return bestI;
}

function eventToSectorCanvasPixel(e) {
    if (!canvas) return null;
    const rect = canvas.getBoundingClientRect();
    if (!rect.width || !rect.height) return null;
    const sx = canvas.width / rect.width;
    const sy = canvas.height / rect.height;
    return {
        x: (e.clientX - rect.left) * sx,
        y: (e.clientY - rect.top) * sy
    };
}

function canvasPixelToSectorLatLon(canvasX, canvasY) {
    updateCentreWaypoint();
    const { ox, oy } = getSectorCanvasEffectiveOriginPx();
    const sectorLonScale = getSectorMapLonCosScale();
    const relLon = (canvasX - ox) / (zoomLevel * sectorLonScale);
    const relLat = (oy - canvasY) / zoomLevel;
    if (centreWaypoint && typeof centreWaypoint.latitude === 'number' && typeof centreWaypoint.longitude === 'number') {
        return {
            latitude: relLat + centreWaypoint.latitude,
            longitude: relLon + centreWaypoint.longitude
        };
    }
    return { latitude: relLat, longitude: relLon };
}

/** Map geographic coordinates to Edit Airspace canvas pixels (inverse of canvasPixelToSectorLatLon). */
function sectorLatLonToCanvasPixel(latitude, longitude) {
    if (!canvas || typeof latitude !== 'number' || typeof longitude !== 'number' ||
        !isFinite(latitude) || !isFinite(longitude)) return null;
    updateCentreWaypoint();
    const { ox: effectiveOriginX, oy: effectiveOriginY } = getSectorCanvasEffectiveOriginPx();
    if (!isFinite(zoomLevel) || zoomLevel <= 0) return null;
    const sectorLonScale = getSectorMapLonCosScale();
    let relLon = longitude;
    let relLat = latitude;
    if (centreWaypoint && typeof centreWaypoint.latitude === 'number' && typeof centreWaypoint.longitude === 'number' &&
        isFinite(centreWaypoint.latitude) && isFinite(centreWaypoint.longitude)) {
        relLon = longitude - centreWaypoint.longitude;
        relLat = latitude - centreWaypoint.latitude;
    }
    const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
    const y = effectiveOriginY - relLat * zoomLevel;
    if (!isFinite(x) || !isFinite(y)) return null;
    return { x, y };
}

/**
 * Session-only calibrated rasters for Edit Airspace map (not persisted). Drawn in order (first = bottom).
 * Four-point layers use a homography (projective) warp; legacy two-point layers use similarity transform.
 * @type {Array<{ blobUrl: string, image: HTMLImageElement, ix1: number, iy1: number, lat1: number, lon1: number, ix2: number, iy2: number, lat2: number, lon2: number, ix3?: number, iy3?: number, lat3?: number, lon3?: number, ix4?: number, iy4?: number, lat4?: number, lon4?: number, naturalWidth: number, naturalHeight: number, pictureName?: string, _samplePixels?: ImageData, _sampleCw?: number, _sampleCh?: number }>}
 */
let sectorMapSessionBackgroundLayers = [];
/** Index pending confirmation in {@link sectorMapBackgroundConfirmDeleteOneModal}. */
let pendingDeleteBackgroundIndex = null;
/**0–1 multiplier applied to all background layers when drawing. */
let sectorMapBackgroundsOpacity = 1;
let sectorMapBackgroundWizardObjectUrl = null;
/** When editing an existing layer, index in {@link sectorMapSessionBackgroundLayers}; null when adding. */
let sectorMapBackgroundWizardEditIndex = null;
/** Blob URL of the layer being edited; do not revoke on cancel if the user did not replace the file. */
let sectorMapBackgroundWizardEditOriginalBlobUrl = null;
/** Original filename from the file input, or carried from the layer when editing. */
let sectorMapBackgroundWizardChosenFileName = null;
/**
 * Linear flow: pick1→coords1→pick2→coords2→pick3→coords3→pick4→coords4 for new images.
 * When false (upgrading a legacy 2-point layer), all markers are shown and host clicks do not place points.
 */
let sectorMapBackgroundWizardLinearFlow = true;
/** @type {'idle'|'pick1'|'coords1'|'pick2'|'coords2'|'pick3'|'coords3'|'pick4'|'coords4'} */
let sectorMapBackgroundWizardStep = 'idle';
let sectorMapBackgroundIx1 = 0;
let sectorMapBackgroundIy1 = 0;
let sectorMapBackgroundIx2 = 0;
let sectorMapBackgroundIy2 = 0;
let sectorMapBackgroundIx3 = 0;
let sectorMapBackgroundIy3 = 0;
let sectorMapBackgroundIx4 = 0;
let sectorMapBackgroundIy4 = 0;

/** Add Background preview: pan/zoom in modal (not persisted). */
let sectorMapBgPanX = 0;
let sectorMapBgPanY = 0;
let sectorMapBgZoom = 1;
let sectorMapBgMiddlePanning = false;
let sectorMapBgPanStartX = 0;
let sectorMapBgPanStartY = 0;
let sectorMapBgPanGrabX = 0;
let sectorMapBgPanGrabY = 0;
let sectorMapBgMiddleDragMoved = false;
/** @type {{ el: HTMLElement, pointerId: number } | null} */
let sectorMapBgCalibMarkerDrag = null;

function sectorMapBackgroundCalibHostCenter() {
    const host = document.getElementById('sectorMapBackgroundImgHost');
    if (!host) return null;
    const HW = host.clientWidth;
    const HH = host.clientHeight;
    if (HW <= 0 || HH <= 0) return null;
    return { cx: HW / 2, cy: HH / 2 };
}

function sectorMapBackgroundApplyPreviewPanZoom() {
    const el = document.getElementById('sectorMapBackgroundPanZoom');
    if (!el) return;
    el.style.transform = `translate(${sectorMapBgPanX}px, ${sectorMapBgPanY}px) scale(${sectorMapBgZoom})`;
}

function sectorMapBackgroundResetPreviewPanZoom() {
    sectorMapBgPanX = 0;
    sectorMapBgPanY = 0;
    sectorMapBgZoom = 1;
    sectorMapBgMiddlePanning = false;
    sectorMapBgMiddleDragMoved = false;
    sectorMapBgCalibMarkerDrag = null;
    sectorMapBackgroundApplyPreviewPanZoom();
}

function sectorMapBackgroundRefreshCalibMarkers() {
    const host = document.getElementById('sectorMapBackgroundImgHost');
    const m1 = document.getElementById('sectorMapBgMarker1');
    const m2 = document.getElementById('sectorMapBgMarker2');
    const m3 = document.getElementById('sectorMapBgMarker3');
    const m4 = document.getElementById('sectorMapBgMarker4');
    if (!host) return;
    if (m1 && m1.style.display !== 'none') {
        positionSectorMapBackgroundMarker(host, sectorMapBackgroundIx1, sectorMapBackgroundIy1, m1);
    }
    if (m2 && m2.style.display !== 'none') {
        positionSectorMapBackgroundMarker(host, sectorMapBackgroundIx2, sectorMapBackgroundIy2, m2);
    }
    if (m3 && m3.style.display !== 'none') {
        positionSectorMapBackgroundMarker(host, sectorMapBackgroundIx3, sectorMapBackgroundIy3, m3);
    }
    if (m4 && m4.style.display !== 'none') {
        positionSectorMapBackgroundMarker(host, sectorMapBackgroundIx4, sectorMapBackgroundIy4, m4);
    }
}

function sectorMapBackgroundOnCalibWheel(e) {
    if (!sectorMapBackgroundWizardObjectUrl) return;
    const host = document.getElementById('sectorMapBackgroundImgHost');
    const img = document.getElementById('sectorMapBackgroundCalibImg');
    if (!host || !img || !img.naturalWidth || !host.contains(e.target)) return;
    const ctr = sectorMapBackgroundCalibHostCenter();
    if (!ctr) return;
    e.preventDefault();
    const rect = host.getBoundingClientRect();
    const sx = e.clientX - rect.left;
    const sy = e.clientY - rect.top;
    const oldZ = sectorMapBgZoom;
    const step = e.deltaY < 0 ? 1.12 : 1 / 1.12;
    const newZ = Math.max(1, Math.min(10, oldZ * step));
    if (Math.abs(newZ - oldZ) < 1e-6) return;
    const hx = (sx - sectorMapBgPanX - ctr.cx) / oldZ + ctr.cx;
    const hy = (sy - sectorMapBgPanY - ctr.cy) / oldZ + ctr.cy;
    sectorMapBgZoom = newZ;
    sectorMapBgPanX = sx - (hx - ctr.cx) * newZ - ctr.cx;
    sectorMapBgPanY = sy - (hy - ctr.cy) * newZ - ctr.cy;
    sectorMapBackgroundApplyPreviewPanZoom();
    sectorMapBackgroundRefreshCalibMarkers();
}

function sectorMapBackgroundOnCalibMouseMove(e) {
    if (!sectorMapBgMiddlePanning) return;
    const dx = e.clientX - sectorMapBgPanStartX;
    const dy = e.clientY - sectorMapBgPanStartY;
    if (Math.hypot(dx, dy) > 2) sectorMapBgMiddleDragMoved = true;
    sectorMapBgPanX = sectorMapBgPanGrabX + dx;
    sectorMapBgPanY = sectorMapBgPanGrabY + dy;
    sectorMapBackgroundApplyPreviewPanZoom();
    sectorMapBackgroundRefreshCalibMarkers();
}

function sectorMapBackgroundOnCalibMouseUp(e) {
    if (!sectorMapBgMiddlePanning) return;
    if (e.button !== 1) return;
    sectorMapBgMiddlePanning = false;
    sectorMapBgMiddleDragMoved = false;
}

function sectorMapBackgroundOnCalibHostClick(ev) {
    if (!sectorMapBackgroundWizardLinearFlow) return;
    if (!sectorMapBackgroundWizardObjectUrl) return;
    if (ev.button != null && ev.button > 0) return;
    if (ev.target.closest('.sector-map-bg-calib-marker')) return;
    const pt = sectorMapBackgroundEventToNaturalImageXY(ev.clientX, ev.clientY);
    if (!pt) return;
    const host = document.getElementById('sectorMapBackgroundImgHost');
    const m1 = document.getElementById('sectorMapBgMarker1');
    const m2 = document.getElementById('sectorMapBgMarker2');
    const m3 = document.getElementById('sectorMapBgMarker3');
    const m4 = document.getElementById('sectorMapBgMarker4');
    const hint = document.getElementById('sectorMapBackgroundCalibHint');
    if (sectorMapBackgroundWizardStep === 'pick1') {
        sectorMapBackgroundIx1 = pt.ix;
        sectorMapBackgroundIy1 = pt.iy;
        if (m1 && host) positionSectorMapBackgroundMarker(host, pt.ix, pt.iy, m1);
        sectorMapBackgroundWizardStep = 'coords1';
        const b1 = document.getElementById('sectorMapBackgroundCoordBlock1');
        if (b1) b1.style.display = 'block';
        if (hint) {
            hint.textContent =
                'Enter point 1: latitude DDMMSS+N/S, longitude DDDMMSS+E/W (no spaces). Then pick point 2 on the image.';
        }
    } else if (sectorMapBackgroundWizardStep === 'pick2') {
        sectorMapBackgroundIx2 = pt.ix;
        sectorMapBackgroundIy2 = pt.iy;
        if (m2 && host) positionSectorMapBackgroundMarker(host, pt.ix, pt.iy, m2);
        sectorMapBackgroundWizardStep = 'coords2';
        const b2 = document.getElementById('sectorMapBackgroundCoordBlock2');
        if (b2) b2.style.display = 'block';
        if (hint) {
            hint.textContent =
                'Enter point 2 the same way. Then pick point 3 along the edge (e.g. clockwise around the map).';
        }
        sectorMapBackgroundWizardRefreshAddEnabled();
    } else if (sectorMapBackgroundWizardStep === 'pick3') {
        sectorMapBackgroundIx3 = pt.ix;
        sectorMapBackgroundIy3 = pt.iy;
        if (m3 && host) positionSectorMapBackgroundMarker(host, pt.ix, pt.iy, m3);
        sectorMapBackgroundWizardStep = 'coords3';
        const b3 = document.getElementById('sectorMapBackgroundCoordBlock3');
        if (b3) b3.style.display = 'block';
        if (hint) hint.textContent = 'Enter point 3 coordinates, then pick point 4 on the image.';
        sectorMapBackgroundWizardRefreshAddEnabled();
    } else if (sectorMapBackgroundWizardStep === 'pick4') {
        sectorMapBackgroundIx4 = pt.ix;
        sectorMapBackgroundIy4 = pt.iy;
        if (m4 && host) positionSectorMapBackgroundMarker(host, pt.ix, pt.iy, m4);
        sectorMapBackgroundWizardStep = 'coords4';
        const b4 = document.getElementById('sectorMapBackgroundCoordBlock4');
        if (b4) b4.style.display = 'block';
        if (hint) hint.textContent = 'Enter point 4 coordinates, then click ADD to map.';
        sectorMapBackgroundWizardRefreshAddEnabled();
    }
}

function sectorMapBackgroundOnCalibMarkerPointerDown(e) {
    if (e.button !== 0) return;
    if (!sectorMapBackgroundWizardObjectUrl) return;
    const t = e.currentTarget;
    if (t.style.display === 'none') return;
    e.stopPropagation();
    try { t.setPointerCapture(e.pointerId); } catch (err) {}
    t.classList.add('sector-map-bg-calib-marker-dragging');
    sectorMapBgCalibMarkerDrag = { el: t, pointerId: e.pointerId };
}

function sectorMapBackgroundOnCalibMarkerPointerMove(e) {
    const d = sectorMapBgCalibMarkerDrag;
    if (!d || !d.el) return;
    if (e.pointerId !== d.pointerId) return;
    const pt = sectorMapBackgroundEventToNaturalImageXYClamped(e.clientX, e.clientY);
    if (!pt) return;
    const img = document.getElementById('sectorMapBackgroundCalibImg');
    const host = document.getElementById('sectorMapBackgroundImgHost');
    if (!img || !host) return;
    const ix = pt.ix;
    const iy = pt.iy;
    if (d.el.id === 'sectorMapBgMarker1') {
        sectorMapBackgroundIx1 = ix;
        sectorMapBackgroundIy1 = iy;
        positionSectorMapBackgroundMarker(host, ix, iy, d.el);
    } else if (d.el.id === 'sectorMapBgMarker2') {
        sectorMapBackgroundIx2 = ix;
        sectorMapBackgroundIy2 = iy;
        positionSectorMapBackgroundMarker(host, ix, iy, d.el);
    } else if (d.el.id === 'sectorMapBgMarker3') {
        sectorMapBackgroundIx3 = ix;
        sectorMapBackgroundIy3 = iy;
        positionSectorMapBackgroundMarker(host, ix, iy, d.el);
    } else if (d.el.id === 'sectorMapBgMarker4') {
        sectorMapBackgroundIx4 = ix;
        sectorMapBackgroundIy4 = iy;
        positionSectorMapBackgroundMarker(host, ix, iy, d.el);
    }
    sectorMapBackgroundWizardOnCoordInput();
}

function sectorMapBackgroundOnCalibMarkerPointerUp(e) {
    const d = sectorMapBgCalibMarkerDrag;
    if (!d || !d.el) return;
    if (e.pointerId !== d.pointerId) return;
    try { d.el.releasePointerCapture(e.pointerId); } catch (err2) {}
    d.el.classList.remove('sector-map-bg-calib-marker-dragging');
    sectorMapBgCalibMarkerDrag = null;
}

function sectorMapBackgroundBindCalibMarkerDragTargets() {
    ['sectorMapBgMarker1', 'sectorMapBgMarker2', 'sectorMapBgMarker3', 'sectorMapBgMarker4'].forEach(id => {
        const el = document.getElementById(id);
        if (!el || el.dataset.sectorMapBgDragBound === '1') return;
        el.dataset.sectorMapBgDragBound = '1';
        el.addEventListener('pointerdown', sectorMapBackgroundOnCalibMarkerPointerDown);
        el.addEventListener('click', function(ev) {
            ev.stopPropagation();
        });
    });
}

function ensureSectorMapBackgroundPanZoomListeners() {
    const host = document.getElementById('sectorMapBackgroundImgHost');
    if (!host || host.dataset.sectorMapBgPanZoomBound === '1') return;
    host.dataset.sectorMapBgPanZoomBound = '1';
    host.addEventListener('wheel', sectorMapBackgroundOnCalibWheel, { passive: false });
    host.addEventListener('click', sectorMapBackgroundOnCalibHostClick);
    host.addEventListener('mousedown', function(e) {
        if (e.button !== 1) return;
        if (!sectorMapBackgroundWizardObjectUrl) return;
        e.preventDefault();
        sectorMapBgMiddlePanning = true;
        sectorMapBgPanStartX = e.clientX;
        sectorMapBgPanStartY = e.clientY;
        sectorMapBgPanGrabX = sectorMapBgPanX;
        sectorMapBgPanGrabY = sectorMapBgPanY;
        sectorMapBgMiddleDragMoved = false;
    });
    document.addEventListener('mousemove', sectorMapBackgroundOnCalibMouseMove);
    document.addEventListener('mouseup', sectorMapBackgroundOnCalibMouseUp);
    document.addEventListener('pointermove', sectorMapBackgroundOnCalibMarkerPointerMove);
    document.addEventListener('pointerup', sectorMapBackgroundOnCalibMarkerPointerUp);
    document.addEventListener('pointercancel', sectorMapBackgroundOnCalibMarkerPointerUp);
    sectorMapBackgroundBindCalibMarkerDragTargets();
}

function sectorMapBackgroundRemoveLayerAt(index) {
    if (index < 0 || index >= sectorMapSessionBackgroundLayers.length) return;
    const layer = sectorMapSessionBackgroundLayers[index];
    if (layer && layer.blobUrl) {
        try { URL.revokeObjectURL(layer.blobUrl); } catch (e) {}
    }
    sectorMapSessionBackgroundLayers.splice(index, 1);
    syncSectorMapBgOpacityControlVisibility();
    try { drawCanvas(); } catch (e) {}
}

/** BG opacity strip in Edit Airspace: only while at least one session background exists. */
function syncSectorMapBgOpacityControlVisibility() {
    const el = document.getElementById('sectorMapBgOpacityControl');
    if (!el) return;
    const show = Array.isArray(sectorMapSessionBackgroundLayers) && sectorMapSessionBackgroundLayers.length > 0;
    el.style.display = show ? 'inline-flex' : 'none';
    el.setAttribute('aria-hidden', show ? 'false' : 'true');
}

function clearSectorMapSessionBackground() {
    sectorMapSessionBackgroundLayers.forEach(layer => {
        if (layer && layer.blobUrl) {
            try { URL.revokeObjectURL(layer.blobUrl); } catch (e) {}
        }
    });
    sectorMapSessionBackgroundLayers = [];
    sectorMapBackgroundsOpacity = 1;
    const opS = document.getElementById('sectorMapBackgroundsOpacitySlider');
    const opL = document.getElementById('sectorMapBackgroundsOpacityValue');
    if (opS) opS.value = '100';
    if (opL) opL.textContent = '100%';
    syncSectorMapBgOpacityControlVisibility();
    try { drawCanvas(); } catch (e) {}
}

/** Signed area ×2 for polygon vertices (shoelace). */
function sectorMapBackgroundPolygonSignedAreaXY(pts) {
    if (!pts || pts.length < 3) return 0;
    let s = 0;
    const n = pts.length;
    for (let i = 0; i < n; i++) {
        const j = (i + 1) % n;
        s += pts[i].x * pts[j].y - pts[j].x * pts[i].y;
    }
    return s / 2;
}

function solveSectorMapBackgroundLinearSystem8(Arows, bvec) {
    const n = 8;
    const M = Arows.map((row, ri) => [...row, bvec[ri]]);
    for (let col = 0; col < n; col++) {
        let piv = col;
        let best = Math.abs(M[piv][col]);
        for (let r = col + 1; r < n; r++) {
            const v = Math.abs(M[r][col]);
            if (v > best) {
                best = v;
                piv = r;
            }
        }
        if (best < 1e-14) return null;
        if (piv !== col) {
            const tmp = M[col];
            M[col] = M[piv];
            M[piv] = tmp;
        }
        const div = M[col][col];
        for (let j = col; j <= n; j++) M[col][j] /= div;
        for (let r = 0; r < n; r++) {
            if (r === col) continue;
            const f = M[r][col];
            if (Math.abs(f) < 1e-15) continue;
            for (let j = col; j <= n; j++) M[r][j] -= f * M[col][j];
        }
    }
    return M.map(row => row[n]);
}

/**
 * Homography H maps image pixel (u,v,1) to canvas pixel homogeneous (x,y,w); x' = x/w, y' = y/w.
 * @param {{x:number,y:number}[]} srcPts image space
 * @param {{x:number,y:number}[]} dstPts canvas space
 * @returns {number[][]|null} 3×3 with H[2][2] === 1
 */
function computeSectorMapBackgroundHomographyImageToCanvas(srcPts, dstPts) {
    if (!srcPts || !dstPts || srcPts.length !== 4 || dstPts.length !== 4) return null;
    const A = [];
    const b = [];
    for (let i = 0; i < 4; i++) {
        const u = srcPts[i].x;
        const v = srcPts[i].y;
        const x = dstPts[i].x;
        const y = dstPts[i].y;
        A.push([u, v, 1, 0, 0, 0, -u * x, -v * x]);
        b.push(x);
        A.push([0, 0, 0, u, v, 1, -u * y, -v * y]);
        b.push(y);
    }
    const sol = solveSectorMapBackgroundLinearSystem8(A, b);
    if (!sol) return null;
    return [
        [sol[0], sol[1], sol[2]],
        [sol[3], sol[4], sol[5]],
        [sol[6], sol[7], 1]
    ];
}

function invertSectorMapBackground3x3(M3) {
    const a = M3[0][0];
    const b = M3[0][1];
    const c = M3[0][2];
    const d = M3[1][0];
    const e = M3[1][1];
    const f = M3[1][2];
    const g = M3[2][0];
    const h = M3[2][1];
    const i = M3[2][2];
    const det =
        a * (e * i - f * h) -
        b * (d * i - f * g) +
        c * (d * h - e * g);
    if (!isFinite(det) || Math.abs(det) < 1e-14) return null;
    const invDet = 1 / det;
    return [
        [(e * i - f * h) * invDet, (c * h - b * i) * invDet, (b * f - c * e) * invDet],
        [(f * g - d * i) * invDet, (a * i - c * g) * invDet, (c * d - a * f) * invDet],
        [(d * h - e * g) * invDet, (b * g - a * h) * invDet, (a * e - b * d) * invDet]
    ];
}

function sectorMapBackgroundApplyHomographyForward(H, u, v) {
    const x = H[0][0] * u + H[0][1] * v + H[0][2];
    const y = H[1][0] * u + H[1][1] * v + H[1][2];
    const w = H[2][0] * u + H[2][1] * v + H[2][2];
    if (!isFinite(w) || Math.abs(w) < 1e-12) return null;
    return { x: x / w, y: y / w };
}

function sectorMapBackgroundApplyHomographyInverse(invH, cx, cy) {
    const x = invH[0][0] * cx + invH[0][1] * cy + invH[0][2];
    const y = invH[1][0] * cx + invH[1][1] * cy + invH[1][2];
    const w = invH[2][0] * cx + invH[2][1] * cy + invH[2][2];
    if (!isFinite(w) || Math.abs(w) < 1e-12) return null;
    return { u: x / w, v: y / w };
}

function sectorMapBackgroundEnsureImagePixels(bg, im) {
    const cw = im.naturalWidth;
    const ch = im.naturalHeight;
    if (bg._samplePixels && bg._sampleCw === cw && bg._sampleCh === ch) return bg._samplePixels;
    try {
        const oc = document.createElement('canvas');
        oc.width = cw;
        oc.height = ch;
        const octx = oc.getContext('2d');
        if (!octx) return null;
        octx.drawImage(im, 0, 0);
        const pix = octx.getImageData(0, 0, cw, ch);
        bg._samplePixels = pix;
        bg._sampleCw = cw;
        bg._sampleCh = ch;
        return pix;
    } catch (e) {
        return null;
    }
}

function sectorMapBackgroundBilinearRGBA(pix, cw, ch, u, v) {
    if (!pix || !pix.data || cw <= 1 || ch <= 1) return null;
    const x0 = Math.floor(u);
    const y0 = Math.floor(v);
    const x1 = Math.min(cw - 1, x0 + 1);
    const y1 = Math.min(ch - 1, y0 + 1);
    const fx = u - x0;
    const fy = v - y0;
    const idx = (x, y) => (y * cw + x) * 4;
    const i00 = idx(x0, y0);
    const i10 = idx(x1, y0);
    const i01 = idx(x0, y1);
    const i11 = idx(x1, y1);
    const d = pix.data;
    const r =
        d[i00] * (1 - fx) * (1 - fy) +
        d[i10] * fx * (1 - fy) +
        d[i01] * (1 - fx) * fy +
        d[i11] * fx * fy;
    const g =
        d[i00 + 1] * (1 - fx) * (1 - fy) +
        d[i10 + 1] * fx * (1 - fy) +
        d[i01 + 1] * (1 - fx) * fy +
        d[i11 + 1] * fx * fy;
    const b =
        d[i00 + 2] * (1 - fx) * (1 - fy) +
        d[i10 + 2] * fx * (1 - fy) +
        d[i01 + 2] * (1 - fx) * fy +
        d[i11 + 2] * fx * fy;
    const a =
        d[i00 + 3] * (1 - fx) * (1 - fy) +
        d[i10 + 3] * fx * (1 - fy) +
        d[i01 + 3] * (1 - fx) * fy +
        d[i11 + 3] * fx * fy;
    return { r, g, b, a };
}

function sectorMapBackgroundHomographyCanvasBBox(H, iw, ih, canvasW, canvasH) {
    const corners = [[0, 0], [iw, 0], [iw, ih], [0, ih]];
    let minX = Infinity;
    let minY = Infinity;
    let maxX = -Infinity;
    let maxY = -Infinity;
    for (let i = 0; i < corners.length; i++) {
        const p = sectorMapBackgroundApplyHomographyForward(H, corners[i][0], corners[i][1]);
        if (!p || !isFinite(p.x) || !isFinite(p.y)) continue;
        minX = Math.min(minX, p.x);
        maxX = Math.max(maxX, p.x);
        minY = Math.min(minY, p.y);
        maxY = Math.max(maxY, p.y);
    }
    if (!isFinite(minX) || !isFinite(maxX)) return null;
    const pad = 2;
    let x0 = Math.floor(minX - pad);
    let y0 = Math.floor(minY - pad);
    let x1 = Math.ceil(maxX + pad);
    let y1 = Math.ceil(maxY + pad);
    x0 = Math.max(0, x0);
    y0 = Math.max(0, y0);
    x1 = Math.min(canvasW, x1);
    y1 = Math.min(canvasH, y1);
    if (x1 <= x0 || y1 <= y0) return null;
    return { x0, y0, x1, y1 };
}

function drawSectorMapSessionBackgroundLayerHomographyWithDstPts(ctx, canvasW, canvasH, bg, im, alpha, dstPts) {
    const iw = bg.naturalWidth || im.naturalWidth;
    const ih = bg.naturalHeight || im.naturalHeight;
    const srcPts = [
        { x: bg.ix1, y: bg.iy1 },
        { x: bg.ix2, y: bg.iy2 },
        { x: bg.ix3, y: bg.iy3 },
        { x: bg.ix4, y: bg.iy4 }
    ];
    if (!dstPts || !dstPts[0] || !dstPts[1] || !dstPts[2] || !dstPts[3]) return;
    const H = computeSectorMapBackgroundHomographyImageToCanvas(srcPts, dstPts);
    if (!H) return;
    const invH = invertSectorMapBackground3x3(H);
    if (!invH) return;
    const bbox = sectorMapBackgroundHomographyCanvasBBox(H, iw, ih, canvasW, canvasH);
    if (!bbox) return;
    const pixIn = sectorMapBackgroundEnsureImagePixels(bg, im);
    if (!pixIn) return;
    const bw = bbox.x1 - bbox.x0;
    const bh = bbox.y1 - bbox.y0;
    const out = ctx.createImageData(bw, bh);
    const od = out.data;
    const ca = Math.max(0, Math.min(1, alpha));
    let wrote = false;
    for (let py = 0; py < bh; py++) {
        for (let px = 0; px < bw; px++) {
            const cx = bbox.x0 + px + 0.5;
            const cy = bbox.y0 + py + 0.5;
            const uv = sectorMapBackgroundApplyHomographyInverse(invH, cx, cy);
            const di = (py * bw + px) * 4;
            if (!uv || !isFinite(uv.u) || !isFinite(uv.v)) {
                od[di + 3] = 0;
                continue;
            }
            if (uv.u < -0.5 || uv.v < -0.5 || uv.u > iw - 0.5 || uv.v > ih - 0.5) {
                od[di + 3] = 0;
                continue;
            }
            const rgba = sectorMapBackgroundBilinearRGBA(pixIn, iw, ih, uv.u, uv.v);
            if (!rgba) {
                od[di + 3] = 0;
                continue;
            }
            od[di] = rgba.r;
            od[di + 1] = rgba.g;
            od[di + 2] = rgba.b;
            od[di + 3] = rgba.a * ca;
            if (rgba.a * ca > 1e-6) wrote = true;
        }
    }
    if (!wrote) return;
    try {
        const tmp = document.createElement('canvas');
        tmp.width = canvasW;
        tmp.height = canvasH;
        const tctx = tmp.getContext('2d');
        if (!tctx) return;
        tctx.putImageData(out, bbox.x0, bbox.y0);
        ctx.save();
        ctx.globalAlpha = 1;
        ctx.drawImage(tmp, 0, 0);
        ctx.restore();
    } catch (e) {
        /* ignore */
    }
}

function drawSectorMapSessionBackgroundLayerHomography(ctx, canvasEl, bg, im, alpha) {
    const dstPts = [
        sectorLatLonToCanvasPixel(bg.lat1, bg.lon1),
        sectorLatLonToCanvasPixel(bg.lat2, bg.lon2),
        sectorLatLonToCanvasPixel(bg.lat3, bg.lon3),
        sectorLatLonToCanvasPixel(bg.lat4, bg.lon4)
    ];
    drawSectorMapSessionBackgroundLayerHomographyWithDstPts(ctx, canvasEl.width, canvasEl.height, bg, im, alpha, dstPts);
}

function drawSectorMapSessionBackgroundLayerSimilarity(ctx, bg, im, alpha, c1, c2) {
    const vix = bg.ix2 - bg.ix1;
    const viy = bg.iy2 - bg.iy1;
    const vcx = c2.x - c1.x;
    const vcy = c2.y - c1.y;
    const lenI = Math.hypot(vix, viy);
    const lenC = Math.hypot(vcx, vcy);
    if (lenI < 1e-6 || lenC < 1e-6) return;
    const s = lenC / lenI;
    const angI = Math.atan2(viy, vix);
    const angC = Math.atan2(vcy, vcx);
    const theta = angC - angI;
    const cos = Math.cos(theta);
    const sin = Math.sin(theta);
    const a = s * cos;
    const b = s * sin;
    const c = -s * sin;
    const d = s * cos;
    const tx = c1.x - (a * bg.ix1 + c * bg.iy1);
    const ty = c1.y - (b * bg.ix1 + d * bg.iy1);
    ctx.save();
    ctx.globalAlpha = alpha;
    try {
        ctx.setTransform(a, b, c, d, tx, ty);
        ctx.drawImage(im, 0, 0, bg.naturalWidth, bg.naturalHeight);
    } catch (e) {
        /* ignore draw errors (e.g. tainted) */
    }
    ctx.restore();
}

function drawSectorMapSessionBackgroundLayer() {
    if (!ctx || !canvas || !sectorMapSessionBackgroundLayers.length) return;
    const alpha = Math.max(0, Math.min(1, sectorMapBackgroundsOpacity));
    if (alpha <= 0) return;
    for (let i = 0; i < sectorMapSessionBackgroundLayers.length; i++) {
        const bg = sectorMapSessionBackgroundLayers[i];
        if (!bg || !bg.image) continue;
        const im = bg.image;
        if (!im.complete || !im.naturalWidth || !im.naturalHeight) continue;
        const useHomography =
            isFinite(bg.lat3) &&
            isFinite(bg.lon3) &&
            isFinite(bg.lat4) &&
            isFinite(bg.lon4) &&
            isFinite(bg.ix3) &&
            isFinite(bg.iy3) &&
            isFinite(bg.ix4) &&
            isFinite(bg.iy4);
        if (useHomography) {
            drawSectorMapSessionBackgroundLayerHomography(ctx, canvas, bg, im, alpha);
        } else {
            const c1 = sectorLatLonToCanvasPixel(bg.lat1, bg.lon1);
            const c2 = sectorLatLonToCanvasPixel(bg.lat2, bg.lon2);
            if (!c1 || !c2) continue;
            drawSectorMapSessionBackgroundLayerSimilarity(ctx, bg, im, alpha, c1, c2);
        }
    }
}

function sectorMapBackgroundGeoPairValid(lat, lon) {
    return isFinite(lat) && isFinite(lon) && lat >= -90 && lat <= 90 && lon >= -180 && lon <= 180;
}

function sectorMapBackgroundWizardParseFourGeoFromInputs() {
    const lat1 = parseLatitudeDMSegment(document.getElementById('sectorMapBgLat1')?.value);
    const lon1 = parseLongitudeDMSegment(document.getElementById('sectorMapBgLon1')?.value);
    const lat2 = parseLatitudeDMSegment(document.getElementById('sectorMapBgLat2')?.value);
    const lon2 = parseLongitudeDMSegment(document.getElementById('sectorMapBgLon2')?.value);
    const lat3 = parseLatitudeDMSegment(document.getElementById('sectorMapBgLat3')?.value);
    const lon3 = parseLongitudeDMSegment(document.getElementById('sectorMapBgLon3')?.value);
    const lat4 = parseLatitudeDMSegment(document.getElementById('sectorMapBgLat4')?.value);
    const lon4 = parseLongitudeDMSegment(document.getElementById('sectorMapBgLon4')?.value);
    return { lat1, lon1, lat2, lon2, lat3, lon3, lat4, lon4 };
}

function sectorMapBackgroundWizardFourGeoAllValid(g) {
    if (!g) return false;
    return (
        g.lat1 != null &&
        g.lon1 != null &&
        g.lat2 != null &&
        g.lon2 != null &&
        g.lat3 != null &&
        g.lon3 != null &&
        g.lat4 != null &&
        g.lon4 != null &&
        sectorMapBackgroundGeoPairValid(g.lat1, g.lon1) &&
        sectorMapBackgroundGeoPairValid(g.lat2, g.lon2) &&
        sectorMapBackgroundGeoPairValid(g.lat3, g.lon3) &&
        sectorMapBackgroundGeoPairValid(g.lat4, g.lon4)
    );
}

/** True if no two geographic control points coincide (approx). */
function sectorMapBackgroundWizardFourGeoDistinct(g) {
    if (!sectorMapBackgroundWizardFourGeoAllValid(g)) return false;
    const pts = [
        [g.lat1, g.lon1],
        [g.lat2, g.lon2],
        [g.lat3, g.lon3],
        [g.lat4, g.lon4]
    ];
    const eps = 1e-7;
    for (let i = 0; i < 4; i++) {
        for (let j = i + 1; j < 4; j++) {
            if (Math.hypot(pts[i][0] - pts[j][0], pts[i][1] - pts[j][1]) <= eps) return false;
        }
    }
    return true;
}

function sectorMapBackgroundWizardImageQuadPts() {
    return [
        { x: sectorMapBackgroundIx1, y: sectorMapBackgroundIy1 },
        { x: sectorMapBackgroundIx2, y: sectorMapBackgroundIy2 },
        { x: sectorMapBackgroundIx3, y: sectorMapBackgroundIy3 },
        { x: sectorMapBackgroundIx4, y: sectorMapBackgroundIy4 }
    ];
}

function sectorMapBackgroundWizardMinEdgeImagePts(ixy) {
    let m = Infinity;
    for (let i = 0; i < 4; i++) {
        const j = (i + 1) % 4;
        m = Math.min(m, Math.hypot(ixy[i].x - ixy[j].x, ixy[i].y - ixy[j].y));
    }
    return m;
}

/** Homography solvable and non-degenerate quads in image + canvas space. */
function sectorMapBackgroundWizardHomographyOk(ixyImg, g) {
    if (!ixyImg || ixyImg.length !== 4) return false;
    const ai = Math.abs(sectorMapBackgroundPolygonSignedAreaXY(ixyImg));
    if (ai < 200 || !isFinite(ai)) return false;
    const dstPts = [
        sectorLatLonToCanvasPixel(g.lat1, g.lon1),
        sectorLatLonToCanvasPixel(g.lat2, g.lon2),
        sectorLatLonToCanvasPixel(g.lat3, g.lon3),
        sectorLatLonToCanvasPixel(g.lat4, g.lon4)
    ];
    if (!dstPts[0] || !dstPts[1] || !dstPts[2] || !dstPts[3]) return false;
    const ac = Math.abs(sectorMapBackgroundPolygonSignedAreaXY(dstPts));
    if (ac < 200 || !isFinite(ac)) return false;
    const H = computeSectorMapBackgroundHomographyImageToCanvas(ixyImg, dstPts);
    if (!H) return false;
    return !!invertSectorMapBackground3x3(H);
}

/**
 * Waypoints for the airspace being edited: live `waypoints` (Edit Airspace), else exercise sector, else saved sector.
 */
function sectorMapBackgroundGetWaypointsForLookup() {
    if (Array.isArray(waypoints) && waypoints.length) return waypoints;
    const wEx = currentEditingSector?.waypoints;
    if (Array.isArray(wEx) && wEx.length) return wEx;
    const sid = currentSectorId || currentEditingSectorId || currentEditingSector?.id;
    if (sid) {
        const sec = getSectors().find(s => s && s.id === sid);
        if (sec && Array.isArray(sec.waypoints) && sec.waypoints.length) return sec.waypoints;
    }
    return [];
}

/** Case-insensitive match on waypoint `name` in the current airspace. */
function sectorMapBackgroundFindWaypointByName(raw) {
    const q = (raw || '').trim();
    if (!q) return null;
    const qu = q.toUpperCase();
    const wpts = sectorMapBackgroundGetWaypointsForLookup();
    for (let i = 0; i < wpts.length; i++) {
        const w = wpts[i];
        if (!w || !isFinite(w.latitude) || !isFinite(w.longitude)) continue;
        const nm = (w.name || '').trim();
        if (!nm) continue;
        if (nm.toUpperCase() === qu) return w;
    }
    return null;
}

/**
 * @param {1|2|3|4} pointIndex
 * @param {'silent'|'user'} feedback — `user`: alert if empty / not found
 * @returns {boolean} true if coordinates were filled
 */
function sectorMapBackgroundApplyExistingWaypoint(pointIndex, feedback) {
    const silent = feedback !== 'user';
    const suf = String(pointIndex);
    const wpIn = document.getElementById('sectorMapBgExistingWp' + suf);
    const latIn = document.getElementById('sectorMapBgLat' + suf);
    const lonIn = document.getElementById('sectorMapBgLon' + suf);
    if (!wpIn || !latIn || !lonIn) return false;
    const raw = (wpIn.value || '').trim();
    if (!raw) {
        if (!silent) alert('Enter a waypoint name.');
        return false;
    }
    const w = sectorMapBackgroundFindWaypointByName(raw);
    if (!w) {
        if (!silent) alert('Waypoint doesn\'t exist.');
        return false;
    }
    latIn.value = formatDMS(decimalToDMS(w.latitude, true), true);
    lonIn.value = formatDMS(decimalToDMS(w.longitude, false), false);
    if (w.name) wpIn.value = w.name;
    sectorMapBackgroundWizardOnCoordInput();
    return true;
}

function sectorMapBackgroundResolveExistingWaypointFields() {
    sectorMapBackgroundApplyExistingWaypoint(1, 'silent');
    sectorMapBackgroundApplyExistingWaypoint(2, 'silent');
    sectorMapBackgroundApplyExistingWaypoint(3, 'silent');
    sectorMapBackgroundApplyExistingWaypoint(4, 'silent');
}

/** Map client pixel to natural image coordinates using preview pan/zoom state. */
/** Map viewport coordinates to natural image pixels using the rendered (transformed) bitmap bounds. */
function sectorMapBackgroundEventToNaturalImageXY(clientX, clientY) {
    const img = document.getElementById('sectorMapBackgroundCalibImg');
    if (!img || !img.naturalWidth) return null;
    const ir = img.getBoundingClientRect();
    if (ir.width <= 0 || ir.height <= 0) return null;
    const ix = (clientX - ir.left) * img.naturalWidth / ir.width;
    const iy = (clientY - ir.top) * img.naturalHeight / ir.height;
    if (!isFinite(ix) || !isFinite(iy)) return null;
    if (ix < 0 || iy < 0 || ix > img.naturalWidth || iy > img.naturalHeight) return null;
    return { ix, iy };
}

/** Same as {@link sectorMapBackgroundEventToNaturalImageXY} but clamps to the image edge (for marker drag). */
function sectorMapBackgroundEventToNaturalImageXYClamped(clientX, clientY) {
    const img = document.getElementById('sectorMapBackgroundCalibImg');
    if (!img || !img.naturalWidth) return null;
    const ir = img.getBoundingClientRect();
    if (ir.width <= 0 || ir.height <= 0) return null;
    const px = Math.max(ir.left, Math.min(ir.right, clientX));
    const py = Math.max(ir.top, Math.min(ir.bottom, clientY));
    const ix = (px - ir.left) * img.naturalWidth / ir.width;
    const iy = (py - ir.top) * img.naturalHeight / ir.height;
    if (!isFinite(ix) || !isFinite(iy)) return null;
    return {
        ix: Math.max(0, Math.min(img.naturalWidth, ix)),
        iy: Math.max(0, Math.min(img.naturalHeight, iy))
    };
}

function positionSectorMapBackgroundMarker(hostEl, ix, iy, markerEl) {
    const host = hostEl;
    const img = document.getElementById('sectorMapBackgroundCalibImg');
    if (!host || !img || !markerEl || !img.naturalWidth) return;
    const hr = host.getBoundingClientRect();
    const ir = img.getBoundingClientRect();
    if (ir.width <= 0 || ir.height <= 0) return;
    const fx = ix / img.naturalWidth;
    const fy = iy / img.naturalHeight;
    const clientX = ir.left + fx * ir.width;
    const clientY = ir.top + fy * ir.height;
    markerEl.style.left = `${clientX - hr.left}px`;
    markerEl.style.top = `${clientY - hr.top}px`;
    markerEl.style.display = 'block';
}

function resetSectorMapBackgroundWizard(opts) {
    const revoke = opts && opts.revokePendingUrl;
    if (revoke && sectorMapBackgroundWizardObjectUrl) {
        const orig = sectorMapBackgroundWizardEditOriginalBlobUrl;
        const cur = sectorMapBackgroundWizardObjectUrl;
        if (!orig || cur !== orig) {
            try { URL.revokeObjectURL(cur); } catch (e) {}
        }
    }
    if (revoke) sectorMapBackgroundWizardObjectUrl = null;
    sectorMapBackgroundWizardEditIndex = null;
    sectorMapBackgroundWizardEditOriginalBlobUrl = null;
    sectorMapBackgroundWizardChosenFileName = null;
    sectorMapBackgroundWizardStep = 'idle';
    sectorMapBackgroundWizardLinearFlow = true;
    const fi = document.getElementById('sectorMapBackgroundFileInput');
    if (fi) fi.value = '';
    const panel = document.getElementById('sectorMapBackgroundCalibPanel');
    if (panel) panel.style.display = 'none';
    const hint = document.getElementById('sectorMapBackgroundCalibHint');
    if (hint) hint.textContent = '';
    const img = document.getElementById('sectorMapBackgroundCalibImg');
    if (img) img.removeAttribute('src');
    const m1 = document.getElementById('sectorMapBgMarker1');
    const m2 = document.getElementById('sectorMapBgMarker2');
    const m3 = document.getElementById('sectorMapBgMarker3');
    const m4 = document.getElementById('sectorMapBgMarker4');
    if (m1) m1.style.display = 'none';
    if (m2) m2.style.display = 'none';
    if (m3) m3.style.display = 'none';
    if (m4) m4.style.display = 'none';
    ['sectorMapBackgroundCoordBlock1', 'sectorMapBackgroundCoordBlock2', 'sectorMapBackgroundCoordBlock3', 'sectorMapBackgroundCoordBlock4'].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.style.display = 'none';
    });
    [
        'sectorMapBgLat1',
        'sectorMapBgLon1',
        'sectorMapBgLat2',
        'sectorMapBgLon2',
        'sectorMapBgLat3',
        'sectorMapBgLon3',
        'sectorMapBgLat4',
        'sectorMapBgLon4',
        'sectorMapBgExistingWp1',
        'sectorMapBgExistingWp2',
        'sectorMapBgExistingWp3',
        'sectorMapBgExistingWp4'
    ].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.value = '';
    });
    const addBtn = document.getElementById('sectorMapBackgroundAddToMapBtn');
    if (addBtn) addBtn.disabled = true;
    sectorMapBackgroundResetPreviewPanZoom();
}

function sectorMapBackgroundWizardRefreshAddEnabled() {
    const addBtn = document.getElementById('sectorMapBackgroundAddToMapBtn');
    if (!addBtn) return;
    const g = sectorMapBackgroundWizardParseFourGeoFromInputs();
    const ixy = sectorMapBackgroundWizardImageQuadPts();
    const stepReady = sectorMapBackgroundWizardLinearFlow ? sectorMapBackgroundWizardStep === 'coords4' : true;
    if (
        !sectorMapBackgroundWizardFourGeoAllValid(g) ||
        !sectorMapBackgroundWizardFourGeoDistinct(g) ||
        sectorMapBackgroundWizardMinEdgeImagePts(ixy) <= 2
    ) {
        addBtn.disabled = true;
        return;
    }
    const okH = sectorMapBackgroundWizardHomographyOk(ixy, g);
    addBtn.disabled = !(stepReady && okH);
}

function sectorMapBackgroundWizardOnCoordInput() {
    const g = sectorMapBackgroundWizardParseFourGeoFromInputs();
    const hint = document.getElementById('sectorMapBackgroundCalibHint');
    if (sectorMapBackgroundWizardLinearFlow) {
        if (sectorMapBackgroundWizardStep === 'coords1') {
            if (
                g.lat1 != null &&
                g.lon1 != null &&
                sectorMapBackgroundGeoPairValid(g.lat1, g.lon1)
            ) {
                sectorMapBackgroundWizardStep = 'pick2';
                if (hint) {
                    hint.textContent =
                        'Step 2: Click the second reference point on the image, then enter its latitude and longitude.';
                }
            }
        } else if (sectorMapBackgroundWizardStep === 'coords2') {
            if (
                g.lat1 != null &&
                g.lon1 != null &&
                g.lat2 != null &&
                g.lon2 != null &&
                sectorMapBackgroundGeoPairValid(g.lat1, g.lon1) &&
                sectorMapBackgroundGeoPairValid(g.lat2, g.lon2)
            ) {
                const geoSep12 = Math.hypot(g.lat2 - g.lat1, g.lon2 - g.lon1);
                const imgSep12 = Math.hypot(
                    sectorMapBackgroundIx2 - sectorMapBackgroundIx1,
                    sectorMapBackgroundIy2 - sectorMapBackgroundIy1
                );
                if (geoSep12 <= 1e-8) {
                    if (hint) hint.textContent = 'Points 1 and 2 must have different geographic positions.';
                } else if (imgSep12 <= 2) {
                    if (hint) {
                        hint.textContent =
                            'Image points 1 and 2 are too close — pick two pixels farther apart on the picture.';
                    }
                } else {
                    sectorMapBackgroundWizardStep = 'pick3';
                    if (hint) {
                        hint.textContent =
                            'Step 3: Click the third reference point (stay in order around the perimeter, e.g. clockwise).';
                    }
                }
            }
        } else if (sectorMapBackgroundWizardStep === 'coords3') {
            if (
                g.lat1 != null &&
                g.lon1 != null &&
                g.lat2 != null &&
                g.lon2 != null &&
                g.lat3 != null &&
                g.lon3 != null &&
                sectorMapBackgroundGeoPairValid(g.lat1, g.lon1) &&
                sectorMapBackgroundGeoPairValid(g.lat2, g.lon2) &&
                sectorMapBackgroundGeoPairValid(g.lat3, g.lon3)
            ) {
                const dup =
                    Math.hypot(g.lat3 - g.lat1, g.lon3 - g.lon1) <= 1e-7 ||
                    Math.hypot(g.lat3 - g.lat2, g.lon3 - g.lon2) <= 1e-7;
                const triImg = Math.abs(
                    sectorMapBackgroundPolygonSignedAreaXY([
                        { x: sectorMapBackgroundIx1, y: sectorMapBackgroundIy1 },
                        { x: sectorMapBackgroundIx2, y: sectorMapBackgroundIy2 },
                        { x: sectorMapBackgroundIx3, y: sectorMapBackgroundIy3 }
                    ])
                );
                const img23 = Math.hypot(
                    sectorMapBackgroundIx3 - sectorMapBackgroundIx2,
                    sectorMapBackgroundIy3 - sectorMapBackgroundIy2
                );
                if (dup) {
                    if (hint) hint.textContent = 'Point 3 must differ geographically from points 1 and 2.';
                } else if (img23 <= 2) {
                    if (hint) hint.textContent = 'Image points 2 and 3 are too close — adjust placement.';
                } else if (triImg < 150) {
                    if (hint) hint.textContent = 'Image points 1–3 are nearly collinear — spread point 3 sideways.';
                } else {
                    sectorMapBackgroundWizardStep = 'pick4';
                    if (hint) hint.textContent = 'Step 4: Click the fourth reference point, then enter its coordinates.';
                }
            }
        } else if (sectorMapBackgroundWizardStep === 'coords4') {
            if (sectorMapBackgroundWizardFourGeoAllValid(g) && sectorMapBackgroundWizardFourGeoDistinct(g)) {
                const ixy = sectorMapBackgroundWizardImageQuadPts();
                if (!sectorMapBackgroundWizardHomographyOk(ixy, g)) {
                    if (hint) {
                        hint.textContent =
                            'Calibration check failed — try reordering the four corners around the map or moving image picks.';
                    }
                } else if (hint) {
                    hint.textContent = 'Review coordinates, then click ADD to map.';
                }
            }
        }
    } else {
        if (
            sectorMapBackgroundWizardFourGeoAllValid(g) &&
            sectorMapBackgroundWizardFourGeoDistinct(g) &&
            hint &&
            !sectorMapBackgroundWizardHomographyOk(sectorMapBackgroundWizardImageQuadPts(), g)
        ) {
            hint.textContent =
                'Calibration check failed — adjust coordinates or marker positions (four corners in consistent order).';
        }
    }
    sectorMapBackgroundWizardRefreshAddEnabled();
}

