function sectorCanvasMapAreaPickMouseDownCapture(e) {
    if (!sectorMapMapAreaPickActive() || e.button !== 0) return;
    if (!document.getElementById('editSectorModal')?.classList.contains('active')) {
        endSectorMapMapAreaPickMode();
        return;
    }
    const c = document.getElementById('sectorCanvas');
    if (!c || e.target !== c) return;
    const px = eventToSectorCanvasPixel(e);
    if (!px) return;
    if (sectorMapMapAreaPickDisambigVisible) {
        hideSectorMapMapAreaPickDisambigPanel();
        e.preventDefault();
        e.stopImmediatePropagation();
        try { drawCanvas(); } catch (err) {}
        return;
    }
    const near = findSectorMapMapAreaIdsNearCanvasSegment(px.x, px.y, 12);
    if (near.length === 0) return;
    e.preventDefault();
    e.stopImmediatePropagation();
    if (sectorMapMapAreaPickMode === 'delete') {
        if (near.length === 1) {
            openSectorMapDeleteMapAreaConfirmModal(near[0]);
            return;
        }
        showSectorMapMapAreaPickDisambigPanel(near, e.clientX, e.clientY, (id) => {
            openSectorMapDeleteMapAreaConfirmModal(id);
        });
        return;
    }
    if (sectorMapMapAreaPickMode === 'edit') {
        const commitEdit = (id) => {
            endSectorMapMapAreaPickMode();
            openMapAreasModalForEdit(id);
        };
        if (near.length === 1) {
            commitEdit(near[0]);
            return;
        }
        showSectorMapMapAreaPickDisambigPanel(near, e.clientX, e.clientY, commitEdit);
    }
}

function formatBoundaryTextFromLatLonPointRows(rows) {
    if (!rows || !rows.length) return '';
    return rows.map(point => {
        const latDMS = decimalToDMS(point.latitude, true);
        const lonDMS = decimalToDMS(point.longitude, false);
        const latStr = formatDMS(latDMS, true).replace(/\s/g, '');
        const lonStr = formatDMS(lonDMS, false).replace(/\s/g, '');
        return `${point.name || 'WP'} ${latStr} ${lonStr}`;
    }).join('\n');
}

/** Add-waypoint map placement: DMS only + exit hint (no decimal line). */
function formatSectorMapWaypointPlacementHint(lat, lon) {
    if (!isFinite(lat) || !isFinite(lon)) return '—\nRight click to exit';
    const la = decimalToDMS(lat, true);
    const lo = decimalToDMS(lon, false);
    const dms = `${la.degrees}° ${la.minutes}' ${la.seconds}" ${la.direction}  ${lo.degrees}° ${lo.minutes}' ${lo.seconds}" ${lo.direction}`;
    return `${dms}\nRight click to exit`;
}

function formatSectorMapAddAtcSectorHint(lat, lon) {
    const coord = formatSectorMapWaypointPlacementHint(lat, lon).replace(/\nRight click to exit$/, '');
    return `${coord}\nMiddle-click: select · Again: deselect · First point (3+ pts): close · Right-click: cancel`;
}

function hideSectorMapAtcSectorEditCommitMenu() {
    const menu = document.getElementById('sectorMapAtcSectorEditCommitMenu');
    if (menu) menu.style.display = 'none';
}

function showSectorMapAtcSectorEditCommitMenu(clientX, clientY) {
    const menu = document.getElementById('sectorMapAtcSectorEditCommitMenu');
    if (!menu) return;
    menu.style.display = 'block';
    const place = () => {
        const w = menu.offsetWidth || 200;
        const h = menu.offsetHeight || 80;
        menu.style.left = `${Math.max(8, Math.min(clientX, window.innerWidth - w - 8))}px`;
        menu.style.top = `${Math.max(8, Math.min(clientY, window.innerHeight - h - 8))}px`;
    };
    place();
    requestAnimationFrame(place);
}

function hideSectorMapAtcSectorEditPickDisambigPanel() {
    sectorMapAtcSectorEditPickDisambigVisible = false;
    sectorMapAtcSectorEditPickDisambigIds = [];
    sectorMapAtcSectorEditPickBoxHoverId = null;
    const panel = document.getElementById('sectorMapEditAtcSectorDisambigPanel');
    if (panel) {
        panel.style.display = 'none';
        panel.innerHTML = '';
    }
}

function showSectorMapAtcSectorEditPickDisambigPanel(atcIds, clientX, clientY) {
    sectorMapAtcSectorEditPickDisambigVisible = true;
    sectorMapAtcSectorEditPickDisambigIds = atcIds.slice();
    sectorMapAtcSectorEditPickBoxHoverId = null;
    const panel = document.getElementById('sectorMapEditAtcSectorDisambigPanel');
    if (!panel) return;
    panel.innerHTML = '';
    atcIds.forEach(aid => {
        const s = atcSectors.find(x => x && x.id === aid);
        const name = s && s.name ? String(s.name) : String(aid);
        const box = document.createElement('button');
        box.type = 'button';
        box.className = 'sector-map-delete-route-disambig-item';
        box.dataset.atcSectorId = aid;
        box.textContent = name;
        box.addEventListener('mouseenter', () => {
            if (!sectorMapAtcSectorEditActive || sectorMapAtcSectorEditTargetId) return;
            sectorMapAtcSectorEditPickBoxHoverId = aid;
            try { drawCanvas(); } catch (e) {}
        });
        const commitPick = (ev, id) => {
            if (ev) {
                ev.preventDefault();
                ev.stopPropagation();
            }
            hideSectorMapAtcSectorEditPickDisambigPanel();
            beginSectorMapAtcSectorEditDraft(id);
            try { drawCanvas(); } catch (e2) {}
        };
        box.addEventListener('mouseup', ev => {
            if (ev.button !== 0) return;
            commitPick(ev, aid);
        });
        box.addEventListener('keydown', ev => {
            if (ev.key !== 'Enter' && ev.key !== ' ') return;
            commitPick(ev, aid);
        });
        panel.appendChild(box);
    });
    panel.onmouseleave = function () {
        if (!sectorMapAtcSectorEditActive || sectorMapAtcSectorEditTargetId) return;
        sectorMapAtcSectorEditPickBoxHoverId = null;
        try { drawCanvas(); } catch (e) {}
    };
    panel.style.display = 'flex';
    panel.style.flexDirection = 'column';
    const place = () => {
        const w = panel.offsetWidth || 200;
        const h = panel.offsetHeight || 120;
        const left = Math.max(8, Math.min(clientX + 8, window.innerWidth - w - 8));
        const top = Math.max(8, Math.min(clientY + 8, window.innerHeight - h - 8));
        panel.style.left = `${left}px`;
        panel.style.top = `${top}px`;
    };
    place();
    requestAnimationFrame(place);
}

function sectorMapAtcSectorEditClearDragListeners() {
    document.removeEventListener('mousemove', sectorMapAtcSectorEditDragDocMouseMove, true);
    document.removeEventListener('mouseup', sectorMapAtcSectorEditDragDocMouseUp, true);
}

function sectorMapAtcSectorEditNewPointFromAcquire(px) {
    if (!px) return null;
    const pick = sectorMapAtcEditPickHitForAcquire(px.x, px.y);
    const ent = selectionEntryFromAddAtcHit(pick);
    if (ent) return ent;
    const ll = canvasPixelToSectorLatLon(px.x, px.y);
    if (!isFinite(ll.latitude) || !isFinite(ll.longitude)) return null;
    sectorMapAtcSectorEditFreeSeq += 1;
    return {
        kind: 'free',
        uid: `ed_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`,
        latitude: ll.latitude,
        longitude: ll.longitude,
        name: `BMAP${sectorMapAtcSectorEditFreeSeq}`
    };
}

function sectorMapAtcSectorEditDragDocMouseMove(e) {
    if (!sectorMapAtcSectorEditDragType || !canvas) return;
    const px = eventToSectorCanvasPixel(e);
    if (px && isFinite(px.x) && isFinite(px.y)) {
        sectorMapAtcSectorEditDragCursorX = px.x;
        sectorMapAtcSectorEditDragCursorY = px.y;
    }
    const pick = px ? sectorMapAtcEditPickHitForAcquire(px.x, px.y) : null;
    let nw = null;
    let nk = null;
    if (pick && pick.hit === 'waypoint') nw = pick.waypoint.id;
    else if (pick && pick.hit === 'atcVertex') nk = `${pick.atcId}:${pick.ptIndex}`;
    if (nw !== sectorMapAtcSectorEditDragAcquireWaypointId || nk !== sectorMapAtcSectorEditDragAcquireAtcKey) {
        sectorMapAtcSectorEditDragAcquireWaypointId = nw;
        sectorMapAtcSectorEditDragAcquireAtcKey = nk;
    }
    try { drawCanvas(); } catch (err) {}
}

function sectorMapAtcSectorEditDragDocMouseUp(e) {
    if (!sectorMapAtcSectorEditDragType) return;
    sectorMapAtcSectorEditClearDragListeners();
    const px = eventToSectorCanvasPixel(e);
    const newPt = px ? sectorMapAtcSectorEditNewPointFromAcquire(px) : null;
    if (newPt && sectorMapAtcSectorEditDragType === 'insert' && sectorMapAtcSectorEditInsertSegIndex != null) {
        const k = sectorMapAtcSectorEditInsertSegIndex;
        const n = sectorMapAtcSectorEditDraftPoints.length;
        if (k === n - 1) sectorMapAtcSectorEditDraftPoints.splice(n, 0, newPt);
        else sectorMapAtcSectorEditDraftPoints.splice(k + 1, 0, newPt);
    }
    sectorMapAtcSectorEditDragType = null;
    sectorMapAtcSectorEditInsertSegIndex = null;
    sectorMapAtcSectorEditDragAcquireWaypointId = null;
    sectorMapAtcSectorEditDragAcquireAtcKey = null;
    sectorMapAtcSectorEditDragAnchorX = null;
    sectorMapAtcSectorEditDragAnchorY = null;
    sectorMapAtcSectorEditDragCursorX = null;
    sectorMapAtcSectorEditDragCursorY = null;
    try { drawCanvas(); } catch (err) {}
}

function sectorMapAtcSectorEditBeginInsertDrag(segIdx, grabCanvasX, grabCanvasY) {
    sectorMapAtcSectorEditDragType = 'insert';
    sectorMapAtcSectorEditInsertSegIndex = segIdx;
    sectorMapAtcSectorEditDragAcquireWaypointId = null;
    sectorMapAtcSectorEditDragAcquireAtcKey = null;
    const n = sectorMapAtcSectorEditDraftPoints.length;
    let j = segIdx + 1;
    if (j >= n) j = 0;
    const p0 = sectorMapAtcEditCanvasXYForDraftIndex(segIdx);
    const p1 = sectorMapAtcEditCanvasXYForDraftIndex(j);
    if (p0 && p1) {
        const c = sectorMapRouteEditClosestPointOnSegmentXY(grabCanvasX, grabCanvasY, p0.x, p0.y, p1.x, p1.y);
        sectorMapAtcSectorEditDragAnchorX = c.x;
        sectorMapAtcSectorEditDragAnchorY = c.y;
    } else {
        sectorMapAtcSectorEditDragAnchorX = grabCanvasX;
        sectorMapAtcSectorEditDragAnchorY = grabCanvasY;
    }
    sectorMapAtcSectorEditDragCursorX = grabCanvasX;
    sectorMapAtcSectorEditDragCursorY = grabCanvasY;
    document.addEventListener('mousemove', sectorMapAtcSectorEditDragDocMouseMove, true);
    document.addEventListener('mouseup', sectorMapAtcSectorEditDragDocMouseUp, true);
    try { drawCanvas(); } catch (e) {}
}

function beginSectorMapAtcSectorEditDraft(atcId) {
    const s = atcSectors.find(x => x && x.id === atcId);
    if (!s || !s.boundary) return;
    sectorMapAtcSectorEditTargetId = atcId;
    sectorMapAtcSectorEditOriginalBoundary = JSON.parse(JSON.stringify(s.boundary));
    sectorMapAtcSectorEditDraftPoints = (s.boundary.points || []).map((p, i) => ({
        kind: 'free',
        uid: `d0_${atcId}_${i}_${Math.random().toString(36).slice(2, 6)}`,
        latitude: p.latitude,
        longitude: p.longitude,
        name: (p.name || `P${i}`).toString()
    }));
    sectorMapAtcSectorEditPickHoverSegmentIds = [];
    sectorMapAtcSectorEditFreeSeq = 0;
    hideSectorMapAtcSectorEditPickDisambigPanel();
    hideSectorMapAtcSectorEditCommitMenu();
}

function applySectorMapAtcSectorEditSave() {
    if (!sectorMapAtcSectorEditTargetId) return;
    const idx = atcSectors.findIndex(s => s && s.id === sectorMapAtcSectorEditTargetId);
    if (idx < 0) return;
    const pts = [];
    for (let i = 0; i < sectorMapAtcSectorEditDraftPoints.length; i++) {
        const r = sectorMapAddAtcSectorLatLonNameFromSelection(sectorMapAtcSectorEditDraftPoints[i]);
        if (r) pts.push({ name: r.name, latitude: r.latitude, longitude: r.longitude });
    }
    if (pts.length < 2) {
        alert('Boundary needs at least 2 points.');
        return;
    }
    const prev = atcSectors[idx];
    prev.boundary = prev.boundary || {};
    prev.boundary.points = pts;
    if (!prev.boundary.id) prev.boundary.id = newSectorEntityId('bd');
    syncBoundariesFromAtcSectors();
    renderBoundariesList();
    hideSectorMapAtcSectorEditCommitMenu();
    endSectorMapAtcSectorEditMode();
    try { drawCanvas(); } catch (e) {}
}

function cancelSectorMapAtcSectorEditDraft() {
    const idx = atcSectors.findIndex(s => s && s.id === sectorMapAtcSectorEditTargetId);
    if (idx >= 0 && sectorMapAtcSectorEditOriginalBoundary) {
        atcSectors[idx].boundary = JSON.parse(JSON.stringify(sectorMapAtcSectorEditOriginalBoundary));
    }
    syncBoundariesFromAtcSectors();
    renderBoundariesList();
    hideSectorMapAtcSectorEditCommitMenu();
    endSectorMapAtcSectorEditMode();
    try { drawCanvas(); } catch (e) {}
}

function endSectorMapAtcSectorEditMode() {
    sectorMapAtcSectorEditActive = false;
    sectorMapAtcSectorEditTargetId = null;
    sectorMapAtcSectorEditDraftPoints = [];
    sectorMapAtcSectorEditOriginalBoundary = null;
    sectorMapAtcSectorEditPickHoverSegmentIds = [];
    if (sectorMapAtcSectorEditPickHoverRaf != null) {
        cancelAnimationFrame(sectorMapAtcSectorEditPickHoverRaf);
        sectorMapAtcSectorEditPickHoverRaf = null;
    }
    if (sectorMapAtcSectorEditDraftHoverRaf != null) {
        cancelAnimationFrame(sectorMapAtcSectorEditDraftHoverRaf);
        sectorMapAtcSectorEditDraftHoverRaf = null;
    }
    sectorMapAtcSectorEditClearDragListeners();
    sectorMapAtcSectorEditDragType = null;
    sectorMapAtcSectorEditInsertSegIndex = null;
    sectorMapAtcSectorEditDragAcquireWaypointId = null;
    sectorMapAtcSectorEditDragAcquireAtcKey = null;
    sectorMapAtcSectorEditDragAnchorX = null;
    sectorMapAtcSectorEditDragAnchorY = null;
    sectorMapAtcSectorEditDragCursorX = null;
    sectorMapAtcSectorEditDragCursorY = null;
    sectorMapAtcSectorEditHoverWaypointId = null;
    sectorMapAtcSectorEditHoverAtcKey = null;
    sectorMapAtcSectorEditFreeSeq = 0;
    document.removeEventListener('mousemove', onSectorMapAtcSectorEditDocMouseMove, true);
    document.removeEventListener('keydown', onSectorMapAtcSectorEditKeydown, true);
    document.getElementById('editSectorModal')?.removeEventListener('contextmenu', onEditSectorContextMenuWhileAtcSectorEditMapMode, true);
    hideSectorMapAtcSectorEditPickDisambigPanel();
    hideSectorMapAtcSectorEditCommitMenu();
    const hint = document.getElementById('sectorMapEditAtcSectorModeHint');
    if (hint) {
        hint.style.display = 'none';
        hint.textContent = '';
    }
    if (canvas && !sectorMapWaypointPlacementActive && !sectorMapWaypointDeleteActive && !sectorMapWaypointEditActive &&
        !sectorMapAddRoutePickingActive && !sectorMapRouteDeleteActive && !sectorMapRouteEditActive && !sectorMapAddAtcSectorActive && !sectorMapAtcSectorDeleteActive &&
        !sectorMapAddMapAreaActive && !sectorMapMapAreaPickActive()) {
        canvas.style.cursor = '';
    }
    try { drawCanvas(); } catch (e) {}
}

function startSectorMapAtcSectorEditMode() {
    hideSectorMapContextMenu();
    hideSectorMapAtcSectorEditCommitMenu();
    if (!currentSectorId) {
        alert('Please select an airspace first');
        return;
    }
    const hasDrawable = atcSectors.some(s => s && s.boundary && s.boundary.points && s.boundary.points.length >= 2);
    if (!hasDrawable) {
        alert('No ATC sector boundaries to edit on the map.');
        return;
    }
    try { endSectorMapAddAtcSectorMode(); } catch (eA) {}
    try { endSectorMapAddRoutePickingMode(); } catch (eR) {}
    try { endSectorMapRouteDeleteMode(); } catch (eD) {}
    try { endSectorMapAtcSectorDeleteMode(); } catch (eAtcDel) {}
    try { endSectorMapRouteEditMode(); } catch (eE) {}
    try { endSectorMapAddMapAreaMode(); } catch (eMa) {}
    try { endSectorMapMapAreaPickMode(); } catch (eMp) {}
    endSectorMapWaypointPlacement();
    endSectorMapWaypointDeleteMode();
    endSectorMapWaypointEditMode();
    endSectorMapAtcSectorEditMode();
    sectorMapAtcSectorEditActive = true;
    sectorMapAtcSectorEditTargetId = null;
    sectorMapAtcSectorEditDraftPoints = [];
    sectorMapAtcSectorEditOriginalBoundary = null;
    document.addEventListener('mousemove', onSectorMapAtcSectorEditDocMouseMove, true);
    document.addEventListener('keydown', onSectorMapAtcSectorEditKeydown, true);
    document.getElementById('editSectorModal')?.addEventListener('contextmenu', onEditSectorContextMenuWhileAtcSectorEditMapMode, true);
    if (canvas) canvas.style.cursor = 'crosshair';
    try { drawCanvas(); } catch (e2) {}
}

function onSectorMapAtcSectorEditDocMouseMove(e) {
    if (!sectorMapAtcSectorEditActive || !canvas) return;
    const hint = document.getElementById('sectorMapEditAtcSectorModeHint');
    const commitMenu = document.getElementById('sectorMapAtcSectorEditCommitMenu');
    const commitOpen = commitMenu && commitMenu.style.display !== 'none';
    if (hint) {
        if (commitOpen) {
            hint.style.display = 'none';
        } else {
            hint.textContent = sectorMapAtcSectorEditTargetId ? 'Edit ATC Sector — middle-click vertex: remove · drag segment: add · right-click: save/cancel' : 'Edit ATC Sector — click boundary segment to select';
            hint.style.display = 'block';
            hint.style.left = `${e.clientX + 14}px`;
            hint.style.top = `${e.clientY + 14}px`;
        }
    }
    if (sectorMapAtcSectorEditDragType) return;
    if (!sectorMapAtcSectorEditTargetId) {
        if (sectorMapAtcSectorEditPickDisambigVisible) return;
        const px = eventToSectorCanvasPixel(e);
        if (!px) return;
        const picked = findSectorMapAtcSectorIdsNearCanvasSegment(px.x, px.y, 12);
        if (sectorMapAtcSectorEditPickHoverSegmentIdsEqual(picked)) return;
        sectorMapAtcSectorEditPickHoverSegmentIds = picked;
        if (sectorMapAtcSectorEditPickHoverRaf != null) return;
        sectorMapAtcSectorEditPickHoverRaf = requestAnimationFrame(() => {
            sectorMapAtcSectorEditPickHoverRaf = null;
            if (sectorMapAtcSectorEditActive && !sectorMapAtcSectorEditTargetId) {
                try { drawCanvas(); } catch (err) {}
            }
        });
        return;
    }
    const px = eventToSectorCanvasPixel(e);
    const pick = px ? sectorMapAtcEditPickHitForAcquire(px.x, px.y) : null;
    let nw = null;
    let nk = null;
    if (pick && pick.hit === 'waypoint') nw = pick.waypoint.id;
    else if (pick && pick.hit === 'atcVertex') nk = `${pick.atcId}:${pick.ptIndex}`;
    if (nw === sectorMapAtcSectorEditHoverWaypointId && nk === sectorMapAtcSectorEditHoverAtcKey) return;
    sectorMapAtcSectorEditHoverWaypointId = nw;
    sectorMapAtcSectorEditHoverAtcKey = nk;
    if (sectorMapAtcSectorEditDraftHoverRaf != null) return;
    sectorMapAtcSectorEditDraftHoverRaf = requestAnimationFrame(() => {
        sectorMapAtcSectorEditDraftHoverRaf = null;
        if (sectorMapAtcSectorEditActive && sectorMapAtcSectorEditTargetId) {
            try { drawCanvas(); } catch (err) {}
        }
    });
}

function onSectorMapAtcSectorEditKeydown(e) {
    if (!sectorMapAtcSectorEditActive) return;
    if (e.key === 'Escape') {
        e.preventDefault();
        if (sectorMapAtcSectorEditTargetId) {
            cancelSectorMapAtcSectorEditDraft();
        } else {
            endSectorMapAtcSectorEditMode();
        }
    }
}

function onEditSectorContextMenuWhileAtcSectorEditMapMode(e) {
    if (!sectorMapAtcSectorEditActive) return;
    e.preventDefault();
    e.stopPropagation();
    hideSectorMapContextMenu();
    if (!sectorMapAtcSectorEditTargetId) {
        endSectorMapAtcSectorEditMode();
        return;
    }
    hideSectorMapAtcSectorEditCommitMenu();
    showSectorMapAtcSectorEditCommitMenu(e.clientX, e.clientY);
}

function sectorCanvasAtcSectorEditMouseDownCapture(e) {
    if (!sectorMapAtcSectorEditActive) return;
    if (!document.getElementById('editSectorModal')?.classList.contains('active')) {
        endSectorMapAtcSectorEditMode();
        return;
    }
    const c = document.getElementById('sectorCanvas');
    if (!c || e.target !== c) return;
    const px = eventToSectorCanvasPixel(e);
    if (!px) return;

    if (!sectorMapAtcSectorEditTargetId) {
        if (e.button !== 0) return;
        if (sectorMapAtcSectorEditPickDisambigVisible) {
            hideSectorMapAtcSectorEditPickDisambigPanel();
            e.preventDefault();
            e.stopImmediatePropagation();
            try { drawCanvas(); } catch (err) {}
            return;
        }
        const near = findSectorMapAtcSectorIdsNearCanvasSegment(px.x, px.y, 12);
        if (near.length === 0) return;
        e.preventDefault();
        e.stopImmediatePropagation();
        if (near.length === 1) {
            beginSectorMapAtcSectorEditDraft(near[0]);
            try { drawCanvas(); } catch (err) {}
            return;
        }
        showSectorMapAtcSectorEditPickDisambigPanel(near, e.clientX, e.clientY);
        return;
    }

    if (sectorMapAtcSectorEditDragType) return;

    if (e.button === 1) {
        const vIdx = findAtcEditDraftVertexIndexAtCanvasPixel(px.x, px.y, 10);
        if (vIdx >= 0) {
            if (sectorMapAtcSectorEditDraftPoints.length <= 2) {
                alert('Boundary must keep at least 2 points.');
            } else {
                e.preventDefault();
                e.stopImmediatePropagation();
                sectorMapAtcSectorEditDraftPoints.splice(vIdx, 1);
                try { drawCanvas(); } catch (err) {}
            }
            return;
        }
        const segIdx = findAtcEditDraftSegmentIndexNearCanvasPixel(px.x, px.y, 14);
        if (segIdx >= 0) {
            e.preventDefault();
            e.stopImmediatePropagation();
            sectorMapAtcSectorEditBeginInsertDrag(segIdx, px.x, px.y);
        }
    }
}

function populateAddWaypointDmsFromDecimal(latitude, longitude) {
    const latDMS = decimalToDMS(latitude, true);
    const lonDMS = decimalToDMS(longitude, false);
    document.getElementById('latDegrees').value = latDMS.degrees;
    document.getElementById('latMinutes').value = latDMS.minutes;
    document.getElementById('latSeconds').value = latDMS.seconds;
    document.getElementById('latDirection').value = latDMS.direction;
    document.getElementById('lonDegrees').value = lonDMS.degrees;
    document.getElementById('lonMinutes').value = lonDMS.minutes;
    document.getElementById('lonSeconds').value = lonDMS.seconds;
    document.getElementById('lonDirection').value = lonDMS.direction;
}

