function showSectorMapContextMenu(clientX, clientY) {
    const menu = document.getElementById('sectorMapContextMenu');
    if (!menu) return;
    menu.classList.remove('sector-map-context-submenu-flip');
    menu.style.display = 'block';
    const subWEstimate = 190;
    const place = () => {
        const w = menu.offsetWidth || 160;
        const h = menu.offsetHeight || 48;
        let left = Math.max(8, Math.min(clientX, window.innerWidth - w - 8));
        if (left + w + subWEstimate > window.innerWidth - 8) {
            left = Math.max(8, window.innerWidth - w - subWEstimate - 8);
        }
        menu.style.left = `${left}px`;
        menu.style.top = `${Math.max(8, Math.min(clientY, window.innerHeight - h - 8))}px`;
        const leftNum = parseFloat(menu.style.left) || 0;
        if (leftNum + w + subWEstimate > window.innerWidth - 8) {
            menu.classList.add('sector-map-context-submenu-flip');
        } else {
            menu.classList.remove('sector-map-context-submenu-flip');
        }
    };
    place();
    requestAnimationFrame(place);
}

