function showSectorMapRouteDeleteDisambigPanel(routeIds, clientX, clientY) {
    sectorMapRouteDeleteDisambigVisible = true;
    sectorMapRouteDeleteDisambigRouteIds = routeIds.slice();
    sectorMapRouteDeleteBoxHoverRouteId = null;
    const panel = document.getElementById('sectorMapDeleteRouteDisambigPanel');
    if (!panel) return;
    panel.innerHTML = '';
    routeIds.forEach(rid => {
        const route = routes.find(r => r && r.id === rid);
        const name = route && route.name ? String(route.name) : String(rid);
        const box = document.createElement('button');
        box.type = 'button';
        box.className = 'sector-map-delete-route-disambig-item';
        box.dataset.routeId = rid;
        box.textContent = name;
        box.addEventListener('mouseenter', () => {
            if (!sectorMapRouteDeleteActive) return;
            sectorMapRouteDeleteBoxHoverRouteId = rid;
            try { drawCanvas(); } catch (e) {}
        });
        const commitDisambigChoice = (ev, routeId) => {
            if (ev) {
                ev.preventDefault();
                ev.stopPropagation();
            }
            hideSectorMapRouteDeleteDisambigPanel();
            openSectorMapDeleteRouteConfirmModal(routeId);
            try { drawCanvas(); } catch (e) {}
        };
        box.addEventListener('mouseup', ev => {
            if (ev.button !== 0) return;
            commitDisambigChoice(ev, rid);
        });
        box.addEventListener('keydown', ev => {
            if (ev.key !== 'Enter' && ev.key !== ' ') return;
            commitDisambigChoice(ev, rid);
        });
        panel.appendChild(box);
    });
    panel.onmouseleave = function () {
        if (!sectorMapRouteDeleteActive) return;
        sectorMapRouteDeleteBoxHoverRouteId = null;
        try { drawCanvas(); } catch (e) {}
    };
    panel.style.display = 'flex';
    panel.style.flexDirection = 'column';
    const place = () => {
        const w = panel.offsetWidth || 200;
        const h = panel.offsetHeight || 120;
        const left = Math.max(8, Math.min(clientX + 8, window.innerWidth - w - 8));
        const top = Math.max(8, Math.min(clientY + 8, window.innerHeight - h - 8));
        panel.style.left = `${left}px`;
        panel.style.top = `${top}px`;
    };
    place();
    requestAnimationFrame(place);
}

function openSectorMapDeleteRouteConfirmModal(routeId) {
    const route = routes.find(r => r && r.id === routeId);
    if (!route) return;
    pendingDeleteRouteId = routeId;
    sectorMapRouteDeleteHoverSegmentRouteIds = [];
    sectorMapRouteDeleteBoxHoverRouteId = null;
    const name = route.name ? String(route.name) : '(unnamed)';
    const msg = document.getElementById('deleteRouteConfirmMessage');
    if (msg) msg.textContent = `Do you want to delete Route "${name}"?`;
    openModal('deleteRouteConfirmModal');
    try { drawCanvas(); } catch (e) {}
}

