function beginSectorMapRouteEditDraftForRoute(routeId) {
    const route = routes.find(r => r && r.id === routeId);
    if (!route) return;
    sectorMapRouteEditTargetRouteId = routeId;
    const validWpSet = new Set(waypoints.map(w => w && w.id).filter(Boolean));
    sectorMapRouteEditDraftIds = (route.waypointIds || []).filter(id => validWpSet.has(id));
    sectorMapRouteEditPickHoverSegmentRouteIds = [];
    hideSectorMapRouteEditPickDisambigPanel();
    hideSectorMapRouteEditCommitMenu();
}

function sectorMapRouteEditClearDragListeners() {
    document.removeEventListener('mousemove', sectorMapRouteEditDragDocMouseMove, true);
    document.removeEventListener('mouseup', sectorMapRouteEditDragDocMouseUp, true);
}

function sectorMapRouteEditCanvasXYForDraftIndex(draftIds, index) {
    if (!canvas || !draftIds || index < 0 || index >= draftIds.length) return null;
    const wid = draftIds[index];
        const waypoint = findSectorRouteFixById(wid);
    if (!waypoint || typeof waypoint.latitude !== 'number' || typeof waypoint.longitude !== 'number') return null;
    updateCentreWaypoint();
    const { ox: effectiveOriginX, oy: effectiveOriginY } = getSectorCanvasEffectiveOriginPx();
    if (!isFinite(zoomLevel) || zoomLevel <= 0) return null;
    const sectorLonScale = getSectorMapLonCosScale();
    let relLon = waypoint.longitude;
    let relLat = waypoint.latitude;
    if (centreWaypoint && isFinite(centreWaypoint.latitude) && isFinite(centreWaypoint.longitude)) {
        relLon = waypoint.longitude - centreWaypoint.longitude;
        relLat = waypoint.latitude - centreWaypoint.latitude;
    }
    const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
    const y = effectiveOriginY - relLat * zoomLevel;
    if (!isFinite(x) || !isFinite(y)) return null;
    return { x, y };
}

function sectorMapRouteEditClosestPointOnSegmentXY(px, py, x1, y1, x2, y2) {
    const dx = x2 - x1;
    const dy = y2 - y1;
    const lenSq = dx * dx + dy * dy;
    if (lenSq < 1e-6) return { x: x1, y: y1 };
    let t = ((px - x1) * dx + (py - y1) * dy) / lenSq;
    t = Math.max(0, Math.min(1, t));
    return { x: x1 + t * dx, y: y1 + t * dy };
}

function sectorMapRouteEditDragDocMouseMove(e) {
    if (!sectorMapRouteEditDragType || !canvas) return;
    const px = eventToSectorCanvasPixel(e);
    if (px && isFinite(px.x) && isFinite(px.y)) {
        sectorMapRouteEditDragCursorX = px.x;
        sectorMapRouteEditDragCursorY = px.y;
    }
    const wp = px ? findSectorRouteFixAtCanvasPixel(px.x, px.y) : null;
    const nextId = wp?.id ?? null;
    const acquireChanged = nextId !== sectorMapRouteEditDragAcquireWaypointId;
    if (acquireChanged) {
        sectorMapRouteEditDragAcquireWaypointId = nextId;
    }
    try { drawCanvas(); } catch (err) {}
}

function sectorMapRouteEditDragDocMouseUp(e) {
    if (!sectorMapRouteEditDragType) return;
    sectorMapRouteEditClearDragListeners();
    const wid = sectorMapRouteEditDragAcquireWaypointId;
    if (wid) {
        if (sectorMapRouteEditDragType === 'prepend') {
            if (wid !== sectorMapRouteEditDraftIds[0]) {
                sectorMapRouteEditDraftIds.unshift(wid);
            }
        } else if (sectorMapRouteEditDragType === 'insert' && sectorMapRouteEditInsertSegIndex != null) {
            const i = sectorMapRouteEditInsertSegIndex;
            sectorMapRouteEditDraftIds.splice(i + 1, 0, wid);
        }
    }
    sectorMapRouteEditDragType = null;
    sectorMapRouteEditInsertSegIndex = null;
    sectorMapRouteEditDragAcquireWaypointId = null;
    sectorMapRouteEditDragAnchorX = null;
    sectorMapRouteEditDragAnchorY = null;
    sectorMapRouteEditDragCursorX = null;
    sectorMapRouteEditDragCursorY = null;
    try { drawCanvas(); } catch (err) {}
}

function sectorMapRouteEditBeginPrepOrInsertDrag(type, segIdx, grabCanvasX, grabCanvasY) {
    sectorMapRouteEditDragType = type;
    sectorMapRouteEditInsertSegIndex = type === 'insert' ? segIdx : null;
    sectorMapRouteEditDragAcquireWaypointId = null;
    sectorMapRouteEditPendingAddEndWaypointId = null;

    const gx = grabCanvasX;
    const gy = grabCanvasY;
    if (type === 'prepend') {
        const a = sectorMapRouteEditCanvasXYForDraftIndex(sectorMapRouteEditDraftIds, 0);
        if (a) {
            sectorMapRouteEditDragAnchorX = a.x;
            sectorMapRouteEditDragAnchorY = a.y;
        } else {
            sectorMapRouteEditDragAnchorX = gx;
            sectorMapRouteEditDragAnchorY = gy;
        }
    } else if (type === 'insert' && segIdx != null && segIdx >= 0) {
        const p0 = sectorMapRouteEditCanvasXYForDraftIndex(sectorMapRouteEditDraftIds, segIdx);
        const p1 = sectorMapRouteEditCanvasXYForDraftIndex(sectorMapRouteEditDraftIds, segIdx + 1);
        if (p0 && p1) {
            const c = sectorMapRouteEditClosestPointOnSegmentXY(gx, gy, p0.x, p0.y, p1.x, p1.y);
            sectorMapRouteEditDragAnchorX = c.x;
            sectorMapRouteEditDragAnchorY = c.y;
        } else {
            sectorMapRouteEditDragAnchorX = gx;
            sectorMapRouteEditDragAnchorY = gy;
        }
    } else {
        sectorMapRouteEditDragAnchorX = gx;
        sectorMapRouteEditDragAnchorY = gy;
    }
    sectorMapRouteEditDragCursorX = gx;
    sectorMapRouteEditDragCursorY = gy;

    document.addEventListener('mousemove', sectorMapRouteEditDragDocMouseMove, true);
    document.addEventListener('mouseup', sectorMapRouteEditDragDocMouseUp, true);
    try { drawCanvas(); } catch (e) {}
}

