function startSectorMapRouteEditMode() {
    hideSectorMapContextMenu();
    hideSectorMapRouteEditCommitMenu();
    if (!currentSectorId) {
        alert('Please select an airspace first');
        return;
    }
    const hasDrawableRoute = routes.some(r => r && r.waypointIds && r.waypointIds.length >= 2);
    if (!hasDrawableRoute) {
        alert('No routes to edit on the map.');
        return;
    }
    try { endSectorMapAddAtcSectorMode(); } catch (eAtc) {}
    try { endSectorMapAtcSectorEditMode(); } catch (eAe) {}
    try { endSectorMapAtcSectorDeleteMode(); } catch (eAtcDel) {}
    try { endSectorMapAddMapAreaMode(); } catch (eMa) {}
    try { endSectorMapMapAreaPickMode(); } catch (eMp) {}
    try { endSectorMapAddRoutePickingMode(); } catch (eR) {}
    try { endSectorMapRouteDeleteMode(); } catch (eD) {}
    endSectorMapWaypointPlacement();
    endSectorMapWaypointDeleteMode();
    endSectorMapWaypointEditMode();
    endSectorMapRouteEditMode();
    sectorMapRouteEditActive = true;
    sectorMapRouteEditTargetRouteId = null;
    document.addEventListener('mousemove', onSectorMapRouteEditDocMouseMove, true);
    document.addEventListener('keydown', onSectorMapRouteEditKeydown, true);
    document.getElementById('editSectorModal')?.addEventListener('contextmenu', onEditSectorContextMenuWhileRouteEditMapMode, true);
    if (canvas) canvas.style.cursor = 'crosshair';
    try { drawCanvas(); } catch (e) {}
}

function sectorCanvasRouteEditMouseDownCapture(e) {
    if (!sectorMapRouteEditActive) return;
    if (!document.getElementById('editSectorModal')?.classList.contains('active')) {
        endSectorMapRouteEditMode();
        return;
    }
    const c = document.getElementById('sectorCanvas');
    if (!c || e.target !== c) return;
    const px = eventToSectorCanvasPixel(e);
    if (!px) return;

    if (!sectorMapRouteEditTargetRouteId) {
        if (e.button !== 0) return;
        if (sectorMapRouteEditPickDisambigVisible) {
            hideSectorMapRouteEditPickDisambigPanel();
            e.preventDefault();
            e.stopImmediatePropagation();
            try { drawCanvas(); } catch (err) {}
            return;
        }
        const near = findSectorMapRouteIdsNearCanvasSegment(px.x, px.y, 12);
        if (near.length === 0) return;
        e.preventDefault();
        e.stopImmediatePropagation();
        if (near.length === 1) {
            beginSectorMapRouteEditDraftForRoute(near[0]);
            try { drawCanvas(); } catch (err) {}
            return;
        }
        showSectorMapRouteEditPickDisambigPanel(near, e.clientX, e.clientY);
        return;
    }

    if (e.button === 1) {
        const wp = findSectorRouteFixAtCanvasPixel(px.x, px.y);
        if (!wp) return;
        e.preventDefault();
        e.stopImmediatePropagation();
        const idx = sectorMapRouteEditDraftIds.lastIndexOf(wp.id);
        if (idx === -1) return;
        sectorMapRouteEditDraftIds.splice(idx, 1);
        try { drawCanvas(); } catch (err) {}
        return;
    }
    if (e.button !== 0) return;

    if (sectorMapRouteEditDragType) return;

    const wpHit = findSectorRouteFixAtCanvasPixel(px.x, px.y);
    const draft0 = sectorMapRouteEditDraftIds[0];
    if (wpHit && draft0 && wpHit.id === draft0) {
        e.preventDefault();
        e.stopImmediatePropagation();
        sectorMapRouteEditBeginPrepOrInsertDrag('prepend', null, px.x, px.y);
        return;
    }
    if (sectorMapRouteEditDraftIds.length >= 2) {
        const segIdx = findDraftSegmentIndexNearCanvasPixel(px.x, px.y, sectorMapRouteEditDraftIds, 14);
        if (segIdx >= 0) {
            e.preventDefault();
            e.stopImmediatePropagation();
            sectorMapRouteEditBeginPrepOrInsertDrag('insert', segIdx, px.x, px.y);
            return;
        }
    }
    if (wpHit) {
        e.preventDefault();
        e.stopImmediatePropagation();
        sectorMapRouteEditPendingAddEndWaypointId = wpHit.id;
        sectorMapRouteEditAddEndStartClientX = e.clientX;
        sectorMapRouteEditAddEndStartClientY = e.clientY;
        return;
    }
}

function sectorCanvasRouteEditMouseUpCapture(e) {
    if (!sectorMapRouteEditActive || !sectorMapRouteEditTargetRouteId || e.button !== 0) return;
    if (sectorMapRouteEditDragType) return;
    const pending = sectorMapRouteEditPendingAddEndWaypointId;
    if (pending == null) return;
    const dx = e.clientX - sectorMapRouteEditAddEndStartClientX;
    const dy = e.clientY - sectorMapRouteEditAddEndStartClientY;
    sectorMapRouteEditPendingAddEndWaypointId = null;
    if (dx * dx + dy * dy > 144) return;
    const px = eventToSectorCanvasPixel(e);
    const wp = px ? findSectorRouteFixAtCanvasPixel(px.x, px.y) : null;
    if (wp && wp.id === pending) {
        sectorMapRouteEditDraftIds.push(wp.id);
        try { drawCanvas(); } catch (err) {}
    }
}

