function onSectorMapAddAtcSectorDocMouseMove(e) {
    if (!sectorMapAddAtcSectorActive || !canvas) return;
    const px = eventToSectorCanvasPixel(e);
    const hint = document.getElementById('sectorMapPlacementHint');
    if (!px || !hint) return;
    const { latitude, longitude } = canvasPixelToSectorLatLon(px.x, px.y);
    hint.textContent = formatSectorMapAddAtcSectorHint(latitude, longitude);
    hint.style.display = 'block';
    hint.style.left = `${e.clientX + 14}px`;
    hint.style.top = `${e.clientY + 14}px`;
    canvas.style.cursor = 'crosshair';

    const pick = sectorMapAddAtcSectorPickHit(px.x, px.y);
    let nextWp = null;
    let nextAtcKey = null;
    let nextFree = null;
    if (pick.hit === 'waypoint') nextWp = pick.waypoint.id;
    else if (pick.hit === 'atcVertex') nextAtcKey = `${pick.atcId}:${pick.ptIndex}`;
    else if (pick.hit === 'free') nextFree = pick.freeSel.uid;

    if (nextWp === sectorMapAddAtcSectorHoverWaypointId && nextAtcKey === sectorMapAddAtcSectorHoverAtcKey &&
        nextFree === sectorMapAddAtcSectorHoverFreeUid) {
        return;
    }
    sectorMapAddAtcSectorHoverWaypointId = nextWp;
    sectorMapAddAtcSectorHoverAtcKey = nextAtcKey;
    sectorMapAddAtcSectorHoverFreeUid = nextFree;
    if (sectorMapAddAtcSectorHoverRaf != null) return;
    sectorMapAddAtcSectorHoverRaf = requestAnimationFrame(() => {
        sectorMapAddAtcSectorHoverRaf = null;
        if (sectorMapAddAtcSectorActive) {
            try { drawCanvas(); } catch (err) {}
        }
    });
}

function sectorCanvasAddAtcSectorMouseDownCapture(e) {
    if (!sectorMapAddAtcSectorActive || e.button !== 1) return;
    if (!document.getElementById('editSectorModal')?.classList.contains('active')) {
        endSectorMapAddAtcSectorMode();
        return;
    }
    const c = document.getElementById('sectorCanvas');
    if (!c || e.target !== c) return;
    const px = eventToSectorCanvasPixel(e);
    if (!px) return;
    const pick = sectorMapAddAtcSectorPickHit(px.x, px.y);
    const entry = selectionEntryFromAddAtcHit(pick);
    const keyFromPick = entry ? sectorMapAddAtcSectorSelectionKey(entry) : '';

    if (sectorMapAddAtcSectorSelection.length >= 3 && keyFromPick &&
        keyFromPick === sectorMapAddAtcSectorSelectionKey(sectorMapAddAtcSectorSelection[0])) {
        e.preventDefault();
        e.stopImmediatePropagation();
        const rows = [];
        for (let i = 0; i < sectorMapAddAtcSectorSelection.length; i++) {
            const row = sectorMapAddAtcSectorLatLonNameFromSelection(sectorMapAddAtcSectorSelection[i]);
            if (row) rows.push(row);
        }
        if (rows.length < 3) {
            endSectorMapAddAtcSectorMode();
            return;
        }
        const first = rows[0];
        const closeName = `${first.name}_E`;
        rows.push({ latitude: first.latitude, longitude: first.longitude, name: closeName });
        const boundaryText = formatBoundaryTextFromLatLonPointRows(rows);
        endSectorMapAddAtcSectorMode();
        openAtcSectorsModalWithBoundaryText(boundaryText);
        return;
    }

    const idxFound = keyFromPick
        ? sectorMapAddAtcSectorSelection.findIndex(s => sectorMapAddAtcSectorSelectionKey(s) === keyFromPick)
        : -1;
    if (idxFound >= 0) {
        e.preventDefault();
        e.stopImmediatePropagation();
        sectorMapAddAtcSectorSelection.splice(idxFound, 1);
        try { drawCanvas(); } catch (err) {}
        return;
    }

    if (pick.hit === 'canvas') {
        const ll = canvasPixelToSectorLatLon(px.x, px.y);
        if (!isFinite(ll.latitude) || !isFinite(ll.longitude)) return;
        e.preventDefault();
        e.stopImmediatePropagation();
        sectorMapAddAtcSectorFreeSeq += 1;
        const name = `BMAP${sectorMapAddAtcSectorFreeSeq}`;
        sectorMapAddAtcSectorSelection.push({
            kind: 'free',
            uid: `fr_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`,
            latitude: ll.latitude,
            longitude: ll.longitude,
            name
        });
        try { drawCanvas(); } catch (err) {}
        return;
    }

    if (entry) {
        e.preventDefault();
        e.stopImmediatePropagation();
        sectorMapAddAtcSectorSelection.push(entry);
        try { drawCanvas(); } catch (err) {}
    }
}

