function openDeleteWaypointConfirmModal(waypoint) {
    if (!waypoint || !waypoint.id) return;
    pendingDeleteWaypointId = waypoint.id;
    const name = waypoint.name ? String(waypoint.name) : '(unnamed)';
    const msg = document.getElementById('deleteWaypointConfirmMessage');
    if (msg) msg.textContent = `Do you want to delete waypoint ${name}?`;
    openModal('deleteWaypointConfirmModal');
}

function sectorCanvasDeleteModeMouseDownCapture(e) {
    if ((!sectorMapWaypointDeleteActive && !sectorMapNavaidDeleteActive) || e.button !== 0) return;
    if (!document.getElementById('editSectorModal')?.classList.contains('active')) {
        if (sectorMapNavaidDeleteActive) endSectorMapNavaidDeleteMode();
        else endSectorMapWaypointDeleteMode();
        return;
    }
    const c = document.getElementById('sectorCanvas');
    if (!c || e.target !== c) return;
    const px = eventToSectorCanvasPixel(e);
    if (!px) return;
    if (sectorMapNavaidDeleteActive) {
        const nav = findSectorNavaidAtCanvasPixel(px.x, px.y);
        if (!nav) return;
        e.preventDefault();
        e.stopImmediatePropagation();
        if (confirm(`Delete NAVAID ${nav.name || '(unnamed)'}?`)) {
            deleteNavaid(nav.id);
            endSectorMapNavaidDeleteMode();
        }
        return;
    }
    const wp = findSectorWaypointAtCanvasPixel(px.x, px.y);
    if (!wp) return;
    e.preventDefault();
    e.stopImmediatePropagation();
    openDeleteWaypointConfirmModal(wp);
}

function onSectorMapPlacementDocMouseMove(e) {
    if (!sectorMapWaypointPlacementActive || !canvas) return;
    const px = eventToSectorCanvasPixel(e);
    const hint = document.getElementById('sectorMapPlacementHint');
    if (!px || !hint) return;
    const { latitude, longitude } = canvasPixelToSectorLatLon(px.x, px.y);
    hint.textContent = formatSectorMapWaypointPlacementHint(latitude, longitude);
    hint.style.display = 'block';
    hint.style.left = `${e.clientX + 14}px`;
    hint.style.top = `${e.clientY + 14}px`;
    canvas.style.cursor = 'crosshair';
}

function onSectorMapPlacementKeydown(e) {
    if (!sectorMapWaypointPlacementActive) return;
    if (e.key === 'Escape') {
        e.preventDefault();
        endSectorMapWaypointPlacement();
    }
}

function startSectorMapWaypointPlacement() {
    hideSectorMapContextMenu();
    if (!currentSectorId) {
        alert('Please select an airspace first');
        return;
    }
    try { endSectorMapAddAtcSectorMode(); } catch (eAtc) {}
    try { endSectorMapAtcSectorEditMode(); } catch (eAe) {}
    try { endSectorMapAtcSectorDeleteMode(); } catch (eAtcDel) {}
    try { endSectorMapAddMapAreaMode(); } catch (eMa) {}
    try { endSectorMapMapAreaPickMode(); } catch (eMp) {}
    try { endSectorMapAddRoutePickingMode(); } catch (eR) {}
    try { endSectorMapRouteDeleteMode(); } catch (eRt) {}
    try { endSectorMapRouteEditMode(); } catch (eRe) {}
    try { endSectorMapWaypointDeleteMode(); } catch (e) {}
    try { endSectorMapWaypointEditMode(); } catch (eE) {}
    endSectorMapWaypointPlacement();
    sectorMapPlacementTarget = 'waypoint';
    sectorMapWaypointPlacementActive = true;
    document.addEventListener('mousemove', onSectorMapPlacementDocMouseMove, true);
    document.addEventListener('keydown', onSectorMapPlacementKeydown, true);
    document.getElementById('editSectorModal')?.addEventListener('contextmenu', onEditSectorContextMenuWhileWaypointPlacementMode, true);
}

function startSectorMapNavaidPlacement() {
    hideSectorMapContextMenu();
    if (!currentSectorId) {
        alert('Please select an airspace first');
        return;
    }
    try { endSectorMapAddAtcSectorMode(); } catch (eAtc) {}
    try { endSectorMapAtcSectorEditMode(); } catch (eAe) {}
    try { endSectorMapAtcSectorDeleteMode(); } catch (eAtcDel) {}
    try { endSectorMapAddMapAreaMode(); } catch (eMa) {}
    try { endSectorMapMapAreaPickMode(); } catch (eMp) {}
    try { endSectorMapAddRoutePickingMode(); } catch (eR) {}
    try { endSectorMapRouteDeleteMode(); } catch (eRt) {}
    try { endSectorMapRouteEditMode(); } catch (eRe) {}
    try { endSectorMapWaypointDeleteMode(); } catch (e) {}
    try { endSectorMapWaypointEditMode(); } catch (eE) {}
    endSectorMapWaypointPlacement();
    sectorMapPlacementTarget = 'navaid';
    sectorMapWaypointPlacementActive = true;
    document.addEventListener('mousemove', onSectorMapPlacementDocMouseMove, true);
    document.addEventListener('keydown', onSectorMapPlacementKeydown, true);
    document.getElementById('editSectorModal')?.addEventListener('contextmenu', onEditSectorContextMenuWhileWaypointPlacementMode, true);
}

function sectorCanvasPlacementMouseDownCapture(e) {
    if (!sectorMapWaypointPlacementActive || e.button !== 0) return;
    if (!document.getElementById('editSectorModal')?.classList.contains('active')) {
        endSectorMapWaypointPlacement();
        return;
    }
    const c = document.getElementById('sectorCanvas');
    if (!c || e.target !== c) return;
    const px = eventToSectorCanvasPixel(e);
    if (!px) return;
    e.preventDefault();
    e.stopImmediatePropagation();
    const { latitude, longitude } = canvasPixelToSectorLatLon(px.x, px.y);
    if (!isFinite(latitude) || !isFinite(longitude)) {
        alert('Could not read coordinates at this position.');
        endSectorMapWaypointPlacement();
        return;
    }
    const placementTarget = sectorMapPlacementTarget;
    endSectorMapWaypointPlacement();
    if (placementTarget === 'navaid') {
        document.getElementById('navaidName').value = '';
        document.getElementById('navaidType').value = 'VOR';
        populateAddNavaidDmsFromDecimal(latitude, longitude);
        delete document.getElementById('addNavaidForm').dataset.editingNavaidId;
        document.getElementById('addNavaidTitle').textContent = 'Add NAVAID';
        openModal('addNavaidModal');
        setTimeout(() => document.getElementById('navaidName')?.focus(), 100);
    } else if (placementTarget === 'parking') {
        // Preserve any name/editing state already in the parking form (Pick from Map mid-edit).
        // Keep the exact clicked coordinates so DMS rounding (whole arc-seconds) doesn't offset the stand.
        sectorMapParkingPickPreciseLatLon = { latitude, longitude };
        populateAddParkingDmsFromDecimal(latitude, longitude);
        openModal('addParkingModal');
        setTimeout(() => document.getElementById('parkingName')?.focus(), 100);
    } else {
        document.getElementById('waypointName').value = '';
        populateAddWaypointDmsFromDecimal(latitude, longitude);
        delete document.getElementById('addWaypointForm').dataset.editingWaypointId;
        document.getElementById('addWaypointTitle').textContent = 'Add Waypoint';
        openModal('addWaypointModal');
        setTimeout(() => document.getElementById('waypointName')?.focus(), 100);
    }
}

