    container.innerHTML = `
        <div class="waypoint-input-group">
            <input type="text" class="route-waypoint-input form-input" placeholder="Type waypoint name..." autocomplete="off">
            <div class="autocomplete-suggestions" style="display: none;"></div>
            <div class="waypoint-error" style="display: none; color: #ff4444; font-size: 0.8rem; margin-top: 0.25rem;">No match</div>
        </div>
    `;
