// Setup autocomplete for route waypoint inputs
function setupRouteWaypointInputs() {
    const inputs = document.querySelectorAll('.route-waypoint-input');
    inputs.forEach(input => {
        // Check if already set up
        if (input.dataset.autocompleteSetup === 'true') {
            return;
        }
        setupAutocomplete(input);
        input.dataset.autocompleteSetup = 'true';
    });
}

// Setup autocomplete for a single input
function setupAutocomplete(input) {
    let selectedIndex = -1;
    let suggestions = [];
    
    input.addEventListener('input', function() {
        const value = this.value.trim();
        const suggestionsDiv = this.parentElement.querySelector('.autocomplete-suggestions');
        const errorDiv = this.parentElement.querySelector('.waypoint-error');
        
        if (!value) {
            suggestionsDiv.style.display = 'none';
            errorDiv.style.display = 'none';
            this.dataset.waypointId = '';
            return;
        }
        
        // Filter route fixes (Waypoints + NAVAIDs) by name.
        suggestions = getSectorRouteFixes().filter(wp => 
            wp && wp.name && wp.name.toLowerCase().includes(value.toLowerCase())
        );
        
        if (suggestions.length === 0) {
            suggestionsDiv.style.display = 'none';
            errorDiv.style.display = 'block';
            this.dataset.waypointId = '';
            return;
        }
        
        errorDiv.style.display = 'none';
        
        // Show suggestions
        suggestionsDiv.innerHTML = suggestions.map((wp, index) => 
            `<div class="autocomplete-suggestion" data-index="${index}" data-waypoint-id="${wp.id}">${wp.name}</div>`
        ).join('');
        suggestionsDiv.style.display = 'block';
        selectedIndex = -1;
    });
    
    input.addEventListener('keydown', function(e) {
        const suggestionsDiv = this.parentElement.querySelector('.autocomplete-suggestions');
        const suggestions = suggestionsDiv.querySelectorAll('.autocomplete-suggestion');
        
        if (e.key === 'ArrowDown') {
            e.preventDefault();
            selectedIndex = Math.min(selectedIndex + 1, suggestions.length - 1);
            suggestions.forEach((s, i) => {
                s.classList.toggle('selected', i === selectedIndex);
            });
        } else if (e.key === 'ArrowUp') {
            e.preventDefault();
            selectedIndex = Math.max(selectedIndex - 1, -1);
            suggestions.forEach((s, i) => {
                s.classList.toggle('selected', i === selectedIndex);
            });
        } else if (e.key === 'Enter') {
            e.preventDefault();
            if (selectedIndex >= 0 && suggestions[selectedIndex]) {
                selectWaypoint(this, suggestions[selectedIndex].dataset.waypointId, suggestions[selectedIndex].textContent);
            } else if (suggestions.length === 1) {
                selectWaypoint(this, suggestions[0].dataset.waypointId, suggestions[0].textContent);
            }
        } else if (e.key === 'Escape') {
            suggestionsDiv.style.display = 'none';
        }
    });
    
    // Click on suggestion
    input.addEventListener('focus', function() {
        const value = this.value.trim();
        if (value && this.parentElement.querySelector('.autocomplete-suggestions').children.length > 0) {
            this.parentElement.querySelector('.autocomplete-suggestions').style.display = 'block';
        }
    });
    
    // Close suggestions when clicking outside
    document.addEventListener('click', function(e) {
        if (!input.contains(e.target) && !input.parentElement.querySelector('.autocomplete-suggestions').contains(e.target)) {
            input.parentElement.querySelector('.autocomplete-suggestions').style.display = 'none';
        }
    });
    
    // Handle suggestion clicks
    input.parentElement.addEventListener('click', function(e) {
        if (e.target.classList.contains('autocomplete-suggestion')) {
            selectWaypoint(input, e.target.dataset.waypointId, e.target.textContent);
        }
    });
}

function selectWaypoint(input, waypointId, waypointName) {
    input.value = waypointName;
    input.dataset.waypointId = waypointId;
    input.parentElement.querySelector('.autocomplete-suggestions').style.display = 'none';
    input.parentElement.querySelector('.waypoint-error').style.display = 'none';
}

// Add new waypoint input field
function addWaypointInputField() {
    const container = document.getElementById('routeWaypointsContainer');
    const newGroup = document.createElement('div');
    newGroup.className = 'waypoint-input-group';
    newGroup.innerHTML = `
        <input type="text" class="route-waypoint-input form-input" placeholder="Type waypoint name..." autocomplete="off">
        <div class="autocomplete-suggestions" style="display: none;"></div>
        <div class="waypoint-error" style="display: none; color: #ff4444; font-size: 0.8rem; margin-top: 0.25rem;">No match</div>
    `;
    container.appendChild(newGroup);
    setupAutocomplete(newGroup.querySelector('.route-waypoint-input'));
}

function openAddRouteModalWithWaypointIdList(orderedWaypointIds) {
    const ids = Array.isArray(orderedWaypointIds) ? orderedWaypointIds.filter(id => id != null && id !== '') : [];
    if (ids.length < 2) return;
    delete document.getElementById('addRouteForm').dataset.editingRouteId;
    document.getElementById('routeName').value = '';
    const modalTitle = document.querySelector('#addRouteModal .modal-header h2');
    if (modalTitle) modalTitle.textContent = 'Add Route';
    const container = document.getElementById('routeWaypointsContainer');
    container.innerHTML = '';
    ids.forEach(waypointId => {
        const waypoint = findSectorRouteFixById(waypointId);
        if (!waypoint) return;
        const newGroup = document.createElement('div');
        newGroup.className = 'waypoint-input-group';
        const nameEsc = String(waypoint.name || '').replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/</g, '&lt;');
        newGroup.innerHTML = `
                <input type="text" class="route-waypoint-input form-input" placeholder="Type waypoint name..." autocomplete="off" value="${nameEsc}" data-waypoint-id="${waypoint.id}">
                <div class="autocomplete-suggestions" style="display: none;"></div>
                <div class="waypoint-error" style="display: none; color: #ff4444; font-size: 0.8rem; margin-top: 0.25rem;">No match</div>
            `;
        container.appendChild(newGroup);
        setupAutocomplete(newGroup.querySelector('.route-waypoint-input'));
    });
    addWaypointInputField();
    openModal('addRouteModal');
    setTimeout(() => document.getElementById('routeName')?.focus(), 100);
}

// Edit route
function editRoute(routeId) {
    const route = routes.find(r => r && r.id === routeId);
    if (!route) return;
    
    // Reset form first
    resetRouteForm();
    
    // Populate route name
    document.getElementById('routeName').value = route.name || '';
    
    // Populate waypoint inputs
    const container = document.getElementById('routeWaypointsContainer');
    container.innerHTML = '';
    
    route.waypointIds.forEach((waypointId, index) => {
        const waypoint = findSectorRouteFixById(waypointId);
        if (waypoint) {
            const newGroup = document.createElement('div');
            newGroup.className = 'waypoint-input-group';
            newGroup.innerHTML = `
                <input type="text" class="route-waypoint-input form-input" placeholder="Type waypoint name..." autocomplete="off" value="${waypoint.name}" data-waypoint-id="${waypoint.id}">
                <div class="autocomplete-suggestions" style="display: none;"></div>
                <div class="waypoint-error" style="display: none; color: #ff4444; font-size: 0.8rem; margin-top: 0.25rem;">No match</div>
            `;
            container.appendChild(newGroup);
            setupAutocomplete(newGroup.querySelector('.route-waypoint-input'));
        }
    });
    
    // Add one empty field if route has waypoints
    if (route.waypointIds.length > 0) {
        addWaypointInputField();
    }
    
    // Store route ID for editing
    document.getElementById('addRouteForm').dataset.editingRouteId = routeId;
    const modalTitle = document.querySelector('#addRouteModal .modal-header h2');
    if (modalTitle) {
        modalTitle.textContent = 'Edit Route';
    }
    
    openModal('addRouteModal');
}

// Delete waypoint
function deleteWaypoint(waypointId) {
    const waypoint = waypoints.find(w => w && w.id === waypointId);
    const wasCentre = waypoint && isCenterWaypointName(waypoint.name);
    
    waypoints = waypoints.filter(w => w && w.id !== waypointId);
    
    // Clean up routes that reference this waypoint
    cleanupInvalidRoutes();
    
    // Update CENTRE waypoint if it was deleted
    if (wasCentre) {
        updateCentreWaypoint();
    }
    
    renderWaypointsList();
    renderRoutesList();
    renderBoundariesList();

    try {
        drawCanvas();
    } catch (error) {
        console.error('Error deleting waypoint:', error);
        drawCanvas();
    }
}

// Delete route
function deleteRoute(routeId) {
    routes = routes.filter(r => r && r.id !== routeId);
    renderRoutesList();
    
    // Safe canvas redraw
    try {
        drawCanvas();
    } catch (error) {
        console.error('Error deleting route:', error);
        drawCanvas();
    }
}

function normalizeAtcSectorFrequency(raw) {
    return (raw ?? '').toString().trim().replace(/\s+/g, ' ');
}

function clearAtcSectorForm(options = {}) {
    const keepFeedback = !!(options && options.keepFeedback);
    const eid = document.getElementById('atcSectorEditingId');
    if (eid) eid.value = '';
    const n = document.getElementById('atcSectorNameInput');
    if (n) n.value = '';
    const freq = document.getElementById('atcSectorFrequencyInput');
    if (freq) freq.value = '';
    const t = document.getElementById('atcBoundaryText');
    if (t) t.value = '';
    ['atcSectorVerticalTopFl', 'atcSectorVerticalBottomFl', 'atcSectorVerticalTransitionFl'].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.value = '';
    });
    if (!keepFeedback) {
        const res = document.getElementById('atcSectorFormResults');
        if (res) res.style.display = 'none';
    }
    const title = document.getElementById('atcSectorsModalTitle');
    if (title) title.textContent = 'ATC Sectors';
}

function renderAtcSectorsExistingInModal() {
    const el = document.getElementById('atcSectorsExistingList');
    if (!el) return;
    if (!atcSectors.length) {
        el.innerHTML = '<div class="hint-text">None yet. Fill the form above and click Save ATC Sector.</div>';
        return;
    }
    el.innerHTML = atcSectors.map(s => {
        const vl = s.verticalLimits || {};
        const fl = (Number.isFinite(vl.topFl) && Number.isFinite(vl.bottomFl))
            ? `TOP ${String(vl.topFl).padStart(3, '0')} BOTTOM ${String(vl.bottomFl).padStart(3, '0')} TR ${String(vl.transitionFl || 0).padStart(3, '0')}`
            : '';
        const nPts = (s.boundary && s.boundary.points) ? s.boundary.points.length : 0;
        const freqTxt = normalizeAtcSectorFrequency(s.frequency);
        const metaParts = [freqTxt, fl, `${nPts} pts`].filter(Boolean);
        return `
            <div class="boundary-item" style="margin-bottom: 0.5rem;">
                <div class="boundary-info">
                    <span class="boundary-points">${escapeHtml(s.name)}</span>
                    <span class="boundary-count" style="font-size: 0.75rem; color: rgba(245, 247, 250, 0.6);">${escapeHtml(metaParts.join(' · '))}</span>
                </div>
                <div class="boundary-actions">
                    <button type="button" class="btn btn-tertiary atc-existing-edit" data-atc-sector-id="${escapeHtml(s.id)}">Edit</button>
                    <button type="button" class="btn btn-tertiary atc-existing-delete" data-atc-sector-id="${escapeHtml(s.id)}">Delete</button>
                </div>
            </div>
        `;
    }).join('');
    el.querySelectorAll('.atc-existing-edit').forEach(b => {
        b.addEventListener('click', () => openAtcSectorsModalForEdit(b.dataset.atcSectorId));
    });
    el.querySelectorAll('.atc-existing-delete').forEach(b => {
        b.addEventListener('click', () => {
            if (confirm('Delete this ATC sector?')) deleteAtcSectorById(b.dataset.atcSectorId);
        });
    });
}

function openAtcSectorsModal() {
    if (!currentSectorId) {
        alert('Please select an airspace first');
        return;
    }
    try { endSectorMapAddAtcSectorMode(); } catch (eAtc) {}
    try { endSectorMapAtcSectorEditMode(); } catch (eAe) {}
    clearAtcSectorForm();
    renderAtcSectorsExistingInModal();
    openModal('atcSectorsModal');
}

function openAtcSectorsModalForEdit(atcSectorId) {
    try { endSectorMapAddAtcSectorMode(); } catch (eAtc) {}
    try { endSectorMapAtcSectorEditMode(); } catch (eAe) {}
    const s = atcSectors.find(x => x && x.id === atcSectorId);
    if (!s) return;
    const eid = document.getElementById('atcSectorEditingId');
    if (eid) eid.value = s.id;
    const n = document.getElementById('atcSectorNameInput');
    if (n) n.value = s.name || '';
    const freq = document.getElementById('atcSectorFrequencyInput');
    if (freq) freq.value = normalizeAtcSectorFrequency(s.frequency);
    const ta = document.getElementById('atcBoundaryText');
    if (ta) {
        if (s.boundary && s.boundary.points && s.boundary.points.length) {
            ta.value = s.boundary.points.map(point => {
                const latDMS = decimalToDMS(point.latitude, true);
                const lonDMS = decimalToDMS(point.longitude, false);
                const latStr = formatDMS(latDMS, true).replace(/\s/g, '');
                const lonStr = formatDMS(lonDMS, false).replace(/\s/g, '');
                return `${point.name || 'WP'} ${latStr} ${lonStr}`;
            }).join('\n');
        } else {
            ta.value = '';
        }
    }
    const vl = s.verticalLimits || {};
    const topEl = document.getElementById('atcSectorVerticalTopFl');
    const botEl = document.getElementById('atcSectorVerticalBottomFl');
    const trEl = document.getElementById('atcSectorVerticalTransitionFl');
    if (topEl) topEl.value = Number.isFinite(vl.topFl) ? String(vl.topFl).padStart(3, '0') : '';
    if (botEl) botEl.value = Number.isFinite(vl.bottomFl) ? String(vl.bottomFl).padStart(3, '0') : '';
    if (trEl) trEl.value = Number.isFinite(vl.transitionFl) ? String(vl.transitionFl).padStart(3, '0') : '';
    const title = document.getElementById('atcSectorsModalTitle');
    if (title) title.textContent = 'Edit ATC Sector';
    const res = document.getElementById('atcSectorFormResults');
    if (res) res.style.display = 'none';
    renderAtcSectorsExistingInModal();
    openModal('atcSectorsModal');
}

function deleteAtcSectorById(id) {
    atcSectors = atcSectors.filter(s => s && s.id !== id);
    syncBoundariesFromAtcSectors();
    const firstVl = atcSectors[0] && atcSectors[0].verticalLimits;
    currentSectorVerticalLimits = (firstVl && Number.isFinite(firstVl.topFl))
        ? { topFl: firstVl.topFl, bottomFl: firstVl.bottomFl, transitionFl: firstVl.transitionFl }
        : null;
    renderBoundariesList();
    renderAtcSectorsExistingInModal();
    try { drawCanvas(); } catch (e) {}
}

function parseBulkAtcSectorBlock(block, blockIndex) {
    const lines = String(block || '').split('\n').map(line => line.trim()).filter(Boolean);
    if (lines.length < 3) {
        return { error: `Block ${blockIndex}: each ATC sector needs a header and at least 2 boundary points.` };
    }

    const headerParts = lines[0].split('|').map(part => part.trim());
    if (headerParts.length < 4) {
        return { error: `Block ${blockIndex}: header must be <Name> | <TOP> | <BOTTOM> | <TRANSITION>.` };
    }

    const name = headerParts[0];
    const top = parseFl3(headerParts[1]);
    const bottom = parseFl3(headerParts[2]);
    const transition = parseFl3(headerParts[3]);
    if (!name) {
        return { error: `Block ${blockIndex}: missing ATC sector name.` };
    }
    if (top == null || bottom == null || transition == null) {
        return { error: `Block ${blockIndex}: TOP, BOTTOM and TRANSITION must be 1-3 digit flight levels.` };
    }
    if (top < bottom) {
        return { error: `Block ${blockIndex}: TOP must be greater than or equal to BOTTOM.` };
    }

    const { points, errors } = parseBoundaryTextToPoints(lines.slice(1).join('\n'));
    if (errors.length) {
        return { error: `Block ${blockIndex}: ${errors.join('; ')}` };
    }

    return {
        name,
        boundary: { id: newSectorEntityId('bd'), points },
        verticalLimits: { topFl: top, bottomFl: bottom, transitionFl: transition }
    };
}

function importBulkAtcSectorsFromText(text) {
    const blocks = String(text || '').split(/\n\s*\n+/).map(block => block.trim()).filter(Boolean);
    const results = { success: [], errors: [] };
    const sectorsToAdd = [];
    if (!blocks.length) {
        results.errors.push('No ATC sector data found.');
        return { sectorsToAdd, results };
    }

    blocks.forEach((block, index) => {
        const parsed = parseBulkAtcSectorBlock(block, index + 1);
        if (parsed.error) {
            results.errors.push(parsed.error);
            return;
        }

        const duplicate = [...atcSectors, ...sectorsToAdd].find(sec =>
            (sec.name || '').toString().trim().toUpperCase() === parsed.name.toUpperCase()
        );
        if (duplicate) {
            results.errors.push(`Block ${index + 1}: ATC sector "${parsed.name}" already exists.`);
            return;
        }

        sectorsToAdd.push({
            id: newSectorEntityId('atc'),
            name: parsed.name,
            boundary: parsed.boundary,
            verticalLimits: parsed.verticalLimits
        });
        results.success.push(parsed.name);
    });

    return { sectorsToAdd, results };
}

/** Parse form, validate, create/update atcSectors entry; refresh map and lists. */
function saveAtcSectorFromForm() {
    const name = (document.getElementById('atcSectorNameInput')?.value || '').trim();
    const frequency = normalizeAtcSectorFrequency(document.getElementById('atcSectorFrequencyInput')?.value);
    const boundaryText = (document.getElementById('atcBoundaryText')?.value || '').trim();
    const editingId = (document.getElementById('atcSectorEditingId')?.value || '').trim();
    const top = parseFl3(document.getElementById('atcSectorVerticalTopFl')?.value);
    const bottom = parseFl3(document.getElementById('atcSectorVerticalBottomFl')?.value);
    const transition = parseFl3(document.getElementById('atcSectorVerticalTransitionFl')?.value);

    const res = document.getElementById('atcSectorFormResults');
    const okEl = document.getElementById('atcSectorFormSuccess');
    const errEl = document.getElementById('atcSectorFormErrors');

    if (!name) {
        alert('Please enter an ATC sector name.');
        return false;
    }
    if (top == null || bottom == null || transition == null) {
        alert('Please enter TOP, BOTTOM and TRANSITION FL as 1–3 digit numbers (e.g. 450, 000, 060).');
        return false;
    }
    if (top < bottom) {
        alert('TOP must be greater than or equal to BOTTOM.');
        return false;
    }

    const { points, errors } = parseBoundaryTextToPoints(boundaryText);
    if (errors.length) {
        if (res) res.style.display = 'block';
        if (okEl) okEl.textContent = '';
        if (errEl) errEl.innerHTML = errors.map(e => escapeHtml(e)).join('<br>');
        return false;
    }

    const verticalLimits = { topFl: top, bottomFl: bottom, transitionFl: transition };
    if (editingId) {
        const idx = atcSectors.findIndex(s => s && s.id === editingId);
        if (idx === -1) {
            alert('ATC sector not found.');
            return false;
        }
        const prev = atcSectors[idx];
        atcSectors[idx] = {
            ...prev,
            name,
            boundary: {
                id: (prev.boundary && prev.boundary.id) ? prev.boundary.id : newSectorEntityId('bd'),
                points
            },
            verticalLimits
        };
        if (frequency) atcSectors[idx].frequency = frequency;
        else delete atcSectors[idx].frequency;
    } else {
        const entry = {
            id: newSectorEntityId('atc'),
            name,
            boundary: { id: newSectorEntityId('bd'), points },
            verticalLimits
        };
        if (frequency) entry.frequency = frequency;
        atcSectors.push(entry);
    }

    syncBoundariesFromAtcSectors();
    const firstVl = atcSectors[0] && atcSectors[0].verticalLimits;
    if (firstVl && Number.isFinite(firstVl.topFl)) {
        currentSectorVerticalLimits = {
            topFl: firstVl.topFl,
            bottomFl: firstVl.bottomFl,
            transitionFl: firstVl.transitionFl
        };
    }

    renderBoundariesList();
    renderAtcSectorsExistingInModal();
    try { drawCanvas(); } catch (e) {}

    if (res) res.style.display = 'block';
    if (okEl) okEl.textContent = editingId ? 'ATC sector updated.' : 'ATC sector saved.';
    if (errEl) errEl.textContent = '';
    clearAtcSectorForm({ keepFeedback: true });
    renderAtcSectorsExistingInModal();
    return true;
}

// Legacy: boundary id referred to nested boundary inside an ATC sector
function editBoundary(boundaryId) {
    const s = atcSectors.find(x => x.boundary && x.boundary.id === boundaryId);
    if (s) openAtcSectorsModalForEdit(s.id);
}

function deleteBoundary(boundaryId) {
    const s = atcSectors.find(x => x.boundary && x.boundary.id === boundaryId);
    if (s && confirm('Delete this ATC sector?')) deleteAtcSectorById(s.id);
}

function refreshEditSectorBaseline() {
    if (!currentSectorId) {
        editSectorBaselineJson = null;
        return;
    }
    const sectors = getSectors();
    const sectorMeta = sectors.find(s => s && String(s.id) === String(currentSectorId));
    const name = sectorMeta ? String(sectorMeta.name || '') : '';
    const description = sectorMeta ? String(sectorMeta.description != null ? sectorMeta.description : '') : '';
    try {
        editSectorBaselineJson = JSON.stringify({
            id: String(currentSectorId),
            name,
            description,
            waypoints: JSON.parse(JSON.stringify(waypoints)),
            routes: JSON.parse(JSON.stringify(routes)),
            atcSectors: JSON.parse(JSON.stringify(atcSectors)),
            mapAreas: JSON.parse(JSON.stringify(mapAreas || [])),
            holdings: JSON.parse(JSON.stringify(sectorHoldings || [])),
            airports: JSON.parse(JSON.stringify(currentSectorAirports || []))
        });
    } catch (e) {
        editSectorBaselineJson = null;
    }
}

function isEditSectorDirty() {
    if (!currentSectorId || editSectorBaselineJson == null) return false;
    const sectors = getSectors();
    const sectorMeta = sectors.find(s => s && String(s.id) === String(currentSectorId));
    const name = sectorMeta ? String(sectorMeta.name || '') : '';
    const description = sectorMeta ? String(sectorMeta.description != null ? sectorMeta.description : '') : '';
    let cur;
    try {
        cur = JSON.stringify({
            id: String(currentSectorId),
            name,
            description,
            waypoints: JSON.parse(JSON.stringify(waypoints)),
            routes: JSON.parse(JSON.stringify(routes)),
            atcSectors: JSON.parse(JSON.stringify(atcSectors)),
            mapAreas: JSON.parse(JSON.stringify(mapAreas || [])),
            holdings: JSON.parse(JSON.stringify(sectorHoldings || [])),
            airports: JSON.parse(JSON.stringify(currentSectorAirports || []))
        });
    } catch (e) {
        return true;
    }
    return cur !== editSectorBaselineJson;
}

function tryCloseEditSectorModal() {
    if (!isEditSectorDirty()) {
        closeModal('editSectorModal');
        editSectorBaselineJson = null;
        return;
    }
    openModal('editSectorUnsavedChangesModal');
}

// Save sector data
function saveSectorData(options) {
    const opts = options && typeof options === 'object' ? options : {};
    const suppressSuccessAlert = !!opts.suppressSuccessAlert;
    if (!currentSectorId) {
        alert('Please select a sector first');
        return false;
    }

    // Clean up invalid routes before saving
    cleanupInvalidRoutes();

    // Filter out invalid waypoints before saving
    const validWaypoints = waypoints.filter(wp =>
        wp &&
        typeof wp.latitude === 'number' &&
        typeof wp.longitude === 'number' &&
        !isNaN(wp.latitude) &&
        !isNaN(wp.longitude) &&
        isFinite(wp.latitude) &&
        isFinite(wp.longitude) &&
        wp.name &&
        typeof wp.name === 'string'
    );

    // Filter out invalid routes before saving
    const validRoutes = routes.filter(route =>
        route &&
        route.name &&
        Array.isArray(route.waypointIds) &&
        route.waypointIds.length >= 2
    );

    const validNavaids = (navaids || []).filter(nav =>
        nav &&
        typeof nav.latitude === 'number' &&
        typeof nav.longitude === 'number' &&
        !isNaN(nav.latitude) &&
        !isNaN(nav.longitude) &&
        isFinite(nav.latitude) &&
        isFinite(nav.longitude) &&
        nav.name &&
        typeof nav.name === 'string'
    ).map(nav => ({
        id: nav.id || newSectorEntityId('nav'),
        name: nav.name,
        type: normalizeNavaidType(nav.type),
        latitude: nav.latitude,
        longitude: nav.longitude
    }));

    const sectors = getSectors();
    const sectorIndex = sectors.findIndex(s => s.id === currentSectorId);

    if (sectorIndex === -1) {
        alert('Could not find airspace to save.');
        return false;
    }

    const validAtcSectors = atcSectors.filter(s =>
        s &&
        (s.name || '').toString().trim() &&
        s.boundary &&
        Array.isArray(s.boundary.points) &&
        s.boundary.points.length >= 2 &&
        s.boundary.points.every(point =>
            point &&
            typeof point.latitude === 'number' &&
            typeof point.longitude === 'number' &&
            isFinite(point.latitude) &&
            isFinite(point.longitude)
        ) &&
        s.verticalLimits &&
        Number.isFinite(s.verticalLimits.topFl) &&
        Number.isFinite(s.verticalLimits.bottomFl) &&
        Number.isFinite(s.verticalLimits.transitionFl)
    ).map(s => {
        const out = {
            id: s.id,
            name: (s.name || '').toString().trim(),
            boundary: {
                id: s.boundary.id || newSectorEntityId('bd'),
                points: JSON.parse(JSON.stringify(s.boundary.points))
            },
            verticalLimits: {
                topFl: s.verticalLimits.topFl,
                bottomFl: s.verticalLimits.bottomFl,
                transitionFl: s.verticalLimits.transitionFl
            }
        };
        const frequency = normalizeAtcSectorFrequency(s.frequency);
        if (frequency) out.frequency = frequency;
        return out;
    });

    const validMapAreas = (mapAreas || []).filter(a =>
        a &&
        (a.name || '').toString().trim() &&
        MAP_AREA_KINDS_LIST.includes(normalizeMapAreaKind(a.kind)) &&
        a.boundary &&
        Array.isArray(a.boundary.points) &&
        a.boundary.points.length >= 2 &&
        a.boundary.points.every(point =>
            point &&
            typeof point.latitude === 'number' &&
            typeof point.longitude === 'number' &&
            isFinite(point.latitude) &&
            isFinite(point.longitude)
        ) &&
        a.verticalLimits &&
        Number.isFinite(a.verticalLimits.topFl) &&
        Number.isFinite(a.verticalLimits.bottomFl)
    ).map(a => {
        const normalized = normalizeMapAreaRecord(a);
        return {
            id: normalized.id,
            name: (normalized.name || '').toString().trim(),
            kind: normalized.kind,
            lineColor: normalized.lineColor,
            boundary: {
                id: normalized.boundary.id || newSectorEntityId('bd'),
                points: JSON.parse(JSON.stringify(normalized.boundary.points))
            },
            verticalLimits: {
                topFl: normalized.verticalLimits.topFl,
                bottomFl: normalized.verticalLimits.bottomFl
            },
            ...(normalized.kind === 'other' ? { otherAction: normalized.otherAction } : {})
        };
    });

    const validParkings = (parkings || []).filter(p =>
        p &&
        typeof p.latitude === 'number' &&
        typeof p.longitude === 'number' &&
        isFinite(p.latitude) &&
        isFinite(p.longitude) &&
        p.name &&
        typeof p.name === 'string'
    ).map(p => ({
        id: p.id ? String(p.id) : newSectorEntityId('pk'),
        name: p.name,
        latitude: p.latitude,
        longitude: p.longitude
    }));

    const validTaxiways = (taxiways || []).filter(t => t && t.name && Array.isArray(t.points)).map(t => {
        const pts = t.points
            .filter(pt => pt && isFinite(pt.latitude) && isFinite(pt.longitude))
            .map((pt, i) => ({ latitude: pt.latitude, longitude: pt.longitude, name: pt.name || `${t.name}_WP${i + 1}` }));
        const endParkingId = (t.endParkingId && validParkings.some(p => p.id === String(t.endParkingId))) ? String(t.endParkingId) : null;
        return { id: t.id ? String(t.id) : newSectorEntityId('twy'), name: String(t.name), points: pts, endParkingId };
    }).filter(t => (t.points.length + (t.endParkingId ? 1 : 0)) >= 2);

    // Persist only satellite (Google Earth) backgrounds — they are re-fetchable from their bounds, so we
    // store metadata only. Uploaded-image backgrounds stay session-only (no kind tag).
    const validSatelliteBackgrounds = (sectorMapSessionBackgroundLayers || []).filter(l =>
        l && l.kind === 'satellite' && l.bounds &&
        isFinite(l.bounds.minLat) && isFinite(l.bounds.maxLat) &&
        isFinite(l.bounds.minLon) && isFinite(l.bounds.maxLon) &&
        l.bounds.maxLon > l.bounds.minLon && l.bounds.maxLat > l.bounds.minLat
    ).map(l => ({
        id: l.id ? String(l.id) : newSatelliteBackgroundId(),
        name: (l.pictureName && String(l.pictureName).trim()) || 'Google Earth',
        minLat: l.bounds.minLat,
        maxLat: l.bounds.maxLat,
        minLon: l.bounds.minLon,
        maxLon: l.bounds.maxLon
    }));

    const validHoldings = (sectorHoldings || []).filter(h =>
        h &&
        h.waypointId != null &&
        String(h.waypointId) !== '' &&
        validWaypoints.some(wp => wp && String(wp.id) === String(h.waypointId))
    ).map(h => {
        const inbound = clampSectorHoldingInboundTrackDeg(h.inboundTrackDeg);
        if (!Number.isFinite(inbound)) return null;
        return {
            id: h.id ? String(h.id) : newSectorEntityId('holding'),
            waypointId: h.waypointId,
            inboundTrackDeg: inbound,
            turnDirection: normalizeSectorHoldingTurnDirection(h.turnDirection),
            outboundMinutes: sanitizeSectorHoldingOutboundMinutes(h.outboundMinutes)
        };
    }).filter(Boolean);

    sectors[sectorIndex].waypoints = JSON.parse(JSON.stringify(validWaypoints));
    if (validNavaids.length) {
        sectors[sectorIndex].navaids = JSON.parse(JSON.stringify(validNavaids));
    } else {
        delete sectors[sectorIndex].navaids;
    }
    sectors[sectorIndex].routes = JSON.parse(JSON.stringify(validRoutes));
    sectors[sectorIndex].atcSectors = JSON.parse(JSON.stringify(validAtcSectors));
    if (validMapAreas.length) {
        sectors[sectorIndex].mapAreas = JSON.parse(JSON.stringify(validMapAreas));
    } else {
        delete sectors[sectorIndex].mapAreas;
    }
    if (validHoldings.length) {
        sectors[sectorIndex].holdings = JSON.parse(JSON.stringify(validHoldings));
    } else {
        delete sectors[sectorIndex].holdings;
    }
    if (validParkings.length) {
        sectors[sectorIndex].parkings = JSON.parse(JSON.stringify(validParkings));
    } else {
        delete sectors[sectorIndex].parkings;
    }
    if (validTaxiways.length) {
        sectors[sectorIndex].taxiways = JSON.parse(JSON.stringify(validTaxiways));
    } else {
        delete sectors[sectorIndex].taxiways;
    }
    if (validSatelliteBackgrounds.length) {
        sectors[sectorIndex].satelliteBackgrounds = JSON.parse(JSON.stringify(validSatelliteBackgrounds));
    } else {
        delete sectors[sectorIndex].satelliteBackgrounds;
    }
    delete sectors[sectorIndex].boundaries;
    delete sectors[sectorIndex].verticalLimits;
    if (validAtcSectors[0] && validAtcSectors[0].verticalLimits) {
        currentSectorVerticalLimits = { ...validAtcSectors[0].verticalLimits };
    } else {
        currentSectorVerticalLimits = null;
    }
    if (Array.isArray(currentSectorAirports) && currentSectorAirports.length) {
        sectors[sectorIndex].airports = JSON.parse(JSON.stringify(currentSectorAirports));
    } else {
        delete sectors[sectorIndex].airports;
    }
    saveSectors(sectors);

    waypoints = validWaypoints;
    navaids = validNavaids;
    routes = validRoutes;
    atcSectors = JSON.parse(JSON.stringify(validAtcSectors));
    syncBoundariesFromAtcSectors();
    mapAreas = JSON.parse(JSON.stringify(validMapAreas));
    sectorHoldings = JSON.parse(JSON.stringify(validHoldings));
    parkings = JSON.parse(JSON.stringify(validParkings));
    taxiways = JSON.parse(JSON.stringify(validTaxiways));

    if (!suppressSuccessAlert) {
        alert(`Airspace "${sectors[sectorIndex].name}" data saved successfully!\n\nWaypoints: ${validWaypoints.length}\nNAVAIDs: ${validNavaids.length}\nRoutes: ${validRoutes.length}\nATC Sectors: ${validAtcSectors.length}\nAreas: ${validMapAreas.length}\nHoldings: ${validHoldings.length}\nTaxiways: ${validTaxiways.length}\nParkings: ${validParkings.length}\nGoogle Earth backgrounds: ${validSatelliteBackgrounds.length}`);
    }

    renderWaypointsList();
    renderNavaidsList();
    renderRoutesList();
    renderBoundariesList();
    renderMapAreasList();
    renderHoldingsList();
    renderTaxiwaysList();
    renderParkingsList();
    try { drawCanvas(); } catch (e) {}

    refreshEditSectorBaseline();
    return true;
}

function sectorLatLonToCanvas(lat, lon, effectiveOriginX, effectiveOriginY) {
    if (!isFinite(lat) || !isFinite(lon) || !isFinite(effectiveOriginX) || !isFinite(effectiveOriginY) || !isFinite(zoomLevel)) return null;
    let relLon = lon;
    let relLat = lat;
    if (centreWaypoint && isFinite(centreWaypoint.longitude) && isFinite(centreWaypoint.latitude)) {
        relLon = lon - centreWaypoint.longitude;
        relLat = lat - centreWaypoint.latitude;
    }
    const sectorLonScale = getSectorMapLonCosScale();
    const x = effectiveOriginX + relLon * zoomLevel * sectorLonScale;
    const y = effectiveOriginY - relLat * zoomLevel;
    if (!isFinite(x) || !isFinite(y)) return null;
    return { x, y };
}

function normalizeSectorHoldingTurnDirection(raw) {
    const k = String(raw || '').trim().toLowerCase();
    return k === 'left' ? 'left' : 'right';
}

function sanitizeSectorHoldingOutboundMinutes(raw) {
    const v = typeof raw === 'number' ? raw : parseFloat(String(raw || '').trim());
    if (!Number.isFinite(v)) return 1;
    return HOLDING_OUTBOUND_MINUTES_ALLOWED.includes(v) ? v : 1;
}

function clampSectorHoldingInboundTrackDeg(n) {
    const v = typeof n === 'number' ? n : parseInt(String(n ?? '').trim(), 10);
    if (!Number.isFinite(v)) return NaN;
    let x = Math.round(v);
    while (x < 1) x += 360;
    while (x > 360) x -= 360;
    return x;
}

/** EN displacement relative to origin lat/lon (flat-Earth approximation for Edit Airspace). */
function holdingEnNmToLatLon(originLatDeg, originLonDeg, eastNm, northNm) {
    const latRad = originLatDeg * Math.PI / 180;
    const cosLat = Math.abs(Math.cos(latRad)) > 1e-6 ? Math.abs(Math.cos(latRad)) : 1e-6;
    return {
        latitude: originLatDeg + northNm / 60,
        longitude: originLonDeg + eastNm / (60 * cosLat)
    };
}

function holdingPerpendicularRight(enEast, enNorth) {
    return { e: enNorth, n: -enEast };
}

function holdingPerpendicularLeft(enEast, enNorth) {
    return { e: -enNorth, n: enEast };
}

/** Unit EN vector inbound (heading θ toward holding fix): bearing clockwise from north. */
function holdingInboundUnitEn(trackDeg) {
    const θ = (trackDeg * Math.PI) / 180;
    return { e: Math.sin(θ), n: Math.cos(θ) };
}

/** Key EN points relative to holding fix at origin — used for geometry + drawing */
function computeSectorHoldingGeometry(inboundTrackDeg, turnRight, legNm = SECTOR_HOLDING_LEG_DRAW_NM, radiusNm = SECTOR_HOLDING_SEMICIRCLE_RADIUS_NM) {
    const inbound = clampSectorHoldingInboundTrackDeg(inboundTrackDeg);
    if (!Number.isFinite(inbound)) return null;
    const L = Number(legNm) > 0 ? Number(legNm) : SECTOR_HOLDING_LEG_DRAW_NM;
    const R = Number(radiusNm) > 0 ? Number(radiusNm) : SECTOR_HOLDING_SEMICIRCLE_RADIUS_NM;
    const uv = holdingInboundUnitEn(inbound);
    const uOut = { e: -uv.e, n: -uv.n };
    const pickPr = uvIn => (turnRight ? holdingPerpendicularRight(uvIn.e, uvIn.n) : holdingPerpendicularLeft(uvIn.e, uvIn.n));

    const O1 = pickPr(uv);
    const O1c = { e: O1.e * R, n: O1.n * R };
    const Pup = { e: -L * uv.e, n: -L * uv.n };
    const Bend = { e: 2 * O1c.e, n: 2 * O1c.n };
    const OutEnd = { e: Bend.e + L * uOut.e, n: Bend.n + L * uOut.n };
    const O2_vec = pickPr(uOut);
    const O2c = { e: OutEnd.e + R * O2_vec.e, n: OutEnd.n + R * O2_vec.n };

    const Fix = { e: 0, n: 0 };
    const arc1 = holdingSampleDirectedSemiArcNm(O1c.e, O1c.n, R, Fix.e, Fix.n, Bend.e, Bend.n, uv.e, uv.n);
    const arc2 = holdingSampleDirectedSemiArcNm(O2c.e, O2c.n, R, OutEnd.e, OutEnd.n, Pup.e, Pup.n, uOut.e, uOut.n);
    return {
        inbound,
        L,
        R,
        uv,
        uOut,
        Pup,
        Bend,
        OutEnd,
        arc1,
        arc2
    };
}

/** Map (east,north) NM direction anchored at anchor lat/lon to a canvas unit vector */
function holdingEnDirectionToCanvasUnit(deltaEastNm, deltaNorthNm, anchorLatDeg, anchorLonDeg, ox, oy) {
    const k = 0.1;
    const p0 = sectorLatLonToCanvas(anchorLatDeg, anchorLonDeg, ox, oy);
    const ll1 = holdingEnNmToLatLon(anchorLatDeg, anchorLonDeg, deltaEastNm * k, deltaNorthNm * k);
    const p1 = sectorLatLonToCanvas(ll1.latitude, ll1.longitude, ox, oy);
    if (!p0 || !p1) return { x: 0, y: 1 };
    const dx = p1.x - p0.x;
    const dy = p1.y - p0.y;
    const h = Math.hypot(dx, dy);
    if (!isFinite(h) || h < 1e-9) return { x: 0, y: 1 };
    return { x: dx / h, y: dy / h };
}

/** Simulation canvas projection for holdings — same lon-scale pattern as elsewhere in drawSimulationCanvas. */
function simulationLatLonToHoldingCanvas(lat, lon, simCentreWaypoint, ox, oy, zoom, lonScale) {
    if (!isFinite(lat) || !isFinite(lon) || !isFinite(ox) || !isFinite(oy) || !isFinite(zoom) || !isFinite(lonScale)) return null;
    let relLon = lon;
    let relLat = lat;
    if (simCentreWaypoint &&
        typeof simCentreWaypoint.longitude === 'number' &&
        typeof simCentreWaypoint.latitude === 'number' &&
        isFinite(simCentreWaypoint.longitude) &&
        isFinite(simCentreWaypoint.latitude)) {
        relLon = lon - simCentreWaypoint.longitude;
        relLat = lat - simCentreWaypoint.latitude;
    }
    const x = ox + relLon * zoom * lonScale;
    const y = oy - relLat * zoom;
    if (!isFinite(x) || !isFinite(y)) return null;
    return { x, y };
}

function simulationHoldingEnDirectionToCanvasUnit(deltaEastNm, deltaNorthNm, anchorLatDeg, anchorLonDeg, simCentreWaypoint, ox, oy, zoom, lonScale) {
    const k = 0.1;
    const p0 = simulationLatLonToHoldingCanvas(anchorLatDeg, anchorLonDeg, simCentreWaypoint, ox, oy, zoom, lonScale);
    const ll1 = holdingEnNmToLatLon(anchorLatDeg, anchorLonDeg, deltaEastNm * k, deltaNorthNm * k);
    const p1 = simulationLatLonToHoldingCanvas(ll1.latitude, ll1.longitude, simCentreWaypoint, ox, oy, zoom, lonScale);
    if (!p0 || !p1) return { x: 0, y: 1 };
    const dx = p1.x - p0.x;
    const dy = p1.y - p0.y;
    const hh = Math.hypot(dx, dy);
    if (!isFinite(hh) || hh < 1e-9) return { x: 0, y: 1 };
    return { x: dx / hh, y: dy / hh };
}

/** Draw holdings from simulation sector (+ MAP popup filters), using same geometry as Edit Airspace. */
function drawSimulationHoldingsPatterns(simulationCtx, effectiveOriginX, effectiveOriginY, simulationZoomLevel, simLonScale, simCentreWaypoint, simWaypoints) {
    const cfg = simulationMap.holdings || SIM_MAP_DEFAULTS.holdings;
    if (!cfg.enabled || !simulationCtx || !Array.isArray(simWaypoints)) return;
    const holdings = getSimulationSectorHoldings();
    if (!(holdings && holdings.length)) return;
    const selectedIds = (cfg.selectedIds && Array.isArray(cfg.selectedIds))
        ? new Set(cfg.selectedIds.map(String))
        : null;

    holdings.forEach(holding => {
        if (!holding) return;
        if (selectedIds && !selectedIds.has(String(holding.id))) return;
        const wp = simWaypoints.find(w => w && String(w.id) === String(holding.waypointId));
        if (!wp || typeof wp.latitude !== 'number' || typeof wp.longitude !== 'number' || !isFinite(wp.latitude) || !isFinite(wp.longitude)) return;
        const trkClamped = clampSectorHoldingInboundTrackDeg(holding.inboundTrackDeg);
        if (!Number.isFinite(trkClamped)) return;
        const turnRight = normalizeSectorHoldingTurnDirection(holding.turnDirection) === 'right';

        const pathLl = buildSectorHoldingPathLatLons(wp.latitude, wp.longitude, trkClamped, turnRight);
        if (!(pathLl && pathLl.length >= 4)) return;

        const pxPath = [];
        pathLl.forEach(ll => {
            const p = simulationLatLonToHoldingCanvas(ll.latitude, ll.longitude, simCentreWaypoint, effectiveOriginX, effectiveOriginY, simulationZoomLevel, simLonScale);
            if (p && isFinite(p.x) && isFinite(p.y)) pxPath.push(p);
        });
        if (pxPath.length < 4) return;

        simulationCtx.save();
        simulationCtx.strokeStyle = HOLDING_DRAW_COLOR_STROKE;
        simulationCtx.lineWidth = 2;
        simulationCtx.lineJoin = 'round';
        simulationCtx.lineCap = 'round';

        simulationCtx.beginPath();
        simulationCtx.moveTo(pxPath[0].x, pxPath[0].y);
        for (let i = 1; i < pxPath.length; i++) {
            simulationCtx.lineTo(pxPath[i].x, pxPath[i].y);
        }
        simulationCtx.stroke();
        simulationCtx.restore();

        const g = computeSectorHoldingGeometry(trkClamped, turnRight);
        if (!g) return;
        const midInLl = holdingEnNmToLatLon(wp.latitude, wp.longitude, g.Pup.e * 0.5, g.Pup.n * 0.5);
        const midOutLl = holdingEnNmToLatLon(
            wp.latitude,
            wp.longitude,
            (g.Bend.e + g.OutEnd.e) * 0.5,
            (g.Bend.n + g.OutEnd.n) * 0.5
        );

        const pInMid = simulationLatLonToHoldingCanvas(midInLl.latitude, midInLl.longitude, simCentreWaypoint, effectiveOriginX, effectiveOriginY, simulationZoomLevel, simLonScale);
        const pOutMid = simulationLatLonToHoldingCanvas(midOutLl.latitude, midOutLl.longitude, simCentreWaypoint, effectiveOriginX, effectiveOriginY, simulationZoomLevel, simLonScale);
        const vIn = simulationHoldingEnDirectionToCanvasUnit(g.uv.e, g.uv.n, wp.latitude, wp.longitude, simCentreWaypoint, effectiveOriginX, effectiveOriginY, simulationZoomLevel, simLonScale);
        const vOut = simulationHoldingEnDirectionToCanvasUnit(g.uOut.e, g.uOut.n, wp.latitude, wp.longitude, simCentreWaypoint, effectiveOriginX, effectiveOriginY, simulationZoomLevel, simLonScale);

        const zArrow = simulationZoomLevel;
        if (pInMid && isFinite(pInMid.x)) {
            simulationCtx.save();
            simulationCtx.fillStyle = HOLDING_DRAW_COLOR_FILL;
            drawSectorMapHoldingMidArrow(simulationCtx, pInMid.x, pInMid.y, vIn.x, vIn.y, zArrow);
            simulationCtx.restore();
        }
        if (pOutMid && isFinite(pOutMid.x)) {
            simulationCtx.save();
            simulationCtx.fillStyle = HOLDING_DRAW_COLOR_FILL;
            drawSectorMapHoldingMidArrow(simulationCtx, pOutMid.x, pOutMid.y, vOut.x, vOut.y, zArrow);
            simulationCtx.restore();
        }
    });
}

/**
 * Half-circle from start→target around (cx,cn). Both valid semicircles share the endpoints;
 * picking by endpoint distance ties (wrong arc). Tie-break with tangent flown from start:
 * tangentEast/North = direction along track into the arc (e.g. inbound uv at fix).
 */
function holdingSampleDirectedSemiArcNm(cx, cn, radiusNm, startE, startN, tarE, tarN, tangentEast, tangentNorth, arcSteps = 52) {
    const a0 = Math.atan2(startN - cn, startE - cx);
    let te = Number(tangentEast);
    let tn = Number(tangentNorth);
    const th = Math.hypot(te, tn);
    if (isFinite(th) && th > 1e-12) {
        te /= th;
        tn /= th;
    } else {
        te = 0;
        tn = 1;
    }
    let best = null;
    for (const sgn of [-1, 1]) {
        const pts = [];
        for (let i = 0; i <= arcSteps; i++) {
            const t = i / arcSteps;
            const a = a0 + sgn * t * Math.PI;
            pts.push({
                e: cx + radiusNm * Math.cos(a),
                n: cn + radiusNm * Math.sin(a)
            });
        }
        const p1 = pts[1];
        const vx = p1.e - startE;
        const vy = p1.n - startN;
        const vh = Math.hypot(vx, vy);
        const dot = vh > 1e-15 ? (vx / vh) * te + (vy / vh) * tn : -Infinity;
        const pLast = pts[pts.length - 1];
        const distErr = Math.hypot(pLast.e - tarE, pLast.n - tarN);
        if (!best ||
            distErr < best.distErr - 1e-10 ||
            (Math.abs(distErr - best.distErr) <= 1e-10 && dot > best.dot)) {
            best = { distErr, dot, pts };
        }
    }
    return best ? best.pts : [];
}

function buildSectorHoldingPathLatLons(fixLat, fixLon, inboundTrackDeg, turnRight, legNm = SECTOR_HOLDING_LEG_DRAW_NM, radiusNm = SECTOR_HOLDING_SEMICIRCLE_RADIUS_NM) {
    const g = computeSectorHoldingGeometry(inboundTrackDeg, turnRight, legNm, radiusNm);
    if (!g) return [];
    const Pup = g.Pup;
    const Bend = g.Bend;
    const OutEnd = g.OutEnd;
    const Fix = { e: 0, n: 0 };
    const arc1 = g.arc1;
    const arc2 = g.arc2;

    const out = [];

    function pushEn(e, n) {
        const ll = holdingEnNmToLatLon(fixLat, fixLon, e, n);
        const last = out[out.length - 1];
        if (last && Math.abs(last.latitude - ll.latitude) < 1e-12 && Math.abs(last.longitude - ll.longitude) < 1e-12) return;
        out.push(ll);
    }

    pushEn(Pup.e, Pup.n);
    pushEn(Fix.e, Fix.n);
    for (let i = 1; i < arc1.length; i++) pushEn(arc1[i].e, arc1[i].n);

    pushEn(Bend.e, Bend.n);
    pushEn(OutEnd.e, OutEnd.n);
    if (arc2.length) {
        for (let i = 1; i < arc2.length; i++) pushEn(arc2[i].e, arc2[i].n);
    }
    pushEn(Pup.e, Pup.n);
    return out;
}

function drawSectorHoldingsLayer(ctx, effectiveOriginX, effectiveOriginY) {
    if (!ctx || !(sectorHoldings && sectorHoldings.length)) return;

    sectorHoldings.forEach(holding => {
        if (!holding) return;
        const wp = waypoints.find(w => w && String(w.id) === String(holding.waypointId));
        if (!wp || typeof wp.latitude !== 'number' || typeof wp.longitude !== 'number' || !isFinite(wp.latitude) || !isFinite(wp.longitude)) return;
        const trkClamped = clampSectorHoldingInboundTrackDeg(holding.inboundTrackDeg);
        if (!Number.isFinite(trkClamped)) return;
        const turnRight = normalizeSectorHoldingTurnDirection(holding.turnDirection) === 'right';

        const pathLl = buildSectorHoldingPathLatLons(wp.latitude, wp.longitude, trkClamped, turnRight);
        if (!(pathLl && pathLl.length >= 4)) return;

        const pxPath = [];
        pathLl.forEach(ll => {
            const p = sectorLatLonToCanvas(ll.latitude, ll.longitude, effectiveOriginX, effectiveOriginY);
            if (p && isFinite(p.x) && isFinite(p.y)) pxPath.push(p);
        });
        if (pxPath.length < 4) return;

        ctx.save();
        ctx.strokeStyle = HOLDING_DRAW_COLOR_STROKE;
        ctx.lineWidth = 2;
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';

        ctx.beginPath();
        ctx.moveTo(pxPath[0].x, pxPath[0].y);
        for (let i = 1; i < pxPath.length; i++) {
            ctx.lineTo(pxPath[i].x, pxPath[i].y);
        }
        ctx.stroke();
        ctx.restore();

        /** Mid-segment arrows in flow direction — inbound toward fix / outbound outbound */
        const g = computeSectorHoldingGeometry(trkClamped, turnRight);
        if (!g) return;
        const midInLl = holdingEnNmToLatLon(wp.latitude, wp.longitude, g.Pup.e * 0.5, g.Pup.n * 0.5);
        const midOutLl = holdingEnNmToLatLon(
            wp.latitude,
            wp.longitude,
            (g.Bend.e + g.OutEnd.e) * 0.5,
            (g.Bend.n + g.OutEnd.n) * 0.5
        );

        const pInMid = sectorLatLonToCanvas(midInLl.latitude, midInLl.longitude, effectiveOriginX, effectiveOriginY);
        const pOutMid = sectorLatLonToCanvas(midOutLl.latitude, midOutLl.longitude, effectiveOriginX, effectiveOriginY);
        const vIn = holdingEnDirectionToCanvasUnit(g.uv.e, g.uv.n, wp.latitude, wp.longitude, effectiveOriginX, effectiveOriginY);
        const vOut = holdingEnDirectionToCanvasUnit(g.uOut.e, g.uOut.n, wp.latitude, wp.longitude, effectiveOriginX, effectiveOriginY);

        if (pInMid && isFinite(pInMid.x)) {
            ctx.save();
            ctx.fillStyle = HOLDING_DRAW_COLOR_FILL;
            drawSectorMapHoldingMidArrow(ctx, pInMid.x, pInMid.y, vIn.x, vIn.y);
            ctx.restore();
        }
        if (pOutMid && isFinite(pOutMid.x)) {
            ctx.save();
            ctx.fillStyle = HOLDING_DRAW_COLOR_FILL;
            drawSectorMapHoldingMidArrow(ctx, pOutMid.x, pOutMid.y, vOut.x, vOut.y);
            ctx.restore();
        }
    });
}

/** @param zoomForArrowPx optional; when omitted uses global zoomLevel (Edit Airspace map). */
function drawSectorMapHoldingMidArrow(ctx, x, y, ux, uy, zoomForArrowPx = null) {
    if (!Number.isFinite(ux) || !Number.isFinite(uy)) return;
    const hlen = Math.hypot(ux, uy);
    if (!isFinite(hlen) || hlen < 1e-9) return;
    const nx = ux / hlen;
    const ny = uy / hlen;
    const zEff = Number.isFinite(zoomForArrowPx) && zoomForArrowPx > 0 ? zoomForArrowPx : zoomLevel;
    const sz = Math.max(5, Math.min(13, zEff ? 11 + Math.log(zEff) * 3 : 9));
    const bx = x - nx * sz * 0.45;
    const by = y - ny * sz * 0.45;
    const px = -ny;
    const py = nx;
    const hw = sz * 0.35;
    ctx.beginPath();
    ctx.moveTo(bx + nx * sz * 1.05, by + ny * sz * 1.05);
    ctx.lineTo(bx + px * hw, by + py * hw);
    ctx.lineTo(bx - px * hw, by - py * hw);
    ctx.closePath();
    ctx.fill();
}

function resetAddHoldingsModalForm() {
    const eid = document.getElementById('holdingEditingId');
    if (eid) eid.value = '';
    const ttl = document.getElementById('addHoldingsModalTitle');
    if (ttl) ttl.textContent = 'Add Holding';
    const subBtn = document.getElementById('addHoldingsSubmitBtn');
    if (subBtn) subBtn.textContent = 'Add Holding';

    const inp = document.getElementById('holdingWaypointInput');
    if (inp) {
        inp.value = '';
        delete inp.dataset.waypointId;
    }
    const errWp = document.getElementById('holdingWaypointError');
    if (errWp) errWp.style.display = 'none';
    const sug = document.getElementById('holdingWaypointSuggestions');
    if (sug) {
        sug.style.display = 'none';
        sug.innerHTML = '';
    }
    const it = document.getElementById('holdingInboundTrackInput');
    if (it) it.value = '';
    const rR = document.getElementById('holdingTurnRightRadio');
    const rL = document.getElementById('holdingTurnLeftRadio');
    if (rR) rR.checked = true;
    if (rL) rL.checked = false;
    const om = document.getElementById('holdingOutboundMinutesSelect');
    if (om) om.value = '1';
}

function renderHoldingsList(filter = null) {
    const container = document.getElementById('holdingsContainer');
    if (!container) return;
    const searchEl = document.getElementById('holdingSearch');
    if (filter === null) filter = searchEl ? searchEl.value.trim() : '';
    let list = (sectorHoldings || []).filter(Boolean);
    if (filter) {
        const ls = filter.toLowerCase();
        list = list.filter(h => {
            const wp = waypoints.find(w => w && String(w.id) === String(h.waypointId));
            const nm = wp && wp.name ? String(wp.name).toLowerCase() : '';
            return nm.includes(ls) ||
                `${h.inboundTrackDeg}`.includes(ls) ||
                String(h.outboundMinutes).includes(ls) ||
                normalizeSectorHoldingTurnDirection(h.turnDirection).includes(ls);
        });
    }
    if (!list.length) {
        container.innerHTML = `<div style="color: rgba(245, 247, 250, 0.5); font-size: 0.8rem;">No holdings${filter ? ` matching "${escapeHtml(filter)}"` : ''}. Use <b>Holdings</b> to add one.</div>`;
        return;
    }
    container.innerHTML = list.map(h => {
        const wp = waypoints.find(w => w && String(w.id) === String(h.waypointId));
        const nm = wp && wp.name ? escapeHtml(wp.name) : `(missing waypoint ${escapeHtml(String(h.waypointId ?? ''))})`;
        const turn = normalizeSectorHoldingTurnDirection(h.turnDirection);
        const trk = clampSectorHoldingInboundTrackDeg(h.inboundTrackDeg);
        const trkStr = Number.isFinite(trk) ? String(trk).padStart(3, '0') : '—';
        const mins = sanitizeSectorHoldingOutboundMinutes(h.outboundMinutes);
        return `
            <div class="boundary-item">
                <div class="boundary-info">
                    <span class="boundary-points">${nm}</span>
                    <span class="boundary-count" style="font-size: 0.75rem; color: rgba(245, 247, 250, 0.6);">Inbound ${escapeHtml(trkStr)}° · ${escapeHtml(turn)} · ${mins} min</span>
                </div>
                <div class="boundary-actions">
                    <button type="button" class="edit-holding-btn" data-holding-id="${escapeHtml(h.id)}">Edit</button>
                    <button type="button" class="delete-holding-btn" data-holding-id="${escapeHtml(h.id)}">Delete</button>
                </div>
            </div>`;
    }).join('');
    container.querySelectorAll('.edit-holding-btn').forEach(btn => {
        btn.addEventListener('click', function() {
            openHoldingsModalForEdit(this.dataset.holdingId);
        });
    });
    container.querySelectorAll('.delete-holding-btn').forEach(btn => {
        btn.addEventListener('click', function() {
            const id = this.dataset.holdingId;
            if (confirm('Remove this holding from the airspace map?')) {
                sectorHoldings = (sectorHoldings || []).filter(x => x && String(x.id) !== String(id));
                renderHoldingsList();
                try { drawCanvas(); } catch (e) {}
            }
        });
    });
}

function ensureAddHoldingsWaypointAutocompleteBound() {
    const inp = document.getElementById('holdingWaypointInput');
    if (!inp || inp.dataset.holdingAutocompleteBound === '1') return;
    inp.dataset.holdingAutocompleteBound = '1';
    setupAutocomplete(inp);
}

function openAddHoldingsModal() {
    if (!currentSectorId) {
        alert('Please select an airspace first');
        return;
    }
    if (!(waypoints && waypoints.length)) {
        alert('Add at least one waypoint to this airspace before adding a holding.');
        return;
    }
    resetAddHoldingsModalForm();
    ensureAddHoldingsWaypointAutocompleteBound();
    openModal('addHoldingsModal');
    setTimeout(() => document.getElementById('holdingWaypointInput')?.focus(), 80);
}

function openHoldingsModalForEdit(holdingId) {
    if (!currentSectorId) {
        alert('Please select an airspace first');
        return;
    }
    if (!(waypoints && waypoints.length)) {
        alert('Add at least one waypoint to this airspace before editing a holding.');
        return;
    }
    const hid = holdingId != null ? String(holdingId) : '';
    const holding = (sectorHoldings || []).find(h => h && String(h.id) === hid);
    if (!holding) {
        alert('Could not find that holding.');
        return;
    }
    resetAddHoldingsModalForm();

    const eid = document.getElementById('holdingEditingId');
    if (eid) eid.value = hid;
    const ttl = document.getElementById('addHoldingsModalTitle');
    if (ttl) ttl.textContent = 'Edit Holding';
    const subBtn = document.getElementById('addHoldingsSubmitBtn');
    if (subBtn) subBtn.textContent = 'Save Holding';

    const wp = waypoints.find(w => w && String(w.id) === String(holding.waypointId));
    const inp = document.getElementById('holdingWaypointInput');
    if (wp && inp) {
        inp.value = wp.name || '';
        inp.dataset.waypointId = String(wp.id);
    } else if (inp) {
        inp.value = '';
        delete inp.dataset.waypointId;
    }

    const trk = clampSectorHoldingInboundTrackDeg(holding.inboundTrackDeg);
    const it = document.getElementById('holdingInboundTrackInput');
    if (it) it.value = Number.isFinite(trk) ? String(trk) : '';

    const td = normalizeSectorHoldingTurnDirection(holding.turnDirection);
    const rR = document.getElementById('holdingTurnRightRadio');
    const rL = document.getElementById('holdingTurnLeftRadio');
    if (rR && rL) {
        const left = td === 'left';
        rL.checked = left;
        rR.checked = !left;
    }

    const mins = sanitizeSectorHoldingOutboundMinutes(holding.outboundMinutes);
    const om = document.getElementById('holdingOutboundMinutesSelect');
    if (om) om.value = String(mins);

    ensureAddHoldingsWaypointAutocompleteBound();
    openModal('addHoldingsModal');
    setTimeout(() => inp?.focus(), 80);
}

function commitAddHoldingsFromModal() {
    const inp = document.getElementById('holdingWaypointInput');
    const errWp = document.getElementById('holdingWaypointError');
    if (errWp) errWp.style.display = 'none';

    const waypointId = inp ? String(inp.dataset.waypointId || '').trim() : '';
    const typed = (inp?.value || '').trim();
    const wp = waypointId ? waypoints.find(w => w && String(w.id) === waypointId) : null;

    if (!wp || !typed || wp.name.trim().toLowerCase() !== typed.toLowerCase()) {
        if (errWp) errWp.style.display = 'block';
        else alert('Choose a valid waypoint from this airspace using the suggestions (name must match exactly).');
        return;
    }

    const trkRaw = parseInt(String(document.getElementById('holdingInboundTrackInput')?.value || '').trim(), 10);
    if (!Number.isFinite(trkRaw) || trkRaw < 1 || trkRaw > 360) {
        alert('Inbound track must be a whole number from 1 to 360 (degrees).');
        return;
    }
    const inboundTrackDeg = clampSectorHoldingInboundTrackDeg(trkRaw);
    if (!Number.isFinite(inboundTrackDeg)) {
        alert('Inbound track must be a whole number from 1 to 360 (degrees).');
        return;
    }

    const turnDirection = document.getElementById('holdingTurnLeftRadio')?.checked ? 'left' : 'right';

    const om = document.getElementById('holdingOutboundMinutesSelect');
    const outboundMinutes = sanitizeSectorHoldingOutboundMinutes(om?.value);

    const editingRaw = document.getElementById('holdingEditingId')?.value;
    const editingId = editingRaw != null ? String(editingRaw).trim() : '';

    if (editingId) {
        const idx = sectorHoldings.findIndex(x => x && String(x.id) === editingId);
        if (idx < 0) {
            alert('Could not update: holding no longer exists.');
            closeModal('addHoldingsModal');
            return;
        }
        sectorHoldings[idx] = {
            ...sectorHoldings[idx],
            id: sectorHoldings[idx].id,
            waypointId: wp.id,
            inboundTrackDeg,
            turnDirection,
            outboundMinutes
        };
    } else {
        sectorHoldings.push({
            id: newSectorEntityId('holding'),
            waypointId: wp.id,
            inboundTrackDeg,
            turnDirection,
            outboundMinutes
        });
    }
    renderHoldingsList();
    try { drawCanvas(); } catch (e) {}
    closeModal('addHoldingsModal');
}

function parseBulkHoldingLine(line, lineNo) {
    const parts = splitBulkPipeLine(line);
    if (parts.length < 4) {
        return { error: `Line ${lineNo}: expected Waypoint | Inbound track | Turn direction | Outbound minutes.` };
    }
    const wpName = (parts[0] || '').toString().trim().toUpperCase();
    const waypoint = (waypoints || []).find(wp => (wp?.name || '').toString().trim().toUpperCase() === wpName);
    if (!wpName || !waypoint) {
        return { error: `Line ${lineNo}: waypoint "${parts[0] || ''}" was not found.` };
    }

    const rawTrack = parseInt(parts[1], 10);
    if (!Number.isFinite(rawTrack) || rawTrack < 1 || rawTrack > 360) {
        return { error: `Line ${lineNo}: inbound track must be a whole number from 1 to 360.` };
    }
    const inboundTrackDeg = clampSectorHoldingInboundTrackDeg(rawTrack);
    const rawTurn = String(parts[2] || '').trim().toLowerCase();
    if (rawTurn !== 'right' && rawTurn !== 'left') {
        return { error: `Line ${lineNo}: turn direction must be "right" or "left".` };
    }
    const turnDirection = normalizeSectorHoldingTurnDirection(rawTurn);
    const outboundMinutes = parseFloat(String(parts[3] || '').trim());
    if (!HOLDING_OUTBOUND_MINUTES_ALLOWED.includes(outboundMinutes)) {
        return { error: `Line ${lineNo}: outbound minutes must be 1, 1.5 or 2.` };
    }

    return {
        id: newSectorEntityId('holding'),
        waypointId: waypoint.id,
        inboundTrackDeg,
        turnDirection,
        outboundMinutes,
        displayName: waypoint.name || wpName
    };
}

function importBulkHoldingsFromText(text) {
    const success = [];
    const errors = [];
    const toAdd = [];
    String(text || '').split('\n').forEach((line, index) => {
        if (!line.trim()) return;
        const parsed = parseBulkHoldingLine(line, index + 1);
        if (parsed.error) {
            errors.push(parsed.error);
            return;
        }
        toAdd.push({
            id: parsed.id,
            waypointId: parsed.waypointId,
            inboundTrackDeg: parsed.inboundTrackDeg,
            turnDirection: parsed.turnDirection,
            outboundMinutes: parsed.outboundMinutes
        });
        success.push(`${parsed.displayName} ${String(parsed.inboundTrackDeg).padStart(3, '0')}° ${parsed.turnDirection}`);
    });
    sectorHoldings.push(...toAdd);
    return { success, errors };
}

function parseFl3(raw) {
    const s = (raw || '').toString().trim();
    if (!/^\d{1,3}$/.test(s)) return null;
    const n = parseInt(s, 10);
    if (!Number.isFinite(n)) return null;
    return Math.max(0, Math.min(500, n));
}

function syncVerticalLimitsModalFromState() {
    const topEl = document.getElementById('sectorVerticalTopFl');
    const botEl = document.getElementById('sectorVerticalBottomFl');
    const trEl = document.getElementById('sectorTransitionFl');
    const readoutEl = document.getElementById('verticalLimitsCurrentReadout');
    const v = currentSectorVerticalLimits;
    if (topEl) topEl.value = (v && Number.isFinite(v.topFl)) ? String(v.topFl).padStart(3, '0') : '';
    if (botEl) botEl.value = (v && Number.isFinite(v.bottomFl)) ? String(v.bottomFl).padStart(3, '0') : '';
    if (trEl) trEl.value = (v && Number.isFinite(v.transitionFl)) ? String(v.transitionFl).padStart(3, '0') : '';
    if (readoutEl) {
        if (v && Number.isFinite(v.topFl) && Number.isFinite(v.bottomFl) && Number.isFinite(v.transitionFl)) {
            readoutEl.innerHTML = `Current limits: <b>TOP</b> ${String(v.topFl).padStart(3, '0')} &nbsp; <b>BOTTOM</b> ${String(v.bottomFl).padStart(3, '0')} &nbsp; <b>TRANSITION</b> ${String(v.transitionFl).padStart(3, '0')}`;
        } else {
            readoutEl.textContent = 'Current limits: None';
        }
    }
}

function applyVerticalLimitsFromModal() {
    const top = parseFl3(document.getElementById('sectorVerticalTopFl')?.value);
    const bottom = parseFl3(document.getElementById('sectorVerticalBottomFl')?.value);
    const transition = parseFl3(document.getElementById('sectorTransitionFl')?.value);
    if (top == null || bottom == null || transition == null) {
        alert('Please enter TOP, BOTTOM and TRANSITION FL as 3-digit numbers.');
        return false;
    }
    if (top < bottom) {
        alert('TOP must be greater than or equal to BOTTOM.');
        return false;
    }
    currentSectorVerticalLimits = { topFl: top, bottomFl: bottom, transitionFl: transition };
    return true;
}

function normalizeAirportIcao(raw) {
    return (raw || '').toString().trim().toUpperCase().replace(/[^A-Z0-9]/g, '').slice(0, 4);
}

function normalizePhraseology(raw) {
    return (raw || '').toString().trim().replace(/\s+/g, ' ').slice(0, 40);
}

function normalizeRunwayDesignator(raw) {
    return (raw || '').toString().trim().toUpperCase().replace(/[^A-Z0-9]/g, '').slice(0, 4);
}

function normalizeCoordSeg(raw) {
    return (raw || '').toString().trim().toUpperCase().replace(/\s+/g, '');
}

function normalizeApproachName(raw) {
    return (raw || '')
        .toString()
        .trim()
        .toUpperCase()
        .replace(/[^A-Z0-9._-]/g, '')
        .slice(0, 16);
}

function normalizeWaypointToken(raw) {
    return (raw || '').toString().trim().toUpperCase().replace(/[^A-Z0-9]/g, '').slice(0, 10);
}

function splitBulkPipeLine(line) {
    return String(line || '').split('|').map(part => part.trim());
}

function findSectorAirportByIcao(icao) {
    const key = normalizeAirportIcao(icao);
    if (!key) return null;
    return (currentSectorAirports || []).find(ap => normalizeAirportIcao(ap?.icao) === key) || null;
}

function findAirportRunwayByDesignator(airport, runwayRef) {
    const ref = String(runwayRef || '').trim().toUpperCase();
    if (!airport || !ref) return null;
    const refs = ref.split('/').map(normalizeRunwayDesignator).filter(Boolean);
    const runways = Array.isArray(airport.runways) ? airport.runways : [];
    return runways.find(rw => {
        const a = normalizeRunwayDesignator(rw?.endA?.name);
        const b = normalizeRunwayDesignator(rw?.endB?.name);
        if (refs.length >= 2) {
            return (a === refs[0] && b === refs[1]) || (a === refs[1] && b === refs[0]);
        }
        return a === refs[0] || b === refs[0];
    }) || null;
}

function parseBulkAirportLine(line, lineNo) {
    const parts = splitBulkPipeLine(line);
    if (parts.length < 4) return { error: `Line ${lineNo}: expected ICAO | Phraseology | Elevation | ARP.` };
    const icao = normalizeAirportIcao(parts[0]);
    const phraseology = normalizePhraseology(parts[1]);
    const elevationFt = parseInt(parts[2], 10);
    const arpCoord = normalizeCoordSeg(parts[3]);
    const arpParsed = parseCoordinateSegment(arpCoord);
    if (!icao || icao.length !== 4) return { error: `Line ${lineNo}: invalid ICAO.` };
    if (!phraseology) return { error: `Line ${lineNo}: missing phraseology name.` };
    if (!arpParsed) return { error: `Line ${lineNo}: invalid ARP coordinate.` };
    return {
        id: newSectorEntityId('apt'),
        icao,
        phraseology,
        elevationFt: Number.isFinite(elevationFt) ? elevationFt : 0,
        arpCoord,
        arpLat: arpParsed.latitude,
        arpLon: arpParsed.longitude,
        runways: []
    };
}

function parseBulkRunwayLine(line, lineNo) {
    const parts = splitBulkPipeLine(line);
    if (parts.length < 5) return { error: `Line ${lineNo}: expected ICAO | End A | Coord A | End B | Coord B.` };
    const icao = normalizeAirportIcao(parts[0]);
    const aName = normalizeRunwayDesignator(parts[1]);
    const aCoord = normalizeCoordSeg(parts[2]);
    const bName = normalizeRunwayDesignator(parts[3]);
    const bCoord = normalizeCoordSeg(parts[4]);
    const aParsed = parseCoordinateSegment(aCoord);
    const bParsed = parseCoordinateSegment(bCoord);
    if (!icao || icao.length !== 4) return { error: `Line ${lineNo}: invalid airport ICAO.` };
    if (!aName || !bName) return { error: `Line ${lineNo}: missing runway end designator.` };
    if (!aParsed || !bParsed) return { error: `Line ${lineNo}: invalid runway threshold coordinate.` };
    return {
        icao,
        runway: {
            id: newSectorEntityId('rwy'),
            endA: { name: aName, coord: aCoord, lat: aParsed.latitude, lon: aParsed.longitude },
            endB: { name: bName, coord: bCoord, lat: bParsed.latitude, lon: bParsed.longitude },
            approaches: []
        }
    };
}

function parseBulkApproachLine(line, lineNo) {
    const parts = splitBulkPipeLine(line);
    if (parts.length < 5) return { error: `Line ${lineNo}: expected ICAO | Runway | Approach | GP | Sequence.` };
    const icao = normalizeAirportIcao(parts[0]);
    const runwayRef = parts[1];
    const name = normalizeApproachName(parts[2]);
    const gpRaw = parts[3];
    const gpVal = gpRaw ? Number(parseFloat(gpRaw)) : null;
    const seqRaw = parts.slice(4).join(' | ');
    if (!icao || icao.length !== 4) return { error: `Line ${lineNo}: invalid airport ICAO.` };
    if (!normalizeRunwayDesignator(runwayRef.split('/')[0])) return { error: `Line ${lineNo}: invalid runway reference.` };
    if (!name) return { error: `Line ${lineNo}: invalid approach name.` };
    if (gpVal != null && (!isFinite(gpVal) || gpVal < 0 || gpVal > 10)) return { error: `Line ${lineNo}: invalid GP angle.` };
    const parsed = parseApproachSequenceRaw(seqRaw);
    if (parsed?.error) return { error: `Line ${lineNo}: ${parsed.error}` };
    if (!parsed?.legs?.length) return { error: `Line ${lineNo}: approach sequence must include at least one waypoint.` };
    return {
        icao,
        runwayRef,
        approach: {
            id: newSectorEntityId('app'),
            airportIcao: icao,
            runwayId: null,
            name,
            gpAngleDeg: (gpVal != null && isFinite(gpVal)) ? gpVal : null,
            sequenceRaw: parsed.normalizedRaw,
            legs: parsed.legs
        }
    };
}

function parseApproachSequenceRaw(raw) {
    const s = (raw || '').toString().trim().toUpperCase().replace(/\s+/g, ' ');
    if (!s) return { legs: [], normalizedRaw: '' };
    const tokens = s.split(' ').map(t => t.trim()).filter(Boolean);

    const wpByName = new Map();
    (Array.isArray(waypoints) ? waypoints : []).forEach(wp => {
        const nm = (wp?.name || '').toString().trim().toUpperCase();
        if (nm) wpByName.set(nm, wp);
    });

    const transition = (currentSectorVerticalLimits && Number.isFinite(currentSectorVerticalLimits.transitionFl))
        ? Number(currentSectorVerticalLimits.transitionFl)
        : null;

    const legs = [];
    for (const tok of tokens) {
        const parts = tok.split('/');
        const wpName = normalizeWaypointToken(parts[0]);
        if (!wpName) return { error: `Invalid token "${tok}".` };
        if (!wpByName.has(wpName)) return { error: `Unknown waypoint "${wpName}". Add it to the sector waypoints first.` };

        let constraint = null;
        if (parts.length > 1) {
            const lvlRaw = (parts[1] || '').toString().trim();
            if (!/^\d{1,4}$/.test(lvlRaw)) return { error: `Invalid altitude/FL in "${tok}". Use digits only.` };
            const n = parseInt(lvlRaw, 10);
            if (!Number.isFinite(n) || n < 0) return { error: `Invalid altitude/FL in "${tok}".` };

            if (transition != null && Number.isFinite(transition)) {
                if (n >= transition) constraint = { kind: 'FL', fl: Math.max(0, Math.min(500, n)), raw: n };
                else constraint = { kind: 'ALT_FT', feet: n * 100, raw: n };
            } else {
                // If no transition level is set, keep a reasonable default:
                // - <=500 treat as FL, otherwise treat as feet.
                if (n <= 500) constraint = { kind: 'FL', fl: n, raw: n };
                else constraint = { kind: 'ALT_FT', feet: n, raw: n };
            }
        }

        legs.push({ wp: wpName, constraint });
    }
    return { legs, normalizedRaw: tokens.join(' ') };
}

function newSectorEntityId(prefix) {
    return `${prefix || 'id'}_${Date.now().toString()}_${Math.random().toString(16).slice(2)}`;
}

/** Snapshot for duplicate: persisted sector metadata + current editor state (includes unsaved changes). */
function buildSectorSnapshotFromEditor() {
    const sectors = getSectors();
    const src = sectors.find(s => s && s.id === currentSectorId);
    if (!src) return null;
    const snap = JSON.parse(JSON.stringify(src));
    snap.waypoints = JSON.parse(JSON.stringify(waypoints || []));
    snap.navaids = JSON.parse(JSON.stringify(navaids || []));
    snap.routes = JSON.parse(JSON.stringify(routes || []));
    snap.atcSectors = JSON.parse(JSON.stringify(atcSectors || []));
    snap.mapAreas = JSON.parse(JSON.stringify(mapAreas || []));
    snap.holdings = JSON.parse(JSON.stringify(sectorHoldings || []));
    delete snap.boundaries;
    delete snap.verticalLimits;
    if (Array.isArray(currentSectorAirports) && currentSectorAirports.length) {
        snap.airports = JSON.parse(JSON.stringify(currentSectorAirports));
    } else {
        delete snap.airports;
    }
    return snap;
}

function deepCloneAirspaceWithNewIds(sourceSector, newDisplayName) {
    const sector = JSON.parse(JSON.stringify(sourceSector));
    sector.id = `sec_${Date.now().toString()}_${Math.random().toString(16).slice(2, 10)}`;
    sector.name = newDisplayName;
    sector.createdAt = new Date().toISOString();

    const wpMap = {};
    sector.waypoints = (Array.isArray(sector.waypoints) ? sector.waypoints : []).filter(Boolean).map(wp => {
        const oid = wp.id;
        const nid = newSectorEntityId('wp');
        if (oid) wpMap[String(oid)] = nid;
        return { ...wp, id: nid };
    });

    sector.navaids = (Array.isArray(sector.navaids) ? sector.navaids : []).filter(Boolean).map(nav => ({
        ...nav,
        id: newSectorEntityId('nav'),
        type: normalizeNavaidType(nav.type)
    }));

    sector.routes = (Array.isArray(sector.routes) ? sector.routes : []).filter(Boolean).map(r => ({
        ...r,
        id: newSectorEntityId('rt'),
        waypointIds: (Array.isArray(r.waypointIds) ? r.waypointIds : []).map(oid => {
            const k = oid != null ? String(oid) : '';
            return k && wpMap[k] != null ? wpMap[k] : oid;
        })
    }));

    sector.atcSectors = (Array.isArray(sector.atcSectors) ? sector.atcSectors : []).filter(Boolean).map(s => ({
        ...s,
        id: newSectorEntityId('atc'),
        boundary: s.boundary && Array.isArray(s.boundary.points)
            ? {
                ...s.boundary,
                id: newSectorEntityId('bd'),
                points: JSON.parse(JSON.stringify(s.boundary.points))
            }
            : s.boundary
    }));

    sector.mapAreas = (Array.isArray(sector.mapAreas) ? sector.mapAreas : []).filter(Boolean).map(a => {
        const normalized = normalizeMapAreaRecord(a);
        return {
            ...normalized,
            id: newSectorEntityId('area'),
            boundary: normalized.boundary && Array.isArray(normalized.boundary.points)
                ? {
                    ...normalized.boundary,
                    id: newSectorEntityId('bd'),
                    points: JSON.parse(JSON.stringify(normalized.boundary.points))
                }
                : normalized.boundary
        };
    });

    sector.holdings = (Array.isArray(sector.holdings) ? sector.holdings : []).filter(Boolean).map(h => {
        const inbound = clampSectorHoldingInboundTrackDeg(h.inboundTrackDeg);
        if (!Number.isFinite(inbound)) return null;
        const oid = h.waypointId;
        const k = oid != null ? String(oid) : '';
        const newWid = k && wpMap[k] != null ? wpMap[k] : oid;
        return {
            ...h,
            id: newSectorEntityId('holding'),
            waypointId: newWid,
            inboundTrackDeg: inbound,
            turnDirection: normalizeSectorHoldingTurnDirection(h.turnDirection),
            outboundMinutes: sanitizeSectorHoldingOutboundMinutes(h.outboundMinutes)
        };
    }).filter(Boolean);

    if (!sector.holdings.length) delete sector.holdings;

    if (Array.isArray(sector.boundaries) && sector.boundaries.length) {
        sector.boundaries = sector.boundaries.map(b => ({
            ...b,
            id: newSectorEntityId('bd'),
            points: JSON.parse(JSON.stringify(b.points || []))
        }));
    } else {
        delete sector.boundaries;
    }
    delete sector.verticalLimits;

    sector.airports = (Array.isArray(sector.airports) ? sector.airports : []).filter(Boolean).map(ap => {
        const newApId = newSectorEntityId('apt');
        const runways = Array.isArray(ap.runways) ? ap.runways.filter(Boolean).map(rw => {
            const nrw = newSectorEntityId('rwy');
            const approaches = Array.isArray(rw.approaches) ? rw.approaches.filter(Boolean).map(app => ({
                ...app,
                id: newSectorEntityId('app'),
                runwayId: nrw,
                airportIcao: ap.icao
            })) : [];
            return { ...rw, id: nrw, approaches };
        }) : [];
        return { ...ap, id: newApId, runways };
    });

    return sector;
}

function airspaceNameAlreadyExists(name, sectors) {
    const t = (name || '').trim().toLowerCase();
    if (!t) return true;
    return sectors.some(s => s && (s.name || '').toString().trim().toLowerCase() === t);
}

function openDuplicateAirspaceModal() {
    if (!currentSectorId) {
        alert('Please select an airspace first');
        return;
    }
    const inp = document.getElementById('duplicateAirspaceNameInput');
    const sectors = getSectors();
    const cur = sectors.find(s => s && s.id === currentSectorId);
    if (inp) {
        const base = cur ? (cur.name || 'Airspace').toString().trim() : 'Airspace';
        inp.value = `${base} (copy)`;
    }
    openModal('duplicateAirspaceModal');
    setTimeout(() => {
        inp?.focus();
        inp?.select();
    }, 100);
}

/** Baseline lines per column on waypoint/route appendix pages (capacity scales × columns). */
const SECTOR_MAP_PRINT_APPENDIX_LINES_PER_COLUMN = 44;

function sectorMapPrintAppendixLinesPerPhysicalPage(opts) {
    const cols = Math.max(1, Math.min(3, Number(opts?.columnsOfData) || 1));
    return SECTOR_MAP_PRINT_APPENDIX_LINES_PER_COLUMN * cols;
}

