const SECTOR_MAP_PRINT_LEADER_GAP_PX = 4;
/**
 * Slider passes 1–8; canvas lineWidth. Levels 1–3 are below 1 device px so leaders can look finer
 * than the old minimum (which was effectively 1 px).
 * @type {number[]}
 */
const SECTOR_MAP_PRINT_LEADER_LINE_LEVEL_TO_PX = [
    0,
    0.15,
    0.28,
    0.42,
    0.58,
    0.75,
    0.92,
    1.1,
    1.35
];

function sectorMapPrintLeaderLineWidthFromLevel(level) {
    const n =
        level != null && isFinite(level) ? Math.max(1, Math.min(8, Math.round(Number(level)))) : 1;
    const w = SECTOR_MAP_PRINT_LEADER_LINE_LEVEL_TO_PX[n];
    return w != null && isFinite(w) ? w : SECTOR_MAP_PRINT_LEADER_LINE_LEVEL_TO_PX[1];
}

