function sectorMapPrintResetPreviewView() {
    sectorMapPrintPreviewZoom = 1;
    sectorMapPrintPreviewPanX = 0;
    sectorMapPrintPreviewPanY = 0;
}

function sectorMapPrintCurrentPageViewLocked() {
    const p = sectorMapPrintPreviewPageIndex;
    const v = sectorMapPrintPageViewport[p];
    return !!(v && v.locked);
}

function sectorMapPrintPersistCurrentPageViewportIfUnlocked() {
    if (sectorMapPrintCurrentPageViewLocked()) return;
    const canvasEl = document.getElementById('printMapsPreviewCanvas');
    const lw = Math.max(1, canvasEl?.clientWidth || 1);
    const lh = Math.max(1, canvasEl?.clientHeight || 1);
    const p = sectorMapPrintPreviewPageIndex;
    sectorMapPrintPageViewport[p] = {
        zoom: sectorMapPrintPreviewZoom,
        panXN: sectorMapPrintPreviewPanX / lw,
        panYN: sectorMapPrintPreviewPanY / lh,
        locked: false
    };
}

function sectorMapPrintRememberPageViewportBeforePageChange() {
    const p = sectorMapPrintPreviewPageIndex;
    const prev = sectorMapPrintPageViewport[p];
    if (prev && prev.locked) return;
    sectorMapPrintPersistCurrentPageViewportIfUnlocked();
}

function sectorMapPrintApplyPageViewportForIndex(pageIndex) {
    const canvasEl = document.getElementById('printMapsPreviewCanvas');
    const lw = Math.max(1, canvasEl?.clientWidth || 1);
    const lh = Math.max(1, canvasEl?.clientHeight || 1);
    const v = sectorMapPrintPageViewport[pageIndex];
    if (!v) {
        sectorMapPrintPreviewZoom = 1;
        sectorMapPrintPreviewPanX = 0;
        sectorMapPrintPreviewPanY = 0;
        sectorMapPrintSyncPdfViewLockButton();
        return;
    }
    sectorMapPrintPreviewZoom = v.zoom;
    sectorMapPrintPreviewPanX = v.panXN * lw;
    sectorMapPrintPreviewPanY = v.panYN * lh;
    sectorMapPrintSyncPdfViewLockButton();
}

function sectorMapPrintSyncPdfViewLockButton() {
    const btn = document.getElementById('printMapsLockViewToPdfBtn');
    if (!btn) return;
    const p = sectorMapPrintPreviewPageIndex;
    const locked = !!(sectorMapPrintPageViewport[p] && sectorMapPrintPageViewport[p].locked);
    btn.textContent = locked ? 'Unlock View' : 'Lock View to PDF';
    btn.setAttribute('aria-pressed', locked ? 'true' : 'false');
    document.getElementById('printMapsPreviewCanvas')?.classList.toggle('print-maps-preview-view-locked', locked);
}

function sectorMapPrintTogglePdfViewLock() {
    if (!document.getElementById('printMapsModal')?.classList.contains('active')) return;
    const canvasEl = document.getElementById('printMapsPreviewCanvas');
    const lw = Math.max(1, canvasEl?.clientWidth || 1);
    const lh = Math.max(1, canvasEl?.clientHeight || 1);
    const p = sectorMapPrintPreviewPageIndex;
    const cur = sectorMapPrintPageViewport[p];
    if (cur && cur.locked) {
        sectorMapPrintPageViewport[p] = {
            zoom: cur.zoom,
            panXN: cur.panXN,
            panYN: cur.panYN,
            locked: false
        };
    } else {
        sectorMapPrintPageViewport[p] = {
            zoom: sectorMapPrintPreviewZoom,
            panXN: sectorMapPrintPreviewPanX / lw,
            panYN: sectorMapPrintPreviewPanY / lh,
            locked: true
        };
    }
    sectorMapPrintSyncPdfViewLockButton();
    sectorMapPrintRedrawPreviewCanvasOnly();
}
