function sectorMapPrintComputeGeoBoundsFromCanvasRect(x0, y0, x1, y1) {
    const llA = canvasPixelToSectorLatLon(x0, y0);
    const llB = canvasPixelToSectorLatLon(x1, y0);
    const llC = canvasPixelToSectorLatLon(x1, y1);
    const llD = canvasPixelToSectorLatLon(x0, y1);
    const lats = [llA.latitude, llB.latitude, llC.latitude, llD.latitude];
    const lons = [llA.longitude, llB.longitude, llC.longitude, llD.longitude];
    const minLat = Math.min(...lats);
    const maxLat = Math.max(...lats);
    const minLon = Math.min(...lons);
    const maxLon = Math.max(...lons);
    if (![minLat, maxLat, minLon, maxLon].every(isFinite)) return null;
    if (Math.abs(maxLat - minLat) < 1e-9 || Math.abs(maxLon - minLon) < 1e-9) return null;
    return { minLat, maxLat, minLon, maxLon };
}

function sectorMapPrintExpandedGeoBounds(geoBounds, frac) {
    const f = frac != null && isFinite(frac) ? frac : 0.06;
    const dLat = geoBounds.maxLat - geoBounds.minLat;
    const dLon = geoBounds.maxLon - geoBounds.minLon;
    const pLat = Math.max(dLat * f, 0.002);
    const pLon = Math.max(dLon * f, 0.002);
    return {
        minLat: geoBounds.minLat - pLat,
        maxLat: geoBounds.maxLat + pLat,
        minLon: geoBounds.minLon - pLon,
        maxLon: geoBounds.maxLon + pLon
    };
}

function sectorMapPrintPointVisible(lat, lon, exp) {
    return lat >= exp.minLat && lat <= exp.maxLat && lon >= exp.minLon && lon <= exp.maxLon;
}

function sectorMapPrintSegmentVisible(lat1, lon1, lat2, lon2, exp) {
    return sectorMapPrintPointVisible(lat1, lon1, exp) || sectorMapPrintPointVisible(lat2, lon2, exp);
}

function sectorMapPrintComputeLayoutForCanvas(cw, ch, geoBounds, padFrac) {
    const pad = Math.min(cw, ch) * (padFrac != null && isFinite(padFrac) ? padFrac : 0.04);
    const availW = cw - 2 * pad;
    const availH = ch - 2 * pad;
    const midLat = (geoBounds.minLat + geoBounds.maxLat) / 2;
    const midLon = (geoBounds.minLon + geoBounds.maxLon) / 2;
    const dLon = Math.max(1e-9, geoBounds.maxLon - geoBounds.minLon);
    const dLat = Math.max(1e-9, geoBounds.maxLat - geoBounds.minLat);
    const lonScale = getSectorMapLonCosScale();
    const zx = availW / (dLon * lonScale);
    const zy = availH / dLat;
    const z = Math.min(zx, zy);
    return { midLat, midLon, z, pad, availW, availH, lonScale, cw, ch };
}

function sectorMapPrintGeoToPixel(lat, lon, L) {
    return {
        x: L.pad + L.availW / 2 + (lon - L.midLon) * L.z * L.lonScale,
        y: L.pad + L.availH / 2 - (lat - L.midLat) * L.z
    };
}

function sectorMapPrintPreloadLogoIfNeeded() {
    if (sectorMapPrintLogoPreloadState === 'ready') return;
    if (sectorMapPrintLogoPreloadState === 'loading') return;
    if (sectorMapPrintLogoPreloadState === 'error') return;
    sectorMapPrintLogoPreloadState = 'loading';
    const im = new Image();
    sectorMapPrintLogoImage = im;
    im.onload = () => {
        sectorMapPrintLogoPreloadState = 'ready';
        scheduleSectorMapPrintPreviewRefresh();
    };
    im.onerror = () => {
        sectorMapPrintLogoPreloadState = 'error';
        sectorMapPrintLogoImage = null;
    };
    im.src = SECTOR_MAP_PRINT_LOGO_URL;
}

/**
 * Bottom-right logo in **viewport** coordinates. Call after full-page white fill, before any
 * translate/scale used for map pan/zoom, so the mark stays fixed when the user pans the map.
 */
function sectorMapPrintDrawLogoUnderlay(ctx, cw, ch) {
    if (!ctx || !cw || !ch || cw < 24 || ch < 24) return;
    sectorMapPrintPreloadLogoIfNeeded();
    const img = sectorMapPrintLogoImage;
    if (!img || !img.complete || !img.naturalWidth || !img.naturalHeight) return;
    const nw = img.naturalWidth;
    const nh = img.naturalHeight;
    const shortSide = Math.min(cw, ch);
    const margin = Math.max(6, shortSide * 0.024);
    const maxW = Math.min(shortSide * 0.2, cw - 2 * margin);
    const w = Math.max(1, maxW);
    const h = Math.max(1, (w * nh) / nw);
    const x = cw - margin - w;
    const y = ch - margin - h;
    if (w < 2 || h < 2 || x < 0 || y < 0) return;
    try {
        ctx.drawImage(img, x, y, w, h);
    } catch (e) {}
}

function sectorMapPrintDrawBackgroundLayers(ctx, cw, ch, layout) {
    if (!sectorMapSessionBackgroundLayers || !sectorMapSessionBackgroundLayers.length) return;
    const alpha = Math.max(0, Math.min(1, sectorMapBackgroundsOpacity));
    if (alpha <= 0) return;
    for (let i = 0; i < sectorMapSessionBackgroundLayers.length; i++) {
        const bg = sectorMapSessionBackgroundLayers[i];
        if (!bg || !bg.image) continue;
        const im = bg.image;
        if (!im.complete || !im.naturalWidth || !im.naturalHeight) continue;
        const useHomography =
            isFinite(bg.lat3) &&
            isFinite(bg.lon3) &&
            isFinite(bg.lat4) &&
            isFinite(bg.lon4) &&
            isFinite(bg.ix3) &&
            isFinite(bg.iy3) &&
            isFinite(bg.ix4) &&
            isFinite(bg.iy4);
        if (useHomography) {
            const dstPts = [
                sectorMapPrintGeoToPixel(bg.lat1, bg.lon1, layout),
                sectorMapPrintGeoToPixel(bg.lat2, bg.lon2, layout),
                sectorMapPrintGeoToPixel(bg.lat3, bg.lon3, layout),
                sectorMapPrintGeoToPixel(bg.lat4, bg.lon4, layout)
            ];
            drawSectorMapSessionBackgroundLayerHomographyWithDstPts(ctx, cw, ch, bg, im, alpha, dstPts);
        } else {
            const c1 = sectorMapPrintGeoToPixel(bg.lat1, bg.lon1, layout);
            const c2 = sectorMapPrintGeoToPixel(bg.lat2, bg.lon2, layout);
            drawSectorMapSessionBackgroundLayerSimilarity(ctx, bg, im, alpha, c1, c2);
        }
    }
}

function sectorMapPrintStrokePolygon(ctx, latLonPts, layout, closed, strokeStyle, lineWidth) {
    if (!latLonPts || latLonPts.length < 2) return;
    ctx.strokeStyle = strokeStyle;
    ctx.lineWidth = lineWidth;
    ctx.beginPath();
    let started = false;
    for (let i = 0; i < latLonPts.length; i++) {
        const pt = latLonPts[i];
        if (!pt || typeof pt.latitude !== 'number' || typeof pt.longitude !== 'number') continue;
        if (!isFinite(pt.latitude) || !isFinite(pt.longitude)) continue;
        const p = sectorMapPrintGeoToPixel(pt.latitude, pt.longitude, layout);
        if (!isFinite(p.x) || !isFinite(p.y)) continue;
        if (!started) {
            ctx.moveTo(p.x, p.y);
            started = true;
        } else {
            ctx.lineTo(p.x, p.y);
        }
    }
    if (!started) return;
    if (closed && latLonPts.length >= 2) {
        const fp = latLonPts[0];
        if (fp && isFinite(fp.latitude) && isFinite(fp.longitude)) {
            const p = sectorMapPrintGeoToPixel(fp.latitude, fp.longitude, layout);
            if (isFinite(p.x) && isFinite(p.y)) ctx.lineTo(p.x, p.y);
        }
    }
    ctx.stroke();
}

function sectorMapPrintRouteVertexVisible(pts, exp) {
    return pts.some(w => sectorMapPrintPointVisible(w.latitude, w.longitude, exp));
}

function sectorMapPrintEscapeHtml(s) {
    return String(s ?? '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

