function sectorMapPrintCommitAnnotEditor() {
    const s = sectorMapPrintAnnotEditorSession;
    if (!s) return;
    if (s.editorKind === 'line') {
        sectorMapPrintAnnotToolbarSyncToSession();
        const lineStyle = sectorMapPrintSanitizeAnnotLineStyle(s.lineStyle);
        const lineThickness = Math.max(1, Math.min(20, Number(s.lineThickness) || 3));
        const arrowMode = sectorMapPrintSanitizeAnnotLineArrows(s.arrowMode);
        const color = sectorMapPrintSanitizeAnnotColor(s.color);
        sectorMapPrintAnnotClampLineEndpoints(s);
        if (s.editingId) {
            const ann = sectorMapPrintAnnotations.find(a => a.id === s.editingId);
            if (ann && ann.kind === 'line') {
                ann.lineStyle = lineStyle;
                ann.lineThickness = lineThickness;
                ann.arrowMode = arrowMode;
                ann.color = color;
                ann.nx0 = s.nx0;
                ann.ny0 = s.ny0;
                ann.nx1 = s.nx1;
                ann.ny1 = s.ny1;
            }
        } else {
            sectorMapPrintAnnotations.push({
                id: sectorMapPrintGenerateAnnotId(),
                kind: 'line',
                nx0: s.nx0,
                ny0: s.ny0,
                nx1: s.nx1,
                ny1: s.ny1,
                lineStyle,
                lineThickness,
                arrowMode,
                color
            });
        }
    } else if (s.editorKind === 'rect') {
        sectorMapPrintAnnotToolbarSyncToSession();
        const canvasEl = document.getElementById('printMapsPreviewCanvas');
        const lw = Math.max(1, canvasEl?.clientWidth || 1);
        const lh = Math.max(1, canvasEl?.clientHeight || 1);
        const lineStyle = sectorMapPrintSanitizeAnnotLineStyle(s.lineStyle);
        const lineThickness = Math.max(1, Math.min(20, Number(s.lineThickness) || 3));
        const color = sectorMapPrintSanitizeAnnotColor(s.color);
        sectorMapPrintAnnotNormalizeRectBounds(s);
        sectorMapPrintAnnotClampRectMinSize(s, lw, lh);
        if (s.editingId) {
            const ann = sectorMapPrintAnnotations.find(a => a.id === s.editingId);
            if (ann && ann.kind === 'rect') {
                ann.lineStyle = lineStyle;
                ann.lineThickness = lineThickness;
                ann.color = color;
                ann.nx0 = s.nx0;
                ann.ny0 = s.ny0;
                ann.nx1 = s.nx1;
                ann.ny1 = s.ny1;
            }
        } else {
            sectorMapPrintAnnotations.push({
                id: sectorMapPrintGenerateAnnotId(),
                kind: 'rect',
                nx0: s.nx0,
                ny0: s.ny0,
                nx1: s.nx1,
                ny1: s.ny1,
                lineStyle,
                lineThickness,
                color
            });
        }
    } else if (s.editorKind === 'shape') {
        sectorMapPrintAnnotToolbarSyncToSession();
        const shapeType = sectorMapPrintSanitizeAnnotShapeType(s.shapeType);
        const size = Math.max(8, Math.min(400, Number(s.size) || 48));
        const rotationDeg = sectorMapPrintNormalizeRotationDeg(s.rotationDeg);
        const color = sectorMapPrintSanitizeAnnotColor(s.color);
        if (s.editingId) {
            const ann = sectorMapPrintAnnotations.find(a => a.id === s.editingId);
            if (ann && ann.kind === 'shape') {
                ann.shapeType = shapeType;
                ann.size = size;
                ann.rotationDeg = rotationDeg;
                ann.color = color;
                ann.nx0 = s.nx0;
                ann.ny0 = s.ny0;
                ann.nx1 = s.nx1;
                ann.ny1 = s.ny1;
            }
        } else {
            sectorMapPrintAnnotations.push({
                id: sectorMapPrintGenerateAnnotId(),
                kind: 'shape',
                nx0: s.nx0,
                ny0: s.ny0,
                nx1: s.nx1,
                ny1: s.ny1,
                shapeType,
                size,
                rotationDeg,
                color
            });
        }
    } else {
        const ta = document.querySelector('#printMapsAnnotOverlayFrameHost .print-maps-annot-overlay-textarea');
        const ff = document.getElementById('printMapsAnnotOverlayFontFamily');
        const fsEl = document.getElementById('printMapsAnnotOverlayFontSize');
        const colorEl = document.getElementById('printMapsAnnotOverlayTextColor');
        const text = ta ? ta.value : s.text;
        const fontFamily = sectorMapPrintSanitizeAnnotFontFamily(ff?.value ?? s.fontFamily);
        const fontSize = Math.max(6, Math.min(96, Number(fsEl?.value) || s.fontSize || 14));
        const color = sectorMapPrintSanitizeAnnotColor(colorEl?.value ?? s.color);
        if (s.editingId) {
            const ann = sectorMapPrintAnnotations.find(a => a.id === s.editingId);
            if (ann && ann.kind === 'text') {
                ann.text = text;
                ann.fontFamily = fontFamily;
                ann.fontSize = fontSize;
                ann.color = color;
                ann.nx0 = s.nx0;
                ann.ny0 = s.ny0;
                ann.nx1 = s.nx1;
                ann.ny1 = s.ny1;
            }
        } else {
            sectorMapPrintAnnotations.push({
                id: sectorMapPrintGenerateAnnotId(),
                kind: 'text',
                nx0: s.nx0,
                ny0: s.ny0,
                nx1: s.nx1,
                ny1: s.ny1,
                text,
                fontFamily,
                fontSize,
                color
            });
        }
    }
    sectorMapPrintHideAnnotEditor();
    sectorMapPrintRenderAnnotationsList();
    sectorMapPrintRedrawPreviewCanvasOnly();
}

/** Kept for callers that still reference the old name; commits either text or shape from the active session. */
