function showBulkImportResults(resultsId, successId, errorsId, successItems, errors, itemLabel) {
    const resultsEl = document.getElementById(resultsId);
    const successEl = document.getElementById(successId);
    const errorsEl = document.getElementById(errorsId);
    if (resultsEl) resultsEl.style.display = 'block';
    if (successEl) {
        successEl.textContent = successItems.length
            ? `Imported ${successItems.length} ${itemLabel}: ${successItems.join(', ')}`
            : '';
    }
    if (errorsEl) {
        errorsEl.innerHTML = errors.length ? `Errors:<br>${errors.map(escapeHtml).join('<br>')}` : '';
    }
}

function importBulkAirportsFromText(text) {
    const success = [];
    const errors = [];
    const toAdd = [];
    String(text || '').split('\n').forEach((line, index) => {
        if (!line.trim()) return;
        const parsed = parseBulkAirportLine(line, index + 1);
        if (parsed.error) {
            errors.push(parsed.error);
            return;
        }
        const duplicate = [...currentSectorAirports, ...toAdd].some(ap => normalizeAirportIcao(ap?.icao) === parsed.icao);
        if (duplicate) {
            errors.push(`Line ${index + 1}: airport ${parsed.icao} already exists.`);
            return;
        }
        toAdd.push(parsed);
        success.push(parsed.icao);
    });
    currentSectorAirports.push(...toAdd);
    toAdd.forEach(ap => expandedSectorAirportIds.add(ap.id));
    return { success, errors };
}

function importBulkRunwaysFromText(text) {
    const success = [];
    const errors = [];
    String(text || '').split('\n').forEach((line, index) => {
        if (!line.trim()) return;
        const parsed = parseBulkRunwayLine(line, index + 1);
        if (parsed.error) {
            errors.push(parsed.error);
            return;
        }
        const airport = findSectorAirportByIcao(parsed.icao);
        if (!airport) {
            errors.push(`Line ${index + 1}: airport ${parsed.icao} was not found.`);
            return;
        }
        if (!Array.isArray(airport.runways)) airport.runways = [];
        const a = normalizeRunwayDesignator(parsed.runway.endA.name);
        const b = normalizeRunwayDesignator(parsed.runway.endB.name);
        const duplicate = airport.runways.some(rw => {
            const ra = normalizeRunwayDesignator(rw?.endA?.name);
            const rb = normalizeRunwayDesignator(rw?.endB?.name);
            return (ra === a && rb === b) || (ra === b && rb === a);
        });
        if (duplicate) {
            errors.push(`Line ${index + 1}: runway ${a}/${b} already exists for ${parsed.icao}.`);
            return;
        }
        airport.runways.push(parsed.runway);
        expandedSectorAirportIds.add(airport.id);
        success.push(`${parsed.icao} ${a}/${b}`);
    });
    return { success, errors };
}

function importBulkApproachesFromText(text) {
    const success = [];
    const errors = [];
    String(text || '').split('\n').forEach((line, index) => {
        if (!line.trim()) return;
        const parsed = parseBulkApproachLine(line, index + 1);
        if (parsed.error) {
            errors.push(parsed.error);
            return;
        }
        const airport = findSectorAirportByIcao(parsed.icao);
        if (!airport) {
            errors.push(`Line ${index + 1}: airport ${parsed.icao} was not found.`);
            return;
        }
        const runway = findAirportRunwayByDesignator(airport, parsed.runwayRef);
        if (!runway) {
            errors.push(`Line ${index + 1}: runway ${parsed.runwayRef} was not found for ${parsed.icao}.`);
            return;
        }
        if (!Array.isArray(runway.approaches)) runway.approaches = [];
        const duplicate = runway.approaches.some(app => normalizeApproachName(app?.name) === parsed.approach.name);
        if (duplicate) {
            errors.push(`Line ${index + 1}: approach ${parsed.approach.name} already exists for ${parsed.icao} ${parsed.runwayRef}.`);
            return;
        }
        parsed.approach.runwayId = runway.id;
        runway.approaches.push(parsed.approach);
        expandedSectorAirportIds.add(airport.id);
        success.push(`${parsed.icao} ${parsed.runwayRef} ${parsed.approach.name}`);
    });
    return { success, errors };
}

let editSectorInportPreviewRows = [];
let editSectorInportAllRows = [];
let editSectorInportVisibleColumns = new Set();
let editSectorInportPendingFunction = null;
const EDIT_SECTOR_INPORT_FLOWS_STORAGE_KEY = 'aitc.editSectorInportFlows.v1';

