    const fileInput = document.getElementById('editSectorInportFileInput');
    const fileName = document.getElementById('editSectorInportFileName');
    const status = document.getElementById('editSectorInportStatus');
    const wrap = document.getElementById('editSectorInportPreviewWrap');
    const table = document.getElementById('editSectorInportPreviewTable');
    const picker = document.getElementById('editSectorInportColumnPicker');
    const builder = document.getElementById('editSectorInportFormatBuilder');
    const fieldButtons = document.getElementById('editSectorInportFieldButtons');
    const strip = document.getElementById('editSectorInportFormatStrip');
    const output = document.getElementById('editSectorInportOutputPreview');
    const countIfBtn = document.getElementById('editSectorInportCountIfBtn');
    const roundBtn = document.getElementById('editSectorInportRoundBtn');
    const functionHint = document.getElementById('editSectorInportFunctionHint');
    const endCountIfBtn = document.getElementById('editSectorInportEndCountIfBtn');
    editSectorInportPreviewRows = [];
