    document.getElementById('turnRadiusSaveBtn')?.addEventListener('click', function() {
        const grid = document.getElementById('turnRadiusGrid');
        if (!grid) return;
        const inputs = Array.from(grid.querySelectorAll('input[data-idx][data-field]'));
        const draft = JSON.parse(JSON.stringify(TURN_RATE_BANDS));
        inputs.forEach(inp => {
            const idx = parseInt(inp.dataset.idx, 10);
            const field = (inp.dataset.field || '').toString();
            if (!Number.isFinite(idx) || !draft[idx] || !field) return;
            const raw = (inp.value || '').toString().trim();
            if (field === 'maxFl') {
                draft[idx][field] = raw === '' ? null : parseInt(raw, 10);
                return;
            }
            if (field === 'minFl') draft[idx][field] = parseInt(raw, 10);
            else if (field === 'minDps' || field === 'maxDps') draft[idx][field] = parseFloat(raw);
        });
        TURN_RATE_BANDS = sanitizeTurnRateBands(draft);
        saveTurnRateBands();
        renderTurnRadiusEditor();
    });

