        const { errors } = parseAircraftDatabaseStrict(raw);
        if (errors.length) {
            alert(`Aircraft DB overrides not saved.\n\n${errors.slice(0, 12).join('\n')}${errors.length > 12 ? '\n...' : ''}`);
            return;
        }
        saveAircraftDbOverridesRaw(raw);
