    document.getElementById('runTypeHostStartBtn')?.addEventListener('click', function() {
        const name = (document.getElementById('runTypeSessionName').value || '').trim();
        const errEl = document.getElementById('runTypeSessionNameError');
        const okEl = document.getElementById('runTypeSessionNameOk');
        if (errEl) errEl.style.display = 'none';
        if (okEl) okEl.style.display = 'none';
        if (!name) {
            if (errEl) { errEl.textContent = 'Please enter a session name.'; errEl.style.display = 'block'; }
            return;
        }
        const exercise = pendingRunExercise;
        if (!exercise) return;
        const sectors = getSectors();
        const sector = sectors.find(s => s.id === exercise.sectorId);
        const payload = {
            name: name,
            mode: 'DL',
            exerciseId: exercise.id,
            sectorId: exercise.sectorId || '',
            exerciseName: exercise.name || '',
            sectorName: (sector && sector.name) || ''
        };
        fetch('/api/sessions', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) })
            .then(r => r.json().then(data => ({ ok: r.ok, status: r.status, data })))
            .then(({ ok, status, data }) => {
                if (!ok && status === 409) {
                    if (errEl) { errEl.textContent = 'Session name already in use.'; errEl.style.display = 'block'; }
                    return;
                }
                if (!ok) {
                    if (errEl) { errEl.textContent = data.error || 'Failed to create session'; errEl.style.display = 'block'; }
                    return;
                }
                clearSimulationJoinerIdentityForHostSession();
                simulationSessionId = data.sessionId;
                window._runTypePresetMode = 'DL';
                startSimulation(exercise);
                closeModal('runTypeModal');
                startHostPpLateralPoll();
                startHostSessionStatePushInterval();
            })
            .catch(() => { if (errEl) { errEl.textContent = 'Network error.'; errEl.style.display = 'block'; } });
    });
    document.getElementById('runTypeSingleStartBtn')?.addEventListener('click', function() {
        const exercise = pendingRunExercise;
        if (!exercise) return;
        const atcSel = document.getElementById('runTypeSingleAtcSectorSelect');
        const atcSectorId = (atcSel?.value || runTypeSingleSelectedAtcSectorId || '').toString().trim();
        if (!atcSectorId) {
            alert('Please select an ATC sector for this exercise.');
            return;
        }
        try { stopHostPpLateralPoll(); } catch (e) {}
        if (simulationHostStateIntervalId) {
            clearInterval(simulationHostStateIntervalId);
            simulationHostStateIntervalId = null;
        }
        hostStatePutInFlight = false;
        try { clearHostReconnectTimers(); } catch (e) {}
        simulationSessionId = null;
        simulationJoinedSessionId = null;
        simulationJoinRole = null;
        simulationJoinAtcSectorId = null;
        simulationJoinBoundaryIdFilter = null;
        simulationIsMonitorOnly = false;
        simulationHostAtcScope = atcSectorId;
        simulationSingleUserAtcSectorLocked = true;
        window._runTypePresetMode = runTypeSingleSelectedMode;
        startSimulation(exercise);
        closeModal('runTypeModal');
    });
