    document.getElementById('addFlightForm')?.addEventListener('submit', function(e) {
        e.preventDefault();
        if (!currentEditingExerciseId) return;

        const form = this;
        const editingFlightId = form.dataset.editingFlightId || null;

        const callsign = document.getElementById('flightCallsign').value;
        const aircraftType = document.getElementById('flightAircraftType').value;
        const departure = document.getElementById('flightDeparture').value;
        const destination = document.getElementById('flightDestination').value;
        const route = document.getElementById('flightRoute').value;
        const spawnTime = document.getElementById('flightSpawnTime').value;
        const pel = document.getElementById('flightPEL').value;
        const alv = document.getElementById('flightALV').value;
        const rlv = document.getElementById('flightRLV').value;

        const errorMsg = validateFlightInputs({ callsign, aircraftType, departure, destination, route, spawnTime, pel, alv, rlv }, editingFlightId);
        if (errorMsg) {
            alert(errorMsg);
            return;
        }

        const flightObj = {
            id: editingFlightId || (Date.now().toString() + Math.random().toString(16).slice(2)),
            callsign: normalizeCallsign(callsign),
            aircraftType: (aircraftType || '').trim().toUpperCase(),
            departure: (departure || '').trim().toUpperCase(),
            destination: (destination || '').trim().toUpperCase(),
            route: (route || '').trim(),
            spawnTime: parseInt(spawnTime, 10),
            pel: parseInt(pel, 10),
            alv: parseInt(alv, 10),
            rlv: parseInt(rlv, 10),
            departureProfile: !!document.getElementById('flightDepartureProfile')?.checked
        };

        if (editingFlightId) {
            const idx = currentEditingFlights.findIndex(f => f && f.id === editingFlightId);
            if (idx !== -1) currentEditingFlights[idx] = flightObj;
        } else {
            currentEditingFlights.push(flightObj);
        }

        initNewCallsignCounter();
        renderExerciseFlightsList();
        try { syncExerciseInitialCallScriptsForAllFlights(); } catch (eSync) {}
        closeModal('addFlightModal');
    });

    // Add Multiple Flights form
    document.getElementById('addMultipleFlightsForm')?.addEventListener('submit', function(e) {
        e.preventDefault();
        if (!currentEditingExerciseId) return;
        const text = document.getElementById('bulkFlightsText').value || '';
        const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
        if (!lines.length) return;

        const errors = [];
        let added = 0;

        lines.forEach((line, idx) => {
            const parts = line.split(/\s+/);
            if (parts.length < 9) {
                errors.push(`Line ${idx + 1}: Expected 9+ fields`);
                return;
            }
            const callsign = parts[0];
            const aircraftType = parts[1];
            const departure = parts[2];
            const destination = parts[3];
            const spawnTime = parts[parts.length - 4];
            const pel = parts[parts.length - 3];
            const alv = parts[parts.length - 2];
            const rlv = parts[parts.length - 1];
            const route = parts.slice(4, parts.length - 4).join(' ');

            const errorMsg = validateFlightInputs({ callsign, aircraftType, departure, destination, route, spawnTime, pel, alv, rlv }, null);
            if (errorMsg) {
                errors.push(`Line ${idx + 1}: ${errorMsg}`);
                return;
            }

            currentEditingFlights.push({
                id: Date.now().toString() + Math.random().toString(16).slice(2),
                callsign: normalizeCallsign(callsign),
                aircraftType: aircraftType.trim().toUpperCase(),
                departure: departure.trim().toUpperCase(),
                destination: destination.trim().toUpperCase(),
                route: route.trim(),
                spawnTime: parseInt(spawnTime, 10),
                pel: parseInt(pel, 10),
                alv: parseInt(alv, 10),
                rlv: parseInt(rlv, 10)
            });
            added += 1;
        });

        initNewCallsignCounter();
        renderExerciseFlightsList();
        try { syncExerciseInitialCallScriptsForAllFlights(); } catch (eSync) {}
        closeModal('addMultipleFlightsModal');
        if (errors.length) {
            alert(`Imported ${added} flight(s).\n\nErrors:\n${errors.slice(0, 12).join('\n')}${errors.length > 12 ? '\n…' : ''}`);
        } else {
            alert(`Imported ${added} flight(s).`);
        }
    });

