    // Add Multiple Routes form handler
    document.getElementById('addMultipleRoutesForm')?.addEventListener('submit', function(e) {
        e.preventDefault();
        
        const bulkText = document.getElementById('bulkRoutesText').value.trim();
        
        if (!bulkText) {
            alert('Please enter route data');
            return;
        }
        
        // Split into lines
        const lines = bulkText.split('\n').filter(line => line.trim());
        
        if (lines.length === 0) {
            alert('No route data found');
            return;
        }
        
        const results = {
            success: [],
            errors: []
        };
        
        // Parse each line - don't add routes until all are validated
        const routesToAdd = [];
        
        lines.forEach((line, index) => {
            const parsed = parseBulkRouteLine(line);
            
            if (parsed.error) {
                results.errors.push(`Line ${index + 1}: ${parsed.error}`);
                return;
            }
            
            // Check for duplicate route name (both existing and in batch)
            if (routes.find(r => r.name === parsed.name) || 
                routesToAdd.find(r => r.name === parsed.name)) {
                results.errors.push(`Line ${index + 1}: Route "${parsed.name}" already exists`);
                return;
            }
            
            // Find route fix IDs by name (Waypoints + NAVAIDs)
            const waypointIds = [];
            const missingWaypoints = [];
            
            parsed.waypointNames.forEach(waypointName => {
                const waypoint = findSectorRouteFixByName(waypointName);
                if (waypoint && waypoint.id) {
                    waypointIds.push(waypoint.id);
                } else {
                    missingWaypoints.push(waypointName);
                }
            });
            
            if (missingWaypoints.length > 0) {
                results.errors.push(`Line ${index + 1}: Route "${parsed.name}" - Waypoints/NAVAIDs not found: ${missingWaypoints.join(', ')}`);
                return; // Don't add this route
            }
            
            if (waypointIds.length < 2) {
                results.errors.push(`Line ${index + 1}: Route "${parsed.name}" must have at least 2 valid waypoints`);
                return; // Don't add this route
            }
            
            // Store route to add (only if all validations pass)
            routesToAdd.push({
                id: Date.now().toString() + '_' + index,
                name: parsed.name,
                waypointIds: waypointIds
            });
            results.success.push(parsed.name);
        });
        
        // Only add routes if validation passed (even if some failed, add the valid ones)
        routesToAdd.forEach(route => {
            routes.push(route);
        });
        
        // Show results
        const resultsDiv = document.getElementById('bulkRoutesImportResults');
        const successDiv = document.getElementById('bulkRoutesImportSuccess');
        const errorsDiv = document.getElementById('bulkRoutesImportErrors');
        
        if (results.success.length > 0 || results.errors.length > 0) {
            resultsDiv.style.display = 'block';
            
            if (results.success.length > 0) {
                successDiv.textContent = `✓ Successfully imported ${results.success.length} route(s): ${results.success.join(', ')}`;
            } else {
                successDiv.textContent = '';
            }
            
            if (results.errors.length > 0) {
                errorsDiv.innerHTML = `✗ Errors (${results.errors.length}):<br>` + results.errors.join('<br>');
            } else {
                errorsDiv.textContent = '';
            }
            
            // Refresh display only if we have valid routes
            if (routesToAdd.length > 0) {
                renderRoutesList();
                // Safe canvas redraw - don't call autoFitZoom for routes
                try {
                    drawCanvas();
                } catch (error) {
                    console.error('Error drawing canvas:', error);
                    // Reset to safe state without changing zoom
                    drawCanvas();
                }
            }
            
            // Clear textarea if all successful
            if (results.errors.length === 0 && results.success.length > 0) {
                document.getElementById('bulkRoutesText').value = '';
            }
        }
    });

    // Add Route form handler
