    document.getElementById('addRouteForm')?.addEventListener('submit', function(e) {
        e.preventDefault();
        
        const name = document.getElementById('routeName').value.trim();
        const waypointInputs = document.querySelectorAll('.route-waypoint-input');
        const waypointIds = [];
        
        // Collect waypoint IDs from inputs that have valid waypoint IDs
        waypointInputs.forEach(input => {
            const waypointId = input.dataset.waypointId;
            const value = input.value.trim();
            if (waypointId && value) {
                waypointIds.push(waypointId);
            } else if (value) {
                // Has value but no valid waypoint ID - show error
                const errorDiv = input.parentElement.querySelector('.waypoint-error');
                if (errorDiv) {
                    errorDiv.style.display = 'block';
                }
            }
        });
        
        // Check for invalid waypoints
        const invalidInputs = Array.from(waypointInputs).filter(input => {
            const value = input.value.trim();
            return value && !input.dataset.waypointId;
        });
        
        if (invalidInputs.length > 0) {
            alert('Please select valid waypoints for all entered waypoint names');
            return;
        }
        
        if (!name) {
            alert('Please enter a route name');
            return;
        }
        
        if (waypointIds.length < 2) {
            alert('Please add at least 2 waypoints');
            return;
        }
        
        // Validate all waypoint IDs exist
        const invalidWaypoints = waypointIds.filter(id => !findSectorRouteFixById(id));
        if (invalidWaypoints.length > 0) {
            alert(`Some selected waypoints are invalid. Please try again.`);
            return;
        }
        
        // Check if we're editing an existing route
        const editingRouteId = this.dataset.editingRouteId;
        if (editingRouteId) {
            // Editing existing route
            const routeIndex = routes.findIndex(r => r && r.id === editingRouteId);
            if (routeIndex === -1) {
                alert('Route not found');
                return;
            }
            
            // Check for duplicate name (excluding current route)
            const duplicateRoute = routes.find(r => r && r.id !== editingRouteId && r.name === name);
            if (duplicateRoute) {
                alert('A route with this name already exists');
                return;
            }
            
            // Update route
            routes[routeIndex].name = name;
            routes[routeIndex].waypointIds = waypointIds;
            
            try {
                renderRoutesList();
                drawCanvas();
            } catch (error) {
                console.error('Error updating route:', error);
                alert('Error updating route. Please try again.');
                return;
            }
            
            // Clear editing flag
            delete this.dataset.editingRouteId;
        } else {
            // Adding new route
            // Check for duplicate name
            if (routes.find(r => r && r.name === name)) {
                alert('A route with this name already exists');
                return;
            }
            
            const newRoute = {
                id: Date.now().toString(),
                name: name,
                waypointIds: waypointIds
            };
            
            routes.push(newRoute);
            
            try {
                renderRoutesList();
                drawCanvas();
            } catch (error) {
                console.error('Error adding route:', error);
                // Remove the route if drawing fails
                routes.pop();
                alert('Error adding route. Please try again.');
                return;
            }
        }
        
        resetRouteForm();
        closeModal('addRouteModal');
    });

