    document.getElementById('addParkingForm')?.addEventListener('submit', function(e) {
        e.preventDefault();
        const name = document.getElementById('parkingName').value.trim();
        if (!name) { alert('Please enter a parking name'); return; }
        const latD = parseInt(document.getElementById('parkingLatDegrees').value, 10);
        const latM = parseInt(document.getElementById('parkingLatMinutes').value, 10);
        const latS = parseInt(document.getElementById('parkingLatSeconds').value, 10);
        const latDir = document.getElementById('parkingLatDirection').value;
        const lonD = parseInt(document.getElementById('parkingLonDegrees').value, 10);
        const lonM = parseInt(document.getElementById('parkingLonMinutes').value, 10);
        const lonS = parseInt(document.getElementById('parkingLonSeconds').value, 10);
        const lonDir = document.getElementById('parkingLonDirection').value;
        if (isNaN(latD) || latD < 0 || latD > 89 || isNaN(latM) || latM < 0 || latM > 59 || isNaN(latS) || latS < 0 || latS > 59) {
            alert('Please enter a valid latitude (DMS).');
            return;
        }
        if (isNaN(lonD) || lonD < 0 || lonD > 179 || isNaN(lonM) || lonM < 0 || lonM > 59 || isNaN(lonS) || lonS < 0 || lonS > 59) {
            alert('Please enter a valid longitude (DMS).');
            return;
        }
        const editingId = this.dataset.editingParkingId;
        const isEditing = !!editingId;
        const dup = parkings.find(p => (p.name || '').toUpperCase() === name.toUpperCase() && (!isEditing || p.id !== editingId));
        if (dup) { alert('A parking with this name already exists'); return; }
        let latitude = DMSToDecimal(latD, latM, latS, latDir);
        let longitude = DMSToDecimal(lonD, lonM, lonS, lonDir);
        // If picked from the map and the DMS fields were left as auto-filled, store the exact
        // clicked coordinates instead of the second-rounded ones (avoids a visible offset at high zoom).
        if (sectorMapParkingPickPreciseLatLon) {
            const pla = decimalToDMS(sectorMapParkingPickPreciseLatLon.latitude, true);
            const plo = decimalToDMS(sectorMapParkingPickPreciseLatLon.longitude, false);
            if (pla.degrees === latD && pla.minutes === latM && pla.seconds === latS && pla.direction === latDir &&
                plo.degrees === lonD && plo.minutes === lonM && plo.seconds === lonS && plo.direction === lonDir) {
                latitude = sectorMapParkingPickPreciseLatLon.latitude;
                longitude = sectorMapParkingPickPreciseLatLon.longitude;
            }
        }
        sectorMapParkingPickPreciseLatLon = null;
        if (isEditing) {
            const idx = parkings.findIndex(p => p.id === editingId);
            if (idx !== -1) parkings[idx] = { id: editingId, name, latitude, longitude };
        } else {
            parkings.push({ id: Date.now().toString(), name, latitude, longitude });
        }
        renderParkingsList();
        try { drawCanvas(); } catch (err) {}
        this.reset();
        delete this.dataset.editingParkingId;
        document.getElementById('addParkingTitle').textContent = 'Add Parking';
        closeModal('addParkingModal');
    });

    document.getElementById('addTaxiwayForm')?.addEventListener('submit', function(e) {
        e.preventDefault();
        const name = document.getElementById('taxiwayName').value.trim().toUpperCase();
        if (!name) { alert('Please enter a taxiway name'); return; }
        const editingId = this.dataset.editingTaxiwayId;
        const isEditing = !!editingId;
        const dup = taxiways.find(t => (t.name || '').toUpperCase() === name && (!isEditing || t.id !== editingId));
        if (dup) { alert('A taxiway with this name already exists'); return; }
        const freePts = sectorMapTaxiwayPickFreePoints.slice();
        const endParking = sectorMapTaxiwayPickEndParking;
        const total = freePts.length + (endParking ? 1 : 0);
        if (total < 2) {
            alert('A taxiway needs at least 2 points. Use "Pick from Map" to draw it on the map.');
            return;
        }
        const points = freePts.map((p, i) => ({ latitude: p.latitude, longitude: p.longitude, name: `${name}_WP${i + 1}` }));
        const endParkingId = endParking ? endParking.id : null;
        if (isEditing) {
            const idx = taxiways.findIndex(t => t.id === editingId);
            if (idx !== -1) taxiways[idx] = { id: editingId, name, points, endParkingId };
        } else {
            taxiways.push({ id: Date.now().toString(), name, points, endParkingId });
        }
        sectorMapTaxiwayPickFreePoints = [];
        sectorMapTaxiwayPickFreePointMeta = [];
        sectorMapTaxiwayPickEndParking = null;
        renderTaxiwaysList();
        try { drawCanvas(); } catch (err) {}
        this.reset();
        delete this.dataset.editingTaxiwayId;
        document.getElementById('addTaxiwayTitle').textContent = 'Add Taxiway';
        closeModal('addTaxiwayModal');
    });

