    // Airports add handler
    document.getElementById('addAirportBtn')?.addEventListener('click', function(e) {
        e.preventDefault();
        if (!currentSectorId) return;
        const icao = normalizeAirportIcao(document.getElementById('airportIcaoInput')?.value);
        const phr = normalizePhraseology(document.getElementById('airportPhraseologyInput')?.value);
        const elev = parseInt(document.getElementById('airportElevationFtInput')?.value, 10);
        const arpCoord = normalizeCoordSeg(document.getElementById('airportArpCoordInput')?.value);
        if (!icao || icao.length !== 4) {
            alert('Please enter a valid 4-letter ICAO code.');
            return;
        }
        if (!phr) {
            alert('Please enter a Phraseology Name.');
            return;
        }
        const arpParsed = parseCoordinateSegment(arpCoord);
        if (!arpParsed) {
            alert('Please enter a valid ARP coordinate (DDMMSSN/DDDMMSSW).');
            return;
        }
        const elevationFt = Number.isFinite(elev) ? elev : 0;
        const exists = currentSectorAirports.some(a => a && normalizeAirportIcao(a.icao) === icao);
        if (exists) {
            alert(`Airport ${icao} already exists in this sector.`);
            return;
        }
        const ap = {
            id: newSectorEntityId('apt'),
            icao,
            phraseology: phr,
            elevationFt,
            arpCoord,
            arpLat: arpParsed.latitude,
            arpLon: arpParsed.longitude,
            runways: []
        };
        currentSectorAirports.push(ap);
        expandedSectorAirportIds.add(ap.id);
        renderSectorAirportsList();
        // keep form for next add
        const i = document.getElementById('airportIcaoInput');
        if (i) i.value = '';
        const a = document.getElementById('airportArpCoordInput');
        if (a) a.value = '';
        setTimeout(() => i?.focus(), 0);
    });

    // Runway add handler
    document.getElementById('saveRunwayBtn')?.addEventListener('click', function(e) {
        e.preventDefault();
        const apId = pendingRunwayAirportId;
        const ap = apId ? currentSectorAirports.find(a => a && a.id === apId) : null;
        if (!ap) { closeModal('addRunwayModal'); return; }
        const aName = normalizeRunwayDesignator(document.getElementById('runwayEnd1Name')?.value);
        const aCoord = normalizeCoordSeg(document.getElementById('runwayEnd1Coord')?.value);
        const bName = normalizeRunwayDesignator(document.getElementById('runwayEnd2Name')?.value);
        const bCoord = normalizeCoordSeg(document.getElementById('runwayEnd2Coord')?.value);
        if (!aName || !bName) {
            alert('Please enter both runway end designators (e.g. 09 and 27).');
            return;
        }
        const aParsed = parseCoordinateSegment(aCoord);
        const bParsed = parseCoordinateSegment(bCoord);
        if (!aParsed || !bParsed) {
            alert('Please enter valid threshold coordinates for both runway ends (DDMMSSN/DDDMMSSW).');
            return;
        }
        // If picked from the map and the coord field still matches the auto-filled DMS, keep the
        // exact clicked lat/lon (avoids a visible offset from second-rounding at high zoom).
        let aLat = aParsed.latitude, aLon = aParsed.longitude;
        let bLat = bParsed.latitude, bLon = bParsed.longitude;
        if (sectorMapRunwayPickPreciseA &&
            formatSectorMapRunwayPickCoord(sectorMapRunwayPickPreciseA.latitude, sectorMapRunwayPickPreciseA.longitude) === aCoord) {
            aLat = sectorMapRunwayPickPreciseA.latitude;
            aLon = sectorMapRunwayPickPreciseA.longitude;
        }
        if (sectorMapRunwayPickPreciseB &&
            formatSectorMapRunwayPickCoord(sectorMapRunwayPickPreciseB.latitude, sectorMapRunwayPickPreciseB.longitude) === bCoord) {
            bLat = sectorMapRunwayPickPreciseB.latitude;
            bLon = sectorMapRunwayPickPreciseB.longitude;
        }
        sectorMapRunwayPickPreciseA = null;
        sectorMapRunwayPickPreciseB = null;
        const rw = {
            id: newSectorEntityId('rwy'),
            endA: { name: aName, coord: aCoord, lat: aLat, lon: aLon },
            endB: { name: bName, coord: bCoord, lat: bLat, lon: bLon }
        };
        if (!Array.isArray(ap.runways)) ap.runways = [];
        ap.runways.push(rw);
        pendingRunwayAirportId = null;
        closeModal('addRunwayModal');
        renderSectorAirportsList();
    });

    // Approach add handler
    document.getElementById('saveApproachBtn')?.addEventListener('click', function(e) {
        e.preventDefault();
        const apId = pendingApproachAirportId;
        const rwId = pendingApproachRunwayId;
        const editId = pendingApproachEditId;
        const ap = apId ? currentSectorAirports.find(a => a && a.id === apId) : null;
        const rw = (ap && Array.isArray(ap.runways)) ? ap.runways.find(r => r && r.id === rwId) : null;
        if (!ap || !rw) { closeModal('addApproachModal'); return; }

        const icao = normalizeAirportIcao(ap.icao);
        const name = normalizeApproachName(document.getElementById('approachNameInput')?.value);
        const seqRaw = (document.getElementById('approachSequenceInput')?.value || '').toString();
        const gpRaw = (document.getElementById('approachGpAngleInput')?.value || '').toString().trim();
        const gpVal = gpRaw ? Number(parseFloat(gpRaw)) : null;
        if (gpVal != null && (!isFinite(gpVal) || gpVal < 0 || gpVal > 10)) {
            alert('Please enter a valid GP angle in degrees (0–10).');
            return;
        }
        if (!name) {
            alert('Please enter a valid approach name (letters/numbers, e.g. ILS34R).');
            return;
        }

        const parsed = parseApproachSequenceRaw(seqRaw);
        if (parsed?.error) {
            alert(parsed.error);
            return;
        }
        const legs = parsed?.legs || [];
        if (!legs.length) {
            alert('Please enter at least one waypoint in the sequence.');
            return;
        }

        if (!Array.isArray(rw.approaches)) rw.approaches = [];
        const exists = rw.approaches.some(a => a && normalizeApproachName(a.name) === name && (!editId || String(a.id) !== String(editId)));
        if (exists) {
            alert(`Approach ${name} already exists for this runway.`);
            return;
        }

        if (editId) {
            const idx = rw.approaches.findIndex(a => a && String(a.id) === String(editId));
            if (idx < 0) { closeModal('addApproachModal'); return; }
            rw.approaches[idx] = {
                ...rw.approaches[idx],
                airportIcao: icao,
                runwayId: rw.id,
                name,
                gpAngleDeg: (gpVal != null && isFinite(gpVal)) ? gpVal : null,
                sequenceRaw: parsed.normalizedRaw,
                legs
            };
        } else {
            rw.approaches.push({
                id: newSectorEntityId('app'),
                airportIcao: icao,
                runwayId: rw.id,
                name,
                gpAngleDeg: (gpVal != null && isFinite(gpVal)) ? gpVal : null,
                sequenceRaw: parsed.normalizedRaw,
                legs
            });
        }

        pendingApproachAirportId = null;
        pendingApproachRunwayId = null;
        pendingApproachEditId = null;
        closeModal('addApproachModal');
        renderSectorAirportsList();
    });

