    // Zoom controls - zoom around center
    document.getElementById('zoomInBtn')?.addEventListener('click', function() {
        const centerX = canvas.width / 2;
        const centerY = canvas.height / 2;
        
        // Calculate world coordinates at center before zoom
        const sectorLonScale = getSectorMapLonCosScale();
        const worldX = (centerX - originX - panX) / (zoomLevel * sectorLonScale);
        const worldY = -(centerY - originY - panY) / zoomLevel;
        
        zoomLevel *= 1.2;
        if (zoomLevel > SECTOR_MAP_MAX_ZOOM) zoomLevel = SECTOR_MAP_MAX_ZOOM;
        
        // Adjust pan to keep center point fixed
        panX = centerX - originX - worldX * zoomLevel * sectorLonScale;
        panY = centerY - originY + worldY * zoomLevel;
        
        drawCanvas();
    });
    
    document.getElementById('zoomOutBtn')?.addEventListener('click', function() {
        const centerX = canvas.width / 2;
        const centerY = canvas.height / 2;
        
        // Calculate world coordinates at center before zoom
        const sectorLonScale = getSectorMapLonCosScale();
        const worldX = (centerX - originX - panX) / (zoomLevel * sectorLonScale);
        const worldY = -(centerY - originY - panY) / zoomLevel;
        
        zoomLevel /= 1.2;
        if (zoomLevel < SECTOR_MAP_MIN_ZOOM) zoomLevel = SECTOR_MAP_MIN_ZOOM;
        
        // Adjust pan to keep center point fixed
        panX = centerX - originX - worldX * zoomLevel * sectorLonScale;
        panY = centerY - originY + worldY * zoomLevel;
        
        drawCanvas();
    });
    
