    function updateSimulationFullscreenLabel() {
        const labelEl = document.getElementById('simulationFullscreenLabel');
        const btn = document.getElementById('simulationFullscreenBtn');
        if (!labelEl || !btn) return;
        const el = document.fullscreenElement || document.webkitFullscreenElement;
        const isFull = (el && el.id === 'simulationModal');
        labelEl.textContent = isFull ? 'Window' : 'Full Screen';
        btn.title = isFull ? 'Exit full screen (windowed)' : 'Full screen';
    }
    document.getElementById('simulationFullscreenBtn')?.addEventListener('click', function() {
        const modal = document.getElementById('simulationModal');
        if (!modal) return;
        const el = document.fullscreenElement || document.webkitFullscreenElement;
        const isFull = (el && el.id === 'simulationModal');
        if (isFull) {
            const exit = document.exitFullscreen || document.webkitExitFullscreen;
            if (exit) exit.call(document);
        } else {
            const req = modal.requestFullscreen || modal.webkitRequestFullscreen;
            if (req) req.call(modal);
        }
    });
