    document.getElementById('labelSetupSelect')?.addEventListener('change', function() {
        const id = (this.value || '').toString();
        const setups = loadLabelSetupsForActiveContext();
        const setup = setups.find(s => s && s.id === id);
        const labelSettings = getLabelEditorSettings();
        if (!setup) {
            labelSettings.labelSetupId = '';
            setLabelEditorLoadedMeta('', '');
            // keep current layout
        } else {
            labelSettings.labelSetupId = setup.id;
            setLabelEditorLoadedMeta(setup.id, (setup.name || '').toString());
            // IMPORTANT: layout is 5x5, so preserve its shape
            labelSettings.labelLayout = (Array.isArray(setup.layout) ? setup.layout : []).map(row =>
                (Array.isArray(row) ? row : []).map(cell => ({
                    field: (cell?.field || '').toString(),
                    freeText: (cell?.freeText || '').toString()
                }))
            );
            const nameEl = document.getElementById('labelSetupName');
            if (nameEl) nameEl.value = setup.name || '';
        }
        syncSimulationLabelEditorControlsFromState();
        if (activeLabelEditorContext === 'simulation' && document.getElementById('simulationModal')?.classList.contains('active')) {
            drawSimulationCanvas();
        }
    });

