    document.getElementById('saveLabelSetupBtn')?.addEventListener('click', function() {
        const nameEl = document.getElementById('labelSetupName');
        const name = (nameEl?.value || '').trim();
        if (!name) {
            alert('Please enter a name for this label setup.');
            return;
        }
        openSimulationLabelAuthModal('Save label setup', async () => {
            const pw = document.getElementById('simulationLabelAuthPassword')?.value || '';
            const err = document.getElementById('simulationLabelAuthError');
            if (pw !== LABEL_SETUP_PASSWORD) {
                if (err) err.style.display = 'block';
                return;
            }
            if (err) err.style.display = 'none';

            applySimulationLabelEditorControlsToState();
            const labelSettings = getLabelEditorSettings();
            const setups = loadLabelSetupsForActiveContext().slice();
            const curId = (labelSettings.labelSetupId || '').toString();
            const { loadedId, loadedName } = getLabelEditorLoadedMeta();
            let setup = curId ? (setups.find(s => s && s.id === curId) || null) : null;

            // Rule:
            // - If a saved setup was loaded and name is unchanged => OVERWRITE that setup.
            // - If name is changed => CREATE NEW (do not affect original).
            const shouldCreateNew = !setup || !loadedId || curId !== loadedId || (name !== loadedName);

            if (shouldCreateNew) {
                const id = `lbl_${Date.now()}_${Math.random().toString(16).slice(2)}`;
                setups.push({
                    id,
                    name,
                    layout: JSON.parse(JSON.stringify(labelSettings.labelLayout)),
                    createdAt: new Date().toISOString()
                });
                labelSettings.labelSetupId = id;
                setLabelEditorLoadedMeta(id, name);
            } else {
                setup.name = name;
                setup.layout = JSON.parse(JSON.stringify(labelSettings.labelLayout));
                setup.updatedAt = new Date().toISOString();
                setLabelEditorLoadedMeta(setup.id, setup.name);
            }
            try {
                await persistLabelSetupsForActiveContext(setups);
                if (activeLabelEditorContext === 'simulation') saveSimulationSettings();
                closeModal('simulationLabelAuthModal');
                syncSimulationLabelEditorControlsFromState();
                alert(activeLabelEditorContext === 'adminGlobal' ? 'Global label setup saved.' : 'Label setup saved.');
            } catch (saveErr) {
                alert(saveErr?.message || 'Could not save label setup.');
            }
        });
    });

    document.getElementById('deleteLabelSetupBtn')?.addEventListener('click', function() {
        const labelSettings = getLabelEditorSettings();
        if (!labelSettings.labelSetupId) return;
        const setups = loadLabelSetupsForActiveContext();
        const setup = setups.find(s => s.id === labelSettings.labelSetupId);
        if (!setup) return;
        if (!confirm(`Delete label setup "${setup.name}"?`)) return;

        openSimulationLabelAuthModal('Delete label setup', async () => {
            const pw = document.getElementById('simulationLabelAuthPassword')?.value || '';
            const err = document.getElementById('simulationLabelAuthError');
            if (pw !== LABEL_SETUP_PASSWORD) {
                if (err) err.style.display = 'block';
                return;
            }
            if (err) err.style.display = 'none';

            const next = loadLabelSetupsForActiveContext().filter(s => s && s.id !== labelSettings.labelSetupId);
            labelSettings.labelSetupId = '';
            setLabelEditorLoadedMeta('', '');
            try {
                await persistLabelSetupsForActiveContext(next);
                if (activeLabelEditorContext === 'simulation') saveSimulationSettings();
                closeModal('simulationLabelAuthModal');
                syncSimulationLabelEditorControlsFromState();
                alert(activeLabelEditorContext === 'adminGlobal' ? 'Global label setup deleted.' : 'Label setup deleted.');
            } catch (saveErr) {
                alert(saveErr?.message || 'Could not delete label setup.');
            }
        });
    });

